window.HADITH_CACHE["nasai_6"] = {"3001":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ عَمْرِو بْنِ مُرَّةَ عَنْ سَالِمِ بْنِ أَبِي الْجَعْدِ عَنْ شُرَحْبِيلَ بْنِ السِّمْطِ قَالَ لِكَعْبِ بْنِ مُرَّةَ يَا كَعْبُ حَدِّثْنَا عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحْذَرْ قَالَسَمِعْتُهُ يَقُولُ مَنْ شَابَ شَيْبَةً فِي الْإِسْلَامِ فِي سَبِيلِ اللَّهِ كَانَتْ لَهُ نُورًا يَوْمَ الْقِيَامَةِقَالَ لَهُ حَدِّثْنَا عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاحْذَرْ قَالَ سَمِعْتُهُ يَقُولُ ارْمُوا مَنْ بَلَغَ الْعَدُوَّ بِسَهْمٍ رَفَعَهُ اللَّهُ بِهِ دَرَجَةً قَالَ ابْنُ النَّحَّامِ يَا رَسُولَ اللَّهِ وَمَا الدَّرَجَةُ قَالَ أَمَا إِنَّهَا لَيْسَتْ بِعَتَبَةِ أُمِّكَ وَلَكِنْ مَا بَيْنَ الدَّرَجَتَيْنِ مِائَةُ عَامٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah], ia berkata; telah menceritakan kepada kami [Al A'masy] dari ['Amr bin Murrah] dari [Salim bin Abu Al Ja'd] dari [Syurahbil bin As Simth], ia berkata; kepada [Ka'ab bin Murrah]; wahai Ka'ab ceritakan kepada kami sebuah hadis dari Rasulullah shallallahu 'alaihi wasallam dan berhati-hatilah, ia berkata; saya pernah mendengar beliau bersabda: \"Barangsiapa yang rambutnya beruban dalam Islam dijalan Allah, ia menjadi cahaya baginya pada Hari Kiamat.\" Ia berkata kepadanya; ceritakan kepada kami sebuah hadis dari Nabi shallallahu 'alaihi wasallam dan berhati-hatilah, ia berkata; saya mendengar beliau bersabda: \"Lemparlah, barangsiapa yang mengenai musuh dengan satu anak panah, Allah mengangkatnya satu derajat, \" Ibn Nahham berkata; wahai Rasulullah, derajat apa itu?, beliau menjawab: \" Tingginya bukan setinggi rumah ibumu, namun jarak antara keduanya adalah seratus tahun.\" "},"3002":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ خَالِدًا يَعْنِي ابْنَ زَيْدٍ أَبَا عَبْدِ الرَّحْمَنِ الشَّامِيَّ يُحَدِّثُ عَنْ شُرَحْبِيلَ بْنِ السِّمْطِ عَنْ عَمْرِو بْنِ عَبَسَةَ قَالَ قُلْتُ يَا عَمْرُو بْنَ عَبَسَةَ حَدِّثْنَا حَدِيثًا سَمِعْتَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ فِيهِ نِسْيَانٌ وَلَا تَنَقُّصٌ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَمَى بِسَهْمٍ فِي سَبِيلِ اللَّهِ فَبَلَغَ الْعَدُوَّ أَخْطَأَ أَوْ أَصَابَ كَانَ لَهُ كَعِدْلِ رَقَبَةٍ وَمَنْ أَعْتَقَ رَقَبَةً مُسْلِمَةً كَانَ فِدَاءُ كُلِّ عُضْوٍ مِنْهُ عُضْوًا مِنْهُ مِنْ نَارِ جَهَنَّمَ وَمَنْ شَابَ شَيْبَةً فِي سَبِيلِ اللَّهِ كَانَتْ لَهُ نُورًا يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Al Mu'tamir], ia berkata; saya pernah mendengar [Khalid yaitu Ibnu Zaid Abu Abdur Rahman Asy Syami] menceritakan dari [Syurahbil bin As Simth] dari ['Amr bin 'Abasah], ia berkata; saya berkata; wahai 'Amr bin 'Abasah, ceritakan kepada kami sebuah hadis yang engkau dengar dari Rasulullah shallallahu 'alaihi wasallam yang tidak terlupakan dan tidak ada kekurangan padanya. Ia berkata; saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa melempar anak panah di jalan Allah, hingga sampai kepada musuh baik luput atau mengenai, baginya seperti budak, dan barang siapa yang memerdekakan budak wanita muslim maka penebusan setiap anggota badan tersebut adalah terbebasnya satu anggota badan dari Jahannam, dan barang siapa yang beruban di jalan Allah, baginya menjadi cahaya pada Hari Kiamat.\""},"3003":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدٍ عَنْ الْوَلِيدِ عَنْ ابْنِ جَابِرٍ عَنْ أَبِي سَلَّامٍ الْأَسْوَدِ عَنْ خَالِدِ بْنِ يَزِيدَ عَنْ عُقْبَةَ بْنِ عَامِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يُدْخِلُ ثَلَاثَةَ نَفَرٍ الْجَنَّةَ بِالسَّهْمِ الْوَاحِدِ صَانِعَهُ يَحْتَسِبُ فِي صُنْعِهِ الْخَيْرَ وَالرَّامِيَ بِهِ وَمُنَبِّلَهُ","id":"Telah mengabarkan kepada kami ['Amr bin Utsman bin Sa'id] dari [Al Walid] dari [Ibnu Jabir] dari [Abu Sallam Al Aswad] dari [Khalid bin Yazid] dari ['Uqbah bin 'Amir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabd: \"Allah 'azza wajalla memasukkan tiga orang ke dalam Surga karena satu anak panah, yaitu pembuatnya asalkan berniat mengharapkan kebaikan, orang yang memanahnya dan orang yang mengambilkannya.\" "},"3004":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يُكْلَمُ أَحَدٌ فِي سَبِيلِ اللَّهِ وَاللَّهُ أَعْلَمُ بِمَنْ يُكْلَمُ فِي سَبِيلِهِ إِلَّا جَاءَ يَوْمَ الْقِيَامَةِ وَجُرْحُهُ يَثْعَبُ دَمًا اللَّوْنُ لَوْنُ دَمٍ وَالرِّيحُ رِيحُ الْمِسْكِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidaklah seseorang terluka di jalan Allah -Allahu a'lam siapa yang terluka di jalan-Nya- kecuali ia datang pada Hari Kiamat dalam keadaan lukanya mengalirkan darah, warnanya sewarna darah dan baunya sebau kasturi.\""},"3005":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ ابْنِ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَمِّلُوهُمْ بِدِمَائِهِمْ فَإِنَّهُ لَيْسَ كَلْمٌ يُكْلَمُ فِي اللَّهِ إِلَّا أَتَى يَوْمَ الْقِيَامَةِ جُرْحُهُ يَدْمَى لَوْنُهُ لَوْنُ دَمٍ وَرِيحُهُ رِيحُ الْمِسْكِ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Ibnu Al Mubarak] dari [Ma'mar] dari [Az Zuhri] dari [Abdullah bin Tsa'labah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tutupi mereka dengan darah mereka, sesungguhnya tidak ada luka karena Allah kecuali pada Hari Kiamat luka tersebut datang mengalirkan darah, warnanya sewarna darah dan baunya sebau kasturi.\""},"3006":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادٍ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يَحْيَى بْنُ أَيُّوبَ وَذَكَرَ آخَرَ قَبْلَهُ عَنْ عُمَارَةَ بْنِ غَزِيَّةَ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَلَمَّا كَانَ يَوْمُ أُحُدٍ وَوَلَّى النَّاسُ كَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَاحِيَةٍ فِي اثْنَيْ عَشَرَ رَجُلًا مِنْ الْأَنْصَارِ وَفِيهِمْ طَلْحَةُ بْنُ عُبَيْدِ اللَّهِ فَأَدْرَكَهُمْ الْمُشْرِكُونَ فَالْتَفَتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ مَنْ لِلْقَوْمِ فَقَالَ طَلْحَةُ أَنَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمَا أَنْتَ فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ أَنَا يَا رَسُولَ اللَّهِ فَقَالَ أَنْتَ فَقَاتَلَ حَتَّى قُتِلَ ثُمَّ الْتَفَتَ فَإِذَا الْمُشْرِكُونَ فَقَالَ مَنْ لِلْقَوْمِ فَقَالَ طَلْحَةُ أَنَا قَالَ كَمَا أَنْتَ فَقَالَ رَجُلٌ مِنْ الْأَنْصَارِ أَنَا فَقَالَ أَنْتَ فَقَاتَلَ حَتَّى قُتِلَ ثُمَّ لَمْ يَزَلْ يَقُولُ ذَلِكَ وَيَخْرُجُ إِلَيْهِمْ رَجُلٌ مِنْ الْأَنْصَارِ فَيُقَاتِلُ قِتَالَ مَنْ قَبْلَهُ حَتَّى يُقْتَلَ حَتَّى بَقِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَطَلْحَةُ بْنُ عُبَيْدِ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ لِلْقَوْمِ فَقَالَ طَلْحَةُ أَنَا فَقَاتَلَ طَلْحَةُ قِتَالَ الْأَحَدَ عَشَرَ حَتَّى ضُرِبَتْ يَدُهُ فَقُطِعَتْ أَصَابِعُهُ فَقَالَ حَسِّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ قُلْتَ بِسْمِ اللَّهِ لَرَفَعَتْكَ الْمَلَائِكَةُ وَالنَّاسُ يَنْظُرُونَ ثُمَّ رَدَّ اللَّهُ الْمُشْرِكِينَ","id":"Telah mengabarkan kepada kami ['Amr bin Sawwad], ia berkata; telah memberitakan kepada kami [Ibnu Wahb], ia berkata; telah memberitakan kepadaku [Yahya bin Ayyub] dan ia menyebutkan yang lain sebelumnya dari ['Umarah bin Ghaziyyah] dari [Abu Az Zubair] dari [Jabir bin Abdullah] ia berkata; ketika perang Uhud dan orang-orang telah mundur, Rasulullah shallallahu 'alaihi wasallam berada diantara dua belas orang Anshar, dan diantara mereka terdapat Tholhah bin Ubaidillah. Kemudian orang-orang musyrikin mendapatkan mereka, lalu Rasulullah shallallahu 'alaihi wasallam menoleh dan bersabda: \"Siapa yang akan menghadang mereka?\" Tholhah menjawab; saya, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tetaplah ditempatmu, \" lalu seorang laki-laki dari kalangan Anshor berkata; saya wahai Rasulullah, beliau bersabda: \" Engkau, \" lalu ia bertempur hingga terbunuh, lalu beliau menoleh, dan ternyata terdapat orang-orang musyrik, beliau bersabda: \"Siapakah yang akan menghadang mereka?\" lalu Tholhah berkata; saya, beliau bersabda: \"Tetaplah di tempatmu\". Kemudian seorang laki-laki dari kalangan Anshor berkata; saya, beliau bersabda: \" Engkau, \" lalu ia bertempur hingga terbunuh. Beliau tiada henti-hentinya mengatakan hal itu dan musuh terus diladeni oleh laki-laki dari kalangan Anshor kemudian bertempur seperti pertempuran orang yang sebelumnya, hingga terbunuh dan tinggallah Rasulullah shallallahu 'alaihi wasallam serta Tholhah bin Ubaidillah, beliau bersabda: \"Siapakah yang menghadapi mereka?\" Tholhah menjawab; saya, lalu ia bertempur seperti pertempuran orang sebelas hingga tangannya terluka dan jari-jarinya terpotong, lalu ia mengucapkan suara pelan, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \" Seandainya engkau mengatakan bismillah, maka malaikat mengangkatmu\", dan orang-orang melihatnya lalu Allah mengalahkan orang-orang musyrik. "},"3007":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ سَوَّادٍ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ وَعَبْدُ اللَّهِ ابْنَا كَعْبِ بْنِ مَالِكٍ أَنَّ سَلَمَةَ بْنَ الْأَكْوَعِ قَالَلَمَّا كَانَ يَوْمُ خَيْبَرَ قَاتَلَ أَخِي قِتَالًا شَدِيدًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَارْتَدَّ عَلَيْهِ سَيْفُهُ فَقَتَلَهُ فَقَالَ أَصْحَابُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ وَشَكُّوا فِيهِ رَجُلٌ مَاتَ بِسِلَاحِهِ قَالَ سَلَمَةُ فَقَفَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ خَيْبَرَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَتَأْذَنُ لِي أَنْ أَرْتَجِزَ بِكَ فَأَذِنَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ اعْلَمْ مَا تَقُولُ فَقُلْتُ وَاللَّهِ لَوْلَا اللَّهُ مَا اهْتَدَيْنَاوَلَا تَصَدَّقْنَا وَلَا صَلَّيْنَافَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَدَقْتَ فَأَنْزِلَنْ سَكِينَةً عَلَيْنَاوَثَبِّتْ الْأَقْدَامَ إِنْ لَاقَيْنَاوَالْمُشْرِكُونَ قَدْ بَغَوْا عَلَيْنَافَلَمَّا قَضَيْتُ رَجَزِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قَالَ هَذَا قُلْتُ أَخِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَرْحَمُهُ اللَّهُ فَقُلْتُ يَا رَسُولَ اللَّهِ وَاللَّهِ إِنَّ نَاسًا لَيَهَابُونَ الصَّلَاةَ عَلَيْهِ يَقُولُونَ رَجُلٌ مَاتَ بِسِلَاحِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَاتَ جَاهِدًا مُجَاهِدًاقَالَ ابْنُ شِهَابٍ ثُمَّ سَأَلْتُ ابْنًا لِسَلَمَةَ بْنِ الْأَكْوَعِ فَحَدَّثَنِي عَنْ أَبِيهِ مِثْلَ ذَلِكَ غَيْرَ أَنَّهُ قَالَ حِينَ قُلْتُ إِنَّ نَاسًا لَيَهَابُونَ الصَّلَاةَ ��َلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَبُوا مَاتَ جَاهِدًا مُجَاهِدًا فَلَهُ أَجْرُهُ مَرَّتَيْنِ وَأَشَارَ بِأُصْبُعَيْهِ","id":"Telah mengabarkan kepada kami ['Amr bin Sawwad], ia berkata; telah memberitakan kepada kami [Ibnu Wahb], ia berkata; telah memberitakan kepadaku [Yunus] dari [Ibnu Syihab], ia berkata; telah memberitakan kepadaku [Abdur Rahman] dan [Abdullah] anak Ka'b bin Malik, bahwa [Salamah bin Al Akwa'] berkata; pada saat perang Khaibar, saudaraku bertempur dengan sengit bersama Rasulullah shallallahu 'alaihi wasallam, kemudian pedangnya berbalik kepadanya kemudian membunuhnya. Kemudian para sahabat Rasulullah shallallahu 'alaihi wasallam membicarakan hal tersebut, dan mengeluhkan hal tersebut; Hiih…..terdapat seorang laki-laki yang mati karena senjatanya. Salamah berkata; kemudian Rasulullah shallallahu 'alaihi wasallam pergi dari Khaibar, lalu saya katakan; wahai Rasulullah, apakah anda mengizinkan saya untuk melantunkan syair bersamamu? Lalu Rasulullah shallallahu 'alaihi wasallam mengizinkannya. Kemudian Umar bin Al Khathab radliallahu 'anhu berkata; sebarkan apa yang engkau katakana. Maka saya dendangkan sebuah syair; demi Allah jika tidak ada Allah, kami tidak mendapat petunjuk, tidak bershadaqah, dan tidak melakukan shalat. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Engkau benar.\" Maka turunkan ketenangan kepada kami, tegarkan kaki kami jika bertemu dengan musuh, dan orang-orang musyrik telah melampaui batas terhadap kami. Tatkala saya menyelesaikan syairku Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah yang mengatakan hal ini?\" saya katakan; saudaraku. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Semoga Allah merahmatinya.\" Kemudian saya katakan; wahai Rasulullah, demi Allah, orang-orang enggan untuk menyalatkannya, dan mereka mengatakan; dia mati karena senjatanya sendiri. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ia meninggal dengan bersungguh-sungguh dan sebagai mujahid.\" Ibnu Syihab berkata; kemudian saya bertanya kepada Ibnu Salamah bin Al Akwa', kemudian ia menceritakan kepadaku dari ayahnya seperti hal tersebut hanya saja ia berkata; ketika saya mengatakan orang-orang enggan untuk menshalatkannya, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Mereka dusta, ia meninggal dengan bersungguh-sungguh dan sebagai mujahid, maka baginya pahala dua kali.\" Dan beliau mengisyaratkan dengan dua jarinya. "},"3008":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى يَعْنِي ابْنَ سَعِيدٍ الْقَطَّانَ عَنْ يَحْيَى يَعْنِي ابْنَ سَعِيدٍ الْأَنْصَارِيَّ قَالَ حَدَّثَنِي ذَكْوَانُ أَبُو صَالِحٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَوْلَا أَنْ أَشُقَّ عَلَى أُمَّتِي لَمْ أَتَخَلَّفْ عَنْ سَرِيَّةٍ وَلَكِنْ لَا يَجِدُونَ حَمُولَةً وَلَا أَجِدُ مَا أَحْمِلُهُمْ عَلَيْهِ وَيَشُقُّ عَلَيْهِمْ أَنْ يَتَخَلَّفُوا عَنِّي وَلَوَدِدْتُ أَنِّي قُتِلْتُ فِي سَبِيلِ اللَّهِ ثُمَّ أُحْيِيتُ ثُمَّ قُتِلْتُ ثُمَّ أُحْيِيتُ ثُمَّ قُتِلْتُ ثَلَاثًا","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya yaitu Ibnu Sa'id Al Qaththan] dari [Yahya yaitu Ibnu Sa'id Al Anshari], ia berkata; telah menceritakan kepadaku [Dzakwan Abu Shaleh] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seandainya saya tidak memberatkan umatku, niscaya saya tidak akan tertinggal dari pasukan, akan tetapi mereka tidak mendapatkan kendaraan dan saya sendiri tidak mendapatkan sesuatu yang dapat mengangkut mereka, dan terasa berat bagi mereka untuk tertinggal dariku. Sungguh saya ingin terbunuh di jalan Allah kemudian dihidupkan kemudian terbunuh kemudian dihidupkan kemudian terbunuh.\" Beliau mengucapkannya sebanyak tiga kali."},"3009":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدٍ قَالَ حَدَّثَنَا أَبِي عَنْ شُعَيْبٍ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ وَالَّذِي نَفْسِي بِيَدِهِ لَوْلَا أَنَّ رِجَالًا مِنْ الْمُؤْمِنِينَ لَا تَطِيبُ أَنْفُسُهُمْ بِأَنْ يَتَخَلَّفُوا عَنِّي وَلَا أَجِدُ مَا أَحْمِلُهُمْ عَلَيْهِ مَا تَخَلَّفْتُ عَنْ سَرِيَّةٍ تَغْزُو فِي سَبِيلِ اللَّهِ وَالَّذِي نَفْسِي بِيَدِهِ لَوَدِدْتُ أَنِّي أُقْتَلُ فِي سَبِيلِ اللَّهِ ثُمَّ أُحْيَا ثُمَّ أُقْتَلُ ثُمَّ أُحْيَا ثُمَّ أُقْتَلُ","id":"Telah mengkhabarkan kepada kami ['Amr bin Utsman bin Sa'id], ia berkata; telah menceritakan kepada kami [ayahku] dari [Syu'aib] dari [Az Zuhri], ia berkata; telah menceritakan kepadaku [Sa'id bin Al Musayyab] dari [Abu Hurairah], ia berkata; saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Dzat yang jiwaku ada di tangan-Nya seandainya tidak ada orang-orang yang beriman yang jiwanya tidak rela untuk tertinggal dariku dan saya tidak mendapatkan kendaraan untuk membawa mereka maka saya tidak akan tertinggal dari mengikuti pasukan yang berperang di jalan Allah 'azza wajalla, dan demi Dzat yang jiwaku ada di tangan-Nya, sungguh saya berharap terbunuh di jalan Allah, kemudian dihidupkan, kemudian terbunuh kemudian dihidupkan kemudian terbunuh.\" "},"3010":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرِ بْنِ سَعْدٍ عَنْ خَالِدِ بْنِ مَعْدَانَ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ ابْنِ أَبِي عَمِيرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا مِنْ النَّاسِ مِنْ نَفْسٍ مُسْلِمَةٍ يَقْبِضُهَا رَبُّهَا تُحِبُّ أَنْ تَرْجِعَ إِلَيْكُمْ وَأَنَّ لَهَا الدُّنْيَا وَمَا فِيهَا غَيْرُ الشَّهِيدِ قَالَ ابْنُ أَبِي عَمِيرَةَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَأَنْ أُقْتَلَ فِي سَبِيلِ اللَّهِ أَحَبُّ إِلَيَّ مِنْ أَنْ يَكُونَ لِي أَهْلُ الْوَبَرِ وَالْمَدَرِ","id":"Telah mengkhabarkan kepada kami ['Amr bin Utsman], ia berkata; telah menceritakan kepada kami [Baqiyah] dari [Bahir bin Sa'd] dari [Khalid bin Ma'dan] dari [Jubair bin Nufair] dari [Ibnu Abi 'Umairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: 'Tidaklah jiwa muslim yang telah dicabut Tuhannya yang ingin kembali kepada kalian, dan sesungguhnya baginya dunia dan seisinya, selain orang yang mati syahid.\" Ibnu Abi 'Amirah berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh terbunuh di jalan Allah lebih aku sukai daripada penduduk padang pasir dan penduduk kota.\" "},"3011":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ سَمِعْتُ جَابِرًا يَقُولُقَالَ رَجُلٌ يَوْمَ أُحُدٍ أَرَأَيْتَ إِنْ قُتِلْتُ فِي سَبِيلِ اللَّهِ فَأَيْنَ أَنَا قَالَ فِي الْجَنَّةِ فَأَلْقَى تَمَرَاتٍ فِي يَدِهِ ثُمَّ قَاتَلَ حَتَّى قُتِلَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr], ia berkata; saya pernah mendengar [Jabir] berkata; seorang laki-laki pada saat perang Uhud berkata; bagaimana pendapat anda apabila saya terbunuh di jalan Allah, dimanakah saya? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Di Surga.\" Lalu orang tersebut mencampakkan beberapa kurma yang ada ditangannya kemudian berperang hingga terbunuh."},"3012":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ يَخْطُبُ عَلَى الْمِنْبَرِ فَقَالَ أَرَأَيْتَ إِنْ قَاتَلْتُ فِي سَبِيلِ اللَّهِ صَابِرًا مُحْتَسِبًا مُقْبِلًا غَيْرَ مُدْبِرٍ أَيُكَفِّرُ اللَّهُ عَنِّي سَيِّئَاتِي قَالَ نَعَمْ ثُمَّ سَكَتَ سَاعَةً قَالَ أَيْنَ السَّائِلُ آنِفًا فَقَالَ الرَّجُلُ هَا أَنَا ذَا قَالَ مَا قُلْتَ قَالَ أَرَأَيْتَ إِنْ قُتِلْتُ فِي سَبِيلِ اللَّهِ صَابِرًا مُحْتَسِبًا مُقْبِلًا غَيْرَ مُدْبِرٍ أَيُكَفِّرُ اللَّهُ عَنِّي سَيِّئَاتِي قَالَ نَعَمْ إِلَّا الدَّيْنَ سَارَّنِي بِهِ جِبْرِيلُ آنِفًا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Abu 'Ashim], ia berkata; telah menceritakan kepada kami [Muhammad bin 'Ajlan] dari [Sa'id Al Maqburi] dari [Abu Hurairah], ia berkata; telah datang seorang laki-laki kepada Nabi shallallahu 'alaihi wasallam dan beliau sedang berkhutbah di atas mimbar, lalu orang tersebut berkata; bagaimana pendapat anda jika saya berperang di jalan Allah dengan bersabar, mengharapkan pahala dan maju tidak mundur, apakah Allah akan mengampuni dosa-dosaku? Beliau menjawab: \"Ya, kecuali hutang. Tadi Jibril telah mengkhabarkannya kepadaku.\""},"3013":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ قُتِلْتُ فِي سَبِيلِ اللَّهِ صَابِرًا مُحْتَسِبًا مُقْبِلًا غَيْرَ مُدْبِرٍ أَيُكَفِّرُ اللَّهُ عَنِّي خَطَايَايَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ فَلَمَّا وَلَّى الرَّجُلُ نَادَاهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْ أَمَرَ بِهِ فَنُودِيَ لَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَيْفَ قُلْتَ فَأَعَادَ عَلَيْهِ قَوْلَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ إِلَّا الدَّيْنَ كَذَلِكَ قَالَ لِي جِبْرِيلُ عَلَيْهِ السَّلَام","id":"Telah mengkhabarkan kepada kami [Muhammad bin Salamah] serta [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Yahya bin Sa'id] dari [Sa'id bin Abi Sa'id] dari [Abdullah bin Abi Qatadah] dari [ayahnya], ia berkata; telah datang seorang laki-laki kepada Rasulullah shallallahu 'alaihi wasallam kemudian berkata; wahai Rasulullah, bagaimana pendapat anda apabila saya terbunuh di jalan Allah dengan bersabar, mengharapkan pahala, dan maju tidak mundur, apakah Allah akan mengampuni dosa-dosaku? Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya.\" Kemudian setelah orang tersebut berpaling, Rasulullah shallallahu 'alaihi wasallam memanggilnya atau beliau memerintahkan untuk memanggil orang tersebut maka orang itupun dipanggil. Kemudian Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apa yang kamu katakan?\" Maka orang tersebut mengulanginya, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya, kecuali hutang. Demikianlah Jibril 'alaihissalam mengatakan kepadaku.\" "},"3014":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِي قَتَادَةَ أَنَّهُ سَمِعَهُ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَامَ فِيهِمْ فَذَكَرَ لَهُمْ أَنَّ الْجِهَادَ فِي سَبِيلِ اللَّهِ وَالْإِيمَانَ بِاللَّهِ أَفْضَلُ الْأَعْمَالِ فَقَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ قُتِلْتُ فِي سَبِيلِ اللَّهِ أَيُكَفِّرُ اللَّهُ عَنِّي خَطَايَايَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ إِنْ قُتِلْتَ فِي سَبِيلِ اللَّهِ وَأَنْتَ صَابِرٌ مُحْتَسِبٌ مُقْبِلٌ غَيْرُ مُدْبِرٍ إِلَّا الدَّيْنَ فَإِنَّ جِبْرِيلَ عَلَيْهِ السَّلَام قَالَ لِي ذَلِكَ","id":"Telah mengkhabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Sa'id bin Abu Sa'id] dari [Abdullah bin Abi Qatadah] dari [Abu Qatadah] bahwa ia mendengarnya menceritakan dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau pernah berdiri diantara mereka kemudian menyebutkan kepada mereka bahwa jihad di jalan Allah serta beriman kepada Allah adalah amalan yang paling utama. Lalu terdapat seorang laki-laki yang berdiri seraya berkata; wahai Rasulullah, bagaimana pendapat anda apabila saya terbunuh di jalan Allah, apakah Allah akan menghapus dosa-dosaku? Maka Rasulullah shallallahu 'alaihi wasallam menjawab: \"Ya, jika engkau terbunuh di jalan Allah dalam keadaan bersabar, mengharapkan pahala, dan maju tidak mundur, kecuali hutang, karena sesungguhnya Jibril 'alaihissalam telah mengatakan demikian kepadaku.\" "},"3015":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو سَمِعَ مُحَمَّدَ بْنَ قَيْسٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي قَتَادَةَ عَنْ أَبِيهِ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ عَلَى الْمِنْبَرِ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ إِنْ ضَرَبْتُ بِسَيْفِي فِي سَبِيلِ اللَّهِ صَابِرًا مُحْتَسِبًا مُقْبِلًا غَيْرَ مُدْبِرٍ حَتَّى أُقْتَلَ أَيُكَفِّرُ اللَّهُ عَنِّي خَطَايَايَ قَالَ نَعَمْ فَلَمَّا أَدْبَرَ دَعَاهُ فَقَالَ هَذَا جِبْرِيلُ يَقُولُ إِلَّا أَنْ يَكُونَ عَلَيْكَ دَيْنٌ","id":"Telah mengkhabarkan kepada kami [Abdul Jabbar bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr], ia telah mendengar [Muhammad bin Qais] dari [Abdullah bin Abi Qatadah] dari [ayahnya], ia berkata; telah datang seorang laki-laki kepada Nabi shallallahu 'alaihi wasallam dan beliau sedang berada di atas mimbar, kemudian orang tersebut berkata; wahai Rasulullah shallallahu 'alaihi wasallam, bagaimana pendapat anda apabila saya menyabetkan pedangku di jalan Allah dalam keadan bersabar, mengharapkan pahala dan maju tidak mundur hingga terbunuh, apakah Allah menghapus dosa-dosaku? Beliau menjawab: \"Ya.\" Kemudian setelah ia berpaling beliau memanggilnya, beliau bersabda: \"Ini Jibril, ia berkata; kecuali engkau memiliki hutang.\""},"3016":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ مُحَمَّدِ بْنِ بَكَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى وَهُوَ ابْنُ الْقَاسِمِ بْنِ سُمَيْعٍ قَالَ حَدَّثَنَا زَيْدُ بْنُ وَاقِدٍ عَنْ كَثِيرِ بْنِ مُرَّةَ أَنَّ عُبَادَةَ بْنَ الصَّامِتِ حَدَّثَهُمْأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا عَلَى الْأَرْضِ مِنْ نَفْسٍ تَمُوتُ وَلَهَا عِنْدَ اللَّهِ خَيْرٌ تُحِبُّ أَنْ تَرْجِعَ إِلَيْكُمْ وَلَهَا الدُّنْيَا إِلَّا الْقَتِيلُ فَإِنَّهُ يُحِبُّ أَنْ يَرْجِعَ فَيُقْتَلَ مَرَّةً أُخْرَى","id":"Telah mengkhabarkan kepada kami [Harun bin Muhammad bin Bakkar], ia berkata; telah menceritakan kepada kami [Muhammad bin Isa yaitu Ibnu Al Qasim bin Sumai'], ia berkata; telah menceritakan kepada kami [Zaid bin Waqid] dari [Katsir bin Murrah] bahwa ['Ubadah bin Ash Shamit] telah menceritakan kepada mereka bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada jiwa dimuka bumi yang meninggal dan di sisi Allah ia memiliki kebaikan yang menginginkan untuk kembali kepada kalian, dan ia memiliki dunia kecuali orang yang terbunuh, sesungguhnya ia ingin kembali kemudian terbunuh lagi.\""},"3017":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ نَافِعٍ قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُؤْتَى بِالرَّجُلِ مِنْ أَهْلِ الْجَنَّةِ فَيَقُولُ اللَّهُ عَزَّ وَجَلَّ يَا ابْنَ آدَمَ كَيْفَ وَجَدْتَ مَنْزِلَكَ فَيَقُولُ أَيْ رَبِّ خَيْرَ مَنْزِلٍ فَيَقُولُ سَلْ وَتَمَنَّ فَيَقُولُ أَسْأَلُكَ أَنْ تَرُدَّنِي إِلَى الدُّنْيَا فَأُقْتَلَ فِي سَبِيلِكِ عَشْرَ مَرَّاتٍ لِمَا يَرَى مِنْ فَضْلِ الشَّهَادَةِ","id":"Telah mengkhabarkan kepada kami [Abu Bakr bin Nafi'], ia berkata; telah menceritakan kepada kami [Bahz], ia berkata; telah menceritakan kepada kami [Hammad] dari [Tsabit] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Didatangkan seorang laki-laki dari penghuni Surga, kemudian Allah 'azza wajalla berfirman: wahai anak Adam, bagaimana engkau mendapati tempat tinggalmu? Maka orang tersebut berkata; wahai Tuhanku, tempat yang terbaik. Kemudian Allah berfirman: Mintalah dan berharaplah. Maka orang tersebut berkata; saya memohon agar Engkau mengembalikanku ke dunia, kemudian terbunuh di jalanMu sepuluh kali. Karena ia melihat sebagian keutamaan mati syahid.\" "},"3018":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا حَاتِمُ بْنُ إِسْمَعِيلَ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ الْقَعْقَاعِ بْنِ حَكِيمٍ عَنْ أَبِي صَالِحٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشَّهِيدُ لَا يَجِدُ مَسَّ الْقَتْلِ إِلَّا كَمَا يَجِدُ أَحَدُكُمْ الْقَرْصَةَ يُقْرَصُهَا","id":"Telah mengkhabarkan kepada kami ['Imran bin Yazid], ia berkata; telah menceritakan kepada kami [Hatim bin Isma'il] dari [Muhammad bin 'Ajlan] dari [Al Qa'qa' bin Hakim] dari [Abu Shalih] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang syahid tidak merasakan terbunuh kecuali sebagaimana salah seorang diantara kalian merasakan cubitan.\""},"3019":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ شُرَيْحٍ أَنَّ سَهْلَ بْنَ أَبِي أُمَامَةَ بْنِ سَهْلِ بْنِ حُنَيْفٍ حَدَّثَهُ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ سَأَلَ اللَّهَ عَزَّ وَجَلَّ الشَّهَادَةَ بِصِدْقٍ بَلَّغَهُ اللَّهُ مَنَازِلَ الشُّهَدَاءِ وَإِنْ مَاتَ عَلَى فِرَاشِهِ","id":"Telah mengkhabarkan kepada kami [Yunus bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah menceritakan kepadaku [Abdur Rahman bin Syuraih] bahwa [Sahl bin Abi Umamah bin Sahl bin Hanif] telah menceritakan kepadanya dari [ayahnya] dari [kakeknya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barangsiapa yang memohon mati syahid kepada Allah Azza wa Jalla dengan benar, maka Allah akan menyampaikannya kepada kedudukan para syuhada` walaupun ia mati diatas kasurnya.\""},"3020":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ شُرَيْحٍ عَنْ عَبْدِ اللَّهِ بْنِ ثَعْلَبَةَ الْحَضْرَمِيِّ أَنَّهُ سَمِعَ ابْنَ حُجَيْرَةَ يُخْبِرُ عَنْ عُقْبَةَ بْنِ عَامِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خَمْسٌ مَنْ قُبِضَ فِي شَيْءٍ مِنْهُنَّ فَهُوَ شَهِيدٌ الْمَقْتُولُ فِي سَبِيلِ اللَّهِ شَهِيدٌ وَالْغَرِقُ فِي سَبِيلِ اللَّهِ شَهِيدٌ وَالْمَبْطُونُ فِي سَبِيلِ اللَّهِ شَهِيدٌ وَالْمَطْعُونُ فِي سَبِيلِ اللَّهِ شَهِيدٌ وَالنُّفَسَاءُ فِي سَبِيلِ اللَّهِ شَهِيدٌ","id":"Telah mengkhabarkan kepada kami [Yunus bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah menceritakan kepadaku [Abdur Rahman bin Syuraih] dari [Abdullah bin Tsa'labah Al Hadhrami] bahwa ia telah mendengar [Ibnu Hujairah] mengabarkan kepadanya dari ['Uqbah bin Amir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lima hal yang jika seseorang mati pada sebagian darinya maka ia syahid, yaitu orang yang terbunuh dijalan Allah adalah orang yang syahid, orang yang tenggelam dijalan Allah adalah orang yang syahid, orang yang sakit perut dijalan Allah adalah orang yang syahid, orang yang terkena terkena sakit pes dijalan Allah adalah orang yang syahid, dan orang yang mati ketika melahirkan di jalan Allah adalah orang yang syahid.\""},"3021":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنَا بَحِيرٌ عَنْ خَالِدٍ عَنْ ابْنِ أَبِي بِلَالٍ عَنْ الْعِرْبَاضِ بْنِ سَارِيَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَخْتَصِمُ الشُّهَدَاءُ وَالْمُتَوَفَّوْنَ عَلَى فُرُشِهِمْ إِلَى رَبِّنَا فِي الَّذِينَ يُتَوَفَّوْنَ مِنْ الطَّاعُونِ فَيَقُولُ الشُّهَدَاءُ إِخْوَانُنَا قُتِلُوا كَمَا قُتِلْنَا وَيَقُولُ الْمُتَوَفَّوْنَ عَلَى فُرُشِهِمْ إِخْوَانُنَا مَاتُوا عَلَى فُرُشِهِمْ كَمَا مُتْنَا فَيَقُولُ رَبُّنَا انْظُرُوا إِلَى جِرَاحِهِمْ فَإِنْ أَشْبَهَ جِرَاحُهُمْ جِرَاحَ الْمَقْتُولِينَ فَإِنَّهُمْ مِنْهُمْ وَمَعَهُمْ فَإِذَا جِرَاحُهُمْ قَدْ أَشْبَهَتْ جِرَاحَهُمْ","id":"Telah mengkhabarkan kepada kami ['Amr bin Utsman], ia berkata; telah menceritakan kepada kami [Baqiyah], ia berkata; telah menceritakan kepada kami [Bahir] dari [Khalid] dari [Ibnu Abi Bilal] dari [Al 'Irbadh bin Sariyah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang-orang yang syahid serta orang-orang yang meninggal di atas kasur mereka saling berselisih kepada Allah mengenai orang-orang yang meninggal karena wabah pes. Orang-orang yang syahid berkata; mereka adalah saudara-saudara kami, mereka terbunuh sebagaimana kami terbunuh. Sedangkan orang-orang yang meninggal di atas kasur mereka berkata; mereka adalah saudara-saudara kami, mereka meninggal di atas kasur mereka sebagaimana kami meninggal. Kemudian Tuhan mereka berfirman: Lihatlah kepada luka mereka, apabila luka mereka serupa dengan luka orang-orang yang terbunuh maka mereka termasuk orang-orang yang terbunuh, dan bersama mereka, dan ternyata luka mereka serupa dengan luka orang-orang yang terbunuh.\""},"3022":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ عَزَّ وَجَلَّ يَعْجَبُ مِنْ رَجُلَيْنِ يَقْتُلُ أَحَدُهُمَا صَاحِبَهُ وَقَالَ مَرَّةً أُخْرَى لَيَضْحَكُ مِنْ رَجُلَيْنِ يَقْتُلُ أَحَدُهُمَا صَاحِبَهُ ثُمَّ يَدْخُلَانِ الْجَنَّةَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Sesungguhnya Allah 'azza wajalla kagum kepada dua orang, salah seorang dari mereka membunuh sahabatnya.\" Dan beliau bersabda lagi: \"Sungguh Allah tertawa karena dua orang, salah seorang dari mereka membunuh sahabatnya, kemudian mereka masuk ke dalam Surga.\""},"3023":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَضْحَكُ اللَّهُ إِلَى رَجُلَيْنِ يَقْتُلُ أَحَدُهُمَا الْآخَرَ كِلَاهُمَا يَدْخُلُ الْجَنَّةَ يُقَاتِلُ هَذَا فِي سَبِيلِ اللَّهِ فَيُقْتَلُ ثُمَّ يَتُوبُ اللَّهُ عَلَى الْقَاتِلِ فَيُقَاتِلُ فَيُسْتَشْهَدُ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Salamah] serta [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Allah tertawa kepada dua orang, salah seorang dari mereka membunuh yang lain, keduanya masuk ke dalam Surga. Orang yang ini berperang di jalan Allah hingga terbunuh, kemudian Allah memberikan taubat kepada orang yang membunuh, hingga ia mati syahid.\" "},"3024":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ شُرَيْحٍ عَنْ عَبْدِ الْكَرِيمِ بْنِ الْحَارِثِ عَنْ أَبِي عُبَيْدَةَ بْنِ عُقْبَةَ عَنْ شُرَحْبِيلَ بْنِ السِّمْطِ عَنْ سَلْمَانَ الْخَيْرِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ رَابَطَ يَوْمًا وَلَيْلَةً فِي سَبِيلِ اللَّهِ كَانَ لَهُ كَأَجْرِ صِيَامِ شَهْرٍ وَقِيَامِهِ وَمَنْ مَاتَ مُرَابِطًا أُجْرِيَ لَهُ مِثْلُ ذَلِكَ مِنْ الْأَجْرِ وَأُجْرِيَ عَلَيْهِ الرِّزْقُ وَأَمِنَ مِنْ الْفَتَّانِ","id":"Telah mengkhabarkan kepada kami [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Wahb], telah mengkhabarkan kepadaku [Abdur Rahman bin Syuraih] dari [Abdul Karim bin Al Harits] dari [Abu 'Ubaidah bin 'Uqbah] dari [Syurahbil bin As Simth] dari [Salman Al Khair] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa yang berjaga sehari semalam di jalan Allah, maka baginya seperti pahala berpuasa dan shalat satu bulan. Dan barang siapa yang meninggal dalam berjaga maka diberikan kepadanya pahala seperti itu dan ia diberi rizqi serta akan mendapat keamanan dari pemberi fitnah.\""},"3025":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي أَيُّوبُ بْنُ مُوسَى عَنْ مَكْحُولٍ عَنْ شُرَحْبِيلَ بْنِ السِّمْطِ عَنْ سَلْمَانَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ رَابَطَ فِي سَبِيلِ اللَّهِ يَوْمًا وَلَيْلَةً كَانَتْ لَهُ كَصِيَامِ شَهْرٍ وَقِيَامِهِ فَإِنْ مَاتَ جَرَى عَلَيْهِ عَمَلُهُ الَّذِي كَانَ يَعْمَلُ وَأَمِنَ الْفَتَّانَ وَأُجْرِيَ عَلَيْهِ رِزْقُهُ","id":"Telah mengkhabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Abdullah bin Yusuf], ia berkata; telah menceritakan kepada kami [Al Laits], ia berkata; telah menceritakan kepadaku [Ayyub bin Musa] dari [Makhul] dari [Syurahbil bin As Simth] dari [Salman], ia berkata; saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam berfirman: \"Barang siapa yang berjaga di jalan Allah sehari semalam maka baginya seperti puasa dan shalat satu bulan, dan jika ia meninggal maka amalnya yang telah ia lakukan mengalir pahalanya kepadanya dan ia aman dari pemberi fitnah, dan diberi rizqi.\""},"3026":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ زُهْرَةَ بْنِ مَعْبَدٍ قَالَ حَدَّثَنِي أَبُو صَالِحٍ مَوْلَى عُثْمَانَ قَالَ سَمِعْتُ عُثْمَانَ بْنَ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ رِبَاطُ يَوْمٍ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ أَلْفِ يَوْمٍ فِيمَا سِوَاهُ مِنْ الْمَنَازِلِ","id":"Telah mengkhabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Abdullah bin Yusuf], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Zahrah bin Ma'bad], ia berkata; telah menceritakan kepadaku [Abu Shalih] sahaya Utsman, ia berkata; saya mendengar [Utsman bin Affan] radliallahu 'anhu berkata; saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berjaga satu hari di jalan Allah adalah lebih baik daripada seribu hari di tempat-tempat selainnya.\""},"3027":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا ابْنُ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو مَعْنٍ قَالَ حَدَّثَنَا زُهْرَةُ بْنُ مَعْبَدٍ عَنْ أَبِي صَالِحٍ مَوْلَى عُثْمَانَ قَالَ قَالَ عُثْمَانُ بْنُ عَفَّانَ رَضِيَ اللَّهُ عَنْهُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَوْمٌ فِي سَبِيلِ اللَّهِ خَيْرٌ مِنْ أَلْفِ يَوْمٍ فِيمَا سِوَاهُ","id":"Telah mengkhabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Abdur Rahman bin Mahdi], ia berkata; telah menceritakan kepada kami [Ibnu Al Mubarak], ia berkata; telah menceritakan kepada kami [Abu Ma'n], ia berkata; telah menceritakan kepada kami [Zuhrah bin Ma'bad] dari [Abu Shalih] sahaya Utsman, ia berkata; [Utsman bin Affan] radliallahu 'anhu berkata; saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu hari di jalan Allah lebih baik daripada seribu hari selainnya.\""},"3028":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذَا ذَهَبَ إِلَى قُبَاءَ يَدْخُلُ عَلَى أُمِّ حَرَامٍ بِنْتِ مِلْحَانَ فَتُطْعِمُهُ وَكَانَتْ أُمُّ حَرَامٍ بِنْتُ مِلْحَانَ تَحْتَ عُبَادَةَ بْنِ الصَّامِتِ فَدَخَلَ عَلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمًا فَأَطْعَمَتْهُ وَجَلَسَتْ تَفْلِي رَأْسَهُ فَنَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ اسْتَيْقَظَ وَهُوَ يَضْحَكُ قَالَتْ فَقُلْتُ مَا يُضْحِكُكَ يَا رَسُولَ اللَّهِ قَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ غُزَاةً فِي سَبِيلِ اللَّهِ يَرْكَبُونَ ثَبَجَ هَذَا الْبَحْرِ مُلُوكٌ عَلَى الْأَسِرَّةِ أَوْ مِثْلُ الْمُلُوكِ عَلَى الْأَسِرَّةِ شَكَّ إِسْحَقُ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ فَدَعَا لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثُمَّ نَامَ وَقَالَ الْحَارِثُ فَنَامَ ثُمَّ اسْتَيْقَظَ فَضَحِكَ فَقُلْتُ لَهُ مَا يُضْحِكُكَ يَا رَسُولَ اللَّهِ قَالَ نَاسٌ مِنْ أُمَّتِي عُرِضُوا عَلَيَّ غُزَاةً فِي سَبِيلِ اللَّهِ مُلُوكٌ عَلَى الْأَسِرَّةِ أَوْ مِثْلُ الْمُلُوكِ عَلَى الْأَسِرَّةِ كَمَا قَالَ فِي الْأَوَّلِ فَقُلْتُ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَ فَرَكِبَتْ الْبَحْرَ فِي زَمَانِ مُعَاوِيَةَ فَصُرِعَتْ عَنْ دَابَّتِهَا حِينَ خَرَجَتْ مِنْ الْبَحْرِ فَهَلَكَتْ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Salamah] serta [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Ishaq bin Abdullah bin Abi Thalhah] dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam apabila pergi ke Quba, beliau menemui Ummu Haram binti Milhan, lalu ia memberinya makan. Ummu Haram binti Milhan adalah isteri Ubadah bin Shamit. Pada suatu hari beliau menemuinya, lalu ia memberi makan beliau, dan duduk serta membersihkan kepala Rasulullah shallallahu 'alaihi wasallam. Lalu Rasulullah shallallahu 'alaihi wasallam tertidur kemudian terbangun sambil tertawa. Ummu Haran berkata; lalu saya katakan; apakah yang menyebabkanmu tertawa wahai Rasulullah shallallahu 'alaihi wasallam? Beliau menjawab: \"Ada orang-orang dari kalangan umatku diperlihatkan kepadaku sebagai orang-orang yang berperang di jalan Allah, mereka mengarungi tengah laut ini, mereka adalah para raja di atas ranjang-ranjang atau seperti raja-raja di atas ranjang-ranjang.\" Sebagaimana pertama beliau berbicara. Kemudian saya katakan; wahai Rasulullah, berdoalah kepada Allah agar menjadikanku bagian dari mereka. Beliau bersabda: \"Engkau bagian dari mereka.\" Beliau bersabda: \"Engkau termasuk orang-orang yang pertama.\" Lalu Ummu Haran mengarungi lautan pada zaman Mu'awiyah, kemudian ia terjatuh dari kendaraannya ketika keluar dari laut hingga meninggal. "},"3029":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ أَنَسِ بْنِ مَالِكٍ عَنْ أُمِّ حَرَامٍ بِنْتِ مِلْحَانَ قَالَتْأَتَانَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عِنْدَنَا فَاسْتَيْقَظَ وَهُوَ يَضْحَكُ فَقُلْتُ يَا رَسُولَ اللَّهِ بِأَبِي وَأُمِّي مَا أَضْحَكَكَ قَالَ رَأَيْتُ قَوْمًا مِنْ أُمَّتِي يَرْكَبُونَ هَذَا الْبَحْرَ كَالْمُلُوكِ عَلَى الْأَسِرَّةِ قُلْتُ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ فَإِنَّكِ مِنْهُمْ ثُمَّ نَامَ ثُمَّ اسْتَيْقَظَ وَهُوَ يَضْحَكُ فَسَأَلْتُهُ فَقَالَ يَعْنِي مِثْلَ مَقَالَتِهِ قُلْتُ ادْعُ اللَّهَ أَنْ يَجْعَلَنِي مِنْهُمْ قَالَ أَنْتِ مِنْ الْأَوَّلِينَ فَتَزَوَّجَهَا عُبَادَةُ بْنُ الصَّامِتِ فَرَكِبَ الْبَحْرَ وَرَكِبَتْ مَعَهُ فَلَمَّا خَرَجَتْ قُدِّمَتْ لَهَا بَغْلَةٌ فَرَكِبَتْهَا فَصَرَعَتْهَا فَانْدَقَّتْ عُنُقُهَا","id":"Telah mengkhabarkan kepada kami [Yahya bin Habib bin 'Arabi], ia berkata; telah menceritakan kepada kami [Hammad] dari [Yahya bin Sa'id] dari [Muhammad bin Yahya bin Habban] dari [Anas bin Malik] dari [Ummu Haran binti Milhan], ia berkata; Rasulullah shallallahu 'alaihi wasallam datang kepada kami dan tidur siang di tempat kami, kemudian beliau terbangun dalam keadaan tertawa, lalu saya katakan; wahai Rasulullah, dengan ayah dan ibuku. Apakah yang menyebabkan anda tertawa? Beliau menjawab: \"Saya bermimpi melihat suatu kaum dari umatku, mereka mengarungi lautan ini seperti para raja di atas ranjang-ranjang.\" Maka saya mengatakan; berdoalah kepada Allah agar menjadikanku bagian dari mereka. Beliau bersabda: \"Engkau bagian dari mereka.\" Kemudian beliau tidur, kemudian terbangun dan tertawa. Lalu saya bertanya kepadanya; kemudian beliau bersabda seperti perkataannya semula. Maka saya katakan; berdoalah kepada Allah agar menjadikanku bagian dari mereka. Beliau bersabda: \"Engkau termasuk orang-orang yang pertama.\" Lalu Ummu Haran dinikahi 'Ubadah bin Shamit, kemudian mengarungi lautan, dan Ummu haran mengarungi bersamanya. Tatkala ia keluar, ia diberi seekor Bighal, lalu ia menaikinya kemudian terjatuh dan lehernya patah. "},"3030":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ عَدِيٍّ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ زَيْدِ بْنِ أَبِي أُنَيْسَةَ عَنْ سَيَّارٍ ح قَالَ وَأَنْبَأَنَا هُشَيْمٌ عَنْ سَيَّارٍ عَنْ جَبْرِ بْنِ عَبِيدَةَ وَقَالَ عُبَيْدُ اللَّهِ عَنْ جُبَيْرٍ عَنْ أَبِي هُرَيْرَةَ قَالَوَعَدَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ الْهِنْدِ فَإِنْ أَدْرَكْتُهَا أُنْفِقْ فِيهَا نَفْسِي وَمَالِي فَإِنْ أُقْتَلْ كُنْتُ مِنْ أَفْضَلِ الشُّهَدَاءِ وَإِنْ أَرْجِعْ فَأَنَا أَبُو هُرَيْرَةَ الْمُحَرَّرُ","id":"Telah mengkhabarkan kepada kami [Ahmad bin Utsman bin Hakim], ia berkata; telah menceritakan kepada kami [Zakariya bin 'Adi], ia berkata; telah menceritakan kepada kami ['Ubaidullah bin 'Amr] dari [Zaid bin Abi Unaisah] dari [Sayyar]. -dari jalur periwayatan yang lain disebutkan; Telah memberitakan kepada kami [Husyaim] dari [Sayyar] dari [Jabar bin 'Ubaidah], -menurut ucapan 'Ubaidullah dari Jubair- dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menjanjikan kepada kami untuk memerangi India, apabila peperang tersebut mendapati diriku maka akan saya infakkan jiwa dan hartaku padanya. Sehingga apabila saya terbunuh maka saya termasuk orang-orang syahid yang paling utama, dan apabila saya kembali maka saya adalah Abu Hurairah yang dimerdekakan. "},"3031":{"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ أَنْبَأَنَا هُشَيْمٌ قَالَ حَدَّثَنَا سَيَّارٌ أَبُو الْحَكَمِ عَنْ جَبْرِ بْنِ عَبِيدَةَ عَنْ أَبِي هُرَيْرَةَ قَالَوَعَدَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزْوَةَ الْهِنْدِ فَإِنْ أَدْرَكْتُهَا أُنْفِقْ فِيهَا نَفْسِي وَمَالِي وَإِنْ قُتِلْتُ كُنْتُ أَفْضَلَ الشُّهَدَاءِ وَإِنْ رَجَعْتُ فَأَنَا أَبُو هُرَيْرَةَ الْمُحَرَّرُ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim], ia berkata; telah menceritakan kepada kami [Yazid], ia berkata; telah memberitakan kepada kami [Husyaim], ia berkata; telah menceritakan kepada kami [Sayyar Abu Al Hakam] dari [Jabar bin 'Ubaidah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah menjanjikan kepada kami untuk memerangi India, apabila peperang tersebut mendapati diriku maka akan saya infakkan jiwa dan hartaku padanya. Sehingga apabila saya terbunuh maka saya adalah orang syahid yang paling utama, dan apabila saya kembali maka saya adalah Abu Hurairah yang dimerdekakan. "},"3032":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنَا أَسَدُ بْنُ مُوسَى قَالَ حَدَّثَنَا بَقِيَّةُ قَالَ حَدَّثَنِي أَبُو بَكْرٍ الزُّبَيْدِيُّ عَنْ أَخِيهِ مُحَمَّدِ بْنِ الْوَلِيدِ عَنْ لُقْمَانَ بْنِ عَامِرٍ عَنْ عَبْدِ الْأَعْلَى بْنِ عَدِيٍّ الْبَهْرَانِيِّ عَنْ ثَوْبَانَ مَوْلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِصَابَتَانِ مِنْ أُمَّتِي أَحْرَزَهُمَا اللَّهُ مِنْ النَّارِ عِصَابَةٌ تَغْزُو الْهِنْدَ وَعِصَابَةٌ تَكُونُ مَعَ عِيسَى ابْنِ مَرْيَمَ عَلَيْهِمَا السَّلَام","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah bin Abdur Rahim], ia berkata; telah menceritakan kepada kami [Asad bin Musa], ia berkata; telah menceritakan kepada kami [Baqiyah], ia berkata; telah menceritakan kepadaku [Abu Bakr Az Zubaidi] dari saudaranya yaitu [Muhammad bin Al Walid] dari [Luqman bin 'Amir] dari [Abdul A'la bin 'Adi Al Bahrani] dari [Tsauban] sahaya Rasulullah shallallahu 'alaihi wasallam, ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Dua kelompok dari umatku yang Allah jaga dari Neraka, yaitu kelompok yang memerangi India, dan kelompok yang bersama dengan Isa bin Maryam 'alaihimas salam.\""},"3033":{"ar":"أَخْبَرَنَا عِيسَى بْنُ يُونُسَ قَالَ حَدَّثَنَا ضَمْرَةُ عَنْ أَبِي زُرْعَةَ السَّيْبَانِيِّ عَنْ أَبِي سُكَيْنَةَ رَجُلٍ مِنْ الْمُحَرَّرِينَ عَنْ رَجُلٍ مَنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَلَمَّا أَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِحَفْرِ الْخَنْدَقِ عَرَضَتْ لَهُمْ صَخْرَةٌ حَالَتْ بَيْنَهُمْ وَبَيْنَ الْحَفْرِ فَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَخَذَ الْمِعْوَلَ وَوَضَعَ رِدَاءَهُ نَاحِيَةَ الْخَنْدَقِ وَقَالَ تَمَّتْ كَلِمَةُ رَبِّكَ صِدْقًا وَعَدْلًا لَا مُبَدِّلَ لِكَلِمَاتِهِ وَهُوَ السَّمِيعُ الْعَلِيمُ فَنَدَرَ ثُلُثُ الْحَجَرِ وَسَلْمَانُ الْفَارِسِيُّ قَائِمٌ يَنْظُرُ فَبَرَقَ مَعَ ضَرْبَةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَرْقَةٌ ثُمَّ ضَرَبَ الثَّانِيَةَ وَقَالَ تَمَّتْ كَلِمَةُ رَبِّكَ صِدْقًا وَعَدْلًا لَا مُبَدِّلَ لِكَلِمَاتِهِ وَهُوَ السَّمِيعُ الْعَلِيمُ فَنَدَرَ الثُّلُثُ الْآخَرُ فَبَرَقَتْ بَرْقَةٌ فَرَآهَا سَلْمَانُ ثُمَّ ضَرَبَ الثَّالِثَةَ وَقَالَ تَمَّتْ كَلِمَةُ رَبِّكَ صِدْقًا وَعَدْلًا لَا مُبَدِّلَ لِكَلِمَاتِهِ وَهُوَ السَّمِيعُ الْعَلِيمُ فَنَدَرَ الثُّلُثُ الْبَاقِي وَخَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخَذَ رِدَاءَهُ وَجَلَسَ قَالَ سَلْمَانُ يَا رَسُولَ اللَّهِ رَأَيْتُكَ حِينَ ضَرَبْتَ مَا تَضْرِبُ ضَرْبَةً إِلَّا كَانَتْ مَعَهَا بَرْقَةٌ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا سَلْمَانُ رَأَيْتَ ذَلِكَ فَقَالَ إِي وَالَّذِي بَعَثَكَ بِالْحَقِّ يَا رَسُولَ اللَّهِ قَالَ فَإِنِّي حِينَ ضَرَبْتُ الضَّرْبَةَ الْأُولَى رُفِعَتْ لِي مَدَائِنُ كِسْرَى وَمَا حَوْلَهَا وَمَدَائِنُ كَثِيرَةٌ حَتَّى رَأَيْتُهَا بِعَيْنَيَّ قَالَ لَهُ مَنْ حَضَرَهُ مِنْ أَصْحَابِهِ يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَفْتَحَهَا عَلَيْنَا وَيُغَنِّمَنَا دِيَارَهُمْ وَيُخَرِّبَ بِأَيْدِينَا بِلَادَهُمْ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ ثُمَّ ضَرَبْتُ الضَّرْبَةَ الثَّانِيَةَ فَرُفِعَتْ لِي مَدَائِنُ قَيْصَرَ وَمَا حَوْلَهَا حَتَّى رَأَيْتُهَا بِعَيْنَيَّ قَالُوا يَا رَسُولَ اللَّهِ ادْعُ اللَّهَ أَنْ يَفْتَحَهَا عَلَيْنَا وَيُغَنِّمَنَا دِيَارَهُمْ وَيُخَرِّبَ بِأَيْدِينَا بِلَادَهُمْ فَدَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ ثُمَّ ضَرَبْتُ الثَّالِثَةَ فَرُفِعَتْ لِي مَدَائِنُ الْحَبَشَةِ وَمَا حَوْلَهَا مِنْ الْقُرَى حَتَّى رَأَيْتُهَا بِعَيْنَيَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ دَعُوا الْحَبَشَةَ مَا وَدَعُوكُمْ وَاتْرُكُوا التُّرْكَ مَا تَرَكُوكُمْ","id":"Telah mengkhabarkan kepada kami [Isa bin Yunus], ia berkata; telah menceritakan kepada kami [Dhamrah] dari [Abu Zur'ah As Saibani] dari [Abu Sukainah] yaitu seseorang yang telah dimerdekakan dari [seorang sahabat Nabi] shallallahu 'alaihi wasallam, ia berkata; tatkala Nabi shallallahu 'alaihi wasallam memerintah untuk menggali parit, tampaklah sebuah batu besar yang menghalangi penggalian parit, lalu Rasulullah shallallahu 'alaihi wasallam mengambil cangkul, lalu meletakkan surbannya disamping parit dan bersabda: \"Telah sempurnalah kalimat Tuhanmu (Al Quran) sebagai kalimat yang benar dan adil. tidak ada yang dapat merubah-rubah kalimat-kalimatNya dan Dia lah yang Maha Mendengar lagi Maha Mengetahui, \" kemudian robohlah sepertiga batu dan Salman Al Farisi berdiri melihat lalu bersamaan dengan pukulan Rasulullah shallallahu 'alaihi wasallam muncullah kilatan cahaya, lalu beliau memukul kedua kalinya dan bersabda: \"Telah sempurnalah kalimat Tuhanmu (Al Quran) sebagai kalimat yang benar dan adil. tidak ada yang dapat merubah-rubah kalimat-kalimatNya dan Dia lah yang Maha Mendengar lagi Maha Mengetahui, \" lalu robohlah sepertiga lainnya dan muncullah kilatan cahaya, dan Salman melihatnya, kemudian beliau memukul untuk ketiga kalinya dan bersabda: \"Telah sempurnalah kalimat Tuhanmu (Al Quran) sebagai kalimat yang benar dan adil. tidak ada yang dapat merubah-rubah kalimat-kalimatNya dan Dia lah yang Maha Mendengar lagi Maha Mengetahui, \" dan robohlah sepertiga sisanya, kemudian Rasulullah shallallahu 'alaihi wasallam keluar dan mengambil selendangnya lalu beliau duduk, Salman berkata; wahai Rasulullah, saya melihatmu ketika engkau memukul, engkau tidak memukul satu pukulan kecuali bersamanya keluar kilatan cahaya, Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Hai Salman apakah engkau melihatnya?\" ia menjawab; ya, demi Dzat yang mengutusmu dengan kebenaran. Beliau bersabda: \"Ketika aku memukul pertama kali, ditampakkan kepadaku kota-kota Kisra dan apa yang ada disekitarnya serta kota-kota yang banyak hingga aku melihatnya dengan kedua mataku, \" para sahabat yang menghadirinya berkata; wahai Rasulullah, berdoalah kepada Allah agar Dia bukakan kota-kota tersebut bagi kita, dan memberikan kepada kita rumah-rumah mereka dan meruntuhkan negeri mereka dengan tangan-tangan kita. Lalu Rasulullah shallallahu 'alaihi wasallam mendoakan hal itu, beliau bersabda: \" Kemudian aku memukul kedua kalinya, ditampakkan kepadaku kota-kota Qaisar dan apa yang ada disekitarnya hingga aku melihatnya dengan kedua mataku, \" para sahabat berkata; wahai Rasulullah, berdoalah kepada Allah agar Dia bukakan kota-kota tersebut bagi kita, dan memberikan kepada kita rumah-rumah mereka dan meruntuhkan negeri mereka dengan tangan-tangan kita. Lalu Rasulullah shallallahu 'alaihi wasallam mendoakan hal itu, beliau bersabda: \" lalu aku memukul untuk ketiga kali, lalu ditampakkan kepadaku kota-kota Habasyah dan desa-desa yang ada disekitarnya, hingga aku melihatnya dengan kedua mataku, \" lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tinggalkanlah Habasyah selama mereka mengucapkan perpisahan kepada kalian, dan tinggalkan Turki selama mereka meninggalkan kalian.\""},"3034":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَعْقُوبُ عَنْ سُهَيْلٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تَقُومُ السَّاعَةُ حَتَّى يُقَاتِلَ الْمُسْلِمُونَ التُّرْكَ قَوْمًا وُجُوهُهُمْ كَالْمَجَانِّ الْمُطْرَقَةِ يَلْبَسُونَ الشَّعَرَ وَيَمْشُونَ فِي الشَّعَرِ","id":"Telah mengkhabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Ya'qub] dari [Suhail] dari [ayahnya] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak akan bangkit Hari Kiamat hingga orang-orang muslim memerangi Turki, orang-orang yang wajah mereka seperti tameng yang ditempa, mereka memakai rambut, dan berjalan di atas rambut.\""},"3035":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِدْرِيسَ قَالَ حَدَّثَنَا عُمَرُ بْنُ حَفْصِ بْنِ غِيَاثٍ عَنْ أَبِيهِ عَنْ مِسْعَرٍ عَنْ طَلْحَةَ بْنِ مُصَرِّفٍ عَنْ مُصْعَبِ بْنِ سَعْدٍ عَنْ أَبِيهِأَنَّهُ ظَنَّ أَنَّ لَهُ فَضْلًا عَلَى مَنْ دُونَهُ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا يَنْصُرُ اللَّهُ هَذِهِ الْأُمَّةَ بِضَعِيفِهَا بِدَعْوَتِهِمْ وَصَلَاتِهِمْ وَإِخْلَاصِهِمْ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Idris], ia berkata; telah menceritakan kepada kami [Umar bin Hafsh bin Ghiyats] dari [ayahnya] dari [Mis'ar] dari [Thalhah bin Musharrif] dari [Mush'ab bin Sa'd] dari [ayahnya] bahwa ia menyangka bahwa ia memiliki keutamaan di atas orang selainnya dari kalangan para sahabat nabi shallallahu 'alaihi wasallam. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya Allah menolong umat ini dengan orang lemahnya, dengan doa mereka, shalat mereka, dan keikhlasan mereka.\""},"3036":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ عُثْمَانَ قَالَ حَدَّثَنَا عُمَرُ بْنُ عَبْدِ الْوَاحِدِ قَالَ حَدَّثَنَا ابْنُ جَابِرٍ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَرْطَاةَ الْفَزَارِيُّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ الْحَضْرَمِيِّ أَنَّهُ سَمِعَ أَبَا الدَّرْدَاءِ يَقُولُسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ ابْغُونِي الضَّعِيفَ فَإِنَّكُمْ إِنَّمَا تُرْزَقُونَ وَتُنْصَرُونَ بِضُعَفَائِكُمْ","id":"Telah mengkhabarkan kepada kami [Yahya bin Utsman], ia berkata; telah menceritakan kepada kami [Umar bin Abdul Wahid], ia berkata; telah menceritakan kepada kami [Ibnu Jabir], ia berkata; telah menceritakan kepadaku [Zaid bin Arthah Al Fazari] dari [Jubair bin Nufair Al Hadhrami] bahwa ia pernah mendengar [Abu Ad Darda`] berkata; saya pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Carikan untukku orang yang lemah, sesungguhnya kalian mendapatkan rizqi dan mendapat kemenangan karena orang-orang lemah kalian.\""},"3037":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي عَمْرُو بْنُ الْحَارِثِ عَنْ بُكَيْرِ بْنِ الْأَشَجِّ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ جَهَّزَ غَازِيًا فِي سَبِيلِ اللَّهِ فَقَدْ غَزَا وَمَنْ خَلَفَهُ فِي أَهْلِهِ بِخَيْرٍ فَقَدْ غَزَا","id":"Telah mengkhabarkan kepada kami [Sulaiman bin Daud] serta [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Wahb], ia berkata; telah mengkhabarkan kepadaku ['Amr bin Al Harits] dari [Bukair bin Al Asyaj] dari [Busr bin Sa'id] dari [Zaid bin Khalid] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barang siapa yang mempersiapkan pejuang di jalan Allah maka sungguh ia telah berperang, dan barang siapa yang menyantuni keluarganya dengan kebaikan maka sungguh ia telah berperang.\""},"3038":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ عَبْدِ الرَّحْمَنِ بْنِ مَهْدِيٍّ قَالَ حَدَّثَنَا حَرْبُ بْنُ شَدَّادٍ عَنْ يَحْيَى عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ بُسْرِ بْنِ سَعِيدٍ عَنْ زَيْدِ بْنِ خَالِدٍ الْجُهَنِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ جَهَّزَ غَازِيًا فَقَدْ غَزَا وَمَنْ خَلَفَ غَازِيًا فِي أَهْلِهِ بِخَيْرٍ فَقَدْ غَزَا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Abdur Rahman bin Mahdi], ia berkata; telah menceritakan kepada kami [Harb bin Syaddad] dari [Yahya] dari [Abu Salamah bin Abdur Rahman] dari [Busr bin Sa'id] dari [Zaid bin Khalid Al Juhani], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang mempersiapkan pejuang maka sungguh ia telah berperang, dan barang siapa yang menyantuni seorang pejuang pada keluarganya dengan kebaikan maka sungguh ia telah berjuang.\""},"3039":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ سَمِعْتُ حُصَيْنَ بْنَ عَبْدِ الرَّحْمَنِ يُحَدِّثُ عَنْ عَمْرِو بْنِ جَاوَانَ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ قَالَخَرَجْنَا حُجَّاجًا فَقَدِمْنَا الْمَدِينَةَ وَنَحْنُ نُرِيدُ الْحَجَّ فَبَيْنَا نَحْنُ فِي مَنَازِلِنَا نَضَعُ رِحَالَنَا إِذْ أَتَانَا آتٍ فَقَالَ إِنَّ النَّاسَ قَدْ اجْتَمَعُوا فِي الْمَسْجِدِ وَفَزِعُوا فَانْطَلَقْنَا فَإِذَا النَّاسُ مُجْتَمِعُونَ عَلَى نَفَرٍ فِي وَسَطِ الْمَسْجِدِ وَفِيهِمْ عَلِيٌّ وَالزُّبَيْرُ وَطَلْحَةُ وَسَعْدُ بْنُ أَبِي وَقَّاصٍ فَإِنَّا لَكَذَلِكَ إِذْ جَاءَ عُثْمَانُ رَضِيَ اللَّهُ عَنْهُ عَلَيْهِ مُلَاءَةٌ صَفْرَاءُ قَدْ قَنَّعَ بِهَا رَأْسَهُ فَقَالَ أَهَاهُنَا طَلْحَةُ أَهَاهُنَا الزُّبَيْرُ أَهَاهُنَا سَعْدٌ قَالُوا نَعَمْ قَالَ فَإِنِّي أَنْشُدُكُمْ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يَبْتَاعُ مِرْبَدَ بَنِي فُلَانٍ غَفَرَ اللَّهُ لَهُ فَابْتَعْتُهُ بِعِشْرِينَ أَلْفًا أَوْ بِخَمْسَةٍ وَعِشْرِينَ أَلْفًا فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ اجْعَلْهُ فِي مَسْجِدِنَا وَأَجْرُهُ لَكَ قَالُوا اللَّهُمَّ نَعَمْ قَالَ أَنْشُدُكُمْ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ ابْتَاعَ بِئْرَ رُومَةَ غَفَرَ اللَّهُ لَهُ فَابْتَعْتُهَا بِكَذَا وَكَذَا فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ قَدْ ابْتَعْتُهَا بِكَذَا وَكَذَا قَالَ اجْعَلْهَا سِقَايَةً لَلْمُسْلِمِينَ وَأَجْرُهَا لَكَ قَالُوا اللَّهُمَّ نَعَمْ قَالَ أَنْشُدُكُمْ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَظَرَ فِي وُجُوهِ الْقَوْمِ فَقَالَ مَنْ يُجَهِّزُ هَؤُلَاءِ غَفَرَ اللَّهُ لَهُ يَعْنِي جَيْشَ الْعُسْرَةِ فَجَهَّزْتُهُمْ حَتَّى لَمْ يَفْقِدُوا عِقَالًا وَلَا خِطَامًا فَقَالُوا اللَّهُمَّ نَعَمْ قَالَ اللَّهُمَّ اشْهَدْ اللَّهُمَّ اشْهَدْ اللَّهُمَّ اشْهَدْ","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Abdulah bin Idris], ia berkata; saya mendengar [Hushain bin Abdur Rahman] menceritakan dari ['Amr bin Jawan] dari [Al Ahnaf bin Qais], ia berkata; kami pernah keluar untuk melakukan haji, lalu kami datang ke Madinah dan kami ingin melakukan haji. Ketika kami berada di rumah kami dan menambatkan kendaraan kami, tiba-tiba datang seseorang kepada kami seraya berkata; sesungguhnya orang-orang telah berkumpul di Masjid dan mereka merasa kaget. Maka kami berangkat ke masjid, ternyata orang-orang sedang berkumpul mengelilingi beberapa orang di tengah masjid, dan diantara mereka terdapat [Ali], [Az Zubair] serta [Thalhah], dan [Sa'd bin Abi Waqqash]. Disaat kami dalam keadaan demikian, tiba-tiba [Utsman] radliallahu 'anhu datang memakai baju kurung kuning, dan menutup kepalanya dengan baju tersebut, seraya berkata; apakah di sini terdapat Thalhah? Apakah di sini terdapat Az Zubair? Apakah di sini terdapat Sa'd? mereka berkata; ya. Utsman berkata; sungguh saya bertanya kepada kalian dan bersumpah dengan nama Allah yang tidak ada Tuhan yang berhak disembah kecuali Dia. Apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Barang siapa yang membeli tempat penambatan unta milik Bani Fulan, maka Allah akan mengampuninya.\" Maka saya membelinya dengan harga dua puluh ribu atau dua puluh lima ribu, kemudian saya datang kepada Rasulullah shallallahu 'alaihi wasallam dan mengkhabarkan kepadanya. Lalu beliau bersabda: \"Jadikanlah berada di masjid kita, dan pahalanya untukmu.\" Mereka mengatakan; ya. Utsman berkata; saya bertanya dan bersumpah dengan nama Allah yang tidak ada Tuhan yang berhak disembah kecuali Dia. Apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Barang siapa yang membeli sumur Rumah, maka Allah akan mengampuninya.\" Maka saya membelinya dengan harga sekian dan sekian, kemudian saya datang kepada Rasulullah shallallahu 'alaihi wasallam dan mengatakan; saya telah membelinya dengan harga sekian dan sekian. Lalu beliau bersabda: \"Jadikanlah untuk memberi minum orang-orang muslim dan pahalanya untukmu.\" Mereka mengatakan; ya. Utsman berkata; saya bertanya dan bersumpah dengan nama Allah yang tidak ada Tuhan yang berhak disembah kecuali Dia, apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam pernah melihat ke wajah beberapa orang lalu bersabda: \"Barang siapa yang mempersiapkan mereka, maka Allah akan mengampuninya.\" Yaitu pasukan Al 'Usrah, maka saya mempersiapkan mereka hingga mereka tidak kehilangan satu tali unta dan satu tali kendalipun. Maka mereka berkata; ya. Utsman berkata; ya Allah saksikanlah, ya Allah saksikanlah, ya Allah saksikanlah. "},"3040":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ حُمَيْدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَنْفَقَ زَوْجَيْنِ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ نُودِيَ فِي الْجَنَّةِ يَا عَبْدَ اللَّهِ هَذَا خَيْرٌ فَمَنْ كَانَ مِنْ أَهْلِ الصَّلَاةِ دُعِيَ مِنْ بَابِ الصَّلَاةِ وَمَنْ كَانَ مِنْ أَهْلِ الْجِهَادِ دُعِيَ مِنْ بَابِ الْجِهَادِ وَمَنْ كَانَ مِنْ أَهْلِ الصَّدَقَةِ دُعِيَ مِنْ بَابِ الصَّدَقَةِ وَمَنْ كَانَ مِنْ أَهْلِ الصِّيَامِ دُعِيَ مِنْ بَابِ الرَّيَّانِ فَقَالَ أَبُو بَكْرٍ رَضِيَ اللَّهُ عَنْهُ هَلْ عَلَى مَنْ دُعِيَ مِنْ هَذِهِ الْأَبْوَابِ مِنْ ضَرُورَةٍ فَهَلْ يُدْعَى أَحَدٌ مِنْ هَذِهِ الْأَبْوَابِ كُلِّهَا قَالَ نَعَمْ وَأَرْجُو أَنْ تَكُونَ مِنْهُمْ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Salamah] serta [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Ibnu Syihab] dari [Humaid bin 'Abdur Rahman] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam beliau bersabda: \"Barang siapa yang menginfakkan satu pasang di jalan Allah 'azza wajalla maka ia akan diseru di Surga; wahai hamba Allah, ini lebih baik. Barang siapa yang merupakan ahli shalat maka ia diseru dari pintu shalat, dan barang siapa yang merupakan ahli jihad maka ia akan diseru dari pintu jihad, dan barang siapa yang merupakan ahli shadaqah maka ia akan diseru dari pintu shadaqah, dan barang siapa yang merupakan ahli puasa maka ia akan diseru dari pintu Ar Rayyan.\" Kemudian Abu Bakr berkata; wahai Nabi Allah, tidak ada ruginya orang yang diseru dari seluruh pintu-pintu tersebut. Apakah ada seseorang yang diseru dari seluruh pintu-pintu tersebut? Beliau menjawab: \"Ya, dan saya berharap engkau diantara mereka.\" "},"3041":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ الْأَوْزَاعِيِّ قَالَ حَدَّثَنِي يَحْيَى عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو سَلمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَنْفَقَ زَوْجَيْنِ فِي سَبِيلِ اللَّهِ دَعَتْهُ خَزَنَةُ الْجَنَّةِ مِنْ أَبْوَابِ الْجَنَّةِ يَا فُلَانُ هَلُمَّ فَادْخُلْ فَقَالَ أَبُو بَكْرٍ يَا رَسُولَ اللَّهِ ذَاكَ الَّذِي لَا تَوَى عَلَيْهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنِّي لَأَرْجُو أَنْ تَكُونَ مِنْهُمْ","id":"Telah mengkhabarkan kepada kami ['Amr bin Utsman], ia berkata; telah menceritakan kepada kami [Baqiyah] dari [Al Auza'i], ia berkata; telah menceritakan kepadaku [Yahya] dari [Muhammad bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang menginfakkan satu pasang di jalan Allah, maka penjaga Surga menyerunya dari pintu-pintu Surga; wahai Fulan, kemarilah masuk.\" Kemudian Abu Bakr berkata; wahai Rasulullah, itu adalah orang yang tidak merugi. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh saya berharap engkau diantara mereka.\" "},"3042":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ الْمُفَضَّلِ عَنْ يُونُسَ عَنْ الْحَسَنِ عَنْ صَعْصَعَةَ بْنِ مُعَاوِيَةَ قَالَلَقِيتُ أَبَا ذَرٍّ قَالَ قُلْتُ حَدِّثْنِي قَالَ نَعَمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ عَبْدٍ مُسْلِمٍ يُنْفِقُ مِنْ كُلِّ مَالٍ لَهُ زَوْجَيْنِ فِي سَبِيلِ اللَّهِ إِلَّا اسْتَقْبَلَتْهُ حَجَبَةُ الْجَنَّةِ كُلُّهُمْ يَدْعُوهُ إِلَى مَا عِنْدَهُ قُلْتُ وَكَيْفَ ذَلِكَ قَالَ إِنْ كَانَتْ إِبِلًا فَبَعِيرَيْنِ وَإِنْ كَانَتْ بَقَرًا فَبَقَرَتَيْنِ","id":"Telah mengkhabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Bisyr bin Al Mufadhdhal] dari [Yunus] dari [Al Hasan] dari [Sha'sha'ah bin Mu'awiyah], ia berkata; saya pernah bertemu dengan [Abu Dzar], ia berkata; saya berkata; ceritakan kepadaku! Ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seorang hamba muslim yang menginfakkan satu pasang dari setiap hartanya di jalan Allah kecuali seluruh penjaga Surga akan menyambutnya, mereka menyerunya agar datang ke sisinya. Saya berkata; bagaimana hal tersebut terjadi? Abu Dzar berkata; apabila unta maka dengan ia mengingakkan dua unta, apabila sapi maka ia menginfakkan dua sapi."},"3043":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ أَبِي النَّضْرِ قَالَ حَدَّثَنَا أَبُو النَّضْرِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ الْأَشْجَعِيُّ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ الرُّكَيْنِ الْفَزَارِيِّ عَنْ أَبِيهِ عَنْ يُسَيْرِ ابْنِ عَمِيلَةَ عَنْ خُرَيْمِ بْنِ فَاتِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَنْفَقَ نَفَقَةً فِي سَبِيلِ اللَّهِ كُتِبَتْ لَهُ بِسَبْعِ مِائَةِ ضِعْفٍ","id":"Telah mengkhabarkan kepada kami [Abu Bakar bin Abi An Nadlr], ia berkata telah menceritakan kepada kami [Abu An Nadlr], ia berkata telah menceritakan kepada kami [Ubaidullah Al Asyja'i] dari [Sufyan Ats Tsauri] dari [Rukain Al Fazari] dari [bapaknya] dari [Yusair bin 'Amilah] dari [Khuraim bin Fatik] ia berkata Rasulullah Shollollohu'alaihi wa sallam bersabda: \"barangsiapa yang memberi nafkah dijalan Allah maka akan ditulis untuknya dengan tujuh ratus kali lipat.\""},"3044":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ أَبَا عَمْرٍو الشَّيْبَانِيَّ عَنْ أَبِي مَسْعُودٍأَنَّ رَجُلًا تَصَدَّقَ بِنَاقَةٍ مَخْطُومَةٍ فِي سَبِيلِ اللَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيَأْتِيَنَّ يَوْمَ الْقِيَامَةِ بِسَبْعِ مِائَةِ نَاقَةٍ مَخْطُومَةٍ","id":"Telah mengkhabarkan kepada kami [Bisyr bin Khalid], ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sulaiman], ia berkata; saya pernah mendengar [Abu 'Amr Asy Syaibani] dari [Abu Mas'ud] bahwa seorang laki-laki bershadaqah dengan seekor unta yang distempel di jalan Allah, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh ia akan datang pada Hari Kiamat membawa tujuh ratus unta yang distempel.\""},"3045":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ بَحِيرٍ عَنْ خَالِدٍ عَنْ أَبِي بَحْرِيَّةَ عَنْ مُعَاذِ بْنِ جَبَلٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْغَزْوُ غَزْوَانِ فَأَمَّا مَنْ ابْتَغَى وَجْهَ اللَّهِ وَأَطَاعَ الْإِمَامَ وَأَنْفَقَ الْكَرِيمَةَ وَيَاسَرَ الشَّرِيكَ وَاجْتَنَبَ الْفَسَادَ كَانَ نَوْمُهُ وَنُبْهُهُ أَجْرًا كُلُّهُ وَأَمَّا مَنْ غَزَا رِيَاءً وَسُمْعَةً وَعَصَى الْإِمَامَ وَأَفْسَدَ فِي الْأَرْضِ فَإِنَّهُ لَا يَرْجِعُ بِالْكَفَافِ","id":"Telah mengkhabarkan kepada kami ['Amr bin Utsman], ia berkata; telah menceritakan kepada kami [Baqiyah] dari [Bahir] dari [Khalid] dari [Abu Bahriyah] dari [Mu'adz bin Jabal] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Berperang ada dua, adapun orang yang mengharapkan wajah Allah dan mentaati pemimpin, menginfakkan barang berharga, memberikan kemudahan kepada sekutu, dan menghindari kerusakan maka tidur dan terjaganya adalah seluruhnya pahala. Adapun orang yang berperang karena ingin dilihat dan didengar serta durhaka kepada pemimpin, dan membuat kerusakan di bumi maka sesungguhnya ia tidak akan kembali dengan sesuatu yang mencukupi.\" "},"3046":{"ar":"أَخْبَرَنَا حُسَيْنُ بْنُ حُرَيْثٍ وَمَحْمُودُ بْنُ غَيْلَانَ وَاللَّفْظُ لِحُسَيْنٍ قَالَا حَدَّثَنَا وَكِيعٌ عَنْ سُفْيَانَ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حُرْمَةُ نِسَاءِ الْمُجَاهِدِينَ عَلَى الْقَاعِدِينَ كَحُرْمَةِ أُمَّهَاتِهِمْ وَمَا مِنْ رَجُلٍ يَخْلُفُ فِي امْرَأَةِ رَجُلٍ مِنْ الْمُجَاهِدِينَ فَيَخُونُهُ فِيهَا إِلَّا وُقِفَ لَهُ يَوْمَ الْقِيَامَةِ فَأَخَذَ مِنْ عَمَلِهِ مَا شَاءَ فَمَا ظَنُّكُمْ","id":"Telah mengkhabarkan kepada kami [Husain bin Huraits] dan [Mahmud bin Ghailan] dan lafazhnya adalah lafazh Husain, mereka berkata; telah menceritakan kepada kami [Waki'] dari [Sufyan] dari ['Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kehormatan para isteri orang-orang yang berjihad atas orang-orang yang tidak berjihad seperti kehormatan ibu-ibu kalian. Tidaklah seseorang menggantikan dalam menjaga isteri seorang mujahid kemudian ia mengkhianatinya dalam diri isterinya kecuali pada Hari Kiamat ia akan diberdirikan kemudian ia akan mengambil amalannya sekehendaknya, maka bagaimana perkiraan kalian?\""},"3047":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا حَرَمِيُّ بْنُ عُمَارَةَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ سُلَيْمَانَ بْنِ بُرَيْدَةَ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حُرْمَةُ نِسَاءِ الْمُجَاهِدِينَ عَلَى الْقَاعِدِينَ كَحُرْمَةِ أُمَّهَاتِهِمْ وَإِذَا خَلَفَهُ فِي أَهْلِهِ فَخَانَهُ قِيلَ لَهُ يَوْمَ الْقِيَامَةِ هَذَا خَانَكَ فِي أَهْلِكَ فَخُذْ مِنْ حَسَنَاتِهِ مَا شِئْتَ فَمَا ظَنُّكُمْ","id":"Telah mengkhabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Harami bin 'Umarah], ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad] dari [Sulaiman bin Buraidah] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kehormatan isteri-isteri orang yang berjihad atas orang-orang yang tidak berjihad seperti kehormatan ibu-ibu mereka. Apabila ia menggantikannya untuk menjaga isterinya kemudian mengkhianatinya pada Hari Kiamat akan dikatakan kepadanya; orang ini telah mengkhianatimu pada diri isterimu, maka ambillah kebaikan-kebaikannya sekehendakmu. Maka bagaimana perkiraan kalian?\" "},"3048":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا قَعْنَبٌ كُوفِيٌّ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ حُرْمَةُ نِسَاءِ الْمُجَاهِدِينَ عَلَى الْقَاعِدِينَ فِي الْحُرْمَةِ كَأُمَّهَاتِهِمْ وَمَا مِنْ رَجُلٍ مِنْ الْقَاعِدِينَ يَخْلُفُ رَجُلًا مِنْ الْمُجَاهِدِينَ فِي أَهْلِهِ إِلَّا نُصِبَ لَهُ يَوْمَ الْقِيَامَةِ فَيُقَالُ يَا فُلَانُ هَذَا فُلَانٌ فَخُذْ مِنْ حَسَنَاتِهِ مَا شِئْتَ ثُمَّ الْتَفَتَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى أَصْحَابِهِ فَقَالَ مَا ظَنُّكُمْ تُرَوْنَ يَدَعُ لَهُ مِنْ حَسَنَاتِهِ شَيْئًا","id":"Telah mengkhabarkan kepada kami [Abdullah bin Muhammad bin Abdur Rahman], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepada kami [Qa'nab Kufi] dari ['Al Qamah bin Martsad] dari [Ibnu Buraidah] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kehormatan isteri-isteri orang yang berjihad atas orang-orang yang tidak berjihad seperti ibu-ibu kalian. Tidakalh seorang laki-laki yang tidak berjihad menggantikan seseorang dalam diri isterinya kecuali akan diangkat baginya pada Hari Kiamat, kemudian dikatakan; wahai Fulan, inilah si Fulan. Ambillah kebaikan-kebaikanmu semaumu.\" Kemudian Nabi shallallahu 'alaihi wasallam menoleh kepada para sahabatnya, kemudian bersabda: \"Bagaimana perkiraan kalian? Apakah kalian mengira ia akan membiarkan sedikit kebaikan-kebaikannya?\""},"3049":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاهِدُوا بِأَيْدِيكُمْ وَأَلْسِنَتِكُمْ وَأَمْوَالِكُمْ","id":"Telah mengkhabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Abdur Rahman], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Humaid] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berjihadlah dengan tangan, lidah dan harta kalian.\""},"3050":{"ar":"أَخْبَرَنَا أَبُو مُحَمَّدٍ مُوسَى بْنُ مُحَمَّدٍ هُوَ الشَّامِيُّ قَالَ حَدَّثَنَا مَيْمُونُ بْنُ الْأَصْبَغِ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ الْقَاسِمِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ رَضِيَ اللَّهُ عَنْهُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ أَمَرَ بِقَتْلِ الْحَيَّاتِ وَقَالَ مَنْ خَافَ ثَأْرَهُنَّ فَلَيْسَ مِنَّا","id":"Telah mengkhabarkan kepada kami [Abu Muhammad Musa bin Muhammad yaitu Asy Syami], ia berkata; telah menceritakan kepada kami [Maimun bin Al Ashbagh], ia berkata; telah menceritakan kepada kami [Yazid bin Harun], ia berkata; telah memberitakan kepada kami [Syarik] dari [abu Ishaq] dari [Al Qasim bin Abdur Rahman] dari [ayahnya] dari [Abdullah] radliallahu 'anhu dari rasulullah shallallahu 'alaihi wasallam bahwa beliau memerintahkan untuk membunuh ular, beliau bersabda: \"Barang siapa yang takut kepada pengaruhnya maka bukan dari golongan kami.\""},"3051":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ عَنْ أَبِي عُمَيْسٍ عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ جَبْرٍ عَنْ أَبِيهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَادَ جَبْرًا فَلَمَّا دَخَلَ سَمِعَ النِّسَاءَ يَبْكِينَ وَيَقُلْنَ كُنَّا نَحْسَبُ وَفَاتَكَ قَتْلًا فِي سَبِيلِ اللَّهِ فَقَالَ وَمَا تَعُدُّونَ الشَّهَادَةَ إِلَّا مَنْ قُتِلَ فِي سَبِيلِ اللَّهِ إِنَّ شُهَدَاءَكُمْ إِذًا لَقَلِيلٌ الْقَتْلُ فِي سَبِيلِ اللَّهِ شَهَادَةٌ وَالْبَطْنُ شَهَادَةٌ وَالْحَرَقُ شَهَادَةٌ وَالْغَرَقُ شَهَادَةٌ وَالْمَغْمُومُ يَعْنِي الْهَدِمَ شَهَادَةٌ وَالْمَجْنُونُ شَهَادَةٌ وَالْمَرْأَةُ تَمُوتُ بِجُمْعٍ شَهِيدَةٌ قَالَ رَجُلٌ أَتَبْكِينَ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَاعِدٌ قَالَ دَعْهُنَّ فَإِذَا وَجَبَ فَلَا تَبْكِيَنَّ عَلَيْهِ بَاكِيَةٌ","id":"Telah mengkhabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami [Ja'far bin 'Aun] dari [Abu 'Umais] dari [Abdullah bin Abdillah bin Jabar] dari [ayahnya] bahwa Rasulullah shallallahu 'alaihi wasallam kembali, kemudian tatkala beliau masuk maka beliau mendengar para wanita menangis, dan mereka berkata; kami mengira anda meninggal karena terbunuh di jalan Allah. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah kalian menganggap syahid kecuali orang yang terbunuh di jalan Allah. Sesungguhnya orang-orang yang syahid kalian jika demikian sungguh sedikit. Terbunuh di jalan Allah adalah syahid, meniggal karena sakit perut adalah syahid, terbakar adalah syahid, tenggelam adalah syahid, orang yang tertimpa reruntuhan adalah syahid, orang yang mati karena gila adalah syahid, wanita yang meninggal karena melahirkan adalah syahid.\" Seorang laki-laki berkata; apakah kalian menangis sedangkan Rasulullah shallallahu 'alaihi wasallam sedang duduk? Beliau bersabda: \"Biarkan mereka, apabila telah meninggal maka tidak boleh ada seorang wanitapun yang menangisinya.\""},"3052":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا دَاوُدُ يَعْنِي الطَّائِيَّ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ جَبْرٍأَنَّهُ دَخَلَ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَيِّتٍ فَبَكَى النِّسَاءُ فَقَالَ جَبْرٌ أَتَبْكِينَ مَا دَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَالِسًا قَالَ دَعْهُنَّ يَبْكِينَ مَا دَامَ بَيْنَهُنَّ فَإِذَا وَجَبَ فَلَا تَبْكِيَنَّ بَاكِيَةٌ","id":"Telah mengkhabarkan kepada kami [Ahmad bin Yahya], ia berkata; telah menceritakan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Daud yaitu Ath Thai] dari [Abdul Malik bin 'Umair] dari [Jabar] bahwa ia pernah mendatangi mayit bersama Rasulullah shallallahu 'alaihi wasallam, kemudia para wanita menangis, maka Jabr berkata; apakah kalian menangis selama Rasulullah shallallahu 'alaihi wasallam duduk? Beliau bersabda: \"Biarkan mereka menangis selama ia berada diantara mereka, apabila ia telah meninggal maka jangan ada seorang wanita yang menangisinya.\""},"3053":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ سَيْفٍ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ قَالَحَضَرْنَا مَعَ ابْنِ عَبَّاسٍ جَنَازَةَ مَيْمُونَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِسَرِفَ فَقَالَ ابْنُ عَبَّاسٍ هَذِهِ مَيْمُونَةُ إِذَا رَفَعْتُمْ جَنَازَتَهَا فَلَا تُزَعْزِعُوهَا وَلَا تُزَلْزِلُوهَا فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ مَعَهُ تِسْعُ نِسْوَةٍ فَكَانَ يَقْسِمُ لِثَمَانٍ وَوَاحِدَةٌ لَمْ يَكُنْ يَقْسِمُ لَهَا","id":"Telah mengkhabarkan kepada kami [Abu Daud Sulaiman bin Saif], ia berkata; telah menceritakan kepada kami [Ja'far bin 'Aun], ia berkata; telah memberitakan kepada kami [Ibnu Juraij] dari ['Atha`], ia berkata; kami pernah menghadiri jenazah Maimunah isteri Nabi shallallahu 'alaihi wasallam bersama Ibnu Abbas. Kemudian [Ibnu Abbas] berkata; ini adalah Maimunah, apabila kalian mengangkatnya maka janganlah kalian menggoyang dan menggoncangnya, karena sesungguhnya bersama Rasulullah shallallahu 'alaihi wasallam sembilan wanita, beliau membagikan bagian kepada delapan orang dan tidak membagi kepada satu diantara mereka. "},"3054":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ قَالَ أَنْبَأَنَا سُفْيَانُ قَالَ حَدَّثَنِي عَمْرُو بْنُ دِينَارٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍ قَالَتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدَهُ تِسْعُ نِسْوَةٍ يُصِيبُهُنَّ إِلَّا سَوْدَةَ فَإِنَّهَا وَهَبَتْ يَوْمَهَا وَلَيْلَتَهَا لِعَائِشَةَ","id":"Telah mengkhabarkan kepada kami [Ibrahim bin Ya'qub], ia berkata; telah menceritakan kepada kami [Ibnu Abi Maryam], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepadaku ['Amr bin Dinar] dari ['Atho`] dari [Ibnu Abbas] ia berkata; Rasulullah shallallahu 'alaihi wasallam wafat dan beliau memiliki sembilan istri yang semua telah beliau gauli kecuali Saudah karena ia memberikan hari-hari dan malamnya untuk 'Aisyah."},"3055":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ عَنْ يَزِيدَ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ أَنَّ أَنَسًا حَدَّثَهُمْأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَطُوفُ عَلَى نِسَائِهِ فِي اللَّيْلَةِ الْوَاحِدَةِ وَلَهُ يَوْمَئِذٍ تِسْعُ نِسْوَةٍ","id":"Telah mengkhabarkan kepada kami [Isma'il bin Mas'ud] dari [Yazid yaitu Ibnu Zurai'], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] bahwa [Anas] bercerita kepada mereka bahwa Nabi shallallahu 'alaihi wasallam mengelilingi para isterinya dalam satu malam dan pada saat itu beliau memiliki sembilan isteri."},"3056":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ الْمُخَرَّمِيُّ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكُنْتُ أَغَارُ عَلَى اللَّاتِي وَهَبْنَ أَنْفُسَهُنَّ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقُولُ أَوَتَهَبَ الْحُرَّةُ نَفْسَهَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ تُرْجِي مَنْ تَشَاءُ مِنْهُنَّ وَتُؤْوِي إِلَيْكَ مَنْ تَشَاءُ }قُلْتُ وَاللَّهِ مَا أَرَى رَبَّكَ إِلَّا يُسَارِعُ لَكَ فِي هَوَاكَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak Al Mukharrimi], ia berkata; telah menceritakan kepada kami [Abu Usamah] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah], ia berkata; saya cemburu kepada para wanita yang menghibahkan dirinya kepada Nabi shallallahu 'alaihi wasallam, maka saya katakan; apakah orang yang merdeka menghibahkan dirinya? Kemudian Allah 'azza wajalla menurunkan ayat: Kamu boleh menangguhkan menggauli siapa yang kamu kehendaki di antara mereka (isteri-isterimu) dan (boleh pula) menggauli siapa yang kamu kehendaki. Saya katakan; demi Allah, saya tidak melihat Tuhanmu kecuali bersegera memberikan keringanan dan melapangkan bagimu dalam urusanmu."},"3057":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ الْمُقْرِئُ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا أَبُو حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍ قَالَأَنَا فِي الْقَوْمِ إِذْ قَالَتْ امْرَأَةٌ إِنِّي قَدْ وَهَبْتُ نَفْسِي لَكَ يَا رَسُولَ اللَّهِ فَرَأْ فِيَّ رَأْيَكَ فَقَامَ رَجُلٌ فَقَالَ زَوِّجْنِيهَا فَقَالَ اذْهَبْ فَاطْلُبْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَذَهَبَ فَلَمْ يَجِدْ شَيْئًا وَلَا خَاتَمًا مِنْ حَدِيدٍ فَقَالَ رَسُولُ اللَّهِ أَمَ��َكَ مِنْ سُوَرِ الْقُرْآنِ شَيْءٌ قَالَ نَعَمْ قَالَ فَزَوَّجَهُ بِمَا مَعَهُ مِنْ سُوَرِ الْقُرْآنِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah bin Yazid Al Muqri`], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; telah menceritakan kepada kami [Abu Hazim] dari [Sahl bin Sa'd], ia berkata; saya sedang berada diantara orang-orang disaat seorang wanita berkata; saya telah menghibahkan diriku kepadamu wahai Rasulullah, lihatlah bagaimana pendapatmu terhadap diriku. Kemudian seorang laki-laki berdiri seraya berkata; nikahkan saya dengannya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pergi dan carilah walau cincin dari besi.\" Lalu orang tersebut pergi dan tidak mendapatkan sesuatupun tidak pula mendapatkan cincin besi. Kemudia Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah engkau hafal beberapa surat Al Qur'an?\" Maka orang tersebut berkata; ya. Sahl bin Sa'd berkata; kemudian Rasulullah shallallahu 'alaihi wasallam menikahkannya dengan surat Al Qur'an yang telah ia hafal. "},"3058":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ عَبْدِ اللَّهِ بْنِ خَالِدٍ النَّيْسَابُورِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى بْنِ أَعْيَنَ قَالَ حَدَّثَنَا أَبِي عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ قَالَ حَدَّثَنَا أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهَا أَخْبَرَتْهُأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَهَا حِينَ أَمَرَهُ اللَّهُ أَنْ يُخَيِّرَ أَزْوَاجَهُ قَالَتْ عَائِشَةُ فَبَدَأَ بِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي ذَاكِرٌ لَكِ أَمْرًا فَلَا عَلَيْكِ أَنْ لَا تُعَجِّلِي حَتَّى تَسْتَأْمِرِي أَبَوَيْكِ قَالَتْ وَقَدْ عَلِمَ أَنَّ أَبَوَيَّ لَا يَأْمُرَانِي بِفِرَاقِهِ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ إِنْ كُنْتُنَّ تُرِدْنَ الْحَيَاةَ الدُّنْيَا وَزِينَتَهَا فَتَعَالَيْنَ أُمَتِّعْكُنَّ }فَقُلْتُ فِي هَذَا أَسْتَأْمِرُ أَبَوَيَّ فَإِنِّي أُرِيدُ اللَّهَ وَرَسُولَهُ وَالدَّارَ الْآخِرَةَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Yahya bin Abdullah bin Khalid An Naisaburi], ia berkata; telah menceritakan kepada kami [Muhammad bin Musa bin A'yan], ia berkata; telah menceritakan kepada kami [ayahku] dari [Ma'mar] dari [Az Zuhri], ia berkata; telah menceritakan kepada kami [Abu Salamah bin Abdur Rahman] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam bahwa ia telah mengkhabarkan bahwa Rasulullah shallallahu 'alaihi wasallam datang kepadanya ketika Allah memerintahkannya untuk memberikan pilihan kepada para isterinya. Aisyah berkata; kemudian Rasulullah shallallahu 'alaihi wasallam memulai dariku, lalu beliau bersabda: \"Sesungguhnya saya mengingatkanmu kepada suatu perkara dan tidak mengapa engkau menundanya hingga engkau minta pendapat kedua orang tuamu.\" Aisyah berkata; sungguh beliau telah mengetahui bahwa kedua orang tuaku tidak memerintahkanku untuk berpisah dengannya. Kemudian Rasulullah shallallahu 'alaihi wasallam membacakan ayat: Hai Nabi, katakanlah kepada isteri-isterimu: \"Jika kamu sekalian mengingini kehidupan dunia dan perhiasannya, maka marilah supaya kuberikan kepadamu mut'ah (yaitu: suatu pemberian yang diberikan kepada perempuan yang telah diceraikan menurut kesanggupan suami). Maka saya katakan; apakah untuk ini saya meminta pendapat kedua orang tuaku? Sungguh saya menginginkan Allah dan rasulNya serta kampong akherat. "},"3059":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ الْعَسْكَرِيُّ قَالَ حَدَّثَنَا غُنْدَرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ قَالَ سَمِعْتُ أَبَا الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْقَدْ خَيَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ أَوْ كَانَ طَلَاقًا","id":"Telah mengkhabarkan kepada kami [Bisyr bin Khalid Al 'Askari], ia berkata; telah menceritakan kepada kami [Ghundar], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sulaiman], ia berkata; saya pernah mendegar [Abu Adh Dhuha] dari [Masruq] dari [Aisyah] radliallahu 'anha, ia berkata; Rasulullah shallallahu 'alaihi wasallam telah memberikan pilihan kepada para isterinya atau dicerai. "},"3060":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ إِسْمَعِيلَ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْخَيَّرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاخْتَرْنَاهُ فَلَمْ يَكُنْ طَلَاقًا","id":"Telah mengkhabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Abdur Rahman] dari [Sufyan] dari [Isma'il] dari [Asy Sya'bi] dari [Masruq] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah memberikan pilihan kepada kami, kemudian kami memilih beliau dan tidak dicerai. "},"3061":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ قَالَ حَفِظْنَاهُ مِنْ عَمْرٍو عَنْ عَطَاءٍ قَالَ قَالَتْ عَائِشَةُمَا مَاتَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أُحِلَّ لَهُ النِّسَاءُ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan], ia berkata; saya menghafalnya dari ['Amr] dari ['Atho`], ia berkata; [Aisyah] telah berkata; Rasulullah shallallahu 'alaihi wasallam tidaklah meninggal hingga dihalalkan baginya para wanita. "},"3062":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا أَبُو هِشَامٍ وَهُوَ الْمُغِيرَةُ بْنُ سَلَمَةَ الْمَخْزُومِيُّ قَالَ حَدَّثَنَا وُهَيْبٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ عَائِشَةَ قَالَتْمَا تُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى أَحَلَّ اللَّهُ لَهُ أَنْ يَتَزَوَّجَ مِنْ النِّسَاءِ مَا شَاءَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak], ia berkata; telah menceritakan kepada kami [Abu Hisyam yaitu Al Mughirah bin Salamah Al Makhzumi], ia berkata; telah menceritakan kepada kami [Wuhaib], ia berkata; telah menceritakan kepada kami [Ibnu Juraij] dari ['Atho`] dari ['Ubaid bin 'Umair] dari [Aisyah], ia berkata; tidaklah Rasulullah shallallahu 'alaihi wasallam meninggal hingga Allah menghalalakan baginya untuk menikahi wanita yang beliau inginkan.\""},"3063":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ زُرَارَةَ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا يُونُسُ عَنْ أَبِي مَعْشَرٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَكُنْتُ مَعَ ابْنِ مَسْعُودٍ وَهُوَ عِنْدَ عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ فَقَالَ عُثْمَانُ خَرَجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى فِتْيَةٍ قَالَ أَبُو عَبْد الرَّحْمَنِ فَلَمْ أَفْهَمْ فِتْيَةً كَمَا أَرَدْتُ فَقَالَ مَنْ كَانَ مِنْكُمْ ذَا طَوْلٍ فَلْيَتَزَوَّجْ فَإِنَّهُ أَغَضُّ لِلْبَصَرِ وَأَحْصَنُ لِلْفَرْجِ وَمَنْ لَا فَالصَّوْمُ لَهُ وِجَاءٌ","id":"Telah mengkhabarkan kepada kami ['Amr bin Zurarah], ia berkata; telah menceritakan kepada kami [Isma'il], ia berkata; telah menceritakan kepada kami [Yunus] dari [Abu Ma'syar] dari [Ibrahim] dari ['Alqamah], ia berkata; saya pernah bersama Ibnu Mas'ud dan ia sedang berada di sisi Utsman radliallahu 'anhu, kemudian [Utsman] berkata; Rasulullah shallallahu 'alaihi wasallam keluar menemui beberapa pemuda. Abu Abdur Rahman berkata; saya tidak memahami para pemuda sebagaimana yang saya inginkan. Kemudian beliau bersabda: \"Barang siapa diantara kalian yang memiliki kemampuan maka hendaknya ia menikah, karena sesungguhnya hal itu lebih menundukkan pandangan dan menjaga kemaluan, dan orang yang tidak memiliki kemampuan maka puasa adalah pengekang baginya.\""},"3064":{"ar":"أَخْبَرَنَا بِشْرُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ عَنْ شُعْبَةَ عَنْ سُلَيْمَانَ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَأَنَّ عُثْمَانَ قَالَ لِابْنِ مَسْعُودٍ هَلْ لَكَ فِي فَتَاةٍ أُزَوِّجُكَهَا فَدَعَا عَبْدُ اللَّهِ عَلْقَمَةَ فَحَدَّثَ أَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ اسْتَطَاعَ الْبَاءَةَ فَلْيَتَزَوَّجْ فَإِنَّهُ أَغَضُّ لِلْبَصَرِ وَأَحْصَنُ لِلْفَرْجِ وَمَنْ لَمْ يَسْتَطِعْ فَلْيَصُمْ فَإِنَّهُ لَهُ وِجَاءٌ","id":"Telah mengkhabarkan kepada kami [Bisyr bin Khalid], ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] dari [Syu'bah] dari [Sulaiman] dari [Ibrahim] dari ['Alqamah] bahwa Utsman berkata kepada Ibnu Mas'ud; apakah engkau punya keinginan kepada seorang wanita muda sehingga saya dapat menikahkanmu dengannya? Kemudian [Abdullah] mengundang 'Alqamah dan menceritakan bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang memiliki kemampuan maka hendaknya ia menikah, karena sesungguhnya hal itu lebih menundukkan pandangan dan menjaga kemaluan. Dan barang siapa yang belum memiliki kemampuan maka hendaknya ia berpuasa, karena sesungguhnya hal tersebut adalah pengekang baginya.\""},"3065":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ إِسْحَقَ الْهَمْدَانِيُّ الْكُوفِيُّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدٍ الْمُحَارِبِيُّ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ وَالْأَسْوَدُ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ اسْتَطَاعَ مِنْكُمْ الْبَاءَةَ فَلْيَتَزَوَّجْ وَمَنْ لَمْ يَسْتَطِعْ فَعَلَيْهِ بِالصَّوْمِ فَإِنَّهُ لَهُ وِجَاءٌقَالَ أَبُو عَبْد الرَّحْمَنِ الْأَسْوَدُ فِي هَذَا الْحَدِيثِ لَيْسَ بِمَحْفُوظٍ","id":"Telah mengkhabarkan kepada kami [Harun bin Ishaq Al Hamdani Al Kufi], ia berkata; telah menceritakan kepada kami [Abdur Rahman bin Muhammad Al Muharibi] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah] dan [Al Aswad] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Barang siapa diantara kalian yang memiliki kemampuan maka hendaknya ia menikah, dan barang siapa yang belum mampu maka hendaknya ia berpuasa, karena sesungguhnya itu adalah pengekang baginya.\" Abu Abdur Rahman berkata; Al Aswad dalam hadits ini tidaklah dikenal. "},"3066":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ بْنِ عُمَيْرٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ قَالَقَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ الشَّبَابِ مَنْ اسْتَطَاعَ مِنْكُمْ الْبَاءَةَ فَلْيَنْكِحْ فَإِنَّهُ أَغَضُّ لِلْبَصَرِ وَأَحْصَنُ لِلْفَرْجِ وَمَنْ لَا فَلْيَصُمْ فَإِنَّ الصَّوْمَ لَهُ وِجَاءٌأَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ عُمَارَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ عَنْ عَبْدِ اللَّهِ قَالَ قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ الشَّبَابِ مَنْ اسْتَطَاعَ مِنْكُمْ الْبَاءَةَ فَلْيَتَزَوَّجْ وَسَاقَ الْحَدِيثَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Al A'masy] dari ['Umarah bin 'Umair] dari [Abdur Rahman bin Yazid] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Wahai para pemuda, barang siapa diantara kalian yang memilki kemampuan maka hendaknya ia menikah, karena sesungguhnya hal itu lebih menundukkan pandangan, dan lebih menjaga kemaluan, dan barang siapa yang tidak mampu maka hendaknya ia berpuasa karena sesungguhnya puasa adalah pengekang baginya.\" Telah mengkhabarkan kepada kami [Muhammad bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari ['Umarah] dari [Abdur Rahman bin Yazid] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda kepada kami: \"Wahai para pemuda, barang siapa diantara kalian yang memiliki kemampuan maka hendaknya ia menikah… \" dan iapun menyebutkan hadits tersebut. "},"3067":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ قَالَكُنْتُ أَمْشِي مَعَ عَبْدِ اللَّهِ بِمِنًى فَلَقِيَهُ عُثْمَانُ فَقَامَ مَعَهُ يُحَدِّثُهُ فَقَالَ يَا أَبَا عَبْدِ الرَّحْمَنِ أَلَا أُزَوِّجُكَ جَارِيَةً شَابَّةً فَلَعَلَّهَا أَنْ تُذَكِّرَكَ بَعْضَ مَا مَضَى مِنْكَ فَقَالَ عَبْدُ اللَّهِ أَمَا لَئِنْ قُلْتَ ذَاكَ لَقَدْ قَالَ لَنَا رَسُولُ اللَّهِ صَلَّى اللَّه�� عَلَيْهِ وَسَلَّمَ يَا مَعْشَرَ الشَّبَابِ مَنْ اسْتَطَاعَ مِنْكُمْ الْبَاءَةَ فَلْيَتَزَوَّجْ","id":"Telah mengkhabarkan kepada kami [Ahmad bin Harb], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari ['Alqamah], ia berkata; saya pernah berjalan bersama Abdullah di Mina, kemudian Utsman menemuinya dan berdiri bersamanya serta menceritakan kepadanya, ia berkata; wahai Abu Abdur Rahman, maukah saya nikahkan engkau dengan seorang wanita muda? Mudah-mudahan ia dapat mengingatkanmu sebagian apa yang telah berlalu darimu. Maka [Abdullah] berkata; adapun apabila engkau berkata demikian, sungguh Rasulullah shallallahu 'alaihi wasallam telah bersabda kepada kami: \"Wahai para pemuda, barang siapa diantara kalian yang memiliki kemampuan maka hendaknya menikah.\" "},"3068":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَلَقَدْ رَدَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى عُثْمَانَ التَّبَتُّلَ وَلَوْ أَذِنَ لَهُ لَاخْتَصَيْنَا","id":"Telah mengkhabarkan kepada kami [Muhammad bin 'Ubaid], ia berkata; telah menceritakan kepada kami [Abdullah bin Al Mubarak] dari [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Sa'ad bin Abi Waqqash], ia berkata; sungguh Rasulullah shallallahu 'alaihi wasallam telah menolak Utsman untuk hidup membujang, jika beliau mengizinkan untuknya niscaya ia akan mengebiri."},"3069":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ أَشْعَثَ عَنْ الْحَسَنِ عَنْ سَعْدِ بْنِ هِشَامٍ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ التَّبَتُّلِ","id":"Telah mengkhabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid] dari [Asy'ats] dari [Al Hasan] dari [Sa'd bin Hisyam] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari hidup membujang. "},"3070":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا مُعَاذُ بْنُ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَمُرَةَ بْنِ جُنْدُبٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى عَنْ التَّبَتُّلِقَالَ أَبُو عَبْد الرَّحْمَنِ قَتَادَةُ أَثْبَتُ وَأَحْفَظُ مِنْ أَشْعَثَ وَحَدِيثُ أَشْعَثَ أَشْبَهُ بِالصَّوَابِ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Mu'adz bin Hisyam], ia berkata; telah menceritakan kepadaku [ayahku] dari [Qatadah] dari [Al Hasan] dari [Samurah bin Jundab] dari Nabi shallallahu 'alaihi wasallam bahwa beliau melarang dari hidup membujang. Abu Abdurrahman berkata; Qotadah lebih kuat dan lebih hafal daripada Asy'at dan hadits Asy'at lebih mendekati kebenaran, wallahu Ta'ala a'lam."},"3071":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ مُوسَى قَالَ حَدَّثَنَا أَنَسُ بْنُ عِيَاضٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ أَنَّ أَبَا هُرَيْرَةَ قَالَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي رَجُلٌ شَابٌّ قَدْ خَشِيتُ عَلَى نَفْسِيَ الْعَنَتَ وَلَا أَجِدُ طَوْلًا أَتَزَوَّجُ النِّسَاءَ أَفَأَخْتَصِي فَأَعْرَضَ عَنْهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى قَالَ ثَلَاثًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا أَبَا هُرَيْرَةَ جَفَّ الْقَلَمُ بِمَا أَنْتَ لَاقٍ فَاخْتَصِ عَلَى ذَلِكَ أَوْ دَعْقَالَ أَبُو عَبْد الرَّحْمَنِ الْأَوْزَاعِيُّ لَمْ يَسْمَعْ هَذَا الْحَدِيثَ مِنْ الزُّهْرِيِّ وَهَذَا حَدِيثٌ صَحِيحٌ قَدْ رَوَاهُ يُونُسُ عَنْ الزُّهْرِيِّ","id":"Telah mengkhabarkan kepada kami [Yahya bin Musa], ia berkata; telah menceritakan kepada kami [Anas bin 'Iyadh], ia berkata; telah menceritakan kepada kami [Al Auza'i] dari [Ibnu Syihab] dari [Abu Salamah] bahwa [Abu Hurairah] berkata; saya berkata; wahai Rasulullah sesungguhnya aku seorang pemuda yang takut dosa atas diriku, dan aku tidak mendapatkan kemampuan untuk menikahi wanita, bolehkah aku mengebiri? Maka Nabi shallallahu 'alaihi wasallam berpaling darinya hingga ia mengatakan hal itu sebanyak tiga kali, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Wahai Abu Hurairah pena telah mengering dengan apa yang akan engkau temui, maka kebirilah karena itu atau tinggalkan, \" Abu Abdurrahman berkata; Auza'i tidak mendengar hadits ini dari Az Zuhri, dan hadits ini adalah shohih dan telah diriwayatkan [Yunus] dari Zuhri."},"3072":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْخَلَنْجِيُّ قَالَ حَدَّثَنَا أَبُو سَعِيدٍ مَوْلَى بَنِي هَاشِمٍ قَالَ حَدَّثَنَا حُصَيْنُ بْنُ نَافِعٍ الْمَازِنِيُّ قَالَ حَدَّثَنِي الْحَسَنُ عَنْ سَعْدِ بْنِ هِشَامٍأَنَّهُ دَخَلَ عَلَى أُمِّ الْمُؤْمِنِينَ عَائِشَةَ قَالَ قُلْتُ إِنِّي أُرِيدُ أَنْ أَسْأَلَكِ عَنْ التَّبَتُّلِ فَمَا تَرَيْنَ فِيهِ قَالَتْ فَلَا تَفْعَلْ أَمَا سَمِعْتَ اللَّهَ عَزَّ وَجَلَّ يَقُولُ{ وَلَقَدْ أَرْسَلْنَا رُسُلًا مِنْ قَبْلِكَ وَجَعَلْنَا لَهُمْ أَزْوَاجًا وَذُرِّيَّةً }فَلَا تَتَبَتَّلْ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah Al Khalanji], ia berkata; telah menceritakan kepada kami [Abu Sa'id sahaya Bani Hasyim], ia berkata; telah menceritakan kepada kami [Hushain bin Nafi' Al Mazini], ia berkata; telah menceritakan kepadaku [Al Hasan] dari [Sa'd bin Hisyam] bahwa ia menemui Ummul mukminin [Aisyah], ia berkata; saya berkata; saya ingin bertanya kepadamu mengenai hidup membujang, bagaimana pendapat anda mengenainya? Aisyah berkata; jangan engkau lakukan, tidakkah engkau mendengar Allah 'azza wajalla berfirman: Dan sesungguhnya Kami telah mengutus beberapa Rasul sebelum kamu dan Kami memberikan kepada mereka isteri-isteri dan keturunan. Maka janganlah engkau hidup membujang. "},"3073":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَفَّانُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ نَفَرًا مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ بَعْضُهُمْ لَا أَتَزَوَّجُ النِّسَاءَ وَقَالَ بَعْضُهُمْ لَا آكُلُ اللَّحْمَ وَقَالَ بَعْضُهُمْ لَا أَنَامُ عَلَى فِرَاشٍ وَقَالَ بَعْضُهُمْ أَصُومُ فَلَا أُفْطِرُ فَبَلَغَ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ مَا بَالُ أَقْوَامٍ يَقُولُونَ كَذَا وَكَذَا لَكِنِّي أُصَلِّي وَأَنَامُ وَأَصُومُ وَأُفْطِرُ وَأَتَزَوَّجُ النِّسَاءَ فَمَنْ رَغِبَ عَنْ سُنَّتِي فَلَيْسَ مِنِّي","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami ['Affan], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Tsabit] dari [Anas] bahwa beberapa orang dari para sahabat Nabi shallallahu 'alaihi wasallam sebagian mereka berkata; saya tidak akan menikah dengan wanita, dan sebagian mereka berkata; saya tidak akan makan daging, dan sebagian mereka mengatakan; saya tidak akan tidur di atas kasur. Dan sebagian mereka mengatakan; saya akan berpuasa dan tidak berbuka. Kemudian hal tersebut sampai kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memuji Allah kemudian bersabda: \"Bagaimana keadaan beberapa orang, mereka mengatakan demikian dan demikian. Akan tetapi saya melakukan shalat dan tidur, berpuasa dan berbuka, serta menikah dengan wanita. Barang siapa yang membenci sunnahku maka ia bukan dari golonganku.\""},"3074":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ مُحَمَّدِ بْنِ عَجْلَانَ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثَةٌ حَقٌّ عَلَى اللَّهِ عَزَّ وَجَلَّ عَوْنُهُمْ الْمُكَاتَبُ الَّذِي يُرِيدُ الْأَدَاءَ وَالنَّاكِحُ الَّذِي يُرِيدُ الْعَفَافَ وَالْمُجَاهِدُ فِي سَبِيلِ اللَّهِ","id":"Telah mengkhabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Muhammad bin 'Ajlan] dari [Sa'id] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga golongan yang merupakan hak atas Allah 'azza wajalla untuk membantu mereka, yaitu; sahaya yang mengadakan perjanjian pembebasan dirinya yang ingin menunaikan kewajibannya, orang yang menikah ingin menjaga kesucian dirinya, dan orang yang berjihad di jalan Allah.\""},"3075":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ عَمْرٍو عَنْ جَابِرٍ قَالَتَزَوَّجْتُ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتَزَوَّجْتَ يَا جَابِرُ قُلْتُ نَعَمْ قَالَ بِكْرًا أَمْ ثَيِّبًا فَقُلْتُ ثَيِّبًا قَالَ فَهَلَّا بِكْرًا تُلَاعِبُهَا وَتُلَاعِبُكَ","id":"Telah mengkhabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Hammad] dari ['Amr] dari [Jabir], ia berkata; saya menikah, kemudian datang kepada Nabi shallallahu 'alaihi wasallam. Lalu beliau bersabda: \"Apakah engkau telah menikah?\" saya katakan; ya. Beliau bertanya: \"Gadis atau janda?\" saya katakan; janda. Maka beliau bersabda: \"Tidakkah engkau menikahi gadis hingga engkau dapat mencandainya dan ia mencandaimu?\""},"3076":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ قَزَعَةَ قَالَ حَدَّثَنَا سُفْيَانُ وَهُوَ ابْنُ حَبِيبٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ جَابِرٍ قَالَلَقِيَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا جَابِرُ هَلْ أَصَبْتَ امْرَأَةً بَعْدِي قُلْتُ نَعَمْ يَا رَسُولَ اللَّهِ قَالَ أَبِكْرًا أَمْ أَيِّمًا قُلْتُ أَيِّمًا قَالَ فَهَلَّا بِكْرًا تُلَاعِبُكَ","id":"Telah mengkhabarkan kepada kami [Al Hasan bin Qaza'ah], ia berkata; telah menceritakan kepada kami [Sufyan yaitu Ibnu Habib] dari [Ibnu Juraij] dari ['Atho`] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam menemuiku kemudian bersabda: \"Wahai Jabir, apakah engkau telah menikahi seorang wanita setelahku?\" Saya katakan; ya wahai Rasulullah. Beliau bersabda: \"Gadis atau janda?\" Saya katakan; janda. Maka beliau bersabda: \"Tidakkah engkau menikahi gadis hingga engkau dapat mencandainya dan ia mencandaimu?\""},"3077":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ الْحُسَيْنِ بْنِ وَاقِدٍ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَخَطَبَ أَبُو بَكْرٍ وَعُمَرُ رَضِيَ اللَّهُ عَنْهُمَا فَاطِمَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا صَغِيرَةٌ فَخَطَبَهَا عَلِيٌّ فَزَوَّجَهَا مِنْهُ","id":"Telah mengkhabarkan kepada kami [Al Husain bin Huraits], ia berkata; telah menceritakan kepada kami [Al Fadhl bin Musa] dari [Al Husain bin Waqid] dari [Abdullah bin Buraidah] dari [ayahnya], ia berkata; Abu Bakar dan Umar radliallahu 'anhuma melamar Fathimah, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ia masih kecil, \" lalu Ali melamarnya dan beliau menikahkannya dengan Ali."},"3078":{"ar":"أَخْبَرَنَا كَثِيرُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ حَرْبٍ عَنْ الزُّبَيْدِيِّ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ عُتْبَةَأَنَّ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ عُثْمَانَ طَلَّقَ وَهُوَ غُلَامٌ شَابٌّ فِي إِمَارَةِ مَرْوَانَ ابْنَةَ سَعِيدِ بْنِ زَيْدٍ وَأُمُّهَا بِنْتُ قَيْسٍ الْبَتَّةَ فَأَرْسَلَتْ إِلَيْهَا خَالَتُهَا فَاطِمَةُ بِنْتُ قَيْسٍ تَأْمُرُهَا بِالِانْتِقَالِ مِنْ بَيْتِ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَسَمِعَ بِذَلِكَ مَرْوَانُ فَأَرْسَلَ إِلَى ابْنَةِ سَعِيدٍ فَأَمَرَهَا أَنْ تَرْجِعَ إِلَى مَسْكَنِهَا وَسَأَلَهَا مَا حَمَلَهَا عَلَى الِانْتِقَالِ مِنْ قَبْلِ أَنْ تَعْتَدَّ فِي مَسْكَنِهَا حَتَّى تَنْقَضِيَ عِدَّتُهَا فَأَرْسَلَتْ إِلَيْهِ تُخْبِرُهُ أَنَّ خَالَتَهَا أَمَرَتْهَا بِذَلِكَ فَزَعَمَتْ فَاطِمَةُ بِنْتُ قَيْسٍ أَنَّهَا كَانَتْ تَحْتَ أَبِي عَمْرِو بْنِ حَفْصٍ فَلَمَّا أَمَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيَّ بْنَ أَبِي طَالِبٍ عَلَى الْيَمَنِ خَرَجَ مَعَهُ وَأَرْسَلَ إِلَيْهَا بِتَطْلِيقَةٍ هِيَ بَقِيَّةُ طَلَاقِهَا وَأَمَرَ لَهَا الْحَارِثَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ بِنَفَقَتِهَا فَأَرْسَلَتْ زَعَمَتْ إِلَى الْحَارِثِ وَعَيَّاشٍ تَسْأَلُهُمَا الَّذِي أَمَرَ لَهَا بِهِ زَوْجُهَا فَقَالَا وَاللَّهِ مَا لَهَا عِنْدَنَا نَفَقَةٌ إِلَّا أَنْ تَكُونَ حَامِلًا وَمَا لَهَا أَنْ تَكُونَ فِي مَسْكَنِنَا إِلَّا بِإِذْنِنَا فَزَعَمَتْ أَنَّهَا أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَصَدَّقَهُمَا قَالَتْ فَاطِمَةُ فَأَيْنَ أَنْتَقِلُ يَا رَسُولَ اللَّهِ قَالَ انْتَقِلِي عِنْدَ ابْنِ أُمِّ مَكْتُومٍ الْأَعْمَى الَّذِي سَمَّاهُ اللَّهُ عَزَّ وَجَلَّ فِي كِتَابِهِ قَالَتْ فَاطِمَةُ فَاعْتَدَدْتُ عِنْدَهُ وَكَانَ رَجُلًا قَدْ ذَهَبَ بَصَرُهُ فَكُنْتُ أَضَعُ ثِيَابِي عِنْدَهُ حَتَّى أَنْكَحَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُسَامَةَ بْنَ زَيْدٍ فَأَنْكَرَ ذَلِكَ عَلَيْهَا مَرْوَانُ وَقَالَ لَمْ أَسْمَعْ هَذَا الْحَدِيثَ مِنْ أَحَدٍ قَبْلَكِ وَسَآخُذُ بِالْقَضِيَّةِ الَّتِي وَجَدْنَا النَّاسَ عَلَيْهَامُخْتَصَرٌ","id":"Telah mengkhabarkan kepada kami [Katsir bin 'Ubaid], ia berkata; telah menceritakan kepada kami [Muhammad bin Harb] dari [Az Zubaidi] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah bin 'Utbah] bahwa Abdullah bin 'Amr bin Utsman mencerai sama sekali anak wanita Sa'id bin Zaid pada masa pemerintahan Marwan dan ia adalah seorang pemuda, dan ibu wanita tersebut adalah anak wanita Qais, lalu bibinya yaitu [Fathimah binti Qais] mengirim utusan memerintahkannya agar pindah dari rumah Abdullah bin 'Amr. Marwan mendengar hal tersebut, kemudian mengirim utusan kepada anak wanita Sa'id dan memerintahkannya agar kembali ke tempat tinggalnya, serta bertanya kepadanya apa yang mendorongnya untuk pindah sebelum ia ber'iddah di tempat tinggalnya hingga selesai 'iddahnya? Lalu ia mengirimkan utusan kepadanya mengkhabarkannya bahwa bibinya memerintahkannya untuk melakukan hal tersebut. Maka Fathimah biti Qais berdalih bahwa ia dahulu di bawah naungan 'Amr bin Hafsh, kemudian tatkala Rasulullah shallallahu 'alaihi wasallam mengangkat Ali menjadi amir di Yaman 'Amr bin Hafsh keluar bersama Ali, dan mengirimkan utusan untuk mencerainya yang merupakan perceraiannya yang terakhir, dan ia memerintahkan Al Harits bin Hisyam serta 'Ayyash bin Abi Rabi'ah untuk memberikan nafkah kepadanya. Kemudian Fathimah mengirimkan utusan kepada Al Harits serta 'Ayyash menanyakan kepada mereka perkara yang diperintahkan suaminya untuk dirinya. Maka mereka berdua mengatakan; demi Allah, ia tidak memiliki nafkah pada kami, kecuali ia hamil. Dan mereka tidak berhak tinggal di tempat tinggal kami kecuali dengan seizing kami. Kemudian Fathimah datang kepada Rasulullah shallallahu 'alaihi wasallam dan menyebutkan hal tersebut kepadanya, lalu beliau membenarkan mereka berdua. Fathimah berkata; kemanakah saya pindah wahai Rasulullah? Beliau bersabda: \"Pindahlah ke rumah Ibnu Ummi Maktum orang yang buta yang telah Allah 'azza wajalla sebutkan dalam kitabNya.\" Fathimah berkata; kemudian saya ber'iddah di rumahnya, dan ia adalah orang yang telah hilang pandangannya, dan saya melepaskan baju di rumahnya hingga Rasulullah shallallahu 'alaihi wasallam menikahkanku dengan Usamah bin Zaid. Kemudian hal tersebut diingkari oleh Marwan, dan ia berkata; saya belum mendengar hadits ini dari seorangpun sebelummu, dan saya akan mengambil permasalahan yang telah kami dapati manusia ada padanya. "},"3079":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارِ بْنِ رَاشِدٍ قَالَ حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَنْبَأَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ عَائِشَةَأَنَّ أَبَا حُذَيْفَةَ بْنَ عُتْبَةَ بْنِ رَبِيعَةَ بْنِ عَبْدِ شَمْسٍ وَكَانَ مِمَّنْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبَنَّى سَالِمًا وَأَنْكَحَهُ ابْنَةَ أَخِيهِ هِنْدَ بِنْتَ الْوَلِيدِ بْنِ عُتْبَةَ بْنِ رَبِيعَةَ بْنِ عَبْدِ شَمْسٍ وَهُوَ مَوْلًى لِامْرَأَةٍ مِنْ الْأَنْصَارِ كَمَا تَبَنَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدًا وَكَانَ مَنْ تَبَنَّى رَجُلًا فِي الْجَاهِلِيَّةِ دَعَاهُ النَّاسُ ابْنَهُ فَوَرِثَ مِنْ مِيرَاثِهِ حَتَّى أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ فِي ذَلِكَ{ ادْعُوهُمْ لِآبَائِهِمْ هُوَ أَقْسَطُ عِنْدَ اللَّهِ فَإِنْ لَمْ تَعْلَمُوا آبَاءَهُمْ فَإِخْوَانُكُمْ فِي الدِّينِ وَمَوَالِيكُمْ }فَمَنْ لَمْ يُعْلَمْ لَهُ أَبٌ كَانَ مَوْلًى وَأَخًا فِي الدِّينِمُخْتَصَرٌ","id":"Telah mengkhabarkan kepada kami ['Imran bin Bakkar bin Rasyid], ia berkata; telah menceritakan kepada kami [Abu Al Yaman], ia berkata; telah memberitakan kepada kami [Syu'aib] dari [Az Zuhri], ia berkata; telah mengkhabarkan kepadaku ['Urwah bin Az Zubair] dari [Aisyah] bahwa Hudzaifah bin 'Utbah bin Rabi'ah bin Abdu Syams yang merupakan diantara orang yang menyaksikan perang Badr bersama Rasulullah shallallahu 'alaihi wasallam mengangkat Salim sebagai anak, dan menikahkannya dengan anak saudaranya yaitu Hindun binti Al Walid bin 'Utbah bin Rabi'ah bin Abdu Syams dan ia adalah sahaya seorang wanita Anshar yang sudah dimerdekakan, sebagaimana Rasulullah shallallahu 'alaihi wasallam mengangkat Zaid sebagai anak. Dan orang yang mengangkat seseorang sebagai anak pada masa jahiliyah orang-orang memanggilnya sebagai anaknya, dan ia mewarisi sebagian harta warisannya hingga Allah 'azza wajalla menurunkan wahyu mengenai hal tersebut: Panggilah mereka (anak-anak angkat itu) dengan (memakai) nama bapak-bapak mereka; itulah yang lebih adil pada sisi Allah, dan jika kamu tidak mengetahui bapak-bapak mereka, maka (panggilah mereka sebagai) saudara-saudaramu seagama dan maula-maulamu (hamba sahaya yang sudah dimerdekakan atau seorang yang telah dijadikan anak angkat). Maka orang yang tidak diketahui ayahnya ia adalah maula dan saudara seagama. "},"3080":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا أَيُّوبُ بْنُ سُلَيْمَانَ بْنِ بِلَالٍ قَالَ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي أُوَيْسٍ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ قَالَ قَالَ يَحْيَى يَعْنِي ابْنَ سَعِيدٍ وَأَخْبَرَنِي ابْنُ شِهَابٍ قَالَ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ وَابْنُ عَبْدِ اللَّهِ بْنِ رَبِيعَةَ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ أَبَا حُذَيْفَةَ بْنَ عُتْبَةَ بْنِ رَبِيعَةَ بْنِ عَبْدِ شَمْسٍ وَكَانَ مِمَّنْ شَهِدَ بَدْرًا مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَبَنَّى سَالِمًا وَهُوَ مَوْلًى لِامْرَأَةٍ مِنْ الْأَنْصَارِ كَمَا تَبَنَّى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَيْدَ بْنَ حَارِثَةَ وَأَنْكَحَ أَبُو حُذَيْفَةَ بْنُ عُتْبَةَ سَالِمًا ابْنَةَ أَخِيهِ هِنْدَ ابْنَةَ الْوَلِيدِ بْنِ عُتْبَةَ بْنِ رَبِيعَةَ وَكَانَتْ هِنْدُ بِنْتُ الْوَلِيدِ بْنِ عُتْبَةَ مِنْ الْمُهَاجِرَاتِ الْأُوَلِ وَهِيَ يَوْمَئِذٍ مِنْ أَفْضَلِ أَيَامَى قُرَيْشٍ فَلَمَّا أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ فِي زَيْدِ بْنِ حَارِثَةَ{ ادْعُوهُمْ لِآبَائِهِمْ هُوَ أَقْسَطُ عِنْدَ اللَّهِ }رُدَّ كُلُّ أَحَدٍ يَنْتَمِي مِنْ أُولَئِكَ إِلَى أَبِيهِ فَإِنْ لَمْ يَكُنْ يُعْلَمُ أَبُوهُ رُدَّ إِلَى مَوَالِيهِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Nashr], ia berkata; telah menceritakan kepada kami [Ayyub bin Sulaiman bin Hilal], ia berkata; telah menceritakan kepadaku [Abu Bakr bin Abi Uwais] dari [Sulaiman bin Bilal], ia berkata; telah berkata [Yahya yaitu Ibnu Sa'id] dan telah mengkhabarkan kepadaku [Ibnu Syihab], ia berkata; telah menceritakan kepadaku ['Urwah bin Az Zubair] serta [Ibnu Abdullah bin Rabi'ah] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam serta [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam; bahwa Abu Hudzaifah bin 'Utbah bin Rabi'ah bin 'Abdu Syams yang merupakan diantara orang yang menyaksikan perang Badr bersama Rasulullah shallallahu 'alaihi wasallam mengangkat Salim sebagai anak, dan ia adalah sahaya seorang wanita Anshar yang telah dimerdekakan sebagaimana Rasulullah shallallahu 'alaihi wasallam mengangkat Zaid bin Haritsah sebagai anak. Dan Abu Hudzaifah bin 'Utbah menikahkan Salim dengan anak wanita saudaranya yaitu Hindun binti Al Walid bin 'Utbah bin Rabi'ah, dan Hindun binti Al Walid bin 'Utbah adalah diantara wanita-wanita pertama yang melakukan hijrah, dan pada saat itu ia adalah janda Quraisy yang terbaik. Kemudian tatkala Allah 'azza wajalla menurunkan ayat mengenai Zaid bin Haritsah: Panggilah mereka (anak-anak angkat itu) dengan (memakai) nama bapak-bapak mereka; itulah yang lebih adil pada sisi Allah. Maka setiap orang yang dinisbatkan dari mereka dikembalikan kepada ayahnya, dan apabila tidak diketahui ayahnya maka dikembalikan kepada tuan-tuannya. "},"3081":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَبُو تُمَيْلَةَ عَنْ حُسَيْنِ بْنِ وَاقِدٍ عَنْ ابْنِ بُرَيْدَةَ عَنْ أَبِيهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَحْسَابَ أَهْلِ الدُّنْيَا الَّذِي يَذْهَبُونَ إِلَيْهِ الْمَالُ","id":"Telah mengkhabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Abu Tumailah] dari [Husain bin Waqid] dari [Ibnu Buraidah] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya keturunan-keturunan penduduk dunia yang mereka tuju adalah harta.\""},"3082":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ عَبْدِ الْمَلِكِ عَنْ عَطَاءٍ عَنْ جَابِرٍأَنَّهُ تَزَوَّجَ امْرَأَةً عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَقِيَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَتَزَوَّجْتَ يَا جَابِرُ قَالَ قُلْتُ نَعَمْ قَالَ بِكْرًا أَمْ ثَيِّبًا قَالَ قُلْتُ بَلْ ثَيِّبًا قَالَ فَهَلَّا بِكْرًا تُلَاعِبُكَ قَالَ قُلْتُ يَا رَسُولَ اللَّهِ كُنَّ لِي أَخَوَاتٌ فَخَشِيتُ أَنْ تَدْخُلَ بَيْنِي وَبَيْنَهُنَّ قَالَ فَذَاكَ إِذًا إِنَّ الْمَرْأَةَ تُنْكَحُ عَلَى دِينِهَا وَمَالِهَا وَجَمَالِهَا فَعَلَيْكَ بِذَاتِ الدِّينِ تَرِبَتْ يَدَاكَ","id":"Telah mengkhabarkan kepada kami [Isma'il bin Mas'ud], ia berkata; telah menceritakan kepada kami [Khalid] dari [Abdul Malik] dari ['Atho`] dari [Jabir] bahwa ia menikahi seorang wanita pada masa Rasulullah shallallahu 'alaihi wasallam kemudian Nabi shallallahu 'alaihi wasallam berjumpa dengannya lalu bertanya: \"Apakah engkau telah menikah wahai Jabir?\" Jabir berkata; saya katakan; ya. Beliau bersabda: \"Gadis atau janda?\" Ia mengatakan; saya katakan; janda. Maka beliau bersabda: \"Tidakkah engkau menikahi seorang gadis sehingga ia dapat mencandaimu?\" Ia berkata; maka saya katakan; wahai Rasulullah, saya memiliki beberapa orang saudara wanita, dan saya khawatir ia akan ikut campur tangan antara diriku dan mereka. Beliau bersabda: \"Itulah yang benar kalau begitu, sesungguhnya seorang wanita dinikahi karena agamanya, hartanya, dan kecantikannya. Carilah yang beragama baik maka engkau akan beruntung.\" "},"3083":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ خَالِدٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ هَارُونَ قَالَ أَنْبَأَنَا الْمُسْتَلِمُ بْنُ سَعِيدٍ عَنْ مَنْصُورِ بْنِ زَاذَانَ عَنْ مُعَاوِيَةَ بْنِ قُرَّةَ عَنْ مَعْقِلِ بْنِ يَسَارٍ قَالَجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي أَصَبْتُ امْرَأَةً ذَاتَ حَسَبٍ وَمَنْصِبٍ إِلَّا أَنَّهَا لَا تَلِدُ أَفَأَتَزَوَّجُهَا فَنَهَاهُ ثُمَّ أَتَاهُ الثَّانِيَةَ فَنَهَاهُ ثُمَّ أَتَاهُ الثَّالِثَةَ فَنَهَاهُ فَقَالَ تَزَوَّجُوا الْوَلُودَ الْوَدُودَ فَإِنِّي مُكَاثِرٌ بِكُمْ","id":"Telah mengkhabarkan kepada kami [Abdur Rahman bin Khalid], ia berkata; telah menceritakan kepada kami [Yazid bin Harun], ia berkata; telah memberitakan kepada kami [Al Mustalim bin Sa'id] dari [Manshur bin Zadzan] dari [Mu'awiyah bin Qurrah] dari [Ma'qil bin Yasar], ia berkata; telah datang seorang laki-laki kepada Rasulullah shallallahu 'alaihi wasallam dan berkata sesungguhnya aku mendapati seorang wanita yang memiliki kedudukan dan harta hanya saja ia mandul, apakah aku boleh menikahinya? Maka beliau melarangnya, kemudian ia mendatangi beliau untuk kedua kalinya dan beliau melarangnya, kemudian ia mendatangi beliau ketiga kalinya, lalu beliau melarangnya dan bersabda: \" Nikahilah wanita yang subur dan pengasih, karena aku bangga dengan banyak anak kalian.\""},"3084":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ مُحَمَّدٍ التَّيْمِيُّ قَالَ حَدَّثَنَا يَحْيَى هُوَ ابْنُ سَعِيدٍ عَنْ عُبَيْدِ اللَّهِ بْنِ الْأَخْنَسِ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّ مَرْثَدَ بْنَ أَبِي مَرْثَدٍ الْغَنَوِيَّ وَكَانَ رَجُلًا شَدِيدًا وَكَانَ يَحْمِلُ الْأُسَارَى مِنْ مَكَّةَ إِلَى الْمَدِينَةِ قَالَ فَدَعَوْتُ رَجُلًا لِأَحْمِلَهُ وَكَانَ بِمَكَّةَ بَغِيٌّ يُقَالُ لَهَا عَنَاقُ وَكَانَتْ صَدِيقَتَهُ خَرَجَتْ فَرَأَتْ سَوَادِي فِي ظِلِّ الْحَائِطِ فَقَالَتْ مَنْ هَذَا مَرْثَدٌ مَرْحَبًا وَأَهْلًا يَا مَرْثَدُ انْطَلِقْ اللَّيْلَةَ فَبِتْ عِنْدَنَا فِي الرَّحْلِ قُلْتُ يَا عَنَاقُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَرَّمَ الزِّنَا قَالَتْ يَا أَهْلَ الْخِيَامِ هَذَا الدُّلْدُلُ هَذَا الَّذِي يَحْمِلُ أُسَرَاءَكُمْ مِنْ مَكَّةَ إِلَى الْمَدِينَةِ فَسَلَكْتُ الْخَنْدَمَةَ فَطَلَبَنِي ثَمَانِيَةٌ فَجَاءُوا حَتَّى قَامُوا عَلَى رَأْسِي فَبَالُوا فَطَارَ بَوْلُهُمْ عَلَيَّ وَأَعْمَاهُمْ اللَّهُ عَنِّي فَجِئْتُ إِلَى صَاحِبِي فَحَمَلْتُهُ فَلَمَّا انْتَهَيْتُ بِهِ إِلَى الْأَرَاكِ فَكَكْتُ عَنْهُ كَبْلَهُ فَجِئْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ أَنْكِحُ عَنَاقَ فَسَكَتَ عَنِّي فَنَزَلَتْ{ الزَّانِيَةُ لَا يَنْكِحُهَا إِلَّا زَانٍ أَوْ مُشْرِكٌ }فَدَعَانِي فَقَرَأَهَا عَلَيَّ وَقَالَ لَا تَنْكِحْهَا","id":"Telah mengkhabarkan kepada kami [Ibrahim bin Muhammad At Taimi], ia berkata; telah menceritakan kepada kami [Yahya yaitu Ibnu Sa'id] dari ['Ubaidullah bin Al Akhnas] dari ['Amr bin Syu'aib] dari [ayahnya] dari [kakeknya] bahwa Martsad bin Abi Martsad Al Ghanawi ia adalah orang yang keras, dan membawa tawanan dari Mekkah ke Madinah, ia berkata; lalu aku memanggil seseorang agar aku membawanya, dan di Makkah ada seorang pelacur yang bernama 'Anaq yang ia dahulu adalah temannya, wanita tersebut keluar lalu melihat warna hitamku dibawah bayangan dinding, ia berkata siapa ini? Martsad? Selamat datang wahai Martsad datanglah malam ini dan bermalamlah dirumahku. Saya katakan; wahai 'Anaq sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah mengharamkan zina. Wanita tersebut berkata; wahai orang-orang yang ada dikemah, ini ada seekor landak yang membawa tawanan kalian dari Mekkah ke Madinah, lalu aku berjalan di gunung kemudian terdapat delapan orang yang mencariku, mereka datang dan berdiri diatas kepalaku lalu kencing, dan kencing mereka beterbangan mengenaiku dan Allah membutakan mereka dari melihatku, kemudian aku mendatangi temanku dan membawanya, ketika aku sampai di dipan aku melepas ikatannya, lalu aku menemui Rasulullah shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah; bolehkan saya menikahi 'Anaq, lalu beliau diam dan turunlah ayat perempuan yang berzina tidak dikawini melainkan oleh laki-laki yang berzina atau laki-laki musyrik. lalu beliau mamanggilku dan bersabda: \" Janganlah engkau menikahinya.\""},"3085":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ وَغَيْرُهُ عَنْ هَارُونَ بْنِ رِئَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ وَعَبْدِ الْكَرِيمِ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَبْدُ الْكَرِيمِ يَرْفَعُهُ إِلَى ابْنِ عَبَّاسٍ وَهَارُونُ لَمْ يَرْفَعْهُ قَالَاجَاءَ رَجُلٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ عِنْدِي امْرَأَةً هِيَ مِنْ أَحَبِّ النَّاسِ إِلَيَّ وَهِيَ لَا تَمْنَعُ يَدَ لَامِسٍ قَالَ طَلِّقْهَا قَالَ لَا أَصْبِرُ عَنْهَا قَالَ اسْتَمْتِعْ بِهَاقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا الْحَدِيثُ لَيْسَ بِثَابِتٍ وَعَبْدُ الْكَرِيمِ لَيْسَ بِالْقَوِيِّ وَهَارُونُ بْنُ رِئَابٍ أَثْبَتُ مِنْهُ وَقَدْ أَرْسَلَ الْحَدِيثَ وَهَارُونُ ثِقَةٌ وَحَدِيثُهُ أَوْلَى بِالصَّوَابِ مِنْ حَدِيثِ عَبْدِ الْكَرِيمِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim], ia berkata; telah menceritakan kepada kami [Yazid], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dan yang lainnya dari [Harun bin Riab] dari [Abdullah bin 'Ubaid bin 'Umair] dan -dari jalur lain- ['Abdul Karim] dari [Abdulah bin 'Ubaid bin 'Umair] dari [Ibn Abbas] yang dimarfu'kan Abdulkarim dan Harun tidak memarfu'kannya, mereka berdua berkata; telah datang seseorang laki-laki kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; aku mempunyai seorang istri yang paling aku cintai, namun ia tidak menolak tangan orang yang menyentuhnya, beliau bersabda: \" Ceraikan dia, \" ia berkata; aku tidak bisa bersabar berpisah darinya, beliau bersabda: \" Bersenang-senanglah dengannya, \" Abu Abdurrahman berkata hadits ini tidak kokoh, dan Abdul Karim bukan orang yang kuat, adapun Harun bin Ritsab lebih kuat darinya, dan ia telah memursalkan hadits tersebut, Harun adalah orang yang tsiqah dan haditsnya lebih benar daripada hadits Abdul Karim."},"3086":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ تُنْكَحُ النِّسَاءُ لِأَرْبَعَةٍ لِمَالِهَا وَلِحَسَبِهَا وَلِجَمَالِهَا وَلِدِينِهَا فَاظْفَرْ بِذَاتِ الدِّينِ تَرِبَتْ يَدَاكَ","id":"Telah mengkhabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah] dari [Sa'id bin Abi Sa'id] dari [ayahnya] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Wanita dinikahi karena empat perkara, karena hartanya, keturunannya, kecantikannya dan agamanya. Dapatnya yang memiliki agama baik maka engkau akan beruntung.\""},"3087":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ عَجْلَانَ عَنْ سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَقِيلَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّ النِّسَاءِ خَيْرٌ قَالَ الَّتِي تَسُرُّهُ إِذَا نَظَرَ وَتُطِيعُهُ إِذَا أَمَرَ وَلَا تُخَالِفُهُ فِي نَفْسِهَا وَمَالِهَا بِمَا يَكْرَهُ","id":"Telah mengkhabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu 'Ajlan] dari [Sa'id Al Maqburi] dari [Abu Hurairah], ia berkata; dikatakan kepada Rasulullah shallallahu 'alaihi wasallam; siapakah wanita yang paling baik? Beliau menjawab: \" Yang paling menyenangkannya jika dilihat suaminya, dan mentaatinya jika ia memerintahkannya dan tidak menyelisihinya dalam diri dan hartanya dengan apa yang dibenci suaminya.\""},"3088":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا حَيْوَةُ وَذَكَرَ آخَرَ أَنْبَأَنَا شُرَحْبِيلُ بْنُ شَرِيكٍ أَنَّهُ سَمِعَ أَبَا عَبْدِ الرَّحْمَنِ الْحُبُلِيَّ يُحَدِّثُ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ الْعَاصِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ الدُّنْيَا كُلَّهَا مَتَاعٌ وَخَيْرُ مَتَاعِ الدُّنْيَا الْمَرْأَةُ الصَّالِحَةُ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah bin Yazid], ia berkata; telah menceritakan kepada kami [ayahku] ia berkata; telah menceritakan kepada kami [Haiwah] dan ia menyebutkan yang lain, telah memberitakan kepada kami [Syurahbil bin Syarik] bahwa ia pernah mendengar [Abu Abdur Rahman Al Hubuli] menceritakan dari [Abdullah bin 'Amr bin Al 'Ash] bahwa Rasulullah shallallahu 'alaihi wasallam berfirman: \"Sesungguhnya dunia seluruhnya adalah perhiasan, dan sebaik-baik perhiasan dunia adalah wanita Shalihah.\""},"3089":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ أَنْبَأَنَا النَّضْرُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ إِسْحَقَ بْنِ عَبْدِ اللَّهِ عَنْ أَنَسٍقَالُوا يَا رَسُولَ اللَّهِ أَلَا تَتَزَوَّجُ مِنْ نِسَاءِ الْأَنْصَارِ قَالَ إِنَّ فِيهِمْ لَغَيْرَةً شَدِيدَةً","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim] telah memberitakan kepada kami [An Nadhr], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Ishaq bin Abdullah] dari [Anas], para sahabat berkata; wahai Rasulullah, tidakkah engkau menikah dengan wanita Anshor? Beliau menjawab: \"Sesungguhnya mereka memiliki kecemburuan yang besar.\""},"3090":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مَرْوَانُ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَخَطَبَ رَجُلٌ امْرَأَةً مِنْ الْأَنْصَارِ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ نَظَرْتَ إِلَيْهَا قَالَ لَا فَأَمَرَهُ أَنْ يَنْظُرَ إِلَيْهَا","id":"Telah mengkhabarkan kepada kami [Abdur Rahman bin Ibrahim], ia berkata; telah menceritakan kepada kami [Marwan], ia berkata; telah menceritakan kepada kami [Yazid yaitu Kaisan] dari [Abu Hazim] dari [Abu Hurairah], ia berkata; seorang laki-laki melamar seorang wanita Anshar, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Apakah engkau telah melihatnya?\" orang tersebut berkata: \"Tidak.\" Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkannya untuk melihat kepadanya. "},"3091":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْعَزِيزِ بْنِ أَبِي رِزْمَةَ قَالَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ قَالَ حَدَّثَنَا عَاصِمٌ عَنْ بَكْرِ بْنِ عَبْدِ اللَّهِ الْمُزَنِيِّ عَنْ الْمُغِيرَةِ بْنِ شُعْبَةَ قَالَخَطَبْتُ امْرَأَةً عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَظَرْتَ إِلَيْهَا قُلْتُ لَا قَالَ فَانْظُرْ إِلَيْهَا فَإِنَّهُ أَجْدَرُ أَنْ يُؤْدَمَ بَيْنَكُمَا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdul Aziz bin Abi Rizmah], ia berkata; telah menceritakan kepada kami [Hafsh bin Ghiyats], ia berkata; telah menceritakan kepada kami ['Ashim] dari [Bakr bin Abdullah Al Muzani] dari [Al Mughirah bin Syu'bah], ia berkata; saya melamar seorang wanita pada masa Rasulullah shallallahu 'alaihi wasallam, kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah engkau sudah melihatnya?\" saya mengatakan; tidak. Beliau bersabda: \"Lihatlah kepadanya, karena hal itu lebih melanggengkan diantara kalian berdua.\""},"3092":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ قَالَ حَدَّثَنِي إِسْمَعِيلُ بْنُ أُمَيَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْتَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَوَّالٍ وَأُدْخِلْتُ عَلَيْهِ فِي شَوَّالٍ وَكَانَتْ عَائِشَةُ تُحِبُّ أَنْ تُدْخِلَ نِسَاءَهَا فِي شَوَّالٍ فَأَيُّ نِسَائِهِ كَانَتْ أَحْظَى عِنْدَهُ مِنِّي","id":"Telah mengkhabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan], ia berkata; telah menceritakan kepadaku [Isma'il bin Umayyah] dari [Abdullah bin 'Urwah] dari ['Urwah] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menikahiku pada Bulan Syawal dan saya berkumpul dengan beliau pada bulan Syawal. Dan Aisyah ingin memasukkan para wanitanya pada Bulan Syawal. Siapakah isterinya lebih ia cintai daripada diriku? "},"3093":{"ar":"أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنِي عَبْدُ الصَّمَدِ بْنُ عَبْدِ الْوَارِثِ قَالَ سَمِعْتُ أَبِي قَالَ حَدَّثَنَا حُسَيْنٌ الْمُعَلِّمُ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ بُرَيْدَةَ قَالَ حَدَّثَنِي عَامِرُ بْنُ شَرَاحِيلَ الشَّعْبِيُّ أَنَّهُ سَمِعَ فَاطِمَةَ بِنْتَ قَيْسٍ وَكَانَتْ مِنْ الْمُهَاجِرَاتِ الْأُوَلِ قَالَتْخَطَبَنِي عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍ فِي نَفَرٍ مِنْ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَخَطَبَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى مَوْلَاهُ أُسَامَةَ بْنِ زَيْدٍ وَقَدْ كُنْتُ حُدِّثْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ أَحَبَّنِي فَلْيُحِبَّ أُسَامَةَ فَلَمَّا كَلَّمَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ أَمْرِي بِيَدِكَ فَانْكِحْنِي مَنْ شِئْتَ فَقَالَ انْطَلِقِي إِلَى أُمِّ شَرِيكٍ وَأُمُّ شَرِيكٍ امْرَأَةٌ غَنِيَّةٌ مِنْ الْأَنْصَارِ عَظِيمَةُ النَّفَقَةِ فِي سَبِيلِ اللَّهِ عَزَّ وَجَلَّ يَنْزِلُ عَلَيْهَا الضِّيفَانُ فَقُلْتُ سَأَفْعَلُ قَالَ لَا تَفْعَلِي فَإِنَّ أُمَّ شَرِيكٍ كَثِيرَةُ الضِّيفَانِ فَإِنِّي أَكْرَهُ أَنْ يَسْقُطَ عَنْكِ خِمَارُكِ أَوْ يَنْكَشِفَ الثَّوْبُ عَنْ سَاقَيْكِ فَيَرَى الْقَوْمُ مِنْكِ بَعْضَ مَا تَكْرَهِينَ وَلَكِنْ انْتَقِلِي إِلَى ابْنِ عَمِّكِ عَبْدِ اللَّهِ بْنِ عَمْرِو بْنِ أُمِّ مَكْتُومٍ وَهُوَ رَجُلٌ مِنْ بَنِي فِهْرٍ فَانْتَقَلْتُ إِلَيْهِمُخْتَصَرٌ","id":"Telah mengkhabarkan kepada kami [Abdur Rahman bin Muhammad bin Sallam], ia berkata; telah menceritakan kepadaku [Abdush Shamad bin Abdul Warits], ia berkata; saya pernah mendengar [ayahku] berkata; telah menceritakan kepada kami [Husain Al Mu'allim], ia berkata; telah menceritakan kepadaku [Abdullah bin Buraidah], ia berkata; telah menceritakan kepadaku ['Amir bin Syarahil Asy Sya'bi] bahwa ia pernah mendengar [Fathimah binti Qais] dan ia termasuk wanita pertama yang berhijrah berkata; Abdur Rahman bin 'Auf melamarku diantara beberapa orang sahabat Muhammad shallallahu 'alaihi wasallam, dan Rasulullah shallallahu 'alaihi wasallam melamarku untuk maulanya yaitu Usamah bin Zaid, dan telah diceritakan kepadaku bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang mencintaiku maka hendaknya ia mencintai Usamah.\" Tatkala Rasulullah shallallahu 'alaihi wasallam mengajakku berbicara maka saya katakan; urusanku ada ditanganmu, maka nikahkanlah saya dengan orang yang engkau kehendaki. Kemudian beliau bersabda: \"Pergilah kepada Ummu Syarik.\" Dan Ummu Syarik adalah orang yang kaya dari kalangan Anshar, banyak memberikan infak di jalan Allah 'azza wajalla. Banyak tamu yang singgah di rumahnya, lalu saya mengatakan; saya akan melakukannya. Beliau bersabda: \"Jangan engkau lakukan, karena Ummu Syarik banyak tamunya, saya tidak ingin terjatuh darimu penutup kepalamu atau pakaianmu tersingkap dari betismu sehingga orang-orang akan melihat sebagian apa yang tidak engkau suka. Akan tetapi pindahlah ke tempat pamanmu Abdullah bin 'Amr bin Ummi Maktum.\" Ia adalah seorang laki-laki dari Bani Fahr, kemudian saya pindah ke rumahnya. "},"3094":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَخْطُبُ أَحَدُكُمْ عَلَى خِطْبَةِ بَعْضٍ","id":"Telah mengkhabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah seseorang diantara kalian meminang di atas pinangan sebagian yang lainnya.\""},"3095":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ وَسَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ مُحَمَّدٌ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَنَاجَشُوا وَلَا يَبِعْ حَاضِرٌ لِبَادٍ وَلَا يَبِعْ الرَّجُلُ عَلَى بَيْعِ أَخِيهِ وَلَا يَخْطُبْ عَلَى خِطْبَةِ أَخِيهِ وَلَا تَسْأَلْ الْمَرْأَةُ طَلَاقَ أُخْتِهَا لِتَكْتَفِئَ مَا فِي إِنَائِهَا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Manshur] dan [Sa'id bin Abdur Rahman] mereka berdua berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: … Dan (dari redaksi Muhammad, ia berkata) dari Nabi shallallahu 'alaihi wasallam: \"Janganlah saling menawar agar orang lain memberikan penawaran, janganlah orang kota menjualkan untuk orang desa, janganlah seseorang menjual diatas jual beli saudaranya, dan janganlah meminang diatas pinangan saudaranya. Dan janganlah seorang wanita meminta cerai saudaranya agar ia dapat menguasai bagian saudaranya tersebut.\""},"3096":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ ح وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ مُحَمَّدِ بْنِ يَحْيَى بْنِ حَبَّانَ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَخْطُبْ أَحَدُكُمْ عَلَى خِطْبَةِ أَخِيهِ","id":"Telah mengkhabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Ma'an], ia berkata; telah menceritakan kepada kami [Malik] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Muhammad bin Yahya bin Habban] dari [Al A'raj] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang diantara kalian meminang diatas pinangan saudaranya.\""},"3097":{"ar":"أَخْبَرَنِي يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَخْطُبْ أَحَدُكُمْ عَلَى خِطْبَةِ أَخِيهِ حَتَّى يَنْكِحَ أَوْ يَتْرُكَ","id":"Telah mengkhabarkan kepada kami [Yunus bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah mengkhabarkan kepadaku [Yunus] dari [Ibnu Syihab], ia berkata; telah mengkhabarkan kepadaku [Sa'id bin Al Musayyab] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Janganlah seseorang diantara kalian meminang di atas pinangan saudaranya hingga ia menikah atau meniggalkan pinangan tersebut.\""},"3098":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا غُنْدَرٌ عَنْ هِشَامٍ عَنْ مُحَمَّدٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَخْطُبْ أَحَدُكُمْ عَلَى خِطْبَةِ أَخِيهِ","id":"Telah mengkhabarkan kepada kami [QUtaibah], ia berkata; telah menceritakan kepada kami [Ghundur] dari [Hisyam] dari [Muhammad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Janganlah seseorang diantara kalian meminang di atas pinangan saudaranya.\""},"3099":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا الْحَجَّاجُ بْنُ مُحَمَّدٍ قَالَ قَالَ ابْنُ جُرَيْجٍ سَمِعْتُ نَافِعًا يُحَدِّثُ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ كَانَ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَبِيعَ بَعْضُكُمْ عَلَى بَيْعِ بَعْضٍ وَلَا يَخْطُبُ الرَّجُلُ عَلَى خِطْبَةِ الرَّجُلِ حَتَّى يَتْرُكَ الْخَاطِبُ قَبْلَهُ أَوْ يَأْذَنَ لَهُ الْخَاطِبُ","id":"Telah mengkhabarkan kepada kami [Ibrahim bin Al Hasan], ia berkata; telah menceritakan kepada kami [Al Hajjaj bin Muhammad], ia berkata; berkata [Ibnu Juraij]; saya pernah mendengar [Nafi'] menceritakan bahwa [Abdullah bin Umar] pernah berkata; Rasulullah shallallahu 'alaihi wasallam melarang sebagian kalian menjual di atas jual beli sebagian yang lain, dan janganlah seseorang meminang di atas pinangan orang lain hingga orang yang meminang sebelumnya meninggalkan pinangannya atau mengizinkan memberikan izin."},"3100":{"ar":"أَخْبَرَنِي حَاجِبُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا ابْنُ أَبِي ذِئْبٍ عَنْ الزُّهْرِيِّ وَيَزِيدُ بْنُ عَبْدِ اللَّهِ بْنِ قُسَيْطٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ وَعَنْ الْحَارِثِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ بْنِ ثَوْبَانَأَنَّهُمَا سَأَلَا فَاطِمَةَ بِنْتَ قَيْسٍ عَنْ أَمْرِهَا فَقَالَتْ طَلَّقَنِي زَوْجِي ثَلَاثًا فَكَانَ يَرْزُقُنِي طَعَامًا فِيهِ شَيْءٌ فَقُلْتُ وَاللَّهِ لَئِنْ كَانَتْ لِي النَّفَقَةُ وَالسُّكْنَى لَأَطْلُبَنَّهَا وَلَا أَقْبَلُ هَذَا فَقَالَ الْوَكِيلُ لَيْسَ لَكِ سُكْنَى وَلَا نَفَقَةٌ قَالَتْ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ فَقَالَ لَيْسَ لَكِ سُكْنَى وَلَا نَفَقَةٌ فَاعْتَدِّي عِنْدَ فُلَانَةَ قَالَتْ وَكَانَ يَأْتِيهَا أَصْحَابُهُ ثُمَّ قَالَ اعْتَدِّي عِنْدَ ابْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ أَعْمَى فَإِذَا حَلَلْتِ فَآذِنِينِي قَالَتْ فَلَمَّا حَلَلْتُ آذَنْتُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَنْ خَطَبَكِ فَقُلْتُ مُعَاوِيَةُ وَرَجُلٌ آخَرُ مِنْ قُرَيْشٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا مُعَاوِيَةُ فَإِنَّهُ غُلَامٌ مِنْ غِلْمَانِ قُرَيْشٍ لَا شَيْءَ لَهُ وَأَمَّا الْآخَرُ فَإِنَّهُ صَاحِبُ شَرٍّ لَا خَيْرَ فِيهِ وَلَكِنْ انْكِحِي أُسَامَةَ بْنَ زَيْدٍ قَالَتْ فَكَرِهْتُهُ فَقَالَ لَهَا ذَلِكَ ثَلَاثَ مَرَّاتٍ فَنَكَحَتْهُ","id":"Telah mengkhabarkan kepada kami [Hajib bin Sulaiman], ia berkata; telah menceritakan kepada kami [Hajjaj], ia berkata; telah menceritakan kepada kami [Ibnu Abi Dzi`b] dari [Az Zuhri] dan [Yazid bin Abdullah bin Qusaith] dari [Abu Salamahbin Abdur Rahman] dan dari [Al Harits bin Abdur Rahman] dan [Muhammad bin Abdur Rahman bin Tsauban] bahwa keduanya bertanya kepada [Fathimah binti Qais] mengenai perkaranya, kemudian ia berkata; suamiku telah menceraikanku tiga kali, dan dia dahulu memberiku makan. Kemudian saya katakan; demi Allah seandainya saya mendapatkan nafkah dan tempat tinggal niscaya saya akan memintanya, dan tidak menerima hal ini. Kemudian wakilnya mengatakan; engkau tidak mendapatkan tempat tinggal dan nafkah. Fathimah berkata; kemudian saya datang kepada Nabi shallallahu 'alaihi wasallam dan menyebutkan hal tersebut kepadanya. Lalu beliau bersabda: \"Engkau tidak mendapatkan tempat tinggal dan nafkah, maka ber'iddahlah di rumah Fulanah.\" Ia berkata; ia sering didatangi para sahabat beliau, kemudian beliau bersabda: \"Ber'iddahlah di rumah Ibnu Ummi Maktum karena sesungguhnya ia adalah orang yang buta, kemudian apabila engkau telah halal maka beritahu saya.\" Ia berkata; kemudian setelah saya halal maka saya beritahu beliau. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah yang melamarmu?\" kemudian saya katakan; Mu'awiyah dan seorang laki-laki lain dari kalangan Quraisy. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Adapun Mu'awiyah maka ia adalah seorang pemuda dari pemuda-pemuda Quraisy yang tidak memiliki apa-apa, adapun yang lain sesungguhnya ia adalah orang yang berperangai buruk dan tidak ada kebaikan padanya. Akan tetapi menikahlah dengan Usamah bin Zaid.\" Ia berkata; maka saya tidak menyukainya. Kemudian beliau mengucapkan hal tersebut kepadanya sebanyak tiga kali, sehingga saya menikah dengannya. "},"3101":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لِمُحَمَّدٍ عَنْ ابْنِ الْقَاسِمِ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍأَنَّ أَبَا عَمْرِو بْنَ حَفْصٍ طَلَّقَهَا الْبَتَّةَ وَهُوَ غَائِبٌ فَأَرْسَلَ إِلَيْهَا وَكِيلُهُ بِشَعِيرٍ فَسَخِطَتْهُ فَقَالَ وَاللَّهِ مَا لَكِ عَلَيْنَا مِنْ شَيْءٍ فَجَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَقَالَ لَيْسَ لَكِ نَفَقَةٌ فَأَمَرَهَا أَنْ تَعْتَدَّ فِي بَيْتِ أُمِّ شَرِيكٍ ثُمَّ قَالَ تِلْكَ امْرَأَةٌ يَغْشَاهَا أَصْحَابِي فَاعْتَدِّي عِنْدَ ابْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ رَجُلٌ أَعْمَى تَضَعِينَ ثِيَابَكِ فَإِذَا حَلَلْتِ فَآذِنِينِي قَالَتْ فَلَمَّا حَلَلْتُ ذَكَرْتُ لَهُ أَنَّ مُعَاوِيَةَ بْنَ أَبِي سُفْيَانَ وَأَبَا جَهْمٍ خَطَبَانِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَّا أَبُو جَهْمٍ فَلَا يَضَعُ عَصَاهُ عَنْ عَاتِقِهِ وَأَمَّا مُعَاوِيَةُ فَصُعْلُوكٌ لَا مَالَ لَهُ وَلَكِنْ انْكِحِي أُسَامَةَ بْنَ زَيْدٍ فَكَرِهْتُهُ ثُمَّ قَالَ انْكِحِي أُسَامَةَ بْنَ زَيْدٍ فَنَكَحْتُهُ فَجَعَلَ اللَّهُ عَزَّ وَجَلَّ فِيهِ خَيْرًا وَاغْتَبَطْتُ بِهِ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, lafazhnya adalah lafazh Muhammad, dari [Ibnu Al Qasim] dari [Malik] dari [Abdullah bin Yazid] dari [Abu Salamah bin Abdur Rahman] dari [Fathimah binti Qais] bahwa Abu 'Amr bin Hafsh menceraikannya sama sekali, dan ia tidak hadir. Kemudian wakilnya mengirimkan gandum kepadanya, lalu iapun marah. Kemudian wakil tersebut berkata; demi Allah, engkau tidak memiliki hak sedikitpun atas kami. Kemudian ia datang kepada Rasulullah shallallahu 'alaihi wasallam dan menyebutkan hal tersebut kepadanya. Kemduian beliau bersabda: \"Engkau tidak mendapatkan nafkah.\" Kemudian beliau memerintahkannya agar ber'iddah di rumah Ummu Syarik, kemudian beliau bersabda: \"Orang itu adalah wanita yang sering didatangi para sahabatku, maka ber'iddahlah di rumah Ibnu Ummi Maktum, karena ia adalah laki-laki yang buta, engkau dapat meletakkan pakaianmu. Kemudian apabila engkau telah halal maka beritahu saya.\" Ia berkata; kemudian setelah halal, saya menyebutkan kepada beliau bahwa Mu'awiyah bin Sufyan dan Abu Jahm telah melamarnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Adapun Abu Jahm maka ia tidak pernah meletakkan tongkatnya dari pundak, adapun Mu'awiyah maka ia adalah orang yang miskin tidak memiliki harta. Akan tetapi menikahlah dengan Usamah bin Zaid.\" Lalu saya membencinya, kemudian beliau bersabda: \"Menikahlah dengan Usamah bin Zaid.\" Maka saya menikah dengannya. Lalu Allah 'azza wajalla menjadikan padanya kebaikan dan sayapun iri kepadanya. "},"3102":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ هَاشِمِ بْنِ الْبَرِيدِ عَنْ يَزِيدَ بْنِ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ مِنْ الْأَنْصَارِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنِّي تَزَوَّجْتُ امْرَأَةً فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَا نَظَرْتَ إِلَيْهَا فَإِنَّ فِي أَعْيُنِ الْأَنْصَارِ شَيْئًاقَالَ أَبُو عَبْد الرَّحْمَنِ وَجَدْتُ هَذَا الْحَدِيثَ فِي مَوْضِعٍ آخَرَ عَنْ يَزِيدَ بْنِ كَيْسَانَ أَنَّ جَابِرَ بْنَ عَبْدِ اللَّهِ حَدَّثَ وَالصَّوَابُ أَبُو هُرَيْرَةَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Adam], ia berkata; telah menceritakan kepada kami [Ali bin Hasyim bin Al Barid] dari [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah], ia berkata; telah datang seorang laki-laki dari kalangan Anshar kepada Rasulullah shallallahu 'alaihi wasallam seraya berkata; sesungguhnya saya telah menikah dengan seorang wanita. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Tidakkah engkau melihat kepadanya? Karena sesungguhnya pada mata orang-orang Anshar terdapat sesuatu.\" Abu Abdur Rahman berkata; saya mendapatkan hadits ini pada tempat yang lain dari Yazid bin Kaisan bahwa Jabir bin Abdullah telah menceritakan…. Dan yang benar adalah Abu Hurairah. "},"3103":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يَزِيدَ بْنِ كَيْسَانَ عَنْ أَبِي حَازِمٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا أَرَادَ أَنْ يَتَزَوَّجَ امْرَأَةً فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْظُرْ إِلَيْهَا فَإِنَّ فِي أَعْيُنِ الْأَنْصَارِ شَيْئًا","id":"Telah mengkhabarkan kepada kami [Muhammad bin Abdullah bin Yazid], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Yazid bin Kaisan] dari [Abu Hazim] dari [Abu Hurairah] bahwa seorang laki-laki ingin menikahi seorang wanita kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Lihatlah kepadanya karena sesungguhnya pada mata orang-orang Anshar terdapat sesuatu.\""},"3104":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ قَالَتَأَيَّمَتْ حَفْصَةُ بِنْتُ عُمَرَ مِنْ خُنَيْسٍ يَعْنِي ابْنَ حُذَافَةَ وَكَانَ مِنْ أَصْحَابِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِمَّنْ شَهِدَ بَدْرًا فَتُوُفِّيَ بِالْمَدِينَةِ فَلَقِيتُ عُثْمَانَ بْنَ عَفَّانَ فَعَرَضْتُ عَلَيْهِ حَفْصَةَ فَقُلْتُ إِنْ شِئْتَ أَنْكَحْتُكَ حَفْصَةَ فَقَالَ سَأَنْظُرُ فِي ذَلِكَ فَلَبِثْتُ لَيَالِيَ فَلَقِيتُهُ فَقَالَ مَا أُرِيدُ أَنْ أَتَزَوَّجَ يَوْمِي هَذَا قَالَ عُمَرُ فَلَقِيتُ أَبَا بَكْرٍ الصِّدِّيقَ رَضِيَ اللَّهُ عَنْهُ فَقُلْتُ إِنْ شِئْتَ أَنْكَحْتُكَ حَفْصَةَ فَلَمْ يَرْجِعْ إِلَيَّ شَيْئًا فَكُنْتُ عَلَيْهِ أَوْجَدَ مِنِّي عَلَى عُثْمَانَ رَضِيَ اللَّهُ عَنْهُ فَلَبِثْتُ لَيَالِيَ فَخَطَبَهَا إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْكَحْتُهَا إِيَّاهُ فَلَقِيَنِي أَبُو بَكْرٍ فَقَالَ لَعَلَّكَ وَجَدْتَ عَلَيَّ حِينَ عَرَضْتَ عَلَيَّ حَفْصَةَ فَلَمْ أَرْجِعْ إِلَيْكَ شَيْئًا قُلْتُ نَعَمْ قَالَ فَإِنَّهُ لَمْ يَمْنَعْنِي حِينَ عَرَضْتَ عَلَيَّ أَنْ أَرْجِعَ إِلَيْكَ شَيْئًا إِلَّا أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُهَا وَلَمْ أَكُنْ لِأُفْشِيَ سِرَّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَوْ تَرَكَهَا نَكَحْتُهَا","id":"Telah mengkhabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abdur Razzaq], ia berkata; telah memberitakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Salim] dari [Ibnu Umar] dari [Umar], ia berkata; Hafshah telah menjadi janda dari Khunais yaitu Ibnu Hudzafah, kemudian saya bertemu dengan Utsman bin Affan dan menawarkan Hafshah kepadanya. Lalu saya katakan; apabila engkau menghendaki maka saya akan menikahkanmu dengan Hafshah. Kemudian Utsman berkata; saya akan memperhatikan mengenai hal tersebut. Lalu saya menunggu beberapa malam, kemudian bertemu dengannya seraya ia berkata; hari ini saya tidak ingin untuk menikah. Umar berkata; kemudian saya bertemu dengan Abu Bakr Ash Shiddiq radliallahu 'anhu lalu saya katakan; jika engkau menghendaki maka saya akan menikahkanmu dengan Hafshah. Kemudian ia tidak membawa jawaban sedikitpun kepadaku, dan saya lebih marah kepadanya daripada kepada Utsman radliallahu 'anhu. Lalu saya menunggu beberapa malam, kemudian Rasulullah shallallahu 'alaihi wasallam meminangnya kepadaku. Maka saya menikahkannya dengan beliau, kemudian Abu Bakr menemuiku dan berkata; kemungkinan engkau marah kepadaku ketika engkau menawarkan Hafshah kepadaku kemudian saya tidak membawa jawaban sedikitpun kepadamu? Maka saya katakan; ya. Ia berkata; sesungguhnya tidak ada yang menghalangiku ketika engkau menawarkan kepadaku untuk kembali kepadamu dengan sesuatu kecuali saya telah mendengar Rasulullah shallallahu 'alaihi wasallam menyebutkannya dan saya tidak akan menyebarkan rahasia Rasulullah shallallahu 'alaihi wasallam, dan jika beliau meninggalkannya maka saya akan menikahinya."},"3105":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنِي مَرْحُومُ بْنُ عَبْدِ الْعَزِيزِ الْعَطَّارُ أَبُو عَبْدِ الصَّمَدِ قَالَ سَمِعْتُ ثَابِتًا الْبُنَانِيَّ يَقُولُ كُنْتُ عِنْدَ أَنَسِ بْنِ مَالِكٍ وَعِنْدَهُ ابْنَةٌ لَهُ فَقَالَجَاءَتْ امْرَأَةٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَرَضَتْ عَلَيْهِ نَفْسَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ أَلَكَ فِيَّ حَاجَةٌ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepadaku [Marhum bin Abdul Aziz Al 'Aththar Abu Abdush Shamad], ia berkata; saya pernah mendengar [Tsabit Al Bunani] berkata; saya pernah berada di sisi [Anas bin Malik], dan di sisinya terdapat anak wanitanya. Kemudian ia berkata; telah datang seorang wanita kepada Rasulullah shallallahu 'alaihi wasallam kemudian menawarkan dirinya kepada beliau. Ia berkata; wahai Rasulullah, apakah engkau menginginkan diriku?\""},"3106":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مَرْحُومٌ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ امْرَأَةً عَرَضَتْ نَفْسَهَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَفَضَحِكَتْ ابْنَةُ أَنَسٍ فَقَالَتْ مَا كَانَ أَقَلَّ حَيَاءَهَا فَقَالَ أَنَسٌ هِيَ خَيْرٌ مِنْكِ عَرَضَتْ نَفْسَهَا عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengkhabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Marhum], ia berkata; telah menceritakan kepada kami [Tzabit] dari [Anas] bahwa terdapat seorang wanita yang menawarkan dirinya kepada Nabi shallallahu 'alaihi wasallam, kemudian anak wanita Anas tertawa, kemudian berkata; betapa sedikit rasa malunya. Kemudian Anas berkata; ia lebih baik darimu, ia menawarkan dirinya kepada nabi shallallahu 'alaihi wasallam. "},"3107":{"ar":"أَخْبَرَنَا سُوَيْدُ بْنُ نَصْرٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ الْمُغِيرَةِ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَلَمَّا انْقَضَتْ عِدَّةُ زَيْنَبَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِزَيْدٍ اذْكُرْهَا عَلَيَّ قَالَ زَيْدٌ فَانْطَلَقْتُ فَقُلْتُ يَا زَيْنَبُ أَبْشِرِي أَرْسَلَنِي إِلَيْكِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَذْكُرُكِ فَقَالَتْ مَا أَنَا بِصَانِعَةٍ شَيْئًا حَتَّى أَسْتَأْمِرَ رَبِّي فَقَامَتْ إِلَى مَسْجِدِهَا وَنَزَلَ الْقُرْآنُ وَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ بِغَيْرِ أَمْرٍ","id":"Telah mengkhabarkan kepada kami [Suwaid bin Nashr], ia berkata; telah memberitakan kepada kami [Abdullah], ia berkata; telah menceritakan kepada kami [Sulaiman bin Al Mughirah] dari [Tsabit] dari [Anas], ia berkata; tatkala telah habis 'iddah Zainab, Rasulullah shallallahu 'alaihi wasallam bersabda kepada Zaid: \"Sebutkan saya kepadanya.\" Zaid berkata; kemudian saya pergi dan berkata; wahai Zainab, bergembiralah. Saya diutus Rasulullah shallallahu 'alaihi wasallam kepadamu, beliau menyebut dirimu. Kemudian ia berkata; saya tidak dapat berbuat sesuatupun hingga meminta petunjuk kepada Tuhanku. Kemudian ia beranjak menuju Masjidnya dan turunlah Al Qur'an. Dan Rasulullah shallallahu 'alaihi wasallam datang kemudian masuk tanpa perintah. "},"3108":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ يَحْيَى الصُّوفِيُّ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا عِيسَى بْنُ طَهْمَانَ أَبُو بَكْرٍ سَمِعْتُ أَنَسَ بْنَ مَالِكٍ يَقُولُكَانَتْ زَيْنَبُ بِنْتُ جَحْشٍ تَفْخَرُ عَلَى نِسَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُ إِنَّ اللَّهَ عَزَّ وَجَلَّ أَنْكَحَنِي مِنْ السَّمَاءِ وَفِيهَا نَزَلَتْ آيَةُ الْحِجَابِ","id":"Telah mengkhabarkan kepada kami [Ahmad bin Yahya Ash Shufi], ia berkata; telah menceritakan kepada kami [Abu Nu'im], ia berkata; telah menceritakan kepada kami [Isa bin Thahman Abu Bakr] saya pernah mendengar [Anas bin Malik] berkata; dahulu Zainab binti Jahsy berbangga diri kepada isteri-isteri Nabi shallallahu 'alaihi wasallam, ia berkata; sesungguhnya Allah 'azza wajalla telah menikahkan diriku dari langit. Dan mengenai dirinya turunlah ayat hijab."},"3109":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا ابْنُ أَبِي الْمَوَالِ عَنْ مُحَمَّدِ بْنِ الْمُنْكَدِرِ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يُعَلِّمُنَا الِاسْتِخَارَةَ فِي الْأُمُورِ كُلِّهَا كَمَا يُعَلِّمُنَا السُّورَةَ مِنْ الْقُرْآنِ يَقُولُ إِذَا هَمَّ أَحَدُكُمْ بِالْأَمْرِ فَلْيَرْكَعْ رَكْعَتَيْنِ مِنْ غَيْرِ الْفَرِيضَةِ ثُمَّ يَقُولُ اللَّهُمَّ إِنِّي أَسْتَخِيرُكَ بِعِلْمِكَ وَأَسْتَعِينُكَ بِقُدْرَتِكَ وَأَسْأَلُكَ مِنْ فَضْلِكَ الْعَظِيمِ فَإِنَّكَ تَقْدِرُ وَلَا أَقْدِرُ وَتَعْلَمُ وَلَا أَعْلَمُ وَأَنْتَ عَلَّامُ الْغُيُوبِ اللَّهُمَّ إِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الْأَمْرَ خَيْرٌ لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ قَالَ فِي عَاجِلِ أَمْرِي وَآجِلِهِ فَاقْدِرْهُ لِي وَيَسِّرْهُ لِي ثُمَّ بَارِكْ لِي فِيهِ وَإِنْ كُنْتَ تَعْلَمُ أَنَّ هَذَا الْأَمْرَ شَرٌّ لِي فِي دِينِي وَمَعَاشِي وَعَاقِبَةِ أَمْرِي أَوْ قَالَ فِي عَاجِلِ أَمْرِي وَآجِلِهِ فَاصْرِفْهُ عَنِّي وَاصْرِفْنِي عَنْهُ وَاقْدُرْ لِي الْخَيْرَ حَيْثُ كَانَ ثُمَّ أَرْضِنِي بِهِ قَالَ وَيُسَمِّي حَاجَتَهُ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Ibnu Abi Al Mawal] dari [Muhammad bin Al Munkadir] dari [Jabir bin Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengajari kami cara beristikharah dalam seluruh perkara sebagaimana beliau mengajari kami surat Al Qur'an. Beliau bersabda: \"Apabila salah seorang diantara kalian hendak melakukan suatu perkara, shalatlah dua rekaat yang bukan shalat wajib, kemudian mengucapkan: ALLAAHUMMA INNII ASTAKHIIRUKA BI'ILMIKA WA ASTA'IINUKA BIQUDRATIKA WA AS ALUKA MIN FADHLIKAL 'AZHIIM FAINNAKA TAQDIRU WA LAA AQDIRU WA TA'LAMU WA LAA A'LAMU WA ANTA 'ALLAAMUL GHUYUUB. ALLAAHUMMA IN KUNTA TA'LAMU ANNA HADZAL AMRA KHAIRUN LII FII DIINII WA MA'AASYII WA 'AAQIBATI AMRII atau mengatakan FII 'AAJILI AMRII, WA AAJILIHI FAQDURHU LII WA YASSIRHU LII TSUMMA BAARIK LII FIIHI WA IN KUNTA TA'LAMU ANNA HAADZAL AMRA SYARRUN LII FII DIINII WA MA'AASYII WA 'AAQIBATI AMRII atau ia mengatakan FII 'AAJILI AMRII WA AAJILIHI FASHRIFHU 'ANNII WASHRIFNII 'ANHU WAQDUR LIL KHAIRA HAITSU KAANA TSUMMA ARDHINII BIHI beliau bersabda: \"Kemudian menyebutkan hajatnya.\""},"3110":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ عَنْ حَمَّادِ بْنِ سَلَمَةَ عَنْ ثَابِتٍ الْبُنَانِيِّ حَدَّثَنِي ابْنُ عُمَرَ بْنِ أَبِي سَلَمَةَ عَنْ أَبِيهِ عَنْ أُمِّ سَلَمَةَلَمَّا انْقَضَتْ عِدَّتُهَا بَعَثَ إِلَيْهَا أَبُو بَكْرٍ يَخْطُبُهَا عَلَيْهِ فَلَمْ تَزَوَّجْهُ فَبَعَثَ إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمَرَ بْنَ الْخَطَّابِ يَخْطُبُهَا عَلَيْهِ فَقَالَتْ أَخْبِرْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنِّي امْرَأَةٌ غَيْرَى وَأَنِّي امْرَأَةٌ مُصْبِيَةٌ وَلَيْسَ أَحَدٌ مِنْ أَوْلِيَائِي شَاهِدٌ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَ ذَلِكَ لَهُ فَقَالَ ارْجِعْ إِلَيْهَا فَقُلْ لَهَا أَمَّا قَوْلُكِ إِنِّي امْرَأَةٌ غَيْرَى فَسَأَدْعُو اللَّهَ لَكِ فَيُذْهِبُ غَيْرَتَكِ وَأَمَّا قَوْلُكِ إِنِّي امْرَأَةٌ مُصْبِيَةٌ فَسَتُكْفَيْنَ صِبْيَانَكِ وَأَمَّا قَوْلُكِ أَنْ لَيْسَ أَحَدٌ مِنْ أَوْلِيَائِي شَاهِدٌ فَلَيْسَ أَحَدٌ مِنْ أَوْلِيَائِكِ شَاهِدٌ وَلَا غَائِبٌ يَكْرَهُ ذَلِكَ فَقَالَتْ لِابْنِهَا يَا عُمَرُ قُمْ فَزَوِّجْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَزَوَّجَهُمُخْتَصَرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim], ia berkata; telah menceritakan kepada kami [Yazid] dari [Hammad bin Salamah] dari [Tsabit Al Bunani] telah menceritakan kepadaku [Ibnu Umar bin Abi Salamah] dari [ayahnya] dari [Ummu Salamah], tatkala 'iddahnya selesai, Abu Bakr mengirim utusan kepadanya untuk melamarnya, hanya ia enggan. Kemudian Rasulullah shallallahu 'alaihi wasallam mengutus Umar bin Al Khathab untuk melamarnya, dan ia berkata; Tolong beritahu Rasulullah shallallahu 'alaihi wasallam kalau saya wanita pencemburu, banyak anak, serta tidak ada seorang waliku yang menyaksikan. Kemudian Umar datang kepada Rasulullah shallallahu 'alaihi wasallam menyampaikan persoalannya. Lalu beliau bersabda: \"Kembalilah kepadanya dan katakan; adapun perkataanmu, 'Saya wanita pencemburu, saya akan berdoa kepada Allah sehingga Dia menghilangkan rasa cemburumu, Adapun perkataanmu 'Saya wanita yang banyak anak' maka akan dicukupkan bagimu anak-anakmu, adapun perkataanmu bahwa tidak ada seorangpun waliku yang menyaksikan, Ketahuilah bahwa tidak ada seorangpun walimu yang menyaksikan atau tidak, lantas membenci pernikahan ini tersebut.\" Maka Ummu Salamah berkata; \"Wahai Umar, berdirilah dan nikahkan Rasulullah shallallahu 'alaihi wasallam.\" Kemudian ia menikahkan Rasulullah shallallahu 'alaihi wasallam. "},"3111":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَهَا وَهِيَ بِنْتُ سِتٍّ وَبَنَى بِهَا وَهِيَ بِنْتُ تِسْعٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abu Mu'awiyah], ia berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah] bahwa Rasulullah shallallahu 'alaihi wasallam menikahinya sedang ia berumur enam tahun dan membangun rumah tangga dengannya sedang ia berumur sembilan tahun. "},"3112":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ النَّضْرِ بْنِ مُسَاوِرٍ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْتَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِسَبْعِ سِنِينَ وَدَخَلَ عَلَيَّ لِتِسْعِ سِنِينَ","id":"Telah mengabarkan kepada kami [Muhammad bin An Nadhr bin Musar], ia berkata; telah menceritakan kepada kami [Ja'far bin Sulaiman] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menikahiku pada umur tujuh tahun dan membangun rumah tangga denganku pada umur sembilan tahun. "},"3113":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْثَرٌ عَنْ مُطَرِّفٍ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عُبَيْدَةَ قَالَ قَالَتْ عَائِشَةُتَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِتِسْعِ سِنِينَ وَصَحِبْتُهُ تِسْعًا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami ['Abtsar] dari [Mutharrif] dari [Abu Ishaq] dari [Abu 'Ubaidah], ia berkata; [Aisyah] berkata; Rasulullah shallallahu 'alaihi wasallam menikahiku pada umur sembilan tahun dan saya menemaninya pada umur sembilan tahun. "},"3114":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَأَحْمَدُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَتَزَوَّجَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ بِنْتُ تِسْعٍ وَمَاتَ عَنْهَا وَهِيَ بِنْتُ ثَمَانِيَ عَشْرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`] dan [Ahmad bin Harb] mereka berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], Rasulullah shallallahu 'alaihi wasallam menikahinya saat berumur sembilan tahun dan meninggal sedang ia berumur delapan belas tahun. "},"3115":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا أَبِي عَنْ صَالِحٍ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ يُحَدِّثُأَنَّ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ حَدَّثَنَا قَالَ يَعْنِي تَأَيَّمَتْ حَفْصَةُ بِنْتُ عُمَرَ مِنْ خُنَيْسِ بْنِ حُذَافَةَ السَّهْمِيِّ وَكَانَ مِنْ أَصْحَابِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتُوُفِّيَ بِالْمَدِينَةِ قَالَ عُمَرُ فَأَتَيْتُ عُثْمَانَ بْنَ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ فَعَرَضْتُ عَلَيْهِ حَفْصَةَ بِنْتَ عُمَرَ قَالَ قُلْتُ إِنْ شِئْتَ أَنْكَحْتُكَ حَفْصَةَ قَالَ سَأَنْظُرُ فِي أَمْرِي فَلَبِثْتُ لَيَالِيَ ثُمَّ لَقِيَنِي فَقَالَ قَدْ بَدَا لِي أَنْ لَا أَتَزَوَّجَ يَوْمِي هَذَا قَالَ عُمَرُ فَلَقِيتُ أَبَا بَكْرٍ الصِّدِّيقَ رَضِيَ اللَّهُ عَنْهُ فَقُلْتُ إِنْ شِئْتَ زَوَّجْتُكَ حَفْصَةَ بِنْتَ عُمَرَ فَصَمَتَ أَبُو بَكْرٍ فَلَمْ يَرْجِعْ إِلَيَّ شَيْئًا فَكُنْتُ عَلَيْهِ أَوْجَدَ مِنِّي عَلَى عُثْمَانَ فَلَبِثْتُ لَيَالِيَ ثُمَّ خَطَبَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنْكَحْتُهَا إِيَّاهُ فَلَقِيَنِي أَبُو بَكْرٍ فَقَالَ لَعَلَّكَ وَجَدْتَ عَلَيَّ حِينَ عَرَضْتَ عَلَيَّ حَفْصَةَ فَلَمْ أَرْجِعْ إِلَيْكَ شَيْئًا قَالَ عُمَرُ قُلْتُ نَعَمْ قَالَ فَإِنَّهُ لَمْ يَمْنَعْنِي أَنْ أَرْجِعَ إِلَيْكَ شَيْئًا فِيمَا عَرَضْتَ عَلَيَّ إِلَّا أَنِّي قَدْ كُنْتُ عَلِمْتُ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ ذَكَرَهَا وَلَمْ أَكُنْ لِأُفْشِيَ سِرَّ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَوْ تَرَكَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَبِلْتُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Al Mubarak], ia berkata; telah menceritakan kepada kami [Ya'qub bin Ibrahim bin Sa'd], ia berkata; telah menceritakan kepada kami [ayahku] dari [Shalih] dari [Ibnu Syihab], ia berkata; telah memberitakan kepadaku [Salim bin Abdullah] bahwa ia pernah mendengar [Abdullah bin Umar] menceritakan bahwa [Umar bin Khathab] radliallahu 'anhu menceritakan kepada kami, ia berkata; Hafshah binti Umar menjanda dari Khunais bin Hudzafah As Sahmi, ia termasuk diantara sahabat Rasulullah shallallahu 'alaihi wasallam dan meninggal di Madinah. Umar berkata; Maka saya datangi Usman bin 'Affan radliallahu 'anhu dan kutawarkan Hafshah binti Umar. Umar berkata; saya katakan; 'Apabila engkau selera, saya nikahkan engkau dengan Hafshah. Usman hanya memberi jawaban 'Saya akan melihat perkaraku dahulu, saya perlu menunggu beberapa malam', kemudian ia menemuiku dan berkata; 'nampaknya saya tidak akan menikah pada saat ini.' Umar berkata; kemudian saya menemui Abu Bakr Ash Shiddiq radliallahu 'anhu, dan saya katakan; apabila engkau menghendaki, saya nikahkan engkau dengan Hafshah binti Umar. Abu Bakar hanya terdiam dan tidak membawa jawaban sedikitpun kepadaku. Dan kemarahanku kepadanya jauh lebih memuncak daripada kepada Usman. Lalu saya menunggu beberapa malam, kemudian Rasulullah shallallahu 'alaihi wasallam meminangnya. Maka saya menikahkannya dengan Rasulullah shallallahu 'alaihi wasallam. Kemudian Abu Bakr menemuiku dan berkata; Sepertinya engkau marah kepadaku ketika engkau menawarkan Hafshah kepadaku dan saya tidak membawa jawaban sedikitpun. Umar berkata; saya katakan; 'Iya.' Abu Bakr berkata; sebenarnya tidak ada yang menghalangiku untuk memberi jawaban kepadamu mengenai apa yang engkau tawarkan kepadaku, kecuali saya telah mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam sering-sering menyebut-nyebutnya, dan tidak mungkin saya akan menyebarkan rahasia Rasulullah shallallahu 'alaihi wasallam. Kalaulah beliau meninggalkannya, tentu saya menerimanya. "},"3116":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَيِّمُ أَحَقُّ بِنَفْسِهَا مِنْ وَلِيِّهَا وَالْبِكْرُ تُسْتَأْذَنُ فِي نَفْسِهَا وَإِذْنُهَا صُمَاتُهَا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Malik] dari [Abdullah bin Al Fadhl] dari [Nafi' bin Jubair bin Muth'im] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang janda lebih berhak terhadap dirinya daripada walinya, dan seorang gadis diminta persetujuannya terhadap dirinya, dan izinnya adalah diam.\""},"3117":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ مَالِكِ بْنِ أَنَسٍ قَالَ سَمِعْتُهُ مِنْهُ بَعْدَ مَوْتِ نَافِعٍ بِسَنَةٍ وَلَهُ يَوْمَئِذٍ حَلْقَةٌ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ الْفَضْلِ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَيِّمُ أَحَقُّ بِنَفْسِهَا مِنْ وَلِيِّهَا وَالْيَتِيمَةُ تُسْتَأْمَرُ وَإِذْنُهَا صُمَاتُهَا","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Malik bin Anas], ia berkata; saya pernah mendengar darinya setelah satu tahun Nafi' meninggal dan pada saat itu ia memiliki gelang, ia berkata; telah mengabarkan kepadaku [Abdullah bin Al Fadhl] dari [Nafi' bin Jubair] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang janda lebih berhak terhadap dirinya daripada walinya dan wanita yatim diminta persetujuannya dan izinnya adalah diamnya.\""},"3118":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ سَعِيدٍ الرِّبَاطِيُّ قَالَ حَدَّثَنَا يَعْقُوبُ قَالَ حَدَّثَنِي أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ حَدَّثَنِي صَالِحُ بْنُ كَيْسَانَ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ بْنِ عَبَّاسِ بْنِ رَبِيعَةَ عَنْ نَافِعِ بْنِ جُبَيْرِ بْنِ مُطْعِمٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْأَيِّمُ أَوْلَى بِأَمْرِهَا وَالْيَتِيمَةُ تُسْتَأْمَرُ فِي نَفْسِهَا وَإِذْنُهَا صُمَاتُهَا","id":"Telah mengabarkan kepada kami [Ahmad bin Sa'id Ar Ribathi], ia berkata; telah menceritakan kepada kami [Ya'qub], ia berkata; telah menceritakan kepadaku [ayahku] dari [Ibnu Ishaq], ia berkata; telah menceritakan kepadaku [Shalih bin Kaisan] dari [Abdullah bin Al Fadhl bin Abbas bin Rabi'ah] dari [Nafi' bin Jubair bin Muth'im] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang janda lebih berhak terhadap urusannya, sedangkan wanita yatim dimintai persetujuannya dan tanda izinnya adalah diamnya.\""},"3119":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ صَالِحِ بْنِ كَيْسَانَ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَيْسَ لِلْوَلِيِّ مَعَ الثَّيِّبِ أَمْرٌ وَالْيَتِيمَةُ تُسْتَأْمَرُ فَصَمْتُهَا إِقْرَارُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'], ia berkata; telah menceritakan kepada kami [Abdur Razzaq], ia berkata; telah memberitakan kepada kami [Ma'mar] dari [Shalih bin Kaisan] dari [Nafi' bin Jubair] dari [Ibnu Abbas] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Seorang wali tidak memiliki urusan bersama janda sedangkan wanita yatim dimintai persetujuannya, dan diamnya adalah persetujuannya.\" "},"3120":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ زِيَادِ بْنِ سَعْدٍ عَنْ عَبْدِ اللَّهِ بْنِ الْفَضْلِ عَنْ نَافِعِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الثَّيِّبُ أَحَقُّ بِنَفْسِهَا وَالْبِكْرُ يَسْتَأْمِرُهَا أَبُوهَا وَإِذْنُهَا صُمَاتُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ziyad bin Sa'ad] dari [Abdullah bin Al Fadhl] dari [Nafi' bin Jubair] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Seorang janda lebih berhak terhadap dirinya, sedang seorang gadis hendaklah bapaknya meminta persetujuannya, dan izinnya adalah diamnya.\" "},"3121":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ قَالَ حَدَّثَنَا يَحْيَى أَنَّ أَبَا سَلَمَةَ حَدَّثَهُ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُنْكَحُ الثَّيِّبُ حَتَّى تُسْتَأْذَنَ وَلَا تُنْكَحُ الْبِكْرُ حَتَّى تُسْتَأْمَرَ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ إِذْنُهَا قَالَ إِذْنُهَا أَنْ تَسْكُتَ","id":"Telah mengabarkan kepada kami [Yahya bin Durusta], ia berkata; telah menceritakan kepada kami [Abu Isma'il], ia berkata; telah menceritakan kepada kami [Yahya] bahwa [Abu Salamah] telah menceritakan kepadanya dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang janda tidak dinikahkan hingga ia dimintai persetujuan, dan seorang gadis tidak dinikahkan hingga dimintai persetujuan.\" Para sahabat bertanya; wahai Rasulullah, bagaimana izinnya? Beliau bersabda: \"Izinya adalah diam.\""},"3122":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ سَمِعْتُ ابْنَ أَبِي مُلَيْكَةَ يُحَدِّثُ عَنْ ذَكْوَانَ أَبِي عَمْرٍو عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ اسْتَأْمِرُوا النِّسَاءَ فِي أَبْضَاعِهِنَّ قِيلَ فَإِنَّ الْبِكْرَ تَسْتَحِي وَتَسْكُتُ قَالَ هُوَ إِذْنُهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Ibnu Juraij], ia berkata; saya pernah mendengar [Ibnu Abi Mulaikah] menceritakan dari [Dzakwan Abu 'Amr] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Mintalah persetujuan para wanita mengenai pernikahan mereka.\" Dikomentari; seorang gadis itu pemalu dan akan diam. Ia bersabda: \"Persetujuannya ya diamnya itu.\""},"3123":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ وَهُوَ ابْنُ الْحَارِثِ قَالَ حَدَّثَنَا هِشَامٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنِي أَبُو هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُنْكَحُ الْأَيِّمُ حَتَّى تُسْتَأْمَرَ وَلَا تُنْكَحُ الْبِكْرُ حَتَّى تُسْتَأْذَنَ قَالُوا يَا رَسُولَ اللَّهِ كَيْفَ إِذْنُهَا قَالَ أَنْ تَسْكُتَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Khalid yaitu Ibnu Al Harits], ia berkata; telah menceritakan kepada kami [Hisyam] dari [Yahya bin Abi Katsir], ia berkata; telah menceritakan kepadaku [Abu Salamah bin Abdur Rahman], ia berkata; telah menceritakan kepadaku [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seorang janda tidak dinikahkan hingga dimintai persetujuannya, dan seorang gadis tidak dinikahkan hingga dimintai izin.\" Para sahabat berkata; wahai Rasulullah, bagaimana izinnya? Beliau bersabda: \"Dengan diam.\""},"3124":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ وَأَنْبَأَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي عَبْدُ الرَّحْمَنِ بْنُ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَبْدِ الرَّحْمَنِ وَمُجَمِّعِ ابْنَيْ يَزِيدَ ابْنِ جَارِيَةَ الْأَنْصَارِيِّ عَنْ خَنْسَاءَ بِنْتِ خِذَامٍأَنَّ أَبَاهَا زَوَّجَهَا وَهِيَ ثَيِّبٌ فَكَرِهَتْ ذَلِكَ فَأَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَدَّ نِكَاحَهُ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Ma'n], ia berkata; telah menceritakan kepada kami [Malik] dari [Abdur Rahman bin Al Qasim], dan telah memberitakan kepada kami [Muhammad bin Salamah], ia berkata; telah menceritakan kepada kami [Abdur Rahman bin Al Qasim] dari [Malik], ia berkata; telah menceritakan kepadaku [Abdurrahman bin Al Qasim] dari [ayahnya] dari [Abdur Rahman] serta [Mujammi' bin Yazid] anak wanita sahaya orang Anshar dari [Khansa` binti Khidzam] bahwa ayahnya menikahkannya dan ia adalah janda, kemudian ia tidak menyukainya, lalu melapor kepada Rasulullah shallallahu 'alaihi wasallam. Maka beliau menolak pernikahannya. "},"3125":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ غُرَابٍ قَالَ حَدَّثَنَا كَهْمَسُ بْنُ الْحَسَنِ عَنْ عَبْدِ اللَّهِ بْنِ بُرَيْدَةَ عَنْ عَائِشَةَأَنَّ فَتَاةً دَخَلَتْ عَلَيْهَا فَقَالَتْ إِنَّ أَبِي زَوَّجَنِي ابْنَ أَخِيهِ لِيَرْفَعَ بِي خَسِيسَتَهُ وَأَنَا كَارِهَةٌ قَالَتْ اجْلِسِي حَتَّى يَأْتِيَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَتْهُ فَأَرْسَلَ إِلَى أَبِيهَا فَدَعَاهُ فَجَعَلَ الْأَمْرَ إِلَيْهَا فَقَالَتْ يَا رَسُولَ اللَّهِ قَدْ أَجَزْتُ مَا صَنَعَ أَبِي وَلَكِنْ أَرَدْتُ أَنْ أَعْلَمَ أَلِلنِّسَاءِ مِنْ الْأَمْرِ شَيْءٌ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Ali bin Ghurab], ia berkata; telah menceritakan kepada kami [Kahmas bin Al Hasan] dari [Abudullah bin Buraidah] dari [Aisyah] bahwa terdapat seorang wanita muda menemuinya, kemudian berkata; ayahku menikahkanku dengan anak saudaranya agar dapat mengangkat kedudukannya, padahal saya tidak suka. Aisyah berkata; duduklah hingga Nabi shallallahu 'alaihi wasallam datang. Kemudian Rasulullah shallallahu 'alaihi wasallam datang, dan Aisyah mengabarkan kepadanya. Lalu beliau mengirim utusan kepada ayahnya dan memanggilnya lalu menjadikan urusannya kepada wanita tersebut. Kemudian wanita tersebut berkata; wahai Rasulullah, saya telah mengizinkan apa yang telah diperbuat ayahku terhadap diriku. Akan tetapi saya hanya ingin mengetahui (mencek), benarkah wanita memiliki hak dalam memilih pasangan? "},"3126":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عَمْرٍو قَالَ حَدَّثَنَا أَبُو سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تُسْتَأْمَرُ الْيَتِيمَةُ فِي نَفْسِهَا فَإِنْ سَكَتَتْ فَهُوَ إِذْنُهَا وَإِنْ أَبَتْ فَلَا جَوَازَ عَلَيْهَا","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Muhammad bin 'Amr], ia berkata; telah menceritakan kepada kami [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wanita yatim dimintai persetujuan mengenai dirinya, apabila ia terdiam, itu adalah izinnya dan apabila ia menolak maka tidak boleh memaksanya.\""},"3127":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ مُحَمَّدِ بْنِ سَوَاءٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ وَيَعْلَى بْنُ حَكِيمٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَتَزَوَّجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَيْمُونَةَ بِنْتَ الْحَارِثِ وَهُوَ مُحْرِمٌ وَفِي حَدِيثِ يَعْلَى بِسَرِفَ","id":"Telah mengabarkan kepada kami ['Amr bin Ali] dari [Muhammad bin Sawa`], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] serta [Ya'la bin Hakim] dari ['Ikrimah] dari [Ibnu Abbas], ia berkata; Rasulullah shallallahu 'alaihi wasallam menikahi Maimunah binti Al Harits dan beliau sedang berihram, dan dalam hadis Ya'la; beliau berada di Sarif."},"3128":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ أَبِي الشَّعْثَاءِ أَنَّ ابْنَ عَبَّاسٍ أَخْبَرَهُأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَ مَيْمُونَةَ وَهُوَ مُحْرِمٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amr] dari [Abu Asy Sya'tsa`] bahwa [Ibnu Abbas] telah mengabarkan kepadanya bahwa Nabi shallallahu 'alaihi wasallam menikahi Maimunah dan beliau sedang berihram."},"3129":{"ar":"أَخْبَرَنَا عُثْمَانُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ الْحَجَّاجِ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَكَحَ مَيْمُونَةَ وَهُوَ مُحْرِمٌ جَعَلَتْ أَمْرَهَا إِلَى الْعَبَّاسِ فَأَنْكَحَهَا إِيَّاهُ","id":"Telah mengabarkan kepada kami [Usman bin Abdullah], ia berkata; telah menceritakan kepadaku [Ibrahim bin Al Hajjaj], ia berkata; telah menceritakan kepada kami [Wuhaib] dari [Ibnu Juraij] dari ['Atho`] dari [Ibnu Abbas] bahwa Nabi shallallahu 'alaihi wasallam menikahi Maimunah dan beliau sedang berihram. Maimunah menyerahkan urusannya kepada Ibnu Abbas, kemudian ia menikahkannya dengan beliau. "},"3130":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ وَهُوَ ابْنُ مُوسَى عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَ مَيْمُونَةَ وَهُوَ مُحْرِمٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Nashr], ia berkata; telah menceritakan kepada kami ['Ubaidullah yaitu Ibnu Musa] dari [Ibnu Juraij] dari ['Atho`] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam menikahi Maimunah dan beliau sedang berihram."},"3131":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ نُبَيْهِ بْنِ وَهْبٍ أَنَّ أَبَانَ بْنَ عُثْمَانَ قَالَ سَمِعْتُ عُثْمَانَ بْنَ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يَنْكِحُ الْمُحْرِمُ وَلَا يُنْكِحُ وَلَا يَخْطُبُ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Ma'n], ia berkata; telah menceritakan kepada kami [Malik] serta [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Nubaih bin Wahb] bahwa [Aban bin Usman] berkata; saya mendengar [Usman bin Affan] radliallahu 'anhu berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Orang yang sedang berihram tidak boleh menikah dan menikahkan serta meminang.\""},"3132":{"ar":"حَدَّثَنَا أَبُو الْأَشْعَثِ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَال�� حَدَّثَنَا سَعِيدٌ عَنْ مَطَرٍ وَيَعْلَى بْنُ حَكِيمٍ عَنْ نُبَيْهِ بْنِ وَهْبٍ عَنْ أَبَانَ بْنِ عُثْمَانَ أَنَّ عُثْمَانَ بْنَ عَفَّانَ رَضِيَ اللَّهُ عَنْهُ حَدَّثَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا يَنْكِحُ الْمُحْرِمُ وَلَا يُنْكِحُ وَلَا يَخْطُبُ","id":"Telah mengabarkan kepada kami [Abul Asy'ats], ia berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Mathar] serta [Ya'la bin Hakim] dari [Nubaih bin Wahb] dari [Aban bin Usman] bahwa [Usman bin Affan] radliallahu 'anhu menceritakan dari Nabi shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Orang yang sedang berihram tidak boleh menikah, dan menikahkan serta meminang.\""},"3133":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا عَبْثَرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَعَلَّمَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ التَّشَهُّدَ فِي الصَّلَاةِ وَالتَّشَهُّدَ فِي الْحَاجَةِ قَالَ التَّشَهُّدُ فِي الْحَاجَةِ أَنْ الْحَمْدُ لِلَّهِ نَسْتَعِينُهُ وَنَسْتَغْفِرُهُ وَنَعُوذُ بِاللَّهِ مِنْ شُرُورِ أَنْفُسِنَا مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ اللَّهُ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ وَيَقْرَأُ ثَلَاثَ آيَاتٍ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami ['Abtsar] dari [Al A'masy] dari [Abu Ishaq] dari [Al Ahwash] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam mengajarkan kepada kamii tasyahud ketika shalat dan tasyahud ketika memilki hajat. Beliau bersabda: \"Tasyahud ketika memiliki hajat adalah: AL HAMDULILLAAH NASTA'IINUHU WA NASTAGHFIRUHU, WA NA'UUDZU BILLAAHI MIN SYURUURI ANFUSINAA, MAN YAHDIHILLAAHU FALAA MUDHILLA LAHU WA MAN YUDHLILILLAAHU FALAA HAADIYA LAH, WA ASYHADU AN LAA ILAAHA ILLALLAAHU WA ASYHADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUHU.\" Dan beliau membaca tiga ayat. "},"3134":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ عِيسَى قَالَ حَدَّثَنَا يَحْيَى بْنُ زَكَرِيَّا بْنِ أَبِي زَائِدَةَ عَنْ دَاوُدَ عَنْ عَمْرِو بْنِ سَعِيدٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا كَلَّمَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَيْءٍ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْحَمْدَ لِلَّهِ نَحْمَدُهُ وَنَسْتَعِينُهُ مَنْ يَهْدِهِ اللَّهُ فَلَا مُضِلَّ لَهُ وَمَنْ يُضْلِلْ اللَّهُ فَلَا هَادِيَ لَهُ وَأَشْهَدُ أَنْ لَا إِلَهَ إِلَّا اللَّهُ وَحْدَهُ لَا شَرِيكَ لَهُ وَأَشْهَدُ أَنَّ مُحَمَّدًا عَبْدُهُ وَرَسُولُهُ أَمَّا بَعْدُ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Muhammad bin Isa], ia berkata; telah menceritakan kepada kami [Yahya bin Zakariya bin Abi Zaidah] dari [Daud] dari ['Amr bin Sa'id] dari [Sa'id bin Jubair] dari [Ibnu Abbas] bahwa terdapat seorang laki-laki yang berbicara kepada Nabi shallallahu 'alaihi wasallam mengenai sesuatu, kemudian Nabi shallallahu 'alaihi wasallam mengucapkan: \" INNAL HAMDA LILLAAH, NAHMADUHU WA NASTA'IINUHU, MAN YAHDIHILLAAHU FALAA MUDHILLALAH WA MAN YUDHLILLAAHU FALAA HAADIYA LAH, WA ASYHADU AN LAA ILAAHA ILLALLAAHU WAHDAHU LAA SYARIIKA LAHU WA ASY HADU ANNA MUHAMMADAN 'ABDUHU WA RASUULUHU. AMMAA BA'DU.\""},"3135":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ أَنْبَأَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْعَزِيزِ عَنْ تَمِيمِ بْنِ طَرَفَةَ عَنْ عَدِيِّ بْنِ حَاتِمٍ قَالَتَشَهَّدَ رَجُلَانِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَحَدُهُمَا مَنْ يُطِعْ اللَّهَ وَرَسُولَهُ فَقَدْ رَشِدَ وَمَنْ يَعْصِهِمَا فَقَدْ غَوَى فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِئْسَ الْخَطِيبُ أَنْتَ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah memberitakan kepada kami [Abdur Rahman], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abdul 'Aziz] dari [Tamim bin Tharafah] dari [Adi bin Hatim], ia berkata; terdapat dua orang laki-laki yang mengucapkan tasyahud (pernyataan syahadat) di sisi Nabi shallallahu 'alaihi wasallam, salah seorang diantara mereka mengucapkan; MAN YUTHI'ILLAAHA WA RASUULAHU FAQAD RASYADA WA MAN YA'SHIHIMAA FAQAD GHAWAA. Maka Rasulullah shallallahu'alaihi wasallam bersabda; \"Seburuk-buruk Khathib adalah engkau.\" "},"3136":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ عَنْ سُفْيَانَ قَالَ سَمِعْتُ أَبَا حَازِمٍ يَقُولُ سَمِعْتُ سَهْلَ بْنَ سَعْدٍ يَقُولُإِنِّي لَفِي الْقَوْمِ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَامَتْ امْرَأَةٌ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّهَا قَدْ وَهَبَتْ نَفْسَهَا لَكَ فَرَأْ فِيهَا رَأْيَكَ فَسَكَتَ فَلَمْ يُجِبْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ ثُمَّ قَامَتْ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّهَا قَدْ وَهَبَتْ نَفْسَهَا لَكَ فَرَأْ فِيهَا رَأْيَكَ فَقَامَ رَجُلٌ فَقَالَ زَوِّجْنِيهَا يَا رَسُولَ اللَّهِ قَالَ هَلْ مَعَكَ شَيْءٌ قَالَ لَا قَالَ اذْهَبْ فَاطْلُبْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَذَهَبَ فَطَلَبَ ثُمَّ جَاءَ فَقَالَ لَمْ أَجِدْ شَيْئًا وَلَا خَاتَمًا مِنْ حَدِيدٍ قَالَ هَلْ مَعَكَ مِنْ الْقُرْآنِ شَيْءٌ قَالَ نَعَمْ مَعِي سُورَةُ كَذَا وَسُورَةُ كَذَا قَالَ قَدْ أَنْكَحْتُكَهَا عَلَى مَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] dari [Sufyan], ia berkata; saya mendengar [Abu Hazim] berkata; saya mendengar [Sahl bin Sa'd] berkata; saya berada diantara orang-orang di sisi Nabi shallallahu 'alaihi wasallam, kemudian terdapat seorang wanita yang berkata; wahai Rasulullah, ia telah menghibahkan dirinya kepadamu, maka lihatlah bagaimana pendapatmu terhadap dirinya. Kemudian beliau terdiam, dan Nabi shallallahu 'alaihi wasallam tidak menjawabnya sedikitpun. Kemudian wanita tersebut berdiri dan berkata; wahai Rasulullah, sesungguhnya ia telah menghibahkan dirinya kepadamu, maka lihatlah bagaimana pendapatmu terhadap dirinya. Kemudian terdapat seorang laki-laki yang berdiri kemudian berkata; nikahkan saya dengannya wahai Rasulullah! Beliau bersabda: \"Apakah engkau memiliki sesuatu?\" Orang tersebut berkata; tidak. Beliau bersabda: \"Pergilah dan carilah walaupun satu cincin besi.\" Lalu orang tersebut pergi dan mencari, kemudian datang dan berkata; saya belum mendapatkan sesuatu dan tidak mendapatkan cincin besi. Beliau bersabda: \"Apakah engkau hafal sedikit dari Al Qur'an?\" orang tersebut berkata; ya, saya hafal surat ini dan surat ini. Beliau bersabda: \"Baik, saya menikahkanmu dengannya dengan sekian hapalan al Qur'anmu.\""},"3137":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ عُقْبَةَ بْنِ عَامِرٍعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحَقَّ الشُّرُوطِ أَنْ يُوَفَّى بِهِ مَا اسْتَحْلَلْتُمْ بِهِ الْفُرُوجَ","id":"Telah mengabarkan kepada kami [Isa bin Hammad], ia berkata; telah memberitakan kepada kami [Al Laits] dari [Yazid bin Abi Habib] dari [Abu Al Khair] dari ['Uqbah bin 'Amir] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Syarat yang paling berhak kau tunaikan adalah yang karenanya kamu menghalalkan kemaluan (Mahar).\""},"3138":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ تَمِيمٍ قَالَ سَمِعْتُ حَجَّاجًا يَقُولُ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي سَعِيدُ بْنُ أَبِي أَيُّوبَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ أَنَّ أَبَا الْخَيْرِ حَدَّثَهُ عَنْ عُقْبَةَ بْنِ عَامِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ أَحَقَّ الشُّرُوطِ أَنْ يُوَفَّى بِهِ مَا اسْتَحْلَلْتُمْ بِهِ الْفُرُوجَ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Tamim], ia berkata; saya pernah mendengar [Hajjaj] berkata; [Ibnu Juraij]; telah mengabarkan kepadaku [Sa'id bin Ayyub] dari [Yazid bin Abi Habib] bahwa [Abu Al Khair] telah menceritakan kepadanya dari ['Alqamah bin 'Amir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Syarat yang paling berhak ditunaikan adalah yang dapat menghalalkan kemaluan.\""},"3139":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْجَاءَتْ امْرَأَةُ رِفَاعَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ رِفَاعَةَ طَلَّقَنِي فَأَبَتَّ طَلَاقِي وَإِنِّي تَزَوَّجْتُ بَعْدَهُ عَبْدَ الرَّحْمَنِ بْنَ الزَّبِيرِ وَمَا مَعَهُ إِلَّا مِثْلُ هُدْبَةِ الثَّوْبِ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لَعَلَّكِ تُرِيدِينَ أَنْ تَرْجِعِي إِلَى رِفَاعَةَ لَا حَتَّى يَذُوقَ عُسَيْلَتَكِ وَتَذُوقِي عُسَيْلَتَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], ia berkata; telah datang isteri Rifa'ah kepada Rasulullah shallallahu 'alaihi wasallam kemudian berkata; Rifa'ah menceraikanku sama sekali, setelah itu saya menikah dengan Abdur Rahman bin Az Zubair dan ia tidak memiliki kemampuan kecuali seperti ujung baju. Maka Rasulullah shallallahu 'alaihi wasallam tertawa dan bersabda: \"Kemungkinan engkau ingin kembali kepada Rifa'ah ataukah tidak, hingga ia merasakan kenikmatanmu dan engkau merasakan kenikmatannya?.\" "},"3140":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا أَبُو الْيَمَانِ قَالَ أَنْبَأَنَا شُعَيْبٌ قَالَ أَخْبَرَنِي الزُّهْرِيُّ قَالَ أَخْبَرَنِي عُرْوَةُ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ وَأُمُّهَا أُمُّ سَلَمَةَ زَوْجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَخْبَرَتْهُ أَنَّ أُمَّ حَبِيبَةَ بِنْتَ أَبِي سُفْيَانَ أَخْبَرَتْهَاأَنَّهَا قَالَتْ يَا رَسُولَ اللَّهِ أَنْكِحْ أُخْتِي بِنْتَ أَبِي سُفْيَانَ قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوَتُحِبِّينَ ذَلِكَ فَقُلْتُ نَعَمْ لَسْتُ لَكَ بِمُخْلِيَةٍ وَأَحَبُّ مَنْ يُشَارِكُنِي فِي خَيْرٍ أُخْتِي فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أُخْتَكِ لَا تَحِلُّ لِي فَقُلْتُ وَاللَّهِ يَا رَسُولَ اللَّهِ إِنَّا لَنَتَحَدَّثُ أَنَّكَ تُرِيدُ أَنْ تَنْكِحَ دُرَّةَ بِنْتَ أَبِي سَلَمَةَ فَقَالَ بِنْتُ أُمِّ سَلَمَةَ فَقُلْتُ نَعَمْ فَقَالَ وَاللَّهِ لَوْلَا أَنَّهَا رَبِيبَتِي فِي حَجْرِي مَا حَلَّتْ لِي إِنَّهَا لَابْنَةُ أَخِي مِنْ الرَّضَاعَةِ أَرْضَعَتْنِي وَأَبَا سَلَمَةَ ثُوَيْبَةُ فَلَا تَعْرِضْنَ عَلَيَّ بَنَاتِكُنَّ وَلَا أَخَوَاتِكُنَّ","id":"Telah mengabarkan kepada kami [Imran bin Bakkar], ia berkata; telah menceritakan kepada kami [Abu Al Yaman], ia berkata; telah memberitakan kepada kami [Syu'aib], ia berkata; telah mengabarkan kepadaku [Az Zuhri], ia berkata; telah mengabarkan kepadaku ['Urwah] bahwa [Zainab binti Abu Salamah] dan ibunya, Ummu salamah isteri Rasulullah shallallahu 'alaihi wasallam telah mengabarkan kepadanya, bahwa [Ummu Habibah binti Abi Sufyan] mengabarkan kepadanya bahwa ia berkata; wahai Rasulullah, nikahilah saudariku binti Abu Sufyan. Ia berkata; kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah engkau menginginkan hal tersebut?\" Maka saya katakan; ya. Bukan hanya saya yang anda miliki, dan orang yang bersamaku dalam kebaikan yang paling aku sukai adalah saudariku. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya saudarimu tidak halal bagiku.\" Kemudian saya berkata; demi Allah wahai Rasulullah, sungguh kami membicarakan bahwa engkau ingin menikahi Durrah binti Abi Salamah? Kemudian beliau bersabda: \"Anak perempuan Ummu Salamah?\" Maka saya katakan; ya. Maka beliau bersabda: \"Demi Allah seandainya ia bukanlah anak isteriku yang dalam asuhanku, ia tetap tidak halal bagiku. Ia adalah anak perempuan saudaraku sesusuan. Tsuwaibah telah menyusuiku dan Abu Salamah, maka janganlah kalian tawarkan kepadaku anak-anak dan jangan pula saudara-saudara wanita kalian.\""},"3141":{"ar":"أَخْبَرَنَا وَهْبُ بْنُ بَيَانٍ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَنَّ عُرْوَةَ بْنَ الزُّبَيْرِ حَدَّثَهُ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ أَنَّ أُمَّ حَبِيبَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْيَا رَسُولَ اللَّهِ أَنْكِحْ بِنْتَ أَبِي تَعْنِي أُخْتَهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَتُحِبِّينَ ذَلِكِ قَالَتْ نَعَمْ لَسْتُ لَكَ بِمُخْلِيَةٍ وَأَحَبُّ مَنْ شَرِكَتْنِي فِي خَيْرٍ أُخْتِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ ذَلِكَ لَا يَحِلُّ قَالَتْ أُمُّ حَبِيبَةَ يَا رَسُولَ اللَّهِ وَاللَّهِ لَقَدْ تَحَدَّثْنَا أَنَّكَ تَنْكِحُ دُرَّةَ بِنْتَ أَبِي سَلَمَةَ فَقَالَ بِنْتُ أُمِّ سَلَمَةَ قَالَتْ أُمُّ حَبِيبَةَ نَعَمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَوَاللَّهِ لَوْ أَنَّهَا لَمْ تَكُنْ رَبِيبَتِي فِي حَجْرِي مَا حَلَّتْ إِنَّهَا لَابْنَةُ أَخِي مِنْ الرَّضَاعَةِ أَرْضَعَتْنِي وَأَبَا سَلَمَةَ ثُوَيْبَةُ فَلَا تَعْرِضْنَ عَلَيَّ بَنَاتِكُنَّ وَلَا أَخَوَاتِكُنَّ","id":"Telah mengabarkan kepada kami [Wahb bin Bayan], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah memberitakan kepadaku [Yunus] dari [Ibnu Syihab] bahwa ['Urwah bin Az Zubair] telah menceritakan kepadanya dari [Zainab binti Abi Salamah] bahwa [Ummu Habibah] -isteri Nabi shallallahu 'alaihi wasallam- berkata; wahai Rasulullah, nikahilah anak wanita ayahku! Yaitu saudaranya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah engkau menginginkan hal tersebut?\" Ia berkata; ya. Bukan hanya saya yang anda miliki, dan orang yang bersamaku dalam kebaikan yang paling aku sukai adalah saudariku. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya hal itu tidaklah halal.\" Ummu Habibah berkata; wahai Rasulullah, demi Allah, kami telah berbicara bahwa engkau akan menikahi Durrah binti Abi Salamah. Kemudian beliau bersabda: \"Anak wanita Ummu Salamah?\" Ummu Salamah berkata; ya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Demi Allah, kalaulah ia ia bukan anak isteriku yang ada dalam asuhanku, ia pun tidaklah halal bagiku, karena ia adalah anak saudaraku sepersusuan. Tsuwaibah telah menyusuiku dan Abu Salamah, maka janganlah kalian tawarkan kepadaku anak-anak wanita dan saudara-saudara wanita kalian.\" "},"3142":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عِرَاكِ بْنِ مَالِكٍ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُأَنَّ أُمَّ حَبِيبَةَ قَالَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّا قَدْ تَحَدَّثْنَا أَنَّكَ نَاكِحٌ دُرَّةَ بِنْتَ أَبِي سَلَمَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعَلَى أُمِّ سَلَمَةَ لَوْ أَنِّي لَمْ أَنْكِحْ أُمَّ سَلَمَةَ مَا حَلَّتْ لِي إِنَّ أَبَاهَا أَخِي مِنْ الرَّضَاعَةِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abi Habib] dari ['Irak bin Malik] bahwa [Zainab binti Abi Salamah] telah mengabarkan kepadanya bahwa [Ummu Habibah] berkata kepada Rasulullah shallallahu 'alaihi wasallam; kami membicarakan bahwa anda akan menikahi Durrah binti Abi Salamah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah ia menjadi madu Ummu Salamah? Seandainya saya tidak menikahi Ummu Salamah, tetap ia tidaklah halal bagiku, sesungguhnya ayahnya adalah saudaraku sepersusuan.\""},"3143":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ عَبْدَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ حَبِيبَةَ أَنَّهَا قَالَتْيَا رَسُولَ اللَّهِ هَلْ لَكَ فِي أُخْتِي قَالَ فَأَصْنَعُ مَاذَا قَالَتْ تَزَوَّجْهَا قَالَ فَإِنَّ ذَلِكَ أَحَبُّ إِلَيْكِ قَالَتْ نَعَمْ لَسْتُ لَكَ بِمُخْلِيَةٍ وَأَحَبُّ مَنْ يَشْرَكُنِي فِي خَيْرٍ أُخْتِي قَالَ إِنَّهَا لَا تَحِلُّ لِي قَالَتْ فَإِنَّهُ قَدْ بَلَغَنِي أَنَّكَ تَخْطُبُ دُرَّةَ بِنْتَ أُمِّ سَلَمَةَ قَالَ بِنْتُ أَبِي سَلَمَةَ قَالَتْ نَعَمْ قَالَ وَاللَّهِ لَوْ لَمْ تَكُنْ رَبِيبَتِي مَا حَلَّتْ لِي إِنَّهَا لَابْنَةُ أَخِي مِنْ الرَّضَاعَةِ فَلَا تَعْرِضْنَ عَلَيَّ بَنَاتِكُنَّ وَلَا أَخَوَاتِكُنَّ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari ['Abdah] dari [Hisyam] dari [ayahnya] dari [Zainab binti Abu Salamah] dari [Ummu Habibah] bahwa ia berkata; wahai Rasulullah; apakah engkau memperhatikan saudariku? Beliau bersabda: \"Apa yang saya lakukan?\" Ia berkata; nikahilah dia. Beliau bersabda: \"Apakah hal itu lebih engkau sukai?\" Ia berkata; ya. Bukan hanya saya yang anda miliki, dan orang yang bersamaku dalam suatu kebaikan yang paling saya sukai adalah saudariku. Beliau bersabda: \"Ia tidak halal bagiku.\" Ia berkata; Telah sampai kepadaku bahwa anda meminang Durrah binti Ummu Salamah. Beliau bersabda: \"Anak wanita Ummu Salamah?\" Ia menjawab; Iya. Beliau bersabda: \"Seandainya ia bukan anak isteriku, ia tetap tidaklah halal bagiku, karena ia adalah anak saudaraku sepersusuan. Maka janganlah kalian tawarkan kepadaku anak-anak dan saudara-saudara wanita kalian.\" "},"3144":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا يُجْمَعُ بَيْنَ الْمَرْأَةِ وَعَمَّتِهَا وَلَا بَيْنَ الْمَرْأَةِ وَخَالَتِهَا","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Ma'n], ia berkata; telah menceritakan kepada kami [Malik] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh dua wanita dihimpun (diperistri seorang pria secara bersama) yaitu, antara seorang wanita dan saudara wanita ayahnya (bibi dari jalur ayah) dan antara seorang wanita dan saudara ibunya (Bibi dari jalur ibu).\""},"3145":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَعْقُوبَ بْنِ عَبْدِ الوَهَّابِ بْنِ يَحْيَى بْنِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ بْنِ الْعَوَّامِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُلَيْحٍ عَنْ يُونُسَ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي قُبَيْصَةُ بْنُ ذُؤَيْبٍ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُجْمَعَ بَيْنَ الْمَرْأَةِ وَعَمَّتِهَا وَالْمَرْأَةِ وَخَالَتِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Ya'qub bin Abdul Wahhab bin Yahya bin 'Abbad bin Abdullah bin Az Zubair bin Al 'Awwam], ia berkata; telah menceritakan kepada kami [Muhammad bin Fulaih] dari [Yunus], telah berkata [Ibnu Syihab]; telah mengabarkan kepadaku [Qubaishah bin Dzuaib] bahwa ia pernah mendengar [Abu Hurairah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang menggabungkan (memperistri dua wanita dalam satu waktu), yaitu antara seorang wanita dan saudara wanita ayahnya (bibi jalur ayah) dan antara seorang wanita dan saudara wanita ibunya (bibi jalur ibu)."},"3146":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ أَنَّ جَعْفَرَ بْنَ رَبِيعَةَ حَدَّثَهُ عَنْ عِرَاكِ بْنِ مَالِكٍ وَعَبْدِ الرَّحْمَنِ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ نَهَى أَنْ تُنْكَحَ الْمَرْأَةُ عَلَى عَمَّتِهَا أَوْ خَالَتِهَا","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub], ia berkata; telah menceritakan kepada kami [Ibnu Abi Maryam], ia berkata; telah menceritakan kepada kami [Yahya bin Ayyub] bahwa [Ja'far bin Rabi'ah] menceritakan kepadanya dari ['Irak bin Malik] serta [Abdur Rahman Al A'raj] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau melarang seorang wanita dinikahi sebagai madu saudara wanita ayahnya (bibi jalur ayah) atau saudara wanita ibunya (bibi jalur ibu)."},"3147":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ أَرْبَعِ نِسْوَةٍ يُجْمَعُ بَيْنَهُنَّ الْمَرْأَةِ وَعَمَّتِهَا وَالْمَرْأَةِ وَخَالَتِهَا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abi Habib] dari ['Irak bin Malik] dari [Abu Hurairah] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari empat orang wanita digabungkan, yaitu seorang wanita dan saudara wanita ayahnya serta seorang wanita dan saudara wanita ibunya."},"3148":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ أَخْبَرَنِي أَيُّوبُ بْنُ مُوسَى عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عَبْدِ الْمَلِكِ بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا تُنْكَحُ الْمَرْأَةُ عَلَى عَمَّتِهَا وَلَا عَلَى خَالَتِهَا","id":"Telah mengabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Abdullah bin Yusuf], ia berkata; telah menceritakan kepada kami [Al Laits], ia berkata; telah memberitakan kepadaku [Ayyub bin Musa] dari [Bukair bin Abdullah bin Al Asyah] dari [Sulaiman bin Yasar] dari [Abdul Malik bin Yasar] dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Tidak boleh seorang wanita dinikahi sebagai madu saudara wanita ayahnya, dan sebagai madu saudara wanita ibunya.\""},"3149":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى قَالَ حَدَّثَنَا ابْنُ عُيَيْنَةَ عَنْ عَمْرِو بْنِ دِينَارٍ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُنْكَحَ الْمَرْأَةُ عَلَى عَمَّتِهَا أَوْ عَلَى خَالَتِهَا","id":"Telah mengabarkan kepada kami [Mujahid bin Musa], ia berkata; telah menceritakan kepada kami [Ibnu 'Uyainah] dari ['Amr bin Dinar] dari [Abu Salamah] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang seorang wanita dinikahi sebagai madu bagi saudara wanita ayahnya atau saudara wanita ibunya."},"3150":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ دُرُسْتَ قَالَ حَدَّثَنَا أَبُو إِسْمَعِيلَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ أَنَّ أَبَا سَلَمَةَ حَدَّثَهُ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ لَا تُنْكَحُ الْمَرْأَةُ عَلَى عَمَّتِهَا وَلَا عَلَى خَالَتِهَا","id":"Telah mengabarkan kepada kami [Yahya bin Durusta], ia berkata; telah menceritakan kepada kami [Abu Isma'il], ia berkata; telah menceritakan kepada kami [Yahya bin Abi Katsir] bahwa [Abu Salamah] telah menceritakan kepadanya dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam bahwa beliau bersabda: \"Tidak boleh seorang wanita dinikahi sebagai madu bagi saudara wanita ayahnya dan saudara wanita ibunya.\" "},"3151":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا هِشَامٌ قَالَ حَدَّثَنَا مُحَمَّدٌ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُنْكَحُ الْمَرْأَةُ عَلَى عَمَّتِهَا وَلَا عَلَى خَالَتِهَا","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepada kami [Hisyam], ia berkata; telah menceritakan kepada kami [Muhammad] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh seorang wanita dinikahi sebagai madu bagi saudara wanita ayahnya dan tidak pula sebagai madu saudara wanita ibunya.\""},"3152":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْمُعْتَمِرُ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُنْكَحَ الْمَرْأَةُ عَلَى عَمَّتِهَا وَالْعَمَّةُ عَلَى بِنْتِ أَخِيهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Al Mu'tamir] dari [Daud bin Abi Hindun] dari [Asy Sya'bi] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang seorang wanita dinikahi sebagai madu bagi saudara wanita ayahnya dan saudara wanita ayahnya sebagai madu bagi anak wanita saudara laki-lakinya. "},"3153":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَاصِمٌ قَالَ قَرَأْتُ عَلَى الشَّعْبِيِّ كِتَابًا فِيهِ عَنْ جَابِرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُنْكَحُ الْمَرْأَةُ عَلَى عَمَّتِهَا وَلَا عَلَى خَالَتِهَاقَالَ سَمِعْتُ هَذَا مِنْ جَابِرٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah mengabarkan kepadaku ['Ashim], ia berkata; saya membaca kitabnya [Asy Sya'bi] didalamnya tertulis dari [Jabir] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak boleh seorang wanita dinikahi sebagai madu bagi saudara wanita ayahnya, dan sebagai madu bagi saudara wanita ibunya.\" Asy Sya'bi berkata; saya mendengar ini dari Jabir. "},"3154":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ عَنْ ابْنِ الْمُبَارَكِ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ قَالَ سَمِعْتُ جَابِرَ بْنَ عَبْدِ اللَّهِ يَقُولُنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُنْكَحَ الْمَرْأَةُ عَلَى عَمَّتِهَا وَخَالَتِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari [Ibnu Al Mubarak] dari ['Ashim] dari [Asy Sya'bi], ia berkata; saya mendengar [Jabir bin Abdullah] berkata; Rasulullah shallallahu 'alaihi wasallam melarang seorang wanita dinikahi sebagai madu bagi saudara wanita ayahnya dan saudara wanita ibunya. "},"3155":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ الْحَسَنِ قَالَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تُنْكَحَ الْمَرْأَةُ عَلَى عَمَّتِهَا أَوْ عَلَى خَالَتِهَا","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan], ia berkata; telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang seorang wanita dinikahi sebagai madu bagi saudara wanita ayahnya atau sebagai madu bagi saudara wanita ibunya."},"3156":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ أَنْبَأَنَا مَالِكٌ قَالَ حَدَّثَنِي عَبْدُ اللَّهِ بْنُ دِينَارٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا حَرَّمَتْهُ الْوِلَادَةُ حَرَّمَهُ الرَّضَاعُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah memberitakan kepada kami [Malik], ia berkata; telah menceritakan kepadaku [Abdullah bin Dinar] dari [Sulaiman bin Yasar] dari ['Urwah] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apa yang diharamkan karena nasab diharamkan pula karena sepersusuan.\""},"3157":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ عِرَاكٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا أَخْبَرَتْهُأَنَّ عَمَّهَا مِنْ الرَّضَاعَةِ يُسَمَّى أَفْلَحَ اسْتَأْذَنَ عَلَيْهَا فَحَجَبَتْهُ فَأُخْبِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَا تَحْتَجِبِي مِنْهُ فَإِنَّهُ يَحْرُمُ مِنْ الرَّضَاعِ مَا يَحْرُمُ مِنْ النَّسَبِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abi Habib] dari ['Irak] dari ['Urwah] dari [Aisyah] bahwa ia telah mengabarkan kepadanya bahwa pamannya dari persusuan yang dipanggil Aflah meminta izin kepadanya, kemudian ia menutup diri darinya. Kemudian Rasulullah shallallahu 'alaihi wasallam diberitahu, kemudian beliau bersabda: \"Janganlah engkau menutup diri darinya, sesungguhnya sesuatu yang haram karena nasab adalah haram karena persusuan.\""},"3158":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ يَحْرُمُ مِنْ الرَّضَاعِ مَا يَحْرُمُ مِنْ النَّسَبِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Yahya] dari [Malik] dari [Abdullah bin Abi Bakr] dari ['Urwah] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Apa yang haram karena nasab adalah haram karena persusuan.\""},"3159":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عُبَيْدٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ هَاشِمٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ أَبِيهِ عَنْ عَمْرَةَ قَالَتْ سَمِعْتُ عَائِشَةَ تَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَحْرُمُ مِنْ الرَّضَاعِ مَا يَحْرُمُ مِنْ الْوِلَادَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin 'Ubaid], ia berkata; telah menceritakan kepada kami [Ali bin Hasyim] dari [Abdullah bin Abi Bakr] dari [ayahnya] dari ['Amrah], ia berkata; saya mendengar [Aisyah] berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang haram karena nasab adalah haram karena persusuan.\""},"3160":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ سَعْدِ بْنِ عُبَيْدَةَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السَّلَمِيِّ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَا لَكَ تَنَوَّقُ فِي قُرَيْشٍ وَتَدَعُنَا قَالَ وَعِنْدَكَ أَحَدٌ قُلْتُ نَعَمْ بِنْتُ حَمْزَةَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّهَا لَا تَحِلُّ لِي إِنَّهَا ابْنَةُ أَخِي مِنْ الرَّضَاعَةِ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Mu'awiyah] dari [Al A'masy] dari [Sa'd bin 'Ubaidah] dari [Abu Abdur Rahman As Sulami] dari [Ali] radliallahu 'anhu, ia berkata; saya berkata; wahai Rasulullah, kenapa anda memilih-memilih diantara orang-orang Quraisy dan membiarkan kami? Beliau bersabda: \"Apakah engkau memiliki seseorang?\" Saya katakan; ya. Anak perempuan Hamzah. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ia tidak halal bagiku, ia adalah anak perempuan saudaraku sepersusuan.\""},"3161":{"ar":"أَخْبَرَنِي إِبْرَاهِيمُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ شُعْبَةَ عَنْ قَتَادَةَ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍ قَالَذُكِرَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِنْتُ حَمْزَةَ فَقَالَ إِنَّهَا ابْنَةُ أَخِي مِنْ الرَّضَاعَةِقَالَ شُعْبَةُ هَذَا سَمِعَهُ قَتَادَةُ مِنْ جَابِرِ بْنِ زَيْدٍ","id":"Telah mengabarkan kepada kami [Ibrahim bin Muhammad], ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Syu'bah] dari [Qatadah] dari [Jabir bin Zaid] dari [Ibnu Abbas], ia berkata; disebut-sebut kepada Rasulullah shallallahu 'alaihi wasallam anak perempuan Hamzah, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ia anak perempuan saudaraku sepersusuan.\" Syu'bah berkata; hadis ini didengar Qatadah dari Jabir bin Zaid."},"3162":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَوَاءٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ جَابِرِ بْنِ زَيْدٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرِيدَ عَلَى بِنْتِ حَمْزَةَ فَقَالَ إِنَّهَا ابْنَةُ أَخِي مِنْ الرَّضَاعَةِ وَإِنَّهُ يَحْرُمُ مِنْ الرَّضَاعِ مَا يَحْرُمُ مِنْ النَّسَبِ","id":"Telah mengabarkan kepada kami [Abdullah bin Ash Shabbah bin Abdullah], ia berkata; telah menceritakan kepada kami [Muhammad bin Sawa`], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Jabir bin Zaid] dari [Ibnu Abbas] bahwa Rasulullah shallallahu 'alaihi wasallam ditawari anak perempuan Hamzah. Kemudian beliau bersabda: \"Ia adalah anak perempuan saudaraku sepersusuan, dan sesuatu yang haram karena nasab haram pula karena persusuan.\""},"3163":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ عَنْ عَائِشَةَ قَالَتْكَانَ فِيمَا أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ وَقَالَ الْحَارِثُ فِيمَا أُنْزِلَ مِنْ الْقُرْآنِ عَشْرُ رَضَعَاتٍ مَعْلُومَاتٍ يُحَرِّمْنَ ثُمَّ نُسِخْنَ بِخَمْسٍ مَعْلُومَاتٍ فَتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ مِمَّا يُقْرَأُ مِنْ الْقُرْآنِ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Ma'n], ia berkata; telah menceritakan kepada kami [Malik] serta [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar dari [Ibnu Al Qasim], ia berkata; telah menceritakan kepadaku [Malik] dari [Abdullah bin Abu Bakr] dari ['Amrah] dari ['Aisyah] ia berkata; diantara ayat yang Allah Azza wa Jalla turunkan.., sedangkan Harits berkata; diantara yang di turunkan dari Al Qur'an adalah: sepuluh kali susuan mengharamkan, lalu ayat itu dihapus dengan lima kali yang diketahui, kemudian Rasulullah shallallahu 'alaihi wasallam meninggal dan ayat itu diantara yang dibaca dalam Alquran."},"3164":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ بْنِ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَوَاءٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ وَأَيُّوبُ عَنْ صَالِحٍ أَبِي الْخَلِيلِ عَنْ عَبْدِ اللَّهِ بْنِ الْحَارِثِ بْنِ نَوْفَلٍ عَنْ أُمِّ الْفَضْلِأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ الرَّضَاعِ فَقَالَ لَا تُحَرِّمُ الْإِمْلَاجَةُ وَلَا الْإِمْلَاجَتَانِ وَقَالَ قَتَادَةُ الْمَصَّةُ وَالْمَصَّتَانِ","id":"Telah mengabarkan kepada kami [Abdullah bin Ash Shabah bin Abdullah], ia berkata; telah menceritakan kepada kami [Muhammad bin Sawa`], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dan [Ayyub] dari [Shalih Abu Al Khalil] dari [Abdullah bin Al Harits bin Naufal] dari [Ummu Al Fadhl] bahwa Nabi shallallahu 'alaihi wasallam pernah ditanya mengenai persusuan. Kemudian beliau bersabda: \"Tidak mengharamkan satu tetekan, dan dua tetekan.\" Qatadah berkata; satu hisapan dan dua hisapan."},"3165":{"ar":"أَخْبَرَنَا شُعَيْبُ بْنُ يُوسُفَ عَنْ يَحْيَى عَنْ هِشَامٍ قَالَ حَدَّثَنِي أَبِي عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا تُحَرِّمُ الْمَصَّةُ وَالْمَصَّتَانِ","id":"Telah mengabarkan kepada kami [Syu'aib bin Yusuf] dari [Yahya] dari [Hisyam], ia berkata; telah menceritakan kepadaku [ayahku] dari [Abdullah bin Az Zubair] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak mengharamkan satu hisapan dan dua hisapan.\""},"3166":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ عَائِشَةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تُحَرِّمُ الْمَصَّةُ وَالْمَصَّتَانِ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Ibnu 'Ulayyah] dari [Ayyub] dari [Ibnu Mulaikah] dari [Abdullah bin Az Zubair] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak mengharamkan satu hisapan dan dua hisapan.\""},"3167":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ يَعْنِي ابْنَ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ قَالَ كَتَبْنَا إِلَى إِبْرَاهِيمَ بْنِ يَزِيدَ النَّخَعِيِّ نَسْأَلُهُ عَنْ الرَّضَاعِ فَكَتَبَ أَنَّ شُرَيْحًا حَدَّثَنَا أَنَّ عَلِيًّا وَابْنَ مَسْعُودٍ كَانَا يَقُولَانِ يُحَرِّمُ مِنْ الرَّضَاعِ قَلِيلُهُ وَكَثِيرُهُ وَكَانَ فِي كِتَابِهِ أَنَّ أَبَا الشَّعْثَاءِ الْمُحَارِبِيَّ حَدَّثَنَا أَنَّ عَائِشَةَ حَدَّثَتْهُأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَقُولُ لَا تُحَرِّمُ الْخَطْفَةُ وَالْخَطْفَتَانِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazi'], ia berkata; telah menceritakan kepada kami [Yazid yaitu Ibnu Zurai'], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah], ia berkata; kami menulis surat kepada [Ibrahim bin Yazid An Nakha'i] bertanya kepadanya mengenai susuan, kemudian ia menulis surat bahwa Syuraih telah menceritakan kepada kami bahwa Ali dan Ibnu Mas'ud berkata; sedikit dan banyaknya susuan mengharamkan. Dan di dalam tulisannya disebutkan bahwa [Abu Asy Sya'tsa` Al Muharibi] telah menceritakan kepada kami bahwa [Aisyah] menceritakan kepadanya bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak mengharamkan satu renggutan dan dua renggutan.\""},"3168":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ فِي حَدِيثِهِ عَنْ أَبِي الْأَحْوَصِ عَنْ أَشْعَثَ بْنِ أَبِي الشَّعْثَاءِ عَنْ أَبِيهِ عَنْ مَسْرُوقٍ قَالَ قَالَتْ عَائِشَةُدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعِنْدِي رَجُلٌ قَاعِدٌ فَاشْتَدَّ ذَلِكَ عَلَيْهِ وَرَأَيْتُ الْغَضَبَ فِي وَجْهِهِ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّهُ أَخِي مِنْ الرَّضَاعَةِ فَقَالَ انْظُرْنَ مَا إِخْوَانُكُنَّ وَمَرَّةً أُخْرَى انْظُرْنَ مَنْ إِخْوَانُكُنَّ مِنْ الرَّضَاعَةِ فَإِنَّ الرَّضَاعَةَ مِنْ الْمَجَاعَةِ","id":"Telah mengabarkan kepada kami [Hannad As Sari] dalam hadis nya dari [Abu Al Ahwash] dari [Asy'ats bin Abi Asy Sya'tsa`] dari [ayahnya] dari [Masruq], ia berkata; ['Aisyah] berkata; Rasulullah shallallahu 'alaihi wasallam menemuiku dan disampingku ada seorang lelaki yang duduk, beliau mengusirnya dan aku melihat kemarahan diwajahnya, aku berkata; wahai Rasulullah, sesungguhnya ia saudaraku sepersusuan, beliau bersabda: \" Lihatlah apa itu saudara kalian, \" pada kali yang lain: \" lihatlah siapakah saudara kalian sepersusuan, karena susuan itu karena lapar.\""},"3169":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ عَمْرَةَ أَنَّ عَائِشَةَ أَخْبَرَتْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عِنْدَهَا وَأَنَّهَا سَمِعَتْ رَجُلًا يَسْتَأْذِنُ فِي بَيْتِ حَفْصَةَ قَالَتْ عَائِشَةُ فَقُلْتُ يَا رَسُولَ اللَّهِ هَذَا رَجُلٌ يَسْتَأْذِنُ فِي بَيْتِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أُرَاهُ فُلَانًا لِعَمِّ حَفْصَةَ مِنْ الرَّضَاعَةِ قَالَتْ عَائِشَةُ فَقُلْتُ لَوْ كَانَ فُلَانٌ حَيًّا لِعَمِّهَا مِنْ الرَّضَاعَةِ دَخَلَ عَلَيَّ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الرَّضَاعَةَ تُحَرِّمُ مَا يُحَرَّمُ مِنْ الْوِلَادَةِ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Ma'n], ia berkata; telah menceritakan kepada kami [Malik] dari [Abdullah bin Abu Bakr] dari ['Amrah] bahwa [Aisyah] mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam ada di rumahnya dan ia mendengar seorang laki-laki meminta izin di rumah Hafshah. Aisyah berkata; wahai Rasulullah, ini, seorang laki-laki meminta izin di rumahmu. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya diberitahu bahwa ia adalah Fulan paman Hafshah sepersusuan.\" Aisyah berkata; lalu saya katakan; seandainya Fulan pamannya sepersusuan masih hidup menemuiku. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Penyusuan mengharamkan apa yang diharamkan karena nasab.\""},"3170":{"ar":"أَخْبَرَنِي إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي عَطَاءٌ عَنْ عُرْوَةَ أَنَّ عَائِشَةَ قَالَتْجَاءَ عَمِّي أَبُو الْجَعْدِ مِنْ الرَّضَاعَةِ فَرَدَدْتُهُ قَالَ وَقَالَ هِشَامٌ هُوَ أَبُو الْقُعَيْسِ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ائْذَنِي لَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Abdur Razzaq], ia berkata; telah memberitakan kepada kami [Ibnu Juraij], ia berkata; ['Atho`] telah mengabarkan kepadaku dari ['Urwah] bahwa [Aisyah] berkata; telah datang pamanku sepersusuan Abu Al Ja'd, kemudian saya menolaknya. 'Atho` berkata; dan Hisyam yaitu Abu Al Qu'ais berkata; kemudian Rasulullah shallallahu 'alaihi wasallam datang dan saya beritahu beliau, lalu Rasulullah shallallahu 'alaihi wasallam bersabda; izinkan dia. "},"3171":{"ar":"أَخْبَرَنَا عَبْدُ الْوَارِثِ بْنُ عَبْدِ الصَّمَدِ بْنِ عَبْدِ الْوَارِثِ قَالَ حَدَّثَنِي أَبِي عَنْ أَيُّوبَ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ أَخَا أَبِي الْقُعَيْسِ اسْتَأْذَنَ عَلَى عَائِشَةَ بَعْدَ آيَةِ الْحِجَابِ فَأَبَتْ أَنْ تَأْذَنَ لَهُ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ائْذَنِي لَهُ فَإِنَّهُ عَمُّكِ فَقُلْتُ إِنَّمَا أَرْضَعَتْنِي الْمَرْأَةُ وَلَمْ يُرْضِعْنِي الرَّجُلُ فَقَالَ إِنَّهُ عَمُّكِ فَلْيَلِجْ عَلَيْكِ","id":"Telah mengabarkan kepada kami [Abdul Warits bin Abdush Shamad bin Abdul Warits], ia berkata; telah menceritakan kepadaku [ayahku] dari [Abu Ayyub] dari [Wahb bin Kaisan] dari ['Urwah] dari [Aisyah] bahwa saudara Abu Al Qu'ais meminta izin untuk menemui Aisyah setelah turun ayat Hijab. Kemudian ia menolak untuk memberikan izin kepadanya. Kemudian hal tersebut disebutkan kepada Nabi shallallahu 'alaihi wasallam, maka beliau bersabda: \"Izinkan dia, karena ia pamanmu.\" Lalu saya berkata; sesungguhnya saya disusui seorang wanita dan tidak disusui orang laki-laki. Maka beliau bersabda: \"Sungguh ia pamanmu, maka hendaknya ia menemuimu.\" "},"3172":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ أَنْبَأَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْكَانَ أَفْلَحُ أَخُو أَبِي الْقُعَيْسِ يَسْتَأْذِنُ عَلَيَّ وَهُوَ عَمِّي مِنْ الرَّضَاعَةِ فَأَبَيْتُ أَنْ آذَنَ لَهُ حَتَّى جَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ ائْذَنِي لَهُ فَإِنَّهُ عَمُّكِ قَالَتْ عَائِشَةُ وَذَلِكَ بَعْدَ أَنْ نَزَلَ الْحِجَابُ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah] telah memberitakan kepada kami [Ma'n], ia berkata; telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah], ia berkata; Aflah saudara Abu Al Qu'ais meminta izin kepadaku dan ia adalah pamanku sepersusuan, lalu saya menolak untuk memberikan izin kepadanya hingga Rasulullah shallallahu 'alaihi wasallam datang dan saya beritahukan kepadanya. Kemudian beliau bersabda: \"Izinkanlah dia, sungguh ia adalah pamanmu.\" Aisyah berkata; dan hal tersebut setelah turun ayat hijab. "},"3173":{"ar":"أَخْبَرَنَا عَبْدُ الْجَبَّارِ بْنُ الْعَلَاءِ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ وَهِشَامُ بْنُ عُرْوَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْاسْتَأْذَنَ عَلَيَّ عَمِّي أَفْلَحُ بَعْدَمَا نَزَلَ الْحِجَابُ فَلَمْ آذَنْ لَهُ فَأَتَانِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ فَقَالَ ائْذَنِي لَهُ فَإِنَّهُ عَمُّكِ قُلْتُ يَا رَسُولَ اللَّهِ إِنَّمَا أَرْضَعَتْنِي الْمَرْأَةُ وَلَمْ يُرْضِعْنِي الرَّجُلُ قَالَ ائْذَنِي لَهُ تَرِبَتْ يَمِينُكِ فَإِنَّهُ عَمُّكِ","id":"Telah mengabarkan kepada kami [Abdul Jabbar bin Al 'Ala`] dari [Sufyan] dari [Az Zuhri] dan [Hisyam bin 'Urwah] dari ['Urwah] dari [Aisyah], ia berkata; pamanku Aflah telah meminta izin untuk menemuiku setelah turun ayat Hijab, kemudian saya tidak mengizinkannya. Hingga Nabi shallallahu 'alaihi wasallam datang, lalu saya bertanya kepadanya. Kemudian beliau bersabda: \"Izinkanlah dia, ia adalah pamanmu.\" Saya katakan; wahai Rasulullah, saya disusui orang wanita dan tidak disusui orang laki-laki. Beliau bersabda: \"Izinkah dia, engkau beruntung. Ia adalah pamanmu.\""},"3174":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ بْنِ دَاوُدَ قَالَ حَدَّثَنَا أَبُو الْأَسْوَدِ وَإِسْحَقُ بْنُ بَكْرٍ قَالَا حَدَّثَنَا بَكْرُ بْنُ مُضَرَ عَنْ جَعْفَرِ بْنِ رَبِيعَةَ عَنْ عِرَاكِ بْنِ مَالِكٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْجَاءَ أَفْلَحُ أَخُو أَبِي الْقُعَيْسِ يَسْتَأْذِنُ فَقُلْتُ لَا آذَنُ لَهُ حَتَّى أَسْتَأْذِنَ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا جَاءَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ لَهُ جَاءَ أَفْلَحُ أَخُو أَبِي الْقُعَيْسِ يَسْتَأْذِنُ فَأَبَيْتُ أَنْ آذَنَ لَهُ فَقَالَ ائْذَنِي لَهُ فَإِنَّهُ عَمُّكِ قُلْتُ إِنَّمَا أَرْضَعَتْنِي امْرَأَةُ أَبِي الْقُعَيْسِ وَلَمْ يُرْضِعْنِي الرَّجُلُ قَالَ ائْذَنِي لَهُ فَإِنَّهُ عَمُّكِ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman bin Daud], ia berkata; telah menceritakan kepada kami [Abu Al Aswad] dan [Ishaq bin Bakr] mereka berkata; telah menceritakan kepada kami [Bakr bin Mudhar] dari [Ja'far bin Rabi'ah] dari ['Irak bin Malik] dari ['Urwah] dari [Aisyah], ia berkata; Aflah saudara Abu Al Qu'ais datang meminta izin, kemudian saya katakan; saya tidak akan mengizinkannya hingga saya meminta izin kepada Nabi shallallahu 'alaihi wasallam, kemudian setelah Nabi shallallahu 'alaihi wasallam datang saya katakan kepadanya; Aflah saudara Abu Al Qu'ais datang meminta izin, kemudian saya menolak untuk mengizinkannya. Maka beliau bersabda: \"Izinkan dia, ia adalah pamanmu.\" Maka saya katakan; saya disusui isteri Abu Al Qu'ais, dan tidak disusui laki-laki. Beliau bersabda: \"Izinkan dia, ia adalah pamanmu.\""},"3175":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مَخْرَمَةُ بْنُ بُكَيْرٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ حُمَيْدَ بْنَ نَافِعٍ يَقُولُ سَمِعْتُ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ تَقُولُ سَمِعْتُ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَقُولُجَاءَتْ سَهْلَةُ بِنْتُ سُهَيْلٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي لَأَرَى فِي وَجْهِ أَبِي حُذَيْفَةَ مِنْ دُخُولِ سَالِمٍ عَلَيَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْضِعِيهِ قُلْتُ إِنَّهُ لَذُو لِحْيَةٍ فَقَالَ أَرْضِعِيهِ يَذْهَبْ مَا فِي وَجْهِ أَبِي حُذَيْفَةَ قَالَتْ وَاللَّهِ مَا عَرَفْتُهُ فِي وَجْهِ أَبِي حُذَيْفَةَ بَعْدُ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepadaku [Makhramah bin Bukair] dari [ayahnya], ia berkata; saya mendengar [Humaid bin Nafi'], ia berkata; saya mendengar [Zainab binti Abu Salamah] berkata; saya mendengar ['Aisyah] istri Nabi shallallahu 'alaihi wasallam berkata; Sahlah binti Suhail menemui Rasulullah shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, saya melihat kemarahan di wajah Abu Hudzaifah karena Salim masuk kerumahku, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Susuilah dia, \" ia menjawab ia sudah memiliki jenggot, beliau bersabda: \"Susuilah ia dan akan pergi kemarahan yang ada diwajah Abi Hudzaifah, \" ia berkata demi Allah aku tidak mengetahuinya diwajah Abi Hudzaifah setelah itu."},"3176":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ سَمِعْنَاهُ مِنْ عَبْدِ الرَّحْمَنِ وَهُوَ ابْنُ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْجَاءَتْ سَهْلَةُ بِنْتُ سُهَيْلٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنِّي أَرَى فِي وَجْهِ أَبِي حُذَيْفَةَ مِنْ دُخُولِ سَالِمٍ عَلَيَّ قَالَ فَأَرْضِعِيهِ قَالَتْ وَكَيْفَ أُرْضِعُهُ وَهُوَ رَجُلٌ كَبِيرٌ فَقَالَ أَلَسْتُ أَعْلَمُ أَنَّهُ رَجُلٌ كَبِيرٌ ثُمَّ جَاءَتْ بَعْدُ فَقَالَتْ وَالَّذِي بَعَثَكَ بِالْحَقِّ نَبِيًّا مَا رَأَيْتُ فِي وَجْهِ أَبِي حُذَيْفَةَ بَعْدُ شَيْئًا أَكْرَهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abdur Rahman], ia berkata; telah menceritakan kepada kami [Sufyan], ia berkata; kami mendengarnya dari [Abdur Rahman yaitu Ibnu Al Qasim] dari [ayahnya] dari [Aisyah], ia berkata; Sahlah binti Suhail menemui Rasulullah shallallahu 'alaihi wasallam dan berkata; saya melihat kemarahan di wajah Abu Hudzaifah karena Salim masuk rumahku. Beliau bersabda: \"Susuilah dia.\" Ia berkata; bagaimana saya menyusuinya, sedangkan dia adalah laki-laki dewasa. Kemudian beliau bersabda: \"Bukankah saya tahu bahwa ia adalah laki-laki dewasa?\" kemudian ia datang setelah itu, dan berkata; demi Dzat yang mengutusmu dengan kebenaran sebagai Nabi. Saya tidak melihat sesuatupun di wajah Abu Hudzaifah setelah itu yang tidak saya suka. "},"3177":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ يَحْيَى أَبُو الْوَزِيرِ قَالَ سَمِعْتُ ابْنَ وَهْبٍ قَالَ أَخْبَرَنِي سُلَيْمَانُ عَنْ يَحْيَى وَرَبِيعَةُ عَنْ الْقَاسِمِ عَنْ عَائِشَةَ قَالَتْأَمَرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةَ أَبِي حُذَيْفَةَ أَنْ تُرْضِعَ سَالِمًا مَوْلَى أَبِي حُذَيْفَةَ حَتَّى تَذْهَبَ غَيْرَةُ أَبِي حُذَيْفَةَ فَأَرْضَعَتْهُ وَهُوَ رَجُلٌقَالَ رَبِيعَةُ فَكَانَتْ رُخْصَةً لِسَالِمٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Yahya Abu Al Wazir], ia berkata; saya mendengar [Ibnu Wahb] berkata; telah mengabarkan kepadaku [Sulaiman] dari [Yahya] dan [Rabi'ah] dari [Al Qasim] dari [Aisyah], ia berkata; Nabi shallallahu 'alaihi wasallam memerintahkan isteri Abu Hudzaifah untuk menyusui Salim maula Abu Hudzaifah hingga hilang kecemburuan Abu Hudzaifah, ia menyusuinya sedang ia adalah laki-laki dewasa. Rabi'ah berkata; hal tersebut merupakan keringanan bagi Salim. "},"3178":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ عَنْ سُفْيَانَ وَهُوَ ابْنُ حَبِيبٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ قَالَتْجَاءَتْ سَهْلَةُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ سَالِمًا يَدْخُلُ عَلَيْنَا وَقَدْ عَقَلَ مَا يَعْقِلُ الرِّجَالُ وَعَلِمَ مَا يَعْلَمُ الرِّجَالُ قَالَ أَرْضِعِيهِ تَحْرُمِي عَلَيْهِ بِذَلِكَفَمَكَثْتُ حَوْلًا لَا أُحَدِّثُ بِهِ وَلَقِيتُ الْقَاسِمَ فَقَالَ حَدِّثْ بِهِ وَلَا تَهَابُهُ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] dari [Sufyan yaitu Ibnu Habib] dari [Ibnu Juraij] dari [Ibnu Abi Mulaikah] dari [Al Qasim bin Muhammad] dari [Aisyah], ia berkata; Sahlah menemui Rasulullah shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, sesungguhnya Salim memasuki rumah kami, dan ia telah berfikiran seperti yang difikirkan para lelaki dewasa, dan telah mengetahui apa yang diketahui laki-laki dewasa. Maka beliau bersabda: \"Susuilah dia, maka engkau akan menjadi haram baginya dengan hal tersebut.\" Kemudian saya tinggal satu tahun tidak menceritakan hadis tersebut, dan bertemu Al Qasim kemudian ia berkata; ceritakan hadis tersebut dan engkau tidak akan takut. "},"3179":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ عَبْدِ الْوَهَّابِ قَالَ أَنْبَأَنَا أَيُّوبُ عَنْ ابْنِ أَبِي مُلَيْكَةَ عَنْ الْقَاسِمِ عَنْ عَائِشَةَأَنَّ سَالِمًا مَوْلَى أَبِي حُذَيْفَةَ كَانَ مَعَ أَبِي حُذَيْفَةَ وَأَهْلِهِ فِي بَيْتِهِمْ فَأَتَتْ بِنْتُ سُهَيْلٍ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ سَالِمًا قَدْ بَلَغَ مَا يَبْلُغُ الرِّجَالُ وَعَقَلَ مَا عَقَلُوهُ وَإِنَّهُ يَدْخُلُ عَلَيْنَا وَإِنِّي أَظُنُّ فِي نَفْسِ أَبِي حُذَيْفَةَ مِنْ ذَلِكَ شَيْئًا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْضِعِيهِ تَحْرُمِي عَلَيْهِ فَأَرْضَعْتُهُ فَذَهَبَ الَّذِي فِي نَفْسِ أَبِي حُذَيْفَةَ فَرَجَعْتُ إِلَيْهِ فَقُلْتُ إِنِّي قَدْ أَرْضَعْتُهُ فَذَهَبَ الَّذِي فِي نَفْسِ أَبِي حُذَيْفَةَ","id":"Telah mengabarkan kepada kami ['Amr bin Ali] dari [Abdul Wahhab], ia berkata; telah memberitakan kepada kami [Ayyub] dari [Ibnu Abi Mulaikah] dari [Al Qasim] dari [Aisyah] bahwa Salim maula Abu Hudzaifah dahulu tinggal bersama Abu Hudzaifah dan isterinya di rumah mereka. Kemudian datang anak wanita Suhail kepada Nabi shallallahu 'alaihi wasallam dan berkata; Salim telah mencapai seperti yang dicapai laki-laki dewasa, dan berfikir seperti yang mereka fikirkan. Dan ia masuk ke rumah kami, dan saya mengetahui ada sesuatu yang \"kurang sreg\" dalam hati Abu Hudzaifah Karena hal tersebut. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Susuilah dia, engkau menjadi haram baginya.\" Maka saya menyusuinya dan hilanglah kejengkelan yang ada dalam hati Abu Hudzaifah. Kemudian saya kembali kepada beliau dan saya katakan; sungguh saya telah menyusuinya, kemudian hilanglah apa yang ada pada hati Abu Hudzaifah. "},"3180":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ وَمَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ قَالَأَبَى سَائِرُ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يَدْخُلَ عَلَيْهِنَّ بِتِلْكَ الرَّضْعَةِ أَحَدٌ مِنْ النَّاسِ يُرِيدُ رَضَا��َةَ الْكَبِيرِ وَقُلْنَ لِعَائِشَةَ وَاللَّهِ مَا نُرَى الَّذِي أَمَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَهْلَةَ بِنْتَ سُهَيْلٍ إِلَّا رُخْصَةً فِي رَضَاعَةِ سَالِمٍ وَحْدَهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاللَّهِ لَا يَدْخُلُ عَلَيْنَا أَحَدٌ بِهَذِهِ الرَّضْعَةِ وَلَا يَرَانَا","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la], ia berkata; telah memberitakan kepada kami [Ibnu Wahb], ia berkata; telah memberitakan kepadaku [Yunus] dan [Malik] dari [Ibnu Syihab] dari ['Urwah], ia berkata; seluruh istri Nabi shallallahu 'alaihi wasallam enggan jika seseorang dengan alasan susuan itu masuk kerumah mereka, dan berniyat ingin menyusukan orang dewasa. mereka berkata kepada 'Aisyah demi Allah kami tidak melihat apa yang Rasulullah shallallahu 'alaihi wasallam perintahkan kepada Sahlah binti Suhail kecuali hanya keringanan dari Rasulullah shallallahu 'alaihi wasallam untuk menyusui Salim saja, demi Allah tidak boleh seseorang masuk kerumah kami karena susuan ini dan iapun tidak akan melihat kami."},"3181":{"ar":"أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ قَالَ أَخْبَرَنِي أَبِي عَنْ جَدِّي قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي أَبُو عُبَيْدَةَ بْنُ عَبْدِ اللَّهِ بْنِ زَمْعَةَ أَنَّ أُمَّهُ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُ أَنَّ أُمَّهَا أُمَّ سَلَمَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَكَانَتْ تَقُولُ أَبَى سَائِرُ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ يُدْخَلَ عَلَيْهِنَّ بِتِلْكَ الرَّضَاعَةِ وَقُلْنَ لِعَائِشَةَ وَاللَّهِ مَا نُرَى هَذِهِ إِلَّا رُخْصَةً رَخَّصَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَاصَّةً لِسَالِمٍ فَلَا يَدْخُلْ عَلَيْنَا أَحَدٌ بِهَذِهِ الرَّضَاعَةِ وَلَا يَرَانَا","id":"Telah mengabarkan kepada kami [Abdul Malik bin Syu'aib bin Al Laits], ia berkata; telah memberitakan kepadaku [ayahku] dari [kakekku], ia berkata; telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab], telah memberitakan kepadaku [Abu 'Ubaidah bin Abdullah bin Zam'ah] bahwa ibunya yaitu [Zainab binti Abi Salamah] telah mengabarkan kepadanya bahwa ibunya yaitu [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam pernah berkata; seluruh isteri Nabi shallallahu 'alaihi wasallam enggan bila seseorang menemui mereka dengan alasan persusuan tersebut, dan mereka berkata kepada Aisyah; demi Allah kami tidak melihat hal ini kecuali sebagai keringanan yang Rasulullah shallallahu 'alaihi wasallam berikan khusus untuk Salim. Maka tidak boleh ada seorangpun yang masuk menemui kami dengan alasan ingin persusuan ini, dan ia tidak akan melihat kami."},"3182":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ وَإِسْحَقُ بْنُ مَنْصُورٍ عَنْ عَبْدِ الرَّحْمَنِ عَنْ مَالِكٍ عَنْ أَبِي الْأَسْوَدِ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّ جُدَامَةَ بِنْتَ وَهْبٍ حَدَّثَتْهَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَقَدْ هَمَمْتُ أَنْ أَنْهَى عَنْ الْغِيلَةِ حَتَّى ذَكَرْتُ أَنَّ فَارِسَ وَالرُّومَ يَصْنَعُهُ وَقَالَ إِسْحَقُ يَصْنَعُونَهُ فَلَا يَضُرُّ أَوْلَادَهُمْ","id":"Telah mengabarkan kepada kami ['Ubaidullah] dan [Ishaq bin Manshur] dari [Abdur Rahman] dari [Malik] dari [Abu Al Aswad] dari ['Urwah] dari [Aisyah] bahwa [Judamah binti Wahb] telah menceritakan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh saya hendak melarang menjimaki wanita saat menyusui, kemudian saya ingat bahwa orang Persia dan Romawi melakukan hal tersebut.\" Ishaq berkata; mereka melakukan hal tersebut dan tidak membahayakan anak-anak mereka (tidak masalah). "},"3183":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ وَحُمَيْدُ بْنُ مَسْعَدَةَ قَالَا حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ بِشْرِ بْنِ مَسْعُودٍ وَرَدَّ الْحَدِيثَ حَتَّى رَدَّهُ إِلَى أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَذُكِرَ ذَلِكَ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ وَمَا ذَاكُمْ قُلْنَا الرَّجُلُ تَكُونُ لَهُ الْمَرْأَةُ فَيُصِيبُهَا وَيَكْرَهُ الْحَمْلَ وَتَكُونُ لَهُ الْأَمَةُ فَيُصِيبُ مِنْهَا وَيَكْرَهُ أَنْ تَحْمِلَ مِنْهُ قَالَ لَا عَلَيْكُمْ أَنْ لَا تَفْعَلُوا فَإِنَّمَا هُوَ الْقَدَرُ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] dan [Humaid bin Mas'adah] mereka berdua; telah menceritakan kepada kami [Yazid bin Zurai'], ia berkata; telah menceritakan kepada kami [Ibnu 'Aun] dari [Muhammad bin Sirin] dari [Abdur Rahman bin Bisyr bin Mas'ud] dan ia mengembalikan hadis hingga mengembalikannya kepada [Abu Sa'id Al Khudri], ia berkata; hal tersebut disebutkan kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau bersabda: \"Apakah ini?\" terdapat seorang laki-laki yang memiliki isteri kemudian ia menggaulinya dan tidak menginginkan kehamilan, dan ia memiliki seorang sahaya wanita, kemudian ia menggaulinya dan tidak menginginkan ia hamil. Beliau bersabda: \"Tidak, kalian tidak boleh melakukannya sesungguhnya hal itu adalah taqdir.\""},"3184":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ عَنْ مُحَمَّدٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي الْفَيْضِ قَالَ سَمِعْتُ عَبْدَ اللَّهِ بْنَ مُرَّةَ الزُّرَقِيَّ عَنْ أَبِي سَعِيدٍ الزُّرَقِيِّأَنَّ رَجُلًا سَأَلَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْعَزْلِ فَقَالَ إِنَّ امْرَأَتِي تُرْضِعُ وَأَنَا أَكْرَهُ أَنْ تَحْمِلَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ مَا قَدْ قُدِّرَ فِي الرَّحِمِ سَيَكُونُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] dari [Muhammad], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Al Faidh], ia berkata; saya pernah mendengar [Abdullah bin Murrah Az Zuraqi] dari [Abu Sa'id Az Zuraqi] bahwa terdapat seorang laki-laki yang bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai 'uzlah (mengeluarkan mani di luar rahim). Ia berkata; sesungguhnya isteri saya sedang menyusui dan saya tidak ingin ia hamil. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya apa yang telah ditakdirkan di dalam rahim akan terjadi.\""},"3185":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى عَنْ هِشَامٍ قَالَ وَحَدَّثَنِي أَبِي عَنْ حَجَّاجِ بْنِ حَجَّاجٍ عَنْ أَبِيهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ مَا يُذْهِبُ عَنِّي مَذَمَّةَ الرَّضَاعِ قَالَ غُرَّةُ عَبْدٍ أَوْ أَمَةٍ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Yahya] dari [Hisyam], ia berkata; dan telah menceritakan kepadaku [ayahku] dari [Hajjaj bin Hajjaj] dari [ayahnya], ia berkata; saya berkata kepada Rasulullah shallallahu 'alaihi wasallam; apakah yang menghilangkan dariku hak karena penyusuan? Beliau bersabda: \"Memberikan sahaya laki-laki atau wanita.\""},"3186":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ ابْنِ أَبِي مُلَيْكَةَ قَالَ حَدَّثَنِي عُبَيْدُ بْنُ أَبِي مَرْيَمَ عَنْ عُقْبَةَ بْنِ الْحَارِثِ قَالَ وَقَدْ سَمِعْتُهُ مِنْ عُقْبَةَ وَلَكِنِّي لِحَدِيثِ عُبَيْدٍ أَحْفَظُ قَالَتَزَوَّجْتُ امْرَأَةً فَجَاءَتْنَا امْرَأَةٌ سَوْدَاءُ فَقَالَتْ إِنِّي قَدْ أَرْضَعْتُكُمَا فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقُلْتُ إِنِّي تَزَوَّجْتُ فُلَانَةَ بِنْتَ فُلَانٍ فَجَاءَتْنِي امْرَأَةٌ سَوْدَاءُ فَقَالَتْ إِنِّي قَدْ أَرْضَعْتُكُمَا فَأَعْرَضَ عَنِّي فَأَتَيْتُهُ مِنْ قِبَلِ وَجْهِهِ فَقُلْتُ إِنَّهَا كَاذِبَةٌ قَالَ وَكَيْفَ بِهَا وَقَدْ زَعَمَتْ أَنَّهَا قَدْ أَرْضَعَتْكُمَا دَعْهَا عَنْكَ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah memberitakan kepada kami [Isma'il] dari [Ayyub] dari [Ibnu Abi Mulaikah], ia berkata; telah menceritakan kepadaku ['Ubaid bin Abi Maryam] dari ['Uqbah bin Al Harits], ia berkata; saya telah mendengarnya dari 'Uqbah akan tetapi saya lebih hafal hadis 'Ubaid, saya hafal ia berkata; saya menikahi seorang wanita, kemudian datang kepada kami seorang wanita hitam. Kemudian berkata; saya pernah menyusui kalian berdua. Kemudian saya datang kepada Nabi shallallahu 'alaihi wasallam dan mengabarkan kepada beliau. Saya katakan; saya telah menikahi Fulanah binti Fulan, kemudian datang kepadaku seorang wanita hitam kemudian berkata; saya pernah menyusui kalian berdua. Kemudian beliau berpaling dariku, lalu saya mendatangi beliau dari depan dan saya katakan; ia berdusta. Beliau bersabda: \"Bagaimana dengannya? Sedang ia telah mengaku bahwa dia pernah menyusui kalian berdua? Tinggalkan wanita tersebut.\" "},"3187":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عُثْمَانَ بْنِ حَكِيمٍ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا الْحَسَنُ بْنُ صَالِحٍ عَنْ السُّدِّيِّ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ الْبَرَاءِ قَالَلَقِيتُ خَالِي وَمَعَهُ الرَّايَةُ فَقُلْتُ أَيْنَ تُرِيدُ قَالَ أَرْسَلَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رَجُلٍ تَزَوَّجَ امْرَأَةَ أَبِيهِ مِنْ بَعْدِهِ أَنْ أَضْرِبَ عُنُقَهُ أَوْ أَقْتُلَهُ","id":"Telah mengabarkan kepada kami [Ahmad bin Usman bin Hakim], ia berkata; telah menceritakan kepada kami [Abu Nu'aim], ia berkata; telah menceritakan kepada kami [Al Hasan bin Shalih] dari [As Suddi] dari [Adi bin Tsabit] dari [Al Barra`], ia berkata; saya berjumpa dengan [pamanku], dan ia membawa bendera. Kemudian saya katakan; engkau hendak pergi kemana? Ia berkata; Rasulullah shallallahu 'alaihi wasallam mengutusku kepada seorang laki-laki yang menikahi isteri ayahnya setelah kematiannya, agar saya penggal lehernya atau saya membunuhnya. "},"3188":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ عَمْرٍو عَنْ زَيْدٍ عَنْ عَدِيِّ بْنِ ثَابِتٍ عَنْ يَزِيدَ بْنِ الْبَرَاءِ عَنْ أَبِيهِ قَالَأَصَبْتُ عَمِّي وَمَعَهُ رَايَةٌ فَقُلْتُ أَيْنَ تُرِيدُ فَقَالَ بَعَثَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى رَجُلٍ نَكَحَ امْرَأَةَ أَبِيهِ فَأَمَرَنِي أَنْ أَضْرِبَ عُنُقَهُ وَآخُذَ مَالَهُ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Abdullah bin Ja'far], ia berkata; telah menceritakan kepada kami ['Ubaidullah bin 'Amr] dari [Zaid] dari [Adi bin Tsabit] dari [Yazid bin Al Barra`] dari [ayahnya], ia berkata; saya menjumpai pamanku dan ia membawa bendera, kemudian saya berkata; engkau hendak kemana? Lalu ia berkata; Rasulullah shallallahu 'alaihi wasallam mengutusku kepada seorang laki-laki yang menikahi isteri ayahnya, beliau memerintahkanku untuk memenggal lehernya dan mengambil hartanya. "},"3189":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ أَبِي الْخَلِيلِ عَنْ أَبِي عَلْقَمَةَ الْهَاشِمِيِّ عَنْ أَبِي سَعِيدٍ الْخُدْرِيِّأَنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعَثَ جَيْشًا إِلَى أَوْطَاسٍ فَلَقُوا عَدُوًّا فَقَاتَلُوهُمْ وَظَهَرُوا عَلَيْهِمْ فَأَصَابُوا لَهُمْ سَبَايَا لَهُنَّ أَزْوَاجٌ فِي الْمُشْرِكِينَ فَكَانَ الْمُسْلِمُونَ تَحَرَّجُوا مِنْ غِشْيَانِهِنَّ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَالْمُحْصَنَاتُ مِنْ النِّسَاءِ إِلَّا مَا مَلَكَتْ أَيْمَانُكُمْ }أَيْ هَذَا لَكُمْ حَلَالٌ إِذَا انْقَضَتْ عِدَّتُهُنَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Yazid bin Zurai'], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Khalil] dari [Abu 'Alqamah Al Hasyimi] dari [Abu Sa'id Al Khudri], Nabi shallallahu 'alaihi wasallam mengutus pasukan ke Authas, kemudian mereka bertemu dengan musuh lalu bertempur dan menang. Mereka mendapatkan beberapa orang tawanan wanita yang memiliki suami dari kalangan orang-orang musyrik. Pasukan muslimin merasa enggan untuk menggauli mereka. Lalu Allah 'azza wajalla menurunkan ayat: Dan (diharamkan juga kamu mengawini) wanita yang bersuami, kecuali budak-budak yang kamu miliki, Yaitu hal ini adalah halal bagi kalian, apabila telah selesai 'iddah mereka. "},"3190":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الشِّغَارِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah], ia berkata; telah memberitakan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang nikah syighar. "},"3191":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا بِشْرٌ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا جَلَبَ وَلَا جَنَبَ وَلَا شِغَارَ فِي الْإِسْلَامِ وَمَنْ انْتَهَبَ نُهْبَةً فَلَيْسَ مِنَّا","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah], ia berkata; telah menceritakan kepada kami [Bisyr], ia berkata; telah menceritakan kepada kami [Humaid] dari [Al Hasan] dari ['Imran bin Hushain] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada jalab, janab dan syighar dalam Islam, dan barang siapa yang merampas suatu rampasan maka bukan dari golongan kami.\" "},"3192":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مُحَمَّدِ بْنِ عَلِيٍّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ عَنْ الْفَزَارِيِّ عَنْ حُمَيْدٍ عَنْ أَنَسٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا جَلَبَ وَلَا جَنَبَ وَلَا شِغَارَ فِي الْإِسْلَامِقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ فَاحِشٌ وَالصَّوَابُ حَدِيثُ بِشْرٍ","id":"Telah mengabarkan kepada kami [Ali bin Muhammad bin Ali], ia berkata; telah menceritakan kepada kami [Muhammad bin Katsir] dari [Al Fazari] dari [Humaid] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada jalab, janab dan syighar dalam Islam.\" Abu Abdur Rahman berkata; hal ini adalah kesalahan fatal, dan yang benar adalah hadis Bisyr. "},"3193":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ ح وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ مَالِكٌ حَدَّثَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ الشِّغَارِ وَالشِّغَارُ أَنْ يُزَوِّجَ الرَّجُلُ الرَّجُلَ ابْنَتَهُ عَلَى أَنْ يُزَوِّجَهُ ابْنَتَهُ وَلَيْسَ بَيْنَهُمَا صَدَاقٌ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Ma'n], ia berkata; telah menceritakan kepada kami [Malik] dari [Nafi'] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar dari [Ibnu Al Qasim], ia berkata; [Malik] berkata; telah menceritakan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam melarang dari syighar, dan syighar adalah seorang laki-laki menikahkan laki-laki yang lain dengan anaknya dengan syarat ia menikahkannya dengan anak wanitanya dan diantara mereka tidak ada mahar. "},"3194":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ وَعَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَا حَدَّثَنَا إِسْحَقُ الْأَزْرَقُ عَنْ عُبَيْدِ اللَّهِ عَنْ أَبِي الزِّنَادِ عَنْ الْأَعْرَجِ عَنْ أَبِي هُرَيْرَةَ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الشِّغَارِقَالَ عُبَيْدُ اللَّهِ وَالشِّغَارُ كَانَ الرَّجُلُ يُزَوِّجُ ابْنَتَهُ عَلَى أَنْ يُزَوِّجَهُ أُخْتَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Ibrahim] dan [Abdur Rahman bin Muhammad bin Sallam] mereka berkata; telah menceritakan kepada kami [Ishaq Al Azraq] dari ['Ubaidullah] dari [Abu Az Zinad] dari [Al A'raj] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melarang dari syighar. 'Ubaidullah berkata; syighar adalah seorang laki-laki menikahkan anak wanitanya dengan orang lain dengan syarat orang tersebut menikahkannya dengan saudara wanitanya. "},"3195":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا يَعْقُوبُ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ امْرَأَةً جَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ جِئْتُ لِأَهَبَ نَفْسِي لَكَ فَنَظَرَ إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصَعَّدَ النَّظَرَ إِلَيْهَا وَصَوَّبَهُ ثُمَّ طَأْطَأَ رَأْسَهُ فَلَمَّا رَأَتْ الْمَرْأَةُ أَنَّهُ لَمْ يَقْضِ فِيهَا شَيْئًا جَلَسَتْ فَقَامَ رَجُلٌ مِنْ أَصْحَابِهِ فَقَالَ أَيْ رَسُولَ اللَّهِ إِنْ لَمْ يَكُنْ لَكَ بِهَا حَاجَةٌ فَزَوِّجْنِيهَا قَالَ هَلْ عِنْدَكَ مِنْ شَيْءٍ فَقَالَ لَا وَاللَّهِ مَا وَجَدْتُ شَيْئًا فَقَالَ انْظُرْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَذَهَبَ ثُمَّ رَجَعَ فَقَالَ لَا وَاللَّهِ يَا رَسُولَ اللَّهِ وَلَا خَاتَمًا مِنْ حَدِيدٍ وَلَكِنْ هَذَا إِزَارِي قَالَ سَهْلٌ مَا لَهُ رِدَاءٌ فَلَهَا نِصْفُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَصْنَعُ بِإِزَارِكَ إِنْ لَبِسْتَهُ لَمْ يَكُنْ عَلَيْهَا مِنْهُ شَيْءٌ وَإِنْ لَبِسَتْهُ لَمْ يَكُنْ عَلَيْكَ مِنْهُ شَيْءٌ فَجَلَسَ الرَّجُلُ حَتَّى طَالَ مَجْلِسُهُ ثُمَّ قَامَ فَرَآهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُوَلِّيًا فَأَمَرَ بِهِ فَدُعِيَ فَلَمَّا جَاءَ قَالَ مَاذَا مَعَكَ مِنْ الْقُرْآنِ قَالَ مَعِي سُورَةُ كَذَا وَسُورَةُ كَذَا عَدَّدَهَا فَقَالَ هَلْ تَقْرَؤُهُنَّ عَنْ ظَهْرِ قَلْبٍ قَالَ نَعَمْ قَالَ مَلَّكْتُكَهَا بِمَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Ya'qub] dari [Abu Hazim] dari [Sahl bin Sa'd] bahwa terdapat seorang wanita yang datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, saya datang untuk menghibahkan diriku kepadamu. Kemudian Rasulullah shallallahu 'alaihi wasallam melihat kepadanya, lalu mengangkat pandangannya kepadanya dan merendahkannya kemudian menundukkan kepalanya. Kemudian tatkala wanita tersebut melihat bahwa beliau tidak menunaikan sesuatu pada dirinya iapun duduk. Lalu terdapat seorang laki-laki dari kalangan sahabat yang berdiri kemudian berkata; wahai Rasulullah, apabila engkau butuh kepadanya maka nikahkanlah saya dengannya. Beliau bersabda: \"Apakah engkau memiliki sesuatu?\" kemudian orang tersebut mengatakan; tidak, demi Allah saya tidak mendapatkan sesuatu. Kemudian beliau bersabda: \"Lihatlah walaupun satu cincin besi.\" Lalu orang tersebut pergi kemudian kembali dan berkata; tidak, demi Allah wahai Rasulullah, tidak juga cincin besi, akan tetapi ini ada sarungku. Sahl berkata; ia memiliki selendang, maka bagi wanita tersebut setengahnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apa yang dapat engkau perbuat dengan sarungmu itu? Apabila engkau memakainya maka ia tidak memakai sedikitpun darinya. Dan jika ia memakainya maka engkau tidak memakai sedikitpun darinya.\" Lalu laki-laki tersebut duduk hingga lama, kemudian berdiri dan dilihat Rasulullah shallallahu 'alaihi wasallam berpaling. Kemudian beliau memerintahkan agar ia dipanggil, lalu orang tersebut dipanggil. Lalu setelah ia datang beliau bersabda: \"Apa yang engkau miliki dari Al Qur'an?\" orang tersebut berkata; saya memiliki surat demikian dan demikian. Dan iapun menyebutkannya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah engkau dapat membacanya di luar kepala?\" orang tersebut berkata; ya. Maka beliau bersabda: \"Saya berikan dia kepadamu dengan apa yang engkau miliki dari Al Qur'an.\""},"3196":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى عَنْ عَبْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ بْنِ أَبِي طَلْحَةَ عَنْ أَنَسٍ قَالَتَزَوَّجَ أَبُو طَلْحَةَ أُمَّ سُلَيْمٍ فَكَانَ صِدَاقُ مَا بَيْنَهُمَا الْإِسْلَامَ أَسْلَمَتْ أُمُّ سُلَيْمٍ قَبْلَ أَبِي طَلْحَةَ فَخَطَبَهَا فَقَالَتْ إِنِّي قَدْ أَسْلَمْتُ فَإِنْ أَسْلَمْتَ نَكَحْتُكَ فَأَسْلَمَ فَكَانَ صِدَاقَ مَا بَيْنَهُمَا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Muhammad bin Musa] dari [Abdullah bin Abdullah bin Abi Thalhah] dari [Anas], ia berkata; Abu Tholhah menikahi Umi Sulaim dan mahar perkawinan keduanya adalah Islam, Umi Sulaim masuk Islam sebelum Abu Thalhah, lalu Abu Thalhah melamarnya dan Umi Sulaim menjawab berkata 'aku telah masuk Islam, jika engkau masuk Islam maka aku akan menerima nikahmu', lalu ia masuk Islam dan itulah mahar keduanya."},"3197":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ النَّضْرِ بْنِ مُسَاوِرٍ قَالَ أَنْبَأَنَا جَعْفَرُ بْنُ سُلَيْمَانَ عَنْ ثَابِتٍ عَنْ أَنَسٍ قَالَخَطَبَ أَبُو طَلْحَةَ أُمَّ سُلَيْمٍ فَقَالَتْ وَاللَّهِ مَا مِثْلُكَ يَا أَبَا طَلْحَةَ يُرَدُّ وَلَكِنَّكَ رَجُلٌ كَافِرٌ وَأَنَا امْرَأَةٌ مُسْلِمَةٌ وَلَا يَحِلُّ لِي أَنْ أَتَزَوَّجَكَ فَإِنْ تُسْلِمْ فَذَاكَ مَهْرِي وَمَا أَسْأَلُكَ غَيْرَهُ فَأَسْلَمَ فَكَانَ ذَلِكَ مَهْرَهَاقَالَ ثَابِتٌ فَمَا سَمِعْتُ بِامْرَأَةٍ قَطُّ كَانَتْ أَكْرَمَ مَهْرًا مِنْ أُمِّ سُلَيْمٍ الْإِسْلَامَ فَدَخَلَ بِهَا فَوَلَدَتْ لَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin An Nadhr bin Musari], ia berkata; telah memberitakan kepada kami [Ja'far bin Sulaiman] dari [Tsabit] dari [Anas], ia berkata; Abu Thalhah melamar Ummu Sulaim. Kemudian Ummu Sulaim berkata; demi Allah, orang sepertimu tidak pantas ditolak wahai Abu Thalhah. Akan tetapi engkau adalah orang kafir dan saya adalah wanita muslimah. Tidak halal saya menikah denganmu, maka jika engkau masuk Islam maka itu adalah maharku. Dan saya tidak meminta selain itu kepadamu. Kemudian iapun masuk Islam, dan itulah yang menjadi maharnya. Tsabit berkata; saya tidak mendengar sama sekali wanita yang maharnya lebih mulia daripada Ummu Sulaim, yaitu Islam. Kemudian Abu Thalhah berumah tangga dengannya dan melahirkan anak dari perkawinannya. "},"3198":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ وَعَبْدُ الْعَزِيزِ يَعْنِي ابْنَ صُهَيْبٍ عَنْ أَنَسِ بْنِ مَالِكٍ ح وَأَنْبَأَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ ثَابِتٍ وَشُعَيْبٌ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتَقَ صَفِيَّةَ وَجَعَلَهُ صَدَاقَهَا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dan [Abdul Aziz yaitu ibnu Shuhaib] dari [Anas bin Malik]. -dari jalur periwayatan yang lain- Telah memberitakan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Hammad] dari [Tsabit] dan [Syu'aib] dari [Anas], Rasulullah shallallahu 'alaihi wasallam memerdekakan Shafiyah dan menjadikannya sebagai maharnya. "},"3199":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا سُفْيَانُ ح وَأَنْبَأَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يُونُسَ عَنْ ابْنِ الْحَبْحَابِ عَنْ أَنَسٍأَعْتَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ صَفِيَّةَ وَجَعَلَ عِتْقَهَا مَهْرَهَاوَاللَّفْظُ لِمُحَمَّدٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'], ia berkata; telah menceritakan kepada kami [Yahya bin Adam], ia berkata; telah menceritakan kepada kami [Sufyan]. Dan -dari jalur periwayatan lain- Telah memberitakan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Abu Nu'aim], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Yunus] dari [Ibnu Al Habhab] dari [Anas], Rasulullah shallallahu 'alaihi wasallam memerdekakan Shafiyah dan menjadikan pembebasannya sebagai maharnya. Dan lafazhnya adalah lafazh Muhammad. "},"3200":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ أَبِي زَائِدَةَ قَالَ حَدَّثَنِي صَالِحُ بْنُ صَالِحٍ عَنْ عَامِرٍ عَنْ أَبِي بُرْدَةَ بْنِ أَبِي مُوسَى عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ثَلَاثَةٌ يُؤْتَوْنَ أَجْرَهُمْ مَرَّتَيْنِ رَجُلٌ كَانَتْ لَهُ أَمَةٌ فَأَدَّبَهَا فَأَحْسَنَ أَدَبَهَا وَعَلَّمَهَا فَأَحْسَنَ تَعْلِيمَهَا ثُمَّ أَعْتَقَهَا وَتَزَوَّجَهَا وَعَبْدٌ يُؤَدِّي حَقَّ اللَّهِ وَحَقَّ مَوَالِيهِ وَمُؤْمِنُ أَهْلِ الْكِتَابِ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Ibnu Abi Zaidah], ia berkata; telah menceritakan kepadaku [Shalih bin Shalih] dari ['Amir] dari [Abu Burdah bin Abu Musa] dari [Abu Musa], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tiga golongan yang diberi pahalanya dua kali, yaitu seorang laki-laki yang memiliki sahaya wanita kemudian mendidiknya dengan baik dan mengajarinya dengan baik, kemudian memerdekakannya dan menikahinya. Dan seorang sahaya yang menunaikan hak Allah dan hak tuan-tuannya, serta seorang mukmin dari kalangan ahli kitab.\" "},"3201":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي زُبَيْدٍ عَبْثَرُ بْنُ الْقَاسِمِ عَنْ مُطَرِّفٍ عَنْ عَامِرٍ عَنْ أَبِي بُرْدَةَ عَنْ أَبِي مُوسَى قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ أَعْتَقَ جَارِيَتَهُ ثُمَّ تَزَوَّجَهَا فَلَهُ أَجْرَانِ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Zubaid 'Abtsar bin Al Qasim] dari [Mutharrif] dari ['Amir] dari [Abu Burdah] dari [Abu Musa], Ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang memerdekakan seorang sahaya wanita kemudian menikahinya, baginya dua pahala.\" "},"3202":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى وَسُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِأَنَّهُ سَأَلَ عَائِشَةَ عَنْ قَوْلِ اللَّهِ عَزَّ وَجَلَّ{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ يَا ابْنَ أُخْتِي هِيَ الْيَتِيمَةُ تَكُونُ فِي حَجْرِ وَلِيِّهَا فَتُشَارِكُهُ فِي مَالِهِ فَيُعْجِبُهُ مَالُهَا وَجَمَالُهَا فَيُرِيدُ وَلِيُّهَا أَنْ يَتَزَوَّجَهَا بِغَيْرِ أَنْ يُقْسِطَ فِي صَدَاقِهَا فَيُعْطِيَهَا مِثْلَ مَا يُعْطِيهَا غَيْرُهُ فَنُهُوا أَنْ يَنْكِحُوهُنَّ إِلَّا أَنْ يُقْسِطُوا لَهُنَّ وَيَبْلُغُوا بِهِنَّ أَعْلَى سُنَّتِهِنَّ مِنْ الصَّدَاقِ فَأُمِرُوا أَنْ يَنْكِحُوا مَا طَابَ لَهُمْ مِنْ النِّسَاءِ سِوَاهُنَّ قَالَ عُرْوَةُ قَالَتْ عَائِشَةُ ثُمَّ إِنَّ النَّاسَ اسْتَفْتَوْا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدُ فِيهِنَّ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ وَيَسْتَفْتُونَكَ فِي النِّسَاءِ قُلْ اللَّهُ يُفْتِيكُمْ فِيهِنَّ إِلَى قَوْلِهِ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }قَالَتْ عَائِشَةُ وَالَّذِي ذَكَرَ اللَّهُ تَعَالَى أَنَّهُ يُتْلَى فِي الْكِتَابِ الْآيَةُ الْأُولَى الَّتِي فِيهَا{ وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا فِي الْيَتَامَى فَانْكِحُوا مَا طَابَ لَكُمْ مِنْ النِّسَاءِ }قَالَتْ عَائِشَةُ وَقَوْلُ اللَّهِ فِي الْآيَةِ الْأُخْرَى{ وَتَرْغَبُونَ أَنْ تَنْكِحُوهُنَّ }رَغْبَةَ أَحَدِكُمْ عَنْ يَتِيمَتِهِ الَّتِي تَكُونُ فِي حَجْرِهِ حِينَ تَكُونُ قَلِيلَةَ الْمَالِ وَالْجَمَالِ فَنُهُوا أَنْ يَنْكِحُوا مَا رَغِبُوا فِي مَالِهَا مِنْ يَتَامَى النِّسَاءِ إِلَّا بِالْقِسْطِ مِنْ أَجْلِ رَغْبَتِهِمْ عَنْهُنَّ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] dan [Sulaiman bin Daud] dari [Ibnu Wahb], telah mengabarkan kepadaku [Yunus] dari [Ibn Syihab], ia berkata; [Urwah bin Zubair] mengabarkan kepadaku bahwa ia bertanya kepada ['Aisyah] mengenai firman Allah Azza wa Jalla: 'Jika kalian takut tidak berbuat adil kepada anak yatim maka nikahilah apa yang kalian suka dari wanita', ia berkata 'wahai anak saudariku yang dimaksud adalah seorang gadis yatim, yang berada di peliharaan walinya, ia membantu dengan hartanya, lalu walinya takjub dengan harta dan kecantikannya dan ia ingin menikahinya namun tidakdisertai berbuat adil dalam maharnya seperti adat yang berlaku dengan memberinya seperti yang diberikan oleh orang selainnya. Maka mereka dilarang untuk menikahi gadis-gadis itu kecuali jika berbuat adil dan memberi sebaik-baik mahar kepada mereka, sehingga mereka bisa memperoleh setinggi-tinggi mahar seukuran kondisi yang berlaku. Maka mereka diperintahkan untuk menikahi wanita yang baik selain anak-anak perempuan yatim itu, Urwah berkata; lalu 'Aisyah berkata; kemudian orang-orang meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam setelah hal itu mengenai wanita-wanita tersebut, lalu Allah Azza wa Jalla menurunkan: dan mereka meminta fatwa kepadamu tentang wanita-wanita, katakanlah bahwa Allah memberi fatwa kepada kalian sampai firman Allah: dan kalian ingin menikahi mereka. 'Aisyah berkata; maksud firman Allah \"jika kalian takut tidak berbuat adil kepada anak yatim maka nikahilah apa yang kalian suka dari wanita.\" dan firman Allah \"Dan kalian ingin menikahi mereka\" maksudnya, ketika terjadi ketidak senangan seseorang diantara kalian kepada anak yatim yang ia pelihara ketika harta dan kecantikannya sedikit, maka mereka dilarang untuk menikahinya karena dorongan niyat untuk menguasai harta gadis-gadis yatim itu. Kecuali jika bisa menegakkan keadilan meskipun ada ketidak senangan kepada mereka."},"3203":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ مُحَمَّدٍ عَنْ يَزِيدَ بْنِ عَبْدِ اللَّهِ بْنِ الْهَادِ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ قَالَسَأَلْتُ عَائِشَةَ عَنْ ذَلِكَ فَقَالَتْ فَعَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى اثْنَتَيْ عَشْرَةَ أُوقِيَّةً وَنَشٍّ وَذَلِكَ خَمْسُ مِائَةِ دِرْهَمٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Abdul Aziz bin Muhammad] dari [Yazid bin Abdullah bin Al Had] dari [Muhammad bin Ibrahim] dari [Abu Salamah], ia berkata; saya pernah bertanya kepada [Aisyah] mengenai hal tersebut, kemudian ia berkata; Rasulullah shallallahu 'alaihi wasallam telah melakukan dengan dua belas setengah uqiyah lebih separoh, yaitu lima ratus dirham. "},"3204":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ الْمُبَارَكِ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا دَاوُدُ بْنُ قَيْسٍ عَنْ مُوسَى بْنِ يَسَارٍ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ الصَّدَاقُ إِذْ كَانَ فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَشْرَةَ أَوَاقٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Al Mubarak], ia berkata; telah menceritakan kepada kami [Abdur Rahman bin Mahdi], ia berkata; telah menceritakan kepada kami [Daud bin Qais] dari [Musa bin Yasar] dari [Abu Hurairah], ia berkata; mahar disaat Rasulullah shallallahu 'alaihi wasallam berada diantara kami adalah sepuluh uqiyah. "},"3205":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرِ بْنِ إِيَاسِ بْنِ مُقَاتِلِ بْنِ مُشَمْرِخِ بْنِ خَالِدٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ بْنُ إِبْرَاهِيمَ عَنْ أَيُّوبَ وَابْنِ عَوْنٍ وَسَلَمَةَ بْنِ عَلْقَمَةَ وَهِشَامِ بْنِ حَسَّانَ دَخَلَ حَدِيثُ بَعْضِهِمْ فِي بَعْضٍ عَنْ مُحَمَّدِ بْنِ سِيرِينَ قَالَ سَلَمَةُ عَنْ ابْنِ سِيرِينَ نُبِّئْتُ عَنْ أَبِي الْعَجْفَاءِ وَقَالَ الْآخَرُونَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَبِي الْعَجْفَاءِ قَالَقَالَ عُمَرُ بْنُ الْخَطَّابِ أَلَا لَا تَغْلُوا صُدُقَ النِّسَاءِ فَإِنَّهُ لَوْ كَانَ مَكْرُمَةً وَفِي الدُّنْيَا أَوْ تَقْوَى عِنْدَ اللَّهِ عَزَّ وَجَلَّ كَانَ أَوْلَاكُمْ بِهِ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا أَصْدَقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ امْرَأَةً مِنْ نِسَائِهِ وَلَا أُصْدِقَتْ امْرَأَةٌ مِنْ بَنَاتِهِ أَكْثَرَ مِنْ ثِنْتَيْ عَشْرَةَ أُوقِيَّةً وَإِنَّ الرَّجُلَ لَيُغْلِي بِصَدُقَةِ امْرَأَتِهِ حَتَّى يَكُونَ لَهَا عَدَاوَةٌ فِي نَفْسِهِ وَحَتَّى يَقُولَ كُلِّفْتُ لَكُمْ عِلْ��َ الْقِرْبَةِ وَكُنْتُ غُلَامًا عَرَبِيًّا مُوَلَّدًا فَلَمْ أَدْرِ مَا عِلْقُ الْقِرْبَةِ قَالَ وَأُخْرَى يَقُولُونَهَا لِمَنْ قُتِلَ فِي مَغَازِيكُمْ أَوْ مَاتَ قُتِلَ فُلَانٌ شَهِيدًا أَوْ مَاتَ فُلَانٌ شَهِيدًا وَلَعَلَّهُ أَنْ يَكُونَ قَدْ أَوْقَرَ عَجُزَ دَابَّتِهِ أَوْ دَفَّ رَاحِلَتِهِ ذَهَبًا أَوْ وَرِقًا يَطْلُبُ التِّجَارَةَ فَلَا تَقُولُوا ذَاكُمْ وَلَكِنْ قُولُوا كَمَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ قُتِلَ فِي سَبِيلِ اللَّهِ أَوْ مَاتَ فَهُوَ فِي الْجَنَّةِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr bin Iyas bin Muqatil bin Musyamrikh bin Khalid], ia berkata; telah menceritakan kepada kami [Isma'il bin Ibrahim] dari [Ayyub] dan [Ibnu 'Aun] dan [Salamah bin 'Alqamah] dan [Hisyam bin Hassan] hadis sebagian mereka masuk kepada sebagian yang lain, dari [Muhammad bin Sirin], berkata Salamah dari Ibnu Sirin; saya telah diberitahu dari [Abu Al 'Ajfa`], dan orang lain mengatakan dari Muhammad bin Sirin dari Abu Al 'Ajfa`, ia berkata; [Umar bin Al Khathab] berkata; \"Jangan kalian memahalkan mahar para wanita, seandainya hal tersebut adalah kemuliaan di dunia atau ketakwaan di sisi Allah 'azza wajalla, orang yang paling berhak adalah Nabi shallallahu 'alaihi wasallam. Tidaklah Rasulullah shallallahu 'alaihi wasallam memberikan mahar kepada seorang isteri-pun dan tidak seorangpun anak wanitanya yang diberi mahar, lebih dari dua belas uqiyah. Dan sesungguhnya seseorang memahalkan mahar isterinya hingga menjadi musuh dalam dirinya, dan hingga ia berkata 'Saya telah dibebani karena kalian untuk mengguyurkan geriba.\"---- Abu Al 'Ajfa` berkata; Saya dahulu adalah anak muda Arab yang baru saja lahir hingga saya tidak mengetahui maksud mengguyurkan geriba----. Abu Al 'Ajfa` berkata; Hal lain yang sering mereka ucapkan terhadap orang yang terbunuh dalam peperangan kalian, atau orang yang mati sebagai Syahid, atau terbunuh seabagai syahid, mereka memberi komentar 'Barangkali ia membebani terlalu berat belakang kendaraannya atau malah meletakkan pelananya dengan emas atau perak yang ingin ia perdagangkan'. Saya ingatkan kalian, janganlah kalian mengucapkan demikian, akan tetapi ucapkanlah sebagaimana yang diucapkan Nabi shallallahu 'alaihi wasallam: \"Barang siapa yang terbunuh di jalan Allah atau meninggal maka ia berada di Surga.\" "},"3206":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ مُحَمَّدٍ الدُّورِيُّ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحَسَنِ بْنِ شَقِيقٍ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ أُمِّ حَبِيبَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَزَوَّجَهَا وَهِيَ بِأَرْضِ الْحَبَشَةِ زَوَّجَهَا النَّجَاشِيُّ وَأَمْهَرَهَا أَرْبَعَةَ آلَافٍ وَجَهَّزَهَا مِنْ عِنْدِهِ وَبَعَثَ بِهَا مَعَ شُرَحْبِيلَ ابْنِ حَسَنَةَ وَلَمْ يَبْعَثْ إِلَيْهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ وَكَانَ مَهْرُ نِسَائِهِ أَرْبَعَ مِائَةِ دِرْهَمٍ","id":"Telah mengabarkan kepada kami [Al Abbas bin Muhammad Ad Duri], ia berkata; telah menceritakan kepada kami [Ali bin Al Hasan bin Asy Syaqiq], ia berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] dari [Ma'mar] dari [Az Zuhri] dari ['Urwah bin Az Zubair] dari [Ummu Habibah] bahwa Rasulullah shallallahu 'alaihi wasallam menikahinya saat berada di negeri Habasyah. Ia dinikahkan oleh An Najasyi, ia memberinya mahar empat ribu, dan memberi perbekalannya dari dirinya sendiri, dan mengirimnya bersama dengan Syurahbil bin Hasanah. Rasulullah shallallahu 'alaihi wasallam tidak mengirimkan kepadanya sesuatupun, dan mahar para isterinya adalah empat ratus dirham. "},"3207":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لِمُحَمَّدٍ عَنْ ابْنِ الْقَاسِمِ عَنْ مَالِكٍ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسِ بْنِ مَالِكٍأَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ جَاءَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَبِهِ أَثَرُ الصُّفْرَةِ فَسَأَلَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ أَنَّهُ تَزَوَّجَ امْرَأَةً مِنْ الْأَنْصَارِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَمْ سُقْتَ إِلَيْهَا قَالَ زِنَةَ نَوَاةٍ مِنْ ذَهَبٍ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, lafazhnya adalah lafazh Muhammad, dari [Ibnu Al Qasim] dari [Malik] dari [Humaid Ath Thawil] dari [Anas bin Malik] bahwa, Abdur Rahman bin 'Auf menemui Nabi shallallahu 'alaihi wasallam dan terlihat padanya bekas warna kuning. Rasulullah shallallahu 'alaihi wasallam bertanya kepadanya, ia pun mengabarkan beliau bahwa ia telah menikahi seorang wanita Anshar. Rasulullah shallallahu 'alaihi wasallam bertanya: \"Berapa engkau memberi mahar untuknya?\" Ia berkata; emas seberat biji kurma. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Rayakan walaupun hanya dengan seekor kambing.\" "},"3208":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ قَالَ سَمِعْتُ أَنَسًا يَقُولُ قَالَ عَبْدُ الرَّحْمَنِ بْنُ عَوْفٍرَآنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلَيَّ بَشَاشَةُ الْعُرْسِ فَقُلْتُ تَزَوَّجْتُ امْرَأَةً مِنْ الْأَنْصَارِ قَالَ كَمْ أَصْدَقْتَهَا قَالَ زِنَةَ نَوَاةٍ مِنْ ذَهَبٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [An Nadhr bin Syumail], ia berkata; telah menceritakan kepada kami [Syu'bah], ia berkata; telah menceritakan kepada kami [Abdul Aziz bin Shuhaib], ia berkata; saya mendengar [Anas] berkata; berkata [Abdur Rahman bin 'Auf]; Rasulullah shallallahu 'alaihi wasallam melihatku dan padaku terdapat keceriaan pengantin. Kemudian saya katakan; saya telah menikahi dengan seorang wanita Anshar. Beliau bersabda: \"Berapa engkau memberinya mahar?\" Ia berkata; emas seberat biji kurma."},"3209":{"ar":"أَخْبَرَنَا هِلَالُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ ابْنُ جُرَيْجٍ حَدَّثَنِي عَمْرُو بْنُ شُعَيْبٍ ح و أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ تَمِيمٍ قَالَ سَمِعْتُ حَجَّاجًا يَقُولُ قَالَ ابْنُ جُرَيْجٍ عَنْ عَمْرِو بْنِ شُعَيْبٍ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَمْرٍوأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ أَيُّمَا امْرَأَةٍ نُكِحَتْ عَلَى صَدَاقٍ أَوْ حِبَاءٍ أَوْ عِدَةٍ قَبْلَ عِصْمَةِ النِّكَاحِ فَهُوَ لَهَا وَمَا كَانَ بَعْدَ عِصْمَةِ النِّكَاحِ فَهُوَ لِمَنْ أُعْطَاهُ وَأَحَقُّ مَا أُكْرِمَ عَلَيْهِ الرَّجُلُ ابْنَتُهُ أَوْ أُخْتُهُاللَّفْظُ لِعَبْدِ اللَّهِ","id":"Telah mengabarkan kepada kami [Hilal bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Hajjaj], berkata [Ibnu Juraij]; telah menceritakan kepada kami ['Amr bin Syu'aib]. -Dan dari jalur periwayatan yang lain- Telah mengabarkan kepadaku [Abdullah bin Muhammad bin Tamim], ia berkata; saya mendengar [Hajjaj] mengatakan; berkata [Ibnu Juraij] dari ['Amr bin Syu'aib] dari [ayahnya] dari [Abdullah bin 'Amr] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Siapapun wanita yang dinikahi dengan mahar, pemberian atau janji sebelum akad nikah, itu adalah untuknya, dan yang diberikan setelah akad nikah maka untuk orang yang diberi. Dan yang paling berhak terhadap penghormatan yang diberikan oleh seseorang adalah anak wanitanya atau saudara wanitanya.\" Lafazh hadis adalah lafazh Abdullah. "},"3210":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا أَبُو سَعِيدٍ عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ عَنْ زَائِدَةَ بْنِ قُدَامَةَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ وَالْأَسْوَدِ قَالَاأُتِيَ عَبْدُ اللَّهِ فِي رَجُلٍ تَزَوَّجَ امْرَأَةً وَلَمْ يَفْرِضْ لَهَا فَتُوُفِّيَ قَبْلَ أَنْ يَدْخُلَ بِهَا فَقَالَ عَبْدُ اللَّهِ سَلُوا هَلْ تَجِدُونَ فِيهَا أَثَرًا قَالُوا يَا أَبَا عَبْدِ الرَّحْمَنِ مَا نَجِدُ فِيهَا يَعْنِي أَثَرًا قَالَ أَقُولُ بِرَأْيِي فَإِنْ كَانَ صَوَابًا فَمِنْ اللَّهِ لَهَا كَمَهْرِ نِسَائِهَا لَا وَكْسَ وَلَا شَطَطَ وَلَهَا الْمِيرَاثُ وَعَلَيْهَا الْعِدَّةُ فَقَامَ رَجُلٌ مَنْ أَشْجَعَ فَقَالَ فِي مِثْلِ هَذَا قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِينَا فِي امْرَأَةٍ يُقَالُ لَهَا بَرْوَعُ بِنْتُ وَاشِقٍ تَزَوَّجَتْ رَجُلًا فَمَاتَ قَبْلَ أَنْ يَدْخُلَ بِهَا فَقَضَى لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِمِثْلِ صَدَاقِ نِسَائِهَا وَلَهَا الْمِيرَاثُ وَعَلَيْهَا الْعِدَّةُ فَرَفَعَ عَبْدُ اللَّهِ يَدَيْهِ وَكَبَّرَقَالَ أَبُو عَبْد الرَّحْمَنِ لَا أَعْلَمُ أَحَدًا قَالَ فِي هَذَا الْحَدِيثِ الْأَسْوَدُ غَيْرَ زَائِدَةَ","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad bin Abdur Rahman], ia berkata; telah menceritakan kepada kami [Abu Sa'id Abdur Rahman bin Abdullah] dari [Zaidah bin Qudamah] dari [Manshur] dari [Ibraihim] dari ['Alqomah] dan [Al Aswad] mereka berdua berkata; Abdullah dihadapkan pada permasalahan mengenai seseorang yang menikahi wanita namun ia belum memberinya mahar, lalu ia mati sebelum menggaulinya, [Abdullah] berkata 'tanyakanlah apakah kalian mendapati suatu bekas padanya', mereka menjawab; 'kami tidak mendapati suatu bekas padanya.' Ia berkata; aku akan mengatakan dengan pendapatku jika ia benar maka itu dari Allah, yaitu ia mendapatkan mahar seperti mahar wanita lainnya, tidak ada pengurangan maupun kezhaliman, ia mendapatkan warisan dan menunggu masa 'iddah. Lalu [seseorang] dari Suku Asyja' berdiri dan berkata; seperti inilah yang diputuskan Rasulullah shallallahu 'alaihi wasallam kepada kami terhadap seorang wanita yang bernama Barwa' binti Wasyiq yang menikah dengan seorang pemuda. Pemuda itu mati sebelum menggaulinya, dan Rasulullah shallallahu 'alaihi wasallam memutuskan agar ia mendapatkan mahar seperti wanita lainnya, ia mendapatkan warisan dan menunggu masa 'iddah, lalu Abdullah mengangkat tangannya dan bertakbir. Abu Abdurrahman berkata; saya tidak mengetahui seseorang yang mempermasalahkan hadis ini, Al Aswad bukanlah Zaidah. "},"3211":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِأَنَّهُ أُتِيَ فِي امْرَأَةٍ تَزَوَّجَهَا رَجُلٌ فَمَاتَ عَنْهَا وَلَمْ يَفْرِضْ لَهَا صَدَاقًا وَلَمْ يَدْخُلْ بِهَا فَاخْتَلَفُوا إِلَيْهِ قَرِيبًا مِنْ شَهْرٍ لَا يُفْتِيهِمْ ثُمَّ قَالَ أَرَى لَهَا صَدَاقَ نِسَائِهَا لَا وَكْسَ وَلَا شَطَطَ وَلَهَا الْمِيرَاثُ وَعَلَيْهَا الْعِدَّةُ فَشَهِدَ مَعْقِلُ بْنُ سِنَانٍ الْأَشْجَعِيُّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى فِي بَرْوَعَ بِنْتِ وَاشِقٍ بِمِثْلِ مَا قَضَيْتَ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman], ia berkata; telah menceritakan kepada kami [Yazid], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] bahwa ia dihadapkan pada permasalahan mengenai seorang wanita yang dinikahi seorang laki-laki, laki-laki tersebut meninggal, belum menentukan mahar dan belum menggaulinya. Lalu mereka mendatangi Abdullah sekitar satu bulan, ia tidak memberikan fatwa kepada mereka. Kemudian ia berkata; saya berpendapat bahwa ia mendapatkan mahar wanita semisalnya, tidak ada pengurangan dan kezhaliman, dan ia mendapatkan warisan, serta menunggu masa 'iddah. Kemudian [Ma'qil bin Sinan Al Asyja'i] memberi persaksian; Rasulullah shallallahu 'alaihi wasallam memberi keputusan terhadap Barwa' binti Wasyiq seperti yang engkau putuskan."},"3212":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَبْدِ اللَّهِفِي رَجُلٍ تَزَوَّجَ امْرَأَةً فَمَاتَ وَلَمْ يَدْخُلْ بِهَا وَلَمْ يَفْرِضْ لَهَا قَالَ لَهَا الصَّدَاقُ وَعَلَيْهَا الْعِدَّةُ وَلَهَا الْمِيرَاثُ فَقَالَ مَعْقِلُ بْنُ سِنَانٍ فَقَدْ سَمِعْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَضَى بِهِ فِي بَرْوَعَ بِنْتِ وَاشِقٍأَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُو��ٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِ مِثْلَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Abdur Rahman], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Firas] dari [Asy Sya'bi] dari [Masruq] dari [Abdullah] mengenai seorang laki-laki yang menikahi seorang wanita, kemudian ia meninggal dan belum menggaulinya serta belum menentukan mahar baginya. Abdullah berkata; ia mendapatkan mahar, wajib menunggu masa 'iddah, serta mendapatkan warisan. Kemudian [Ma'qil bin Sinan] berkata; sungguh saya mendengar Nabi shallallahu 'alaihi wasallam memberikan keputusan mengenai Barwa' binti Wasyiq dengan hal tersebut. Telah mengabarkan kepada kami [Ishaq bin Manshur], ia berkata; telah menceritakan kepada kami [Abdur Rahman] dari [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Abdullah] seperti itu. "},"3213":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ دَاوُدَ بْنِ أَبِي هِنْدٍ عَنْ الشَّعْبِيِّ عَنْ عَلْقَمَةَ عَنْ عَبْدِ اللَّهِأَنَّهُ أَتَاهُ قَوْمٌ فَقَالُوا إِنَّ رَجُلًا مِنَّا تَزَوَّجَ امْرَأَةً وَلَمْ يَفْرِضْ لَهَا صَدَاقًا وَلَمْ يَجْمَعْهَا إِلَيْهِ حَتَّى مَاتَ فَقَالَ عَبْدُ اللَّهِ مَا سُئِلْتُ مُنْذُ فَارَقْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَشَدَّ عَلَيَّ مِنْ هَذِهِ فَأْتُوا غَيْرِي فَاخْتَلَفُوا إِلَيْهِ فِيهَا شَهْرًا ثُمَّ قَالُوا لَهُ فِي آخِرِ ذَلِكَ مَنْ نَسْأَلُ إِنْ لَمْ نَسْأَلْكَ وَأَنْتَ مِنْ جِلَّةِ أَصْحَابِ مُحَمَّدٍ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِهَذَا الْبَلَدِ وَلَا نَجِدُ غَيْرَكَ قَالَ سَأَقُولُ فِيهَا بِجَهْدِ رَأْيِي فَإِنْ كَانَ صَوَابًا فَمِنْ اللَّهِ وَحْدَهُ لَا شَرِيكَ لَهُ وَإِنْ كَانَ خَطَأً فَمِنِّي وَمِنْ الشَّيْطَانِ وَاللَّهُ وَرَسُولُهُ مِنْهُ بُرَآءُ أُرَى أَنْ أَجْعَلَ لَهَا صَدَاقَ نِسَائِهَا لَا وَكْسَ وَلَا شَطَطَ وَلَهَا الْمِيرَاثُ وَعَلَيْهَا الْعِدَّةُ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا قَالَ وَذَلِكَ بِسَمْعِ أُنَاسٍ مَنْ أَشْجَعَ فَقَامُوا فَقَالُوا نَشْهَدُ أَنَّكَ قَضَيْتَ بِمَا قَضَى بِهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي امْرَأَةٍ مِنَّا يُقَالُ لَهَا بَرْوَعُ بِنْتُ وَاشِقٍ قَالَ فَمَا رُئِيَ عَبْدُ اللَّهِ فَرِحَ فَرْحَةً يَوْمَئِذٍ إِلَّا بِإِسْلَامِهِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Ali bin Mushir] dari [Daud bin Abi Hindun] dari [Asy Sya'bi] dari ['Alqamah] dari [Abdullah], telah datang kepadanya beberapa orang, mereka berkata; seorang laki-laki dari kami menikahi seorang wanita dan belum menentukan mahar, belum mengumpulinya hingga laki-laki tersebut meninggal. Kemudian Abdullah berkata; sejak berpisah dengan Rasulullah shallallahu 'alaihi wasallam saya belum pernah ditanya yang lebih berat bagiku daripada permasalahan ini. Begini saja, datangilah selainku. Mereka tetap mendatangi Abdullah selama sebulan namun belum juga mendapat titik temu. Akhirnya mereka katakan; siapakah yang kami tanya jika kami tidak bertanya kepadamu, sedangkan engkau termasuk diantara sahabat Muhammad shallallahu 'alaihi wasallam di negeri ini, dan kami tidak mendapatkan selainmu. Abdullah berkata; saya akan berkata mengenainya dengan pendapatku, apabila benar maka hanya dari Allah tidak ada sekutu baginya dan apabila salah maka itu berasal dariku dan dari setan, Allah dan rasulNya berlepas diri darinya. Saya berpendapat bahwa ia diberi mahar wanita seperti wanita lainnnya, tidak ada pengurangan, serta kezhaliman dan ia mendapatkan warisan serta menunggu masa 'iddah empat bulan sepuluh hari. 'Alqamah berkata; dan hal tersebut di dengar [orang-orang] dari Asyja', kemudian mereka berdiri dan berkata; kami bersaksi bahwa engkau memberi keputusan dengan apa yang diputuskan Rasulullah shallallahu 'alaihi wasallam terhadap seorang wanita dari kami yang biasa dikenal dengan Barwa' binti Wasyiq. 'Alqamah berkata; tidaklah Abdullah terlihat bergembira seperti kegembiraan pada saat itu kecuali karena keIslamannya. "},"3214":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ عَنْ أَبِي حَازِمٍ عَنْ سَهْلِ بْنِ سَعْدٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَتْهُ امْرَأَةٌ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي قَدْ وَهَبْتُ نَفْسِي لَكَ فَقَامَتْ قِيَامًا طَوِيلًا فَقَامَ رَجُلٌ فَقَالَ زَوِّجْنِيهَا إِنْ لَمْ يَكُنْ لَكَ بِهَا حَاجَةٌ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ عِنْدَكَ شَيْءٌ قَالَ مَا أَجِدُ شَيْئًا قَالَ الْتَمِسْ وَلَوْ خَاتَمًا مِنْ حَدِيدٍ فَالْتَمَسَ فَلَمْ يَجِدْ شَيْئًا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ مَعَكَ مِنْ الْقُرْآنِ شَيْءٌ قَالَ نَعَمْ سُورَةُ كَذَا وَسُورَةُ كَذَا لِسُوَرٍ سَمَّاهَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ زَوَّجْتُكَهَا عَلَى مَا مَعَكَ مِنْ الْقُرْآنِ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah], ia berkata; telah menceritakan kepada kami [Ma'n], ia berkata; telah menceritakan kepada kami [Malik] dari [Abu Hazim] dari [Sahl bin Sa'd] bahwa Rasulullah shallallahu 'alaihi wasallam didatangi seorang wanita dan berkata; wahai Rasulullah, saya menghibahkan diriku kepadamu. Kemudian wanita tersebut berdiri lama. Setelah waktu berselang seorang laki-laki berdiri dan berkata; nikahkan saya dengannya apabila anda tidak punya selera terhadapnya. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apakah engkau memiliki sesuatu?\" Ia menjawab; saya tidak mendapati sesuatu. Beliau bersabda: \"Carilah walaupun satu cincin besi.\" Kemudian orang tersebut mencari dan tidak mendapatkan sesuatu. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Apakah engkau memiliki hapalan Al Qur'an?\" Ia berkata; ya, surat ini dan surat ini. Ia menyebutkan beberapa surat. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Saya menikahkanmu dengannya dengan hapalan Al Qur'an yang engkau miliki.\""},"3215":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بِشْرٍ عَنْ خَالِدِ بْنِ عُرْفُطَةَ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّجُلِ يَأْتِي جَارِيَةَ امْرَأَتِهِ قَالَ إِنْ كَانَتْ أَحَلَّتْهَا لَهُ جَلَدْتُهُ مِائَةً وَإِنْ لَمْ تَكُنْ أَحَلَّتْهَا لَهُ رَجَمْتُهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Muhammad], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Bisyr] dari [Khalid bin 'Urfuthah] dari [Habib bin Salim] dari [An Nu'man bin Basyir] dari Nabi shallallahu 'alaihi wasallam mengenai seorang laki-laki yang menggauli sahaya isterinya, beliau bersabda: \"Apabila ia menghalalkan untuknya, saya mencambuknya seratus kali, dan apabila ia tidak menghalalkan untuknya, saya merajamnya.\""},"3216":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا أَبَانُ عَنْ قَتَادَةَ عَنْ خَالِدِ بْنِ عُرْفُطَةَ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ رَجُلًا يُقَالُ لَهُ عَبْدُ الرَّحْمَنِ بْنُ حُنَيْنٍ وَيُنْبَزُ قُرْقُورًا أَنَّهُ وَقَعَ بِجَارِيَةِ امْرَأَتِهِ فَرُفِعَ إِلَى النُّعْمَانِ بْنِ بَشِيرٍ فَقَالَ لَأَقْضِيَنَّ فِيهَا بِقَضِيَّةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنْ كَانَتْ أَحَلَّتْهَا لَكَ جَلَدْتُكَ وَإِنْ لَمْ تَكُنْ أَحَلَّتْهَا لَكَ رَجَمْتُكَ بِالْحِجَارَةِ فَكَانَتْ أَحَلَّتْهَا لَهُ فَجُلِدَ مِائَةًقَالَ قَتَادَةُ فَكَتَبْتُ إِلَى حَبِيبِ بْنِ سَالِمٍ فَكَتَبَ إِلَيَّ بِهَذَا","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar], ia berkata; telah menceritakan kepada kami [Habban], ia berkata; telah menceritakan kepada kami [Aban] dari [Qatadah] dari [Khalid bin 'Urfuthah] dari [Habib bin Salim] dari [An Nu'man bin Basyir] bahwa seorang laki-laki yang biasa dipanggil Abdur Rahman bin Hunain dan Yunbaz Qurquran menggauli sahaya isterinya, kemudian kasus tersebut diadukan kepada An Nu'man bin Basyir. Ia berkata; sungguh saya akan memutuskan dengan keputusan Rasulullah shallallahu 'alaihi wasallam, yaitu apabila ia menghalalkan untukmu, saya mencambukmu dan jika ia tidak menghalalkan untukmu, saya merajammu dengan bebatuan. Kemudian isterinya menghalalkan untuknya, lalu ia dicambuk seratus kali. Qatadah berkata; saya pernah menulis surat kepada Habib bin Salim, kemudian ia menulis surat kepadaku dengan hadis ini. "},"3217":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا عَارِمٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ حَبِيبِ بْنِ سَالِمٍ عَنْ النُّعْمَانِ بْنِ بَشِيرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِي رَجُلٍ وَقَعَ بِجَارِيَةِ امْرَأَتِهِ إِنْ كَانَتْ أَحَلَّتْهَا لَهُ فَأَجْلِدْهُ مِائَةً وَإِنْ لَمْ تَكُنْ أَحَلَّتْهَا لَهُ فَأَرْجُمْهُ","id":"Telah mengabarkan kepada kami [Abu Daud], ia berkata; telah menceritakan kepada kami ['Arim], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Sa'id bin Abi 'Arubah] dari [Qatadah] dari [Habib bin Salim] dari [An Nu'man bin Basyir] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda mengenai seorang laki-laki yang menggauli sahaya isterinya: \"Apabila ia menghalalkan untuknya, saya mencambuknya seratus kali, dan apabila ia tidak menghalalkan untuknya, saya merajamnya.\""},"3218":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ قَبِيصَةَ بْنِ حُرَيْثٍ عَنْ سَلَمَةَ بْنِ الْمُحَبَّقِ قَالَقَضَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي رَجُلٍ وَطِئَ جَارِيَةَ امْرَأَتِهِ إِنْ كَانَ اسْتَكْرَهَهَا فَهِيَ حُرَّةٌ وَعَلَيْهِ لِسَيِّدَتِهَا مِثْلُهَا وَإِنْ كَانَتْ طَاوَعَتْهُ فَهِيَ لَهُ وَعَلَيْهِ لِسَيِّدَتِهَا مِثْلُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'], ia berkata; telah menceritakan kepada kami [Abdur Razzaq], ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Qatadah] dari [Al Hasan] dari [Qabishah bin Juraits] dari [Salamah bin Al Muhabbaq], ia berkata; Nabi shallallahu 'alaihi wasallam memberi keputusan mengenai seorang laki-laki yang menggauli sahaya isterinya: \"Apabila ia memaksanya, sahaya tersebut merdeka dan ia wajib mengganti untuk tuannya dengan yang seperti sahaya tersebut, dan apabila sahaya tersebut menyerahkan diri dengan suka rela, ia menjadi miliknya dan ia wajib mengganti untuk tuannya dengan yang seperti sahaya tersebut.\" "},"3219":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ قَتَادَةَ عَنْ الْحَسَنِ عَنْ سَلَمَةَ بْنِ الْمُحَبَّقِأَنَّ رَجُلًا غَشِيَ جَارِيَةً لِامْرَأَتِهِ فَرُفِعَ ذَلِكَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنْ كَانَ اسْتَكْرَهَهَا فَهِيَ حُرَّةٌ مِنْ مَالِهِ وَعَلَيْهِ الشَّرْوَى لِسَيِّدَتِهَا وَإِنْ كَانَتْ طَاوَعَتْهُ فَهِيَ لِسَيِّدَتِهَا وَمِثْلُهَا مِنْ مَالِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Bazi'], ia berkata; telah menceritakan kepada kami [Yazid], ia berkata; telah menceritakan kepada kami [Sa'id] dari [Qatadah] dari [Al Hasan] dari [Salamah bin Al Muhabbaq] bahwa seorang laki-laki menggauli sahaya isterinya, kemudian hal tersebut diadukan kepada Rasulullah shallallahu 'alaihi wasallam, dan beliau bersabda: \"Apabila ia memaksanya maka sahaya tersebut merdeka dengan biaya dari harta orang tersebut, dan ia wajib mengganti untuk tuannya dengan yang semisalnya. Dan jika sahaya tersebut menyerahkan diri dengan suka rela, maka sahaya tersebut menjadi miliknya dan ia wajib mengganti untuk tuannya dengan yang semisalnya.\""},"3220":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ قَالَ حَدَّثَنِي الزُّهْرِيُّ عَنْ الْحَسَنِ وَعَبْدِ اللَّهِ ابْنَيْ مُحَمَّدٍ عَنْ أَبِيهِمَاأَنَّ عَلِيًّا بَلَغَهُ أَنَّ رَجُلًا لَا يَرَى بِالْمُتْعَةِ بَأْسًا فَقَالَ إِنَّكَ تَائِهٌ إِنَّهُ نَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَن��هَا وَعَنْ لُحُومِ الْحُمُرِ الْأَهْلِيَّةِ يَوْمَ خَيْبَرَ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah bin Umar], ia berkata; telah menceritakan kepadaku [Az Zuhri] dari [Al Hasan] dan [Abdullah] keduanya anak Muhammad, dari [ayah mereka], Ali mendapat informasi bahwa terdapat seorang laki-laki yang berpendapat nikah mut'ah tidak dilarang. Kemudian [Ali] berkata; Engkau sesat, Rasulullah shallallahu 'alaihi wasallam telah melarang nikah mut'ah dan daging keledai jinak pada saat terjadi perang Khaibar. "},"3221":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عَبْدِ اللَّهِ وَالْحَسَنِ ابْنَيْ مُحَمَّدِ بْنِ عَلِيٍّ عَنْ أَبِيهِمَا عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَهَى عَنْ مُتْعَةِ النِّسَاءِ يَوْمَ خَيْبَرَ وَعَنْ لُحُومِ الْحُمُرِ الْإِنْسِيَّةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] serta [Al Harits bin Miskin] dengan membaca riwayat dan saya mendengar, lafazhnya adalah lafazh Al Harits, ia berkata; telah memberitakan kepada kami [Ibnu Al Qasim] dari [Malik] dari [Ibnu Syihab] dari [Abdullah] dan [Al Hasan] keduanya anak Muhammad bin Ali, dari [ayah mereka] dari [Ali bin Abi Thalib] bahwa Rasulullah shallallahu 'alaihi wasallam melarang untuk menikahi wanita dengan cara mut'ah pada saat perang Khaibar, dan daging keledai jinak."},"3222":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ بَشَّارٍ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالُوا أَنْبَأَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ يَقُولُ أَخْبَرَنِي مَالِكُ بْنُ أَنَسٍ أَنَّ ابْنَ شِهَابٍ أَخْبَرَهُ أَنَّ عَبْدَ اللَّهِ وَالْحَسَنَ ابْنَيْ مُحَمَّدِ بْنِ عَلِيٍّ أَخْبَرَاهُ أَنَّ أَبَاهُمَا مُحَمَّدَ بْنَ عَلِيٍّ أَخْبَرَهُمَا أَنَّ عَلِيَّ بْنَ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَنَهَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ خَيْبَرَ عَنْ مُتْعَةِ النِّسَاءِ قَالَ ابْنُ الْمُثَنَّى يَوْمَ حُنَيْنٍوَقَالَ هَكَذَا حَدَّثَنَا عَبْدُ الْوَهَّابِ مِنْ كِتَابِهِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali] dan [Muhammad bin Basysyar] serta [Muhammad bin Al Mutsanna], mereka berkata; telah memberitakan kepada kami [Abdul Wahhab], ia berkata; saya pernah mendengar [Yahya bin Sa'id] berkata; telah memberitakan kepadaku [Malik bin Anas] bahwa [Ibnu Syihab] telah mengabarkan kepadanya bahwa [Abdullah] dan [Al Hasan] keduanya anak Muhammad bin Ali, mereka mengabarkan kepadanya bahwa ayah mereka yaitu [Muhammad bin Ali] telah mengabarkan kepada mereka bahwa [Ali bin Abi Thalib] radliallahu 'anhu berkata; Rasulullah shallallahu 'alaihi wasallam melarang untuk menikahi wanita dengan cara mut'ah pada saat perang Khaibar. Ibnu Al Mutsanna berkata; pada saat perang Hunain, dan ia berkata; demikian Abdul Wahhab telah menceritakan kepada kami dari tulisannya. "},"3223":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ الرَّبِيعِ بْنِ سَبْرَةَ الْجُهَنِيِّ عَنْ أَبِيهِ قَالَأَذِنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِالْمُتْعَةِ فَانْطَلَقْتُ أَنَا وَرَجُلٌ إِلَى امْرَأَةٍ مِنْ بَنِي عَامِرٍ فَعَرَضْنَا عَلَيْهَا أَنْفُسَنَا فَقَالَتْ مَا تُعْطِينِي فَقُلْتُ رِدَائِي وَقَالَ صَاحِبِي رِدَائِي وَكَانَ رِدَاءُ صَاحِبِي أَجْوَدَ مِنْ رِدَائِي وَكُنْتُ أَشَبَّ مِنْهُ فَإِذَا نَظَرَتْ إِلَى رِدَاءِ صَاحِبِي أَعْجَبَهَا وَإِذَا نَظَرَتْ إِلَيَّ أَعْجَبْتُهَا ثُمَّ قَالَتْ أَنْتَ وَرِدَاؤُكَ يَكْفِينِي فَمَكَثْتُ مَعَهَا ثَلَاثًا ثُمَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ كَانَ عِنْدَهُ مِنْ هَذِهِ النِّسَاءِ اللَّاتِي يَتَمَتَّعُ فَلْيُخَلِّ سَبِيلَهَا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ar Rabi' bin Sabrah Al Juhani] dari [ayahnya], ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah mengizinkan nikah mut'ah, kemudian saya pergi bersama seorang laki-laki menuju seorang wanita dari Bani 'Amir. Kemudian kami menawarkan diri kami, wanita tersebut berkata; apa yang akan engkau berikan kepadaku? saya berujar; selendangku. Sedangkan sahabatku berkata; selendangku aja. Kebetulan selendang sahabatku lebih bagus daripada selendangku, dan saya lebih muda darinya. Kemudian disaat wanita tersebut melihat kepada selendang sahabatku ia tertarik kepadanya, dan di saat ia melihat kepadaku maka ia kagum kepadaku. Kemudian wanita tersebut berkata; engkau dan selendangmu cukup bagiku. Maka saya tinggal bersamanya selama tiga hari, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Barang siapa yang memiliki wanita yang ia mut'ah maka hendaknya ia melepaskannya.\""},"3224":{"ar":"أَخْبَرَنَا مُجَاهِدُ بْنُ مُوسَى قَالَ حَدَّثَنَا هُشَيْمٌ عَنْ أَبِي بَلْجٍ عَنْ مُحَمَّدِ بْنِ حَاطِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَصْلُ مَا بَيْنَ الْحَلَالِ وَالْحَرَامِ الدُّفُّ وَالصَّوْتُ فِي النِّكَاحِ","id":"Telah mengabarkan kepada kami [Mujahid bin Musa], ia berkata; telah menceritakan kepada kami [Husyaim] dari [Abu Balj] dari [Muhammad bin Hathib], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Pemisah antara halal dan haram adalah rebana dan suara dalam pernikahan.\""},"3225":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ عَنْ شُعْبَةَ عَنْ أَبِي بَلْجٍ قَالَ سَمِعْتُ مُحَمَّدَ بْنَ حَاطِبٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ فَصْلَ مَا بَيْنَ الْحَلَالِ وَالْحَرَامِ الصَّوْتُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al A'la], ia berkata; telah menceritakan kepada kami [Khalid] dari [Syu'bah] dari [Abu Balj], ia berkata; saya pernah mendengar [Muhammad bin Hathib], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pemisah antara halal dan haram adalah suara.\""},"3226":{"ar":"حَدَّثَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَا حَدَّثَنَا خَالِدٌ عَنْ أَشْعَثَ عَنْ الْحَسَنِ قَالَتَزَوَّجَ عَقِيلُ بْنُ أَبِي طَالِبٍ امْرَأَةً مِنْ بَنِي جَثْمٍ فَقِيلَ لَهُ بِالرِّفَاءِ وَالْبَنِينَ قَالَ قُولُوا كَمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَارَكَ اللَّهُ فِيكُمْ وَبَارَكَ لَكُمْ","id":"Telah mengabarkan kepada kami ['Amr bin Ali] dan [Muhammad bin Abdul A'la] mereka berkata; telah menceritakan kepada kami [Khalid] dari [Asy'ats] dari [Al Hasan], ia berkata; ['Uqail bin Abi Thalib] menikahi seorang wanita dari Bani Jatsm. Kemudian ia diberi ucapan selamat; semoga senantiasa berkumpul dan banyak anak. Maka ia mengatakan; katakanlah sebagaimana yang dikatakan Rasulullah shallallahu 'alaihi wasallam: BAARAKALLAAHU FIIKUM WA BAARAKA LAKUM (semoga Allah memberi berkah pada kalian dan melipatgandakan keberkahan bagi kalian)."},"3227":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ثَابِتٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَأَى عَلَى عَبْدِ الرَّحْمَنِ أَثَرَ صُفْرَةٍ فَقَالَ مَا هَذَا قَالَ تَزَوَّجْتُ امْرَأَةً عَلَى وَزْنِ نَوَاةٍ مِنْ ذَهَبٍ فَقَالَ بَارَكَ اللَّهُ لَكَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Tsabit] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam melihat pada diri Abdur Rahman terdapat bekas warna kuning. Kemudian beliau bersabda: \"Apakah ini?\" Ia berkata; saya telah menikahi seorang wanita dengan mahar emas seberat biji kurma. Kemudian beliau mengucapkan: \"Semoga Allah memberikan berkah untukmu, rayakan walaupun hanya dengan seekor kambing.\""},"3228":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ نَافِعٍ قَالَ حَدَّثَنَا بَهْزُ بْنُ أَسَدٍ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍأَنَّ عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ جَاءَ وَعَلَيْهِ رَدْعٌ مِنْ زَعْفَرَانٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَهْيَمْ قَالَ تَزَوَّجْتُ امْرَأَةً قَالَ وَمَا أَصْدَقْتَ قَالَ وَزْنَ نَوَاةٍ مِنْ ذَهَبٍ قَالَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Nafi'], ia berkata; telah menceritakan kepada kami [Bahz bin Asad], ia berkata; telah menceritakan kepada kami [Hammad], ia berkata; telah menceritakan kepada kami [Tsabit] dari [Anas] bahwa Abdur Rahman bin 'Auf datang padanya terdapat bekas kunyit. Kemudian Rasulullah shallallahu 'alaihi wasallam bertanya: \"Apa ini?\" Ia berkata; saya telah menikahi seorang wanita. Beliau bertanya: \"Mahar apakah yang engkau berikan kepadanya?\" Ia berkata; emas seberat biji kurma. Beliau bersabda: \"Rayakan walaupun hanya dengan seekor kambing.\""},"3229":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ يَحْيَى بْنِ الْوَزِيرِ بْنِ سُلَيْمَانَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ كَثِيرِ بْنِ عُفَيْرٍ قَالَ أَنْبَأَنَا سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسٍ قَالَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيَّ كَأَنَّهُ يَعْنِي عَبْدَ الرَّحْمَنِ بْنَ عَوْفٍ أَثَرَ صُفْرَةٍ فَقَالَ مَهْيَمْ قَالَ تَزَوَّجْتُ امْرَأَةً مِنْ الْأَنْصَارِ فَقَالَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Yahya bin Al Wazir bin Sulaiman], ia berkata; telah menceritakan kepada kami [Sa'id bin Katsir bin 'Ufair], ia berkata; telah memberitakan kepada kami [Sulaiman bin Bilal] dari [Yahya bin Sa'id] dari [Humaid Ath Thawil] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam melihat pada diriku -sepertinya yang ia maksud adalah Abdur Rahman bin 'Auf-- terdapat bekas kuning, kemudian beliau bertanya: \"Apa ini?\" Ia berkata; saya telah menikahi seorang wanita Anshar. Kemudian beliau bersabda: \"Rayakan walaupun dengan seekor kambing.\""},"3230":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ أَنَّ عَلِيًّا قَالَتَزَوَّجْتُ فَاطِمَةَ رَضِيَ اللَّهُ عَنْهَا فَقُلْتُ يَا رَسُولَ اللَّهِ ابْنِ بِي قَالَ أَعْطِهَا شَيْئًا قُلْتُ مَا عِنْدِي مِنْ شَيْءٍ قَالَ فَأَيْنَ دِرْعُكَ الْحُطَمِيَّةُ قُلْتُ هِيَ عِنْدِي قَالَ فَأَعْطِهَا إِيَّاهُ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Hisyam bin Abdul Malik], ia berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari ['Ikrimah] dari [Ibnu Abbas] bahwa [Ali] berkata; Dahulu saat saya akan menikahi Fathimah radliallahu 'anha, saya berkata; wahai Rasulullah, tolong Fatimah serumahtanggakan denganku, beliau bersabda: \"Baik, Berilah ia sesuatu\", saya berkata; saya tidak memiliki sesuatu, beliau bersabda: \"Dimanakah baju zirahmu yang anti pedang itu?, \" saya menjawab ia ada padaku, beliau bersabda: \"Berikan padanya.\""},"3231":{"ar":"أَخْبَرَنَا هَارُونُ بْنُ إِسْحَقَ عَنْ عَبْدَةَ عَنْ سَعِيدٍ عَنْ أَيُّوبَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَلَمَّا تَزَوَّجَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ فَاطِمَةَ رَضِيَ اللَّهُ عَنْهَا قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْطِهَا شَيْئًا قَالَ مَا عِنْدِي قَالَ فَأَيْنَ دِرْعُكَ الْحُطَمِيَّةُ","id":"Telah mengabarkan kepada kami [Harun bin Ishaq] dari ['Abdah] dari [Sa'id] dari [Ayyub] dari ['Ikrimah] dari [Ibnu Abbas], ia berkata; tatkala Ali radliallahu 'anhu menikahi Fathimah radliallahu 'anha, Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Berikan sesuatu kepadanya.\" Ia berkata; saya tidak memiliki. Beliau bertanya: \"Dimanakah baju zirahmu yang anti pedang itu?\""},"3232":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ إِسْمَعِيلَ بْنِ أُمَيَّةَ عَنْ عَبْدِ اللَّهِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْتَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي شَوَّالٍ وَأُدْخِلْتُ عَلَيْهِ فِي شَوَّالٍ فَأَيُّ نِسَائِهِ كَانَ أَحْظَى عِنْدَهُ مِنِّي","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Waki'], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Isma'il bin Umayyah] dari [Abdullah bin 'Urwah] dari [ayahnya] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menikahiku pada bulan Syawal dan saya tinggal bersamanya pada bulan Syawal. Siapakah isterinya yang lebih beruntung daripada diriku? "},"3233":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ آدَمَ عَنْ عَبْدَةَ عَنْ هِشَامٍ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْتَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَنَا بِنْتُ سِتٍّ وَدَخَلَ عَلَيَّ وَأَنَا بِنْتُ تِسْعِ سِنِينَ وَكُنْتُ أَلْعَبُ بِالْبَنَاتِ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam] dari ['Abdah] dari [Hisyam] dari [Ayahnya] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menikahiku sedang saya berumur sembilan tahun, dan saya masih bermain dengan anak-anak sebaya. "},"3234":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سَعْدِ بْنِ الْحَكَمِ بْنِ أَبِي مَرْيَمَ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا يَحْيَى بْنُ أَيُّوبَ قَالَ أَخْبَرَنِي عُمَارَةُ بْنُ غَزِيَّةَ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عَائِشَةَ قَالَتْتَزَوَّجَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ بِنْتُ سِتِّ سِنِينَ وَبَنَى بِهَا وَهِيَ بِنْتُ تِسْعٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Sa'd bin Al Hakam bin Abu Maryam], ia berkata; telah menceritakan kepada kami [pamanku], ia berkata; telah menceritakan kepada kami [Yahya bin Ayyub], ia berkata; telah mengabarkan kepadaku ['Ammarah bin Ghaziyyah] dari [Muhammad bin Ibrahim] dari [Abu Salamah bin Abdur Rahman] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam menikahiku sedang saya adalah anak yang berumur enam tahun, dan beliau berumahtangga denganku saat umurnya sembilan tahun. "},"3235":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا إِسْمَعِيلُ ابْنُ عُلَيَّةَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ صُهَيْبٍ عَنْ أَنَسٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ غَزَا خَيْبَرَ فَصَلَّيْنَا عِنْدَهَا الْغَدَاةَ بِغَلَسٍ فَرَكِبَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَرَكِبَ أَبُو طَلْحَةَ وَأَنَا رَدِيفُ أَبِي طَلْحَةَ فَأَخَذَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي زُقَاقِ خَيْبَرَ وَإِنَّ رُكْبَتِي لَتَمَسُّ فَخِذَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِنِّي لَأَرَى بَيَاضَ فَخِذِ نَبِيِّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا دَخَلَ الْقَرْيَةَ قَالَ اللَّهُ أَكْبَرُ خَرِبَتْ خَيْبَرُ إِنَّا إِذَا نَزَلْنَا بِسَاحَةِ قَوْمٍ فَسَاءَ صَبَاحُ الْمُنْذَرِينَ قَالَهَا ثَلَاثَ مَرَّاتٍ قَالَ وَخَرَجَ الْقَوْمُ إِلَى أَعْمَالِهِمْ قَالَ عَبْدُ الْعَزِيزِ فَقَالُوا مُحَمَّدٌ قَالَ عَبْدُ الْعَزِيزِ وَقَالَ بَعْضُ أَصْحَابِنَا وَالْخَمِيسُ وَأَصَبْنَاهَا عَنْوَةً فَجَمَعَ السَّبْيَ فَجَاءَ دِحْيَةُ فَقَالَ يَا نَبِيَّ اللَّهِ أَعْطِنِي جَارِيَةً مِنْ السَّبْيِ قَالَ اذْهَبْ فَخُذْ جَارِيَةً فَأَخَذَ صَفِيَّةَ بِنْتَ حُيَيٍّ فَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ أَعْطَيْتَ دِحْيَةَ صَفِيَّةَ بِنْتَ حُيَيٍّ سَيِّدَةَ قُرَيْظَةَ وَالنَّضِيرِ مَا تَصْلُحُ إِلَّا لَكَ قَالَ ادْعُوهُ بِهَا فَجَاءَ بِهَا فَلَمَّا نَظَرَ إِلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ خُذْ جَارِيَةً مِنْ السَّبْيِ غَيْرَهَا قَالَ وَإِنَّ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْتَقَهَا وَتَزَوَّجَهَا فَقَالَ لَهُ ثَابِتٌ يَا أَبَا حَمْزَةَ مَا أَصْدَقَهَا قَالَ نَفْسَهَا أَعْتَقَهَا وَتَزَوَّجَهَا قَالَ حَتَّى إِذَا كَانَ بِالطَّرِيقِ جَهَّزَتْهَا لَهُ أُمُّ سُلَيْمٍ فَأَهْدَتْهَا إِلَيْهِ مِنْ اللَّيْلِ فَأَصْبَحَ عَرُوسًا قَالَ مَنْ كَانَ عِنْدَهُ شَيْءٌ فَلْيَجِئْ بِهِ قَالَ وَبَسَطَ نِطَعًا فَجَعَلَ الرَّجُلُ يَجِيءُ بِالْأَقِطِ وَجَعَلَ الرَّجُلُ يَجِيءُ بِالتَّمْرِ وَجَعَلَ الرَّجُلُ يَجِيءُ بِالسَّمْنِ فَحَاسُوا حَيْسَةً فَكَانَتْ وَلِيمَةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Isma'il bin 'Ulayyah], ia berkata; telah menceritakan kepada kami [Abdul Aziz bin Shuhaib] dari [Anas] bahwa Rasulullah shallallahu 'alaihi wasallam memerangi Khaibar, kemudian kami melakukan shalat subuh padanya disaat masih gelap. Kemudian Nabi shallallahu 'alaihi wasallam mengendarai kendaraannya, dan Abu Thalhah mengendarai kendaraannya sedang saya membonceng Abu Thalhah. Lalu Nabi shallallahu 'alaihi wasallam mengambil jalan di lorong Khaibar, dan kedua lututku menyentuh paha Rasulullah shallallahu 'alaihi wasallam, dan sungguh saya melihat putih paha Nabi shallallahu 'alaihi wasallam. Tatkala beliau memasuki kampung beliau mengucapkan: \"Allahu akbar, khaibar hancur. Sesungguhnya bila kita singgah di halaman orang-orang, maka amat buruklah pagi hari yang dialami oleh orang-orang yang diperingatkan itu.\" Beliau mengucapkan hal tersebut sebanyak tiga kali, dan orang-orang berangkat menuju pekerjaan mereka. --Abdul Aziz berkata; kemudian mereka berkata; Muhammad. Abdul Aziz berkata; dan sebagian sahabat kami berkata; tibalah hari kamis, kami melumpuhkan Khaibar secara paksa--. Beliau mengumpulkan tawanan, lalu Dihyah berkata; wahai Nabi Allah, berikan kepadaku budak wanita diantara tawanan tersebut! Beliau bersabda: \"Pergi dan ambillah seorang budak wanita.\" Ia mengambil Shafiyyah binti Huyai. Kemudian seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; wahai Nabi Allah, engkau telah memberikan Shafiyyah binti Huyai pemimpin Quraidzhah dan An Nazhir kepada Dihyah. Ia tidak layak kecuali untukmu. Maka beliau bersabda: \"Panggilah dia dengan membawanya.\" Setelah melihat Shafiyyah beliau bersabda: \"Ambillah budak dari tawanan selain dia.\" Anas berkata; dan Nabi shallallahu 'alaihi wasallam membebaskannya dan menikahinya. Kemudian Tsabit berkata; wahai Abu Hamzah, mahar apakah yang beliau berikan kepadanya? Ia mengatakan; dirinya, beliau telah membebaskannya dan menikahinya. Ibnu Abbas berkata; hingga setelah berada di suatu jalan Ummu Sulaim mempersiapkan Shafiyyah, dan menghadiahkannya kepada beliau pada malam hari. Dan pada pagi harinya beliau menjadi pengantin. Beliau bersabda: \"Barang siapa yang memiliki sesuatu, bawa kemari.\" Ibnu Abbas berkata; dan beliau menghamparkan permadani dari kulit, kemudian seorang laki-laki datang membawa keju, laki-laki lain membawa kurma, laki-laki lain membawa mentega, kemudian mereka membuat makanan dari campuran kurma, keju dan mentega. Itulah pesta perkawinan Rasulullah shallallahu 'alaihi wasallam. "},"3236":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ نَصْرٍ قَالَ حَدَّثَنَا أَيُّوبُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنِي أَبُو بَكْرِ بْنُ أَبِي أُوَيْسٍ عَنْ سُلَيْمَانَ بْنِ بِلَالٍ عَنْ يَحْيَى عَنْ حُمَيْدٍ أَنَّهُ سَمِعَ أَنَسًا يَقُولُإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقَامَ عَلَى صَفِيَّةَ بِنْتِ حُيَيِّ بْنِ أَخْطَبَ بِطَرِيقِ خَيْبَرَ ثَلَاثَةَ أَيَّامٍ حِينَ عَرَّسَ بِهَا ثُمَّ كَانَتْ فِيمَنْ ضُرِبَ عَلَيْهَا الْحِجَابُ","id":"Telah mengabarkan kepada kami [Muhammad bin Nashr], ia berkata; telah menceritakan kepada kami [Ayyub bin Sulaiman], ia berkata; telah menceritakan kepadaku [Abu Bakr bin Abu Uwais] dari [Sulaiman bin Bilal] dari [Yahya] dari [Humaid] bahwa ia mendengar [Anas] berkata; Rasulullah shallallahu 'alaihi wasallam tinggal bersama Shafiyyah binti Huyai bin Akhthab di jalan Khaibar selama tiga hari ketika beliau menikah dengannya, kemudian ia termasuk diantara wanita yang diwajibkan memakai hijab. "},"3237":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَأَقَامَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ خَيْبَرَ وَالْمَدِينَةِ ثَلَاثًا يَبْنِي بِصَفِيَّةَ بِنْتِ حُيَيٍّ فَدَعَوْتُ الْمُسْلِمِينَ إِلَى وَلِيمَتِهِ فَمَا كَانَ فِيهَا مِنْ خُبْزٍ وَلَا لَحْمٍ أَمَرَ بِالْأَنْطَاعِ وَأَلْقَى عَلَيْهَا مِنْ التَّمْرِ وَالْأَقِطِ وَالسَّمْنِ فَكَانَتْ وَلِيمَتَهُ فَقَالَ الْمُسْلِمُونَ إِحْدَى أُمَّهَاتِ الْمُؤْمِنِينَ أَوْ مِمَّا مَلَكَتْ يَمِينُهُ فَقَالُوا إِنْ حَجَبَهَا فَهِيَ مِنْ أُمَّهَاتِ الْمُؤْمِنِينَ وَإِنْ لَمْ يَحْجُبْهَا فَهِيَ مِمَّا مَلَكَتْ يَمِينُهُ فَلَمَّا ارْتَحَلَ وَطَّأَ لَهَا خَلْفَهُ وَمَدَّ الْحِجَابَ بَيْنَهَا وَبَيْنَ النَّاسِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Isma'il], ia berkata; telah menceritakan kepada kami [Humaid] dari [Anas], ia berkata; Nabi shallallahu 'alaihi wasallam tinggal diantara Khaibar dan Madinah selama tiga hari, beliau tinggal bersama Shafiyyah binti Huyai. Kemudian saya memanggil orang-orang muslim untuk menghadiri pesta perkawinan beliau, padahal beliau tak mempunyai roti, dan daging. Beliau memerintahkan untuk menghamparkan permadani dari kulit, dan beliau letakkan padanya kurma, keju dan mentega. Itulah pesta pernikahan beliau. Kemudian orang-orang muslim bertanya-tanya; apakah ia ummahatul muslimin ataukah sekedar sahaya yang beliau miliki?. Mereka berkata; apabila beliau memberinya hijab tentu ia termasuk ummahatul mukminin, dan jika beliau tidak memberinya hijab maka ia sekedar sahaya yang beliau miliki. Setelah beliau berangkat beliau menempatkannya dibelakang beliau dan membentangkan hijab antara Shafiyyah dan orang-orang. "},"3238":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا شَرِيكٌ عَنْ أَبِي إِسْحَقَ عَنْ عَامِرِ بْنِ سَعْدٍ قَالَدَخَلْتُ عَلَى قُرَظَةَ بْنِ كَعْبٍ وَأَبِي مَسْعُودٍ الْأَنْصَارِيِّ فِي عُرْسٍ وَإِذَا جَوَارٍ يُغَنِّينَ فَقُلْتُ أَنْتُمَا صَاحِبَا رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمِنْ أَهْلِ بَدْرٍ يُفْعَلُ هَذَا عِنْدَكُمْ فَقَالَ اجْلِسْ إِنْ شِئْتَ فَاسْمَعْ مَعَنَا وَإِنْ شِئْتَ اذْهَبْ قَدْ رُخِّصَ لَنَا فِي اللَّهْوِ عِنْدَ الْعُرْسِ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah menceritakan kepada kami [Syarik] dari [Abu Ishaq] dari ['Amir bin Sa'd], ia berkata; saya menemui [Qurazhah bin Ka'b] dan [Abu Mas'ud Al Anshari] dalam suatu pesta pernikahan. Dan ternyata terdapat beberapa sahaya wanita yang bernyanyi, kemudian saya katakan; kalian berdua adalah sahabat Rasulullah shallallahu 'alaihi wasallam, dan termasuk ahli Badr. Apakah pantas dilalukan hal ini di hadapan kalian? Kemudian ia berkata; duduklah jika engkau mau dan dengarkan bersama kami, dan jika engkau mau pergi maka pergilah, sungguh telah diberikan keringanan bagi kita dalam hiburan ketika pesta pernikahan. "},"3239":{"ar":"أَخْبَرَنَا نَصِيرُ بْنُ الْفَرَجِ قَالَ حَدَّثَنَا أَبُو أُسَامَةَ عَنْ زَائِدَةَ قَالَ حَدَّثَنَا عَطَاءُ بْنُ السَّائِبِ عَنْ أَبِيهِ عَنْ عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ قَالَجَهَّزَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاطِمَةَ فِي خَمِيلٍ وَقِرْبَةٍ وَوِسَادَةٍ حَشْوُهَا إِذْخِرٌ","id":"Telah mengabarkan kepada kami [Nashir bin Al Faraj], ia berkata; telah menceritakan kepada kami [Abu Usamah] dari [Zaidah], ia berkata; telah menceritakan kepada kami ['Atho` bin As Saib] dari [ayahnya] dari [Ali] radliallahu 'anhu, ia berkata; Rasulullah shallallahu 'alaihi wasallam mempersiapkan Fathimah dalam sebuah sebuah kain beludru, geriba, dan bantal yang isinya adalah rumput jeruk."},"3240":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي أَبُو هَانِئٍ الْخَوْلَانِيُّ أَنَّهُ سَمِعَ أَبَا عَبْدِ الرَّحْمَنِ الْحُبُلِيَّ يَقُولُ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ فِرَاشٌ لِلرَّجُلِ وَفِرَاشٌ لِأَهْلِهِ وَالثَّالِثُ لِلضَّيْفِ وَالرَّابِعُ لِلشَّيْطَانِ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la], ia berkata; telah memberitakan kepada kami [Ibnu Wahb], ia berkata; telah memberitakan kepadaku [Abu Hani` Al Khaulani] bahwa ia mendengar [Abu Abdur Rahman Al Hubuli] berkata dari [Jabir bin Abdullah] bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Satu kasur untuk seorang laki-laki, dan satu kasur untuk isterinya dan yang ketiga untuk tamu serta yang keempat adalah untuk setan.\""},"3241":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ الْمُنْكَدِرِ عَنْ جَابِرٍ قَالَقَالَ لِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ تَزَوَّجْتَ قُلْتُ نَعَمْ قَالَ هَلْ اتَّخَذْتُمْ أَنْمَاطًا قُلْتُ وَأَنَّى لَنَا أَنْمَاطٌ قَالَ إِنَّهَا سَتَكُونُ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Al Munkadir] dari [Jabir], ia berkata; Rasulullah shallallahu 'alaihi wasallam bertanya kepadaku: \"Apakah engkau telah menikah?\" Saya katakan; ya. Beliau bersabda: \"Apakah kalian menggunakan permadani?\" Saya katakan; dari mana kami memiliki permadani? Beliau bersabda: \"Ia akan ada.\" "},"3242":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا جَعْفَرٌ وَهُوَ ابْنُ سُلَيْمَانَ عَنْ الْجَعْدِ أَبِي عُثْمَانَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَتَزَوَّجَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ بِأَهْلِهِ قَالَ وَصَنَعَتْ أُمِّي أُمُّ سُلَيْمٍ حَيْسًا قَالَ فَذَهَبَتْ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّ أُمِّي تُقْرِئُكَ السَّلَامَ وَتَقُولُ لَكَ إِنَّ هَذَا لَكَ مِنَّا قَلِيلٌ قَالَ ضَعْهُ ثُمَّ قَالَ اذْهَبْ فَادْعُ فُلَانًا وَفُلَانًا وَمَنْ لَقِيتَ وَسَمَّى رِجَالًا فَدَعَوْتُ مَنْ سَمَّى وَمَنْ لَقِيتُهُ قُلْتُ لِأَنَسٍ عِدَّةُ كَمْ كَانُوا قَالَ يَعْنِي زُهَاءَ ثَلَاثَ مِائَةٍ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيَتَحَلَّقْ عَشَرَةٌ عَشَرَةٌ فَلْيَأْكُلْ كُلُّ إِنْسَانٍ مِمَّا يَلِيهِ فَأَكَلُوا حَتَّى شَبِعُوا فَخَرَجَتْ طَائِفَةٌ وَدَخَلَتْ طَائِفَةٌ قَالَ لِي يَا أَنَسُ ارْفَعْ فَرَفَعْتُ فَمَا أَدْرِي حِينَ رَفَعْتُ كَانَ أَكْثَرَ أَمْ حِينَ وَضَعْتُ","id":"Telah mengabarkan kepada kami [Qutaibah] telah menceritakan kepada kami [Ja'far yaitu Ibnu Sulaiman] dari [Al Ja'd Abu 'Utsman] dari [Anas bin Malik], ia berkata; Rasulullah shallallahu 'alaihi wasallam menikah, lalu beliau masuk menemui istrinya Anas berkata; sedangkan ibuku Ummu Sulaim membuat makan dari kurma, keju dan mentega. Ia berkata; lalu ia membawanya kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian saya berkata; ibuku menyampaikan salam kepadamu dan berkata ini ada sedikit sesuatu dari kami untukmu. Beliau bersabda: \"Letakkanlah\", kemudian beliau bersabda: \"Pergilah dan panggillah fulan, fulan dan siapa yang engkau temui, \" beliau menyebut nama beberapa orang, lalu saya memanggil orang-orang yang beliau sebutkan dan siapa saja yang saya temui. Saya berkata kepada Anas; berapa jumlahnya? Ia menjawab; yakni sekitar tiga ratusan. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Buatlah kelompok sepuluh orang-sepuluh orang dan setiap orang agar makan dengan yang didekatnya.\" Lalu mereka makan hingga kenyang, satu rombongan keluar dan rombongan lain masuk, beliau bersabda kepadaku: \" Wahai Anas, angkatlah.\" Lalu saya mengangatnya, saya tidak mengetahui apakah lebih banyak ketika saya angkat atau saya turunkan."},"3243":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ يَحْيَى بْنِ الْوَزِيرِ قَالَ حَدَّثَنَا سَعِيدُ بْنُ كَثِيرِ بْنِ عُفَيْرٍ قَالَ أَخْبَرَنِي سُلَيْمَانُ بْنُ بِلَالٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ حُمَيْدٍ الطَّوِيلِ عَنْ أَنَسٍ أَنَّهُ سَمِعَهُ يَقُولُآخَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ قُرَيْشٍ وَالْأَنْصَارِ فَآخَى بَيْنَ سَعْدِ بْنِ الرَّبِيعِ وَعَبْدِ الرَّحْمَنِ بْنِ عَوْفٍ فَقَالَ لَهُ سَعْدٌ إِنَّ لِي مَالًا فَهُوَ بَيْنِي وَبَيْنَكَ شَطْرَانِ وَلِي امْرَأَتَانِ فَ��نْظُرْ أَيُّهُمَا أَحَبُّ إِلَيْكَ فَأَنَا أُطَلِّقُهَا فَإِذَا حَلَّتْ فَتَزَوَّجْهَا قَالَ بَارَكَ اللَّهُ لَكَ فِي أَهْلِكَ وَمَالِكَ دُلُّونِي أَيْ عَلَى السُّوقِ فَلَمْ يَرْجِعْ حَتَّى رَجَعَ بِسَمْنٍ وَأَقِطٍ قَدْ أَفْضَلَهُ قَالَ وَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيَّ أَثَرَ صُفْرَةٍ فَقَالَ مَهْيَمْ فَقُلْتُ تَزَوَّجْتُ امْرَأَةً مِنْ الْأَنْصَارِ فَقَالَ أَوْلِمْ وَلَوْ بِشَاةٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Yahya bin Al Wazir], ia berkata; telah menceritakan kepada kami [Sa'id bin Katsir bin 'Ufair], ia berkata; telah mengabarkan kepadaku [Sulaiman bin Bilal] dari [Yahya bin Sa'id] dari [Humaid Ath Thawil] dari [Anas] bahwa ia mendengarnya mengatakan; Rasulullah shallallahu 'alaihi wasallam mempersaudarakan antara orang-orang Quraisy dan Anshar, dan mempersaudarakan antara Sa'd bin Ar Rabi' dan Abdur Rahman bin 'Auf. Kemudian Sa'd berkata kepadanya; Saya memiliki harta, harta tersebut dibagi dua antara saya dan engkau. Dan saya memiliki dua orang isteri, lihatlah siapakah diantara keduanya yang lebih engkau sukai, maka saya akan mencerainya kemudian apabila ia telah selesai masa 'iddahnya nikahilah dia. Abdur Rahman berkata; semoga Allah memberikan berkah bagimu pada keluarga dan hartamu. Cukuplah tunjukkan kepadaku dimanakah pasar? Kemudian ia tidak kembali hingga kembali membawa mentega, dan keju yang Allah anugerahkan kepadanya. Abdur Rahman berkata; dan Rasulullah shallallahu 'alaihi wasallam melihat padaku terdapat bekas warna kuning. Kemudian bertanya: \"Apa ini?\" Lalu saya katakan; saya telah menikah dengan seorang wanita dari kalangan Anshar. Kemudian beliau bersabda: \"Rayakan walaupun hanya dengan seekor kambing.\" "},"3244":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ السَّرْخَسِيُّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ الْقَطَّانُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ عَبْدِ اللَّهِأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَاسْتَفْتَى عُمَرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ عَبْدَ اللَّهِ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَقَالَ مُرْ عَبْدَ اللَّهِ فَلْيُرَاجِعْهَا ثُمَّ يَدَعْهَا حَتَّى تَطْهُرَ مِنْ حَيْضَتِهَا هَذِهِ ثُمَّ تَحِيضَ حَيْضَةً أُخْرَى فَإِذَا طَهُرَتْ فَإِنْ شَاءَ فَلْيُفَارِقْهَا قَبْلَ أَنْ يُجَامِعَهَا وَإِنْ شَاءَ فَلْيُمْسِكْهَا فَإِنَّهَا الْعِدَّةُ الَّتِي أَمَرَ اللَّهُ عَزَّ وَجَلَّ أَنْ تُطَلَّقَ لَهَا النِّسَاءُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id As Sarkhasi], ia berkata; telah menceritakan kepada kami [Yahya bin Sa'id Al Qaththan] dari ['Ubaidulah bin Umar], ia berkata; telah memberitakan kepadaku [Nafi'] dari [Abdullah] bahwa ia telah mencerai isterinya dalam keadaan haid. Kemudian Umar meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam, ia berkata; Abdullah menceraikan isterinya dalam keadaan haid. Maka beliau bersabda: \"Perintahkan kepada Abdullah agar kembali kepadanya, kemudian membiarkannya hingga suci dari haidnya ini, kemudian haid berikutnya, kemudian apabila telah suci maka apabila ia menghendaki maka silahkan ia mencerainya sebelum menggaulinya, dan jika ia menghendaki maka silahkan ia menahannya. Itulah 'iddah yang Allah 'azza wajalla perintahkan agar wanita dicerai padanya.\" "},"3245":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فِي عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ عُمَرُ بْنُ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْهُ فَلْيُرَاجِعْهَا ثُمَّ لِيُمْسِكْهَا حَتَّى تَطْهُرَ ثُمَّ تَحِيضَ ثُمَّ تَطْهُرَ ثُمَّ إِنْ شَاءَ أَمْسَكَ بَعْدُ وَإِنْ شَاءَ طَلَّقَ قَبْلَ أَنْ يَمَسَّ فَتِلْكَ الْعِدَّةُ الَّتِي أَمَرَ اللَّهُ عَزَّ وَجَلَّ أَنْ تُطَلَّقَ لَهَا النِّسَاءُ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah], ia berkata; telah memberitakan kepada kami [Ibnu Al Qasim] dari [Malik] dari [Nafi'] dari [Ibnu Umar] bahwa ia telah mencerai isterinya dalam keadaan haid pada masa Rasulullah shallallahu 'alaihi wasallam. Kemudian Umar bin Al Khathab radliallahu 'anhu bertanya mengenai hal tersebut. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perintahkan kepadanya agar kembali kepadanya kemudian menahannya hingga suci, kemudian haid kemudian suci kemudian apabila ia menghendaki maka ia boleh menahannya setelah itu, dan jika ia menghendaki maka ia boleh mencerainya sebelum menggaulinya. Itulah 'iddah yang Allah 'azza wajalla perintahkan agar wanita dicerai padanya. "},"3246":{"ar":"أَخْبَرَنِي كَثِيرُ بْنُ عُبَيْدٍ عَنْ مُحَمَّدِ بْنِ حَرْبٍ قَالَ حَدَّثَنَا الزُّبَيْدِيُّ قَالَ سُئِلَ الزُّهْرِيُّ كَيْفَ الطَّلَاقُ لِلْعِدَّةِ فَقَالَ أَخْبَرَنِي سَالِمُ بْنُ عَبْدِ اللَّهِ بْنِ عُمَرَ أَنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَطَلَّقْتُ امْرَأَتِي فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ حَائِضٌ فَذَكَرَ ذَلِكَ عُمَرُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَتَغَيَّظَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي ذَلِكَ فَقَالَ لِيُرَاجِعْهَا ثُمَّ يُمْسِكْهَا حَتَّى تَحِيضَ حَيْضَةً وَتَطْهُرَ فَإِنْ بَدَا لَهُ أَنْ يُطَلِّقَهَا طَاهِرًا قَبْلَ أَنْ يَمَسَّهَا فَذَاكَ الطَّلَاقُ لِلْعِدَّةِ كَمَا أَنْزَلَ اللَّهُ عَزَّ وَجَلَّقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ فَرَاجَعْتُهَا وَحَسَبْتُ لَهَا التَّطْلِيقَةَ الَّتِي طَلَّقْتُهَا","id":"Telah mengabarkan kepada kami [Katsir bin 'Ubaid] dari [Muhammad bin Harb], ia berkata; telah menceritakan kepada kami [Az Zubaidi], ia berkata; [Az Zuhri] pernah ditanya; bagaimana cerai pada 'iddahnya? Kemudian ia berkata; telah mengabarkan kepadaku [Salim bin Abdullah bin Umar] bahwa [Abdullah bin Umar] berkata; saya mencerai isteriku dalam keadaan haid pada masa hidupnya Rasulullah shallallahu 'alaihi wasallam. Kemudian Umar menyebutkan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam, maka Rasulullah shallallahu 'alaihi wasallam marah karena hal tersebut, dan bersabda: \"Hendaknya ia kembali kepadanya, kemudian menahannya hingga mengalami haid, dan suci, kemudian apabila ia menginginkan untuk mencerainya dalam keadaan suci sebelum menggaulinya maka itulah cerai pada 'iddahnya sebagaimana yang telah Allah 'azza wajalla turunkan.\" Abdullah bin Umar berkata; kemudian saya kembali kepadanya dan menghitung baginya satu cerai yang telah saya lakukan kepadanya. "},"3247":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ وَعَبْدُ اللَّهِ بْنُ مُحَمَّدِ بْنِ تَمِيمٍ عَنْ حَجَّاجٍ قَالَ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِي أَبُو الزُّبَيْرِأَنَّهُ سَمِعَ عَبْدَ الرَّحْمَنِ بْنَ أَيْمَنَ يَسْأَلُ ابْنَ عُمَرَ وَأَبُو الزُّبَيْرِ يَسْمَعُ كَيْفَ تَرَى فِي رَجُلٍ طَلَّقَ امْرَأَتَهُ حَائِضًا فَقَالَ لَهُ طَلَّقَ عَبْدُ اللَّهِ بْنُ عُمَرَ امْرَأَتَهُ وَهِيَ حَائِضٌ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ عُمَرُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ عَبْدَ اللَّهِ بْنَ عُمَرَ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِيُرَاجِعْهَا فَرَدَّهَا عَلَيَّ قَالَ إِذَا طَهُرَتْ فَلْيُطَلِّقْ أَوْ لِيُمْسِكْ قَالَ ابْنُ عُمَرَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ يَا أَيُّهَا النَّبِيُّ إِذَا طَلَّقْتُمْ النِّسَاءَ فَطَلِّقُوهُنَّ }فِي قُبُلِ عِدَّتِهِنَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] dan [Abdullah bin Muhammad bin Tamim] dari [Hajjaj], ia berkata; telah berkata [Ibnu Juraij]; telah mengabarkan kepadaku [Abu Az Zubair] bahwa ia mendengar Abdur Rahman bin Aiman bertanya kepada Ibnu Umar dan Abu Az Zubair mendengarnya; bagaimana pendapatmu mengenai seorang laki-laki yang mencerai isterinya dalam keadaan haid? [Ibnu Umar] berkata kepadanya; Abdullah bin Umar mencerai isterinya dalam keadaan haid pada masa Rasulullah shallallahu 'alaihi wasallam. Kemudian Umar bertanya kepada Rasulullah shallallahu 'alaihi wasallam, ia berkata; Abdullah bin Umar telah mencerai isterinya dalam keadaan haid. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Hendaknya ia kembali kepadanya.\" Beliau mengembalikannya kepadaku. Beliau bersabda: \"Apabila ia telah suci maka silahkan ia mencerai atau menahannya.\" Ibnu Umar berkata; kemudian Nabi shallallahu 'alaihi wasallam mengucapkan: \"Wahai Nabi, apabila engkau mencerai isteri-isterimu maka cerailah pada awal 'iddahnya.\""},"3248":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ قَالَ سَمِعْتُ مُجَاهِدًا يُحَدِّثُهُ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ عَزَّ وَجَلَّ{ يَا أَيُّهَا النَّبِيُّ إِذَا طَلَّقْتُمْ النِّسَاءَ فَطَلِّقُوهُنَّ لِعِدَّتِهِنَّ }قَالَ ابْنُ عَبَّاسٍ رَضِيَ اللَّهُ عَنْهُ قُبُلِ عِدَّتِهِنَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam], ia berkata; saya pernah mendengar Ibnu Abbas menceritakan kepada [Mujahid] tentang firman Allah Azza wa Jalla: Hai Nabi jika engkau menceraikan istri-istrimu maka hendaknya engkau ceraikan mereka pada waktu mereka mendapati iddahnya, [Ibnu Abbas] radliallahu 'anhu berkata; yaitu pada awal 'iddahnya."},"3249":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ أَيُّوبَ قَالَ حَدَّثَنَا حَفْصُ بْنُ غِيَاثٍ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ أَنَّهُ قَالَطَلَاقُ السُّنَّةِ تَطْلِيقَةٌ وَهِيَ طَاهِرٌ فِي غَيْرِ جِمَاعٍ فَإِذَا حَاضَتْ وَطَهُرَتْ طَلَّقَهَا أُخْرَى فَإِذَا حَاضَتْ وَطَهُرَتْ طَلَّقَهَا أُخْرَى ثُمَّ تَعْتَدُّ بَعْدَ ذَلِكَ بِحَيْضَةٍقَالَ الْأَعْمَشُ سَأَلْتُ إِبْرَاهِيمَ فَقَالَ مِثْلَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Yahya bin Ayyub], Ia berkata; telah menceritakan kepada kami [Hafsh bin Ghiyats], ia berkata; telah menceritakan kepada kami [Al A'masy] dari [Abu Ishaq] dari [Al Ahwash] dari [Abdullah] ia berkata; mencerai yang sesuai sunnah yaitu mencerai ketika ia dalam keadaan suci dan belum dilakukan jima', jika ia haid lalu suci, maka ia menceraikannya kedua kalinya, jika ia haid dan bersuci maka ia menceraikan ketiga kalinya, kemudian ia menunggu masa iddah setelah itu dengan sekali haid. Al A'masy berkata saya bertanya kepada Ibrahim, dan ia berkata seperti itu."},"3250":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ سُفْيَانَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي الْأَحْوَصِ عَنْ عَبْدِ اللَّهِ قَالَطَلَاقُ السُّنَّةِ أَنْ يُطَلِّقَهَا طَاهِرًا فِي غَيْرِ جِمَاعٍ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya] dari [Sufyan] dari [Abu Ishaq] dari [Abu Al Ahwash] dari [Abdullah], ia berkata; menceraikan yang sunnah adalah menceraikannya ketika ia dalam keadaan suci belum digauli. "},"3251":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ عُبَيْدَ اللَّهِ بْنَ عُمَرَ عَنْ نَافِعٍ عَنْ عَبْدِ اللَّهِأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ تَطْلِيقَةً فَانْطَلَقَ عُمَرُ فَأَخْبَرَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِذَلِكَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْ عَبْدَ اللَّهِ فَلْيُرَاجِعْهَا فَإِذَا اغْتَسَلَتْ فَلْيَتْرُكْهَا حَتَّى تَحِيضَ فَإِذَا اغْتَسَلَتْ مِنْ حَيْضَتِهَا الْأُخْرَى فَلَا يَمَسَّهَا حَتَّى يُطَلِّقَهَا فَإِنْ شَاءَ أَنْ يُمْسِكَهَا فَلْيُمْسِكْهَا فَإِنَّهَا الْعِدَّةُ الَّتِي أَمَرَ اللَّهُ عَزَّ وَجَلَّ أَنْ تُطَلَّقَ لَهَا النِّسَاءُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Al Mu'tamir], ia berkata; saya mendengar ['Ubaidullah bin Umar] dari [Nafi'] dari [Abdullah] bahwa ia menceraikan isterinya ketika ia dalam keadaan haid dengan satu kali cerai. Kemudian Umar pergi dan mengabarkan hal tersebut kepada Nabi shallallahu 'alaihi wasallam. Lalu Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Hendaknya ia kembali kepadanya, kemudian apabila ia telah mandi untuk bersuci maka hendaknya ia membiarkannya hingga mengalami haid, kemudian apabila ia telah mandi untuk bersuci dari haidnya yang lain maka hendaknya ia tidak menyentuhnya hingga ia mencerainya, apabila ia inggin menahannya maka hendaknya ia menahannya. Itulah 'iddah yang telah Allah 'azza wajalla perintahkan agar wanita diceraikan padanya.\" "},"3252":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ مَوْلَى طَلْحَةَ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عُمَرَأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُرْهُ فَلْيُرَاجِعْهَا ثُمَّ لِيُطَلِّقْهَا وَهِيَ طَاهِرٌ أَوْ حَامِلٌ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan], ia berkata; telah menceritakan kepada kami [Waki'], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Muhammad bin Abdur Rahman maula Thalhah] dari [Salim bin Abdullah] dari [Ibnu Umar] bahwa ia mencerai isterinya ketika ia dalam keadaan haid. Kemudian hal tersebut disebutkan kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Perintahkan dia agar kembali kepadanya, kemudian mencerainya ketika ia dalam keadaan suci atau hamil.\" "},"3253":{"ar":"أَخْبَرَنِي زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا هُشَيْمٌ قَالَ أَخْبَرَنَا أَبُو بِشْرٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عُمَرَأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَرَدَّهَا عَلَيْهِ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى طَلَّقَهَا وَهِيَ طَاهِرٌ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub], ia berkata; telah menceritakan kepada kami [Husyaim], ia berkata; telah mengabarkan kepada kami [Abu Bisyr] dari [Sa'id bin Jubair] dari [Ibnu Umar] bahwa ia menceraikan isterinya ketika ia dalam keadaan haid. Kemudian Rasulullah shallallahu 'alaihi wasallam mengembalikannya kepada Ibnu Umar, hingga ia mencerainya ketika dalam keadaan suci. "},"3254":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَيُّوبَ عَنْ مُحَمَّدٍ عَنْ يُونُسَ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عُمَرَعَنْ رَجُلٍ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَقَالَ هَلْ تَعْرِفُ عَبْدَ اللَّهِ بْنَ عُمَرَ فَإِنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَسَأَلَ عُمَرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهُ أَنْ يُرَاجِعَهَا ثُمَّ يَسْتَقْبِلَ عِدَّتَهَا فَقُلْتُ لَهُ فَيَعْتَدُّ بِتِلْكَ التَّطْلِيقَةِ فَقَالَ مَهْ أَرَأَيْتَ إِنْ عَجَزَ وَاسْتَحْمَقَ","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Hammad] dari [Ayyub] dari [Muhammad] dari [Yunus bin Jubair], ia berkata; saya bertanya kepada [Ibnu Umar] mengenai seorang laki-laki yang mencerai isterinya ketika ia dalam keadaan haid. Kemudian ia berkata; apakah engkau mengetahui Abdullah bin Umar bahwa ia mencerai isterinya ketika dalam keadaan haid. Kemudian Umar bertanya kepada Nabi shallallahu 'alaihi wasallam dan memerintah Ibnu Umar agar kembali kepada isterinya, kemudian menghadapi 'iddahnya. Kemudian saya katakan kepadanya; apakah ia menghitung penceraian tersebut? Maka ia berkata; diamlah, bagaimana pendapatmu apabila ia tidak mampu dan berpura-pura bodoh? "},"3255":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ يُونُسَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ يُونُسَ بْنِ جُبَيْرٍ قَالَ قُلْتُ لِابْنِ عُمَرَرَجُلٌ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَقَالَ أَتَعْرِفُ عَبْدَ اللَّهِ بْنَ عُمَرَ فَإِنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَأَتَى عُمَرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْأَلُهُ فَأَمَرَهُ أَنْ يُرَاجِعَهَا ثُمَّ يَسْتَقْبِلَ عِدَّتَهَا قُلْتُ لَهُ إِذَا طَلَّقَ الرَّجُلُ امْرَأَتَهُ وَهِيَ حَائِضٌ أَيَعْتَدُّ بِتِلْكَ التَّطْلِيقَةِ فَقَالَ مَهْ وَإِنْ عَجَزَ وَاسْتَحْمَقَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Ibnu 'Aliyyah] dari [Yunus] dari [Muhammad bin Sirin] dari [Yunus bin Jubair], ia berkata; saya katakan kepada [Ibnu Umar]; seorang laki-laki menceraikan isterinya ketika ia dalam keadaan haid. Kemudian ia berkata; tahukah engkau Abdullah bin Umar, ia menceraikan isterinya ketika ia dalam keadaan haid, kemudian Umar datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya kepadanya. Lalu beliau memerintahkannya agar kembali kepada isterinya kemudian menghadapi 'iddahnya. Saya katakan kepadanya; apabila seorang laki-laki menceraikan isterinya ketika ia dalam keadaan haid, apakah ia menghitung penceraian tersebut? Maka ia berkata; diamlah, apabila ia tidak mampu dan berpura-pura bodoh. "},"3256":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي مَخْرَمَةُ عَنْ أَبِيهِ قَالَ سَمِعْتُ مَحْمُودَ بْنَ لَبِيدٍ قَالَأُخْبِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ رَجُلٍ طَلَّقَ امْرَأَتَهُ ثَلَاثَ تَطْلِيقَاتٍ جَمِيعًا فَقَامَ غَضْبَانًا ثُمَّ قَالَ أَيُلْعَبُ بِكِتَابِ اللَّهِ وَأَنَا بَيْنَ أَظْهُرِكُمْ حَتَّى قَامَ رَجُلٌ وَقَالَ يَا رَسُولَ اللَّهِ أَلَا أَقْتُلُهُ","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dari [Ibn Wahab] ia berkata [Makhromah] telah mengabarkan kepadaku dari [ayahnya], ia berkata; saya mendengar [Mahmud bin Labid] berkata; Rasulullah shallallahu 'alaihi wasallam diberi kabar mengenai seseorang yang menceraikan istrinya dengan tiga kali cerai sekaligus. Maka beliau berdiri dalam keadaan marah, kemudian bersabda: \"Apakah ia mempermainkan Kitab Allah sedangkan aku berada diantara kalian, \" hingga seseorang berdiri dan berkata; ya Rasulullah bolehkan aku membunuhnya."},"3257":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ قَالَ حَدَّثَنِي ابْنُ شِهَابٍ أَنَّ سَهْلَ بْنَ سَعْدٍ السَّاعِدِيَّ أَخْبَرَهُأَنَّ عُوَيْمِرًا الْعَجْلَانِيَّ جَاءَ إِلَى عَاصِمِ بْنِ عَدِيٍّ فَقَالَ أَرَأَيْتَ يَا عَاصِمُ لَوْ أَنَّ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَيَقْتُلُونَهُ أَمْ كَيْفَ يَفْعَلُ سَلْ لِي يَا عَاصِمُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ ذَلِكَ فَسَأَلَ عَاصِمٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسَائِلَ وَعَابَهَا حَتَّى كَبُرَ عَلَى عَاصِمٍ مَا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَجَعَ عَاصِمٌ إِلَى أَهْلِهِ جَاءَهُ عُوَيْمِرٌ فَقَالَ يَا عَاصِمُ مَاذَا قَالَ لَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَاصِمٌ لِعُوَيْمِرٍ لَمْ تَأْتِنِي بِخَيْرٍ قَدْ كَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسْأَلَةَ الَّتِي سَأَلْتَ عَنْهَا فَقَالَ عُوَيْمِرٌ وَاللَّهِ لَا أَنْتَهِي حَتَّى أَسْأَلَ عَنْهَا رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَقْبَلَ عُوَيْمِرٌ حَتَّى أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسْطَ النَّاسِ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ رَجُلًا وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَقْتُلُونَهُ أَمْ كَيْفَ يَفْعَلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ نَزَلَ فِيكَ وَفِي صَاحِبَتِكَ فَاذْهَبْ فَأْتِ بِهَا قَالَ سَهْلٌ فَتَلَاعَنَا وَأَنَا مَعَ النَّاسِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا فَرَغَ عُوَيْمِرٌ قَالَ كَذَبْتُ عَلَيْهَا يَا رَسُولَ اللَّهِ إِنْ أَمْسَكْتُهَا فَطَلَّقَهَا ثَلَاثًا قَبْلَ أَنْ يَأْمُرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah], ia berkata; telah menceritakan kepada kami [Ibnu Al Qasim] dari [Malik], ia berkata; telah menceritakan kepadaku [Ibnu Syihab] bahwa [Sahl bin Sa'd As Sa'idi] telah mengabarkan kepadanya bahwa 'Uwaimir Al 'Ajalani datang kepada 'Ashim bin Adi kemudian berkata; bagaimana pendapatmu wahai 'Ashim, seandainya seorang laki-laki mendapatkan bersama isterinya terdapat seorang laki-laki? Apakah ia membunuhnya kemudian orang-orang membunuhnya, atau bagaimana ia berbuat? Wahai 'Ashim, Tanyakan kepada Rasulullah shallallahu 'alaihi wasallam mengenai hal tersebut. Kemudian 'Ashim bertanya kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau tidak menyukai masalah-masalah tersebut, dan mencelanya, hingga terasa berat hal tersebut bagi 'Ashim apa yang ia dengar dari Rasulullah shallallahu 'alaihi wasallam. Kemudian tatkala 'Ashim kembali kepada keluarganya datanglah 'Uwaimir kepadanya dan berkata; wahai 'Ashim, apa yang dikatakan Rasulullah shallallahu 'alaihi wasallam kepadamu? Kemudian 'Ashim berkata kepada 'Uwaimir; engkau tidak datang kepadaku dengan kebaikan, sungguh Rasulullah shallallahu 'alaihi wasallam tidak menyukai permasalahan yang engkau tanyakan. Kemudian 'Uwaimir berkata; demi Allah, saya tidak akan berhenti hingga menanyakannya kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian 'Uwaimir datang kepada Rasulullah shallallahu 'alaihi wasallam di tengah orang-orang. Kemudian ia berkata; wahai Rasulullah, bagaimana pendapat anda mengenai seorang laki-laki yang mendapatkan bersama isterinya terdapat laki-laki yang lain, apakah ia membunuhnya dan orang-orang membunuhnya atau bagaimana ia berbuat? Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh telah turun wahyu mengenaimu dan isterimu. Pergi dan bawalah dia.\" Sahl berkata; kemudian mereka berdua saling melaknat, dan saya bersama orang-orang yang lain berada di sisi Rasulullah shallallahu 'alaihi wasallam. Kemudian tatkala 'Uwaimir selesai, ia berkata; wahai Rasulullah, saya telah berdusta apabila saya menahannya. Kemudian ia menceraikan isterinya sebanyak tiga kali talak sebelum Rasulullah shallallahu 'alaihi wasallam memerintahkannya. "},"3258":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ يَحْيَى قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سَعِيدُ بْنُ يَزِيدَ الْأَحْمَسِيُّ قَالَ حَدَّثَنَا الشَّعْبِيُّ قَالَ حَدَّثَتْنِي فَاطِمَةُ بِنْتُ قَيْسٍ قَالَتْأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أَنَا بِنْتُ آلِ خَالِدٍ وَإِنَّ زَوْجِي فُلَانًا أَرْسَلَ إِلَيَّ بِطَلَاقِي وَإِنِّي سَأَلْتُ أَهْلَهُ النَّفَقَةَ وَالسُّكْنَى فَأَبَوْا عَلَيَّ قَالُوا يَا رَسُولَ اللَّهِ إِنَّهُ قَدْ أَرْسَلَ إِلَيْهَا بِثَلَاثِ تَطْلِيقَاتٍ قَالَتْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا النَّفَقَةُ وَالسُّكْنَى لِلْمَرْأَةِ إِذَا كَانَ لِزَوْجِهَا عَلَيْهَا الرَّجْعَةُ","id":"Telah mengabarkan kepada kami [Ahmad bin Yahya], ia berkata; telah menceritakan kepada kami [Abu Nu'aim], ia berkata; telah menceritakan kepada kami [Sa'id bin Yazid Al Ahmasi], ia berkata; telah menceritakan kepada kami [Asy Sya'bi], ia berkata; telah menceritakan kepadaku [Fathimah binti Qais], ia berkata; saya datang kepada Nabi shallallahu 'alaihi wasallam dan berkata; saya adalah anak Ali Khalid, dan suamiku Fulan telah mengirimkan utusan kepadaku untuk menceraikanku, dan saya meminta nafkah dan tempat tinggal kepada keluarganya. Kemudian mereka menolak. Mereka berkata; wahai Rasulullah, sesungguhnya ia telah mengirimkan utusan kepadanya untuk mencerainya tiga kali. Fathimah berkata; kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya nafkah dan tempat tinggal untuk seorang wanita apabila suaminya memiliki hak untuk kembali kepadanya.\""},"3259":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سَلَمَةَ عَنْ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمُطَلَّقَةُ ثَلَاثًا لَيْسَ لَهَا سُكْنَى وَلَا نَفَقَةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar], ia berkata; telah menceritakan kepada kami [Abdur Rahman], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Salamah] dari [Asy Sya'bi] dari [Fathimah binti Qais] dari Nabi shallallahu 'alaihi wasallam; seorang wanita yang diceraikan tiga kali tidak mendapatkan tempat tinggal dan nafkah. "},"3260":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ أَبِي عَمْرٍو وَهُوَ الْأَوْزَاعِيُّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنِي أَبُو سَلَمَةَ قَالَ حَدَّثَتْنِي فَاطِمَةُ بِنْتُ قَيْسٍأَنَّ أَبَا عَمْرِو بْنَ حَفْصٍ الْمَخْزُومِيَّ طَلَّقَهَا ثَلَاثًا فَانْطَلَقَ خَالِدُ بْنُ الْوَلِيدِ فِي نَفَرٍ مِنْ بَنِي مَخْزُومٍ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنَّ أَبَا عَمْرِو بْنَ حَفْصٍ طَلَّقَ فَاطِمَةَ ثَلَاثًا فَهَلْ لَهَا نَفَقَةٌ فَقَالَ لَيْسَ لَهَا نَفَقَةٌ وَلَا سُكْنَى","id":"Telah mengabarkan kepada kami ['Amr bin Utsman], ia berkata; telah menceritakan kepada kami [Baqiyyah] dari [Abu 'Amr yaitu Al Auza'i], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepadaku [Abu Salamah], ia berkata; telah menceritakan kepadaku [Fathimah binti Qais] bahwa Abu 'Amr bin Hafsh Al Makhzumi telah menceraikannya sebanyak tiga kali, kemudian Khalid bin Walid pergi bersama beberapa orang dari Bani Makhzum kepada Rasulullah shallallahu 'alaihi wasallam, dan berkata; wahai Rasulullah, sesungguhnya Abu 'Amr bin Hafsh telah menceraikan Fathimah tiga kali, apakah ia mendapatkan nafkah? Kemudian beliau bersabda: \"Ia tidak mendapatkan nafkah dan tempat tinggal.\""},"3261":{"ar":"أَخْبَرَنَا أَبُو دَاوُدَ سُلَيْمَانُ بْنُ سَيْفٍ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ عَنْ ابْنِ جُرَيْجٍ عَنْ ابْنِ طَاوُسٍ عَنْ أَبِيهِ أَنَّ أَبَا الصَّهْبَاءِجَاءَ إِلَى ابْنِ عَبَّاسٍ فَقَالَ يَا ابْنَ عَبَّاسٍ أَلَمْ تَعْلَمْ أَنَّ الثَّلَاثَ كَانَتْ عَلَى عَهْدِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبِي بَكْرٍ وَصَدْرًا مِنْ خِلَافَةِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَا تُرَدُّ إِلَى الْوَاحِدَةِ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Abu Daud Sulaiman bin Saif], ia berkata; telah menceritakan kepada kami [Abu 'Ashim] dari [Ibnu Juraij] dari [Ibnu Thawus] dari [ayahnya] bahwa Abu Shohba' datang menemui [Ibnu Abbas] dan berkata; wahai Ibnu Abbas, tidakkah engkau tahu bahwa tiga kali cerai terjadi dimasa Rasulullah shallallahu 'alaihi wasallam, Abu Bakr dan awal-awal masa kekhilafahan Umar radliallahu 'anhuma dikembalikan kepada sekali talak? Ia menjawab; ya."},"3262":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ رَجُلٍ طَلَّقَ امْرَأَتَهُ فَتَزَوَّجَتْ زَوْجًا غَيْرَهُ فَدَخَلَ بِهَا ثُمَّ طَلَّقَهَا قَبْلَ أَنْ يُوَاقِعَهَا أَتَحِلُّ لِلْأَوَّلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا حَتَّى يَذُوقَ الْآخَرُ عُسَيْلَتَهَا وَتَذُوقَ عُسَيْلَتَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala`], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam ditanya mengenai seorang laki-laki yang mencerai isterinya kemudian wanita tersebut menikah dengan suami yang lain. Kemudian ia menemuinya kemudian mencerainya sebelum menggaulinya. Apakah wanita tersebut halal bagi orang yang pertama? Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak, hingga orang yang lain merasakan kenikmatan wanita tersebut dan ia merasakan kenikmatan orang tersebut.\" "},"3263":{"ar":"أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ عَنْ أَبِيهِ قَالَ حَدَّثَنِي أَيُّوبُ بْنُ مُوسَى عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْجَاءَتْ امْرَأَةُ رِفَاعَةَ الْقُرَظِيِّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي نَكَحْتُ عَبْدَ الرَّحْمَنِ بْنَ الزَّبِيرِ وَاللَّهِ مَا مَعَهُ إِلَّا مِثْلُ هَذِهِ الْهُدْبَةِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَعَلَّكِ تُرِيدِينَ أَنْ تَرْجِعِي إِلَى رِفَاعَةَ لَا حَتَّى يَذُوقَ عُسَيْلَتَكِ وَتَذُوقِي عُسَيْلَتَهُ","id":"Telah mengabarkan kepada kami [Abdur Rahman bin Abdullah bi Abdul Hakam], Ia berkata; telah menceritakan kepada kami [Syu'aib bin Al Laits] dari [ayahnya], ia berkata; telah menceritakan kepadaku [Ayyub bin Musa] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah], ia berkata; telah datang isteri Rifa'ah Al Qurazhi kepada Rasulullah shallallahu 'alaihi wasallam dan berkata; wahai Rasulullah, saya menikah dengan Abdur Rahman bin Az Zubair, demi Allah ia tidak memiliki kemampuan kecuali seperti ujung baju ini. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kemungkinan engkau ingin kembali kepada Rifa'ah. Tidak, hingga ia merasakan kenikmatanmu dan engkau merasakan kenikmatannya.\""},"3264":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْجَاءَتْ امْرَأَةُ رِفَاعَةَ الْقُرَظِيِّ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَأَبُو بَكْرٍ عِنْدَهُ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنِّي كُنْتُ تَحْتَ رِفَاعَةَ الْقُرَظِيِّ فَطَلَّقَنِي الْبَتَّةَ فَتَزَوَّجْتُ عَبْدَ الرَّحْمَنِ بْنَ الزَّبِيرِ وَإِنَّهُ وَاللَّهِ يَا رَسُولَ اللَّهِ مَا مَعَهُ إِلَّا مِثْلُ هَذِهِ الْهُدْبَةِ وَأَخَذَتْ هُدْبَةً مِنْ جِلْبَابِهَا وَخَالِدُ بْنُ سَعِيدٍ بِالْبَابِ فَلَمْ يَأْذَنْ لَهُ فَقَالَ يَا أَبَا بَكْرٍ أَلَا تَسْمَعُ هَذِهِ تَجْهَرُ بِمَا تَجْهَرُ بِهِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ تُرِيدِينَ أَنْ تَرْجِعِي إِلَى رِفَاعَةَ لَا حَتَّى تَذُوقِي عُسَيْلَتَهُ وَيَذُوقَ عُسَيْلَتَكِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yazid bin Zurai'], ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], ia berkata; telah datang isteri Rifa'ah Al Qurazhi kepada Nabi shallallahu 'alaihi wasallam dan Abu Bakr ada di sisi beliau. Ia berkata; wahai Rasulullah, sesungguhnya saya dahulu dibawah naungan Rifa'ah Al Qurazhi, kemudian ia menceraiku sama sekali. Kemudian saya menikah dengan Abdur Rahman bin Az Zubair, dan demi Allah wahai Rasulullah, ia tidak memiliki kemampuan kecuali seperti ujung pakaian ini. Dan ia mengambil ujung jilbabnya, dan Khalid bin Sa'id ada di depan pintu, dan Rasulullah shallallahu 'alaihi wasallam tidak mengizinkannya masuk. Kemudian beliau bersabda: \"wahai Abu Bakr, tidakkah engkau mendengar wanita ini berkata keji dengan apa yang ia katakan di sisi Rasulullah shallallahu 'alaihi wasallam?\" Kemudian beliau bersabda: \"Apakah engkau ingin kembali kepada Rifa'ah? Tidak, hingga engkau merasakan kenikmatannya dan ia merasakan kenikmatanmu.\" "},"3265":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ نَصْرِ بْنِ عَلِيٍّ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ قَالَ قُلْتُ لِأَيُّوبَ هَلْ عَلِمْتَ أَحَدًا قَالَ فِي أَمْرِكِ بِيَدِكِ أَنَّهَا ثَلَاثٌ غَيْرَ الْحَسَنِ فَقَالَ لَا ثُمَّ قَالَ اللَّهُمَّ غَفْرًا إِلَّا مَا حَدَّثَنِي قَتَادَةُ عَنْ كَثِيرٍ مَوْلَى ابْنِ سَمُرَةَ عَنْ أَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ثَلَاثٌفَلَقِيتُ كَثِيرًا فَسَأَلْتُهُ فَلَمْ يَعْرِفْهُ فَرَجَعْتُ إِلَى قَتَادَةَ فَأَخْبَرْتُهُ فَقَالَ نَسِيَ قَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا حَدِيثٌ مُنْكَرٌ","id":"Telah mengabarkan kepada kami [Ali bin Nadhr bin Ali], ia berkata; telah menceritakan kepada kami [Sulaiman bin Harb], ia berkata; telah menceritakan kepada kami [Hammad bin Zaid], ia berkata; aku berkata kepada [Ayyub]; apakah engkau tahu seseorang yang berkata; \"mengenai urusanmu ada di tanganmu\". Bahwa hal tersebut merupakan talak tiga kali selain Hasan? Ia berkata tidak, kemudian ia berkata; ya Allah ampunilah, kecuali apa yang dikatakan [Qotadah] kepadaku dari [Katsir] mantan budak Ibnu Samurah dari [Abu Salamah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \" Tiga kali, \" lalu aku bertemu dengan Katsir lalu bertanya kepadanya, dan ia tidak tahu, lalu aku kembali kepada Qotadah dan aku mengkhabar kepadanya, maka ia berkata; beliau lupa. Abu Abdurrahman berkata hadis ini munkar."},"3266":{"ar":"حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْجَاءَتْ امْرَأَةُ رِفَاعَةَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ زَوْجِي طَلَّقَنِي فَأَبَتَّ طَلَاقِي وَإِنِّي تَزَوَّجْتُ بَعْدَهُ عَبْدَ الرَّحْمَنِ بْنَ الزَّبِيرِ وَمَا مَعَهُ إِلَّا مِثْلُ هُدْبَةِ الثَّوْبِ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ لَعَلَّكِ تُرِيدِينَ أَنْ تَرْجِعِي إِلَى رِفَاعَةَ لَا حَتَّى يَذُوقَ عُسَيْلَتَكِ وَتَذُوقِي عُسَيْلَتَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], ia berkata; telah datang isteri Rifa'ah kepada Rasulullah shallallahu 'alaihi wasallam, dan berkata; sesungguhnya suamiku telah menceraiku sama sekali, dan saya menikah dengan Abdur Rahman bin Az Zubair setelahnya, dan ia tidak memiliki kemampuan kecuali seperti ujung pakaian ini. Kemudian Rasulullah shallallahu 'alaihi wasallam tertawa, dan bersabda: \"Kemungkinan engkau ingin kembali kepada Rifa'ah, tidak hingga ia merasakan kenikmatanmu dan engkau merasakan kenikmatannya.\""},"3267":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنِي عُبَيْدُ اللَّهِ قَالَ حَدَّثَنِي الْقَاسِمُ عَنْ عَائِشَةَأَنَّ رَجُلًا طَلَّقَ امْرَأَتَهُ ثَلَاثًا فَتَزَوَّجَتْ زَوْجًا فَطَلَّقَهَا قَبْلَ أَنْ يَمَسَّهَا فَسُئِلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَحِلُّ لِلْأَوَّلِ فَقَالَ لَا حَتَّى يَذُوقَ عُسَيْلَتَهَا كَمَا ذَاقَ الْأَوَّلُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna], ia berkata; telah menceritakan kepada kami [Yahya], ia berkata; telah menceritakan kepadaku ['Ubaidullah], ia berkata; telah menceritakan kepadaku [Al Qasim] dari [Aisyah] bahwa seorang laki-laki menceraikan isterinya tiga kali talak, kemudian ia menikah dengan suami yang lain, kemudian ia menceraikannya sebelum menyentuhnya. Lalu Rasulullah shallallahu 'alaihi wasallam ditanya apakah wanita tersebut halal bagi orang yang pertama? Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak, hingga ia merasakan kenikmatan wanita tersebut sebagaimana orang pertama merasakan.\""},"3268":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا هُشَيْمٌ قَالَ أَنْبَأَنَا يَحْيَى بْنُ أَبِي إِسْحَقَ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍأَنَّ الْغُمَيْصَاءَ أَوْ الرُّمَيْصَاءَ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَشْتَكِي زَوْجَهَا أَنَّهُ لَا يَصِلُ إِلَيْهَا فَلَمْ يَلْبَثْ أَنْ جَاءَ زَوْجُهَا فَقَالَ يَا رَسُولَ اللَّهِ هِيَ كَاذِبَةٌ وَهُوَ يَصِلُ إِلَيْهَا وَلَكِنَّهَا تُرِيدُ أَنْ تَرْجِعَ إِلَى زَوْجِهَا الْأَوَّلِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَيْسَ ذَلِكَ حَتَّى تَذُوقِي عُسَيْلَتَهُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr], ia berkata; telah memberitakan kepada kami [Husyaim], ia berkata; telah memberitakan kepada kami [Yahya bin Abi Ishaq] dari [Sulaiman bin Yasar] dari ['Ubaidullah bin Abbas] bahwa Ar Rumaisha` datang kepada Nabi shallallahu 'alaihi wasallam mengeluhkan suaminya bahwa ia tidak menghubunginya. Tidak lama kemudian suaminya datang dan berkata; wahai Rasulullah, ia berdusta. Suaminya menghubunginya akan tetapi ia ingin kembali kepada suaminya yang pertama. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh demikian, hingga engkau merasakan kenikmatannya.\""},"3269":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ قَالَ سَمِعْتُ سَالِمَ بْنَ رَزِينٍ يُحَدِّثُ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ ابْنِ عُمَرَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي الرَّجُلِ تَكُونُ لَهُ الْمَرْأَةُ يُطَلِّقُهَا ثُمَّ يَتَزَوَّجُهَا رَجُلٌ آخَرُ فَيُطَلِّقُهَا قَبْلَ أَنْ يَدْخُلَ بِهَا فَتَرْجِعَ إِلَى زَوْجِهَا الْأَوَّلِ قَالَ لَا حَتَّى تَذُوقَ الْعُسَيْلَةَ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Muhammad bin Ja'far], ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Alqamah bin Martsad], ia berkata; saya mendengar [Salim bin Razin] menceritakan dari [Salim bin Abdullah] dari [Sa'id bin Al Musayyab] dari [Ibnu] Umar dari Nabi shallallahu 'alaihi wasallam mengenai seseorang yang memiliki isteri yang ia ceraikan kemudian wanita tersebut dinikahi laki-laki yang lain, lalu ia mencerainya sebelum menggaulinya dan ia kembali ke suaminya yang pertama. Beliau bersabda: \" Tidak boleh, sampai ia merasakan kenikmatan.\""},"3270":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَلْقَمَةَ بْنِ مَرْثَدٍ عَنْ رَزِينِ بْنِ سُلَيْمَانَ الْأَحْمَرِيِّ عَنْ ابْنِ عُمَرَ قَالَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الرَّجُلِ يُطَلِّقُ امْرَأَتَهُ ثَلَاثًا فَيَتَزَوَّجُهَا الرَّجُلُ فَيُغْلِقُ الْبَابَ وَيُرْخِي السِّتْرَ ثُمَّ يُطَلِّقُهَا قَبْلَ أَنْ يَدْخُلَ بِهَا قَالَ لَا تَحِلُّ لِلْأَوَّلِ حَتَّى يُجَامِعَهَا الْآخَرُقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا أَوْلَى بِالصَّوَابِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] telah menceritakan kepada kami [Waki'], ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Alqamah bin Martsad] dari [Razin bin Sulaiman Al Ahmari] dari [Ibnu Umar], ia berkata; Nabi shallallahu 'alaihi wasallam ditanya mengenai seorang laki-laki yang mencerai isterinya tiga kali, kemudian wanita tersebut dinikahi laki-laki yang lain, kemudian menutup pintu dan mengulurkan tabir, kemudian mencerainya sebelum menggaulinya. Maka beliau bersabda: \"Ia tidak halal bagi orang yang pertama hingga orang yang lain menggaulinya.\" Abu Abdur Rahman berkata; hal ini lebih benar."},"3271":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ عَنْ سُفْيَانَ عَنْ أَبِي قَيْسٍ عَنْ هُزَيْلٍ عَنْ عَبْدِ اللَّهِ قَالَلَعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَاشِمَةَ وَالْمُوتَشِمَةَ وَالْوَاصِلَةَ وَالْمَوْصُولَةَ وَآكِلَ الرِّبَا وَمُوكِلَهُ وَالْمُحَلِّلَ وَالْمُحَلَّلَ لَهُ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Abu Nu'aim] dari [Sufyan] dari [Abu Qais] dari [Huzail] dari [Abdullah], ia berkata; Rasulullah shallallahu 'alaihi wasallam melaknat wanita yang mentato dan yang ditato, wanita yang menyambung rambutnya dan yang disambung rambutnya, orang yang memakan riba, wakilnya, dan orang yang menikahi isteri orang yang telah dicerai tiga talak agar menjadi halal bagi orang yang mencerai dan orang yang mencerai isterinya tiga talak dan menyewa orang lain agar menikahinya kemudian menceraikannya."},"3272":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْوَلِيدُ بْنُ مُسْلِمٍ قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ سَأَلْتُ الزُّهْرِيَّ عَنْ الَّتِي اسْتَعَاذَتْ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَخْبَرَنِي عُرْوَةُ عَنْ عَائِشَةَأَنَّ الْكِلَابِيَّةَ لَمَّا دَخَلَتْ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْ أَعُوذُ بِاللَّهِ مِنْكَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَقَدْ عُذْتِ بِعَظِيمٍ الْحَقِي بِأَهْلِكِ","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits], ia berkata; telah menceritakan kepada kami [Al Walid bin Muslim], ia berkata; telah menceritakan kepada kami [Al Auza'i], ia berkata; saya bertanya kepada [Az Zuhri] mengenai seorang wanita yang berlindung dari Rasulullah shallallahu 'alaihi wasallam, ia berkata; telah mengabarkan kepadaku ['Urwah] dari ['Aisyah] bahwasa seorang wanita dari Suku Al Kilab ketika bertatap muka dengan Nabi shallallahu 'alaihi wasallam ia berkata; aku berlindung kepada Allah darimu, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Engkau berlindung kepada Allah yang Maha Agung, kembalilah kepada keluargamu.\""},"3273":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ أَبِي بَكْرٍ وَهُوَ ابْنُ أَبِي الْجَهْمِ قَالَ سَمِعْتُ فَاطِمَةَ بِنْتَ قَيْسٍ تَقُولُأَرْسَلَ إِلَيَّ زَوْجِي بِطَلَاقِي فَشَدَدْتُ عَلَيَّ ثِيَابِي ثُمَّ أَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كَمْ طَلَّقَكِ فَقُلْتُ ثَلَاثًا قَالَ لَيْسَ لَكِ نَفَقَةٌ وَاعْتَدِّي فِي بَيْتِ ابْنِ عَمِّكِ ابْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ ضَرِيرُ الْبَصَرِ تُلْقِينَ ثِيَابَكِ عِنْدَهُ فَإِذَا انْقَضَتْ عِدَّتُكِ فَآذِنِينِي مُخْتَصَرٌأَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ تَمِيمٍ مَوْلَى فَاطِمَةَ عَنْ فَاطِمَةَ نَحْوَهُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'i], ia berkata; telah menceritakan kepada kami [Abdur Rahman] dari [Sufyan] dari [Abu Bakr yaitu Ibnu Abi Al Jahm], ia berkata; saya pernah mendengar [Fathimah binti Qais] berkata; suamiku mengirim utusan kepadaku untuk menceraiku. Lalu saya kencangkan pakaianku kemudian kudatangi Nabi shallallahu 'alaihi wasallam. Lalu beliau bertanya: \"Berapakah ia menceraimu?\" kemudian saya katakan; tiga talak. Beliau bersabda: \"Engkau tidak mendapatkan nafkah, ber'iddahlah di rumah pamanmu yaitu Ibnu Ummi Maktum, ia adalah orang yang buta. Engkau bisa melepas pakaianmu di rumahnya. Kemudian apabila telah habis 'iddahmu maka beritahukan kepadaku.\" Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami ['Abdur Rahman] dari [Sufyan] dari [Manshur] dari [Mujahid] dari [Tamim maula Fathimah] dari [Fathimah] seperti itu. "},"3274":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ عَبْدِ الصَّمَدِ بْنِ عَلِيٍّ الْمَوْصِلِيُّ قَالَ حَدَّثَنَا مَخْلَدٌ عَنْ سُفْيَانَ عَنْ سَالِمٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ قَالَأَتَاهُ رَجُلٌ فَقَالَ إِنِّي جَعَلْتُ امْرَأَتِي عَلَيَّ حَرَامًا قَالَ كَذَبْتَ لَيْسَتْ عَلَيْكَ بِحَرَامٍ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ يَا أَيُّهَا النَّبِيُّ لِمَ تُحَرِّمُ مَا أَحَلَّ اللَّهُ لَكَ }عَلَيْكَ أَغْلَظُ الْكَفَّارَةِ عِتْقُ رَقَبَةٍ","id":"Telah mengabarkan kepada kami [Abdullah bin Abdush Shamad bin Ali Al Mushili], ia berkata; telah menceritakan kepada kami [Makhlad] dari [Sufyan] dari [Salim] dari [Sa'id bin Jubair] dari [Ibnu Abbas], ia berkata; telah datang kepadanya seorang laki-laki dan berkata; saya telah menjadikan istriku haram atas diriku. Ia berkata; engkau berdusta, ia tidak haram atas dirimu. Kemudian ia membaca ayat ini Hai Nabi kenapa engkau haramkan apa yang Allah halalkan kepadamu. Engkau wajib membayar kafarah yang terberat yaitu memerdekakan budak."},"3275":{"ar":"أَخْبَرَنَا قُتَيْبَةُ عَنْ حَجَّاجٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ أَنَّهُ سَمِعَ عُبَيْدَ بْنَ عُمَيْرٍ قَالَ سَمِعْتُ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ يَمْكُثُ عِنْدَ زَيْنَبَ وَيَشْرَبُ عِنْدَهَا عَسَلًا فَتَوَاصَيْتُ وَحَفْصَةُ أَيَّتُنَا مَا دَخَلَ عَلَيْهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلْتَقُلْ إِنِّي أَجِدُ مِنْكَ رِيحَ مَغَافِيرَ فَدَخَلَ عَلَى إِحْدَيْهِمَا فَقَالَتْ ذَلِكَ لَهُ فَقَالَ بَلْ شَرِبْتُ عَسَلًا عِنْدَ زَيْنَبَ وَقَالَ لَنْ أَعُودَ لَهُ فَنَزَلَ{ يَا أَيُّهَا النَّبِيُّ لِمَ تُحَرِّمُ مَا أَحَلَّ اللَّهُ لَكَ }{ إِنْ تَتُوبَا إِلَى اللَّهِ }لِعَائِشَةَ وَحَفْصَةَ{ وَإِذْ أَسَرَّ النَّبِيُّ إِلَى بَعْضِ أَزْوَاجِهِ حَدِيثًا }لِقَوْلِهِ بَلْ شَرِبْتُ عَسَلًاكُلُّهُ فِي حَدِيثِ عَطَاءٍ","id":"Telah mengabarkan kepada kami [Qutaibah] dari [Hajjaj] dari [Ibnu Juraij] dari ['Atho`] bahwa ia mendengar ['Ubaid bin 'Umair], ia berkata; saya mendengar [Aisyah] isteri Nabi shallallahu 'alaihi wasallam bahwa Nabi shallallahu 'alaihi wasallam pernah tinggal di rumah Zainab, dan minum madu di rumahnya. Kemudian saya dan Hafshah bersepakat apabila Nabi shallallahu 'alaihi wasallam menemui salah seorang dari kami maka hendaknya ia mengatakan; sesungguhnya saya mendapatkan bau Maghafir. Lalu beliau menemui salah seorang dari mereka berdua, kemudian ia mengatakan hal tersebut kepadanya. Kemudian beliau bersabda: \"Melainkan saya minum madu di rumah Zainab.\" Dan beliau bersabda: \"Saya tidak akan kembali untuk melakukannya.\" Kemudian turunlah ayat: 'Hai Nabi kenapa engkau haramkan apa yang Allah halalkan kepadamu'. 'Jika kamu berdua bertaubat kepada Allah' untuk Aisyah dan Hafshah. Dan Allah menurunkan ayat 'Dan ingatlah ketika Nabi membicarakan secara rahasia kepada salah seorang isterinya (Hafsah) suatu peristiwa' atas ucapan beliau: \"Melainkan saya minum madu.\" Seluruhnya ada dalam hadis 'Atho`. "},"3276":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ نُعَيْمٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مَكِّيِّ بْنِ عِيسَى قَالَ حَدَّثَنَا عَبْدُ اللَّهِ قَالَ حَدَّثَنَا يُونُسُ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍ يُحَدِّثُ حَدِيثَهُ حِينَ تَخَلَّفَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ وَقَالَ فِيهِ إِذَا رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِينِي فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ح و أَخْبَرَنِي سُلَيْمَانُ بْنُ دَاوُدَ قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ عَنْ يُونُسَ قَالَ ابْنُ شِهَابٍ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبِ بْنِ مَالِكٍ قَالَ سَمِعْتُ كَعْبَ بْنَ مَالِكٍيُحَدِّثُ حَدِيثَهُ حِينَ تَخَلَّفَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ وَسَاقَ قِصَّتَهُ وَقَالَ إِذَا رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِي فَقَالَ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكَ أَنْ تَعْتَزِلَ امْرَأَتَكَ فَقُلْتُ أُطَلِّقُهَا أَمْ مَاذَا قَالَ لَا بَلْ اعْتَزِلْهَا فَلَا تَقْرَبْهَا فَقُلْتُ لِامْرَأَتِي الْحَقِي بِأَهْلِكِ فَكُونِي عِنْدَهُمْ حَتَّى يَقْضِيَ اللَّهُ عَزَّ وَجَلَّ فِي هَذَا الْأَمْرِ","id":"Telah mengabarkan kepada kami [Muhammad bin Hatim bin Nu'aim], ia berkata; telah menceritakan kepada kami [Muhammad bin Makki bin Isa], ia berkata; telah menceritakan kepada kami [Abdullah], ia berkata; telah menceritakan kepada kami [Yunus] dari [Az Zuhri] dari [Abdur Rahman bin Abdullah bin Ka'b bin Malik], ia berkata; saya mendengar [Ka'b bin Malik] menceritakan peristiwanya ketika tertinggal dari Rasulullah shallallahu 'alaihi wasallam dalam perang Tabuk. Ia berkata padanya; tiba-tiba utusan Rasulullah shallallahu 'alaihi wasallam datang kepadaku kemudian berkata; Rasulullah shallallahu 'alaihi wasallam -dengan jalur periwayatan lain-Dan telah mengabarkan kepadaku [Sulaiman bin Daud], ia berkata; telah memberitakan kepada kami [Ibnu Wahab] dari [Yunus], [Ibnu Syihab] berkata, telah mengabarkan kepadaku [Abdur Rahman bin Abdullah bin Ka'b bin Malik] bahwa [Abdullah bin Ka'b bin Malik] berkata; saya mendengar [Ka'b bin Malik] menceritakan peristiwanya ketika tertinggal dari Rasulullah shallallahu 'alaihi wasallam dalam perang Tabuk, dan ia menceritakan kisahnya. Ia berkata; tiba-tiba utusan Rasulullah shallallahu 'alaihi wasallam datang dan berkata \"Rasulullah shallallahu 'alaihi wasallam memerintahkanmu untuk menjauhi isterimu. Maka saya katakan; apakah saya menceraikannya atau apa? Ia berkata; tidak melainkan jauhi dia, dan jangan engkau dekati. Kemudian saya katakan kepada isteriku; kembalilah kepada keluargamu dan tinggallah bersama mereka hingga Allah 'azza wajalla memberikan keputusan mengenai perkara ini! "},"3277":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ جَبَلَةَ وَمُحَمَّدُ بْنُ يَحْيَى بْنِ مُحَمَّدٍ قَالَا حَدَّثَنَا مُحَمَّدُ بْنُ مُوسَى بْنِ أَعْيَنَ قَالَ حَدَّثَنَا أَبِي عَنْ إِسْحَقَ بْنِ رَاشِدٍ عَنْ الزُّهْرِيِّ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَ سَمِعْتُ أَبِي كَعْبَ بْنَ مَالِكٍ قَالَ وَهُوَ أَحَدُ الثَّلَاثَةِ الَّذِينَ تِيبَ عَلَيْهِمْ يُحَدِّثُ قَالَأَرْسَلَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِلَى صَاحِبَيَّ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكُمْ أَنْ تَعْتَزِلُوا نِسَاءَكُمْ فَقُلْتُ لِلرَّسُولِ أُطَلِّقُ امْرَأَتِي أَمْ مَاذَا أَفْعَلُ قَالَ لَا بَلْ تَعْتَزِلُهَا فَلَا تَقْرَبْهَا فَقُلْتُ لِامْرَأَتِي الْحَقِي بِأَهْلِكِ فَكُونِي فِيهِمْ فَلَحِقَتْ بِهِمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Jabalah] dan [Muhammad bin Yahya bin Muhammad] mereka berkata; telah menceritakan kepada kami [Muhammad bin Musa bin A'yan], ia berkata; telah menceritakan kepada kami [ayahku] dari [Ishaq bin Rasyid] dari [Az Zuhri] telah mengabarkan kepadaku [Abdur Rahman bin Abdullah bin Ka'b bin Malik] dari [ayahnya], ia berkata; saya mendengar ayahku yaitu [Ka'b bin Malik] -dan ia adalah salah satu dari tiga orang yang diberi taubat- bercerita, ia berkata; Rasulullah shallallahu 'alaihi wasallam mengirim utusan kepadaku dan kedua orang sahabatku mengatakan; Rasulullah shallallahu 'alaihi wasallam memerintahkan kalian agar menjauhi isteri-isteri kalian. Kemudian saya katakan kepada utusan tersebut; saya cerai isteriku atau apa yang saya lakukan? Ia berkata; tidak, melainkan engkau menjauhinya dan jangan mendekatinya. Lalu saya katakan kepada isteriku; kembalilah kepada keluargamu, dan tinggallah bersama mereka. Dan iapun kembali kepada mereka. "},"3278":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا اللَّيْثُ بْنُ سَعْدٍ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبٍ أَنَّ عَبْدَ اللَّهِ بْنَ كَعْبٍ قَالَ سَمِعْتُ كَعْبًايُحَدِّثُ حَدِيثَهُ حِينَ تَخَلَّفَ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي غَزْوَةِ تَبُوكَ وَقَالَ فِيهِ إِذَا رَسُولُ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْتِينِي وَيَقُولُ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكَ أَنْ تَعْتَزِلَ امْرَأَتَكَ فَقُلْتُ أُطَلِّقُهَا أَمْ مَاذَا أَفْعَلُ قَالَ بَلْ اعْتَزِلْهَا وَلَا تَقْرَبْهَا وَأَرْسَلَ إِلَى صَاحِبَيَّ بِمِثْلِ ذَلِكَ فَقُلْتُ لِامْرَأَتِي الْحَقِي بِأَهْلِكِ وَكُونِي عِنْدَهُمْ حَتَّى يَقْضِيَ اللَّهُ عَزَّ وَجَلَّ فِي هَذَا الْأَمْرِخَالَفَهُمْ مَعْقِلُ بْنُ عُبَيْدِ اللَّهِ","id":"Telah mengabarkan kepada kami [Yusuf bin Sa'id], ia berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad], ia berkata; telah menceritakan kepada kami [Al Laits bin Sa'd], ia berkata; telah menceritakan kepadaku ['Uqail] dari [Ibnu Syihab], ia berkata; telah mengabarkan kepadaku [Abdur Rahman bin Abdullah bin Ka'b] bahwa [Abdullah bin Ka'b] berkata; saya mendengar [Ka'ab] menceritakan peristiwanya ketika tertinggal dari Rasulullah shallallahu 'alaihi wasallam pada perang Tabuk, dan ia berkata mengenainya; tiba-tiba utusan Rasulullah shallallahu 'alaihi wasallam datang kepadaku dan berkata; Rasulullah shallallahu 'alaihi wasallam memerintahkanmu agar menjauhi isterimu. Lalu saya katakan; saya menceraikannya atau apa yang saya lakukan? Ia berkata; melainkan jauhilah ia dan jangan engkau dekati. Dan beliau mengirim kepada kedua sahabatku dengan hal seperti itu. Kemudian saya katakan kepada isteri saya; kembalilah kepada keluargamu, dan tinggallah bersama mereka hingga Allah 'azza wajalla memberikan keputusan mengenai perkara ini. Ma'qil bin 'Ubaidullah menyelisihi mereka. "},"3279":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْدَانَ بْنِ عِيسَى قَالَ حَدَّثَنَا الْحَسَنُ بْنُ أَعْيَنَ قَالَ حَدَّثَنَا مَعْقِلٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَبْدِ اللَّهِ بْنِ كَعْبٍ عَنْ عَمِّهِ عُبَيْدِ اللَّهِ بْنِ كَعْبٍ قَالَ سَمِعْتُ أَبِي كَعْبًا يُحَدِّثُ قَالَأَرْسَلَ إِلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِلَى صَاحِبَيَّ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَأْمُرُكُمْ أَنْ تَعْتَزِلُوا نِسَاءَكُمْ فَقُلْتُ لِلرَّسُولِ أُطَلِّقُ امْرَأَتِي أَمْ مَاذَا أَفْعَلُ قَالَ لَا بَلْ تَعْتَزِلُهَا وَلَا تَقْرَبْهَا فَقُلْتُ لِامْرَأَتِي الْحَقِي بِأَهْلِكِ فَكُونِي فِيهِمْ حَتَّى يَقْضِيَ اللَّهُ عَزَّ وَجَلَّ فَلَحِقَتْ بِهِمْخَالَفَهُ مَعْمَرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'dan bin Isa], ia berkata; telah menceritakan kepada kami [Al Hasan bin A'yan], ia berkata; telah menceritakan kepada kami [Ma'qil] dari [Az Zuhri], ia berkata; telah mengabarkan kepadaku [Abdur Rahman bin Abdullah bin Ka'b] dari pamannya yaitu ['Ubaidullah bin Ka'b], ia berkata; saya mendengar ayahku yaitu [Ka'ab] menceritakan, ia berkata; Rasulullah mengirimkan utusan kepadaku dan kepada kedua sahabatku, mengatakan; Rasulullah shallallahu 'alaihi wasallam memerintahkan kalian agar menjauhi isteri -isteri kalian. Kemudian saya katakan kepada utusan tersebut; apakah saya mencerai isteriku atau apa yang saya lakukan? Ia berkata; tidak, melainkan engkau jauhi dan jangan engkau mendekatinya. Lalu saya katakan kepada isteriku; kembalilah kepada isterimu dan tinggallah bersama mereka hingga Allah 'azza wajalla memberikan keputusan. Maka iapun kembali kepada mereka. Ma'mar menyelisihi hadis tersebut. "},"3280":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُحَمَّدٌ وَهُوَ ابْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عَبْدِ الرَّحْمَنِ بْنِ كَعْبِ بْنِ مَالِكٍ عَنْ أَبِيهِ قَالَ فِي حَدِيثِهِإِذَا رَسُولٌ مِنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَتَانِي فَقَالَ اعْتَزِلْ امْرَأَتَكَ فَقُلْتُ أُطَلِّقُهَا قَالَ لَا وَلَكِنْ لَا تَقْرَبْهَاوَلَمْ يَذْكُرْ فِيهِ الْحَقِي بِأَهْلِكِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Muhammad yaitu Ibnu Tsaur] dari [Ma'mar] dari [Az Zuhri] dari [Abdur Rahman bin Ka'b bin Malik] dari [ayahnya], ia berkata mengenai peristiwanya; tiba-tiba utusan dari Nabi shallallahu 'alaihi wasallam datang kepadaku dan berkata; jauhilah isterimu. Kemudian saya katakan; apakah saya mencerainya? Ia berkata; tidak akan tetapi janganlah engkau mendekatinya. Dan ia tidak menyebutkan kata; kembalilah kepada keluargamu. "},"3281":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ سَمِعْتُ يَحْيَى قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ عَنْ عُمَرَ بْنِ مُعَتِّبٍ أَنَّ أَبَا حَسَنٍ مَوْلَى بَنِي نَوْفَلٍ أَخْبَرَهُ قَالَكُنْتُ أَنَا وَامْرَأَتِي مَمْلُوكَيْنِ فَطَلَّقْتُهَا تَطْلِيقَتَيْنِ ثُمَّ أُعْتِقْنَا جَمِيعًا فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ إِنْ رَاجَعْتَهَا كَانَتْ عِنْدَكَ عَلَى وَاحِدَةٍ قَضَى بِذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَخَالَفَهُ مَعْمَرٌ","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; saya mendengar [Yahya] berkata; telah menceritakan kepada kami [Ali bin Al Mubarak], ia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] dari [Umar bin Mu'attib] bahwa [Abu Hasan] -mantan budak Bani Naufal- mengabarkan kepadanya, ia berkata; saya dan istri saya adalah budak, lalu aku menceraikannya dengan dua kali talak, lalu kami dimerdekakan. Kemudian saya bertanya kepada [Ibnu Abbas], ia berkata; apabila engkau telah ruju' kepadanya, ia bagimu masih sekali talak lagi, itulah yang diputuskan Rasulullah shallallahu 'alaihi wasallam. Ma'mar menyelisihi hadis tersebut."},"3282":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا مَعْمَرٌ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ عَنْ عُمَرَ بْنِ مُعَتِّبٍ عَنْ الْحَسَنِ مَوْلَى بَنِي نَوْفَلٍ قَالَ سُئِلَ ابْنُ عَبَّاسٍعَنْ عَبْدٍ طَلَّقَ امْرَأَتَهُ تَطْلِيقَتَيْنِ ثُمَّ عُتِقَا أَيَتَزَوَّجُهَا قَالَ نَعَمْ قَالَ عَمَّنْ قَالَ أَفْتَى بِذَلِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَقَالَ عَبْدُ الرَّزَّاقِ قَالَ ابْنُ الْمُبَارَكِ لِمَعْمَرٍ الْحَسَنُ هَذَا مَنْ هُوَ لَقَدْ حَمَلَ صَخْرَةً عَظِيمَةً","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'], ia berkata; telah menceritakan kepada kami [Abdur Razzaq], ia berkata; telah memberitakan kepada kami [Ma'mar] dari [Yahya bin Abu Katsir] dari [Umar bin Mu'attib] dari [Al Hasan] -mantan budak Bani Naufal-, ia berkata; [Ibnu Abbas] ditanya mengenai seorang sahaya yang menceraikan isterinya dengan dua kali talak. Kemudian mereka berdua dimerdekakan. Apakah ia boleh menikahinya? Ibnu Abbas berkata; ya. Ia berkata; dari siapa? Ibnu Abbas berkata; Rasulullah shallallahu 'alaihi wasallam telah berfatwa dengan hal seperti itu. Abdur Razzaq berkata; berkata Ibnu Al Mubarak kepada Ma'mar; Al Hasan ini siapa? Sungguh ia telah memikul batu besar. "},"3283":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَسَدُ بْنُ مُوسَى قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ أَبِي جَعْفَرٍ الْخَطْمِيِّ عَنْ عُمَارَةَ بْنِ خُزَيْمَةَ عَنْ كَثِيرِ بْنِ السَّائِبِ قَالَ حَدَّثَنِي ابْنَا قُرَيْظَةَأَنَّهُمْ عُرِضُوا عَلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ قُرَيْظَةَ فَمَنْ كَانَ مُحْتَلِمًا أَوْ نَبَتَتْ عَانَتُهُ قُتِلَ وَمَنْ لَمْ يَكُنْ مُحْتَلِمًا أَوْ لَمْ تَنْبُتْ عَانَتُهُ تُرِكَ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman], ia berkata; telah menceritakan kepada kami [Asad bin Musa], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Abu Ja'far Al Khathmi] dari ['Umarah bin Khuzaimah] dari [Katsir bin As Saib], ia berkata; telah menceritakan kepadaku [dua anak Quraizhah] bahwa mereka dihadapkan kepada Rasulullah shallallahu 'alaihi wasallam pada saat perang bani Quraizhah. Kemudian orang yang telah bermimpi atau telah tumbuh rambut kemaluannya dibunuh dan orang yang belum bermimpi atau belum tumbuh bulu kemaluannya dibiarkan. "},"3284":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ عَطِيَّةَ الْقُرَظِيِّ قَالَكُنْتُ يَوْمَ حُكْمِ سَعْدٍ فِي بَنِي قُرَيْظَةَ غُلَامًا فَشَكُّوا فِيَّ فَلَمْ يَجِدُونِي أَنْبَتُّ فَاسْتُبْقِيتُ فَهَا أَنَا ذَا بَيْنَ أَظْهُرِكُمْ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur], ia berkata; telah menceritakan kepada kami [Sufyan] dari [Abdul Malik bin 'Umair] dari ['Athiyyah Al Qurazhi], ia berkata; saya pada saat Sa'd memberikan hukum mengenai Bani Quraizhah adalah anak kecil, kemudian mereka meragukan diriku, dan mereka tidak mendapatiku telah tumbuh bulu kemaluannya, sehingga mereka membiarkanku, dan inilah saya berada diantara kalian. "},"3285":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا يَحْيَى عَنْ عُبَيْدِ اللَّهِ قَالَ أَخْبَرَنِي نَافِعٌ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَرَضَهُ يَوْمَ أُحُدٍ وَهُوَ ابْنُ أَرْبَعَ عَشْرَةَ سَنَةً فَلَمْ يُجِزْهُ وَعَرَضَهُ يَوْمَ الْخَنْدَقِ وَهُوَ ابْنُ خَمْسَ عَشْرَةَ سَنَةً فَأَجَازَهُ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Yahya] dari ['Ubaidullah], ia berkata; telah mengabarkan kepadaku [Nafi'] dari [Ibnu Umar] bahwa Rasulullah shallallahu 'alaihi wasallam mengajukan kepadanya pada saat perang Uhud dan ia berumur empat belas tahun, maka beliau tidak memperbolehkannya, dan ia mengajukan kepadanya pada saat perang Khandaq dan ia berumur lima belas tahun, maka beliau memperbolehkannya. "},"3286":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ بْنُ مَهْدِيٍّ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ حَمَّادٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ رُفِعَ الْقَلَمُ عَنْ ثَلَاثٍ عَنْ النَّائِمِ حَتَّى يَسْتَيْقِظَ وَعَنْ الصَّغِيرِ حَتَّى يَكْبُرَ وَعَنْ الْمَجْنُونِ حَتَّى يَعْقِلَ أَوْ يُفِيقَ","id":"Telah mengabarkan kepada kami [Ya'qub bin Ibrahim], ia berkata; telah menceritakan kepada kami [Abdur Rahman bin Mahdi], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Hammad] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Diangkat pena dari tiga orang, yaitu orang yang tidur hingga ia bangun, dari anak kecil hingga ia dewasa, dan dari orang yang gila hingga ia berakal atau sadar.\" "},"3287":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ الْحَسَنِ وَعَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَا حَدَّثَنَا حَجَّاجُ بْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ عَنْ عَطَاءٍ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ عَبْدُ الرَّحْمَنِ عَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ تَعَالَى تَجَاوَزَ عَنْ أُمَّتِي كُلَّ شَيْءٍ حَدَّثَتْ بِهِ أَنْفُسَهَا مَا لَمْ تَكَلَّمْ بِهِ أَوْ تَعْمَلْ","id":"Telah mengabarkan kepada kami [Ibrahim bin Al Hasan] dan [Abdur Rahman bin Muhammad bin Sallam] mereka berkata; telah menceritakan kepada kami [Hajjaj bin Muhammad] dari [Ibnu Juraij] dari ['Atho`] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: --Dari jalur lain, dari Abdur Rahman berkata dari Rasulullah shallallahu 'alaihi wasallam bersabda--; Allah ta'ala mengampuni umatku segala sesuatu yang terbersit dalam hatinya selama ia tidak mengucapkan atau melakukannya. "},"3288":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ مِسْعَرٍ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ وَجَلَّ تَجَاوَزَ لِأُمَّتِي مَا وَسْوَسَتْ بِهِ وَحَدَّثَتْ بِهِ أَنْفُسَهَا مَا لَمْ تَعْمَلْ أَوْ تَتَكَلَّمْ بِهِ","id":"Telah mengabarkan kepada kami ['Ubaidullah bin Sa'id], ia berkata; telah menceritakan kepada kami [Ibnu Idris] dari [Mis'ar] dari [Qatadah] dari [Zurarah bin Aufa] dari [Abu Hurairah], ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \" Allah 'azza wajalla mengampuni umatku apa yang dibisikkan dan dikatakan oleh hati mereka selama tidak melakukan atau mengucapkannya.\""},"3289":{"ar":"أَخْبَرَنِي مُوسَى بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا حُسَيْنٌ الْجُعْفِيُّ عَنْ زَائِدَةَ عَنْ شَيْبَانَ عَنْ قَتَادَةَ عَنْ زُرَارَةَ بْنِ أَوْفَى عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنَّ اللَّهَ تَعَالَى تَجَاوَزَ لِأُمَّتِي عَمَّا حَدَّثَتْ بِهِ أَنْفُسَهَا مَا لَمْ تَكَلَّمْ أَوْ تَعْمَلْ بِهِ","id":"Telah mengabarkan kepada kami [Musa bin Abdur Rahman], ia berkata; telah menceritakan kepada kami [Husain Al Ju'fi] dari [Zaidah] dari [Syaiban] dari [Qatadah] dari [Zurarah bin Aufa] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Allah ta'ala mengampuni umatku dari apa yang dikatakan hati mereka selama mereka tidak mengucapkan atau melakukannya.\""},"3290":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ نَافِعٍ قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَكَانَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَارٌ فَارِسِيٌّ طَيِّبُ الْمَرَقَةِ فَأَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ وَعِنْدَهُ عَائِشَةُ فَأَوْمَأَ إِلَيْهِ بِيَدِهِ أَنْ تَعَالَ وَأَوْمَأَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى عَائِشَةَ أَيْ وَهَذِهِ فَأَوْمَأَ إِلَيْهِ الْآخَرُ هَكَذَا بِيَدِهِ أَنْ لَا مَرَّتَيْنِ أَوْ ثَلَاثًا","id":"Telah mengabarkan kepada kami [Abu Bakr bin Nafi'], ia berkata; telah menceritakan kepada kami [Bahz], ia berkata; telah menceritakan kepada kami [Hammad bin Salamah], ia berkata; telah menceritakan kepada kami [Tsabit] dari [Anas], ia berkata; Rasulullah shallallahu 'alaihi wasallam pernah memiliki tetangga orang Persia yang pandai memasak, kemudian ia datang kepada Rasulullah shallallahu 'alaihi wasallam pada suatu hari, dan di sisinya terdapat Aisyah. Lalu orang tersebut memberi isyarat kepadanya dengan tangan agar beliau datang, lalu Rasulullah shallallahu 'alaihi wasallam dengan jarinya memberi isyarat menunjuk Aisyah yang maksudnya apakah dengan Aisyah? Maka yang lain memberikan isyarat demikian dengan tangannya yanga maksudnya: tidak. Hal tersebut berlangsung dua atau tiga kali. "},"3291":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ مَسْلَمَةَ قَالَ حَدَّثَنَا مَالِكٌ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ أَخْبَرَنِي مَالِكٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ مُحَمَّدِ بْنِ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ بْنِ وَقَّاصٍ عَنْ عُمَرَ بْنِ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ وَفِي حَدِيثِ الْحَارِثِ أَنَّهُ سَمِعَ عُمَرَ يَقُولُقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا الْأَعْمَالُ بِالنِّيَّةِ وَإِنَّمَا لِامْرِئٍ مَا نَوَى فَمَنْ كَانَتْ هِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ فَهِجْرَتُهُ إِلَى اللَّهِ وَرَسُولِهِ وَمَنْ كَانَتْ هِجْرَتُهُ لِدُنْيَا يُصِيبُهَا أَوْ امْرَأَةٍ يَتَزَوَّجُهَا فَهِجْرَتُهُ إِلَى مَا هَاجَرَ إِلَيْهِ","id":"Telah mengabarkan kepada kami ['Amr bin Manshur], ia berkata; telah menceritakan kepada kami [Abdullah bin Maslamah] , ia berkata; telah menceritakan kepada kami [Malik] serta [Al Harits bin Miskin] dengan membacakan riwayat dan saya mendengar, dari [Ibnu Al Qasim], ia berkata; telah mengabarkan kepadaku [Malik] dari [Yahya bin Sa'id] dari [Muhammad bin Ibrahim] dari ['Alqamah bin Waqqash] dari [Umar bin Al Khathab] radliallahu 'anhu. Dan dalam hadis Al Harits bahwa ia mendengar Umar berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Setiap amalan tergantung niat, dan setiap orang mendapatkan balasan dari niatnya. Barang siapa yang hijrahnya kepada Allah dan RasulNya maka hijrahnya dicatat kepada Allah dan RasulNya. Sebaliknya barang siapa yang hijrahnya untuk dunia atau wanita yang hendak ia nikahi, hijrahnya sekedar mendapat tujuan hijrahnya.\""},"3292":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ عَيَّاشٍ قَالَ حَدَّثَنِي شُعَيْبٌ قَالَ حَدَّثَنِي أَبُو الزِّنَادِ مِمَّا حَدَّثَهُ عَبْدُ الرَّحْمَنِ الْأَعْرَجُ مِمَّا ذَكَرَ أَنَّهُ سَمِعَ أَبَا هُرَيْرَةَ يُحَدِّثُعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ قَالَ انْظُرُوا كَيْفَ يَصْرِفُ اللَّهُ عَنِّي شَتْمَ قُرَيْشٍ وَلَعْنَهُمْ إِنَّهُمْ يَشْتِمُونَ مُذَمَّمًا وَيَلْعَنُونَ مُذَمَّمًا وَأَنَا مُحَمَّدٌ","id":"Telah mengabarkan kepada kami ['Imran bin Bakkar], ia berkata; telah menceritakan kepada kami [Ali bin Ayyasy], ia berkata; telah menceritakan kepadaku [Syu'aib], ia berkata; telah menceritakan kepadaku [Abu Az Zinad] dari apa yang diceritakan [Abdur Rahman Al A'raj] kepadanya, dari apa yang disebutkannya bahwa ia mendengar [Abu Hurairah] menceritakan dari Rasulullah shallallahu 'alaihi wasallam ia berkata; Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lihatlah bagaimana Allah memalingkan dariku celaan orang-orang Quraisy dan laknat mereka. Sesungguhnya mereka mencela orang yang tercela dan melaknat orang yang tercela, sedang saya adalah Muhammad.\""},"3293":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَنْبَأَنَا يُونُسُ بْنُ يَزِيدَ وَمُوسَى بْنُ عُلَيٍّ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ عَائِشَةَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْلَمَّا أُمِرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِتَخْيِيرِ أَزْوَاجِهِ بَدَأَ بِي فَقَالَ إِنِّي ذَاكِرٌ لَكِ أَمْرًا فَلَا عَلَيْكِ أَنْ لَا تُعَجِّلِي حَتَّى تَسْتَأْمِرِي أَبَوَيْكِ قَالَتْ قَدْ عَلِمَ أَنَّ أَبَوَايَ لَمْ يَكُونَا لِيَأْمُرَانِّي بِفِرَاقِهِ قَالَتْ ثُمَّ تَلَا هَذِهِ الْآيَةَ{ يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ إِنْ كُنْتُنَّ تُرِدْنَ الْحَيَاةَ الدُّنْيَا إِلَى قَوْلِهِ جَمِيلًا }فَقُلْتُ أَفِي هَذَا أَسْتَأْمِرُ أَبَوَيَّ فَإِنِّي أُرِيدُ اللَّهَ عَزَّ وَجَلَّ وَرَسُولَهُ وَالدَّارَ الْآخِرَةَ قَالَتْ عَائِشَةُ ثُمَّ فَعَلَ أَزْوَاجُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِثْلَ مَا فَعَلْتُ وَلَمْ يَكُنْ ذَلِكَ حِينَ قَالَ لَهُنَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَاخْتَرْنَهُ طَلَاقًا مِنْ أَجْلِ أَنَّهُنَّ اخْتَرْنَهُ","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Ibnu Wahb], ia berkata; telah mengabarkan kepada kami [Yunus bin Yazid] dan [Musa bin Ali] dari [Ibnu Syihab], ia berkata; telah mengabarkan kepadaku [Abu Salamah bin Abdur Rahman] bahwa [Aisyah] isteri nabi shallallahu 'alaihi wasallam berkata; tatkala Rasulullah shallallahu 'alaihi wasallam diperintahkan untuk memberikan pilihan kepada para isterinya, maka beliau memulai terhadapku. Beliau bersabda: \"Saya mengingatkan engkau kepada suatu perkara, maka tidak mengapa engkau tidak menyegerakan hingga engkau meminta petunjuk kepada kedua orang tuamu.\" Aisyah berkata; beliau telah mengetahui bahwa kedua orang tuaku tidak memerintahkanku untuk berpisah dengannya. Ia berkata; kemudian beliau membaca ayat ini: \"Hai Nabi, katakanlah kepada isteri-isterimu: \"Jika kamu sekalian mengingini kehidupan dunia dan perhiasannya, maka marilah supaya kuberikan kepadamu mut'ah dan aku ceraikan kamu dengan cara yang baik.\" Maka saya katakan apakah mengenai hal ini saya meminta petunjuk kepada kedua orang tuaku? Sesungguhnya saya menginginkan Allah 'azza wajalla dan rasulNya, serta kampung Akherat. Aisyah berkata; kemudian isteri-isteri Nabi shallallahu 'alaihi wasallam melakukan seperti apa yang saya lakukan. Perceraian itu betul-betul tidak terjadi, saat nabi shallallahu 'alaihi wasallam memberi mereka kebebasan memilih dan mereka bebas menentukan pilihan, sebab memang mereka memilih beliau. "},"3294":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ ثَوْرٍ عَنْ مَعْمَرٍ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْلَمَّا نَزَلَتْ{ إِنْ كُنْتُنَّ تُرِدْنَ اللَّهَ وَرَسُولَهُ }دَخَلَ عَلَيَّ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَدَأَ بِي فَقَالَ يَا عَائِشَةُ إِنِّي ذَاكِرٌ لَكِ أَمْرًا فَلَا عَلَيْكِ أَنْ لَا تُعَجِّلِي حَتَّى تَسْتَأْمِرِي أَبَوَيْكِ قَالَتْ قَدْ عَلِمَ وَاللَّهِ أَنَّ أَبَوَيَّ لَمْ يَكُونَا لِيَأْمُرَانِّي بِفِرَاقِهِ فَقَرَأَ عَلَيَّ{ يَا أَيُّهَا النَّبِيُّ قُلْ لِأَزْوَاجِكَ إِنْ كُنْتُنَّ تُرِدْنَ الْحَيَاةَ الدُّنْيَا وَزِينَتَهَا }فَقُلْتُ أَفِي هَذَا أَسْتَأْمِرُ أَبَوَيَّ فَإِنِّي أُرِيدُ اللَّهَ وَرَسُولَهُقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالْأَوَّلُ أَوْلَى بِالصَّوَابِ وَاللَّهُ سُبْحَانَهُ وَتَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Muhammad bin Tsaur] dari [Ma'mar] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], ia berkata; tatkala turun ayat: \"Jika kamu sekalian mengingini kehidupan dunia dan perhiasannya\" maka saya katakan; apakah mengenai hal ini saya meminta petunjuk kedua orang tuaku? Sesungguhnya saya menginginkan Allah dan RasulNya. Abu Abdur Rahman berkata; hal ini adalah salah, yang pertama lebih benar. Dan Allah subhanahu wa ta'ala lebih tahu. "},"3295":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى هُوَ ابْنُ سَعِيدٍ عَنْ إِسْمَعِيلَ عَنْ عَامِرٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْخَيَّرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاخْتَرْنَاهُ فَهَلْ كَانَ طَلَاقًا","id":"Telah mengabarkan kepada kami ['Amr bin Ali], ia berkata; telah menceritakan kepada kami [Yahya yaitu Ibnu Sa'id] dari [Isma'il] dari ['Amir] dari [Masruq] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam memberikan pilihan kepada kami, maka kami memilih beliau. Hal itu bukanlah pencerai? "},"3296":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَاصِمٍ قَالَ قَالَ الشَّعْبِيُّ عَنْ مَسْرُوقٍ عَ��ْ عَائِشَةَ قَالَتْقَدْ خَيَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ فَلَمْ يَكُنْ طَلَاقًا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Syu'bah] dari ['Ashim], ia berkata; [Asy Sya'bi] berkata dari [Masruq] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah memberikan pilihan kepada para isterinya, dan hal tersebut bukanlah pencerai. "},"3297":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِبْرَاهِيمَ بْنِ صُدْرَانَ عَنْ خَالِدِ بْنِ الْحَارِثِ قَالَ حَدَّثَنَا أَشْعَثُ وَهُوَ ابْنُ عَبْدِ الْمَلِكِ عَنْ عَاصِمٍ عَنْ الشَّعْبِيِّ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْقَدْ خَيَّرَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ فَلَمْ يَكُنْ طَلَاقًا","id":"Telah mengabarkan kepada kami [Muhammad bin Ibrahim bin Shudran] dari [Khalid bin Al Harits], ia berkata; telah menceritakan kepada kami [Asy'ats yaitu Ibnu Abdul Malik] dari ['Ashim] dari [Asy Sya'bi] dari [Masruq] dari [Aisyah], ia berkata; Nabi shallallahu 'alaihi wasallam telah memberikan pilihan kepada isteri-isterinya, dan hal itu bukanlah bukanlah pencerai. "},"3298":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سُلَيْمَانَ عَنْ أَبِي الضُّحَى عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْقَدْ خَيَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نِسَاءَهُ أَفَكَانَ طَلَاقًا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la], ia berkata; telah menceritakan kepada kami [Khalid], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Sulaiman] dari [Abu Adh Dhuha] dari [Masruq] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah memberikan pilihan kepada para isterinya. Hal tersebut bukanlah penceraian. "},"3299":{"ar":"أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ مُحَمَّدٍ الضَّعِيفُ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا الْأَعْمَشُ عَنْ مُسْلِمٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْخَيَّرَنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاخْتَرْنَاهُ فَلَمْ يَعُدَّهَا عَلَيْنَا شَيْئًا","id":"Telah mengabarkan kepada kami [Abdullah bin Muhammad Adh Dha'if], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah], ia berkata; telah menceritakan kepada kami [Al A'masy] dari [Muslim] dari [Masruq] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam telah memberikan pilihan kepada kami, maka kami memilih beliau, dan hal tersebut tidak terhitung sesuatupun atas kami. "},"3300":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا حَمَّادُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا ابْنُ مَوْهَبٍ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ قَالَكَانَ لِعَائِشَةَ غُلَامٌ وَجَارِيَةٌ قَالَتْ فَأَرَدْتُ أَنْ أُعْتِقَهُمَا فَذَكَرْتُ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ ابْدَئِي بِالْغُلَامِ قَبْلَ الْجَارِيَةِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah menceritakan kepada kami [Hammad bin Mas'adah], ia berkata; telah menceritakan kepada kami [Ibnu Mawhab] dari [Al Qasim bin Muhammad], ia berkata; dahulu ['Aisyah] memiliki seorang budak anak laki dan perempuan, ia berkata; saya ingin memerdekakan mereka, kemudian saya menceritakannya kepada Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Mulailah dengan yang laki-laki sebelum yang perempuan.\""},"3301":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ عَنْ رَبِيعَةَ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ عَائِشَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَتْكَانَ فِي بَرِيرَةَ ثَلَاثُ سُنَنٍ إِحْدَى السُّنَنِ أَنَّهَا أُعْتِقَتْ فَخُيِّرَتْ فِي زَوْجِهَا وَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَاءُ لِمَنْ أَعْتَقَ وَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَالْبُرْمَةُ تَفُورُ بِلَحْمٍ فَقُرِّبَ إِلَيْهِ خُبْزٌ وَأُدْمٌ مِنْ أُدْمِ الْبَيْتِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَلَمْ أَرَ بُرْمَةً فِيهَا لَحْمٌ فَقَالُوا بَلَى يَا رَسُولَ اللَّهِ ذَلِكَ لَحْمٌ تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ وَأَنْتَ لَا تَأْكُلُ الصَّدَقَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هُوَ عَلَيْهَا صَدَقَةٌ وَهُوَ لَنَا هَدِيَّةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah], ia berkata; telah memberitakan kepada kami [Ibnu Al Qasim] dari [Malik] dari [Rabi'ah] dari [Al Qasim bin Muhammad] dari [Aisyah] isteri Nabi shallallahu 'alaihi wasallam, ia berkata; dalam diri Barirah terdapat tiga hukum syar'i, salah satunya adalah bahwa ia dimerdekakan kemudian diberi pilihan mengenai suaminya. Dan Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perwalian adalah milik orang yang memerdekakan.\" Dan Rasulullah shallallahu 'alaihi wasallam memasuki rumah sedang sebuah kuali tengah mendidih berisikan daging. Kemudian didekatkan kepada beliau roti dan lauk yang ada di rumah. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bukankah saya melihat kuali berisi daging?\" Maka mereka berkata; benar wahai Rasulullah, itu adalah daging yang disedekahkan kepada Barirah, sedangkan anda tidak memakan sedekah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Itu adalah sedekah untuknya dan bagi kita adalah hadiah.\""},"3302":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ آدَمَ قَالَ حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ هِشَامٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَانَ فِي بَرِيرَةَ ثَلَاثُ قَضِيَّاتٍ أَرَادَ أَهْلُهَا أَنْ يَبِيعُوهَا وَيَشْتَرِطُوا الْوَلَاءَ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اشْتَرِيهَا وَأَعْتِقِيهَا فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْتَقَ وَأُعْتِقَتْ فَخَيَّرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاخْتَارَتْ نَفْسَهَا وَكَانَ يُتَصَدَّقُ عَلَيْهَا فَتُهْدِي لَنَا مِنْهُ فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ كُلُوهُ فَإِنَّهُ عَلَيْهَا صَدَقَةٌ وَهُوَ لَنَا هَدِيَّةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Adam], ia berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Hisyam] dari [Abdur Rahman bin Al Qasim] dari [ayahnya] dari [Aisyah], ia berkata; dalam diri Barirah terdapat tiga perkara, tuannya berkeinginan untuk menjualnya, dan mereka memberi syarat mendapatkan perwaliannya. Kemudian hal tersebut saya laporkan kepada Nabi shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Belilah dan merdekakan dia. Sesungguhnya perwalian adalah milik orang yang memerdekakan.\" Dan iapun dimerdekakan, kemudian Rasulullah shallallahu 'alaihi wasallam memberikan pilihan kepadanya dan iapun memilih dirinya. Ia diberi sedekah kemudian sebagiannya ia hadiahkan kepada kami. hal tersebut lantas saya laporkan kepada Nabi shallallahu 'alaihi wasallam kemudian beliau bersabda: \"Makanlah, sedekah untuknya dan hadiah bagi kita.\" "},"3303":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْاشْتَرَيْتُ بَرِيرَةَ فَاشْتَرَطَ أَهْلُهَا وَلَاءَهَا فَذَكَرْتُ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَعْتِقِيهَا فَإِنَّمَا الْوَلَاءُ لِمَنْ أَعْطَى الْوَرِقَ قَالَتْ فَأَعْتَقْتُهَا فَدَعَاهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَخَيَّرَهَا مِنْ زَوْجِهَا قَالَتْ لَوْ أَعْطَانِي كَذَا وَكَذَا مَا أَقَمْتُ عِنْدَهُ فَاخْتَارَتْ نَفْسَهَا وَكَانَ زَوْجُهَا حُرًّا","id":"Telah mengabarkan kepada kami [Qutaibah], ia berkata; telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Aisyah], ia berkata; saya membeli Barirah, dan tuannya memberi syarat perwaliannya untuk mereka. Kemudian hal tersebut saya sebutkan kepada Nabi shallallahu 'alaihi wasallam, dan beliau bersabda: \"Merdekakan dia, karena perwalian itu bagi rang yang memberikan uang.\""},"3304":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ عَنْ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ الْحَكَمِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَأَنَّهَا أَرَادَتْ أَنْ تَشْتَرِيَ بَرِيرَةَ فَاشْتَرَطُوا وَلَاءَهَا فَذَكَرَتْ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اشْتَرِيهَا وَأَعْتِقِيهَا فَإِنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ وَأُتِيَ بِلَحْمٍ فَقِيلَ إِنَّ هَذَا مِمَّا تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَقَالَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ وَخَيَّرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ زَوْجُهَا حُرًّا","id":"Telah mengabarkan kepada kami ['Amr bin Ali] dari [Abdur Rahman], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Al Hakam] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] bahwa ia ingin membeli Barirah, kemudian mereka mensyaratkan perwaliannya untuk mereka. Lalu ia melaporkan kasus tersebut kepada Nabi shallallahu 'alaihi wasallam dan bersabda: \"Belilah dan merdekakan dia, karena perwalian adalah untuk orang memerdekakan.\" Dan didatangkan sebuah daging kemudian dikatakan; ini diantara yang disedekahkan kepada Barirah. Maka beliau bersabda: \"Itu sedekah untuknya dan bagi kita adalah hadiah.\" Beliau memberikan pilihan kepada Barirah, dan suaminya adalah orang yang merdeka. "},"3305":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْكَاتَبَتْ بَرِيرَةُ عَلَى نَفْسِهَا بِتِسْعِ أَوَاقٍ فِي كُلِّ سَنَةٍ بِأُوقِيَّةٍ فَأَتَتْ عَائِشَةَ تَسْتَعِينُهَا فَقَالَتْ لَا إِلَّا أَنْ يَشَاءُوا أَنْ أَعُدَّهَا لَهُمْ عَدَّةً وَاحِدَةً وَيَكُونُ الْوَلَاءُ لِي فَذَهَبَتْ بَرِيرَةُ فَكَلَّمَتْ فِي ذَلِكَ أَهْلَهَا فَأَبَوْا عَلَيْهَا إِلَّا أَنْ يَكُونَ الْوَلَاءُ لَهُمْ فَجَاءَتْ إِلَى عَائِشَةَ وَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عِنْدَ ذَلِكَ فَقَالَتْ لَهَا مَا قَالَ أَهْلُهَا فَقَالَتْ لَا هَا اللَّهِ إِذًا إِلَّا أَنْ يَكُونَ الْوَلَاءُ لِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا هَذَا فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ بَرِيرَةَ أَتَتْنِي تَسْتَعِينُ بِي عَلَى كِتَابَتِهَا فَقُلْتُ لَا إِلَّا أَنْ يَشَاءُوا أَنْ أَعُدَّهَا لَهُمْ عَدَّةً وَاحِدَةً وَيَكُونُ الْوَلَاءُ لِي فَذَكَرَتْ ذَلِكَ لِأَهْلِهَا فَأَبَوْا عَلَيْهَا إِلَّا أَنْ يَكُونَ الْوَلَاءُ لَهُمْ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ابْتَاعِيهَا وَاشْتَرِطِي لَهُمْ الْوَلَاءَ فَإِنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ ثُمَّ قَامَ فَخَطَبَ النَّاسَ فَحَمِدَ اللَّهَ وَأَثْنَى عَلَيْهِ ثُمَّ قَالَ مَا بَالُ أَقْوَامٍ يَشْتَرِطُونَ شُرُوطًا لَيْسَتْ فِي كِتَابِ اللَّهِ عَزَّ وَجَلَّ يَقُولُونَ أَعْتِقْ فُلَانًا وَالْوَلَاءُ لِي كِتَابُ اللَّهِ عَزَّ وَجَلَّ أَحَقُّ وَشَرْطُ اللَّهِ أَوْثَقُ وَكُلُّ شَرْطٍ لَيْسَ فِي كِتَابِ اللَّهِ فَهُوَ بَاطِلٌ وَإِنْ كَانَ مِائَةَ شَرْطٍ فَخَيَّرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ زَوْجِهَا وَكَانَ عَبْدًا فَاخْتَارَتْ نَفْسَهَاقَالَ عُرْوَةُ فَلَوْ كَانَ حُرًّا مَا خَيَّرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Jarir] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah], ia berkata; Barirah mengadakan perjanjian pembebasan dirinya dengan membayar sembilan uqiyah, setiap tahun satu uqiyah. Kemudian ia datang kepada Aisyah, dan meminta bantuan kepadanya. Ia berkata; tidak, kecuali apabila mereka menghendaki saya menghitungnya satu hitungan untuk mereka, dan perwaliannya adalah untukku. Kemudian Barirah pergi dan membicarakan hal tersebut dengan tuannya. Maka mereka menolak hal tersebut kecuali perwaliannya adalah untuk mereka. Kemudian ia datang kepada Aisyah, dan Rasulullah shallallahu 'alaihi wasallam pada saat itu datang, lalu Barirah mengatakan apa yang dikatakan tuannya. Maka Aisyah berkata; demi Allah kalau demikian tidak. Kecuali perwalian adalah untukku. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ada apa ini?\" kemudian Aisyah berkata; wahai Rasulullah, Barirah datang kepadaku meminta bantuan menyelesaikan perjanjian pembebasannya, kemudian saya katakan; tidak, kecuali mereka menghendaki saya menghitung bagi mereka satu hitungan dan perwaliannya adalah untukku. Kemudian ia menyebutkan hal tersebut kepada tuannya, lalu mereka menolak kecuali perwalian untuk mereka. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Belilah dia dan mintalah syarat perwalian kepada mereka. Dan perwalian hanyalah untuk orang yang memerdekakan.\" Kemudian beliau berdiri dan berkhutbah kepada manusia, beliau memuji Allah kemudian bersabda: \"Bagaimana keadaan orang-orang, mereka memberikan berbagai syarat yang tidak ada dalam Kitab Allah 'azza wajalla. Mereka mengatakan; bebaskan Fulan, dan perwaliannya untukku.\" Kitab Allah lebih berhak dan syarat Allah lebih kuat, dan segala syarat yang tidak ada di dalam Kitab Allah adalah batil walaupun seratus syarat. Kemudian Rasulullah shallallahu 'alaihi wasallam memberikan pilihan kepada Barirah. "},"3306":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْمُغِيرَةُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ يَزِيدَ بْنِ رُومَانَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْكَانَ زَوْجُ بَرِيرَةَ عَبْدًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim], ia berkata; telah memberitakan kepada kami [Al Mughirah bin Salamah], ia berkata; telah menceritakan kepada kami [Wuhaib] dari ['Ubaidullah bin Umar] dari [Yazid bin Ruman] dari ['Urwah] dari [Aisyah] radliallahu 'anha, ia berkata; dahulu suami Barirah adalah seorang sahaya. "},"3307":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا حُسَيْنٌ عَنْ زَائِدَةَ عَنْ سِمَاكٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ عَائِشَةَأَنَّهَا اشْتَرَتْ بَرِيرَةَ مِنْ أُنَاسٍ مِنْ الْأَنْصَارِ فَاشْتَرَطُوا الْوَلَاءَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَاءُ لِمَنْ وَلِيَ النِّعْمَةَ وَخَيَّرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَكَانَ زَوْجُهَا عَبْدًا وَأَهْدَتْ لِعَائِشَةَ لَحْمًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ وَضَعْتُمْ لَنَا مِنْ هَذَا اللَّحْمِ قَالَتْ عَائِشَةُ تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ فَقَالَ هُوَ عَلَيْهَا صَدَقَةٌ وَهُوَ لَنَا هَدِيَّةٌ","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakariya bin Dinar], ia berkata; telah menceritakan kepada kami [Husain] dari [Zaidah] dari [Simak] dari [Abdur Rahman bin Al Qasim] dari [Aisyah] bahwa ia membeli Barirah dari beberapa orang Anshar. Mereka mengajukan syarat perwalian untuk mereka. Namun Rasulullah shallallahu 'alaihi wasallam bersabda: \"Perwalian adalah untuk orang yang memerdekakan.\" Dan Rasulullah shallallahu 'alaihi wasallam memberikan pilihan kepadanya. Suaminya adalah seorang sahaya, dan Barirah memberikan hadiah daging kepada Aisyah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ohh,,,, seandainya kalian memberikan sebagian daging ini kepada kami.\" Aisyah berkata; itu disedekahkan kepada Barirah. Maka beliau bersabda: \"Itu sedekah untuknya dan hadiah bagi kita.\" "},"3308":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ الْكَرْمَانِيُّ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَ وَكَانَ وَصِيَّ أَبِيهِ قَالَ وَفَرِقْتُ أَنْ أَقُولَ سَمِعْتُهُ مِنْ أَبِيكَ قَالَتْ عَائِشَةُسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ بَرِيرَةَ وَأَرَدْتُ أَنْ أَشْتَرِيَهَا وَاشْتُرِطَ الْوَلَاءُ لِأَهْلِهَا فَقَالَ اشْتَرِيهَا فَإِنَّ الْوَلَاءَ لِمَنْ أَعْتَقَ قَالَ وَخُيِّرَتْ وَكَانَ زَوْجُهَا عَبْدًا ثُمَّ قَالَ بَعْدَ ذَلِكَ مَا أَدْرِي وَأُتِيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِلَحْمٍ فَقَالُوا هَذَا مِمَّا تُصُدِّقَ بِهِ عَلَى بَرِيرَةَ قَالَ هُوَ لَهَا صَدَقَةٌ وَلَنَا هَدِيَّةٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim], ia berkata; telah menceritakan kepada kami [Yahya bin Abu Bukair Al Karmani], ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Abdur Rahman bin Al Qasim] dari [ayahnya] dari [Aisyah], Al Qasim berkata yang merupakan orang yang diberi wasiat oleh ayahnya berkata; saya khawatir untuk mengatakan; saya telah mendengar dari ayahmu. Aisyah berkata; saya bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai Barirah, sedang saya ingin membelinya dan bersyarat perwalian untuk tuannya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Belilah dia, dan perwalian adalah untuk orang yang memerdekakan.\" Al Qasim berkata; dan Barirah diberi pilihan, sedang suaminya adalah seorang sahaya. Setelah itu Al Qasim berkata; saya tidak tahu. Dan Rasulullah shallallahu 'alaihi wasallam diberi daging, kemudian mereka berkata; ini adalah sebagian yang disedekahkan kepada Barirah. Beliau bersabda: \"Itu sedekah baginya dan hadiah bagi kita.\""},"3309":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ الْبَصْرِيُّ قَالَ حَدَّثَنَا مَرْوَانُ بْنُ مُعَاوِيَةَ قَالَ حَدَّثَنَا أَبُو يَعْفُورٍ عَنْ أَبِي الضُّحَى قَالَ تَذَاكَرْنَا الشَّهْرَ عِنْدَهُ فَقَالَ بَعْضُنَا ثَلَاثِينَ وَقَالَ بَعْضُنَا تِسْعًا وَعِشْرِينَ فَقَالَ أَبُو الضُّحَى حَدَّثَنَا ابْنُ عَبَّاسٍ قَالَأَصْبَحْنَا يَوْمًا وَنِسَاءُ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَبْكِينَ عِنْدَ كُلِّ امْرَأَةٍ مِنْهُنَّ أَهْلُهَا فَدَخَلْتُ الْمَسْجِدَ فَإِذَا هُوَ مَلْآنٌ مِنْ النَّاسِ قَالَ فَجَاءَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ فَصَعِدَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهُوَ فِي عُلِّيَّةٍ لَهُ فَسَلَّمَ عَلَيْهِ فَلَمْ يُجِبْهُ أَحَدٌ ثُمَّ سَلَّمَ فَلَمْ يُجِبْهُ أَحَدٌ ثُمَّ سَلَّمَ فَلَمْ يُجِبْهُ أَحَدٌ فَرَجَعَ فَنَادَى بِلَالًا فَدَخَلَ عَلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَطَلَّقْتَ نِسَاءَكَ فَقَالَ لَا وَلَكِنِّي آلَيْتُ مِنْهُنَّ شَهْرًا فَمَكَثَ تِسْعًا وَعِشْرِينَ ثُمَّ نَزَلَ فَدَخَلَ عَلَى نِسَائِهِ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam Al Bashri] ia berkata; telah menceritakan kepada kami [Marwan bin Mu'awiyah] ia berkata; telah menceritakan kepada kami [Abu Ya'fur] dari [Abu Adl Dluha] ia berkata, \"Kami saling menyebutkan (tentang jumlah hari dalam) sebulan di sisi beliau, lalu sebagian kami menyebutkan bahwa jumlahnya adalah tiga puluh hari dan sebagian menyebutkan dua puluh sembilan, lalu Abu Adl Dluha berkata, \" [Ibnu Abbas] berkata, \"Pada suatu pagi kami bangun dan para isteri Nabi shallallahu 'alaihi wasallam menangis di sisi setiap keluarganya, lalu aku memasuki masjid, ternyata masjid penuh orang berkumpul.\" Abu Adalah Duha berkata, \"Lalu datanglah Umar Radliyallahu'anhu dan ia naik ke ruangan Nabi shallallahu 'alaihi wasallam yang berada di kamar atasnya, ia mengucapkan salam kepada beliau namun beliau tidak menjawabnya, kemudian ia mengucapkan salam lagi namun tidak seorang pun yang menjawab, kemudian ia mengucapkan salam lagi namun tidak ada yang menjawab. Kemudian ia kembali dan memanggil Bilal. Bilal lalu masuk menemui Nabi shallallahu 'alaihi wasallam dan berkata, \"Apakah engkau menceraikan para isterimu?\" beliau menjawab: \"Tidak, aku hanya bersumpah untuk tidak menggauli mereka selama sebulan, \" beliau tinggal selama dua puluh sembilan hari, lalu turun dari kamarnya dan menemui para isterinya.\""},"3310":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَآلَى النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مِنْ نِسَائِهِ شَهْرًا فِي مَشْرَبَةٍ لَهُ فَمَكَثَ تِسْعًا وَعِشْرِينَ لَيْلَةً ثُمَّ نَزَلَ فَقِيلَ يَا رَسُولَ اللَّهِ أَلَيْسَ آلَيْتَ عَلَى شَهْرٍ قَالَ الشَّهْرُ تِسْعٌ وَعِشْرُونَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Humaid] dari [Anas] ia berkata, \"Nabi shallallahu 'alaihi wasallam bersumpah untuk tidak menggauli isteri-isterinya selama sebulan di ruangan beliau yang tinggi, lalu beliau tinggal selama dua puluh sembilan malam kemudian beliau turun, lalu dikatakan, \"Wahai Rasulullah, bukankan engkau bersumpah untuk sebulan?\" beliau bersabda: \"Sebulan itu dua puluh sembilan hari.\""},"3311":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى عَنْ مَعْمَرٍ عَنْ الْحَكَمِ بْنِ أَبَانَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ ظَاهَرَ مِنْ امْرَأَتِهِ فَوَقَعَ عَلَيْهَا فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي ظَاهَرْتُ مِنْ امْرَأَتِي فَوَقَعْتُ قَبْلَ أَنْ أُكَفِّرَ قَالَ وَمَا حَمَلَكَ عَلَى ذَلِكَ يَرْحَمُكَ اللَّهُ قَالَ رَأَيْتُ خَلْخَالَهَا فِي ضَوْءِ الْقَمَرِ فَقَالَ لَا تَقْرَبْهَا حَتَّى تَفْعَلَ مَا أَمَرَ اللَّهُ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Al Hasan bin Huraits] ia berkata; telah menceritakan kepada kami [Al Fadll bin Musa] dari [Ma'mar] dari [Al Hakam bin Aban] dari ['Ikrimah] dari [Ibnu Abbas], bahwa seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam, ia telah menzhihar (mengatakan kepada isterinya engkau seperti punggung ibuku) isterinya lalu ia menggaulinya, ia berkata, \"Wahai Rasulullah, aku telah menzhihar isteriku lalu aku menggaulinya sebelum membayar kaffarat?\" Beliau bersabda: \"Apa yang mendorongmu untuk melakukan hal itu, semoga Allah merahmatimu?\" Aku melihat gelang kakinya di bawah cahaya bulan.\" Beliau bersabda: \"Janganlah engkau mendekatinya hingga melakukan apa yang Allah Azza wa Jalla perintahkan.\""},"3312":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الْحَكَمِ بْنِ أَبَانَ عَنْ عِكْرِمَةَ قَالَتَظَاهَرَ رَجُلٌ مِنْ امْرَأَتِهِ فَأَصَابَهَا قَبْلَ أَنْ يُكَفِّرَ فَذَكَرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَمَلَكَ عَلَى ذَلِكَ قَالَ رَحِمَكَ اللَّهُ يَا رَسُولَ اللَّهِ رَأَيْتُ خَلْخَالَهَا أَوْ سَاقَيْهَا فِي ضَوْءِ الْقَمَرِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاعْتَزِلْهَا حَتَّى تَفْعَلَ مَا أَمَرَكَ اللَّهُ عَزَّ وَجَلَّ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] ia berkata; telah menceritakan kepada kami [Abdurrazzaq] ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Al Hakam bin Aban] dari ['Ikrimah] ia berkata, \"Seorang laki-laki telah menzhihar isterinya, kemudian ia menggaulinya sebelum membayar kafarat. Lalu ia menceritakan hal tersebut kepada Nabi shallallahu 'alaihi wasallam, maka Nabi shallallahu 'alaihi wasallam pun bersabda kepadanya: \"Apakah yang mendorongmu untuk melakukan hal tersebut?\" Ia menjawab, \"Semoga Allah merahmatimu, wahai Rasulullah, aku telah melihat gelang kakinya atau kedua betisnya dalam cahaya rembulan.\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jauhilah dia hingga engkau melakukan apa yang telah Allah 'azza wajalla perintahkan.\""},"3313":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْمُعْتَمِرُ ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا الْمُعْتَمِرُ قَالَ سَمِعْتُ الْحَكَمَ بْنَ أَبَانَ قَالَ سَمِعْتُ عِكْرِمَةَ قَالَأَتَى رَجُلٌ نَبِيَّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا نَبِيَّ اللَّهِ إِنَّهُ ظَاهَرَ مِنْ امْرَأَتِهِ ثُمَّ غَشِيَهَا قَبْلَ أَنْ يَفْعَلَ مَا عَلَيْهِ قَالَ مَا حَمَلَكَ عَلَى ذَلِكَ قَالَ يَا نَبِيَّ اللَّهِ رَأَيْتُ بَيَاضَ سَاقَيْهَا فِي الْقَمَرِ قَالَ نَبِيُّ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاعْتَزِلْ حَتَّى تَقْضِيَ مَا عَلَيْكَ وَقَالَ إِسْحَقُ فِي حَدِيثِهِ فَاعْتَزِلْهَا حَتَّى تَقْضِيَ مَا عَلَيْكَوَاللَّفْظُ لِمُحَمَّدٍ قَالَ أَبُو عَبْد الرَّحْمَنِ الْمُرْسَلُ أَوْلَى بِالصَّوَابِ مِنْ الْمُسْنَدِ وَاللَّهُ سُبْحَانَهُ وَتَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Al Mu'tamir]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Al Mu'tamir] ia berkata; aku mendengar [Al Hakam bin Aban] ia berkata; aku mendengar ['Ikrimah] berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallamm dan berkata, \"Wahai Nabi Allah, sesungguhnya ia telah menzhihar isterinya, kemudian menggaulinya sebelum melakukan apa yang menjadi kewajibannya?\" Beliau bersabda: \"Apakah yang mendorongmu untuk melakukan hal tersebut? Ia menjawab, \"Wahai Nabi Allah, aku melihat betisnya yang putih dalam cahaya rembulan.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Jauhilah hingga engkau menunaikan apa yang menjadi kewajibanmu.\" [Ishaq] menyebutkan dalam haditsnya, \"Jauhilah dia hingga engkau menunaikan apa yang menjadi kewajibanmu.\" Dan lafazh tersebut adalah lafazh Muhammad. Abu Abdurrahman berkata, \"Hadits mursal lebih benar daripada musnad. Wallahu A'lam.\""},"3314":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ تَمِيمِ بْنِ سَلَمَةَ عَنْ عُرْوَةَ عَنْ عَائِشَةَ أَنَّهَا قَالَتْالْحَمْدُ لِلَّهِ الَّذِي وَسِعَ سَمْعُهُ الْأَصْوَاتَ لَقَدْ جَاءَتْ خَوْلَةُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَشْكُو زَوْجَهَا فَكَانَ يَخْفَى عَلَيَّ كَلَامُهَا فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ{ قَدْ سَمِعَ اللَّهُ قَوْلَ الَّتِي تُجَادِلُكَ فِي زَوْجِهَا وَتَشْتَكِي إِلَى اللَّهِ وَاللَّهُ يَسْمَعُ تَحَاوُرَكُمَا }الْآيَةَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Al A'masy] dari [Tamim bin Salamah] dari ['Urwah] dari ['Aisyah] bahwa ia berkata, \"Segala puji bagi Allah yang Maha luas pendengaran-Nya terhadap segala suara. Sungguh Khaulah telah datang kepada Rasulullah shallallahu 'alaihi wasallam mengadukan suaminya, namun perkataannya kepadaku tidak jelas bagiku. Kemudian Allah Azza wa Jalla menurunkan ayat: '(Sesungguhnya Allah Telah mendengar perkataan wanita yang mengajukan gugatan kepada kamu tentang suaminya, dan mengadukan (halnya) kepada Allah. dan Allah mendengar soal jawab antara kamu berdua…) ' (Qs. Al Mujadilah: 1)."},"3315":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْمَخْزُومِيُّ وَهُوَ الْمُغِيرَةُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا وُهَيْبٌ عَنْ أَيُّوبَ عَنْ الْحَسَنِ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ قَالَ الْمُنْتَزِعَاتُ وَالْمُخْتَلِعَاتُ هُنَّ الْمُنَافِقَاتُقَالَ الْحَسَنُ لَمْ أَسْمَعْهُ مِنْ غَيْرِ أَبِي هُرَيْرَةَ قَالَ أَبُو عَبْد الرَّحْمَنِ الْحَسَنُ لَمْ يَسْمَعْ مِنْ أَبِي هُرَيْرَةَ شَيْئًا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Al Makhzumi] -yaitu Al Mughirah bin Salamah- ia berkata; telah menceritakan kepada kami [Wuhaib] dari [Ayyub] dari [Al Hasan] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau bersabda: \"Wanita-wanita yang meminta cerai dengan mengembalikan hak-haknya adalah orang munafik.\" Al Hasan berkata, \"Aku belum pernah mendengarnya kecuali dari Abu Hurairah.\" Abu Abdurrahman berkata, \"Al Hasan belum mendengar sesuatupun dari Abu Hurairah.\""},"3316":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَمْرَةَ بِنْتِ عَبْدِ الرَّحْمَنِ أَنَّهَا أَخْبَرَتْهُ عَنْ حَبِيبَةَ بِنْتِ سَهْلٍأَنَّهَا كَانَتْ تَحْتَ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ وَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ خَرَجَ إِلَى الصُّبْحِ فَوَجَدَ حَبِيبَةَ بِنْتَ سَهْلٍ عِنْدَ بَابِهِ فِي الْغَلَسِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ هَذِهِ قَالَتْ أَنَا حَبِيبَةُ بِنْتُ سَهْلٍ يَا رَسُولَ اللَّهِ قَالَ مَا شَأْنُكِ قَالَتْ لَا أَنَا وَلَا ثَابِتُ بْنُ قَيْسٍ لِزَوْجِهَا فَلَمَّا جَاءَ ثَابِتُ بْنُ قَيْسٍ قَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذِهِ حَبِيبَةُ بِنْتُ سَهْلٍ قَدْ ذَكَرَتْ مَا شَاءَ اللَّهُ أَنْ تَذْكُرَ فَقَالَتْ حَبِيبَةُ يَا رَسُولَ اللَّهِ كُلُّ مَا أَعْطَانِي عِنْدِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِثَابِتٍ خُذْ مِنْهَا فَأَخَذَ مِنْهَا وَجَلَسَتْ فِي أَهْلِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] ia berkata; telah memberitakan kepada kami [Ibnu Al Qasim] dari [Malik] dari [Yahya bin Sa'id] dari ['Amrah binti Abdurrahman] bahwa ia telah mengabarkan kepadanya dari [Habibah binti Sahl], bahwa ia pernah menjadi isteri Tsabit bin Qais bin Syammas. Dan Rasulullah shallallahu 'alaihi wasallam keluar untuk shalat Subuh, kemudian mendapati Habibah binti Sahl ada di depan pintunya di waktu yang masih gelap malam. Lalu Rasulullah shallallahu 'alaihi wasallam bertanya: \"Siapakah ini?\" Ia menjawab, \"Aku Habibah binti Sahl, wahai Rasulullah.\" Beliau bersabda: \"Apa urusanmu?\" Ia menjawab, \"Aku dab Tsabit bin Qais tidak ada kecocokkan.\" Kemudian setelah Tsabit bin Qais datang, Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Ini Habibah binti Sahl. Ia telah menyebutkan apa yang Allah kehendaki untuk ia sebutkan.\" Kemudian Habibah berkata, \"Wahai Rasulullah, seluruh apa yang ia berikan ada padaku.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepada Tsabit: \"Ambillah darinya.\" Kemudian iapun mengambil darinya, dan Habibah tinggal bersama keluarganya.\""},"3317":{"ar":"أَخْبَرَنَا أَزْهَرُ بْنُ جَمِيلٍ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ حَدَّثَنَا خَالِدٌ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ امْرَأَةَ ثَابِتِ بْنِ قَيْسٍ أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ ثَابِتُ بْنُ قَيْسٍ أَمَا إِنِّي مَا أَعِيبُ عَلَيْهِ فِي خُلُقٍ وَلَا دِينٍ وَلَكِنِّي أَكْرَهُ الْكُفْرَ فِي الْإِسْلَامِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَرُدِّينَ عَلَيْهِ حَدِيقَتَهُ قَالَتْ نَعَمْ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْبَلْ الْحَدِيقَةَ وَطَلِّقْهَا تَطْلِيقَةً","id":"Telah mengabarkan kepada kami [Azhar bin Jamil] ia berkata; telah menceritakan kepada kami [Abdul Wahhab] ia berkata; telah menceritakan kepada kami [Khalid] dari ['Ikrimah] dari [Ibnu Abbas], bahwa isteri Tsabit bin Qais datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, Tsabit bin Qais, aku tidak mencela akhlak dan agamanya, namun aku tidak ingin melakukan kekufuran dalam Islam.\" Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Maukah engkau mengembalikan kebunnya, \" ia menjawab, \"Ya.\" Rasulullah shallallahu 'alaihi wasallam bersabda (kepada Tsabit): \"Terimalah ladangnya dan talaklah ia sekali.\""},"3318":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ حُرَيْثٍ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى قَالَ حَدَّثَنَا الْحُسَيْنُ بْنُ وَاقِدٍ عَنْ عُمَارَةَ بْنِ أَبِي حَفْصَةَ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ امْرَأَتِي لَا تَمْنَعُ يَدَ لَامِسٍ فَقَالَ غَرِّبْهَا إِنْ شِئْتَ قَالَ إِنِّي أَخَافُ أَنْ تَتَّبِعَهَا نَفْسِي قَالَ اسْتَمْتِعْ بِهَا","id":"Telah mengabarkan kepada kami [Al Husain bin Huraits] ia berkata; telah menceritakan kepada kami [Al Fadll bin Musa] ia berkata; telah menceritakan kepada kami [Al Husain bin Waqid] dari ['Umarah bin Abi Hafshah] dari ['Ikrimah] dari [Ibnu Abbas] ia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya isteriku tidak menolak tangan orang yang menyentuhnya!\" Maka beliau bersabda: \"Asingkan dia apabila engkau mau.\" Laki-laki itu berkata, \"Aku khawatir hatiku akan mengikutinya.\" Beliau bersabda: \"Bersenang-senanglah dengannya.\""},"3319":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا النَّضْرُ بْنُ شُمَيْلٍ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ قَالَ أَنْبَأَنَا هَارُونُ بْنُ رِئَابٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ بْنِ عُمَيْرٍ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنَّ تَحْتِي امْرَأَةً لَا تَرُدُّ يَدَ لَامِسٍ قَالَ طَلِّقْهَا قَالَ إِنِّي لَا أَصْبِرُ عَنْهَا قَالَ فَأَمْسِكْهَاقَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا خَطَأٌ وَالصَّوَابُ مُرْسَلٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [An Nadlr bin Syumail] ia berkata; telah menceritakan kepada kami [Hammad bin Salamah] ia berkata; telah memberitakan kepada kami [Harun bin Ri`ab] dari [Abdullah bin 'Ubaid bin 'Umair] dari [Ibnu Abbas], bahwa seorang laki-laki berkata, \"Wahai Rasulullah, aku mempunyai seorang isteri yang tidak pernah menolak tangan orang yang menyentuhnya?\" Maka beliau bersabda: \"Ceraikan dia.\" Orang tersebut berkata, \"Aku tidak dapat bersabar darinya (masih cinta)?\" Maka beliau bersabda: \"Kalau begitu pertahankanlah bahteramu.\" Abu Abdurrahman berkata, \"Ini adalah salah, dan yang benar hadits ini adalah mursal.\""},"3320":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا عَبْدُ الْعَزِيزِ بْنُ أَبِي سَلَمَةَ وَإِبْرَاهِيمُ بْنُ سَعْدٍ عَنْ الزُّهْرِيِّ عَنْ سَهْلِ بْنِ سَعْدٍ عَنْ عَاصِمِ بْنِ عَدِيٍّ قَالَجَاءَنِي عُوَيْمِرٌ رَجُلٌ مِنْ بَنِي الْعَجْلَانِ فَقَالَ أَيْ عَاصِمُ أَرَأَيْتُمْ رَجُلًا رَأَى مَعَ امْرَأَتِهِ رَجُلًا أَيَقْتُلُهُ فَتَقْتُلُونَهُ أَمْ كَيْفَ يَفْعَلُ يَا عَاصِمُ سَلْ لِي رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَ عَاصِمٌ عَنْ ذَلِكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَعَابَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسَائِلَ وَكَرِهَهَا فَجَاءَهُ عُوَيْمِرٌ فَقَالَ مَا صَنَعْتَ يَا عَاصِمُ فَقَالَ صَنَعْتُ أَنَّكَ لَمْ تَأْتِنِي بِخَيْرٍ كَرِهَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْمَسَائِلَ وَعَابَهَا قَالَ عُوَيْمِرٌ وَاللَّهِ لَأَسْأَلَنَّ عَنْ ذَلِكَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْطَلَقَ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَهُ فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَنْزَلَ اللَّهُ عَزَّ وَجَلَّ فِيكَ وَفِي صَاحِبَتِكَ فَأْتِ بِهَا قَالَ سَهْلٌ وَأَنَا مَعَ النَّاسِ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ بِهَا فَتَلَاعَنَا فَقَالَ يَا رَسُولَ اللَّهِ وَاللَّهِ لَئِنْ أَمْسَكْتُهَا لَقَدْ كَذَبْتُ عَلَيْهَا فَفَارَقَهَا قَبْلَ أَنْ يَأْمُرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِفِرَاقِهَا فَصَارَتْ سُنَّةَ الْمُتَلَاعِنَيْنِ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] ia berkata; telah menceritakan kepada kami [Abu Daud] ia berkata; telah menceritakan kepada kami [Abdul Aziz bin Abu Salamah] dan [Ibrahim bin Sa'd] dari [Az Zuhri] dari [Sahl bin Sa'd] dari ['Ashim bin Adi] ia berkata, \"Uwaimir, seorang laki-laki dari Bani Al 'Ajlan, datang kepadaku. Ia berkata, \"Wahai 'Ashim, bagaimana pendapatmu mengenai seorang laki-laki yang melihat seorang laki-laki bersama isterinya? Apakah ia boleh membunuhnya sehingga mereka (wali kurban) membunuhnya (sebagai qishash) atau bagaimana ia berbuat? Wahai 'Ashim, tanyakanlah kepada Rasulullah shallallahu 'alaihi wasallam.\" Kemudian 'Ashim bertanya mengenai hal tersebut kepada Nabi shallallahu 'alaihi wasallam. Lalu Rasulullah shallallahu 'alaihi wasallam mencela permasalahan-permasalahan tersebut, dan beliau tidak menyukainya. Kemudian 'Uwaimir datang dan berkata, \"Apa yang telah engkau perbuat wahai 'Ashim? Ashim menjawab, \"Aku berbuat bahwa engkau tidak datang kepadaku dengan kebaikan, Rasulullah shallallahu 'alaihi wasallam tidak menyukai permasalahan-permasalahan tersebut, dan mencelanya.\" 'Uwaimir berkata, \"Demi Allah, sungguh aku akan menanyakan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam.\" Kemudian ia datang kepada Rasulullah shallallahu 'alaihi wasallam dan bertanya kepadanya. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda kepadanya: \"Sungguh Allah 'azza wajalla telah menurunkan mengenai dirimu dan isterimu. Maka datangkanlah dia.\" Sahl berkata, \"Aku bersama orang-orang berada di sisi Rasulullah shallallahu 'alaihi wasallam, kemudian ia datang membawa isterinya. Keduanya lalu saling melaknat, 'Uwaimir kemudian berkata, \"Wahai Rasulullah, demi Allah, seandainya aku menahannya sungguh aku telah berdusta terhadapnya.\" Kemudian ia menceraikannya sebelum Rasulullah shallallahu 'alaihi wasallam memerintahkannya untuk menceraikannya. Kemudian hal tersebut menjadi hukum dua orang yang saling melaknat.\""},"3321":{"ar":"حَدَّثَنَا أَحْمَدُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ أَبِي بَكْرٍ قَالَ حَدَّثَنَا عُمَرُ بْنُ عَلِيٍّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ عُقْبَةَ عَنْ أَبِي الزِّنَادِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ ابْنِ عَبَّاسٍ قَالَلَاعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ الْعَجْلَانِيِّ وَامْرَأَتِهِ وَكَانَتْ حُبْلَى","id":"Telah mengabarkan kepada kami [Ahmad bin Ali] ia berkata; telah menceritakan kepada kami [Muhammad bin Abu Bakr] ia berkata; telah menceritakan kepada kami [Umar bin Ali] ia berkata; telah menceritakan kepada kami [Ibrahim bin 'Uqbah] dari [Abu Az Zinad] dari [Al Qasim bin Muhammad] dari [Ibnu Abbas] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam melaknat memerintahkan seorang laki-laki dari Al 'Ajlan dan isterinya yang sedang keadaan hamil untuk saling melaknat (sumpah).\""},"3322":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ الْأَعْلَى قَالَ سُئِلَ هِشَامٌ عَنْ الرَّجُلِ يَقْذِفُ امْرَأَتَهُ فَحَدَّثَنَا هِشَامٌ عَنْ مُحَمَّدٍ قَالَسَأَلْتُ أَنَسَ بْنَ مَالِكٍ عَنْ ذَلِكَ وَأَنَا أَرَى أَنَّ عِنْدَهُ مِنْ ذَلِكَ عِلْمًا فَقَالَ إِنَّ هِلَالَ بْنَ أُمَيَّةَ قَذَفَ امْرَأَتَهُ بِشَرِيكِ بْنِ السَّحْمَاءِ وَكَانَ أَخُو الْبَرَاءِ بْنِ مَالِكٍ لِأُمِّهِ وَكَانَ أَوَّلَ مَنْ لَاعَنَ فَلَاعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَا ثُمَّ قَالَ ابْصُرُوهُ فَإِنْ جَاءَتْ بِهِ أَبْيَضَ سَبِطًا قَضِيءَ الْعَيْنَيْنِ فَهُوَ لِهِلَالِ بْنِ أُمَيَّةَ وَإِنْ جَاءَتْ بِهِ أَكْحَلَ جَعْدًا أَحْمَشَ السَّاقَيْنِ فَهُوَ لِشَرِيكِ بْنِ السَّحْمَاءِ قَالَ فَأُنْبِئْتُ أَنَّهَا جَاءَتْ بِهِ أَكْحَلَ جَعْدًا أَحْمَشَ السَّاقَيْنِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Abdul A'la] ia berkata; Hisyam pernah ditanya mengenai seorang laki-laki yang menuduh isterinya berbuat zina. Maka [Hisyam] menceritakan kepada kami dari [Muhammad] ia berkata; aku telah bertanya kepada [Anas bin Malik] mengenai hal tersebut, dan aku melihat ia memiliki ilmu mengenai hal tersebut. Anas berkata, \"Sesungguhnya Hilal bin Umayyah telah menuduh isterinya berbuat zina dengan Syarik bin As Sahma`, dan ia adalah saudara Al Barra` bin Malik seibu. Dan ia adalah orang pertama yang melakukan li'an. Kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkan keduanya untuk saling laknat (sumpah). Setelah itu beliau bersabda: \"Lihatlah, apabila wanita tersebut melahirkan anak yang putih, berambut lurus, dan kedua matanya rusak, maka ia adalah milik Hilal bin Umayyah. Dan apabila ia melahirkan anak yang hitam pelupuk matanya, berambut keriting, kedua betisnya kecil maka ia adalah milik Syarik bin As Sahma`.\" Anas berkata, \"Kemudian aku diberitahu bahwa wanita tersebut melahirkan anak yang berpelupuk mata hitam, berambut keriting, dan kecil kedua betisnya.\""},"3323":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ يَزِيدَ قَالَ حَدَّثَنَا مَخْلَدُ بْنُ حُسَيْنٍ الْأَزْدِيُّ قَالَ حَدَّثَنَا هِشَامُ بْنُ حَسَّانَ عَنْ مُحَمَّدِ بْنِ سِيرِينَ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَإِنَّ أَوَّلَ لِعَانٍ كَانَ فِي الْإِسْلَامِ أَنَّ هِلَالَ بْنَ أُمَيَّةَ قَذَفَ شَرِيكَ بْنَ السَّحْمَاءِ بِامْرَأَتِهِ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِذَلِكَ فَقَالَ لَهُ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْبَعَةَ شُهَدَاءَ وَإِلَّا فَحَدٌّ فِي ظَهْرِكَ يُرَدِّدُ ذَلِكَ عَلَيْهِ مِرَارًا فَقَالَ لَهُ هِلَالٌ وَاللَّهِ يَا رَسُولَ اللَّهِ إِنَّ اللَّهَ عَزَّ وَجَلَّ لَيَعْلَمُ أَنِّي صَادِقٌ وَلَيُنْزِلَنَّ اللَّهُ عَزَّ وَجَلَّ عَلَيْكَ مَا يُبَرِّئُ ظَهْرِي مِنْ الْجَلْدِ فَبَيْنَمَا هُمْ كَذَلِكَ إِذْ نَزَلَتْ عَلَيْهِ آيَةُ اللِّعَانِ{ وَالَّذِينَ يَرْمُونَ أَزْوَاجَهُمْ }إِلَى آخِرِ الْآيَةِ فَدَعَا هِلَالًا فَشَهِدَ أَرْبَعَ شَهَادَاتٍ بِاللَّهِ إِنَّهُ لَمِنْ الصَّادِقِينَ وَالْخَامِسَةُ أَنَّ لَعْنَةَ اللَّهِ عَلَيْهِ إِنْ كَانَ مِنْ الْكَاذِبِينَ ثُمَّ دُعِيَتْ الْمَرْأَةُ فَشَهِدَتْ أَرْبَعَ شَهَادَاتٍ بِاللَّهِ إِنَّهُ لَمِنْ الْكَاذِبِينَ فَلَمَّا أَنْ كَانَ فِي الرَّابِعَةِ أَوْ الْخَامِسَةِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقِّفُوهَا فَإِنَّهَا مُوجِبَةٌ فَتَلَكَّأَتْ حَتَّى مَا شَكَكْنَا أَنَّهَا سَتَعْتَرِفُ ثُمَّ قَالَتْ لَا أَفْضَحُ قَوْمِي سَائِرَ الْيَوْمِ فَمَضَتْ عَلَى الْيَمِينِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ انْظُرُوهَا فَإِنْ جَاءَتْ بِهِ أَبْيَضَ سَبِطًا قَضِيءَ الْعَيْنَيْنِ فَهُوَ لِهِلَالِ بْنِ أُمَيَّةَ وَإِنْ جَاءَتْ بِهِ آدَمَ جَعْدًا رَبْعًا حَمْشَ السَّاقَيْنِ فَهُوَ لِشَرِيكِ بْنِ السَّحْمَاءِ فَجَاءَتْ بِهِ آدَمَ جَعْدًا رَبْعًا حَمْشَ السَّاقَيْنِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْلَا مَا سَبَقَ فِيهَا مِنْ كِتَابِ اللَّهِ لَكَانَ لِي وَلَهَا شَأْنٌقَالَ الشَّيْخُ وَالْقَضِئُ طَوِيلُ شَعْرِ الْعَيْنَيْنِ لَيْسَ بِمَفْتُوحِ الْعَيْنِ وَلَا جَاحِظِهِمَا وَاللَّهُ سُبْحَانَهُ وَتَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami ['Imran bin Yazid] Ia berkata; telah menceritakan kepada kami [Makhlad bin Husain Al Azdi] ia berkata; telah menceritakan kepada kami [Hisyam bin Hassan] dari [Muhammad bin Sirin] dari [Anas bin Malik] ia berkata, \"Peristiwa li'an yang pertama dalam Islam adalah ketika Hilal bin Umayyah menuduh Syarik bin As Sahma` bezina dengan isterinya. Kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan mengabarkan hal tersebut. Lalu Nabi shallallahu 'alaihi wasallam bersabda kepadanya: \"Datangkanlah empat orang saksi, jika tidak maka hukuman had di punggungmu.\" Beliau mengulang-ulang perkataan itu kepadanya. Kemudian Hilal berkata kepadanya, \"Demi Allah! Wahai Rasulullah, sungguh Allah 'azza wajalla mengetahui bahwa aku benar, dan Allah pasti akan menurunkan kepadamu sesuatu yang akan membebaskan punggungku dari cambukan.\" Kemudian ketika mereka dalam keadaan demikian tiba-tiba turun ayat li'an: '(Dan orang-orang yang menuduh isterinya (berzina) ….) ' (Qs. An Nuur: 6). Kemudian beliau memanggil Hilal, lalu ia bersumpah empat kali sumpah dengan nama Allah bahwa ia termasuk orang-orang yang benar, dan yang kelimanya bahwa laknat Allah akan menimpanya jika ia termasuk orang-orang yang berdusta. Kemudian wanita tersebut dipanggil dan bersumpah empat kali sumpah dengan nama Allah bahwa suaminya termasuk orang-orang yang berdusta. Kemudian setelah keempat atau kelimanya, Rasulullah shallallahu 'alaihi wasallam bersabda: \"Berdirikanlah dia, sesungguhnya sumpah itu telah terjadi.\" Kemudian ia tertunda, hingga kami tidak ragu bahwa ia akan mengaku. Kemudian wanita tersebut berkata, \"Aku tidak akan mencemarkan kaumku sepanjang hari.\" Lalu ia terus bersumpah, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Lihatlah dia, apabila ia melahirkan anak yang putih, berambut lurus dan bermata rusak, maka ia milik Hilal bin Umayyah. Dan apabila ia melahirkan anak berkulit sawo matang, berambut keriting, kedua betisnya kecil maka ia milik Syarik bin As Sahma`.\" Kemudian wanita tersebut melahirkan anak yang berkulit sawo matang, berambut keriting, dan kedua betisnya kecil. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seandainya tidak ada ketentuan yang telah berlalu mengenainya dari Kitab Allah, niscaya aku memiliki urusan dengan wanita tersebut.\" Syaikh berkata, \"Qadli` adalah rambut kedua matanya panjang, dan matanya tidak terbuka, serta tidak melotot. Waallahu A'lam.\""},"3324":{"ar":"أَخْبَرَنَا عِيسَى بْنُ حَمَّادٍ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ الْقَاسِمِ عَنْ الْقَاسِمِ بْنِ مُحَمَّدٍ عَنْ ابْنِ عَبَّاسٍ أَنَّهُ قَالَذُكِرَ التَّلَاعُنُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَاصِمُ بْنُ عَدِيٍّ فِي ذَلِكَ قَوْلًا ثُمَّ انْصَرَفَ فَأَتَاهُ رَجُلٌ مِنْ قَوْمِهِ يَشْكُو إِلَيْهِ أَنَّهُ وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا قَالَ عَاصِمٌ مَا ابْتُلِيتُ بِهَذَا إِلَّا بِقَوْلِي فَذَهَبَ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِالَّذِي وَجَدَ عَلَيْهِ امْرَأَتَهُ وَكَانَ ذَلِكَ الرَّجُلُ مُصْفَرًّا قَلِيلَ اللَّحْمِ سَبِطَ الشَّعْرِ وَكَانَ الَّذِي ادَّعَى عَلَيْهِ أَنَّهُ وَجَدَهُ عِنْدَ أَهْلِهِ آدَمَ خَدْلًا كَثِيرَ اللَّح��مِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَيِّنْ فَوَضَعَتْ شَبِيهًا بِالرَّجُلِ الَّذِي ذَكَرَ زَوْجُهَا أَنَّهُ وَجَدَهُ عِنْدَهَا فَلَاعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَافَقَالَ رَجُلٌ لِابْنِ عَبَّاسٍ فِي الْمَجْلِسِ أَهِيَ الَّتِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ رَجَمْتُ أَحَدًا بِغَيْرِ بَيِّنَةٍ رَجَمْتُ هَذِهِ قَالَ ابْنُ عَبَّاسٍ لَا تِلْكَ امْرَأَةٌ كَانَتْ تُظْهِرُ فِي الْإِسْلَامِ الشَّرَّ","id":"Telah mengabarkan kepada kami [Isa bin Hammad] ia berkata; telah memberitakan kepada kami [Al Laits] dari [Yahya bin Sa'id] dari [Abdurrahman bin Al Qasim] dari [Al Qasim bin Muhammad] dari [Ibnu Abbas] bahwa ia berkata, \"Telah disebutkan li'an di sisi Rasulullah shallallahu 'alaihi wasallam kemudian, 'Ashim bin 'Adi lalu berkata dengan suatu perkataan mengenai hal tersebut kemudian pergi. Lalu seorang laki-laki dari kaumnya datang mengadu kepadanya bahwa ia mendapati seseorang bersama isterinya. 'Ashim berkata, \"Aku tidak mendapatkan ujian dengan hal ini kecuali karena perkataanku.\" Kemudian ia pergi bersamanya kepada Rasulullah shallallahu 'alaihi wasallam dan mengabarkan kepada beliau mengenai seseorang yang mendapati isterinya berada di atasnya. Laki-laki tersebut adalah orang yang kuning, sedikit dagingnya, dan berambut lurus. Sedangkan orang yang ia tuduh, bahwa ia mendapatinya di sisi isterinya adalah orang yang berkulit sawo matang, gempal, dan banyak dagingnya. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, berilah kejelasan.\" Kemudian wanita tersebut melahirkan anak yang serupa dengan orang yang disebutkan suaminya, bahwa ia mendapatinya di sisi isterinya. Dan Rasulullah shallallahu 'alaihi wasallam memerintahkan antara keduanya untuk saling laknat (sumpah). Kemudian seorang laki-laki berkata kepada Ibnu Abbas dalam suatu majelis, \"Apakah wanita tersebut adalah yang dikatakan oleh Rasulullah shallallahu 'alaihi wasallam: 'Seandainya aku boleh merajam seseorang tanpa ada bukti maka aku akan merajam wanita ini'? Ibnu Abbas menjawab, \"Tidak. Itu adalah wanita yang menampakkan keburukan dalam Islam.\""},"3325":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ مُحَمَّدِ بْنِ السَّكَنِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَهْضَمٍ عَنْ إِسْمَعِيلَ بْنِ جَعْفَرٍ عَنْ يَحْيَى قَالَ سَمِعْتُ عَبْدَ الرَّحْمَنِ بْنَ الْقَاسِمِ يُحَدِّثُ عَنْ أَبِيهِ عَنْ عَبْدِ اللَّهِ بْنِ عَبَّاسٍ أَنَّهُ قَالَذُكِرَ التَّلَاعُنُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ عَاصِمُ بْنُ عَدِيٍّ فِي ذَلِكَ قَوْلًا ثُمَّ انْصَرَفَ فَلَقِيَهُ رَجُلٌ مِنْ قَوْمِهِ فَذَكَرَ أَنَّهُ وَجَدَ مَعَ امْرَأَتِهِ رَجُلًا فَذَهَبَ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ بِالَّذِي وَجَدَ عَلَيْهِ امْرَأَتَهُ وَكَانَ ذَلِكَ الرَّجُلُ مُصْفَرًّا قَلِيلَ اللَّحْمِ سَبِطَ الشَّعْرِ وَكَانَ الَّذِي ادَّعَى عَلَيْهِ أَنَّهُ وَجَدَ عِنْدَ أَهْلِهِ آدَمَ خَدْلًا كَثِيرَ اللَّحْمِ جَعْدًا قَطَطًا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اللَّهُمَّ بَيِّنْ فَوَضَعَتْ شَبِيهًا بِالَّذِي ذَكَرَ زَوْجُهَا أَنَّهُ وَجَدَهُ عِنْدَهَا فَلَاعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَهُمَافَقَالَ رَجُلٌ لِابْنِ عَبَّاسٍ فِي الْمَجْلِسِ أَهِيَ الَّتِي قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَوْ رَجَمْتُ أَحَدًا بِغَيْرِ بَيِّنَةٍ رَجَمْتُ هَذِهِ قَالَ ابْنُ عَبَّاسٍ لَا تِلْكَ امْرَأَةٌ كَانَتْ تُظْهِرُ الشَّرَّ فِي الْإِسْلَامِ","id":"Telah mengabarkan kepada kami [Yahya bin Muhammad bin As Sakan] ia berkata; telah menceritakan kepada kami [Muhammad bin Jahdlam] dari [Isma'il bin Ja'far] dari [Yahya] ia berkata; aku mendengar [Abdurrahman bin Al Qasim] menceritakan dari [ayahnya] dari [Abdullah bin Abbas] bahwa ia berkata, \"Telah disebutkan li'an di hadapan Rasulullah shallallahu 'alaihi wasallam. Kemudian 'Ashim bin 'Adi menyebutkan suatu perkataan mengenai hal tersebut, kemudian ia pergi. Lalu seorang laki-laki dari kaumnya berjumpa dengannya kemudian menyebutkan, bahwa ia mendapati seorang laki-laki sedang bersama dengan isterinya. Maka 'Ashim mengajaknya pergi bersamanya menemui Rasulullah shallallahu 'alaihi wasallam. Lalu ia mengabarkan kepada beliau mengenai seseorang yang mendapati orang lainsedang bersama isterinya. Laki-laki tersebut adalah orang yang kuning, sedikit dagingnya, dan berambut lurus. Sedangkan orang yang ia tuduh bahwa ia mendapatinya di sisi isterinya adalah orang yang berkulit sawo matang, gempal, banyak dagingnya berambut keriting dan sangat kaku. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya Allah, berilah kejelasan.\" Kemudian wanita tersebut melahirkan anak yang serupa dengan orang yang disebutkan suaminya bahwa ia mendapatinya di sisi isterinya. Rasulullah shallallahu 'alaihi wasallam lalu memerintahkan kepada keduanya untuk saling laknat (sumpah). Kemudian seorang laki-laki berkata kepada Ibnu Abbas dalam suatu majelis, 'Apakah wanita tersebut adalah yang dikatakan oleh Rasulullah shallallahu 'alaihi wasallam: 'Seandainya aku boleh merajam seseorang tanpa ada bukti maka aku akan merajam wanita ini? ' Ibnu Abbas menjawab, \"Tidak. Itu adalah wanita yang menampakkan keburukan dalam Islam.\""},"3326":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ مَيْمُونٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَاصِمِ بْنِ كُلَيْبٍ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَ رَجُلًا حِينَ أَمَرَ الْمُتَلَاعِنَيْنِ أَنْ يَتَلَاعَنَا أَنْ يَضَعَ يَدَهُ عِنْدَ الْخَامِسَةِ عَلَى فِيهِ وَقَالَ إِنَّهَا مُوجِبَةٌ","id":"Telah mengabarkan kepada kami [Ali bin Makmun] ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Ashim bin Kulaib] dari [ayahnya] dari [Ibnu Abbas], bahwa Nabi shallallahu 'alaihi wasallam memerintahkan seseorang ketika -memerintahkan dua laki-laki yang saling melakukan li'an (sumpah) -, untuk meletakkan tangannya pada mulut pada kali kelimanyha. Beliau bersabda: \"Sesungguhnya ia telah wajib (mendapat murka Allah jika berdusta).\""},"3327":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى قَالَا حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا عَبْدُ الْمَلِكِ بْنُ أَبِي سُلَيْمَانَ قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يَقُولُسُئِلْتُ عَنْ الْمُتَلَاعِنَيْنِ فِي إِمَارَةِ ابْنِ الزُّبَيْرِ أَيُفَرَّقُ بَيْنَهُمَا فَمَا دَرَيْتُ مَا أَقُولُ فَقُمْتُ مِنْ مَقَامِي إِلَى مَنْزِلِ ابْنِ عُمَرَ فَقُلْتُ يَا أَبَا عَبْدِ الرَّحْمَنِ الْمُتَلَاعِنَيْنِ أَيُفَرَّقُ بَيْنَهُمَا قَالَ نَعَمْ سُبْحَانَ اللَّهِ إِنَّ أَوَّلَ مَنْ سَأَلَ عَنْ ذَلِكَ فُلَانُ بْنُ فُلَانٍ فَقَالَ يَا رَسُولَ اللَّهِ أَرَأَيْتَ وَلَمْ يَقُلْ عَمْرٌو أَرَأَيْتَ الرَّجُلَ مِنَّا يَرَى عَلَى امْرَأَتِهِ فَاحِشَةً إِنْ تَكَلَّمَ فَأَمْرٌ عَظِيمٌ وَقَالَ عَمْرٌو أَتَى أَمْرًا عَظِيمًا وَإِنْ سَكَتَ سَكَتَ عَلَى مِثْلِ ذَلِكَ فَلَمْ يُجِبْهُ فَلَمَّا كَانَ بَعْدَ ذَلِكَ أَتَاهُ فَقَالَ إِنَّ الْأَمْرَ الَّذِي سَأَلْتُكَ ابْتُلِيتُ بِهِ فَأَنْزَلَ اللَّهُ عَزَّ وَجَلَّ هَؤُلَاءِ الْآيَاتِ فِي سُورَةِ النُّورِ{ وَالَّذِينَ يَرْمُونَ أَزْوَاجَهُمْ حَتَّى بَلَغَ وَالْخَامِسَةَ أَنَّ غَضَبَ اللَّهِ عَلَيْهَا إِنْ كَانَ مِنْ الصَّادِقِينَ }فَبَدَأَ بِالرَّجُلِ فَوَعَظَهُ وَذَكَّرَهُ وَأَخْبَرَهُ أَنَّ عَذَابَ الدُّنْيَا أَهْوَنُ مِنْ عَذَابِ الْآخِرَةِ فَقَالَ وَالَّذِي بَعَثَكَ بِالْحَقِّ مَا كَذَبْتُ ثُمَّ ثَنَّى بِالْمَرْأَةِ فَوَعَظَهَا وَذَكَّرَهَا فَقَالَتْ وَالَّذِي بَعَثَكَ بِالْحَقِّ إِنَّهُ لَكَاذِبٌ فَبَدَأَ بِالرَّجُلِ فَشَهِدَ أَرْبَعَ شَهَادَاتٍ بِاللَّهِ إِنَّهُ لَمِنْ الصَّادِقِينَ وَالْخَامِسَةُ أَنَّ لَعْنَةَ اللَّهِ عَلَيْهِ إِنْ كَانَ مِنْ الْكَاذِبِينَ ثُمَّ ثَنَّى بِالْمَرْأَةِ فَشَهِدَتْ أَرْبَعَ شَهَادَاتٍ بِاللَّهِ إِنَّهُ لَمِنْ الْكَاذِبِينَ وَالْخَامِسَةَ أَنَّ غَضَبَ اللَّهِ عَلَيْهَا إِنْ كَانَ مِنْ الصَّادِقِينَ فَفَرَّقَ بَيْنَهُمَا","id":"Telah mengabarkan kepada kami ['Amru bin Ali] dan [Muhammad bin Al Mutsanna] mereka berkata; telah menceritakan kepada kami [Yahya bin Sa'id] ia berkata; telah menceritakan kepada kami [Abdul Malik bin Abu Sulaiman] ia berkata; aku mendengar [Sa'id bin Jubair] berkata, \"Aku ditanya mengenai dua orang yang saling melakukan li'an (sumpah) pada masa pemerintahan Ibnu Az Zubair, apakah keduanya dipisahkan? Maka aku tidak mengetahui apa yang akan aku katakan. Kemudian aku berdiri dari tempatku menuju rumah [Ibnu Umar] dan berkata, \"Wahai Abu Abdurrahman, apakah dua orang yang melakukan li'an dipisahkan antara keduanya? Ia menjawab, \"Ya, subhanallah. Sesungguhnya orang pertama yang bertanya mengenai hal tersebut adalah Fulan bin Fulan. Ia berkata, \"Wahai Rasulullah, bagaimana pendapat anda… -'Amru tidak berkata; bagaimana pendapatmu- seorang lelaki di antara kami melihat perbuatan keji pada isterinya, apabila ia berbicara maka hal itu adalah suatu perkara yang besar, -sedangkan 'Amru berkata; ia telah melakukan perkara yang besar-, dan apabila ia diam maka ia diam dalam kondisi seperti itu.\" Kemudian beliau tidak menjawabnya. Setelah itu, orang tersebut datang kepada beliau dan berkata, \"Sesungguhnya perkara yang telah aku tanyakan kepada anda, telah diujikan kepadaku (membuat penderitaan). Kemudian Allah 'azza wajalla menurunkan ayat-ayat tersebut pada Surat An Nuur: '(Dan orang-orang yang menuduh isterinya (berzina), hingga firman Allah (dan (sumpah) yang kelima bahwa kemurkaan Allah akan menimpanya (isteri), jika dia (suami) termasuk orang yang berkata benar) ' (Qs. An Nuur: 6-9). Maka beliau memulai dari laki-laki, menasehati, mengingatkan dan mengabarkan kepadanya, bahwa adzab dunia lebih ringan daripada 'adzab akhirat. Kemudian orang tersebut berkata, 'Demi Dzat yang telah mengutusmu dengan kebenaran, aku tidak berdusta.' Kemudian kepada wanita, beliau nasehati dan mengingatkannya. Kemudian wanita tersebut berkata, 'Demi Dzat yang mengutusmu dengan kebenaran, sesungguhnya ia telah berdusta.' Kemudian beliau memulai dari yang laki-laki (untuk bersumpah). Maka laki-laki itu pun bersumpah empat kali dengan nama Allah, bahwa ia termasuk di antara orang-orang yang benar, dan yang kelimanya bahwa laknat Allah tertimpa kepadanya apabila ia termasuk orang yang berdusta. Kemudian kepada yang wanita, maka ia bersumpah sebanyak empat kali dengan nama Allah, bahwa suaminya merupakan di antara orang-orang yang berdusta, dan yang kelimanya bahwa kemurkaan Allah tertimpa kepadanya apabila suaminya termasuk di antara orang-orang yang benar. Kemudian beliau memisahkan di antara mereka berdua.\""},"3328":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ وَمُحَمَّدُ بْنُ الْمُثَنَّى وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا مُعَاذُ بْنُ هِشَامٍ حَدَّثَنِي أَبِي عَنْ قَتَادَةَ عَنْ عَزْرَةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَلَمْ يُفَرِّقْ الْمُصْعَبُ بَيْنَ الْمُتَلَاعِنَيْنِ قَالَ سَعِيدٌ فَذَكَرْتُ ذَلِكَ لِابْنِ عُمَرَ فَقَالَ فَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَخَوَيْ بَنِي الْعَجْلَانِ","id":"Telah mengabarkan kepada kami ['Amr bin Ali] dan [Muhammad bin Al Mutsanna] dan lafazhnya adalah lafazh Muhammad bin Al Mutsanna, mereka berdua berkata; telah menceritakan kepada kami [Mu'adz bin Hisyam] telah menceritakan kepadaku [ayahku] dari [Qatadah] dari ['Azrah] dari [Sa'id bin Jubair] ia berkata, \"Mush'ab tidak memisahkan antara kedua orang yang saling melakukan li'an (sumpah).\" Sa'id berkata, \"Kemudian aku sebutkan hal tersebut kepada [Ibnu Umar], maka ia pun berkata, \"Rasulullah shallallahu 'alaihi wasallam telah memisahkan antara dua saudara Bani Al 'Ajlan.\""},"3329":{"ar":"أَخْبَرَنَا زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا ابْنُ عُلَيَّةَ عَنْ أَيُّوبَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَقُلْتُ لِابْنِ عُمَرَ رَجُلٌ قَذَفَ امْرَأَتَهُ قَالَ فَرَّقَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ أَخَوَيْ بَنِي الْعَجْلَانِ وَقَالَ اللَّهُ يَعْلَمُ إِنَّ أَحَدَكُمَا كَاذِبٌ فَهَلْ مِنْكُمَا تَائِبٌ قَالَ لَهُمَا ثَلَاثًا فَأَبَيَا فَفَرَّقَ بَيْنَهُمَاقَالَ أَيُّوبُ وَقَالَ عَمْرُو بْنُ دِينَارٍ إِنَّ فِي هَذَا الْحَدِيثِ شَيْئًا لَا أَرَاكَ تُحَدِّثُ بِهِ قَالَ قَالَ الرَّجُلُ مَالِي قَالَ لَا مَالَ لَكَ إِنْ كُنْتَ صَادِقًا فَقَدْ دَخَلْتَ بِهَا وَإِنْ كُنْتَ كَاذِبًا فَهِيَ أَبْعَدُ مِنْكَ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] ia berkata; telah menceritakan kepada kami [Ibnu 'Uliyyah] dari [Ayyub] dari [Sa'id bin Jubair] ia berkata; aku berkata kepada [Ibnu Umar], \"Seorang laki-laki menuduh isterinya berbuat zina?\" Ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam telah memisahkan antara dua saudara Bani Al 'Ajlan, beliau bersabda: \"Sesungguhnya Allah mengetahui bahwa salah seorang di antara kalian berdusta. Apakah di antara kalian berdua ada yang bertaubat?\" Beliau mengatakan demikian kepada mereka sebanya tiga kali. Kemudian mereka menolak, lalu beliau memisahkan antara keduanya.\" Ayyub berkata, \"'Amru bin Dinar berkata, \"Aku melihat bahwa dalam hadits ini ada sesuatu yang tidak kamuj ceritakan.\" Ia berkata, \"Laki-laki (suami) itu berkata, \"Hartaku?\" Beliau menjawab: \"Tidak ada harta bagimu, jika kamu berkata benar maka kamu juga telah bersetubuh dengannya, namun jika kamu bohong maka harta itu lebih mustahil untuk kamu dapatkan lagi.\""},"3330":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عَمْرٍو قَالَ سَمِعْتُ سَعِيدَ بْنَ جُبَيْرٍ يَقُولُسَأَلْتُ ابْنَ عُمَرَ عَنْ الْمُتَلَاعِنَيْنِ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لِلْمُتَلَاعِنَيْنِ حِسَابُكُمَا عَلَى اللَّهِ أَحَدُكُمَا كَاذِبٌ وَلَا سَبِيلَ لَكَ عَلَيْهَا قَالَ يَا رَسُولَ اللَّهِ مَالِي قَالَ لَا مَالَ لَكَ إِنْ كُنْتَ صَدَقْتَ عَلَيْهَا فَهُوَ بِمَا اسْتَحْلَلْتَ مِنْ فَرْجِهَا وَإِنْ كُنْتَ كَذَبْتَ عَلَيْهَا فَذَاكَ أَبْعَدُ لَكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Amru] ia berkata; aku pernah mendengar [Sa'id bin Jubair] berkata; aku bertanya [Ibnu Umar] mengenai dua orang yang melakukan li'an (sumpah). Ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam lalu bersabda kepada dua orang yang melakukan li'an: \"Hisap kalian ada pada Allah, salah seorang di antara kalian ada yang berdusta, dan tidak ada jalan bagimu untuk kembali kepada wanita itu.\" Orang tersebut berkata, \"Wahai Rasulullah, hartaku (mahar)?\" Beliau bersabda: \"Tidak ada harta bagimu, apabila engkau benar (dalam sumpahmu) maka hal itu sebagai ganti dari apa yang telah engkau halalkan dari kemaluannya, dan apabila engkau berdusta maka mustahil engkau akan mendapatkan harta itu lagi.\""},"3331":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَلَاعَنَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَيْنَ رَجُلٍ وَامْرَأَتِهِ وَفَرَّقَ بَيْنَهُمَا وَأَلْحَقَ الْوَلَدَ بِالْأُمِّ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Malik] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam memerintahkan antara suami dan isterinya untuk saling laknat (sumpah), lalu memisahkan antara keduanya dan menisbatkan sang anak kepada ibunya.\""},"3332":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا مِنْ بَنِي فَزَارَةَ أَتَى رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ امْرَأَتِي وَلَدَتْ غُلَامًا أَسْوَدَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ فَمَا أَلْوَانُهَا قَالَ حُمْرٌ قَالَ فَهَلْ فِيهَا مِنْ أَوْرَقَ قَالَ إِنَّ فِيهَا لَوُرْقًا قَالَ فَأَنَّى تَرَى أَتَى ذَلِكَ قَالَ عَسَى أَنْ يَكُونَ نَزَعَهُ عِرْقٌ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهَذَا عَسَى أَنْ يَكُونَ نَزَعَهُ عِرْقٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah], bahwa seorang laki-laki dari Bani Fazarah datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya isteriku melahirkan anak hitam!\" Maka Rasulullah shallallahu 'alaihi wasallam pun bertanya: \"Apakah engkau memiliki unta?\" Ia menjawab, \"Ya.\" Beliau bertanya lagi: \"Apakah warnanya?\" Ia menjawab, \"Merah.\" Beliau bertanya lagi: \"Apakah padanya terdapat warna putih kehitaman?\" Ia menjawab, \"Ya, padanya terdapat warna putih kehitaman.\" Beliau bersabda: \"Dari manakah menurut pendapatmu warna itu ada?\" Ia menjawab, \"Kemungkinan karena keturunan.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Barangkali anakmu juga karena keturunan.\""},"3333":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ بْنُ زُرَيْعٍ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ مِنْ بَنِي فَزَارَةَ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ امْرَأَتِي وَلَدَتْ غُلَامًا أَسْوَدَ وَهُوَ يُرِيدُ الِانْتِفَاءَ مِنْهُ فَقَالَ هَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ مَا أَلْوَانُهَا قَالَ حُمْرٌ قَالَ هَلْ فِيهَا مِنْ أَوْرَقَ قَالَ فِيهَا ذَوْدُ وُرْقٍ قَالَ فَمَا ذَاكَ تُرَى قَالَ لَعَلَّهُ أَنْ يَكُونَ نَزَعَهَا عِرْقٌ قَالَ فَلَعَلَّ هَذَا أَنْ يَكُونَ نَزَعَهُ عِرْقٌ قَالَ فَلَمْ يُرَخِّصْ لَهُ فِي الِانْتِفَاءِ مِنْهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Bazi'] ia berkata; telah menceritakan kepada kami [Yazid bin Zurai'] ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] ia berkata, \"Seorang laki-laki dari Bani Fazarah datang kepada Nabi shallallahu 'alaihi wasallam kemudian berkata, 'Sesungguhnya isteriku melahirkan anak berkulit hitam? ', dan ia ingin mengingkari asalnya dari dirinya. Beliau bersabda: \"Apakah engkau memiliki unta?\" Laki-laki itu menjawab, \"Ya.\" Beliau bersabda: \"Apakah warnanya?\" Ia menjawab, \"Merah.\" Beliau bersabda: \"Apakah padanya terdapat warna putih kehitaman?\" orang tersebut menjawab, \"Ya, padanya terdapat unta coklat.\" Beliau bersabda: \"Bagaimana pendapatmu?\" Ia berkata, \"Kemungkinan hal itu ditimbulkan oleh keturunan.\" Beliau bersabda: \"Kemungkinan anakmu juga ditimbulkan oleh keturunan.\" Abu Hurairah berkata, \"Maka beliau tidak memberikan keringanan untuk mengingkari asalnya dari dirinya.\""},"3334":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ مُحَمَّدِ بْنِ الْمُغِيرَةِ قَالَ حَدَّثَنَا أَبُو حَيْوَةَ حِمْصِيٌّ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ أَبِي حَمْزَةَ عَنْ الزُّهْرِيِّ عَنْ سَعِيدِ بْنِ الْمُسَيَّبِ عَنْ أَبِي هُرَيْرَةَ قَالَبَيْنَمَا نَحْنُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَامَ رَجُلٌ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي وُلِدَ لِي غُلَامٌ أَسْوَدُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَنَّى كَانَ ذَلِكَ قَالَ مَا أَدْرِي قَالَ فَهَلْ لَكَ مِنْ إِبِلٍ قَالَ نَعَمْ قَالَ فَمَا أَلْوَانُهَا قَالَ حُمْرٌ قَالَ فَهَلْ فِيهَا جَمَلٌ أَوْرَقُ قَالَ فِيهَا إِبِلٌ وُرْقٌ قَالَ فَأَنَّى كَانَ ذَلِكَ قَالَ مَا أَدْرِي يَا رَسُولَ اللَّهِ إِلَّا أَنْ يَكُونَ نَزَعَهُ عِرْقٌ قَالَ وَهَذَا لَعَلَّهُ نَزَعَهُ عِرْقٌ فَمِنْ أَجْلِهِ قَضَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَذَا لَا يَجُوزُ لِرَجُلٍ أَنْ يَنْتَفِيَ مِنْ وَلَدٍ وُلِدَ عَلَى فِرَاشِهِ إِلَّا أَنْ يَزْعُمَ أَنَّهُ رَأَى فَاحِشَةً","id":"Telah mengabarkan kepada kami [Ahmad bin Muhammad bin Al Mughirah] ia berkata; telah menceritakan kepada kami [Abu Haiwah Himshi] ia berkata; telah menceritakan kepada kami [Syu'aib bin Abi Hamzah] dari [Az Zuhri] dari [Sa'id bin Al Musayyab] dari [Abu Hurairah] ia berkata, \"Pada saat kami bersama Rasulullah shallallahu 'alaihi wasallam, seorang laki-laki berdiri dan berkata, 'wahai Rasulullah, aku mendapatkan kelahiran bayi yang berkulit hitam?\" Rasulullah shallallahu 'alaihi wasallam pun bertanya: \"Dari manakah hal itu datang?\" ia menjawab, \"Aku tidak tahu.\" Beliau bersabda: \"Apakah engkau memiliki unta?\" ia menjawab, \"Ya.\" Beliau bersabda: \"Apakah warnanya?\" Ia menjawab, \"Merah.\" Beliau lalu bertanya: \"Apakah padanya terdapat unta putih kehitaman?\" Orang tersebut menjawab, \"Ya.\" Beliau bertanya lagi: \"Dari manakah warna itu?\" orang itu menjawab, \"Aku tidak tahu wahai Rasulullah, kecuali bahwa ia ditimbulkan oleh keturunan.\" Beliau bersabda: \"Dan ini kemungkinan ditimbulkan oleh keturunan.\" Oleh Karena itu Rasulullah shallallahu 'alaihi wasallam memutuskan hal ini tidak boleh bagi seseorang untuk mengingkari anak yang terlahirkan di atas kasurnya, kecuali ia mengklaim melihat perbuatan keji.\""},"3335":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ عَبْدِ الْحَكَمِ قَالَ شُعَيْبٌ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ الْهَادِ عَنْ عَبْدِ اللَّهِ بْنِ يُونُسَ عَنْ سَعِيدِ بْنِ أَبِي سَعِيدٍ الْمَقْبُرِيِّ عَنْ أَبِي هُرَيْرَةَأَنَّهُ سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ حِينَ نَزَلَتْ آيَةُ الْمُلَاعَنَةِ أَيُّمَا امْرَأَةٍ أَدْخَلَتْ عَلَى قَوْمٍ رَجُلًا لَيْسَ مِنْهُمْ فَلَيْسَتْ مِنْ اللَّهِ فِي شَيْءٍ وَلَا يُدْخِلُهَا اللَّهُ جَنَّتَهُ وَأَيُّمَا رَجُلٍ جَحَدَ وَلَدَهُ وَهُوَ يَنْظُرُ إِلَيْهِ احْتَجَبَ اللَّهُ عَزَّ وَجَلَّ مِنْهُ وَفَضَحَهُ عَلَى رُءُوسِ الْأَوَّلِينَ وَالْآخِرِينَ يَوْمَ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Abdul Hakam] ia berkata; [Syu'aib] berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Al Had] dari [Abdullah bin Yunus] dari [Sa'id bin Abi Sa'id Al Maqburi] dari [Abu Hurairah], bahwa ia mendengar Rasulullah shallallahu 'alaihi wasallam bersabda ketika turun ayat mengenai li'an: \"Wanita mana saja yang memasukkan seorang laki-laki (asing) yang bukan dari mereka, maka ia bukan bagian dari Allah sedikitpun, dan Allah tidak akan memasukkannya ke dalam Surga-Nya. Dan laki-laki mana saja yang mengingkari anaknya padahal ia melihatnya, maka Allah Azza wa Jalla akan menutup diri darinya, dan Allah akan membuka aibnya di hadapan manusia pertama hingga terakhir pada Hari Kiamat.\""},"3336":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Sa'id] dan [Abu Salamah] dari [Abu Hurairah], bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Anak itu untuk pemilik ranjang (suami), dan bagi pezina adalah batu (hukuman rajam).\""},"3337":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ عَنْ عَبْدِ الرَّزَّاقِ قَالَ حَدَّثَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ سَعِيدٍ وَأَبِي سَلَمَةَ عَنْ أَبِي هُرَيْرَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] dari [Abdurrazzaq] ia berkata; telah menceritakan kepada kami [Ma'mar] dari [Az Zuhri] dari [Sa'id] dan [Abu Salamah] dari [Abu Hurairah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Anak itu milik pemilik ranjang, dan bagi pezina adalah batu (hukuman rajam).\""},"3338":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْاخْتَصَمَ سَعْدُ بْنُ أَبِي وَقَّاصٍ وَعَبْدُ بْنُ زَمْعَةَ فِي غُلَامٍ فَقَالَ سَعْدٌ هَذَا يَا رَسُولَ اللَّهِ ابْنُ أَخِي عُتْبَةَ بْنِ أَبِي وَقَّاصٍ عَهِدَ إِلَيَّ أَنَّهُ ابْنُهُ انْظُرْ إِلَى شَبَهِهِ وَقَالَ عَبْدُ بْنُ زَمْعَةَ أَخِي وُلِدَ عَلَى فِرَاشِ أَبِي مِنْ وَلِيدَتِهِ فَنَظَرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى شَبَهِهِ فَرَأَى شَبَهًا بَيِّنًا بِعُتْبَةَ فَقَالَ هُوَ لَكَ يَا عَبْدُ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُ وَاحْتَجِبِي مِنْهُ يَا سَوْدَةُ بِنْتُ زَمْعَةَ فَلَمْ يَرَ سَوْدَةَ قَطُّ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] ia berkata, \"Sa'd bin Abu Waqqash dan Abd bin Zam'ah berselisih mengenai seorang anak. Sa'd berkata, \"Wahai Rasulullah, ini adalah anak saudara laki-lakiku, 'Utbah bin Abu Waqqash, ia bersumpah kepadaku bahwa anak ini adalah anaknya. Lihatlah kepada kemiripannya.\" Sedangkan Abd bin Zam'ah berkata, \"Ia saudaraku, ia terlahirkan di atas ranjang ayahku dari sahaya wanitanya.\" Kemudian Rasulullah shallallahu 'alaihi wasallam melihat kemiripannya. Maka beliau melihat kemiripan jelas dengan 'Utbah, maka beliau bersabda: \"Anak ini untukmu (wahai Sa'd). Wahai 'Abd, anak itu milik pemilik ranjang dan bagi pezina adalah hukuman rajam, dan berhijablah darinya (anak tersebut) wahai Saudah binti Zam'ah.\" Dan beliau tidak menghitung Saudah sebagai mahram sama sekali.\""},"3339":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ مُجَاهِدٍ عَنْ يُوسُفَ بْنِ الزُّبَيْرِ مَوْلًى لَهُمْ عَنْ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ قَالَكَانَتْ لِزَمْعَةَ جَارِيَةٌ يَطَؤُهَا هُوَ وَكَانَ يَظُنُّ بِآخَرَ يَقَعُ عَلَيْهَا فَجَاءَتْ بِوَلَدٍ شِبْهِ الَّذِي كَانَ يَظُنُّ بِهِ فَمَاتَ زَمْعَةُ وَهِيَ حُبْلَى فَذَكَرَتْ ذَلِكَ سَوْدَةُ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَدُ لِلْفِرَاشِ وَاحْتَجِبِي مِنْهُ يَا سَوْدَةُ فَلَيْسَ لَكِ بِأَخٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Jarir] dari [Manshur] dari [Mujahid] dari [Yusuf bin Az Zubair] mantan budak mereka, dari [Abdullah bin Az Zubair] ia berkata, \"Zam'ah memiliki seorang sahaya wanita yang ia gauli, dan ia punya kecurigaan bahwa ada pihak lain yang menggaulinya. Kemudian sahaya tersebut melahirkan anak yang mirip dengan orang orang yang ia yakini tersebut. Kemudian Zam'ah meninggal dan sahaya tersebut dalam keadaan hamil. Kemudian Saudah menyebutkan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anak itu milik pemilik ranjang, dan berhijablah darinya wahai Saudah. Ia bukanlah saudaramu.\""},"3340":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مُغِيرَةَ عَنْ أَبِي وَائِلٍ عَنْ عَبْدِ اللَّهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْوَلَدُ لِلْفِرَاشِ وَلِلْعَاهِرِ الْحَجَرُقَالَ أَبُو عَبْد الرَّحْمَنِ وَلَا أَحْسَبُ هَذَا عَنْ عَبْدِ اللَّهِ بْنِ مَسْعُودٍ وَاللَّهُ تَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Jarir] dari [Mughirah] dari [Abu Wail] dari [Abdullah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Anak itu milik pemilik ranjang, dan bagi pezina hukumannya adalah batu (hukum rajam).\" Abu Abdurrahman berkata, \"Aku tidak yakin ini berasal dari Abdullah bin Mas'ud, Allah ta'ala lebih mengetahui.\""},"3341":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْاخْتَصَمَ سَعْدُ بْنُ أَبِي وَقَّاصٍ وَعَبْدُ بْنُ زَمْعَةَ فِي ابْنِ زَمْعَةَ قَالَ سَعْدٌ أَوْصَانِي أَخِي عُتْبَةُ إِذَا قَدِمْتَ مَكَّةَ فَانْظُرْ ابْنَ وَلِيدَةِ زَمْعَةَ فَهُوَ ابْنِي فَقَالَ عَبْدُ بْنُ زَمْعَةَ هُوَ ابْنُ أَمَةِ أَبِي وُلِدَ عَلَى فِرَاشِ أَبِي فَرَأَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ شَبَهًا بَيِّنًا بِعُتْبَةَ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْوَلَدُ لِلْفِرَاشِ وَاحْتَجِبِي مِنْهُ يَا سَوْدَةُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] ia berkata, \"Sa'd bin Abu Waqqash dan Abd bin Zam'ah berselisih mengenai akan Zam'ah. Sa'd berkata, \"Saudaraku 'Utbah telah berwasiat kepadaku 'Apabila engkau datang ke Makkah maka lihatlah anak laki-laki sahaya Zam'ah, ia adalah anakku'.\" Kemudian Abd bin Zam'ah berkata, \"Ia adalah anak sahaya ayahku, ia terlahir di atas ranjang ayahku.\" Kemudian Rasulullah shallallahu 'alaihi wasallam melihat kemiripan yang jelas dengan 'Utbah. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Anak itu milik pemilik ranjang, dan berhijablah engkau darinya wahai Saudah.\""},"3342":{"ar":"أَخْبَرَنَا أَبُو عَاصِمٍ خُشَيْشُ بْنُ أَصْرَمَ قَالَ أَنْبَأَنَا عَبْدُ الرَّزَّاقِ قَالَ أَنْبَأَنَا الثَّوْرِيُّ عَنْ صَالِحٍ الْهَمْدَانِيِّ عَنْ الشَّعْبِيِّ عَنْ عَبْدِ خَيْرٍ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَأُتِيَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ بِثَلَاثَةٍ وَهُوَ بِالْيَمَنِ وَقَعُوا عَلَى امْرَأَةٍ فِي طُهْرٍ وَاحِدٍ فَسَأَلَ اثْنَيْنِ أَتُقِرَّانِ لِهَذَا بِالْوَلَدِ قَالَا لَا ثُمَّ سَأَلَ اثْنَيْنِ أَتُقِرَّانِ لِهَذَا بِالْوَلَدِ قَالَا لَا فَأَقْرَعَ بَيْنَهُمْ فَأَلْحَقَ الْوَلَدَ بِالَّذِي صَارَتْ عَلَيْهِ الْقُرْعَةُ وَجَعَلَ عَلَيْهِ ثُلُثَيْ الدِّيَةِ فَذُكِرَ ذَلِكَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَضَحِكَ حَتَّى بَدَتْ نَوَاجِذُهُأَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا عَلِيُّ بْنُ مُسْهِرٍ عَنْ الْأَجْلَحِ عَنْ الشَّعْبِيِّ قَالَ أَخْبَرَنِي عَبْدُ اللَّهِ بْنُ أَبِي الْخَلِيلِ الْحَضْرَمِيُّ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَ بَيْنَا نَحْنُ عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِذْ جَاءَهُ رَجُلٌ مِنْ الْيَمَنِ فَجَعَلَ يُخْبِرُهُ وَيُحَدِّثُهُ وَعَلِيٌّ بِهَا فَقَالَ يَا رَسُولَ اللَّهِ أَتَى عَلِيًّا ثَلَاثَةُ نَفَرٍ يَخْتَصِمُونَ فِي وَلَدٍ وَقَعُوا عَلَى امْرَأَةٍ فِي طُهْرٍ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Abu 'Ashim Khusyaisy bin Ashram] ia berkata; telah memberitakan kepada kami [Abdurrazzaq] ia berkata; telah memberitakan kepada kami [Ats Tsauri] dari [Shalih Al Hamdani] dari [Asy Sya'bi] dari [Abd Khair] dari [Zaid bin Arqam] ia berkata, \"Dihadapkan tiga orang kepada Ali saat ia berada di Yaman, mereka telah menggauli seorang wanita dalam satu masa suci. Lalu Ali bertanya kepada kedua orang, \"Apakah engkau mengakuinya sebagai anak orang ini? Mereka menjawab, \"Tidak.\" Kemudian bertanya kepada dua orang, \"Apakah engkau mengakuinya sebagai anak orang ini? Mereka menjawab, \"Tidak.\" Maka Ali pun mengundi mereka dan menisbatkan anak kepada orang yang mendapatkan undian dan mengharuskan kepadanya membayar dua pertiga diyat. Lalu hal itu disampaikan kepada Nabi shallallahu 'alaihi wasallam dan beliau tertawa hingga tampak gigi gerahamnya.\" [Ali bin Hujr] berkata, \"Telah menceritakan kepada kami [Ali bin Mushir] dari [Al 'Ajlah] dari [Asy Sya'bi] ia berkata; telah mengabarkan kepadaku [Abdullah bin Abu Khalil Al Hadrami] dari [Zaid bin Arqam] ia berkata, \"Ketika kami bersama Rasulullah shallallahu 'alaihi wasallam, tiba-tiba datanglah seorang laki-laki dari Yaman kepada beliau dan mengabarkan dan menceritakan hal tersebut sementara Ali di Yaman, ia berkata, \"Wahai Rasulullah, ada tiga orang datang kepada Ali mengadukan mengenai seorang anak, hasil hubungan mereka dari seorang wanita yang mereka gauli saat suci… Zaid bin Arqam lalu menyebutkan hadits itu.\""},"3343":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى عَنْ الْأَجْلَحِ عَنْ الشَّعْبِيِّ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي الْخَلِيلِ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَكُنْتُ عِنْدَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَلِيٌّ رَضِيَ اللَّهُ عَنْهُ يَوْمَئِذٍ بِالْيَمَنِ فَأَتَاهُ رَجُلٌ فَقَالَ شَهِدْتُ عَلِيًّا أُتِيَ فِي ثَلَاثَةِ نَفَرٍ ادَّعَوْا وَلَدَ امْرَأَةٍ فَقَالَ عَلِيٌّ لِأَحَدِهِمْ تَدَعُهُ لِهَذَا فَأَبَى وَقَالَ لِهَذَا تَدَعُهُ لِهَذَا فَأَبَى وَقَالَ لِهَذَا تَدَعُهُ لِهَذَا فَأَبَى قَالَ عَلِيٌّ رَضِيَ اللَّهُ عَنْهُ أَنْتُمْ شُرَكَاءُ مُتَشَاكِسُونَ وَسَأَقْرَعُ بَيْنَكُمْ فَأَيُّكُمْ أَصَابَتْهُ الْقُرْعَةُ فَهُوَ لَهُ وَعَلَيْهِ ثُلُثَا الدِّيَةِ فَضَحِكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حَتَّى بَدَتْ نَوَاجِذُهُأَخْبَرَنَا إِسْحَقُ بْنُ شَاهِينٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ الشَّيْبَانِيِّ عَنْ الشَّعْبِيِّ عَنْ رَجُلٍ مِنْ حَضْرَمَوْتَ عَنْ زَيْدِ بْنِ أَرْقَمَ قَالَ بَعَثَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيًّا عَلَى الْيَمَنِ فَأُتِيَ بِغُلَامٍ تَنَازَعَ فِيهِ ثَلَاثَةٌ وَسَاقَ الْحَدِيثَ خَالَفَهُمْ سَلَمَةُ بْنُ كُهَيْلٍ أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ قَالَ سَمِعْتُ الشَّعْبِيَّ يُحَدِّثُ عَنْ أَبِي الْخَلِيلِ أَوْ ابْنِ أَبِي الْخَلِيلِ أَنَّ ثَلَاثَةَ نَفَرٍ اشْتَرَكُوا فِي طُهْرٍ فَذَكَرَ نَحْوَهُ وَلَمْ يَذْكُرْ زَيْدَ بْنَ أَرْقَمَ وَلَمْ يَرْفَعْهُ قَالَ أَبُو عَبْد الرَّحْمَنِ هَذَا صَوَابٌ وَاللَّهُ سُبْحَانَهُ وَتَعَالَى أَعْلَمُ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] ia berkata; telah menceritakan kepada kami [Yahya] dari [Al Ajlah] dari [Asy Sya'bi] dari [Abdullah bin Abu Al Khalil] dari [Zaid bin Arqam] ia berkata, \"Aku pernah bersama Nabi shallallahu 'alaihi wasallam sedangkan Ali radliallahu 'anhu pada saat itu berada di Yaman. Kemudian datang kepadanya seorang laki-laki dan berkata, \"Aku melihat Ali dihadapkan kepadanya tiga orang yang mengklaim anak seorang wanita. Kemudian Ali berkata kepada salah seorang dari mereka, 'Apakah engkau membiarkan anak tersebut untuk orang ini? ', orang tersebut menolak. Lalu ia berkata kepada yang ini 'Apakah engkau biarkan anak tersebut untuk anak ini? ', ia menolak. Lalu Ali berkata kepada orang yang ini, 'Apakah engkau membiarkan anak tersebut untuk orang ini? ', orang tersebut menolak. Maka Ali radliallahu 'anhu kemudian berkata, \"Kalian adalah orang-orang dalam perseteruan ini. Maka aku akan mengundi di antara kalian, siapa yang mendapatkan undian maka anak tersebut miliknya, dan ia berkewajiban membayar dua pertiga diyah.\" Kemudian Rasulullah shallallahu 'alaihi wasallam tertawa hingga nampak gigi gerahamnya.\" Telah menceritakan kepada kami [Ishaq bin Syahin] berkata; telah mengabarkan kepada kami [Khalid] dari [Asy Syaibani] dari [Asy Sya'bi] dari [seorang laki-laki] dari Hadlramaut, dari [Zaid bin Arqam] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengutus Ali untuk memimpin Yaman, kemudian dihadapkan kepadanya seorang anak yang diperselisihkan oleh tiga orang… lalu ia sebutkan hadits tersebut, namun Salamah bin Kuhail menyelisihinya.\" Telah mengabarkan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Muhammad] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Salamah bin Kuhail] ia berkata; aku mendengar [Asy Sya'bi] menceritakan dari [Abu Al Khalil] atau Ibnu Abu Al Khalil, bahwa ada tiga orang yang berserikat dalam menggauli (wanita) pada masa suci…lalu ia menyebutkan yang semisal. Namun ia tidak menyebutkan nama Zaid bin Arqam, dan tidak memarfu'kannya. Abu Abdurrahman berkata, \"Ini adalah benar. Waallahu A'lam.\""},"3344":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ عَنْ عَائِشَةَ قَالَتْإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دَخَلَ عَلَيَّ مَسْرُورًا تَبْرُقُ أَسَارِيرُ وَجْهِهِ فَقَالَ أَلَمْ تَرَيْ أَنَّ مُجَزِّزًا نَظَرَ إِلَى زَيْدِ بْنِ حَارِثَةَ وَأُسَامَةَ فَقَالَ إِنَّ بَعْضَ هَذِهِ الْأَقْدَامِ لَمِنْ بَعْضٍ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Ibnu Syihab] dari ['Urwah] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemuiku dalam keadaan senang dan guratan-guratan dahinya bersinar. Kemudian beliau bersabda: \"Tidakkah engkau melihat bahwa Mujazziz melihat kepada Zaid bin Haritsah dan Usamah? Kemudian ia berkata; sesungguhnya sebagian telapak-telapak ini mengikuti sebagian yang lain.\""},"3345":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَ رَضِيَ اللَّهُ عَنْهَا قَالَتْدَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ ذَاتَ يَوْمٍ مَسْرُورًا فَقَالَ يَا عَائِشَةُ أَلَمْ تَرَيْ أَنَّ مُجَزِّزًا الْمُدْلِجِيَّ دَخَلَ عَلَيَّ وَعِنْدِي أُسَامَةُ بْنُ زَيْدٍ فَرَأَى أُسَامَةَ بْنَ زَيْدٍ وَزَيْدًا وَعَلَيْهِمَا قَطِيفَةٌ وَقَدْ غَطَّيَا رُءُوسَهُمَا وَبَدَتْ أَقْدَامُهُمَا فَقَالَ هَذِهِ أَقْدَامٌ بَعْضُهَا مِنْ بَعْضٍ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah] dari [Aisyah] radliallahu 'anha, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam menemuiku pada suatu hari dalam keadaan senang, kemudian bersabda: \"Wahai Aisyah, tidakkah engkau melihat bahwa Mujazziz Al Mudliji menemuiku saat Usamah bin Zaid bersamaku, kemudian ia melihat Usamah bin Zaid dan Zaid, keduanya memakai pakaian beludru dan menutupi kepala mereka serta nampak telapak kaki mereka. Kemudian Mujazziz berkata, 'sesungguhnya telapak-telapak kaki ini sebagiannya berasal dari sebagian yang lain'.\""},"3346":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا عَبْدُ الرَّزَّاقِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عُثْمَانَ الْبَتِّيِّ عَنْ عَبْدِ الْحَمِيدِ بْنِ سَلَمَةَ الْأَنْصَارِيِّ عَنْ أَبِيهِ عَنْ جَدِّهِأَنَّهُ أَسْلَمَ وَأَبَتْ امْرَأَتُهُ أَنْ تُسْلِمَ فَجَاءَ ابْنٌ لَهُمَا صَغِيرٌ لَمْ يَبْلُغْ الْحُلُمَ فَأَجْلَسَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْأَبَ هَا هُنَا وَالْأُمَّ هَا هُنَا ثُمَّ خَيَّرَهُ فَقَالَ اللَّهُمَّ اهْدِهِ فَذَهَبَ إِلَى أَبِيهِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] ia berkata; telah menceritakan kepada kami [Abdurrazzaq] ia berkata; telah menceritakan kepada kami [Sufyan] dari [Utsman Al Batti] dari [Abdul Hamid bin Salamah Al Anshari] dari [ayahnya] dari [kakeknya], bahwa ia masuk Islam namun isterinya menolak untuk masuk Islam. Kemudian anak kecil mereka berdua yang belum baligh datang, kemudian Nabi shallallahu 'alaihi wasallam mendudukkan ayah di sini dan ibu di sini, kemudian menyuruh anak tersebut untuk memilih. Kemudian beliau mengucapkan: \"Ya Allah, berilah ia petunjuk menuju ayahnya.\""},"3347":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي زِيَادٌ عَنْ هِلَالِ بْنِ أُسَامَةَ عَنْ أَبِي مَيْمُونَةَ قَالَبَيْنَا أَنَا عِنْدَ أَبِي هُرَيْرَةَ فَقَالَ إِنَّ امْرَأَةً جَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ فِدَاكَ أَبِي وَأُمِّي إِنَّ زَوْجِي يُرِيدُ أَنْ يَذْهَبَ بِابْنِي وَقَدْ نَفَعَنِي وَسَقَانِي مِنْ بِئْرِ أَبِي عِنَبَةَ فَجَاءَ زَوْجُهَا وَقَالَ مَنْ يُخَاصِمُنِي فِي ابْنِي فَقَالَ يَا غُلَامُ هَذَا أَبُوكَ وَهَذِهِ أُمُّكَ فَخُذْ بِيَدِ أَيِّهِمَا شِئْتَ فَأَخَذَ بِيَدِ أُمِّهِ فَانْطَلَقَتْ بِهِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Ibnu Juraij] ia berkata; telah mengabarkan kepadaku [Ziyad] dari [Hilal bin Usamah] dari [Abu Maimunah] ia berkata, \"Saat aku bersama [Abu Hurairah], ia berkata, \"Seorang wanita datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Ayah dan ibuku sebagai tebusanmu. Sesungguhnya suamiku ingin pergi membawa anakku, dan anak tersebut telah memberiku manfaat, ia membawakan aku air dari sumur Abu 'Anabah.\" Kemudian suaminya datang dan berkata, \"Siapakah yang berselisih denganku mengenai anakku?\" Kemudian beliau bersabda: \"Wahai anak kecil, ini adalah ayahmu dan ini adalah ibumu. Gandenglah tangan salah seorang dari mereka yang engkau kehendaki.\" Kemudian anak tersebut menggandeng tangan ibunya, maka ia pun pergi bersamanya.\""},"3348":{"ar":"أَخْبَرَنَا أَبُو عَلِيٍّ مُحَمَّدُ بْنُ يَحْيَى الْمَرْوَزِيُّ قَالَ أَخْبَرَنِي شَاذَانُ بْنُ عُثْمَانَ أَخُو عَبْدَانَ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْمُبَارَكِ عَنْ يَحْيَى بْنِ أَبِي كَثِيرٍ قَالَ أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ الرُّبَيِّعَ بِنْتَ مُعَوِّذِ بْنِ عَفْرَاءَ أَخْبَرَتْهُأَنَّ ثَابِتَ بْنَ قَيْسِ بْنِ شَمَّاسٍ ضَرَبَ امْرَأَتَهُ فَكَسَرَ يَدَهَا وَهِيَ جَمِيلَةُ بِنْتُ عَبْدِ اللَّهِ بْنِ أُبَيٍّ فَأَتَى أَخُوهَا يَشْتَكِيهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَرْسَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَى ثَابِتٍ فَقَالَ لَهُ خُذْ الَّذِي لَهَا عَلَيْكَ وَخَلِّ سَبِيلَهَا قَالَ نَعَمْ فَأَمَرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَتَرَبَّصَ حَيْضَةً وَاحِدَةً فَتَلْحَقَ بِأَهْلِهَا","id":"Telah mengabarkan kepada kami [Abu Ali Muhammad bin Yahya Al Marwazi] ia berkata; telah mengabarkan kepadaku [Syadzan bin Utsman] saudara Abdan, ia berkata; telah menceritakan kepada kami [Bapakku] berkata; telah menceritakan kepada kami [Ali bin Al Mubarak] dari [Yahya bin Abu Katsir] ia berkata; telah mengabarkan kepadaku [Muhammad bin Abdurrahman] bahwa [Ar Rubayyi' binti Mu'awwidz bin 'Afra] telah mengabarkan kepadanya, bahwa Tsabit bin Qais bin Syammas memukul isterinya hingga mematahkan tangannya, yaitu Jamilah binti Abdullah bin Ubay. Saudaranya (Jamilah) lalu datang mengadukan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam, lalu Rasulullah shallallahu 'alaihi wasallam mengutus seseorang kepada Tsabit dan berkata kepadanya: \"Ambillah apa yang menjadi haknya atas dirimu dan lepaskan dia!\" Tsabit lalu berkata, Ya.\" Rasulullah shallallahu 'alaihi wasallam lantas menyuruh Jamilah untuk menunggu (Idaah) dalam durasi satu kali haid sebelum kembali kepada keluarganya.\""},"3349":{"ar":"أَخْبَرَنَا عُبَيْدُ اللَّهِ بْنُ سَعْدِ بْنِ إِبْرَاهِيمَ بْنِ سَعْدٍ قَالَ حَدَّثَنَا عَمِّي قَالَ حَدَّثَنَا أَبِي عَنْ ابْنِ إِسْحَقَ قَالَ حَدَّثَنِي عُبَادَةُ بْنُ الْوَلِيدِ بْنِ عُبَادَةَ بْنِ الصَّامِتِ عَنْ رُبَيِّعَ بِنْتِ مُعَوِّذٍ قَالَقُلْتُ لَهَا حَدِّثِينِي حَدِيثَكِ قَالَتْ اخْتَلَعْتُ مِنْ زَوْجِي ثُمَّ جِئْتُ عُثْمَانَ فَسَأَلْتُهُ مَاذَا عَلَيَّ مِنْ الْعِدَّةِ فَقَالَ لَا عِدَّةَ عَلَيْكِ إِلَّا أَنْ تَكُونِي حَدِيثَةَ عَهْدٍ بِهِ فَتَمْكُثِي حَتَّى تَحِيضِي حَيْضَةً قَالَ وَأَنَا مُتَّبِعٌ فِي ذَلِكَ قَضَاءَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرْيَمَ الْمَغَالِيَّةِ كَانَتْ تَحْتَ ثَابِتِ بْنِ قَيْسِ بْنِ شَمَّاسٍ فَاخْتَلَعَتْ مِنْهُ","id":"Telah mengabarkan kepada kami [Ubaidullah bin Sa'd bin Ibrahim bin Sa'd] ia berkata; telah menceritakan kepada kami [pamanku] ia berkata; telah menceritakan kepada kami [ayahku] dari [Ibnu Ishaq] ia berkata; telah menceritakan kepadaku [Ubadah bin Al Walid bin 'Ubadah bin Ash Shamid] dari [Rubayyi' binti Mu'awwidz] ia berkata, \"Aku berkata kepadanya, \"Ceritakanlah hadits yang kamu riwayatkan kepadaku.\" Rubayyi' berkata, \"Aku minta cerai kepada suamiku, lalu aku mendatangi Utsman dan aku tanyakan kepadanya 'apakah aku harus menunggu masa iddah? ia lalu menjawab, 'Tidak ada iddah atasmu, kecuali jika engkau baru menikah dengannya maka engkau tinggallah hingga engkau mengalami haid sekali'.\" Ubadah bin Ash Shamid berkata, \"Aku mengikuti apa yang diputuskan Rasulullah shallallahu 'alaihi wasallam kepada Maryam Al Mughaliyyah, dahulu ia berada dalam naungan Tsabit bin Qais bin Syammas, lalu ia minta cerai kepadanya.\""},"3350":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ أَنْبَأَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ }وَقَالَ{ وَاللَّائِي يَئِسْنَ مِنْ الْمَحِيضِ مِنْ نِسَائِكُمْ إِنْ ارْتَبْتُمْ فَعِدَّتُهُنَّ ثَلَاثَةُ أَشْهُرٍ }فَنُسِخَ مِنْ ذَلِكَ قَالَ تَعَالَى وَإِنْ{ طَلَّقْتُمُوهُنَّ مِنْ قَبْلِ أَنْ تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍ تَعْتَدُّونَهَا }","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] ia berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Ali bin Al Husain bin Waqid] ia berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah memberitakan kepada kami [Yazid bin An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai ayat: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 101), dan firman Allah '(menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh (hapus) dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru') ', (Qs. Al Baqarah: 228). Dan firman: '(Dan perempuan-perempuan yang tidak haid lagi (monopause) di antara perempuan-perempuanmu jika kamu ragu-ragu (tentang masa iddahnya), Maka masa iddah mereka adalah tiga bulan) ' (Qs. Ath Thallaaq: 40), lalu dinasakh dari hal tersebut, firman Allah Ta'ala: '(Kemudian kamu ceraikan mereka sebelum kamu mencampurinya Maka sekali-sekali tidak wajib atas mereka 'iddah bagimu yang kamu minta menyempurnakannya) ' (Qs. Al Ahzaab: 49)."},"3351":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ وَكِيعٍ عَنْ شُعْبَةَ قَالَ حَدَّثَنِي حُمَيْدُ بْنُ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ قَالَتْ أُمُّ حَبِيبَةَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ تَحِدُّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثَةِ أَيَّامٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Waki'] dari [Syu'bah] ia berkata; telah menceritakan kepadaku [Humaid bin Nafi'] dari [Zainab binti Ummu Salamah], [Ummu Habibah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan Hari Akhir berkabung atas mayit lebih dari tiga hari kecuali atas meninggalnya suami, yaitu empat bulan sepuluh hari.\""},"3352":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ حُمَيْدِ بْنِ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ قُلْتُ عَنْ أُمِّهَاقَالَ نَعَمْ إِنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سُئِلَ عَنْ امْرَأَةٍ تُوُفِّيَ عَنْهَا زَوْجُهَا فَخَافُوا عَلَى عَيْنِهَا أَتَكْتَحِلُ فَقَالَ قَدْ كَانَتْ إِحْدَاكُنَّ تَمْكُثُ فِي بَيْتِهَا فِي شَرِّ أَحْلَاسِهَا حَوْلًا ثُمَّ خَرَجَتْ فَلَا أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] ia berkata; telah menceritakan kepada kami [Khalid] ia berkata; telah menceritakan kepada kami [Syu'bah] dari [Humaid bin Nafi'] dari [Zainab binti Ummu Salamah] aku berkata dari [ibunya]? Ia berkata, \"Ya. Sesungguhnya Nabi shallallahu 'alaihi wasallam telah ditanya mengenai seorang wanita yang ditinggal mati suaminya, kemudian mereka khawatir atas matanya apakah ia boleh memakai celak? Kemudian beliau bersabda: \"Sungguh salah seorang di antara kalian tinggal di rumahnya dalam pakai tipis yang paling buruk selama atau tahun kemudian keluar. Maka tidak, hingga berlalu empat bulan sepuluh hari.\""},"3353":{"ar":"أَخْبَرَنِي إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ يَحْيَى بْنِ سَعِيدِ بْنِ قَيْسِ بْنِ قَهْدٍ الْأَنْصَارِيِّ وَجَدُّهُ قَدْ أَدْرَكَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ حُمَيْدِ بْنِ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أُمِّ سَلَمَةَ عَنْ أُمِّ سَلَمَةَ وَأُمِّ حَبِيبَةَ قَالَتَاجَاءَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ ابْنَتِي تُوُفِّيَ عَنْهَا زَوْجُهَا وَإِنِّي أَخَافُ عَلَى عَيْنِهَا أَفَأَكْحُلُهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ كَانَتْ إِحْدَاكُنَّ تَجْلِسُ حَوْلًا وَإِنَّمَا هِيَ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا فَإِذَا كَانَ الْحَوْلُ خَرَجَتْ وَرَمَتْ وَرَاءَهَا بِبَعْرَةٍ","id":"Telah mengabarkan kepada kami [Ishaq] ia berkata; telah memberitakan kepada kami [Jarir] dari [Yahya bin Sa'id bin Qais bin Qahd Al Anshari] -dan kakeknya pernah bertemu dengan Nabi shallallahu 'alaihi wasallam- dari [Humaid bin Nafi'] dari [Zainab binti Ummu Salamah] dari [Ummu Salamah] dan [Ummu Habibah] mereka berdua berkata, \"Seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya anak wanitaku telah ditinggal mati suaminya dan aku mengkhawatirkan matanya, apakah boleh aku memberinya celak? Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, salah seorang di antara kalian telah duduk satu tahun, padahal berkabung itu hanyalah empat bulan sepuluh hari, kemudian apabila telah satu tahun ia keluar dan melempar kotoran binatang di belakangnya.\""},"3354":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا عَبْدُ الْوَهَّابِ قَالَ سَمِعْتُ يَحْيَى بْنَ سَعِيدٍ يَقُولُ سَمِعْتُ نَافِعًا يَقُولُ عَنْ صَفِيَّةَ بِنْتِ أَبِي عُبَيْدٍ أَنَّهَا سَمِعَتْ حَفْصَةَ بِنْتَ عُمَرَ زَوْجَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ تَحِدُّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ فَإِنَّهَا تَحِدُّ عَلَيْهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] ia berkata; telah menceritakan kepada kami [Abdul Wahhab] ia berkata; aku mendengar [Yahya bin Sa'id] berkata; aku mendengar [Nafi'] berkata dari [Shafiyah binti Abu 'Ubaid] bahwa ia telah mendengar [Hafshah binti Umar] isteri Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan Hari Akhir untuk berkabung terhadap mayit di atas tiga hari kecuali terhadap suaminya, maka ia berkabung terhadapnya selama empat bulan sepuluh hari.\""},"3355":{"ar":"أَخْبَرَنَا عَبْدُ اللَّهِ بْنُ الصَّبَّاحِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَوَاءٍ قَالَ أَنْبَأَنَا سَعِيدٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ صَفِيَّةَ بِنْتِ أَبِي عُبَيْدٍ عَنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَعَنْ أُمِّ سَلَمَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ تَحِدُّ عَلَى مَيِّتٍ أَكْثَرَ مِنْ ثَلَاثَةِ أَيَّامٍ إِلَّا عَلَى زَوْجٍ فَإِنَّهَا تَحِدُّ عَلَيْهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًاأَخْبَرَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا السَّهْمِيُّ يَعْنِي عَبْدَ اللَّهِ بْنَ بَكْرٍ قَالَ حَدَّثَنَا سَعِيدٌ عَنْ أَيُّوبَ عَنْ نَافِعٍ عَنْ صَفِيَّةَ بِنْتِ أَبِي عُبَيْدٍ عَنْ بَعْضِ أَزْوَاجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ أُمُّ سَلَمَةَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Abdullah bin Ash Shabbah] ia berkata; telah menceritakan kepada kami [Muhammad bin Sawa`] ia berkata; telah memberitakan kepada kami [Sa'id] dari [Ayyub] dari [Nafi'] dari [Shafiyah binti Abu 'Ubaid] dari sebagian isteri Nabi shallallahu 'alaihi wasallam, dan dari [Ummu Salamah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak boleh bagi seorang wanita yang beriman kepada Allah dan Hari Akhir untuk berkabung terhadap mayit melebihi tiga hari kecuali terhadap suaminya, maka ia berkabung selama empat bulan sepuluh hari.\" Telah mengabarkan kepadaku [Muhammad bin Isma'il bin Ibrahim] ia berkata; telah menceritakan kepada kami [As Sahmi] -yaitu Abdullah bin Bakr- ia berkata; telah menceritakan kepada kami [Sa'id] dari [Ayyub] dari [Nafi'] dari [Shafiyah binti Abu 'Ubaid] dari sebagian isteri Nabi shallallahu 'alaihi wasallam yaitu [Ummu Salamah] dari Nabi shallallahu 'alaihi wasallam seperti itu.\""},"3356":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لِمُحَمَّدٍ قَالَا أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَأَنَّ سُبَيْعَةَ الْأَسْلَمِيَّةَ نُفِسَتْ بَعْدَ وَفَاةِ زَوْجِهَا بِلَيَالٍ فَجَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْذَنَتْ أَنْ تَنْكِحَ فَأَذِنَ لَهَا فَنَكَحَتْ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan aku mendengar, lafazhnya adalah lafazh Muhammad, mereka berdua mengatakan; telah memberitakan kepada kami [Ibnu Al Qasim] dari [Malik] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Al Miswar bin Makhramah], bahwa Subai'ah mengalami nifas setelah kematian suaminya selama beberapa malam, kemudian datang kepada Rasulullah shallallahu 'alaihi wasallam dan meminta izin untuk menikah, lalu beliau mengizinkannya sehingga iapun menikah.\""},"3357":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ قُدَامَةَ قَالَ أَخْبَرَنِي جَرِيرٌ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ أَبِي السَّنَابِلِ قَالَوَضَعَتْ سُبَيْعَةُ حَمْلَهَا بَعْدَ وَفَاةِ زَوْجِهَا بِثَلَاثَةٍ وَعِشْرِينَ أَوْ خَمْسَةٍ وَعِشْرِينَ لَيْلَةً فَلَمَّا تَعَلَّتْ تَشَوَّفَتْ لِلْأَزْوَاجِ فَعِيبَ ذَلِكَ عَلَيْهَا فَذُكِرَ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مَا يَمْنَعُهَا قَدْ انْقَضَى أَجَلُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Qudamah] ia berkata; telah mengabarkan kepadaku [Jarir] dari [Manshur] dari [Ibrahim] dari [Al Aswad] dari [Abu As Sanabil] ia berkata, \"Subai'ah telah melahirkan kandungannya dua puluh tiga atau dua puluh malam setelah kematian suaminya. Kemudian setelah suci ia berhias untuk menikah, maka ia mendapat celaan karena hal itu. Kemudian hal tersebut diceritakan kepada Rasulullah shallallahu 'alaihi wasallam, beliau lantas bersabda: \"Apa yang menghalanginya? Sungguh telah selesai waktunya.\""},"3358":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا أَبُو دَاوُدَ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ أَخْبَرَنِي عَبْدُ رَبِّهِ بْنُ سَعِيدٍ قَالَ سَمِعْتُ أَبَا سَلَمَةَ يَقُولُ اخْتَلَفَ أَبُو هُرَيْرَةَ وَابْنُ عَبَّاسٍ فِي الْمُتَوَفَّى عَنْهَا زَوْجُهَا إِذَا وَضَعَتْ حَمْلَهَا قَالَ أَبُو هُرَيْرَةَ تُزَوَّجُ وَقَالَ ابْنُ عَبَّاسٍ أَبْعَدَ الْأَجَلَيْنِ فَبَعَثُوا إِلَى أُمِّ سَلَمَةَ فَقَالَتْتُوُفِّيَ زَوْجُ سُبَيْعَةَ فَوَلَدَتْ بَعْدَ وَفَاةِ زَوْجِهَا بِخَمْسَةَ عَشَرَ نِصْفِ شَهْرٍ قَالَتْ فَخَطَبَهَا رَجُلَانِ فَحَطَّتْ بِنَفْسِهَا إِلَى أَحَدِهِمَا فَلَمَّا خَشُوا أَنْ تَفْتَاتَ بِنَفْسِهَا قَالُوا إِنَّكِ لَا تَحِلِّينَ قَالَتْ فَانْطَلَقْتُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ قَدْ حَلَلْتِ فَانْكِحِي مَنْ شِئْتِ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] ia berkata; telah menceritakan kepada kami [Abu Daud] ia berkata; telah menceritakan kepada kami [Syu'bah] ia berkata; telah mengabarkan kepadaku ['Abdu Rabbih bin Sa'id] ia berkata; aku mendengar [Abu Salamah] berkata, \"Abu Hurairah berselisih dengan Ibnu Abbas mengenai seorang wanita yang ditinggal mati suaminya apabila ia telah melahirkan. Abu Hurairah berpendapat, \"Ia boleh dinikahi.\" Sedangkan Ibnu Abbas berpendapat, \"Waktu yang paling lama.\" Kemudian mereka mengirim utusan kepada Ummu Salamah (untuk menanyakan hal tersebut), kemudian [Ummu Salamah] berkata, \"Suami Subai'ah meninggal, lalu lima belas hari kemudian ia melahirkan.\" Ummu Salamah melanjutkan, \"Kemudian ada dua orang laki-laki yang meminangnya, lalu ia menaruh perhatian kepada salah seorang dari kedua laki-laki tersebut. Maka ketika mereka khawatir Subai'ah menjatuhkan pilihannya, mereka pun berkata, \"Sesungguhnya engkau belum halal (untuk nikah).\" Ummu salamah berkata, \"Maka aku pergi menemui Rasulullah shallallahu 'alaihi wasallam untuk menanyakan hal tersebut, beliau lalu menjawab: \"Sungguh engkau telah halal, maka menikahlah dengan orang yang engkau kehendaki.\""},"3359":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا حَجَّاجٌ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي كَثِيرٍ قَالَ حَدَّثَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَ قِيلَ لِابْنِ عَبَّاسٍ فِي امْرَأَةٍ وَضَعَتْ بَعْدَ وَفَاةِ زَوْجِهَا بِعِشْرِينَ لَيْلَةً أَيَصْلُحُ لَهَا أَنْ تَزَوَّجَ قَالَ لَا إِلَّا آخِرَ الْأَجَلَيْنِ قَالَ قُلْتُ قَالَ اللَّهُ تَبَارَكَ وَتَعَالَى{ وَأُولَاتُ الْأَحْمَالِ أَجَلُهُنَّ أَنْ يَضَعْنَ حَمْلَهُنَّ }فَقَالَ إِنَّمَا ذَلِكَ فِي الطَّلَاقِفَقَالَ أَبُو هُرَيْرَةَ أَنَا مَعَ ابْنِ أَخِي يَعْنِي أَبَا سَلَمَةَ فَأَرْسَلَ غُلَامَهُ كُرَيْبًا فَقَالَ ائْتِ أُمَّ سَلَمَةَ فَسَلْهَا هَلْ كَانَ هَذَا سُنَّةٌ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ فَقَالَ قَالَتْ نَعَمْ سُبَيْعَةُ الْأَسْلَمِيَّةُ وَضَعَتْ بَعْدَ وَفَاةِ زَوْجِهَا بِعِشْرِينَ لَيْلَةً فَأَمَرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَزَوَّجَ فَكَانَ أَبُو السَّنَابِلِ فِيمَنْ يَخْطُبُهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Bazi'] ia berkata; telah menceritakan kepada kami [Yazid] -yaitu Ibnu Zurai'- ia berkata; telah menceritakan kepada kami [Hajjaj] ia berkata; telah menceritakan kepada kami [Yahya bin Abu Katsir] ia berkata; telah menceritakan kepadaku [Abu Salamah bin Abdurrahman] ia berkata, \"Dikatakan kepada Ibnu Abbas mengenai seorang wanita yang melahirkan dua puluh malam setelah suaminya meninggal, apakah layak dia untuk menikah lagi? Ia berkata, 'Tidak, kecuali pada akhir di antara dua waktu (iddah).\" Abu Salamah bin Abdurrahman berkata, \"Aku mengatakan, \"Allah tabaaraka wa Ta'ala berfirman: '(Dan perempuan-perempuan yang hamil, waktu iddah mereka itu ialah sampai mereka melahirkan kandungannya..) ' (Qs. Ath Thalaq: 4). Ibnu Abbas berkata, \"Sungguh, itu berkenaan dengan masalah talak.\" Kemudian Abu Hurairah berkata, \"Aku bersama anak saudaraku, yaitu Abu Salamah, kemudian ia mengirim sahayanya, [Kuraib], seraya berkata, \"Datanglah kepada Ummu Salamah dan tanyakan kepadanya apakah hal ini sunnah dari Rasulullah shallallahu 'alaihi wasallam? Kemudian ia datang dan berkata, \" [Ummu Salamah] berkata, \"Ya. Subai'ah Al Aslamiyah telah melahirkan dua puluh malam setelah suaminya meninggal, kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkannya untuk menikah. Dan Abu As Sanabil adalah termasuk orang yang melamarnya.\""},"3360":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَحْيَى عَنْ سُلَيْمَانَ بْنِ يَسَارٍ أَنَّ أَبَا هُرَيْرَةَ وَابْنَ عَبَّاسٍ وَأَبَا سَلَمَةَ بْنَ عَبْدِ الرَّحْمَنِ تَذَاكَرُوا عِدَّةَ الْمُتَوَفَّى عَنْهَا زَوْجُهَا تَضَعُ عِنْدَ وَفَاةِ زَوْجِهَا فَقَالَ ابْنُ عَبَّاسٍ تَعْتَدُّ آخِرَ الْأَجَلَيْنِ وَقَالَ أَبُو سَلَمَةَ بَلْ تَحِلُّ حِينَ تَضَعُ فَقَالَ أَبُو هُرَيْرَةَ أَنَا مَعَ ابْنِ أَخِيفَأَرْسَلُوا إِلَى أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ وَضَعَتْ سُبَيْعَةُ الْأَسْلَمِيَّةُ بَعْدَ وَفَاةِ زَوْجِهَا بِيَسِيرٍ فَاسْتَفْتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَمَرَهَا أَنْ تَتَزَوَّجَ","id":"Telah mengabarkan kepada kami [Qutaibah] ia berkata; telah menceritakan kepada kami [Al Laits] dari [Yahya] dari [Sulaiman bin Yasar], bahwa Abu Hurairah dari Ibnu Abbas dan Abu Salamah bin Abdurrahman saling menyebut-nyebut waktu 'iddah seorang wanita melahirkan setelah kematian suaminya. Ibnu Abbas berpendapat, \"Ia ber'iddah hingga akhir dua masa 'iddah.\" Dan Abu Salamah berkata, \"Ia sudah halal setelah melahirkan.\" Kemudian Abu Hurairah berkata, \"Aku bersama dengan anak saudaraku, kemudian mereka mengirim utusan kepada Ummu Salamah isteri Nabi shallallahu 'alaihi wasallam. [Ummu Salamah] lantas berkata, \"Subai'ah Al Aslamiyah telah melahirkan sesat setelah suaminya meninggal, kemudian ia meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam, lalu beliau memerintahkannya untuk menikah.\""},"3361":{"ar":"أَخْبَرَنَا عَبْدُ الْأَعْلَى بْنُ وَاصِلِ بْنِ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ عَنْ سُفْيَانَ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ كُرَيْبٍ عَنْ أُمِّ سَلَمَةَ وَمُحَمَّدُ بْنُ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ كُرَيْبٍ عَنْ أُمِّ سَلَمَةَ قَالَتْوَضَعَتْ سُبَيْعَةُ بَعْدَ وَفَاةِ زَوْجِهَا بِأَيَّامٍ فَأَمَرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَزَوَّجَ","id":"Telah mengabarkan kepada kami [Abdul A'la bin Washil bin Abdul A'la] berkata; telah menceritakan kepada kami [Yahya bin Adam] dari [Sufyan] dari [Yahya bin Sa'id] dari [Sulaiman bin Yasar] dari [Kuraib] dari [Ummu Salamah] dan [Muhammad bin 'Amru] dari [Abu Salamah] ia berkata, \"Subai'ah melahirkan beberapa hari setelah suaminya meninggal, kemudian Rasulullah shallallahu 'alaihi wasallam memerintahkannya agar menikah.\""},"3362":{"ar":"أَخْبَرَنَا حُسَيْنُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا جَعْفَرُ بْنُ عَوْنٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ أَخْبَرَنِي سُلَيْمَانُ بْنُ يَسَارٍ قَالَ أَخْبَرَنِي أَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ قَالَ كُنْتُ أَنَا وَابْنُ عَبَّاسٍ وَأَبُو هُرَيْرَةَ فَقَالَ ابْنُ عَبَّاسٍ إِذَا وَضَعَتْ الْمَرْأَةُ بَعْدَ وَفَاةِ زَوْجِهَا فَإِنَّ عِدَّتَهَا آخِرُ الْأَجَلَيْنِ فَقَالَ أَبُو سَلَمَةَ فَبَعَثْنَا كُرَيْبًا إِلَى أُمِّ سَلَمَةَيَسْأَلُهَا عَنْ ذَلِكَ فَجَاءَنَا مِنْ عِنْدِهَا أَنَّ سُبَيْعَةَ تُوُفِّيَ عَنْهَا زَوْجُهَا فَوَضَعَتْ بَعْدَ وَفَاةِ زَوْجِهَا بِأَيَّامٍ فَأَمَرَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنْ تَتَزَوَّجَ","id":"Telah mengabarkan kepada kami [Husain bin Manshur] berkata; telah menceritakan kepada kami [Ja'far bin 'Aud] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah mengabarkan kepadaku [Sulaiman bin Yasar] berkata; telah mengabarkan kepada kami [Abu Salamah bin Abdurrahman] berkata, \"Aku bersama Ibnu Abbas dan Abu Hurairah. Kemudian Ibnu Abbas berkata, \"Apabila seorang wanita melahirkan setelah suaminya meninggal, maka sesungguhnya 'iddahnya adalah akhir dari dua masa 'iddah.\" Kemudian Abu Salamah berkata, \"Kemudian kami mengirim [Kuraib] kepada [Ummu Salamah] untuk menanyakan hal tersebut, kemudian ia datang lagi kepada kami mengabarkan bahwa Subai'ah telah ditinggal mati suaminya dan melahirkan beberapa hari setelah suaminya meninggal. Rasulullah shallallahu 'alaihi wasallam kemudian memerintahkan kepadanya agar menikah lagi.\""},"3363":{"ar":"أَخْبَرَنَا عَبْدُ الْمَلِكِ بْنُ شُعَيْبِ بْنِ اللَّيْثِ بْنِ سَعْدٍ قَالَ حَدَّثَنِي أَبِي عَنْ جَدِّي قَالَ حَدَّثَنِي جَعْفَرُ بْنُ رَبِيعَةَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ هُرْمُزَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ أَنَّ زَيْنَبَ بِنْتَ أَبِي سَلَمَةَ أَخْبَرَتْهُ عَنْ أُمِّهَا أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَأَنَّ امْرَأَةً مِنْ أَسْلَمَ يُقَالُ لَهَا سُبَيْعَةُ كَانَتْ تَحْتَ زَوْجِهَا فَتُوُفِّيَ عَنْهَا وَهِيَ حُبْلَى فَخَطَبَهَا أَبُو السَّنَابِلِ بْنُ بَعْكَكٍ فَأَبَتْ أَنْ تَنْكِحَهُ فَقَالَ مَا يَصْلُحُ لَكِ أَنْ تَنْكِحِي حَتَّى تَعْتَدِّي آخِرَ الْأَجَلَيْنِ فَمَكَثَتْ قَرِيبًا مِنْ عِشْرِينَ لَيْلَةً ثُمَّ نُفِسَتْ فَجَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ انْكِحِي","id":"Telah mengabarkan kepada kami [Abdul Malik bin Syu'aib bin Al Laits bin Sa'd] berkata; telah menceritakan kepadaku [ayahku] dari [kakekku] berkata; telah menceritakan kepadaku [Ja'far bin Rabi'ah] dari [Abdurrahman bin Hurmuz] dari [Abu Salamah bin Abdurrahman] bahwa [Zainab binti Abu Salamah] mengabarkan kepadanya dari ibunya [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam, bahwa seorang wanita dari Bani Aslam yang dipanggil Subai'ah, isteri dari seorang laki-laki, telah ditinggal mati oleh suaminya saat ia hamil. Kemudian ia dilamar oleh Abu As Sanabil bin Ba'kak, namun ia menolak untuk menikah dengannya. Kemudian Abu As Sanabil berkata, 'Tidak layak bagimu untuk menikah sampai ber'iddah hingga akhir di antara dua masa 'iddah.' Maka Subai'ah pun berdiam diri (menutup diri dari lamaran orang) hingga dua puluh malam, setelah nifas ia menemui Rasulullah shallallahu 'alaihi wasallam, lalu beliau bersabda: \"Menikahlah.\""},"3364":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ حَدَّثَهُ أَنَّ أَبَاهُ كَتَبَ إِلَى عُمَرَ بْنِ عَبْدِ اللَّهِ بْنِ أَرْقَمَ الزُّهْرِيِّيَأْمُرُهُ أَنْ يَدْخُلَ عَلَى سُبَيْعَةَ بِنْتِ الْحَارِثِ الْأَسْلَمِيَّةِ فَيَسْأَلَهَا حَدِيثَهَا وَعَمَّا قَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ اسْتَفْتَتْهُ فَكَتَبَ عُمَرُ بْنُ عَبْدِ اللَّهِ إِلَى عَبْدِ اللَّهِ بْنِ عُتْبَةَ يُخْبِرُهُ أَنَّ سُبَيْعَةَ أَخْبَرَتْهُ أَنَّهَا كَانَتْ تَحْتَ سَعْدِ بْنِ خَوْلَةَ وَهُوَ مِنْ بَنِي عَامِرِ بْنِ لُؤَيٍّ وَكَانَ مِمَّنْ شَهِدَ بَدْرًا فَتُوُفِّيَ عَنْهَا زَوْجُهَا فِي حَجَّةِ الْوَدَاعِ وَهِيَ حَامِلٌ فَلَمْ تَنْشَبْ أَنْ وَضَعَتْ حَمْلَهَا بَعْدَ وَفَاتِهِ فَلَمَّا تَعَلَّتْ مِنْ نِفَاسِهَا تَجَمَّلَتْ لِلْخُطَّابِ فَدَخَلَ عَلَيْهَا أَبُو السَّنَابِلِ بْنُ بَعْكَكٍ رَجُلٌ مِنْ بَنِي عَبْدِ الدَّارِ فَقَالَ لَهَا مَا لِي أَرَاكِ مُتَجَمِّلَةً لَعَلَّكِ تُرِيدِينَ النِّكَاحَ إِنَّكِ وَاللَّهِ مَا أَنْتِ بِنَاكِحٍ حَتَّى تَمُرَّ عَلَيْكِ أَرْبَعَةُ أَشْهُرٍ وَعَشْرًا قَالَتْ سُبَيْعَةُ فَلَمَّا قَالَ لِي ذَلِكَ جَمَعْتُ عَلَيَّ ثِيَابِي حِينَ أَمْسَيْتُ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلْتُهُ عَنْ ذَلِكَ فَأَفْتَانِي بِأَنِّي قَدْ حَلَلْتُ حِينَ وَضَعْتُ حَمْلِي وَأَمَرَنِي بِالتَّزْوِيجِ إِنْ بَدَا لِي","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] berkata; telah menceritakan kepada kami [Ibnu Wahb] berkata; telah memberitakan kepadaku [Yunus] dari [Ibnu Syihab] bahwa ['Ubaidullah bin Abdullah] menceritakan kepadanya bahwa [ayahnya] mengirim surat kepada [Umar bin Abdulllah bin Arqam Az Zuhri] memerintahkan kepadanya agar menemui Subai'ah binti Al Harits Al Aslamiyah. Kemudian iapun bertanya kepada [Subai'ah] mengenai kisahnya dan apa yang dikatakan Rasulullah shallallahu 'alaihi wasallam kepadanya saat minta fatwa. Kemudian Umar bin Abdullah mengirim surat kepada Abdullah bin 'Utbah mengabarkan kepadanya, bahwa Subai'ah mengabarkan kepadanya bahwa ia pernah menjadi isteri Sa'd bin Khaulah dari Bani 'Amir bin Luai, seorang ahli badar. Kemudian suaminya meninggal saat haji Wada', sementara dirinya dalam keadaan hamil. Dan tak lama kemudian iua melahirkan anak. Setelah selesai nifas ia berhias untuk orang yang meminang. Lalu ia ditemui Abu As Sanabil bin Ba'kak seorang laki-laki dari Bani Abdu Ad Dar. Abu Sanabil lalu berkata kepadanya, \"Kenapa aku lihat engkau berhias? Apakah engkau akan menikah? Sungguh, demi Allah engkau tidak halal menikah hingga lewat empat bulan sepuluh hari.\" Subai'ah berkata, \"Setelah ia mengatakan itu kepadaku, maka aku pun mengumpulkan pakaianku, kemudian di sore harinya aku menemui Rasulullah shallallahu 'alaihi wasallam dan menanyakan hal tersebut. Beliau kemudian memberikan fatwa bahwa aku telah halal ketika melahirkan kandunganku. Dan beliau memerintahkanku untuk menikah apabila aku menghendaki.\""},"3365":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ وَهْبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي أَبُو عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَبِي أُنَيْسَةَ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ مُحَمَّدِ بْنِ مُسْلِمٍ الزُّهْرِيِّ قَالَ كَتَبَ إِلَيْهِ يَذْكُرُ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ حَدَّثَهُ أَنَّ زُفَرَ بْنَ أَوْسِ بْنِ الْحَدَثَانِ النَّصْرِيَّ حَدَّثَهُأَنَّ أَبَا السَّنَابِلِ بْنَ بَعْكَكِ بْنِ السَّبَّاقِ قَالَ لِسُبَيْعَةَ الْأَسْلَمِيَّةِ لَا تَحِلِّينَ حَتَّى يَمُرَّ عَلَيْكِ أَرْبَعَةُ أَشْهُرٍ وَعَشْرًا أَقْصَى الْأَجَلَيْنِ فَأَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَتْهُ عَنْ ذَلِكَ فَزَعَمَتْ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْتَاهَا أَنْ تَنْكِحَ إِذَا وَضَعَتْ حَمْلَهَا وَكَانَتْ حُبْلَى فِي تِسْعَةِ أَشْهُرٍ حِينَ تُوُفِّيَ زَوْجُهَا وَكَانَتْ تَحْتَ سَعْدِ بْنِ خَوْلَةَ فَتُوُفِّيَ فِي حَجَّةِ الْوَدَاعِ مَعَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَنَكَحَتْ فَتًى مِنْ قَوْمِهَا حِينَ وَضَعَتْ مَا فِي بَطْنِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Wahb] berkata; telah menceritakan kepadaku [Muhammad bin Salamah] berkata; telah memberitakan kepadaku [Abu Abdurrahim] berkata; telah menceritakan kepadaku [Zaid bin Abu Unais] dari [Yazid bin Abu Habib] dari [Muhammad bin Muslim Az Zuhri] berkata, \"Ia menulis surat kepadanya menyebutkan bahwa ['Ubaidullah bin Abdullah] menceritakan kepadanya, bahwa [Zufar bin Aus bin Al Hadatsan An Nashri] menceritakan kepadanya, bahwa Abu As Sanabil bin Ba'kak bin As Sabbaq berkata kepada Subai'ah Al Aslamiyah, \"Engkau tidak halal hingga berlalu empat bulan sepuluh hari, yang paling lama di antara dua masa 'iddah.\" Kemudian [Subai'ah] datang kepada Rasulullah shallallahu 'alaihi wasallam dan menanyakan hal tersebut. Ia mengaku bahwa Rasulullah shallallahu 'alaihi wasallam memberinya fatwa untuk menikah apabila telah melahirkan kandungannya, dan ia hamil pada bulan ke sembilan ketika suaminya meninggal. Ia adalah isteri Sa'd bin Khaulah yang meninggal pada saat haji wada' bersama Rasulullah shallallahu 'alaihi wasallam. Kemudian Subai'ah menikah dengan seorang pemuda dari kaumnya ketika telah melahirkan bayi yang ada di perutnya.\""},"3366":{"ar":"أَخْبَرَنَا مَحْمُودُ بْنُ غَيْلَانَ قَالَ حَدَّثَنَا زَيْدُ بْنُ الْحُبَابِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ إِبْرَاهِيمَ عَنْ عَلْقَمَةَ عَنْ ابْنِ مَسْعُودٍأَنَّهُ سُئِلَ عَنْ رَجُلٍ تَزَوَّجَ امْرَأَةً وَلَمْ يَفْرِضْ لَهَا صَدَاقًا وَلَمْ يَدْخُلْ بِهَا حَتَّى مَاتَ قَالَ ابْنُ مَسْعُودٍ لَهَا مِثْلُ صَدَاقِ نِسَائِهَا لَا وَكْسَ وَلَا شَطَطَ وَعَلَيْهَا الْعِدَّةُ وَلَهَا الْمِيرَاثُ فَقَامَ مَعْقِلُ بْنُ سِنَانٍ الْأَشْجَعِيُّ فَقَالَ قَضَى فِينَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَرْوَعَ بِنْتِ وَاشِقٍ امْرَأَةٍ مِنَّا مِثْلَ مَا قَضَيْتَ فَفَرِحَ ابْنُ مَسْعُودٍ رَضِيَ اللَّهُ عَنْهُ","id":"Telah mengabarkan kepada kami [Mahmud bin Ghailan] berkata; telah menceritakan kepada kami [Zaid bin Al Hubab] berkata; telah menceritakan kepada kami [Sufyan] dari [Manshur] dari [Ibrahim] dari ['Alqamah] dari [Ibnu Mas'ud], bahwa ia ditanya mengenai seorang laki-laki yang menikahi seorang wanita, ia belum menentukan mahar dan belum menggaulinya hingga meninggal. Ibnu Mas'ud berkata, \"Wanita tersebut berhak mendapatkan mahar sebagai seorang wanita, tidak ada pengurangan dan kezhaliman, ia wajib ber'iddah dan mendapatkan warisan.\" Kemudian [Ma'qil bin Sinan Al Asyja'i] berdiri dan berkata, \"Rasulullah shallallahu 'alaihi wasallam telah memberikan keputusan pada kami terhadap Barwa' binti Wasyiq, seorang wanita di antara kami seperti apa yang telah engkau putuskan.\" Maka Ibnu Mas'ud merasa senang.\""},"3367":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تَحِدُّ عَلَى مَيِّتٍ أَكْثَرَ مِنْ ثَلَاثٍ إِلَّا عَلَى زَوْجِهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah memberitakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Urwah] dari [Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang wanita untuk berkabung terhadap mayit melebihi tiga hari kecuali terhadap suaminya.\""},"3368":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْمَرٍ قَالَ حَدَّثَنَا حَبَّانُ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ قَالَ حَدَّثَنَا الزُّهْرِيُّ عَنْ عُرْوَةَ عَنْ عَائِشَةَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تَحِدَّ فَوْقَ ثَلَاثَةِ أَيَّامٍ إِلَّا عَلَى زَوْجٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'mar] berkata; telah menceritakan kepada kami [Habban] berkata; telah menceritakan kepada kami [Sulaiman bin Katsir] berkata; telah menceritakan kepada kami [Az Zuhri] dari ['Urwah] dari [Aisyah] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak halal seorang wanita yang beriman kepada Allah dan Hari Akhir untuk berkabung di atas tiga hari kecuali terhadap suaminya.\""},"3369":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي أَيُّوبُ بْنُ مُوسَى عَنْ حُمَيْدِ بْنِ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ أَنَّ أُمَّ حَبِيبَةَ قَالَتْسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى هَذَا الْمِنْبَرِ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَرَسُولِهِ أَنْ تَحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثِ لَيَالٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] berkata; telah menceritakan kepada kami [Abdullah bin Yusuf] berkata; telah menceritakan kepada kami [Al Laits] berkata; telah menceritakan kepadaku [Ayyub bin Musa] dari [Humaid bin Nafi'] dari [Zainab binti Abu Salamah] bahwa [Ummu Habibah] berkata, \"Aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbar ini: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan rasul-Nya untuk berkabung terhadap mayit di atas tiga malam, kecuali terhadap suaminya hingga empat bulan sepuluh hari.\""},"3370":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْعَلَاءِ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ شُعْبَةَ وَابْنُ جُرَيْجٍ وَيَحْيَى بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ إِسْحَقَ عَنْ سَعْدِ بْنِ إِسْحَقَ عَنْ زَيْنَبَ بِنْتِ كَعْبٍ عَنْ الْفَارِعَةِ بِنْتِ مَالِكٍأَنَّ زَوْجَهَا خَرَجَ فِي طَلَبِ أَعْلَاجٍ فَقَتَلُوهُ قَالَ شُعْبَةُ وَابْنُ جُرَيْجٍ وَكَانَتْ فِي دَارٍ قَاصِيَةٍ فَجَاءَتْ وَمَعَهَا أَخُوهَا إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرُوا لَهُ فَرَخَّصَ لَهَا حَتَّى إِذَا رَجَعَتْ دَعَاهَا فَقَالَ اجْلِسِي فِي بَيْتِكِ حَتَّى يَبْلُغَ الْكِتَابُ أَجَلَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala] berkata; telah menceritakan kepada kami [Ibnu Idris] dari [Syu'bah] dan [Ibnu Juraij] dan [Yahya bin Sa'id] dan [Muhammad bin Ishaq] dari [Sa'd bin Ishaq] dari [Zainab binti Ka'b] dari [Al Fari'ah binti Malik], bahwa suaminya keluar untuk mencari pekerja yang kuat, kemudian mereka membunuhnya.\" [Syu'bah] dan [Ibnu Juraij] berkata, \"Al Fari'ah berada di kampung yang jauh, kemudian ia datang bersama saudara laki-lakinya kepada Rasulullah shallallahu 'alaihi wasallam. Kemudian mereka menceritakan kepada beliau dan beliau memberikan keringanan untuknya, hingga ketika Fari'ah kembali, beliau memanggilnya dan bersabda: \"Duduklah di rumahmu hingga selesai masa 'iddah.\""},"3371":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ يَزِيدَ بْنِ مُحَمَّدٍ عَنْ سَعْدِ بْنِ إِسْحَقَ عَنْ عَمَّتِهِ زَيْنَبَ بِنْتِ كَعْبٍ عَنْ الْفُرَيْعَةِ بِنْتِ مَالِكٍأَنَّ زَوْجَهَا تَكَارَى عُلُوجًا لِيَعْمَلُوا لَهُ فَقَتَلُوهُ فَذَكَرَتْ ذَلِكَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَتْ إِنِّي لَسْتُ فِي مَسْكَنٍ لَهُ وَلَا يَجْرِي عَلَيَّ مِنْهُ رِزْقٌ أَفَأَنْتَقِلُ إِلَى أَهْلِي وَيَتَامَايَ وَأَقُومُ عَلَيْهِمْ قَالَ افْعَلِي ثُمَّ قَالَ كَيْفَ قُلْتِ فَأَعَادَتْ عَلَيْهِ قَوْلَهَا قَالَ اعْتَدِّي حَيْثُ بَلَغَكِ الْخَبَرُ","id":"Telah mengabarkan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Yazid bin Muhammad] dari [Sa'd bin Ishaq] dari bibinya [Zainab binti Ka'b] dari [Al Furai'ah binti Malik], bahwa suaminya menyewa pekerja kuat agar bekerja kepadanya, kemudian mereka membunuhnya. Lalu ia menyebutkan hal tersebut kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya aku tidak berada di rumahnya dan aku tidak mendapatkan nafkah darinya. Apakah boleh aku pindah kepada keluargaku dan mengurusi anak-anak yatimku? Beliau bersabda: \"Lakukanlah.\" Kemudian beliau bersabda: \"Apa yang kamu katakan?\" Kemudian ia mengulangi perkataannya lagi. Beliau bersabda: \"Lakukanlah Iddah di tempat kamu mendengar kabar (kematian itu).\""},"3372":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ سَعْدِ بْنِ إِسْحَقَ عَنْ زَيْنَبَ عَنْ فُرَيْعَةَأَنَّ زَوْجَهَا خَرَجَ فِي طَلَبِ أَعْلَاجٍ لَهُ فَقُتِلَ بِطَرَفِ الْقَدُّومِ قَالَتْ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ لَهُ النُّقْلَةَ إِلَى أَهْلِي وَذَكَرَتْ لَهُ حَالًا مِنْ حَالِهَا قَالَتْ فَرَخَّصَ لِي فَلَمَّا أَقْبَلْتُ نَادَانِي فَقَالَ امْكُثِي فِي أَهْلِكِ حَتَّى يَبْلُغَ الْكِتَابُ أَجَلَهُ","id":"Telah mengabarkan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Hammad] dari [Sa'd bin Ishaq] dari [Zainab] dari [Furai'ah], bahwa suaminya keluar untuk mencari budak miliknya. Kemudian ia terbunuh di Tharafi Al Qaddum. Furai'ah berkata, \"Kemudian aku datang kepada Nabi shallallahu 'alaihi wasallam dan menceritakan kepada beliau bahwa aku ingin pindah kepada keluargaku.\" Kemudian Furai'ah menyebutkan kondisinya. Furai'ah berkata, \"Beliau lalu memberiku keringanan, namun saat aku berbalik (ingin berlalu pergi) beliau memanggilku dan bersabda: \"Tinggallah di rumah keluargamu hingga selesai masa 'iddah.\""},"3373":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَزِيدُ قَالَ حَدَّثَنَا وَرْقَاءُ عَنْ ابْنِ أَبِي نَجِيحٍ قَالَ عَطَاءٌ عَنْ ابْنِ عَبَّاسٍنَسَخَتْ هَذِهِ الْآيَةُ عِدَّتَهَا فِي أَهْلِهَا فَتَعْتَدُّ حَيْثُ شَاءَتْ وَهُوَ قَوْلُ اللَّهِ عَزَّ وَجَلَّ غَيْرَ إِخْرَاجٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] berkata; telah menceritakan kepada kami [Yazid] berkata; telah menceritakan kepada kami [Warqa`] dari [Ibnu Abu Najih] ['Atha] berkata dari [Ibnu Abbas], \"Ayat ini telah menghapus bahwa ia harus melakukan iddah di rumah keluarganya, dan ia boleh melakukan iddah di tempat yang ia kehendaki, yaitu firman Allah Azza wa Jalla: '(tanpa keluar rumah).\""},"3374":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ عَنْ سُفْيَانَ عَنْ سَعْدِ بْنِ إِسْحَقَ قَالَ حَدَّثَتْنِي زَيْنَبُ بِنْتُ كَعْبٍ قَالَتْ حَدَّثَتْنِي فُرَيْعَةُ بِنْتُ مَالِكٍ أُخْتُ أَبِي سَعِيدٍ الْخُدْرِيِّ قَالَتْتُوُفِّيَ زَوْجِي بِالْقَدُومِ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ لَهُ إِنَّ دَارَنَا شَاسِعَةٌ فَأَذِنَ لَهَا ثُمَّ دَعَاهَا فَقَالَ امْكُثِي فِي بَيْتِكِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا حَتَّى يَبْلُغَ الْكِتَابُ أَجَلَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Manshur] berkata; telah menceritakan kepada kami [Abdurrahman] dari [Sufyan] dari [Sa'd bin Ishaq] berkata; telah menceritakan kepadaku [Zainab binti Ka'b] berkata; telah menceritakan kepadaku [Furai'ah binti Malik] saudara wanita Abu Sa'id Al Khudri, ia berkata, \"Suamiku meninggal di daerah Al Qadum, kemudian aku datang kepada Nabi shallallahu 'alaihi wasallam dan menyebutkan kepadanya bahwa kampung kami jauh.\" Beliau kemudian memberinya izin, namun kemudian beliau memanggilnya kembali seraya bersabda: \"Tinggallah di rumahmu selama empat bulan sepuluh hari hingga selesai masa 'iddah.\""},"3375":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ قَالَ أَنْبَأَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي بَكْرٍ عَنْ حُمَيْدِ بْنِ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ أَنَّهَا أَخْبَرَتْهُ بِهَذِهِ الْأَحَادِيثِ الثَّلَاثَةِقَالَتْ زَيْنَبُ دَخَلْتُ عَلَى أُمِّ حَبِيبَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَ أَبُوهَا أَبُو سُفْيَانَ بْنُ حَرْبٍ فَدَعَتْ أُمُّ حَبِيبَةَ بِطِيبٍ فَدَهَنَتْ مِنْهُ جَارِيَةً ثُمَّ مَسَّتْ بِعَارِضَيْهَا ثُمَّ قَالَتْ وَاللَّهِ مَا لِي بِالطِّيبِ مِنْ حَاجَةٍ غَيْرَ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ تَحِدُّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثِ لَيَالٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan aku mendengar, lafazhnya adalah lafazh Al Harits, ia berkata; telah memberitakan kepada kami [Ibnu Al Qasim] dari [Malik] dari [Abdullah bin Abu Bakr] dari [Humaid bin Nafi'] dari [Zainab binti Abu Salamah], bahwa ia mengabarkan kepadanya tiga hadits.\" Zainab berkata, \"Aku menemui [Ummu Habibah] isteri Nabi shallallahu 'alaihi wasallam ketika ayahnya, Abu Sufyan bin Harb, meninggal. Kemudian Ummu Habibah meminta minyak wangi dan memberi seorang sahaya wanita sebagian darinya kemudian ia mengusap kedua pipinya kemudian berkata, \"Demi Allah, aku tidak butuh kepada minyak wangi, hanya saja aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan Hari Akhir untuk berkabung terhadap mayit di atas tiga malam, kecuali terhadap suaminya hingga empat bulan sepuluh hari.\""},"3376":{"ar":"قَالَتْ زَيْنَبُثُمَّ دَخَلْتُ عَلَى زَيْنَبَ بِنْتِ جَحْشٍ حِينَ تُوُفِّيَ أَخُوهَا وَقَدْ دَعَتْ بِطِيبٍ وَمَسَّتْ مِنْهُ ثُمَّ قَالَتْ وَاللَّهِ مَا لِي بِالطِّيبِ مِنْ حَاجَةٍ غَيْرَ أَنِّي سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ عَلَى الْمِنْبَرِ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ تَحِدُّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثِ لَيَالٍ إِلَّا عَلَى زَوْجٍ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya) [Zainab] berkata, \"Aku menemui [Zainab binti Jahsy] ketika saudaranya meninggal, dan ia minta minyak wangi dan mengusap dengan sebagiannya, kemudian berkata, \"Demi Allah, aku tidak membutuhkan minyak wangi, hanya saja aku pernah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda di atas mimbar: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan Hari Akhir untuk berkabung terhadap mayit di atas tiga malam, kecuali terhadap suami hingga empat bulan sepuluh hari.\""},"3377":{"ar":"وَقَالَتْ زَيْنَبُ سَمِعْتُ أُمَّ سَلَمَةَ تَقُولُجَاءَتْ امْرَأَةٌ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنَتِي تُوُفِّيَ عَنْهَا زَوْجُهَا وَقَدْ اشْتَكَتْ عَيْنَهَا أَفَأَكْحُلُهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا ثُمَّ قَالَ إِنَّمَا هِيَ أَرْبَعَةُ أَشْهُرٍ وَعَشْرًا وَقَدْ كَانَتْ إِحْدَاكُنَّ فِي الْجَاهِلِيَّةِ تَرْمِي بِالْبَعْرَةِ عِنْدَ رَأْسِ الْحَوْلِقَالَ حُمَيْدٌ فَقُلْتُ لِزَيْنَبَ وَمَا تَرْمِي بِالْبَعْرَةِ عِنْدَ رَأْسِ الْحَوْلِ قَالَتْ زَيْنَبُ كَانَتْ الْمَرْأَةُ إِذَا تُوُفِّيَ عَنْهَا زَوْجُهَا دَخَلَتْ حِفْشًا وَلَبِسَتْ شَرَّ ثِيَابِهَا وَلَمْ تَمَسَّ طِيبًا وَلَا شَيْئًا حَتَّى تَمُرَّ بِهَا سَنَةٌ ثُمَّ تُؤْتَى بِدَابَّةٍ حِمَارٍ أَوْ شَاةٍ أَوْ طَيْرٍ فَتَفْتَضُّ بِهِ فَقَلَّمَا تَفْتَضُّ بِشَيْءٍ إِلَّا مَاتَ ثُمَّ تَخْرُجُ فَتُعْطَى بَعْرَةً فَتَرْمِي بِهَا وَتُرَاجِعُ بَعْدُ مَا شَاءَتْ مِنْ طِيبٍ أَوْ غَيْرِهِ قَالَ مَالِكٌ تَفْتَضُّ تَمْسَحُ بِهِ فِي حَدِيثِ مُحَمَّدٍ قَالَ مَالِكٌ الْحِفْشُ الْخُصُّ","id":"(Masih dari jalur periwayatan yang sama dengan hadits sebelumnya), [Zainab] berkata, \"Aku mendengar [Ummu Salamah] berkata, \"Seorang wanita datang menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya anak wanitaku telah ditinggal mati suaminya dan ia mengeluhkan matanya, apakah aku boleh memberinya celak? Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak.\" Kemudian beliau bersabda: \"Sesungguhnya 'iddahnya adalah empat bulan sepuluh hari, dan sungguh salah seorang di antara kalian pada masa jahiliyah melempar kotoran binatang di penghujung tahun.\" Humaid berkata, \"Kemudian aku katakan kepada Zainab, \"Kenapa ia melempar kotoran binatang pada penghujung tahun? Zainab menjawab, \"Seorang wanita apabila ditinggal mati suaminya ia masuk ke rumah kecil dan buruk, memakai pakaian yang terburuk serta tidak mengusap minyak wangi atau apapun hingga lewat satu tahun. Kemudian didatangkan kepadanya binatang, keledai atau kambing atau burung kemudian ia memegangnya, jarang sekali ia menyentuh sesuatu kecuali sesuatu tersebut akan mati. Kemudian ia keluar dan diberi kotoran binatang, setelah itu ia melemparkannya dan kembali mengenakan minyak wangi atau yang lainnya.\" Malik berkata, \"Taftadldlu adalah mengusapnya.\" Dalam hadits Muhammad, Malik berkata, \"Al Hifsyu adalah rumah dari bambu.\""},"3378":{"ar":"أَخْبَرَنَا حُسَيْنُ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَ قَالَتْقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا تَحِدُّ امْرَأَةٌ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ فَإِنَّهَا تَحِدُّ عَلَيْهِ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا وَلَا تَلْبَسُ ثَوْبًا مَصْبُوغًا وَلَا ثَوْبَ عَصْبٍ وَلَا تَكْتَحِلُ وَلَا تَمْتَشِطُ وَلَا تَمَسُّ طِيبًا إِلَّا عِنْدَ طُهْرِهَا حِينَ تَطْهُرُ نُبَذًا مِنْ قُسْطٍ وَأَظْفَارٍ","id":"Telah mengabarkan kepada kami [Husain bin Muhammad bin Muhammad] berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Hisyam] dari [Hafshah] dari [Ummu 'Athiyah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak boleh seorang wanita berkabung terhadap mayit di atas tiga hari kecuali terhadap seorang suami. Sesungguhnya ia berkabung terhadapnya selama empat bulan sepuluh hari. Dan tidak memakai pakaian yang dicelup serta pakaian bergaris dari Yaman, tidak memakai celak dan menyisir rambut serta mengusap minyak wangi kecuali ketika suci, yaitu beberapa bagian dari anggota badan yang kering atau beberapa kuku.\""},"3379":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ إِسْمَعِيلَ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنَا يَحْيَى بْنُ أَبِي بُكَيْرٍ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ طَهْمَانَ قَالَ حَدَّثَنِي بُدَيْلٌ عَنْ الْحَسَنِ بْنِ مُسْلِمٍ عَنْ صَفِيَّةَ بِنْتِ شَيْبَةَ عَنْ أُمِّ سَلَمَةَ زَوْجِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْمُتَوَفَّى عَنْهَا زَوْجُهَا لَا تَلْبَسُ الْمُعَصْفَرَ مِنْ الثِّيَابِ وَلَا الْمُمَشَّقَةَ وَلَا تَخْتَضِبُ وَلَا تَكْتَحِلُ","id":"Telah mengabarkan kepada kami [Muhammad bin Isma'il bin Ibrahim] berkata; telah menceritakan kepada kami [Yahya bin Abu Bukair] berkata; telah menceritakan kepada kami [Ibrahim bin Thahman] berkata; telah menceritakan kepadaku [Budail] dari [Al Hasan bin Muslim] dari [Shafiyah binti Syaibah] dari [Ummu Salamah] isteri Nabi shallallahu 'alaihi wasallam, dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Wanita yang ditinggal mati suaminya tidak boleh memakai pakaian yang berwarna kuning, pakaian yang dicelup dengan tanah liat merah, serta tidak mengecat kuku serta memakai celak.\""},"3380":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنَا عَاصِمٌ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا يَحِلُّ لِامْرَأَةٍ تُؤْمِنُ بِاللَّهِ وَالْيَوْمِ الْآخِرِ أَنْ تَحِدَّ عَلَى مَيِّتٍ فَوْقَ ثَلَاثٍ إِلَّا عَلَى زَوْجٍ وَلَا تَكْتَحِلُ وَلَا تَخْتَضِبُ وَلَا تَلْبَسُ ثَوْبًا مَصْبُوغًا","id":"Telah mengabarkan kepada kami [Muhammad bin Manshur] berkata; telah menceritakan kepada kami [Sufyan] berkata; telah menceritakan kepada kami ['Ashim] dari [Hafshah] dari [Ummu 'Athiyah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak halal bagi seorang wanita yang beriman kepada Allah dan Hari Akhir untuk berkabung terhadap mayit di atas tiga hari kecuali terhadap suami, ia tidak boleh memakai celak, mengecat kuku serta memakai pakaian yang dicelup.\""},"3381":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَمْرِو بْنِ السَّرْحِ قَالَ حَدَّثَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي مَخْرَمَةُ عَنْ أَبِيهِ قَالَ سَمِعْتُ الْمُغِيرَةَ بْنَ الضَّحَّاكِ يَقُولُ حَدَّثَتْنِي أُمُّ حَكِيمٍ بِنْتُ أَسِيدٍ عَنْ أُمِّهَاأَنَّ زَوْجَهَا تُوُفِّيَ وَكَانَتْ تَشْتَكِي عَيْنَهَا فَتَكْتَحِلُ الْجَلَاءَ فَأَرْسَلَتْ مَوْلَاةً لَهَا إِلَى أُمِّ سَلَمَةَ فَسَأَلَتْهَا عَنْ كُحْلِ الْجَلَاءِ فَقَالَتْ لَا تَكْتَحِلُ إِلَّا مِنْ أَمْرٍ لَا بُدَّ مِنْهُ دَخَلَ عَلَيَّ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ تُوُفِّيَ أَبُو سَلَمَةَ وَقَدْ جَعَلْتُ عَلَى عَيْنِي صَبْرًا فَقَالَ مَا هَذَا يَا أُمَّ سَلَمَةَ قُلْتُ إِنَّمَا هُوَ صَبْرٌ يَا رَسُولَ اللَّهِ لَيْسَ فِيهِ طِيبٌ قَالَ إِنَّهُ يَشُبُّ الْوَجْهَ فَلَا تَجْعَلِيهِ إِلَّا بِاللَّيْلِ وَلَا تَمْتَشِطِي بِالطِّيبِ وَلَا بِالْحِنَّاءِ فَإِنَّهُ خِضَابٌ قُلْتُ بِأَيِّ شَيْءٍ أَمْتَشِطُ يَا رَسُولَ اللَّهِ قَالَ بِالسِّدْرِ تُغَلِّفِينَ بِهِ رَأْسَكِ","id":"Telah mengabarkan kepada kami [Ahmad bin 'Amru bin As Sarh] berkata; telah menceritakan kepada kami [Ibnu Wahb] berkata; telah mengabarkan kepada kami [Makhramah] dari [ayahnya] berkata; aku mendengar [Mughirah bin Adl Dlahhak] berkata; telah menceritakan kepadaku [Ummu Hakim binti Asid] dari [Ibunya], bahwa suaminya meninggal dan ia mengeluhkan matanya, lalu ia mengenakan celak pada matanya. Setelah itu ia mengirim budak wanitanya menemui [Ummu Salamah] agar bertanya kepadanya mengenai celak mata. Ummu Salamah lalu menjawab, \"Janganlah ia memakai celak kecuali pada perkara yang penting, Rasulullah shallallahu 'alaihi wasallam menemuiku ketika Abu Salamah meninggal dan aku telah memakai perasan pohon yang pahit dimataku, beliau bersabda: \"Apa ini hai Ummu Salamah?\" aku menjawab, \"Itu perasan pohon yang pahit wahai Rasulullah.\" Beliau lalu bersabda: \"Sesungguhnya ia memperindah wajah, maka janganlah engkau memakainya kecuali diwaktu malam, jangan engkau menyisir rambut dengan parfum dan inai, karena itu adalah cat.\" Aku lalu bertanya, \"Lantas dengan apa aku bersisir wahai Rasulullah? Beliau menjawab: \"Olesilah kepalamu dengan daun bidara.\""},"3382":{"ar":"أَخْبَرَنَا الرَّبِيعُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا شُعَيْبُ بْنُ اللَّيْثِ عَنْ أَبِيهِ قَالَ حَدَّثَنَا أَيُّوبُ وَهُوَ ابْنُ مُوسَى قَالَ حُمَيْدٌ وَحَدَّثَتْنِي زَيْنَبُ بِنْتُ أَبِي سَلَمَةَ عَنْ أُمِّهَا أُمِّ سَلَمَةَ قَالَتْجَاءَتْ امْرَأَةٌ مِنْ قُرَيْشٍ فَقَالَتْ يَا رَسُولَ اللَّهِ إِنَّ ابْنَتِي رَمِدَتْ أَفَأَكْحُلُهَا وَكَانَتْ مُتَوَفًّى عَنْهَا فَقَالَ أَلَا أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا ثُمَّ قَالَتْ إِنِّي أَخَافُ عَلَى بَصَرِهَا فَقَالَ لَا إِلَّا أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا قَدْ كَانَتْ إِحْدَاكُنَّ فِي الْجَاهِلِيَّةِ تَحِدُّ عَلَى زَوْجِهَا سَنَةً ثُمَّ تَرْمِي عَلَى رَأْسِ السَّنَةِ بِالْبَعْرَةِ","id":"Telah mengabarkan kepada kami [Ar Rabi' bin Sulaiman] berkata; telah menceritakan kepada kami [Syu'aib bin Al Laits] dari [ayahnya] berkata; telah menceritakan kepada kami [Ayyub] -yaitu Ibnu Musa-, [Humaid] berkata; dan telah menceritakan kepadaku [Zainab binti Abu Salamah] dari ibunya [Ummu Salamah] ia berkata, \"Seorang wanita Quraisy datang dan berkata, \"Wahai Rasulullah, sesungguhnya anak wanitaku mengalami sakit mata, apakah aku boleh memakaikan celak kepadanya? Ia adalah wanita yang telah ditinggal mati suaminya?\" Maka beliau bersabda: \"Tidak, hingga berlalu empat bulan sepuluh hari.\" Kemudian wanita itu berkata, \" Sesungguhnya aku mengkhawatirkan penglihatannya.\" Kemudian beliau bersabda: \"Tidak, kecuali setelah empat bulan sepuluh hari. Dahulu salah seorang dari kalian pada masa jahiliyah berkabung terhadap suaminya hingga satu tahun, kemudian melempar kotoran binatang pada penghujung tahun.\""},"3383":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ يَزِيدَ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ حُمَيْدِ بْنِ نَافِعٍ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّهَاأَنَّ امْرَأَةً أَتَتْ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَتْهُ عَنْ ابْنَتِهَا مَاتَ زَوْجُهَا وَهِيَ تَشْتَكِي قَالَ قَدْ كَانَتْ إِحْدَاكُنَّ تَحِدُّ السَّنَةَ ثُمَّ تَرْمِي الْبَعْرَةَ عَلَى رَأْسِ الْحَوْلِ وَإِنَّمَا هِيَ أَرْبَعَةُ أَشْهُرٍ وَعَشْرًا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Yazid] berkata; telah menceritakan kepada kami [Sufyan] dari [Yahya bin Sa'id] dari [Humaid bin Nafi'] dari [Zainab binti Abu Salamah] dari [Ibunya], bahwa seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam kemudian bertanya mengenai anak wanitanya yang ditinggal mati suaminya dan ia sedang sakit. Beliau lalu bersabda: \"Sungguh, dahulu salah seorang di antara kalian berkabung hingga satu tahun kemudian melempar kotoran hewan pada penghujung tahun. Sesungguhnya 'iddah itu empat bulan sepuluh hari.\""},"3384":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مَعْدَانَ بْنِ عِيسَى بْنِ مَعْدَانَ قَالَ حَدَّثَنَا ابْنُ أَعْيَنَ قَالَ حَدَّثَنَا زُهَيْرُ بْنُ مُعَاوِيَةَ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ عَنْ حُمَيْدِ بْنِ نَافِعٍ مَوْلَى الْأَنْصَارِ عَنْ زَيْنَبَ بِنْتِ أَبِي سَلَمَةَ عَنْ أُمِّ سَلَمَةَأَنَّ امْرَأَةً مِنْ قُرَيْشٍ جَاءَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَتْ إِنَّ ابْنَتِي تُوُفِّيَ عَنْهَا زَوْجُهَا وَقَدْ خِفْتُ عَلَى عَيْنِهَا وَهِيَ تُرِيدُ الْكُحْلَ فَقَالَ قَدْ كَانَتْ إِحْدَاكُنَّ تَرْمِي بِالْبَعْرَةِ عَلَى رَأْسِ الْحَوْلِ وَإِنَّمَا هِيَ أَرْبَعَةُ أَشْهُرٍ وَعَشْرًافَقُلْتُ لِزَيْنَبَ مَا رَأْسُ الْحَوْلِ قَالَتْ كَانَتْ الْمَرْأَةُ فِي الْجَاهِلِيَّةِ إِذَا هَلَكَ زَوْجُهَا عَمَدَتْ إِلَى شَرِّ بَيْتٍ لَهَا فَجَلَسَتْ فِيهِ حَتَّى إِذَا مَرَّتْ بِهَا سَنَةٌ خَرَجَتْ فَرَمَتْ وَرَاءَهَا بِبَعْرَةٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Ma'dan bin Isa bin Ma'dan] ia berkata; telah menceritakan kepada kami [Ibnu A'yan] berkata; telah menceritakan kepada kami [Zuhair bin Mu'awiyah] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] dari [Humaid bin Nafi'] mantan budak kaum Anshar dari [Zainab binti Abu Salamah] dari [Ummu Salamah], bahwa seorang wanita Quraisy datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Sesungguhnya anak wanitaku ditinggal mati suaminya dan aku mengkhawatirkan matanya, maka aku ia ingin memakai celak?\" Beliau lalu bersabda: \"Sungguh, dahulu seseorang di antara kalian melempar kotoran hewan pada penghujung tahun. Sesungguhnya masa 'iddah adalah empat bulan sepuluh hari.\" Kemudian aku berkata kepada Zainab, \"Apakah penghujung tahun itu? Ia menjawab, \"Di masa jahiliyah dulu seorang wanita jika suaminya meninggal maka ia menuju rumahnya yang paling buruk dan tinggal di sana hingga berlalu satu tahun, kemudian ia keluar dan melempar kotoran hewan di belakangnya.\""},"3385":{"ar":"أَخْبَرَنَا يَحْيَى بْنُ حَبِيبِ بْنِ عَرَبِيٍّ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ يَحْيَى بْنِ سَعِيدٍ عَنْ حُمَيْدِ بْنِ نَافِعٍ عَنْ زَيْنَبَأَنَّ امْرَأَةً سَأَلَتْ أُمَّ سَلَمَةَ وَأُمَّ حَبِيبَةَ أَتَكْتَحِلُ فِي عِدَّتِهَا مِنْ وَفَاةِ زَوْجِهَا فَقَالَتْ أَتَتْ امْرَأَةٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَسَأَلَتْهُ عَنْ ذَلِكَ فَقَالَ قَدْ كَانَتْ إِحْدَاكُنَّ فِي الْجَاهِلِيَّةِ إِذَا تُوُفِّيَ عَنْهَا زَوْجُهَا أَقَامَتْ سَنَةً ثُمَّ قَذَفَتْ خَلْفَهَا بِبَعْرَةٍ ثُمَّ خَرَجَتْ وَإِنَّمَا هِيَ أَرْبَعَةُ أَشْهُرٍ وَعَشْرًا حَتَّى يَنْقَضِيَ الْأَجَلُ","id":"Telah mengabarkan kepada kami [Yahya bin Habib bin 'Arabi] berkata; telah menceritakan kepada kami [Hammad] dari [Yahya bin Sa'id] dari [Humaid bin Nafi'] dari [Zainab], bahwa seorang wanita bertanya kepada [Ummu Salamah] dan [Ummu Habibah], \"Apakah seorang wanita boleh memakai celak pada masa 'iddahnya karena kematian suaminya? Maka ia menjawab, \"Pernah seorang wanita datang kepada Nabi shallallahu 'alaihi wasallam dan bertanya mengenai hal tersebut. Beliau kemudian bersabda: \"Pada masa jahiliyah dulu, jika salah seorang dari kalian ditinggal mati suaminya, maka ia tinggal selama satu tahun kemudian melempar kotoran ke belakangnya kemudian keluar. Sesungguhnya masa 'iddah adalah empat bulan sepuluh hari hingga selesai masa 'iddah.\""},"3386":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ مُحَمَّدٍ هُوَ الدُّورِيُّ قَالَ حَدَّثَنَا الْأَسْوَدُ بْنُ عَامِرٍ عَنْ زَائِدَةَ عَنْ هِشَامٍ عَنْ حَفْصَةَ عَنْ أُمِّ عَطِيَّةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ رَخَّصَ لِلْمُتَوَفَّى عَنْهَا عِنْدَ طُهْرِهَا فِي الْقُسْطِ وَالْأَظْفَارِ","id":"Telah mengabarkan kepada kami [Al Abbas bin Muhammad] -yaitu Ad Duri- ia berkata; telah menceritakan kepada kami [Al Aswad bin 'Amir] dari [Zaidah] dari [Hisyam] dari [Hafshah] dari [Ummu 'Athiyah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau memberikan keringanan bagi seorang wanita yang ditinggal mati untuk mengenakan wewangian jika telah suci.\""},"3387":{"ar":"أَخْبَرَنَا زَكَرِيَّا بْنُ يَحْيَى السِّجْزِيُّ خَيَّاطُ السُّنَّةِ قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ أَخْبَرَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ }نُسِخَ ذَلِكَ بِآيَةِ الْمِيرَاثِ مِمَّا فُرِضَ لَهَا مِنْ الرُّبُعِ وَالثُّمُنِ وَنَسَخَ أَجَلَ الْحَوْلِ أَنْ جُعِلَ أَجَلُهَا أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya As Sijzi Khayyath As Sunnah] berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] berkata; telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata; telah memberitakan kepadaku [ayahku] ia berkata; telah menceritakan kepada kami [Yazid An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai firman Allah: '(Dan orang-orang yang akan meninggal dunia di antara kamu dan meninggalkan isteri, hendaklah berwasiat untuk isteri-isterinya, (yaitu) diberi nafkah hingga setahun lamanya dan tidak disuruh pindah (dari rumahnya) ' (Qs. Al Baqarah: 240), telah dihapus dengan ayat mengenai ayat warisan di antara yang ditetapkan baginya dari seperempat dan seperdelapan, dan Allah juga menghapus masa 'iddah satu tahun dan dijadikan empat bulan sepuluh hari.\""},"3388":{"ar":"أَخْبَرَنَا قُتَيْبَةُ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ سِمَاكٍ عَنْ عِكْرِمَةَفِي قَوْلِهِ عَزَّ وَجَلَّ{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا وَصِيَّةً لِأَزْوَاجِهِمْ مَتَاعًا إِلَى الْحَوْلِ غَيْرَ إِخْرَاجٍ }قَالَ نَسَخَتْهَا{ وَالَّذِينَ يُتَوَفَّوْنَ مِنْكُمْ وَيَذَرُونَ أَزْوَاجًا يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا }","id":"Telah mengabarkan kepada kami [Qutaibah] berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Simak] dari ['Ikrimah] mengenai firman Allah 'azza wajalla: '(Dan orang-orang yang akan meninggal dunia di antara kamu dan meninggalkan isteri, hendaklah berwasiat untuk isteri-isterinya, (yaitu) diberi nafkah hingga setahun lamanya dan tidak disuruh pindah (dari rumahnya) ' (Qs. Al Baqarah: 240). 'Ikrimah berkata, \"Ayat tersebut dihapus oleh ayat: '(Orang-orang yang meninggal dunia di antaramu dengan meninggalkan isteri-isteri (hendaklah para isteri itu) menangguhkan dirinya (ber'iddah) empat bulan sepuluh hari) ' (Qs. Al Baqarah: 234)."},"3389":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ عَطَاءٍ قَالَ أَخْبَرَنِي عَبْدُ الرَّحْمَنِ بْنُ عَاصِمٍ أَنَّ فَاطِمَةَ بِنْتَ قَيْسٍ أَخْبَرَتْهُ وَكَانَتْ عِنْدَ رَجُلٍ مِنْ بَنِي مَخْزُومٍأَنَّهُ طَلَّقَهَا ثَلَاثًا وَخَرَجَ إِلَى بَعْضِ الْمَغَازِي وَأَمَرَ وَكِيلَهُ أَنْ يُعْطِيَهَا بَعْضَ النَّفَقَةِ فَتَقَالَّتْهَا فَانْطَلَقَتْ إِلَى بَعْضِ نِسَاءِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَهِيَ عِنْدَهَا فَقَالَتْ يَا رَسُولَ اللَّهِ هَذِهِ فَاطِمَةُ بِنْتُ قَيْسٍ طَلَّقَهَا فُلَانٌ فَأَرْسَلَ إِلَيْهَا بِبَعْضِ النَّفَقَةِ فَرَدَّتْهَا وَزَعَمَ أَنَّهُ شَيْءٌ تَطَوَّلَ بِهِ قَالَ صَدَقَ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَانْتَقِلِي إِلَى أُمِّ كُلْثُومٍ فَاعْتَدِّي عِنْدَهَا ثُمَّ قَالَ إِنَّ أُمَّ كُلْثُومٍ امْرَأَةٌ يَكْثُرُ عُوَّادُهَا فَانْتَقِلِي إِلَى عَبْدِ اللَّهِ ابْنِ أُمِّ مَكْتُومٍ فَإِنَّهُ أَعْمَى فَانْتَقَلَتْ إِلَى عَبْدِ اللَّهِ فَاعْتَدَّتْ عِنْدَهُ حَتَّى انْقَضَتْ عِدَّتُهَا ثُمَّ خَطَبَهَا أَبُو الْجَهْمِ وَمُعَاوِيَةُ بْنُ أَبِي سُفْيَانَ فَجَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسْتَأْمِرُهُ فِيهِمَا فَقَالَ أَمَّا أَبُو الْجَهْمِ فَرَجُلٌ أَخَافُ عَلَيْكِ قَسْقَاسَتَهُ لِلْعَصَا وَأَمَّا مُعَاوِيَةُ فَرَجُلٌ أَمْلَقُ مِنْ الْمَالِ فَتَزَوَّجَتْ أُسَامَةَ بْنَ زَيْدٍ بَعْدَ ذَلِكَ","id":"Telah mengabarkan kepada kami [Abdul Hamid bin Muhammad] berkata; telah menceritakan kepada kami [Makhlad] berkata; telah menceritakan kepada kami [Ibnu Juraij] dari ['Atha] berkata; telah mengabarkan kepadaku [Abdurrahman bin 'Ashim] bahwa [Fatimah binti Qais] mengabarkan kepadanya, bahwa ia pernah menjadi isteri seorang laki-laki Bani Makhzum, dan dia telah menceraikannya dengan tiga talak. Laki-laki itu kemudian keluar kesebagian peperangan dan memerintahkan wakilnya agar memberikan nafkah kepadanya, namun ia menolak pemberian itu. Setelah itu ia pergi menemui sebagian isteri Nabi shallallahu 'alaihi wasallam, dan ketika Rasulullah shallallahu 'alaihi wasallam masuk ia sedang bersama salah seorang isterinya. Isteri beliau kemudian berkata, \"Wahai Rasulullah, ini Fatimah binti Qais, ia telah dicerai oleh Fulan. Kemudian Fulan mengirimkan kepadanya sebagian nafkah, namun ia menolak pemberian itu. Dan Fulan mengaku bahwa hal tersebut merupakan sesuatu yang ia berikan sebagai kebaikan darinya. Beliau bersabda: \"Ia benar\". Nabi shallallahu 'alaihi wasallam bersabda: \"Pindahlah kamu ke rumah Ummu Kultsum, dan lakukanlah iddah di sana.\" Kemudian beliau bersabda: \"Sesungguhnya Ummu Kultsum banyak orang yang mengunjunginya, maka pindahlah kepada Abdullah Ibnu Ummi Maktum, sesungguhnya ia adalah orang yang buta.\" Kemudian Fatimah pindah ke rumah Abdullah dan ber'iddah di rumahnya hingga selesai 'iddahnya, lalu ia dilamar Abu Al Jahm dan Mu'awiyah bin Abu Sufyan. Maka ia pun datang menemui Rasulullah shallallahu 'alaihi wasallam meminta petunjuk mengenai keduanya. Beliau bersabda: \"Abu Al Jahm itu seorang laki-laki yang aku khawatir dirimu terhadap pukulan tongkatnya. Adapun Mu'awiyah ia adalah laki-laki yang miskin tidak memiliki harta. Maka menikahlah dengan Usamah bin Zaid.\""},"3390":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا حُجَيْنُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا اللَّيْثُ عَنْ عُقَيْلٍ عَنْ ابْنِ شِهَابٍ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ أَنَّهَا أَخْبَرَتْهُأَنَّهَا كَانَتْ تَحْتَ أَبِي عَمْرِو بْنِ حَفْصِ بْنِ الْمُغِيرَةِ فَطَلَّقَهَا آخِرَ ثَلَاثِ تَطْلِيقَاتٍ فَزَعَمَتْ فَاطِمَةُ أَنَّهَا جَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَفْتَتْهُ فِي خُرُوجِهَا مِنْ بَيْتِهَا فَأَمَرَهَا أَنْ تَنْتَقِلَ إِلَى ابْنِ أُمِّ مَكْتُومٍ الْأَعْمَىفَأَبَى مَرْوَانُ أَنْ يُصَدِّقَ فَاطِمَةَ فِي خُرُوجِ الْمُطَلَّقَةِ مِنْ بَيْتِهَا قَالَ عُرْوَةُ أَنْكَرَتْ عَائِشَةُ ذَلِكَ عَلَى فَاطِمَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] berkata; telah menceritakan kepada kami [Hujain bin Al Mutsanna] berkata; telah menceritakan kepada kami [Al Laits] dari ['Uqail] dari [Ibnu Syihab] dari [Abu Salamah bin Abdurrahman] dari [Fatimah binti Qais] ia mengabarkan kepadanya, bahwa dirinya pernah menjadi isteri Abu 'Amru bin Hafsh bin Al Mughirah, kemudian ia mencerainya dengan talak ketiga. Kemudian Fatimah mengaku bahwa ia datang kepada Rasulullah shallallahu 'alaihi wasallam dan meminta fatwa untuk keluar dari rumahnya. Maka beliau memerintahkannya untuk pindah ke rumah Ibnu Ummi Maktum, seorang laki-laki orang yang buta. Namun Marwan menolak untuk mempercayai Fatimah mengenai keluarnya orang yang dicerai dari rumahnya.\" 'Urwah berkata, \"Aisyah mengingkari perbuatan Fatimah tersebut.\""},"3391":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا حَفْصٌ قَالَ حَدَّثَنَا هِشَامٌ عَنْ أَبِيهِ عَنْ فَاطِمَةَ قَالَتْقُلْتُ يَا رَسُولَ اللَّهِ زَوْجِي طَلَّقَنِي ثَلَاثًا وَأَخَافُ أَنْ يُقْتَحَمَ عَلَيَّ فَأَمَرَهَا فَتَحَوَّلَتْ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Hafsh] berkata; telah menceritakan kepada kami [Hisyam] dari [ayahnya] dari [Fatimah] berkata; aku berkata, \"Wahai Rasulullah, suamiku telah menceraiku dengan talak tiga, dan aku khawatir akan digauli.\" Kemudian beliau memerintahkannya untuk pindah, maka ia pun pindah.\""},"3392":{"ar":"أَخْبَرَنَا يَعْقُوبُ بْنُ مَاهَانَ بَصْرِيٌّ عَنْ هُشَيْمٍ قَالَ حَدَّثَنَا سَيَّارٌ وَحُصَيْنٌ وَمُغِيرَةُ وَدَاوُدُ بْنُ أَبِي هِنْدٍ وَإِسْمَعِيلُ بْنُ أَبِي خَالِدٍ وَذَكَرَ آخَرِينَ عَنْ الشَّعْبِيِّ قَالَدَخَلْتُ عَلَى فَاطِمَةَ بِنْتِ قَيْسٍ فَسَأَلْتُهَا عَنْ قَضَاءِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَيْهَا فَقَالَتْ طَلَّقَهَا زَوْجُهَا الْبَتَّةَ فَخَاصَمَتْهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي السُّكْنَى وَالنَّفَقَةِ قَالَتْ فَلَمْ يَجْعَلْ لِي سُكْنَى وَلَا نَفَقَةً وَأَمَرَنِي أَنْ أَعْتَدَّ فِي بَيْتِ ابْنِ أُمِّ مَكْتُومٍ","id":"Telah mengabarkan kepada kami [Ya'qub bin Mahan Bashri] dari [Husyaim] berkata; telah menceritakan kepada kami [Sayyar] dan [Hushain] [Mughirah] [Daud bin Abu Hindun] dan [Isma'il bin Abu Khalid] dan ia menyebutkan beberapa orang yang lain dari [Asy Sya'bi] berkata, \"Aku menemui [Fatimah binti Qais] bertanya kepadanya mengenai keputusan Rasulullah shallallahu 'alaihi wasallam terhadapnya. Kemudian ia berkata, bahwa suaminya telah menceraikannya dengan talak tiga, lalu ia mengadu kepada Rasulullah shallallahu 'alaihi wasallam perihal tempat tinggal dan nafkah. Ia berkata, \"Beliau tidak memberiku tempat tinggal dan nafkah. Dan beliau memerintahkanku untuk ber'iddah di rumah Ibnu Ummi Maktum.\""},"3393":{"ar":"أَخْبَرَنِي أَبُو بَكْرِ بْنُ إِسْحَقَ الصَّاغَانِيُّ قَالَ حَدَّثَنَا أَبُو الْجَوَّابِ قَالَ حَدَّثَنَا عَمَّارٌ هُوَ ابْنُ رُزَيْقٍ عَنْ أَبِي إِسْحَقَ عَنْ الشَّعْبِيِّ عَنْ فَاطِمَةَ بِنْتِ قَيْسٍ قَالَتْطَلَّقَنِي زَوْجِي فَأَرَدْتُ النُّقْلَةَ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ انْتَقِلِي إِلَى بَيْتِ ابْنِ عَمِّكِ عَمْرِو بْنِ أُمِّ مَكْتُومٍ فَاعْتَدِّي فِيهِفَحَصَبَهُ الْأَسْوَدُ وَقَالَ وَيْلَكَ لِمَ تُفْتِي بِمِثْلِ هَذَا قَالَ عُمَرُ إِنْ جِئْتِ بِشَاهِدَيْنِ يَشْهَدَانِ أَنَّهُمَا سَمِعَاهُ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَإِلَّا لَمْ نَتْرُكْ كِتَابَ اللَّهِ لِقَوْلِ امْرَأَةٍ{ لَا تُخْرِجُوهُنَّ مِنْ بُيُوتِهِنَّ وَلَا يَخْرُجْنَ إِلَّا أَنْ يَأْتِينَ بِفَاحِشَةٍ مُبَيِّنَةٍ }","id":"Telah mengabarkan kepada kami [Abu Bakr bin Ishaq Ash Shaghani] berkata; telah menceritakan kepada kami [Abu Al Jawwab] berkata; telah menceritakan kepada kami ['Ammar] -yaitu Ibnu Ruzaiq- dari [Abu Ishaq] dari [Asy Sya'bi] dari [Fatimah binti Qais] ia berkata, \"Suamiku telah menceraiku, kemudian aku ingin pindah. Lalu aku datang kepada Rasulullah shallallahu 'alaihi wasallam, maka beliau pun bersabda: \"Pindahlah ke rumah anak pamanmu, 'Amru bin Ummi Maktum, dan lakukanlah iddah di sana.\" Kemudian Al Aswad melempar Asy Sya'bi dan berkata, \"Celaka engkau! Kenapa engkau berfatwa dengan hal ini?\" Umar berkata, \"Apabila engkau mendatangkan dua saksi yang bisa bersaksi bahwa mereka mendengarnya dari Rasulullah shallallahu 'alaihi wasallam, dan jika tidak maka kami tidak akan meninggalkan Kitab Allah demi perkataan seorang wanita: '(Janganlah kamu keluarkan mereka dari rumah mereka dan janganlah mereka (diizinkan) ke luar kecuali mereka mengerjakan perbuatan keji yang terang) ' (Qs. Ath Thalaq: 1)."},"3394":{"ar":"أَخْبَرَنَا عَبْدُ الْحَمِيدِ بْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا مَخْلَدٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍ قَالَطُلِّقَتْ خَالَتُهُ فَأَرَادَتْ أَنْ تَخْرُجَ إِلَى نَخْلٍ لَهَا فَلَقِيَتْ رَجُلًا فَنَهَاهَا فَجَاءَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ اخْرُجِي فَجُدِّي نَخْلَكِ لَعَلَّكِ أَنْ تَصَدَّقِي وَتَفْعَلِي مَعْرُوفًا","id":"Telah mengabarkan kepada kami [Abdul Hamid bin Muhammad] berkata; telah menceritakan kepada kami [Makhlad] berkata; telah menceritakan kepada kami [Ibnu Juraij] dari [Az Zubair] dari [Jabir] ia berkata, bahwa bibinya telah dicerai kemudian ia (bibinya) ingin keluar menuju kebun kurmanya, saat bertemu dengan seorang laki-laki, laki-laki itu lalu melarangnya. Maka ia pun datang kepada Rasulullah shallallahu 'alaihi wasallam. Rasulullah shallallahu 'alaihi wasallam kemudian bersabda: \"Kemungkinan engkau ingin bersedekah dan melakukan suatu kebaikan.\""},"3395":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ اللَّهِ بْنِ الْحَكَمِ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي بَكْرِ بْنِ أَبِي الْجَهْمِ قَالَدَخَلْتُ أَنَا وَأَبُو سَلَمَةَ عَلَى فَاطِمَةَ بِنْتِ قَيْسٍ قَالَتْ طَلَّقَنِي زَوْجِي فَلَمْ يَجْعَلْ لِي سُكْنَى وَلَا نَفْقَةً قَالَتْ فَوَضَعَ لِي عَشْرَةَ أَقْفِزَةٍ عِنْدَ ابْنِ عَمٍّ لَهُ خَمْسَةٌ شَعِيرٌ وَخَمْسَةٌ تَمْرٌ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ ذَلِكَ فَقَالَ صَدَقَ وَأَمَرَنِي أَنْ أَعْتَدَّ فِي بَيْتِ فُلَانٍ وَكَانَ زَوْجُهَا طَلَّقَهَا طَلَاقًا بَائِنًا","id":"Telah mengabarkan kepada kami [Ahmad bin Abdullah bin Al Hakam] berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Bakr bin Abu Al Jahm] berkata; aku dan Abu Salamah menemui [Fatimah binti Qais] ia berkata, \"Suamiku telah menceraiku dan tidak memberikan kepadaku tempat tinggal dan nafkah. Kemudian ia memberiku sepuluh qafiz yang ada pada anak pamannya, yaitu lima qafiz gandum dan lima qafiz kurma. Kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan aku katakan hal tersebut kepada beliau. Beliau pun bersabda: 'Ia telah benar'. Dan beliau memerintahkan aku agar melakukan iddah di rumah Fulan.' Suaminya telah mencerainya dengan talak tiga.\""},"3396":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرِ بْنِ دِينَارٍ قَالَ حَدَّثَنَا أَبِي عَنْ شُعَيْبٍ قَالَ قَالَ الزُّهْرِيُّ أَخْبَرَنِي عُبَيْدُ اللَّهِ بْنُ عَبْدِ اللَّهِ بْنِ عُتْبَةَأَنَّ عَبْدَ اللَّهِ بْنَ عَمْرِو بْنِ عُثْمَانَ طَلَّقَ ابْنَةَ سَعِيدِ بْنِ زَيْدٍ وَأُمُّهَا حَمْنَةُ بِنْتُ قَيْسٍ الْبَتَّةَ فَأَمَرَتْهَا خَالَتُهَا فَاطِمَةُ بِنْتُ قَيْسٍ بِالِانْتِقَالِ مِنْ بَيْتِ عَبْدِ اللَّهِ بْنِ عَمْرٍو وَسَمِعَ بِذَلِكَ مَرْوَانُ فَأَرْسَلَ إِلَيْهَا فَأَمَرَهَا أَنْ تَرْجِعَ إِلَى مَسْكَنِهَا حَتَّى تَنْقَضِيَ عِدَّتُهَا فَأَرْسَلَتْ إِلَيْهِ تُخْبِرُهُ أَنَّ خَالَتَهَا فَاطِمَةَ أَفْتَتْهَا بِذَلِكَ وَأَخْبَرَتْهَا أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَفْتَاهَا بِالِانْتِقَالِ حِينَ طَلَّقَهَا أَبُو عَمْرِو بْنُ حَفْصٍ الْمَخْزُومِيُّ فَأَرْسَلَ مَرْوَانُ قَبِيصَةَ بْنَ ذُؤَيْبٍ إِلَى فَاطِمَةَ فَسَأَلَهَا عَنْ ذَلِكَ فَزَعَمَتْ أَنَّهَا كَانَتْ تَحْتَ أَبِي عَمْرٍو لَمَّا أَمَّرَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلِيَّ بْنَ أَبِي طَالِبٍ عَلَى الْيَمَنِ خَرَجَ مَعَهُ فَأَرْسَلَ إِلَيْهَا بِتَطْلِيقَةٍ وَهِيَ بَقِيَّةُ طَلَاقِهَا فَأَمَرَ لَهَا الْحَارِثَ بْنَ هِشَامٍ وَعَيَّاشَ بْنَ أَبِي رَبِيعَةَ بِنَفَقَتِهَا فَأَرْسَلَتْ إِلَى الْحَارِثِ وَعَيَّاشٍ تَسْأَلُهُمَا النَّفَقَةَ الَّتِي أَمَرَ لَهَا بِهَا زَوْجُهَا فَقَالَا وَاللَّهِ مَا لَهَا عَلَيْنَا نَفَقَةٌ إِلَّا أَنْ تَكُونَ حَامِلًا وَمَا لَهَا أَنْ تَسْكُنَ فِي مَسْكَنِنَا إِلَّا بِإِذْنِنَا فَزَعَمَتْ فَاطِمَةُ أَنَّهَا أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرَتْ ذَلِكَ لَهُ فَصَدَّقَهُمَا قَالَتْ فَقُلْتُ أَيْنَ أَنْتَقِلُ يَا رَسُولَ اللَّهِ فَقَالَ انْتَقِلِي عِنْدَ ابْنِ أُمِّ مَكْتُومٍ وَهُوَ الْأَعْمَى الَّذِي عَاتَبَهُ اللَّهُ عَزَّ وَجَلَّ فِي كِتَابِهِ فَانْتَقَلْتُ عِنْدَهُ فَكُنْتُ أَضَعُ ثِيَابِي عِنْدَهُ حَتَّى أَنْكَحَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ زَعَمَتْ أُسَامَةَ بْنَ زَيْدٍ","id":"Telah mengabarkan kepada kami ['Amr bin Utsman bin Sa'id bin Katsir] telah menceritakan kepada kami [ayahku] dari [Syu'aib] berkata; [Az Zuhri] berkata; telah memberitakan kepadaku ['Ubaidullah bin Abdullah bin 'Utbah] bahwa Abdullah bin 'Amru bin Utsman menceraikan anak Sa'id bin Zaid dengan talak tiga, sedang ibunya adalah Hamnah binti Qais. Kemudian bibinya, [Fatimah binti Qais], memerintahkan kepadanya untuk pindah dari rumah Abdullah bin 'Amru, dan hal tersebut didengar oleh Marwan. Kemudian Marwan mengirimkan utusan kepada wanita tersebut agar kembali ke tempatnya hingga selesai 'iddahnya. Kemudian wanita itu ganti mengutus seseorang untuk mengabarkan kepadanya, bahwa bibinya, Fatimah, telah memberinya fatwa untuk pindah. Dan bibinya juga mengabarkan kepadanya bahwa Rasulullah shallallahu 'alaihi wasallam telah berfatwa kepadanya untuk pindah ketika Abu 'Amru bin Hafsh Al Makhzumi menceraikannya. Kemudian Marwan mengirimkan Qabishah bin Dzuaib kepada Fatimah dan bertanya kepadanya mengenai hal tersebut. Fatimah kemudian mengaku bahwa ia dahulu pernah menjadi isteri Abu 'Amru. Tatkala Rasulullah shallallahu 'alaihi wasallam mengangkat Ali bin Abu Thalib sebagai amir di Yaman, maka ia keluar bersamanya dan mengirimkan utusan kepadanya untuk mencerainya dan itu adalah sisa cerainya. Kemudian memerintahkan Al Harits bin Hisyam dan 'Ayyasy bin Abu Rabi'ah agar memberinya nafkah. Lalu Fatimah mengirim utusan kepada Al Harits dan 'Ayyasy meminta nafkah kepada mereka berdua yang diperintahkan oleh suaminya agar diberikan kepadanya. Kemudian mereka berdua berkata, \"Demi Allah, ia tidak punya nafkah atas kami kecuali apabila ia sedang hamil. Dan ia tidak berhak tinggal di tempat tinggal kami kecuali dengan izin kami.\" Kemudian Fatimah mengaku bahwa ia pernah datang kepada Rasulullah shallallahu 'alaihi wasallam dan meceritakan hal tersebut, kemudian beliau membenarkan mereka berdua.\" Fatimah berkata, \"Kemudian aku katakan, 'Kemanakah aku berpindah wahai Rasulullah? Kemudian beliau bersabda: 'Pindahlah di rumah Ibnu Ummi Maktum, ia adalah orang yang buta yang Allah 'azza wajalla sebutkan dalam Kitab-Nya.' Kemudian aku pindah ke rumah Ibnu Ummi Maktum, dan aku meletakkan pakaian di rumahnya.' Hingga Rasulullah shallallahu 'alaihi wasallam menikahkannya dengan Usamah bin Zaid.\""},"3397":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ قَالَ حَدَّثَنَا اللَّيْثُ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ بُكَيْرِ بْنِ عَبْدِ اللَّهِ بْنِ الْأَشَجِّ عَنْ الْمُنْذِرِ بْنِ الْمُغِيرَةِ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ أَنَّ فَاطِمَةَ ابْنَةَ أَبِي حُبَيْشٍ حَدَّثَتْهُأَنَّهَا أَتَتْ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَشَكَتْ إِلَيْهِ الدَّمَ فَقَالَ لَهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا ذَلِكَ عِرْقٌ فَانْظُرِي إِذَا أَتَاكِ قُرْؤُكِ فَلَا تُصَلِّي فَإِذَا مَرَّ قُرْؤُكِ فَلْتَطْهُرِي قَالَ ثُمَّ صَلِّي مَا بَيْنَ الْقُرْءِ إِلَى الْقُرْءِ","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] berkata; telah menceritakan kepada kami [Abdullah bin Yusuf] berkata; telah menceritakan kepada kami [Al Laits] berkata; telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Bukair bin Abdullah bin Al Asyaj] dari [Al Mundzir bin Al Mughirah] dari ['Urwah bin Az Zubair] bahwa [Fatimah binti Abu Hubaisy] menceritakan kepadanya, bahwa ia datang kepada Rasulullah shallallahu 'alaihi wasallam dan mengeluhkan mengenai darah, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya ia hanyalah pembuluh darah, maka lihatlah, apabila haidmu mendatangimu maka janganlah melakukan shalat, lalu jika haidmu telah berlalu maka bersucilah lalu lakukan shalat di antara haid satu hingga haid yang lain.\""},"3398":{"ar":"حَدَّثَنَا زَكَرِيَّا بْنُ يَحْيَى قَالَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا عَلِيُّ بْنُ الْحُسَيْنِ بْنِ وَاقِدٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنَا يَزِيدُ النَّحْوِيُّ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍفِي قَوْلِهِ{ مَا نَنْسَخْ مِنْ آيَةٍ أَوْ نُنْسِهَا نَأْتِ بِخَيْرٍ مِنْهَا أَوْ مِثْلِهَا }وَقَالَ{ وَإِذَا بَدَّلْنَا آيَةً مَكَانَ آيَةٍ وَاللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ }الْآيَةَ وَقَالَ{ يَمْحُو اللَّهُ مَا يَشَاءُ وَيُثْبِتُ وَعِنْدَهُ أُمُّ الْكِتَابِ }فَأَوَّلُ مَا نُسِخَ مِنْ الْقُرْآنِ الْقِبْلَةُ وَقَالَ{ وَالْمُطَلَّقَاتُ يَتَرَبَّصْنَ بِأَنْفُسِهِنَّ ثَلَاثَةَ قُرُوءٍ وَلَا يَحِلُّ لَهُنَّ أَنْ يَكْتُمْنَ مَا خَلَقَ اللَّهُ فِي أَرْحَامِهِنَّ إِلَى قَوْلِهِ إِنْ أَرَادُوا إِصْلَاحًا }وَذَلِكَ بِأَنَّ الرَّجُلَ كَانَ إِذَا طَلَّقَ امْرَأَتَهُ فَهُوَ أَحَقُّ بِرَجْعَتِهَا وَإِنْ طَلَّقَهَا ثَلَاثًا فَنَسَخَ ذَلِكَ وَقَالَ{ الطَّلَاقُ مَرَّتَانِ فَإِمْسَاكٌ بِمَعْرُوفٍ أَوْ تَسْرِيحٌ بِإِحْسَانٍ }","id":"Telah mengabarkan kepada kami [Zakaria bin Yahya] berkata; telah menceritakan kepada kami [Ishaq bin Ibrahim] ia berkata; telah menceritakan kepada kami [Ali bin Al Husain bin Waqid] berkata; telah menceritakan kepadaku [ayahku] ia berkata; telah menceritakan kepada kami [Yazid An Nahwi] dari ['Ikrimah] dari [Ibnu Abbas] mengenai firman Allah: '(ayat mana saja yang kami nasakhkan atau kami jadikan lupa kepadanya maka kami datangkan yang lebih baik daripadanya atau yang sebanding darinya) ' (Qs. Al Baqarah: 106), dan firman Allah: '(Dan apabila kami letakkan suatu ayat di tempat ayat yang lain sebagai penggantinya padahal Allah lebih mengetahui apa yang diturunkan-Nya) ' (Qs. An Nahl: 1o1), dan firman Allah: '(Allah menghapuskan apa yang dia kehendaki dan menetapkan (apa yang dia kehendaki, dan di sisi-Nya-lah terdapat Ummul-Kitab (Lauh mahfuzh)) ' (Qs. Ar Ra'd: 39). Yang pertama kali dinasakh dalam Al Qur'an adalah tentang kiblat, dan firman: '(Wanita-wanita yang ditalak hendaklah menahan diri (menunggu) tiga kali quru'. Tidak boleh mereka menyembunyikan apa yang diciptakan Allah dalam rahimnya, jika mereka beriman kepada Allah dan hari akhirat. Dan suami-suaminya berhak merujukinya dalam masa menanti itu, jika mereka (para suami) menghendaki ishlah) ' (Qs. Al Baqarah: 228). Hal itu karena jika seorang laki-laki mencerai isterinya, maka ia lebih berhak untuk kembali kepadanya walaupun telah mencerainya tiga kali, kemudian Allah menghapus hal tersebut dan berfirman: '(Talak (yang dapat dirujuki) dua kali. Setelah itu boleh rujuk lagi dengan cara yang ma'ruf atau menceraikan dengan cara yang baik) ' (Qs. Al Baqarah: 229)."},"3399":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ قَالَ سَمِعْتُ يُونُسَ بْنَ جُبَيْرٍ قَالَ سَمِعْتُ ابْنَ عُمَرَ قَالَطَلَّقْتُ امْرَأَتِي وَهِيَ حَائِضٌ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عُمَرُ فَذَكَرَ لَهُ ذَلِكَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مُرْهُ أَنْ يُرَاجِعَهَا فَإِذَا طَهُرَتْ يَعْنِي فَإِنْ شَاءَ فَلْيُطَلِّقْهَا قُلْتُ لِابْنِ عُمَرَ فَاحْتَسَبْتَ مِنْهَا فَقَالَ مَا يَمْنَعُهَا أَرَأَيْتَ إِنْ عَجَزَ وَاسْتَحْمَقَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] ia berkata; telah menceritakan kepada kami [Muhammad] berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] berkata; aku mendengar [Yunus bin Jubair] berkata; aku mendengar [Ibnu Umar] berkata, \"Aku telah mencerai isteriku ketika sedang haid, kemudian Umar pergi menemui Nabi shallallahu 'alaihi wasallam dan menceritakan hal itu. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Perintahkan dia untuk merujuknya kembali, jika isterinya telah suci, jika mau ia boleh menceraikannya.\" Aku katakan kepada Ibnu Umar, \"Apakah kamu menghitungnya sebagai talak? ' Ibnu Umar menjawab, \"Apa yang menghalanginya? Bagaimana pendapatmu jika ia lemah atau bodoh?\""},"3400":{"ar":"حَدَّثَنَا بِشْرُ بْنُ خَالِدٍ قَالَ أَنْبَأَنَا يَحْيَى بْنُ آدَمَ عَنْ ابْنِ إِدْرِيسَ عَنْ مُحَمَّدِ بْنِ إِسْحَقَ وَيَحْيَى بْنُ سَعِيدٍ وَعُبَيْدُ اللَّهِ بْنُ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ ح و أَخْبَرَنَا زُهَيْرٌ عَنْ مُوسَى بْنِ عُقْبَةَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالُواإِنَّ ابْنَ عُمَرَ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَذَكَرَ عُمَرُ رَضِيَ اللَّهُ عَنْهُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ مُرْهُ فَلْيُرَاجِعْهَا حَتَّى تَحِيضَ حَيْضَةً أُخْرَى فَإِذَا طَهُرَتْ فَإِنْ شَاءَ طَلَّقَهَا وَإِنْ شَاءَ أَمْسَكَهَا فَإِنَّهُ الطَّلَاقُ الَّذِي أَمَرَ اللَّهُ عَزَّ وَجَلَّ بِهِ قَالَ تَعَالَى{ فَطَلِّقُوهُنَّ لِعِدَّتِهِنَّ }","id":"Telah mengabarkan kepada kami [Bisyr bin Khalid] ia berkata; telah memberitakan kepada kami [Yahya bin Adam] dari [Ibnu Abbas] dari [Muhammad bin Ishaq] dan [Yahya bin Sa'id] dan ['Ubaidullah bin Abdullah bin Umar] dari [Nafi'] dari [Ibnu Umar]. (dalam jalur lain disebutkan) Dan telah mengabarkan kepada kami [Zuhair] dari [Musa bin 'Uqbah] dari [Nafi'] dari [Ibnu Umar] mereka berkata, \"Sesungguhnya Ibnu Umar telah mencerai isterinya ketika ia dalam keadaan haid, kemudian Umar radliallahu 'anhu menyebutkan hal tersebut kepada Nabi shallallahu 'alaihi wasallam. Maka beliau pun bersabda: \"Perintahkan agar dia merujuk isterinya hingga ia mengalami haid yang lain, kemudian apabila telah suci, jika mau dia boleh mencerai dan jika mau dia boleh meneruskan pernikahannya. Sesungguhnya itu adalah talak yang diperintahkan Allah 'azza wajalla. Allah ta'ala berfirman: '(Hendaklah kamu ceraikan mereka pada waktu mereka dapat (menghadapi) iddahnya (yang wajar)) ' (Qs. Ath Thalaq: 1)."},"3401":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ أَيُّوبَ عَنْ نَافِعٍ قَالَكَانَ ابْنُ عُمَرَ إِذَا سُئِلَ عَنْ الرَّجُلِ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَيَقُولُ أَمَّا إِنْ طَلَّقَهَا وَاحِدَةً أَوْ اثْنَتَيْنِ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَمَرَهُ أَنْ يُرَاجِعَهَا ثُمَّ يُمْسِكَهَا حَتَّى تَحِيضَ حَيْضَةً أُخْرَى ثُمَّ تَطْهُرَ ثُمَّ يُطَلِّقَهَا قَبْلَ أَنْ يَمَسَّهَا وَأَمَّا إِنْ طَلَّقَهَا ثَلَاثًا فَقَدْ عَصَيْتَ اللَّهَ فِيمَا أَمَرَكَ بِهِ مِنْ طَلَاقِ امْرَأَتِكَ وَبَانَتْ مِنْكَ امْرَأَتُكَ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Isma'il] dari [Ayyub] dari [Nafi'] berkata, \"Jika [Ibnu Umar] ditanya mengenai seorang laki-laki yang mencerai isterinya saat dalam kondisi haid, maka ia berkata, \"Jika ia mencerainya dengan satu atau dua talak, maka Rasulullah shallallahu 'alaihi wasallam memerintahkannya untuk kembali kepadanya, kemudian menahannya hingga mengalami haid satu kali kemudian suci kemudian ia menceraikannya sebelum menggaulinya. Sedangkan jika ia mencerainya dengan talak tiga maka sungguh engkau telah berbuat durhaka kepada Allah dalam menceraikan isterimu yang telah Allah perintahkan kepadamu, dan isterimu telah dicerai secara bain (talak tiga).\""},"3402":{"ar":"أَخْبَرَنَا يُوسُفُ بْنُ عِيسَى مَرْوَزِيٌّ قَالَ حَدَّثَنَا الْفَضْلُ بْنُ مُوسَى قَالَ حَدَّثَنَا حَنْظَلَةُ عَنْ سَالِمٍ عَنْ ابْنِ عُمَرَأَنَّهُ طَلَّقَ امْرَأَتَهُ وَهِيَ حَائِضٌ فَأَمَرَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَرَاجَعَهَا","id":"Telah mengabarkan kepada kami [Yusuf bin Marwazi] berkata; telah menceritakan kepada kami [Al Fadll bin Musa] berkata; telah menceritakan kepada kami [Hanzhalah] dari [Salim] dari [Ibnu Umar], bahwa ia telah mencerai isterinya ketika dalam keadaan hamil, kemudian Rasulullah shallallahu 'alaihi wasallam memerintahakan kepadanya untuk merujuknya, maka ia pun kembali merujuk isterinya.\""},"3403":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو عَاصِمٍ قَالَ ابْنُ جُرَيْجٍ أَخْبَرَنِيهِ ابْنُ طَاوُسٍ عَنْ أَبِيهِ أَنَّهُ سَمِعَ عَبْدَ اللَّهِ بْنَ عُمَرَ يُسْأَلُعَنْ رَجُلٍ طَلَّقَ امْرَأَتَهُ حَائِضًا فَقَالَ أَتَعْرِفُ عَبْدَ اللَّهِ بْنَ عُمَرَ قَالَ نَعَمْ قَالَ فَإِنَّهُ طَلَّقَ امْرَأَتَهُ حَائِضًا فَأَتَى عُمَرُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرَهُ الْخَبَرَ فَأَمَرَهُ أَنْ يُرَاجِعَهَا حَتَّى تَطْهُرَ وَلَمْ أَسْمَعْهُ يَزِيدُ عَلَى هَذَا","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Abu 'Ashim] berkata; [Ibnu Juraij] telah mengabarkan kepadaku [Ibnu Thawus] dari [ayahnya] bahwa ia telah mendengar [Abdullah bin Umar] ditanya mengenai seorang laki-laki yang mencerai isterinya ketika dalam keadaan haid. Kemudian Ibnu Umar menjawab, \"Apakah engkau mengetahui Abdullah bin Umar? Orang yang bertanya itu berkata, \"Ya.\" Ibnu Umar lalu berkata, 'Sesungguhnya ia telah mencerai isterinya saat haid, kemudian Umar datang kepada Nabi shallallahu 'alaihi wasallam dan mengabarkan berita tersebut, maka beliau memerintahkan kepadanya agar merujuk isterinya hingga suci.' Dan aku tidak mendengar dia menambahkan lebih dari ini.\""},"3404":{"ar":"أَخْبَرَنَا عَبْدَةُ بْنُ عَبْدِ اللَّهِ قَالَ أَنْبَأَنَا يَحْيَى بْنُ آدَمَ ح وَأَنْبَأَنَا عَمْرُو بْنُ مَنْصُورٍ قَالَ حَدَّثَنَا سَهْلُ بْنُ مُحَمَّدٍ أَبُو سَعِيدٍ قَالَ نُبِّئْتُ عَنْ يَحْيَى بْنِ زَكَرِيَّا عَنْ صَالِحِ بْنِ صَالِحٍ عَنْ سَلَمَةَ بْنِ كُهَيْلٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ عَنْ ابْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَقَالَ عَمْرٌو إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ طَلَّقَ حَفْصَةَ ثُمَّ رَاجَعَهَا وَاللَّهُ أَعْلَمُ","id":"Telah mengabarkan kepada kami ['Abdah bin Abdullah] berkata; telah memberitakan kepada kami [Yahya bin Adam]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami ['Amru bin Manshur] berkata; telah menceritakan kepada kami [Sahl bin Muhammad Abu Sa'id] berkata; aku diberitahu dari [Yahya bin Zakaria] dari [Shalih bin Shalih] dari [Salamah bin Khuhail] dari [Sa'id bin Jubair] dari [Ibnu Abbas] dari [Ibnu Umar], bahwa Nabi shallallahu 'alaihi wasallam, … Dan 'Amru berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam pernah mencerai Hafshah kemudian kembali kepadanya. Wallahua'lam.\""},"3405":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ عَبْدِ الْوَاحِدِ قَالَ حَدَّثَنَا مَرْوَانُ وَهُوَ ابْنُ مُحَمَّدٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ يَزِيدَ بْنِ صَالِحِ بْنِ صَبِيحٍ الْمُرِّيُّ قَالَ حَدَّثَنَا إِبْرَاهِيمُ بْنُ أَبِي عَبْلَةَ عَنْ الْوَلِيدِ بْنِ عَبْدِ الرَّحْمَنِ الْجُرَشِيِّ عَنْ جُبَيْرِ بْنِ نُفَيْرٍ عَنْ سَلَمَةَ بْنِ نُفَيْلٍ الْكِنْدِيِّ قَالَكُنْتُ جَالِسًا عِنْدَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَذَالَ النَّاسُ الْخَيْلَ وَوَضَعُوا السِّلَاحَ وَقَالُوا لَا جِهَادَ قَدْ وَضَعَتْ الْحَرْبُ أَوْزَارَهَا فَأَقْبَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِوَجْهِهِ وَقَالَ كَذَبُوا الْآنَ الْآنَ جَاءَ الْقِتَالُ وَلَا يَزَالُ مِنْ أُمَّتِي أُمَّةٌ يُقَاتِلُونَ عَلَى الْحَقِّ وَيُزِيغُ اللَّهُ لَهُمْ قُلُوبَ أَقْوَامٍ وَيَرْزُقُهُمْ مِنْهُمْ حَتَّى تَقُومَ السَّاعَةُ وَحَتَّى يَأْتِيَ وَعْدُ اللَّهِ وَالْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ وَهُوَ يُوحَى إِلَيَّ أَنِّي مَقْبُوضٌ غَيْرَ مُلَبَّثٍ وَأَنْتُمْ تَتَّبِعُونِي أَفْنَادًا يَضْرِبُ بَعْضُكُمْ رِقَابَ بَعْضٍ وَعُقْرُ دَارِ الْمُؤْمِنِينَ الشَّامُ","id":"Telah mengabarkan kepada kami [Ahmad bin Abdulwahid] berkata; telah menceritakan kepada kami [Marwan] -yaitu Ibnu Muhammad- berkata; telah menceritakan kepada kami [Khalid bin Yazid bin Shalih bin Shabih Al Murri] berkata; telah menceritakan kepada kami [Ibrahim bin Abu 'Ablah] dari [Al Walid bin 'Abdurrahman Al Jurasyi] dari [Jubair bin Nufair] dari [Salamah bin Nufail Al Kindi] berkata, \"Aku pernah duduk di samping Rasulullah shallallahu 'alaihi wasallam, lalu seseorang berkata, \"Wahai Rasulullah, orang-orang telah turun dari kuda mereka, mereka meletakkan senjata mereka dan berkata bahwa tidak ada jihad lagi dan perang telah usai.\" Rasulullah shallallahu 'alaihi wasallam lalu menghadapkan wajahnya seraya bersabda: \"Mereka dusta! saat inilah, saat inilah perang telah datang, akan senantiasa ada dari umatku orang-orang yang berperang di atas kebenaran dan Allah akan menjadikan hati orang-orang condong kepada mereka, Allah akan memberi mereka rizqi dari mereka hingga datang Hari Kiamat, dan hingga datang janji Allah. Dan pada setiap ubun-ubun kuda telah tertulis kebaikan sampai Hari Kiamat, diwahyukan kepadaku bahwa aku akan mati tanpa menunggu-nunggu sedangkan kalian akan mengikutiku secara berpisah-pisah, sebagian kalian menebas leher yang lain, dan tempat asal kaum beriman adalah Syam.\""},"3406":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ يَحْيَى بْنِ الْحَارِثِ قَالَ حَدَّثَنَا مَحْبُوبُ بْنُ مُوسَى قَالَ حَدَّثَنَا أَبُو إِسْحَقَ يَعْنِي الْفَزَارِيَّ عَنْ سُهَيْلِ بْنِ أَبِي صَالِحٍ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْخَيْلُ ثَلَاثَةٌ فَهِيَ لِرَجُلٍ أَجْرٌ وَهِيَ لِرَجُلٍ سَتْرٌ وَهِيَ عَلَى رَجُلٍ وِزْرٌ فَأَمَّا الَّذِي هِيَ لَهُ أَجْرٌ فَالَّذِي يَحْتَبِسُهَا فِي سَبِيلِ اللَّهِ فَيَتَّخِذُهَا لَهُ وَلَا تُغَيِّبُ فِي بُطُونِهَا شَيْئًا إِلَّا كُتِبَ لَهُ بِكُلِّ شَيْءٍ غَيَّبَتْ فِي بُطُونِهَا أَجْرٌ وَلَوْ عَرَضَتْ لَهُ مَرْجٌ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami ['Amru bin Yahya bin Al Harits] berkata; telah menceritakan kepada kami [Mahbub bin Musa] berkata; telah menceritakan kepada kami [Abu Ishaq] -yaitu Al Fazari- dari [Suhail bin Abi Shalih] dari [ayahnya] dari [Abu Hurairah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada setiap ubun-ubun kuda telah tertulis kebaikan hingga hari kiamat. Dan kuda perang ada tiga; ia bisa menjadi pahala bagi seseorang, bisa menjadi tabir bagi seseorang dan bisa menjadi dosa bagi seseorang. Yang menjadikan pahala bagi seseorang adalah, orang yang menahannya di jalan Allah dan menjadikannya untuk Allah dan tidaklah kuda tersebut makan sesuatu dalam perutnya kecuali telah ditetapkan baginya dengan setiap yang dimakan dalam perutnya sebagai pahala, meskipun itu pada rumput yang dilaluinya…..dan seterusnya.\""},"3407":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ زَيْدِ بْنِ أَسْلَمَ عَنْ أَبِي صَالِحٍ السَّمَّانِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْلُ لِرَجُلٍ أَجْرٌ وَلِرَجُلٍ سَتْرٌ وَعَلَى رَجُلٍ وِزْرٌ فَأَمَّا الَّذِي هِيَ لَهُ أَجْرٌ فَرَجُلٌ رَبَطَهَا فِي سَبِيلِ اللَّهِ فَأَطَالَ لَهَا فِي مَرْجٍ أَوْ رَوْضَةٍ فَمَا أَصَابَتْ فِي طِيَلِهَا ذَلِكَ فِي الْمَرْجِ أَوْ الرَّوْضَةِ كَانَ لَهُ حَسَنَاتٌ وَلَوْ أَنَّهَا قَطَعَتْ طِيَلَهَا ذَلِكَ فَاسْتَنَّتْ شَرَفًا أَوْ شَرَفَيْنِ كَانَتْ آثَارُهَا وَفِي حَدِيثِ الْحَارِثِ وَأَرْوَاثُهَا حَسَنَاتٍ لَهُ وَلَوْ أَنَّهَا مَرَّتْ بِنَهَرٍ فَشَرِبَتْ مِنْهُ وَلَمْ يُرِدْ أَنْ تُسْقَى كَانَ ذَلِكَ حَسَنَاتٍ فَهِيَ لَهُ أَجْرٌ وَرَجُلٌ رَبَطَهَا تَغَنِّيًا وَتَعَفُّفًا وَلَمْ يَنْسَ حَقَّ اللَّهِ عَزَّ وَجَلَّ فِي رِقَابِهَا وَلَا ظُهُورِهَا فَهِيَ لِذَلِكَ سَتْرٌ وَرَجُلٌ رَبَطَهَا فَخْرًا وَرِيَاءً وَنِوَاءً لِأَهْلِ الْإِسْلَامِ فَهِيَ عَلَى ذَلِكَ وِزْرٌ وَسُئِلَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ الْحَمِيرِ فَقَالَ لَمْ يَنْزِلْ عَلَيَّ فِيهَا شَيْءٌ إِلَّا هَذِهِ الْآيَةُ الْجَامِعَةُ الْفَاذَّةُ{ فَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ وَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ }","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan aku mendengar, lafazhnya adalah lafazh Al Harits bin Miskin, dari [Ibnu Al Qasim] berkata; telah menceritakan kepadaku [Malik] dari [Zaid bin Aslam] dari [Abu Shalih As Samman] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kuda perang bagi seseorang sebagai pahala, bagi seseorang sebagai tabir dan atas seseorang sebagai dosa. Adapun yang menjadi pahala bagi seseorang yaitu seseorang mengikatnya di jalan Allah kemudian ia membiarkannya lama di tempat penggembalaan atau dalam sebuah kebun. Maka apa yang ia makan sepanjang berada di tempat menambat dan di kebun tersebut maka baginya beberapa kebaikan, dan jika kuda tersebut berhenti kemudian berjalan melalui satu atau dua tempat tinggi maka jejak-jejaknya -sedangkan dalam hadits Al Harits; disebutkan 'dan kotoran-kotorannya'- menjadi kebaikan baginya. Apabila ia melewati sungai kemudian minum darinya, meskipun ia tidak menginginkan kudanya minum, maka hal tersebut menjadi beberapa kebaikan baginya, maka kuda tersebut adalah pahala baginya. Dan seseorang yang mengikatnya agar ia tercukupi dan tidak menjadi meminta-minta, ia tidak melupakan hak Allah dan dalam pundak kuda dan punggungnya, maka kuda itu adalah sebagai tabir baginya. Dan seseorang yang mengikatnya untuk berbangga dan pamer kepada orang Islam, maka kuda itu akan menjadi dosa baginya.\" Nabi shallallahu 'alaihi wasallam juga ditanya mengenai keledai. Beliau lalu bersabda: \"Tidak ada sesuatupun yang turun kepadaku mengenai hal tersebut kecuali ayat yang sempurna ini: '(Barangsiapa yang mengerjakan kebaikan seberat dzarrahpun, niscaya dia akan melihat (balasan) nya) ' (Qs. Al Zalzalah: 7-8)."},"3408":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ حَفْصٍ قَالَ حَدَّثَنِي أَبِي قَالَ حَدَّثَنِي إِبْرَاهِيمُ بْنُ طَهْمَانَ عَنْ سَعِيدِ بْنِ أَبِي عَرُوبَةَ عَنْ قَتَادَةَ عَنْ أَنَسٍ قَالَلَمْ يَكُنْ شَيْءٌ أَحَبَّ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَعْدَ النِّسَاءِ مِنْ الْخَيْلِ","id":"Telah mengabarkan kepada kami [Ahmad bin Hafsh] berkata; telah menceritakan kepadaku [ayahku] berkata; telah menceritakan kepadaku [Ibrahim bin Thahman] dari [Sa'id bin Abu 'Urwah] dari [Qatadah] dari [Anas] ia berkata, \"Tidak ada sesuatu yang lebih dicintai Rasulullah shallallahu 'alaihi wasallam setelah isteri kecuali kuda perang.\""},"3409":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا أَبُو أَحْمَدَ الْبَزَّازُ هِشَامُ بْنُ سَعِيدٍ الطَّالَقَانِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ مُهَاجِرٍ الْأَنْصَارِيُّ عَنْ عَقِيلِ بْنِ شَبِيبٍ عَنْ أَبِي وَهْبٍ وَكَانَتْ لَهُ صُحْبَةٌ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ تَسَمَّوْا بِأَسْمَاءِ الْأَنْبِيَاءِ وَأَحَبُّ الْأَسْمَاءِ إِلَى اللَّهِ عَزَّ وَجَلَّ عَبْدُ اللَّهِ وَعَبْدُ الرَّحْمَنِ وَارْتَبِطُوا الْخَيْلَ وَامْسَحُوا بِنَوَاصِيهَا وَأَكْفَالِهَا وَقَلِّدُوهَا وَلَا تُقَلِّدُوهَا الْأَوْتَارَ وَعَلَيْكُمْ بِكُلِّ كُمَيْتٍ أَغَرَّ مُحَجَّلٍ أَوْ أَشْقَرَ أَغَرَّ مُحَجَّلٍ أَوْ أَدْهَمَ أَغَرَّ مُحَجَّلٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] berkata; telah menceritakan kepada kami [Abu Ahmad Al Bazzar Hisyam bin Sa'id Ath Thalaqani] berkata; telah menceritakan kepada kami [Muhammad bin Muhajir Al Anshari] dari ['Aqil bin Syabib] dari [Abu Wahb] dan ia pernah menyertai Rasulullah shallallahu 'alaihi wasallam, ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Namailah diri kalian dengan nama para nabi, dan nama yang paling disukai Allah 'azza wajalla adalah Abdullah dan 'Abdurrahman. Ikatlah kuda perang dan usaplah ubun-ubunnya dan pahanya, siapkanlah ia dan gunakanlah untuk kebaikan. Dan hendaknya kalian memiliki kuda hitam kemerah-merahan yang dahinya berwarna putih, atau yang berwarna blonde dahi dan kakinya berwarna putih, atau kuda hitam yang dahi dan kakinya berwarna putih.\""},"3410":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ حَدَّثَنَا شُعْبَةُ ح وَأَنْبَأَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ يَزِيدَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَكْرَهُ الشِّكَالَ مِنْ الْخَيْلِوَاللَّفْظُ لِإِسْمَعِيلَ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah menceritakan kepada kami [Muhammad bin Ja'far] berkata; telah menceritakan kepada kami [Syu'bah]. (dalam jalur lain disebutkan) Telah memberitakan kepada kami [Isma'il bin Mas'ud] berkata; telah menceritakan kepada kami [Bisyr] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abdullah bin Yazid] dari [Abu Zur'ah] dari [Abu Hurairah] berkata, \"Nabi shallallahu 'alaihi wasallam tidak menyukai kuda yang ketiga kakinya berwarna putih.\" Dan ini adalah lafadz Isma'il."},"3411":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي سَلْمُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَنَّهُ كَرِهَ الشِّكَالَ مِنْ الْخَيْلِقَالَ أَبُو عَبْد الرَّحْمَنِ الشِّكَالُ مِنْ الْخَيْلِ أَنْ تَكُونَ ثَلَاثُ قَوَائِمَ مُحَجَّلَةً وَوَاحِدَةٌ مُطْلَقَةً أَوْ تَكُونَ الثَّلَاثَةُ مُطْلَقَةً وَرِجْلٌ مُحَجَّلَةً وَلَيْسَ يَكُونُ الشِّكَالُ إِلَّا فِي رِجْلٍ وَلَا يَكُونُ فِي الْيَدِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Yahya] ia berkata; telah menceritakan kepada kami [Sufyan] berkata; telah menceritakan kepadaku [Salm bin 'Abdurrahman] dari [Abu Zur'ah] dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, bahwa beliau tidak menyukai kuda yang salah satu kakinya berwarna putih.\" 'Abdurrahman berkata, \"Syikal adalah kuda yang ketiga kakinya berwarna putih dan yang satunya hitam, atau ketiga kakinya hitam dan satu kakinya berwarna putih. Dan syikal tidak ada kecuali pada kaki, bukan pada tangan.\""},"3412":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ وَمُحَمَّدُ بْنُ مَنْصُورٍ وَاللَّفْظُ لَهُ قَالَا حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ سَالِمٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشُّؤْمُ فِي ثَلَاثَةٍ الْمَرْأَةِ وَالْفَرَسِ وَالدَّارِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] dan [Muhammad bin Manshur] dan ini adalah lafadz Muhammad bin Manshur, berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari [Salim] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Kesialan ada dalam tiga hal: wanita, kuda, dan rumah.\""},"3413":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مَعْنٌ قَالَ حَدَّثَنَا مَالِكٌ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ وَاللَّفْظُ لَهُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ حَمْزَةَ وَسَالِمٍ ابْنَيْ عَبْدِ اللَّهِ بْنِ عُمَرَ عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَ رَضِيَ اللَّهُ عَنْهُمَاأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الشُّؤْمُ فِي الدَّارِ وَالْمَرْأَةِ وَالْفَرَسِ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah] berkata; telah menceritakan kepada kami [Ma'n] berkata; telah menceritakan kepada kami [Malik] dan [Al Harits bin Miskin] dengan membacakan riwayat dan aku mendengar, lafazhnya adalah lafazh Al Harits bin Miskin, dari [Al Qasim] berkata; telah menceritakan kepada kami [Malik] dari [Ibnu Syihab] dari [Hamzah] dan [Salim] keduanya adalah anak Abdullah bin Umar, dari [Abdullah bin Umar] radliallahu 'anhuma, bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Kesialan ada dalam rumah, wanita dan kuda.\""},"3414":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ الْأَعْلَى قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ عَنْ أَبِي الزُّبَيْرِ عَنْ جَابِرٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِنْ يَكُ فِي شَيْءٍ فَفِي الرَّبْعَةِ وَالْمَرْأَةِ وَالْفَرَسِ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdul A'la] berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Ibnu Juraij] dari [Abu Az Zubair] dari [Jabir], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila kesialan ada dalam sesuatu maka ada dalam rumah, wanita dan kuda.\""},"3415":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا النَّضْرُ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي التَّيَّاحِ قَالَ سَمِعْتُ أَنَسًا ح وَأَنْبَأَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنِي أَبُو التَّيَّاحِ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْبَرَكَةُ فِي نَوَاصِي الْخَيْلِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah memberitakan kepada kami [An Nadlr] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu At Tayyah] berkata; aku mendengar [Anas]. (dalam jalur lain disebutkan) Telah menceritakan dan memberitakan kepada kami [Muhammad bin Basysysar] berkata; telah menceritakan kepada kami [Yahya] berkata; telah menceritakan kepada kami [Syu'bah] berkata; telah menceritakan kepadaku [Abu At Tayyah] dari [Anas bin Malik] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda itu telah tertulis keberkahan.\""},"3416":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ قَالَ حَدَّثَنَا يُونُسُ عَنْ عَمْرِو بْنِ سَعِيدٍ عَنْ أَبِي زُرْعَةَ بْنِ عَمْرِو بْنِ جَرِيرٍ عَنْ جَرِيرٍ قَالَرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَفْتِلُ نَاصِيَةَ فَرَسٍ بَيْنَ أُصْبُعَيْهِ وَيَقُولُ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْغَنِيمَةُ","id":"Telah mengabarkan kepada kami [Imran bin Musa] berkata; telah menceritakan kepada kami [Abdul Warits] berkata; telah menceritakan kepada kami [Yunus] dari ['Amru bin Sa'id] dari [Abu Zur'ah bin 'Amru bin Jarir] dari [Jarir] berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam menganyam rambut jambul kuda di antara kedua jarinya, dan beliau bersabda: \"Pada ubun-ubun kuda telah tertulis kebaikan hingga Hari Kiamat; yaitu pahala dan rampasan perang.\""},"3417":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْلُ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Al Laits] dari [Nafi'] dari [Ibnu Umar] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Pada ubun-ubun kuda telah tertulis padanya kebaikan hingga Hari Kiamat.\""},"3418":{"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ الْعَلَاءِ أَبُو كُرَيْبٍ قَالَ حَدَّثَنَا ابْنُ إِدْرِيسَ عَنْ حُصَيْنٍ عَنْ عَامِرٍ عَنْ عُرْوَةَ الْبَارِقِيِّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ","id":"Telah mengabarkan kepada kami [Muhammad bin Al 'Ala Abu Kuraib] berkata; telah menceritakan kepada kami [Ibnu Idris] dari [Hushain] dari ['Amir] dari ['Urwah Al Bariqi] Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda telah tertulis padanya kebaikan hingga Hari Kiamat.\""},"3419":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى وَمُحَمَّدُ بْنُ بَشَّارٍ قَالَا حَدَّثَنَا ابْنُ أَبِي عَدِيٍّ عَنْ شُعْبَةَ عَنْ حُصَيْنٍ عَنْ الشَّعْبِيِّ عَنْ عُرْوَةَ بْنِ أَبِي الْجَعْدِأَنَّهُ سَمِعَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْمَغْنَمُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dan [Muhammad bin Basysyar] mereka berdua berkata; telah menceritakan kepada kami [Ibnu Abu 'Adi] dari [Syu'bah] dari [Hushain] dari [Asy Sya'bi] dari ['Urwah bin Abu Al Ja'd] bahwa ia telah mendengar Nabi shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda perang telah tertulis kebaikan hingga Hari Kiamat; yaitu pahala dan rampasan perang.\""},"3420":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ أَنْبَأَنَا مُحَمَّدُ بْنُ جَعْفَرٍ قَالَ أَنْبَأَنَا شُعْبَةُ عَنْ عَبْدِ اللَّهِ بْنِ أَبِي السَّفَرِ عَنْ الشَّعْبِيِّ عَنْ عُرْوَةَ قَالَسَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْمَغْنَمُ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah memberitakan kepada kami [Muhammad bin Ja'far] berkata; telah memberitakan kepada kami [Syu'bah] dari [Abdullah bin Abu As Safar] dari [Asy Sya'bi] dari ['Urwah] berkata, \"Aku mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: \"Pada ubun-ubun kuda perang telah tertulis kebaikan hingga Hari Kiamat; yaitu pahala dan rampasan perang.\""},"3421":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ أَنْبَأَنَا شُعْبَةُ قَالَ أَخْبَرَنِي حُصَيْنٌ وَعَبْدُ اللَّهِ بْنُ أَبِي السَّفَرِ أَنَّهُمَا سَمِعَا الشَّعْبِيَّ يُحَدِّثُ عَنْ عُرْوَةَ بْنِ أَبِي الْجَعْدِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الْخَيْلُ مَعْقُودٌ فِي نَوَاصِيهَا الْخَيْرُ إِلَى يَوْمِ الْقِيَامَةِ الْأَجْرُ وَالْمَغْنَمُ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami ['Abdurrahman] berkata; telah memberitakan kepada kami [Syu'bah] ia berkata; telah mengabarkan kepadaku [Hushain] dan [Abdullah bin Abu As Safar] bahwa keduanya mendengar [Asy Sya'bi] menceritakan dari ['Urwah bin Abu Al Ja'd] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Pada ubun-ubun kuda perang telah tertulis kebaikan hingga Hari Kiamat; yaitu pahala dan rampasan perang.\""},"3422":{"ar":"أَخْبَرَنَا الْحَسَنُ بْنُ إِسْمَعِيلَ بْنِ مُجَالِدٍ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ عَنْ عَبْدِ الرَّحْمَنِ بْنِ يَزِيدَ بْنِ جَابِرٍ قَالَ حَدَّثَنِي أَبُو سَلَّامٍ الدِّمَشْقِيُّ عَنْ خَالِدِ بْنِ يَزِيدَ الْجُهَنِيِّ قَالَكَانَ عُقْبَةُ بْنُ عَامِرٍ يَمُرُّ بِي فَيَقُولُ يَا خَالِدُ اخْرُجْ بِنَا نَرْمِي فَلَمَّا كَانَ ذَاتَ يَوْمٍ أَبْطَأْتُ عَنْهُ فَقَالَ يَا خَالِدُ تَعَالَ أُخْبِرْكَ بِمَا قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَتَيْتُهُ فَقَالَ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ يُدْخِلُ بِالسَّهْمِ الْوَاحِدِ ثَلَاثَةَ نَفَرٍ الْجَنَّةَ صَانِعَهُ يَحْتَسِبُ فِي صُنْعِهِ الْخَيْرَ وَالرَّامِيَ بِهِ وَمُنَبِّلَهُ وَارْمُوا وَارْكَبُوا وَأَنْ تَرْمُوا أَحَبُّ إِلَيَّ مِنْ أَنْ تَرْكَبُوا وَلَيْسَ اللَّهْوُ إِلَّا فِي ثَلَاثَةٍ تَأْدِيبِ الرَّجُلِ فَرَسَهُ وَمُلَاعَبَتِهِ امْرَأَتَهُ وَرَمْيِهِ بِقَوْسِهِ وَنَبْلِهِ وَمَنْ تَرَكَ الرَّمْيَ بَعْدَ مَا عَلِمَهُ رَغْبَةً عَنْهُ فَإِنَّهَا نِعْمَةٌ كَفَرَهَا أَوْ قَالَ كَفَرَ بِهَا","id":"Telah mengabarkan kepada kami [Al Hasan bin Isma'il bin Mujalid] berkata; telah menceritakan kepada kami [Isa bin Yunus] dari ['Abdurrahman bin Yazid bin Jabir] berkata; telah menceritakan kepadaku [Abu Salam Ad Dimasyqi] dari [Khalid bin Yazid Al Juhani] berkata; ['Uqbah bin 'Amir] melewatiku dan berkata, \"Wahai Khalid, keluarlah bersama kami untuk melempar.\" Kemudian pada suatu hari aku memperlambat jalan darinya, kemudian ia berkata, \"Wahai Khalid, kemarilah. Aku kabarkan kepadamu apa yang telah disabdakan Rasulullah shallallahu 'alaihi wasallam.\" Kemudian aku datang kepadanya dan ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, dengan satu anak panah Allah memasukkan tiga orang ke dalam Surga; yaitu pembuatnya yang dalam membuatnya mengharapkan kebaikan, orang yang memanah dan orang yang mengambilkan anak panah. Panah dan berkudalah, dan kalian memanah lebih aku sukai daripada kalian berkuda. Tidak ada hiburan kecuali dalam tiga hal; seorang laki-laki yang melatih kudanya, candaan seorang terhadap isterinya, dan lemparan anak panahnya. Dan barangsiapa yang tidak melempar setelah ia mengetahui ilmunya karena tidak menyenanginya, maka sesungguhnya hal itu adalah kenikmatan yang ia kufuri.\""},"3423":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ أَنْبَأَنَا يَحْيَى قَالَ حَدَّثَنَا عَبْدُ الْحَمِيدِ بْنُ جَعْفَرٍ قَالَ حَدَّثَنِي يَزِيدُ بْنُ أَبِي حَبِيبٍ عَنْ سُوَيْدِ بْنِ قَيْسٍ عَنْ مُعَاوِيَةَ بْنِ حُدَيْجٍ عَنْ أَبِي ذَرٍّ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا مِنْ فَرَسٍ عَرَبِيٍّ إِلَّا يُؤْذَنُ لَهُ عِنْدَ كُلِّ سَحَرٍ بِدَعْوَتَيْنِ اللَّهُمَّ خَوَّلْتَنِي مَنْ خَوَّلْتَنِي مِنْ بَنِي آدَمَ وَجَعَلْتَنِي لَهُ فَاجْعَلْنِي أَحَبَّ أَهْلِهِ وَمَالِهِ إِلَيْهِ أَوْ مِنْ أَحَبِّ مَالِهِ وَأَهْلِهِ إِلَيْهِ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah memberitakan kepada kami [Yahya] berkata; telah menceritakan kepada kami [Abdul Hamid bin Ja'far] berkata; telah menceritakan kepadaku [Yazid bin Abu Habib] dari [Suwaid bin Qais] dari [Mu'awiyah bin Hudaij] dari [Abu Dzar] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidaklah seekor kuda arab itu melainkan ia diijinkan setiap waktu sahur dengan dua doa, yaitu \"Ya Allah, Engkau menjadikan pemilikku dari anak Adam dan engkau jadikan aku miliknya, maka jadikanlah aku sebagai keluarga dan harta yang paling dicintainya di antara harta dan keluarga yang paling dicintainya.\""},"3424":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا اللَّيْثُ عَنْ يَزِيدَ بْنِ أَبِي حَبِيبٍ عَنْ أَبِي الْخَيْرِ عَنْ ابْنِ زُرَيْرٍ عَنْ عَلِيِّ بْنِ أَبِي طَالِبٍ رَضِيَ اللَّهُ عَنْهُ قَالَأُهْدِيَتْ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بَغْلَةٌ فَرَكِبَهَا فَقَالَ عَلِيٌّ لَوْ حَمَلْنَا الْحَمِيرَ عَلَى الْخَيْلِ لَكَانَتْ لَنَا مِثْلُ هَذِهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّمَا يَفْعَلُ ذَلِكَ الَّذِينَ لَا يَعْلَمُونَ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Al Laits] dari [Yazid bin Abu Habib] dari [Abu Al Khair] dari [Ibnu Zurair] dari [Ali bin Abu Thalib] radliallahu 'anhu berkata, \"Rasulullah shallallahu 'alaihi wasallam diberi hadiah seekor bighal, kemudian beliau menaikinya. Kemudian Ali berkata, \"Seandainya kita kawinkan keledai dengan kuda niscaya kita memiliki yang seperti ini. Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya yang melakukan hal itu adalah orang-orang yang tidak mengetahui.\""},"3425":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا حَمَّادٌ عَنْ أَبِي جَهْضَمٍ عَنْ عَبْدِ اللَّهِ بْنِ عُبَيْدِ اللَّهِ بْنِ عَبَّاسٍ قَالَكُنْتُ عِنْدَ ابْنِ عَبَّاسٍ فَسَأَلَهُ رَجُلٌ أَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّه�� عَلَيْهِ وَسَلَّمَ يَقْرَأُ فِي الظُّهْرِ وَالْعَصْرِ قَالَ لَا قَالَ فَلَعَلَّهُ كَانَ يَقْرَأُ فِي نَفْسِهِ قَالَ خَمْشًا هَذِهِ شَرٌّ مِنْ الْأُولَى إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَبْدٌ أَمَرَهُ اللَّهُ تَعَالَى بِأَمْرِهِ فَبَلَّغَهُ وَاللَّهِ مَا اخْتَصَّنَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِشَيْءٍ دُونَ النَّاسِ إِلَّا بِثَلَاثَةٍ أَمَرَنَا أَنْ نُسْبِغَ الْوُضُوءَ وَأَنْ لَا نَأْكُلَ الصَّدَقَةَ وَلَا نُنْزِيَ الْحُمُرَ عَلَى الْخَيْلِ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] berkata; telah menceritakan kepada kami [Hammad] dari [Abu Jahdlam] dari [Abdullah bin 'Ubaidullah bin Abbas] berkata, \"Aku pernah bersama [Ibnu Abbas], lalu ada seorang laki-laki bertanya kepadanya, 'Apakah Rasulullah shallallahu 'alaihi wasallam membaca dalam Shalat zhuhur dan ashar? Ibnu Abbas menjawab, \"Tidak.\" Orang itu lalu berkata, \"Kemungkinan beliau membaca dalam hati.\" Ibnu Abbas berkata, \"Semoga wajahmu tercakar, ini lebih buruk daripada yang pertama. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam adalah seorang hamba, Allah telah memerintahkan kepadanya dengan perintah-Nya, kemudian beliau menyampaikan perintah tersebut. Demi Allah, Rasulullah shallallahu 'alaihi wasallam tidak pernah mengkhususkan kami dengan sesuatu dari orang lain, kecuali dalam tiga hal; beliau memerintahkan kami agar menyempurnakan wudlu, tidak makan sedekah dan tidak mengawinkan keledai dengan kuda.\""},"3426":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ حَدَّثَنِي طَلْحَةُ بْنُ أَبِي سَعِيدٍ أَنَّ سَعِيدًا الْمَقْبُرِيَّ حَدَّثَهُ عَنْ أَبِي هُرَيْرَةَعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ احْتَبَسَ فَرَسًا فِي سَبِيلِ اللَّهِ إِيمَانًا بِاللَّهِ وَتَصْدِيقًا لِوَعْدِ اللَّهِ كَانَ شِبَعُهُ وَرِيُّهُ وَبَوْلُهُ وَرَوْثُهُ حَسَنَاتٍ فِي مِيزَانِهِ","id":"Telah mengabarkan kepada kami [Al Harits bin Miskin] dengan membacakan riwayat dan aku mendengar, dari [Ibnu Wahb] telah menceritakan kepadaku [Thalhah bin Abu Sa'id] bahwa [Sa'id Al Maqburi] telah menceritakan kepadanya dari [Abu Hurairah] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Barangsiapa menahan kuda di jalan Allah karena keimanan kepada Allah dan membenarkan janji Allah maka kenyangnya, kepuasan minumnya, kencingnya, dan kotorannya menjadi kebaikan dalam timbangannya.\""},"3427":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَابَقَ بَيْنَ الْخَيْلِ يُرْسِلُهَا مِنْ الْحَفْيَاءِ وَكَانَ أَمَدُهَا ثَنِيَّةَ الْوَدَاعِ وَسَابَقَ بَيْنَ الْخَيْلِ الَّتِي لَمْ تُضْمَرْ وَكَانَ أَمَدُهَا مِنْ الثَّنِيَّةِ إِلَى مَسْجِدِ بَنِي زُرَيْقٍ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] berkata; telah menceritakan kepada kami [Khalid] dari [Ibnu Abu Dzi`b] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam mengadakan lomba antara kuda perang, beliau melepasnya dari Al Hafya` dan berakhir di Tsaniyah Al Wada'. Sementara kuda yang belum dipersiapkan untuk lomba dari Ats Tsaniyah hingga Masjid Bani Zuraiq.\""},"3428":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ وَالْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ قَالَ حَدَّثَنِي مَالِكٌ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ سَابَقَ بَيْنَ الْخَيْلِ الَّتِي قَدْ أُضْمِرَتْ مِنْ الْحَفْيَاءِ وَكَانَ أَمَدُهَا ثَنِيَّةَ الْوَدَاعِ وَسَابَقَ بَيْنَ الْخَيْلِ الَّتِي لَمْ تُضْمَرْ مِنْ الثَّنِيَّةِ إِلَى مَسْجِدِ بَنِي زُرَيْقٍ وَأَنَّ عَبْدَ اللَّهِ كَانَ مِمَّنْ سَابَقَ بِهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] dan [Al Harits bin Miskin] dengan membacakan riwayat dan aku mendengar, dari [Ibnu Al Qasim] berkata; telah menceritakan kepadaku [Malik] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam melombakan antara kuda yang sudah dipersiapkan untuk lomba dari Al Hafya` dan berakhir hingga Tsaniyah Al Wada`, dan melombakan antara kuda yang belum dipersiapkan untuk lomba dari Ats Tsaniyah hingga masjid Bani Zura'iq, dan Abdullah adalah termasuk di antara orang yang berlomba.\""},"3429":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ نَافِعِ بْنِ أَبِي نَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا سَبَقَ إِلَّا فِي نَصْلٍ أَوْ حَافِرٍ أَوْ خُفٍّ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] berkata; telah menceritakan kepada kami [Khalid] dari [Ibnu Abu Dzi`b] dari [Nafi' bin Abu Nafi'] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada sabaq (hadiah dalam perlombaan) kecuali dalam lomba memanah, kuda dan unta.\""},"3430":{"ar":"أَخْبَرَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ أَبُو عُبَيْدِ اللَّهِ الْمَخْزُومِيُّ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ ابْنِ أَبِي ذِئْبٍ عَنْ نَافِعِ بْنِ أَبِي نَافِعٍ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا سَبَقَ إِلَّا فِي نَصْلٍ أَوْ خُفٍّ أَوْ حَافِرٍ","id":"Telah mengabarkan kepada kami [Sa'id bin 'Abdurrahman Abu 'Ubaidullah Al Makhzumi] berkata; telah menceritakan kepada kami [Sufyan] dari [Ibnu Abu Dzi`b] dari [Nafi' bin Abu Nafi'] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada sabaq (hadiah dalam perlombaan) kecuali dalam lomba memanah, unta atau kuda.\""},"3431":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يَعْقُوبَ قَالَ حَدَّثَنَا ابْنُ أَبِي مَرْيَمَ قَالَ أَنْبَأَنَا اللَّيْثُ عَنْ ابْنِ أَبِي جَعْفَرٍ عَنْ مُحَمَّدِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ سُلَيْمَانَ بْنِ يَسَارٍ عَنْ أَبِي عَبْدِ اللَّهِ مَوْلَى الْجُنْدَعِيِّينَ عَنْ أَبِي هُرَيْرَةَ رَضِيَ اللَّهُ عَنْهُ قَالَلَا يَحِلُّ سَبَقٌ إِلَّا عَلَى خُفٍّ أَوْ حَافِرٍ","id":"Telah mengabarkan kepada kami [Ibrahim bin Ya'qub] berkata; telah menceritakan kepada kami [Ibnu Abu Maryam] berkata; telah memberitakan kepada kami [Al Laits] dari [Ibnu Abu Ja'far] dari [Muhammad bin 'Abdurrahman] dari [Sulaiman bin Yasar] dari [Abu Abdullah] mantan budak orang-orang Al Junda', dari [Abu Hurairah] radliallahu 'anhu, ia berkata, \"Sabaq (hadiah dalam perlombaan) tidak halal kecuali pada lomba panahan, unta dan kuda.\""},"3432":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ خَالِدٍ قَالَ حَدَّثَنَا حُمَيْدٌ عَنْ أَنَسٍ قَالَكَانَتْ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَاقَةٌ تُسَمَّى الْعَضْبَاءَ لَا تُسْبَقُ فَجَاءَ أَعْرَابِيٌّ عَلَى قَعُودٍ فَسَبَقَهَا فَشَقَّ عَلَى الْمُسْلِمِينَ فَلَمَّا رَأَى مَا فِي وُجُوهِهِمْ قَالُوا يَا رَسُولَ اللَّهِ سُبِقَتْ الْعَضْبَاءُ قَالَ إِنَّ حَقًّا عَلَى اللَّهِ أَنْ لَا يَرْتَفِعَ مِنْ الدُّنْيَا شَيْءٌ إِلَّا وَضَعَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Khalid] berkata; telah menceritakan kepada kami [Humaid] dari [Anas] berkata, \"Dahulu Rasulullah shallallahu 'alaihi wasallam memiliki seekor unta yang dinamakan Al 'Adlba` yang tidak terkalahkan dalam perlombaan. Kemudian datanglah seorang badui di atas unta yang ditunggangi. Badui itu kemudian mendahului Al 'Adlba`, sehingga hal tersebut membuat orang-orang Muslim serasa sesak. Kemudian ketika sebagian sahabat melihat raut muka sebagian yang lain ada tanda kekecewaan, maka berkatalah sebagian yang lain, \"Wahai Rasulullah, Al 'Adlba` didahului!\" Maka beliau bersabda: \"Sungguh, telah menjadi ketetapan Allah atas apa yang ada di dunia ini, bahwa tidaklah angkat kecuali Dia akan merendahkannya kembali.\""},"3433":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ مُوسَى قَالَ حَدَّثَنَا عَبْدُ الْوَارِثِ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي الْحَكَمِ مَوْلًى لِبَنِي لَيْثٍ عَنْ أَبِي هُرَيْرَةَعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا سَبَقَ إِلَّا فِي خُفٍّ أَوْ حَافِرٍ","id":"Telah mengabarkan kepada kami [Imran bin Musa] berkata; telah menceritakan kepada kami [Abdul Warits] dari [Muhammad bin 'Amru] dari [Abu Al Hakam] mantan budak Bani Laits, dari [Abu Hurairah] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada sabaq (hadiah dalam perlombaan) kecuali pada balap kuda atau unta.\""},"3434":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ بْنِ بَزِيعٍ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا حُمَيْدٌ قَالَ حَدَّثَنَا الْحَسَنُ عَنْ عِمْرَانَ بْنِ حُصَيْنٍعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا جَلَبَ وَلَا جَنَبَ وَلَا شِغَارَ فِي الْإِسْلَامِ وَمَنْ انْتَهَبَ نُهْبَةً فَلَيْسَ مِنَّا","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah bin Bazi'] berkata; telah menceritakan kepada kami [Yazid] -yaitu Ibnu Zurai'- berkata; telah menceritakan kepada kami [Humaid] berkata; telah menceritakan kepada kami [Al Hasan] dari ['Imran Ibnu Hushain] dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak ada jalab (seseorang menjadikan orang lain mengikuti kudanya untuk menghardiknya supaya berlari cepat, janab (mengiringkan kuda lain di samping kuda yang digunakan untuk lomba kemudian apabila telah lelah maka ia berpindah kepada kuda yang lain) dan syighar dalam Islam. Dan barangsiapa merampas suatu rampasan maka bukan dari golongan kami.\""},"3435":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ عَنْ أَبِي قَزَعَةَ عَنْ الْحَسَنِ عَنْ عِمْرَانَ بْنِ حُصَيْنٍأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا جَلَبَ وَلَا جَنَبَ وَلَا شِغَارَ فِي الْإِسْلَامِ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Muhammad] berkata; telah menceritakan kepada kami [Syu'bah] dari [Abu Qaza'ah] dari [Al Hasan] dari [Imran bin Hushain], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada jalab (seseorang menjadikan orang lain mengikuti kudanya untuk menghardiknya supaya berlari cepat, janab (mengiringkan kuda lain di samping kuda yang digunakan untuk lomba kemudian apabila telah lelah maka ia berpindah kepada kuda yang lain) dan syighar dalam Islam.\" "},"3436":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدِ بْنِ كَثِيرٍ قَالَ حَدَّثَنَا بَقِيَّةُ بْنُ الْوَلِيدِ قَالَ حَدَّثَنِي شُعْبَةُ قَالَ حَدَّثَنِي حُمَيْدٌ الطَّوِيلُ عَنْ أَنَسِ بْنِ مَالِكٍ قَالَسَابَقَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَعْرَابِيٌّ فَسَبَقَهُ فَكَأَنَّ أَصْحَابَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَجَدُوا فِي أَنْفُسِهِمْ مِنْ ذَلِكَ فَقِيلَ لَهُ فِي ذَلِكَ فَقَالَ حَقٌّ عَلَى اللَّهِ أَنْ لَا يَرْفَعَ شَيْءٌ نَفْسَهُ فِي الدُّنْيَا إِلَّا وَضَعَهُ اللَّهُ","id":"Telah mengabarkan kepada kami ['Amru bin Utsman bin Sa'id bin Katsir] berkata; telah menceritakan kepada kami [Baqiyyah bin Al Walid] berkata; telah menceritakan kepadaku [Syu'bah] berkata; telah menceritakan kepadaku [Humaid Ath Thawil] dari [Anas bin Malik] berkata, \"Seorang badui berlomba dengan Rasulullah shallallahu 'alaihi wasallam dan berhasil mendahului beliau, maka seolah-olah para sahabat Rasulullah shallallahu 'alaihi wasallam tidak menyukai hal tersebut. Kemudian dikatakan kepada beliau mengenai hal tersebut, lalu beliau bersabda: \"\"Sungguh, telah menjadi ketetapan Allah atas apa yang ada di dunia ini, bahwa tidaklah angkat kecuali Dia akan merendahkannya kembali.\""},"3437":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ يَحْيَى بْنِ عَبَّادِ بْنِ عَبْدِ اللَّهِ بْنِ الزُّبَيْرِ عَنْ جَدِّهِ أَنَّهُ كَانَ يَقُولُضَرَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَامَ خَيْبَرَ لِلزُّبَيْرِ بْنِ الْعَوَّامِ أَرْبَعَةَ أَسْهُمٍ سَهْمًا لِلزُّبَيْرِ وَسَهْمًا لِذِي الْقُرْبَى لِصَفِيَّةَ بِنْتِ عَبْدِ الْمُطَّلِبِ أُمِّ الزُّبَيْرِ وَسَهْمَيْنِ لِلْفَرَسِ","id":"Telah mengabarkan kepada kami [Al Harits bin Miskin] dengan membacakan riwayat dan aku mendengar, dari [Ibnu Wahb] berkata; telah mengabarkan kepadaku [Sa'id bin 'Abdurrahman] dari [Hisyam bin 'Urwah] dari [Yahya bin 'Abbad bin Abdullah bin Az Zubair] dari [kakeknya] bahwa ia berkata, \"Rasulullah shallallahu 'alaihi wasallam memberikan kepada Az Zubair bin Al Awwam empat bagian; satu bagian untuk Zubair, satu bagian untuk kerabat Shafiyah binti Abdul Muthallib, ibu Az Zubair dan dua bagian untuk kuda perang.\""},"3438":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو الْأَحْوَصِ عَنْ أَبِي إِسْحَقَ عَنْ عَمْرِو بْنِ الْحَارِثِ قَالَمَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِينَارًا وَلَا دِرْهَمًا وَلَا عَبْدًا وَلَا أَمَةً إِلَّا بَغْلَتَهُ الشَّهْبَاءَ الَّتِي كَانَ يَرْكَبُهَا وَسِلَاحَهُ وَأَرْضًا جَعَلَهَا فِي سَبِيلِ اللَّهِ وَقَالَ قُتَيْبَةُ مَرَّةً أُخْرَى صَدَقَةً","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Abu Al Ahwash] dari [Abu Ishaq] dari ['Amru bin Al Harits] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak meninggalkan dinar dan dirham, sahaya laki-laki dan perempuan kecuali bighalnya yang berwarna abu-abu biasa beliau kendarai, senjata dan tanah yang beliau berikan di jalan Allah.\" Dalam kesempatan lain Qutaibah menyebutkan, \"Sebagai sedekah.\""},"3439":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ قَالَ حَدَّثَنِي أَبُو إِسْحَقَ قَالَ سَمِعْتُ عَمْرَو بْنَ الْحَارِثِ يَقُولُمَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِلَّا بَغْلَتَهُ الْبَيْضَاءَ وَسِلَاحَهُ وَأَرْضًا تَرَكَهَا صَدَقَةً","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Yahya bin Sa'id] berkata; telah menceritakan kepada kami [Sufyan] telah menceritakan kepadaku [Abu Ishaq] berkata; aku mendengar ['Amru bin Al Harits] berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak meninggalkan kecuali bighalnya yang putih, senjata dan tanah yang beliau tinggalkan sebagai sedekah.\""},"3440":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا أَبُو بَكْرٍ الْحَنَفِيُّ قَالَ حَدَّثَنَا يُونُسُ بْنُ أَبِي إِسْحَقَ عَنْ أَبِيهِ قَالَ سَمِعْتُ عَمْرَو بْنَ الْحَارِثِ يَقُولُرَأَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا تَرَكَ إِلَّا بَغْلَتَهُ الشَّهْبَاءَ وَسِلَاحَهُ وَأَرْضًا تَرَكَهَا صَدَقَةً","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Abu Bakr Al Hanafi] berkata; telah menceritakan kepada kami [Yunus bin Abu Ishaq] dari [ayahnya] ia berkata; aku mendengar ['Amru bin Al Harits] berkata, \"Aku melihat Rasulullah shallallahu 'alaihi wasallam tidak meninggalkan sesuatu kecuali bighalnya yang berwarna abu-abu, pedang dan tanah yang beliau tinggalkan sebagai sedekah.\""},"3441":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو دَاوُدَ الْحَفَرِيُّ عُمَرُ بْنُ سَعْدٍ عَنْ سُفْيَانَ الثَّوْرِيِّ عَنْ ابْنِ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ قَالَأَصَبْتُ أَرْضًا مِنْ أَرْضِ خَيْبَرَ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ أَصَبْتُ أَرْضًا لَمْ أُصِبْ مَالًا أَحَبَّ إِلَيَّ وَلَا أَنْفَسَ عِنْدِي مِنْهَا قَالَ إِنْ شِئْتَ تَصَدَّقْتَ بِهَا فَتَصَدَّقَ بِهَا عَلَى أَنْ لَا تُبَاعَ وَلَا تُوهَبَ فِي الْفُقَرَاءِ وَذِي الْقُرْبَى وَالرِّقَابِ وَالضَّيْفِ وَابْنِ السَّبِيلِ لَا جُنَاحَ عَلَى مَنْ وَلِيَهَا أَنْ يَأْكُلَ بِالْمَعْرُوفِ غَيْرَ مُتَمَوِّلٍ مَالًا وَيُطْعِمَأَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا مُعَاوِيَةُ بْنُ عَمْرٍو عَنْ أَبِي إِسْحَقَ الْفَزَارِيِّ عَنْ ابْنِ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَحْوَهُ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] ia berkata; telah memberitakan kepada kami [Abu Daud Al Hafari Umar bin Sa'd] dari [Sufyan Atsauri] dari [Ibnu 'Aun] dari [Nafi'] dari [Ibnu Umar] dari [Umar] ia berkata, \"Aku mendapatkan lahan dari lahan Khaibar, kemudian aku mendatangi Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Aku mendapatkan lahan dan tidak ada lahan yang paling aku sukai kecuali lahan tersebut.\" Beliau bersabda: \"Apabila engkau menghendaki maka engkau bisa mensedekahkannya.\" Kemudian ia mensedekahkannya dengan syarat tidak dijual dan tidak dihibahkan untuk orang-orang fakir, kerabat rasul, tamu, dan ibnu sabil. Dan tidak mengapa bagi orang yang mengurusnya untuk memakan dengan cara yang baik tanpa mengembangkan harta dan memberikan makan orang lain.\" Telah mengabarkan kepadaku [Harun bin Abdullah] berkata; telah menceritakan kepada kami [Mu'awiyah bin 'Amru] dari [Abu Ishaq Al Fazari] dari [Ibnu 'Aun] dari [Nafi'] dari [Ibnu Umar] radliallahu 'anhu, dari Nabi shallallahu 'alaihi wasallam seperti itu.\""},"3442":{"ar":"أَخْبَرَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا يَزِيدُ وَهُوَ ابْنُ زُرَيْعٍ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَأَصَابَ عُمَرُ أَرْضًا بِخَيْبَرَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ أَصَبْتُ أَرْضًا لَمْ أُصِبْ مَالًا قَطُّ أَنْفَسَ عِنْدِي فَكَيْفَ تَأْمُرُ بِهِ قَالَ إِنْ شِئْتَ حَبَّسْتَ أَصْلَهَا وَتَصَدَّقْتَ بِهَا فَتَصَدَّقَ بِهَا عَلَى أَنْ لَا تُبَاعَ وَلَا تُوهَبَ وَلَا تُورَثَ فِي الْفُقَرَاءِ وَالْقُرْبَى وَالرِّقَابِ وَفِي سَبِيلِ اللَّهِ وَالضَّيْفِ وَابْنِ السَّبِيلِ لَا جُنَاحَ عَلَى مَنْ وَلِيَهَا أَنْ يَأْكُلَ مِنْهَا بِالْمَعْرُوفِ وَيُطْعِمَ صَدِيقًا غَيْرَ مُتَمَوِّلٍ فِيهِ","id":"Telah mengabarkan kepada kami [Humaid bin Mas'adah] berkata; telah menceritakan kepada kami [Yazid] -yaitu Ibnu Zurai'- berkata; telah menceritakan kepada kami [Ibnu 'Aun] dari [Nafi'] dari [Ibnu Umar] berkata; Umar telah mendapatkan lahan di Khaibar, kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Aku telah mendapatkan lahan yang tidak ada harta sama sekali yang aku dapatkan yang lebih berharga bagi aku daripada lahan tersebut, maka apa yang anda perintahkan? Beliau bersabda: \"Apabila engkau menghendaki maka engkau dapat menahan pokoknya dan bersedekah dengannya.\" Maka ia pun bersedekah dengan syarat tidak dijual, tidak dihibahkan, tidak diwariskan untuk orang-orang fakir, kerabat rasul, hamba sahaya, di jalan Allah, tamu, dan ibnu sabil. Tidak mengapa bagi orang yang mengurusnya untuk makan darinya dengan cara yang baik, memberi makan teman tanpa mengembangkannya.\""},"3443":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا بِشْرٌ عَنْ ابْنِ عَوْنٍ قَالَ وَأَنْبَأَنَا حُمَيْدُ بْنُ مَسْعَدَةَ قَالَ حَدَّثَنَا بِشْرٌ قَالَ حَدَّثَنَا ابْنُ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَأَصَابَ عُمَرُ أَرْضًا بِخَيْبَرَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَأْمَرَهُ فِيهَا فَقَالَ إِنِّي أَصَبْتُ أَرْضًا كَثِيرًا لَمْ أُصِبْ مَالًا قَطُّ أَنْفَسَ عِنْدِي مِنْهُ فَمَا تَأْمُرُ فِيهَا قَالَ إِنْ شِئْتَ حَبَّسْتَ أَصْلَهَا وَتَصَدَّقْتَ بِهَا فَتَصَدَّقَ بِهَا عَلَى أَنَّهُ لَا تُبَاعُ وَلَا تُوهَبُ فَتَصَدَّقَ بِهَا فِي الْفُقَرَاءِ وَالْقُرْبَى وَفِي الرِّقَابِ وَفِي سَبِيلِ اللَّهِ وَابْنِ السَّبِيلِ وَالضَّيْفِ لَا جُنَاحَ يَعْنِي عَلَى مَنْ وَلِيَهَا أَنْ يَأْكُلَ أَوْ يُطْعِمَ صَدِيقًا غَيْرَ مُتَمَوِّلٍاللَّفْظُ لِإِسْمَعِيلَ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] ia berkata; telah menceritakan kepada kami [Bisyr] dari [Ibnu 'Aun]. Dan telah memberitakan kepada kami [Humaid bin Mas'adah] berkata; telah menceritakan kepada kami [Bisyr] berkata; telah menceritakan kepada kami [Ibnu 'Aun] dari [Nafi'] dari [Ibnu Umar] ia berkata, \"Umar mendapatkan lahan di Khaibar kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam dan meminta pendapatnya mengenai lahan tersebut. Ia berkata, \"Sesungguhnya aku telah mendapatkan lahan yang banyak, aku belum pernah mendapatkan harta sama sekali yang lebih berharga bagiku daripada lahan tersebut. Apakah yang anda perintahkan mengenai lahan tersebut? Beliau bersabda: \"Apabila engkau menghendaki maka engkau bisa menahan pokoknya, dan bersedekah dengannya dengan syarat tidak dijual dan tidak dihibahkan.\" Kemudian ia mensedekahkanya untuk orang-orang fakir, kerabat Nabi, hamba sahaya, di jalan Allah, ibnu Sabil, serta tamu. Dan tidak mengapa bagi orang yang mengurusnya untuk makan atau memberi makan teman tanpa mengembangkan.\" Lafazh hadits tersebut adalah lafazh Isma'il."},"3444":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا أَزْهَرُ السَّمَّانُ عَنْ ابْنِ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ عُمَرَ أَصَابَ أَرْضًا بِخَيْبَرَ فَأَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَسْتَأْمِرُهُ فِي ذَلِكَ فَقَالَ إِنْ شِئْتَ حَبَّسْتَ أَصْلَهَا وَتَصَدَّقْتَ بِهَا فَحَبَّسَ أَصْلَهَا أَنْ لَا تُبَاعَ وَلَا تُوهَبَ وَلَا تُورَثَ فَتَصَدَّقَ بِهَا عَلَى الْفُقَرَاءِ وَالْقُرْبَى وَالرِّقَابِ وَفِي الْمَسَاكِينِ وَابْنِ السَّبِيلِ وَالضَّيْفِ لَا جُنَاحَ عَلَى مَنْ وَلِيَهَا أَنْ يَأْكُلَ مِنْهَا بِالْمَعْرُوفِ أَوْ يُطْعِمَ صَدِيقَهُ غَيْرَ مُتَمَوِّلٍ فِيهِ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah menceritakan kepada kami [Azhar As Samman] dari [Ibnu 'Aun] dari [Nafi'] dari [Ibnu Umar], bahwa Umar mendapatkan lahan di Khaibar kemudian ia datang kepada Nabi shallallahu 'alaihi wasallam meminta petunjuk mengenai lahan tersebut. Maka beliau bersabda: \"Apabila engkau menghendaki maka engkau bisa menahan pokoknya dan bersedekah dengannya.\" Kemudian ia menahan pokoknya dengan syarat tidak dijual, dan tidak dihibahkan serta tidak diwariskan. Dan ia bersedekah dengannya kepada orang-orang fakir, kerabat Nabi, para hamba sahaya, orang-orang miskin, ibnu sabil, dan tamu. Dan tidak mengapa bagi orang yang mengurusnya untuk makan sebagian darinya dengan cara yang baik atau memberi makan temannya tanpa mengembangkannya.\""},"3445":{"ar":"أَخْبَرَنَا أَبُو بَكْرِ بْنُ نَافِعٍ قَالَ حَدَّثَنَا بَهْزٌ قَالَ حَدَّثَنَا حَمَّادٌ قَالَ حَدَّثَنَا ثَابِتٌ عَنْ أَنَسٍ قَالَلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ لَنْ تَنَالُوا الْبِرَّ حَتَّى تُنْفِقُوا مِمَّا تُحِبُّونَ }قَالَ أَبُو طَلْحَةَ إِنَّ رَبَّنَا لَيَسْأَلُنَا عَنْ أَمْوَالِنَا فَأُشْهِدُكَ يَا رَسُولَ اللَّهِ أَنِّي قَدْ جَعَلْتُ أَرْضِي لِلَّهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اجْعَلْهَا فِي قَرَابَتِكَ فِي حَسَّانَ بْنِ ثَابِتٍ وَأُبَيِّ بْنِ كَعْبٍ","id":"Telah mengabarkan kepada kami [Abu Bakr bin Nafi'] berkata; telah menceritakan kepada kami [Bahz] berkata; telah menceritakan kepada kami [Hammad] berkata; telah menceritakan kepada kami [Tsabit] dari [Anas] berkata, \"Tatkala turun ayat ini: '(Kamu sekali-kali tidak sampai kepada kebajikan (yang sempurna), sebelum kamu menafkahkan sebagian harta yang kamu cintai) ' (Qs. Ali Imran: 92), maka Abu Thalhah berkata, \"Sungguh, tuhan kita akan bertanya kepada kita mengenai harta-harta kita. Maka aku meminta persaksianmu wahai Rasulullah, bahwa aku telah menjadikan lahanku untuk Allah.\" Maka Rasulullah shallallahu 'alaihi wasallam bersabda: \"Jadikanlah lahan tersebut untuk para kerabatmu, yaitu Hasan bin Tsabit dan Ubay bin Ka'b.\""},"3446":{"ar":"أَخْبَرَنَا سَعِيدُ بْنُ عَبْدِ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ بْنُ عُيَيْنَةَ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ عُمَرُ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْمِائَةَ سَهْمٍ الَّتِي لِي بِخَيْبَرَ لَمْ أُصِبْ مَالًا قَطُّ أَعْجَبَ إِلَيَّ مِنْهَا قَدْ أَرَدْتُ أَنْ أَتَصَدَّقَ بِهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ احْبِسْ أَصْلَهَا وَسَبِّلْ ثَمَرَتَهَا","id":"Telah mengabarkan kepada kami [Sa'id bin 'Abdurrahman] berkata; telah menceritakan kepada kami [Sufyan bin 'Uyainah] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] berkata, \"Umar berkata kepada Nabi shallallahu 'alaihi wasallam, 'Sungguh, aku belum pernah mendapatkan harta yang lebih aku cintai dari seratus saham yang aku dapat di Khaibar. Dan aku berkeinginan untuk bersedekah dengannya.\" Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Tahanlah pokoknya dan jadikan buahnya di jalan Allah.\""},"3447":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ عَبْدِ اللَّهِ الْخَلَنْجِيُّ بِبَيْتِ الْمَقْدِسِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ رَضِيَ اللَّهُ عَنْهُ قَالَجَاءَ عُمَرُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ إِنِّي أَصَبْتُ مَالًا لَمْ أُصِبْ مِثْلَهُ قَطُّ كَانَ لِي مِائَةُ رَأْسٍ فَاشْتَرَيْتُ بِهَا مِائَةَ سَهْمٍ مِنْ خَيْبَرَ مِنْ أَهْلِهَا وَإِنِّي قَدْ أَرَدْتُ أَنْ أَتَقَرَّبَ بِهَا إِلَى اللَّهِ عَزَّ وَجَلَّ قَالَ فَاحْبِسْ أَصْلَهَا وَسَبِّلْ الثَّمَرَةَ","id":"Telah mengabarkan kepada kami [Muhammad bin Abdullah Al Khalanji] di Baitul Maqdis, ia berkata; telah menceritakan kepada kami [Sufyan] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dari [Umar] radliallahu 'anhu, ia berkata, \"Umar datang kepada Rasulullah shallallahu 'alaihi wasallam kemudian berkata, \"Wahai Rasulullah, sungguh aku mendapatkan harta yang belum pernah aku dapatkan yang semisalnya. Aku memiliki seratus budak, kemudian aku membeli dengannya seratus saham Khaibar dari pemiliknya, dan aku ingin mendekatkan diri dengannya kepada Allah 'azza wajalla.\" Maka beliau bersabda: \"Tahan pokoknya dan jadikan buahnya di jalan Allah.\""},"3448":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ مُصَفَّى بْنِ بَهْلُولٍ قَالَ حَدَّثَنَا بَقِيَّةُ عَنْ سَعِيدِ بْنِ سَالِمٍ الْمَكِّيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عُمَرَ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ عَنْ عُمَرَ قَالَسَأَلْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَنْ أَرْضٍ لِي بِثَمْغٍ قَالَ احْبِسْ أَصْلَهَا وَسَبِّلْ ثَمَرَتَهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Mushaffa bin Bahlul] berkata; telah menceritakan kepada kami [Baqiyyah] dari [Sa'id bin Salim Al Makki] dari ['Ubaidullah bin Umar] dari [Nafi'] dari [Ibnu Umar] dari [Umar] berkata, \"Aku bertanya kepada Rasulullah shallallahu 'alaihi wasallam mengenai lahanku di Tsamgh, beliau bersabda: \"Tahanlah pokoknya dan jadikan buahnya di jalan Allah.\""},"3449":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا الْمُعْتَمِرُ بْنُ سُلَيْمَانَ قَالَ سَمِعْتُ أَبِي يُحَدِّثُ عَنْ حُصَيْنِ بْنِ عَبْدِ الرَّحْمَنِ عَنْ عُمَرَ بْنِ جَاوَانَ رَجُلٍ مِنْ بَنِي تَمِيمٍ وَذَاكَ أَنِّي قُلْتُ لَهُ أَرَأَيْتَ اعْتِزَالَ الْأَحْنَفِ بْنِ قَيْسٍ مَا كَانَ قَالَ سَمِعْتُ الْأَحْنَفَ يَقُولُأَتَيْتُ الْمَدِينَةَ وَأَنَا حَاجٌّ فَبَيْنَا نَحْنُ فِي مَنَازِلِنَا نَضَعُ رِحَالَنَا إِذْ أَتَى آتٍ فَقَالَ قَدْ اجْتَمَعَ النَّاسُ فِي الْمَسْجِدِ فَاطَّلَعْتُ فَإِذَا يَعْنِي النَّاسَ مُجْتَمِعُونَ وَإِذَا بَيْنَ أَظْهُرِهِمْ نَفَرٌ قُعُودٌ فَإِذَا هُوَ عَلِيُّ بْنُ أَبِي طَالِبٍ وَالزُّبَيْرُ وَطَلْحَةُ وَسَعْدُ بْنُ أَبِي وَقَّاصٍ رَحْمَةُ اللَّهِ عَلَيْهِمْ فَلَمَّا قُمْتُ عَلَيْهِمْ قِيلَ هَذَا عُثْمَانُ بْنُ عَفَّانَ قَدْ جَاءَ قَالَ فَجَاءَ وَعَلَيْهِ مُلَيَّةٌ صَفْرَاءُ فَقُلْتُ لِصَاحِبِي كَمَا أَنْتَ حَتَّى أَنْظُرَ مَا جَاءَ بِهِ فَقَالَ عُثْمَانُ أَهَاهُنَا عَلِيٌّ أَهَاهُنَا الزُّبَيْرُ أَهَاهُنَا طَلْحَةُ أَهَاهُنَا سَعْدٌ قَالُوا نَعَمْ قَالَ فَأَنْشُدُكُمْ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يَبْتَاعُ مِرْبَدَ بَنِي فُلَانٍ غَفَرَ اللَّهُ لَهُ فَابْتَعْتُهُ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي ابْتَعْتُ مِرْبَدَ بَنِي فُلَانٍ قَالَ فَاجْعَلْهُ فِي مَسْجِدِنَا وَأَجْرُهُ لَكَ قَالُوا نَعَمْ قَالَ فَأَنْشُدُكُمْ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يَبْتَاعُ بِئْرَ رُومَةَ غَفَرَ اللَّهُ لَهُ فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ قَدْ ابْتَعْتُ بِئْرَ رُومَةَ قَالَ فَاجْعَلْهَا سِقَايَةً لِلْمُسْلِمِينَ وَأَجْرُهَا لَكَ قَالُوا نَعَمْ قَالَ فَأَنْشُدُكُمْ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يُجَهِّزُ جَيْشَ الْعُسْرَةِ غَفَرَ اللَّهُ لَهُ فَجَهَّزْتُهُمْ حَتَّى مَا يَفْقِدُونَ عِقَالًا وَلَا خِطَامًا قَالُوا نَعَمْ قَالَ اللَّهُمَّ اشْهَدْ اللَّهُمَّ اشْهَدْ اللَّهُمَّ اشْهَدْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah memberitakan kepada kami [Al Mu'tamir bin Sulaiman] berkata; aku mendengar [ayahku] menceritakan dari [Hushain bin 'Abdurrahman] dari [Umar bin Jawan] seorang laki-laki dari Bani Tamim, aku berkata kepadanya, \"Bagaimana pendapatmu mengenai sebab [Al Ahnaf] menyingkir dari apa yang telah terjadi?\" Ia menjawab, \"Aku mendengar Al Ahnaf berkata, 'Aku datang ke Madinah dan aku sedang melakukan haji, ketika kami berada di rumah kami dan menambatkan kendaraan kami, tiba-tiba datang seseorang kepada kami seraya berkata, 'Sesungguhnya orang-orang telah berkumpul di Masjid! ' Kemudian aku lihat ternyata orang-orang sedang berkumpul, dan ternyata di antara orang-orang yang duduk itu ada [Ali bin Abu Thalib], [Az Zubair], [Thalhah] dan [Sa'd bin Abu Waqqash], semoga rahmat Allah terlimpahkan kepada mereka. Saat aku berdiri menuju mereka, maka dikatakan, 'Ini [Utsman bin Affan] telah tiba'.\" Al Ahnaf berkata, \"Ia datang memakai baju kurung kuning. Kemudian aku katakan kepada sahabatku, 'Tetaplah di tempatmu hingga aku melihat apa yang ia bawa.' Kemudian Utsman berkata, \"Apakah di sini ada Ali? Apakah di sini ada Az Zubair? Apakah di sini ada Thalhah? Apakah di sini ada Sa'd?\" Mereka menjawab, 'Ya.\" Utsman lalu berkata, \"Sungguh, aku bertanya kepada kalian dan bersumpah dengan nama Allah yang tidak ada Tuhan yang berhak disembah kecuali Dia. Apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Barangsiapa membeli tempat penambatan unta milik Bani Fulan, maka Allah akan mengampuninya.\" Maka aku membelinya kemudian datang kepada Rasulullah shallallahu 'alaihi wasallam dan berkata kepadanya, \"Sesungguhnya aku telah membeli tempat penambatan unta milik Bani Fulan. Lalu beliau bersabda: \"Jadikanlah berada di masjid kita, dan pahalanya untukmu.\" Mereka mengatakan, \"Ya.\" Utsman berkata, \"Aku bertanya dan bersumpah dengan nama Allah yang tidak ada Tuhan yang berhak disembah kecuali Dia. Apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Barangsiapa membeli sumur Rumah, maka Allah akan mengampuninya.\" Kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan mengatakan, \"Aku telah membelinya.\" Lalu beliau bersabda: \"Jadikanlah untuk memberi minum orang-orang muslim dan pahalanya untukmu.\" Mereka mengatakan, \"Ya.\" Utsman berkata lagi, \"Aku bertanya dan bersumpah dengan nama Allah yang tidak ada Tuhan yang berhak disembah kecuali Dia. Apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Barangsiapa mempersiapkan pasukan Al 'Usrah maka Allah akan mengampuninya.\" Maka aku mempersiapkan mereka hingga mereka tidak kehilangan satu tali unta dan satu tali kendali pun.\" Maka mereka menjawab, \"Ya.\" Utsman lalu berkata, \"Ya Allah, saksikanlah. Ya Allah saksikanlah. Ya Allah saksikanlah.\""},"3450":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ إِدْرِيسَ قَالَ سَمِعْتُ حُصَيْنَ بْنَ عَبْدِ الرَّحْمَنِ يُحَدِّثُ عَنْ عُمَرَ بْنِ جَاوَانَ عَنْ الْأَحْنَفِ بْنِ قَيْسٍ قَالَخَرَجْنَا حُجَّاجًا فَقَدِمْنَا الْمَدِينَةَ وَنَحْنُ نُرِيدُ الْحَجَّ فَبَيْنَا نَحْنُ فِي مَنَازِلِنَا نَضَعُ رِحَالَنَا إِذْ أَتَانَا آتٍ فَقَالَ إِنَّ النَّاسَ قَدْ اجْتَمَعُوا فِي الْمَسْجِدِ وَفَزِعُوا فَانْطَلَقْنَا فَإِذَا النَّاسُ مُجْتَمِعُونَ عَلَى نَفَرٍ فِي وَسَطِ الْمَسْجِدِ وَ��ِذَا عَلِيٌّ وَالزُّبَيْرُ وَطَلْحَةُ وَسَعْدُ بْنُ أَبِي وَقَّاصٍ فَإِنَّا لَكَذَلِكَ إِذْ جَاءَ عُثْمَانُ بْنُ عَفَّانَ عَلَيْهِ مُلَاءَةٌ صَفْرَاءُ قَدْ قَنَّعَ بِهَا رَأْسَهُ فَقَالَ أَهَاهُنَا عَلِيٌّ أَهَاهُنَا طَلْحَةُ أَهَاهُنَا الزُّبَيْرُ أَهَاهُنَا سَعْدٌ قَالُوا نَعَمْ قَالَ فَإِنِّي أَنْشُدُكُمْ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يَبْتَاعُ مِرْبَدَ بَنِي فُلَانٍ غَفَرَ اللَّهُ لَهُ فَابْتَعْتُهُ بِعِشْرِينَ أَلْفًا أَوْ بِخَمْسَةٍ وَعِشْرِينَ أَلْفًا فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَأَخْبَرْتُهُ فَقَالَ اجْعَلْهَا فِي مَسْجِدِنَا وَأَجْرُهُ لَكَ قَالُوا اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكُمْ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَنْ يَبْتَاعُ بِئْرَ رُومَةَ غَفَرَ اللَّهُ لَهُ فَابْتَعْتُهُ بِكَذَا وَكَذَا فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ قَدْ ابْتَعْتُهَا بِكَذَا وَكَذَا قَالَ اجْعَلْهَا سِقَايَةً لِلْمُسْلِمِينَ وَأَجْرُهَا لَكَ قَالُوا اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكُمْ بِاللَّهِ الَّذِي لَا إِلَهَ إِلَّا هُوَ أَتَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَظَرَ فِي وُجُوهِ الْقَوْمِ فَقَالَ مَنْ جَهَّزَ هَؤُلَاءِ غَفَرَ اللَّهُ لَهُ يَعْنِي جَيْشَ الْعُسْرَةِ فَجَهَّزْتُهُمْ حَتَّى مَا يَفْقِدُونَ عِقَالًا وَلَا خِطَامًا قَالُوا اللَّهُمَّ نَعَمْ قَالَ اللَّهُمَّ اشْهَدْ اللَّهُمَّ اشْهَدْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah memberitakan kepada kami [Abdullah bin Idris] berkata; aku pernah mendengar [Hushain bin 'Abdurrahman] menceritakan dari [Umar bin Jawan] dari [Al Ahnaf bin Qais] berkata, \"Kami pernah keluar untuk melakukan haji, lalu kami datang ke Madinah dan kami ingin melakukan haji. Ketika kami berada di rumah kami dan menambatkan kendaraan kami, tiba-tiba datang seseorang kepada kami seraya berkata, \"Sesungguhnya orang-orang telah berkumpul di Masjid dan mereka merasa kaget.\" Maka kami berangkat ke masjid, ternyata orang-orang sedang berkumpul mengelilingi beberapa orang yang berada di tengah masjid, dan ternyata mereka adalah [Ali], [Az Zubair], [Thalhah] dan [Sa'd bin Abu Waqqash]. Sungguh, saat dalam kondisi seperti itu tiba-tiba [Utsman bin 'Affan] datang memakai baju kurung kuning, dan menutup kepalanya dengan baju tersebut, ia lalu berkata, \"Apakah di sini ada Ali? Apakah di sini ada Thalhah? Apakah di sini ada Az Zubair? Apakah di sini ada Sa'd?\" Mereka berkata, \"Ya.\" Utsman lalu berkata, \"Sungguh, aku bertanya kepada kalian dan bersumpah dengan nama Allah yang tidak ada Tuhan yang berhak disembah kecuali Dia. Apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Barangsiapa membeli tempat penambatan unta milik Bani Fulan, maka Allah akan mengampuninya.\" Maka aku membelinya dengan harga dua puluh ribu atau dua puluh lima ribu, kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan mengabarkan kepadanya. Lalu beliau bersabda: \"Jadikanlah berada di masjid kita, dan pahalanya untukmu.\" Mereka mengatakan, \"Ya.\" Utsman berkata lagi, \"Aku bertanya dan bersumpah dengan nama Allah yang tidak ada Tuhan yang berhak disembah kecuali Dia. Apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam pernah bersabda: \"Barangsiapa membeli sumur Rumah, maka Allah akan mengampuninya.\" Maka aku membelinya dengan harga sekian dan sekian, kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan mengatakan, \"Aku telah membelinya dengan harga sekian dan sekian.\" Lalu beliau bersabda: \"Jadikanlah untuk memberi minum orang-orang muslim dan pahalanya untukmu.\" Mereka mengatakan, \"Ya.\" Utsman berkata lagi, \"Aku bertanya dan bersumpah dengan nama Allah yang tidak ada Tuhan yang berhak disembah kecuali Dia. Apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam pernah melihat ke wajah beberapa orang lalu bersabda: \"Barangsiapa mempersiapkan mereka, maka Allah akan mengampuninya.\" -Yaitu pasukan Al 'Usrah- Maka aku mempersiapkan mereka hingga mereka tidak kehilangan satu tali unta dan satu tali kendalipun. Maka mereka berkata, \"Ya.\" Utsman lalu berkata, \"Ya Allah, saksikanlah. Ya Allah, saksikanlah.\""},"3451":{"ar":"أَخْبَرَنِي زِيَادُ بْنُ أَيُّوبَ قَالَ حَدَّثَنَا سَعِيدُ بْنُ عَامِرٍ عَنْ يَحْيَى بْنِ أَبِي الْحَجَّاجِ عَنْ سَعِيدٍ الْجُرَيْرِيِّ عَنْ ثُمَامَةَ بْنِ حَزْنٍ الْقُشَيْرِيِّ قَالَشَهِدْتُ الدَّارَ حِينَ أَشْرَفَ عَلَيْهِمْ عُثْمَانُ فَقَالَ أَنْشُدُكُمْ بِاللَّهِ وَبِالْإِسْلَامِ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدِمَ الْمَدِينَةَ وَلَيْسَ بِهَا مَاءٌ يُسْتَعْذَبُ غَيْرَ بِئْرِ رُومَةَ فَقَالَ مَنْ يَشْتَرِي بِئْرَ رُومَةَ فَيَجْعَلُ فِيهَا دَلْوَهُ مَعَ دِلَاءِ الْمُسْلِمِينَ بِخَيْرٍ لَهُ مِنْهَا فِي الْجَنَّةِ فَاشْتَرَيْتُهَا مِنْ صُلْبِ مَالِي فَجَعَلْتُ دَلْوِي فِيهَا مَعَ دِلَاءِ الْمُسْلِمِينَ وَأَنْتُمْ الْيَوْمَ تَمْنَعُونِي مِنْ الشُّرْبِ مِنْهَا حَتَّى أَشْرَبَ مِنْ مَاءِ الْبَحْرِ قَالُوا اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكُمْ بِاللَّهِ وَالْإِسْلَامِ هَلْ تَعْلَمُونَ أَنِّي جَهَّزْتُ جَيْشَ الْعُسْرَةِ مِنْ مَالِي قَالُوا اللَّهُمَّ نَعَمْ قَالَ فَأَنْشُدُكُمْ بِاللَّهِ وَالْإِسْلَامِ هَلْ تَعْلَمُونَ أَنَّ الْمَسْجِدَ ضَاقَ بِأَهْلِهِ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ يَشْتَرِي بُقْعَةَ آلِ فُلَانٍ فَيَزِيدُهَا فِي الْمَسْجِدِ بِخَيْرٍ لَهُ مِنْهَا فِي الْجَنَّةِ فَاشْتَرَيْتُهَا مِنْ صُلْبِ مَالِي فَزِدْتُهَا فِي الْمَسْجِدِ وَأَنْتُمْ تَمْنَعُونِي أَنْ أُصَلِّيَ فِيهِ رَكْعَتَيْنِ قَالُوا اللَّهُمَّ نَعَمْ قَالَ أَنْشُدُكُمْ بِاللَّهِ وَالْإِسْلَامِ هَلْ تَعْلَمُونَ أَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَانَ عَلَى ثَبِيرٍ ثَبِيرِ مَكَّةَ وَمَعَهُ أَبُو بَكْرٍ وَعُمَرُ وَأَنَا فَتَحَرَّكَ الْجَبَلُ فَرَكَضَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ بِرِجْلِهِ وَقَالَ اسْكُنْ ثَبِيرُ فَإِنَّمَا عَلَيْكَ نَبِيٌّ وَصِدِّيقٌ وَشَهِيدَانِ قَالُوا اللَّهُمَّ نَعَمْ قَالَ اللَّهُ أَكْبَرُ شَهِدُوا لِي وَرَبِّ الْكَعْبَةِ يَعْنِي أَنِّي شَهِيدٌ","id":"Telah mengabarkan kepada kami [Ziyad bin Ayyub] berkata; telah menceritakan kepada kami [Sa'id bin 'Amir] dari [Yahya bin Abu Al Hajjaj] dari [Sa'id Al Jurairi] dari [Tsumamah bin Hazn Al Qusyairi] ia berkata, \"Aku sedang berada di dalam rumah saat [Utsman] menampakkan kemuliannya kepada para sahabat, ia berkata, \"Aku bertanya kepada kalian dan bersumpah dengan nama Allah dan Islam, apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam datang ke Madinah dan tidak ada padanya air segar selain sumur Rumah, kemudian beliau bersabda: \"Barangsiapa membeli sumur Rumah kemudian meletakkan padanya embernya bersama dengan ember orang-orang muslim dengan kebaikan darinya, maka ia akan berada dalam Surga.\" Lalu aku membelinya dari hartaku secara murni, kemudian aku meletakkan padanya emberku dari ember orang-orang Muslim, dan kalian melarangku minum darinya hingga aku minum dari air laut? Mereka mengatakan, \"Ya Allah, benar.\" Utsman berkata, \"Aku bertanya kepada kalian dan bersumpah dengan nama Allah dan Islam, apakah kalian mengetahui bahwa aku telah mempersiapkan pasukan Al 'Usrah dari hartaku? Mereka berkata, \"Ya Allah, benar.\" Utsman berkata lagi, \"Aku bertanya kepada kalian dan bersumpah dengan nama Allah dan Islam, apakah kalian mengetahui bahwa masjid telah sesak dengan penghuninya, kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah yang membeli lahan keluarga Fulan kemudian menambahkannya di masjid lalu ia akan mendapatkan kebaikan di surga?\" Lalu aku membelinya dari hartaku secara murni, kemudian aku tambahkan di dalam masjid dan kalian melarangku untuk melakukan shalat dua rakaat di dalamnya?\" Mereka menjawab, \"Ya Allah, benar.\" Utsman berkata lagi, \"Aku bertanya kepada kalian dan bersumpah dengan nama Allah dan Islam, apakah kalian mengetahui bahwa Rasulullah shallallahu 'alaihi wasallam pernah berada di atas bukit Makkah bersama Abu Bakr, Umar dan aku. Kemudian gunung itu bergerak sehingga Rasulullah shallallahu 'alaihi wasallam menjejaknya kakinya seraya bersabda: \"Diamlah hai bukit! Sesungguhnya di atasmu terdapat seorang nabi, shiddiq, dan dua orang syahid.\" Mereka berkata, \"Ya Allah, benar.\" Utsman lalu berkata, \"Allahu akbar! Mereka telah bersaksi demi Tuhan Ka'bah, bahwa aku adalah orang yang syahid.\""},"3452":{"ar":"أَخْبَرَنَا عِمْرَانُ بْنُ بَكَّارِ بْنِ رَاشِدٍ قَالَ حَدَّثَنَا خَطَّابُ بْنُ عُثْمَانَ قَالَ حَدَّثَنَا عِيسَى بْنُ يُونُسَ حَدَّثَنِي أَبِي عَنْ أَبِي إِسْحَقَ عَنْ أَبِي سَلَمَةَ بْنِ عَبْدِ الرَّحْمَنِأَنَّ عُثْمَانَ أَشْرَفَ عَلَيْهِمْ حِينَ حَصَرُوهُ فَقَالَ أَنْشُدُ بِاللَّهِ رَجُلًا سَمِعَ مِنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ يَوْمَ الْجَبَلِ حِينَ اهْتَزَّ فَرَكَلَهُ بِرِجْلِهِ وَقَالَ اسْكُنْ فَإِنَّهُ لَيْسَ عَلَيْكَ إِلَّا نَبِيٌّ أَوْ صِدِّيقٌ أَوْ شَهِيدَانِ وَأَنَا مَعَهُ فَانْتَشَدَ لَهُ رِجَالٌ ثُمَّ قَالَ أَنْشُدُ بِاللَّهِ رَجُلًا شَهِدَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ بَيْعَةِ الرِّضْوَانِ يَقُولُ هَذِهِ يَدُ اللَّهِ وَهَذِهِ يَدُ عُثْمَانَ فَانْتَشَدَ لَهُ رِجَالٌ ثُمَّ قَالَ أَنْشُدُ بِاللَّهِ رَجُلًا سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَوْمَ جَيْشِ الْعُسْرَةِ يَقُولُ مَنْ يُنْفِقُ نَفَقَةً مُتَقَبَّلَةً فَجَهَّزْتُ نِصْفَ الْجَيْشِ مِنْ مَالِي فَانْتَشَدَ لَهُ رِجَالٌ ثُمَّ قَالَ أَنْشُدُ بِاللَّهِ رَجُلًا سَمِعَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَقُولُ مَنْ يَزِيدُ فِي هَذَا الْمَسْجِدِ بِبَيْتٍ فِي الْجَنَّةِ فَاشْتَرَيْتُهُ مِنْ مَالِي فَانْتَشَدَ لَهُ رِجَالٌ ثُمَّ قَالَ أَنْشُدُ بِاللَّهِ رَجُلًا شَهِدَ رُومَةَ تُبَاعُ فَاشْتَرَيْتُهَا مِنْ مَالِي فَأَبَحْتُهَا لِابْنِ السَّبِيلِ فَانْتَشَدَ لَهُ رِجَالٌأَخْبَرَنِي مُحَمَّدُ بْنُ وَهْبٍ قَالَ حَدَّثَنِي مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنِي أَبُو عَبْدِ الرَّحِيمِ قَالَ حَدَّثَنِي زَيْدُ بْنُ أَبِي أُنَيْسَةَ عَنْ أَبِي إِسْحَقَ عَنْ أَبِي عَبْدِ الرَّحْمَنِ السَّلَمِيِّ قَالَ لَمَّا حُصِرَ عُثْمَانُ فِي دَارِهِ اجْتَمَعَ النَّاسُ حَوْلَ دَارِهِ قَالَ فَأَشْرَفَ عَلَيْهِمْ وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami [Imran bin Bakkar bin Rasyid] berkata; telah menceritakan kepada kami [Khaththab bin Utsman] berkata; telah menceritakan kepada kami [Isa bin Yunus] berkata; telah menceritakan kepadaku [ayahku] dari [Abu Ishaq] dari [Abu Salamah bin 'Abdurrahman] bahwa [Utsman] menampakkan kemuliannya kepada mereka saat mereka mengepungnya, Ia katakan, \"Aku bersumpah dengan nama Allah atas seseorang yang telah mendengar dari Rasulullah shallallahu 'alaihi wasallam, bahwa beliau bersabda pada hari gunung, yaitu ketika gunung tersebut bergoncang kemudian beliau menjejak kakinya seraya bersabda: 'Diamlah! Sesungguhnya tidak ada yang berada di atasmu kecuali seorang nabi atau shiddiq atau dua orang syahid'. Dan aku bersama beliau? Lalu orang-orang memujinya. Kemudian Utsman berkata, \"Aku bersumpah dengan nama Allah dan bertanya kepada atas seseorang yang menyaksikan Rasulullah shallallahu 'alaihi wasallam pada saat bai'at Ridlwan, beliau bersabda: \"Ini adalah tangan Allah, dan ini tangan Utsman.\" Lalu orang-orang memujinya. Kemudian Utsman berkata, \"Aku bersumpah dengan nama Allah atas seseorang yang telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda pada hari (peristiwa) pasukan Al 'Usrah, beliau bersabda: 'Barangsiapa memberikan infak yang diterima? ' Maka aku mempersiapkan setengah pasukan dari hartaku.\" Lalu orang-orang memujinya. Kemudian Utsman berkata lagi, \"Aku bersumpah dengan nama Allah atas seseorang yang telah mendengar Rasulullah shallallahu 'alaihi wasallam bersabda: 'Barangsiapa menambahkan ke dalam masjid ini dengan sebuah rumah di Surga? ' Maka aku membelinya dari hartaku.\" Lalu orang-orang memujinya. Kemudian Utsman berkata lagi, \"Aku bersumpah dengan nama Allah atas seseorang yang telah menyaksikan sumur Rumah dijual, kemudian aku membelinya dari hartaku?\" Lalu orang-orang memujinya.\" Telah mengabarkan kepadaku [Muhammad bin Wahb] berkata; telah menceritakan kepadaku [Muhammad bin Salamah] berkata; telah menceritakan kepadaku [Abu Abdurrahim] berkata; telah menceritakan kepadaku [Zaid bin Abi Unais] dari [Abu Ishaq] dari [Abu 'Abdurrahman As Salami] ia berkata, \"Tatkala Utsman dikepung di rumahnya, orang-orang berkumpul di sekitar rumahnya.\" Ia berkata, \"Kemudian [Utsman] menampakkan kemuliannya kepada mereka…dan ia menyebutkan hadits tersebut.\""},"3453":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ حَرْبٍ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ فُضَيْلٍ عَنْ عُمَارَةَ عَنْ أَبِي زُرْعَةَ عَنْ أَبِي هُرَيْرَةَ قَالَجَاءَ رَجُلٌ إِلَى النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أَيُّ الصَّدَقَةِ أَعْظَمُ أَجْرًا قَالَ أَنْ تَصَدَّقَ وَأَنْتَ صَحِيحٌ شَحِيحٌ تَخْشَى الْفَقْرَ وَتَأْمُلُ الْبَقَاءَ وَلَا تُمْهِلْ حَتَّى إِذَا بَلَغَتْ الْحُلْقُومَ قُلْتَ لِفُلَانٍ كَذَا وَقَدْ كَانَ لِفُلَانٍ","id":"Telah mengabarkan kepada kami [Ahmad bin Harb] berkata; telah menceritakan kepada kami [Muhammad bin Fudlail] dari ['Umarah] dari [Abu Zur'ah] dari [Abu Hurairah] ia berkata, \"Seorang laki-laki datang kepada Nabi shallallahu 'alaihi wasallam kemudian berkata, \"Wahai Rasulullah, sedekah apakah yang paling besar pahalanya?\" Beliau bersabda: \"Engkau bersedekah sedang engkau dalam keadaan sehat, pelit dan takut miskin dan ingin hidup kekal, engkau tidak menunda (untuk sedekah) hingga nyawa telah sampai pada leher. Engkau katakan 'Ini untuk fulan sekian dan ini untuk si fulan sekian'.\""},"3454":{"ar":"أَخْبَرَنَا هَنَّادُ بْنُ السَّرِيِّ عَنْ أَبِي مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ التَّيْمِيِّ عَنْ الْحَارِثِ بْنِ سُوَيْدٍ عَنْ عَبْدِ اللَّهِ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَيُّكُمْ مَالُ وَارِثِهِ أَحَبُّ إِلَيْهِ مِنْ مَالِهِ قَالُوا يَا رَسُولَ اللَّهِ مَا مِنَّا مِنْ أَحَدٍ إِلَّا مَالُهُ أَحَبُّ إِلَيْهِ مِنْ مَالِ وَارِثِهِ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اعْلَمُوا أَنَّهُ لَيْسَ مِنْكُمْ مِنْ أَحَدٍ إِلَّا مَالُ وَارِثِهِ أَحَبُّ إِلَيْهِ مِنْ مَالِهِ مَالُكَ مَا قَدَّمْتَ وَمَالُ وَارِثِكَ مَا أَخَّرْتَ","id":"Telah mengabarkan kepada kami [Hannad bin As Sari] dari [Abu Mu'awiyah] dari [Al A'masy] dari [Ibrahim At Taimi] dari [Al Harits bin Suwaid] dari [Abdullah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Siapakah di antara kalian yang harta pewarisnya lebih ia cintai daripada hartanya?\" Mereka berkata, \"Wahai Rasulullah, tidaklah di antara kami seorang pun kecuali hartanya lebih ia sukai daripada harta pewarisnya.\" Rasulullah shallallahu 'alaihi wasallam lalu bersabda: \"Ketahuilah, sesungguhnya tidak ada seorangpun di antara kalian melainkan harta pewarisnya lebih ia cintai daripada hartanya. Hartamu adalah apa yang telah engkau dahulukan sedang harta pewarismu adalah apa yang engkau tunda.\""},"3455":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا شُعْبَةُ عَنْ قَتَادَةَ عَنْ مُطَرِّفٍ عَنْ أَبِيهِعَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ{ أَلْهَاكُمْ التَّكَاثُرُ حَتَّى زُرْتُمْ الْمَقَابِرَ }قَالَ يَقُولُ ابْنُ آدَمَ مَالِي مَالِي وَإِنَّمَا مَالُكَ مَا أَكَلْتَ فَأَفْنَيْتَ أَوْ لَبِسْتَ فَأَبْلَيْتَ أَوْ تَصَدَّقْتَ فَأَمْضَيْتَ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Yahya] berkata; telah menceritakan kepada kami [Syu'bah] dari [Qatadah] dari [Mutharrif] dari [ayahnya] dari Nabi shallallahu 'alaihi wasallam, beliau membaca ayat: '(Bermegah-megahan telah melalaikan kamu sampai kamu masuk ke dalam kubur) ' (Qs. At Takaatsur: 1-2). Beliau bersabda: \"Anak Adam berkata, 'Hartaku, hartaku'. Sesungguhnya hartamu adalah apa yang telah engkau makan hingga engkau habiskan, atau engkau pakai hingga engkau hancurkan, atau engkau sedekahkan sehingga habis.\""},"3456":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ بَشَّارٍ قَالَ حَدَّثَنَا مُحَمَّدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ سَمِعْتُ أَبَا إِسْحَقَ سَمِعَ أَبَا حَبِيبَةَ الطَّائِيَّ قَالَأَوْصَى رَجُلٌ بِدَنَانِيرَ فِي سَبِيلِ اللَّهِ فَسُئِلَ أَبُو الدَّرْدَاءِ فَحَدَّثَ عَنْ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَثَلُ الَّذِي يُعْتِقُ أَوْ يَتَصَدَّقُ عِنْدَ مَوْتِهِ مَثَلُ الَّذِي يُهْدِي بَعْدَمَا يَشْبَعُ","id":"Telah mengabarkan kepada kami [Muhammad bin Basysyar] berkata; telah menceritakan kepada kami [Muhammad] berkata; telah menceritakan kepada kami [Syu'bah] berkata; aku mendengar [Abu Ishaq] mendengar [Abu Habibah Ath Thai] berkata, \"Seseorang telah berwasiat dengan beberapa dinar di jalan Allah. Kemudian [Abu Ad Darda] ditanya (tentang hal tersebut), kemudian ia menceritakan dari Nabi shallallahu 'alaihi wasallam, beliau bersabda: \"Permisalan orang memerdekakan budak atau bersedekah di saat akan meninggal seperti orang yang memberikan hadiah setelah ia Kenyang.\""},"3457":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا الْفُضَيْلُ عَنْ عُبَيْدِ اللَّهِ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا حَقُّ امْرِئٍ مُسْلِمٍ لَهُ شَيْءٌ يُوصَى فِيهِ أَنْ يَبِيتَ لَيْلَتَيْنِ إِلَّا وَوَصِيَّتُهُ مَكْتُوبَةٌ عِنْدَهُ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Al Fudlail] dari ['Ubaidullah] dari [Nafi'] dari [Ibnu Umar] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hak atas seorang muslim yang mempunyai sesuatu untuk diwasiatkan, untuk bermalam selama dua malam kecuali wasiatnya telah tertulis di sisinya.\""},"3458":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا حَقُّ امْرِئٍ مُسْلِمٍ لَهُ شَيْءٌ يُوصَى فِيهِ يَبِيتُ لَيْلَتَيْنِ إِلَّا وَوَصِيَّتُهُ مَكْتُوبَةٌ عِنْدَهُأَخْبَرَنَا مُحَمَّدُ بْنُ حَاتِمِ بْنِ نُعَيْمٍ قَالَ حَدَّثَنَا حِبَّانُ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ عَنْ ابْنِ عَوْنٍ عَنْ نَافِعٍ عَنْ ابْنِ عُمَرَ قَوْلَهُ","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] berkata; telah menceritakan kepada kami [Ibnu Alqasim] dari [Malik] dari [Nafi'] dari [Ibnu Umar], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tidak ada hak atas seorang muslim yang mempunyai sesuatu untuk diwasiatkan, untuk bermalam selama dua malam kecuali wasiatnya telah tertulis di sisinya.\" Telah mengabarkan kepada kami [Muhammad bin Hatim bin Nu'aim] berkata; telah menceritakan kepada kami [Hibban] berkata; telah memberitakan kepada kami [Abdullah] dari [Ibnu 'Aun] dari [Nafi'] dari [Ibnu Umar], hadits senada.\""},"3459":{"ar":"أَخْبَرَنَا يُونُسُ بْنُ عَبْدِ الْأَعْلَى قَالَ أَنْبَأَنَا ابْنُ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ فَإِنَّ سَالِمًا أَخْبَرَنِي عَنْ عَبْدِ اللَّهِ بْنِ عُمَرَأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا حَقُّ امْرِئٍ مُسْلِمٍ تَمُرُّ عَلَيْهِ ثَلَاثُ لَيَالٍ إِلَّا وَعِنْدَهُ وَصِيَّتُهُقَالَ عَبْدُ اللَّهِ بْنُ عُمَرَ مَا مَرَّتْ عَلَيَّ مُنْذُ سَمِعْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ ذَلِكَ إِلَّا وَعِنْدِي وَصِيَّتِي","id":"Telah mengabarkan kepada kami [Yunus bin Abdul A'la] berkata; telah memberitakan kepada kami [Ibnu Wahb] berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] berkata; bahwa [Salim] mengabarkan kepadaku dari [Abdullah bin Umar] bahwa Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak ada hak atas seorang muslim (untuk bermalam) lebih dari tiga malam kecuali wasiatnya telah tertulis di sisinya.\" Abdullah bin Umar berkata, \"Semenjak aku mendengar sabda Rasulullah shallallahu 'alaihi wasallam tersebut, tidak pernah terlewatkan olehku untuk menulis wasiatku.\""},"3460":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ يَحْيَى بْنِ الْوَزِيرِ بْنِ سُلَيْمَانَ قَالَ سَمِعْتُ ابْنَ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ وَعَمْرُو بْنُ الْحَارِثِ عَنْ ابْنِ شِهَابٍ عَنْ سَالِمِ بْنِ عَبْدِ اللَّهِ عَنْ أَبِيهِعَنْ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ مَا حَقُّ امْرِئٍ مُسْلِمٍ لَهُ شَيْءٌ يُوصَى فِيهِ فَيَبِيتُ ثَلَاثَ لَيَالٍ إِلَّا وَوَصِيَّتُهُ عِنْدَهُ مَكْتُوبَةٌ","id":"Telah mengabarkan kepada kami [Ahmad bin Yahya bin Az Zubair bin Sulaiman] berkata; aku mendengar [Ibnu Wahb] berkata; telah mengabarkan kepadaku [Yunus] dan ['Amru bin Al Harits] dari [Ibnu Syihab] dari [Salim bin Abdullah] dari [ayahnya] dari Rasulullah shallallahu 'alaihi wasallam, beliau bersabda: \"Tidak berhak bagi seorang muslim yang memiliki sesuatu untuk diwasiatkan, untuk bermalam selama tiga malam, melainkan wasiatnya telah tertulis di sisinya.\""},"3461":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدُ بْنُ الْحَارِثِ قَالَ حَدَّثَنَا مَالِكُ بْنُ مِغْوَلٍ قَالَ حَدَّثَنَا طَلْحَةُ قَالَسَأَلْتُ ابْنَ أَبِي أَوْفَى أَوْصَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ لَا قُلْتُ كَيْفَ كَتَبَ عَلَى الْمُسْلِمِينَ الْوَصِيَّةَ قَالَ أَوْصَى بِكِتَابِ اللَّهِ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] berkata; telah menceritakan kepada kami [Khalid bin Al Harits] berkata; telah menceritakan kepada kami [Malik bin Mighwal] berkata; telah menceritakan kepada kami [Thalhah] berkata; aku bertanya kepada [Ibnu Abu Aufa], \"Apakah Rasulullah shallallahu 'alaihi wasallam memberikan wasiat?\" Ia menjawab, \"Tidak.\" Aku lalu katakan, \"Bagaimana beliau mewajibkan wasiat terhadap orang-orang Muslim!\" Ia menjawab, \"Beliau berwasiat dengan Kitab Allah.\""},"3462":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ رَافِعٍ قَالَ حَدَّثَنَا يَحْيَى بْنُ آدَمَ قَالَ حَدَّثَنَا مُفَضَّلٌ عَنْ الْأَعْمَشِ وَأَنْبَأَنَا مُحَمَّدُ بْنُ الْعَلَاءِ وَأَحْمَدُ بْنُ حَرْبٍ قَالَا حَدَّثَنَا أَبُو مُعَاوِيَةَ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْمَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِينَارًا وَلَا دِرْهَمًا وَلَا شَاةً وَلَا بَعِيرًا وَلَا أَوْصَى بِشَيْءٍ","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] berkata; telah menceritakan kepada kami [Yahya bin Adam] berkata; telah menceritakan kepada kami [Mufadldlal] dari [Al A'masy], dan telah memberitakan kepada kami [Muhammad bin Al A'la] dan [Ahmad bin Harb] mereka berkata; telah menceritakan kepada kami [Abu Mu'awiyah] dari [Al A'masy] dari [Syaqiq] dari [Masruq] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak meninggalkan uang dinar, dirham, kambing atau unta, beliau tidak berwasiat dengan sesuatu.\""},"3463":{"ar":"أَخْبَرَنِي مُحَمَّدُ بْنُ رَافِعٍ حَدَّثَنَا مُصْعَبٌ حَدَّثَنَا دَاوُدُ عَنْ الْأَعْمَشِ عَنْ شَقِيقٍ عَنْ مَسْرُوقٍ عَنْ عَائِشَةَ قَالَتْمَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِرْهَمًا وَلَا دِينَارًا وَلَا شَاةً وَلَا بَعِيرًا وَمَا أَوْصَى","id":"Telah mengabarkan kepada kami [Muhammad bin Rafi'] telah menceritakan kepada kami [Mush'ab] telah menceritakan kepada kami [Daud] dari [Al A'masy] dari [Syaqiq] dari [Masruq] dari [Aisyah], ia berkata; Rasulullah shallallahu 'alaihi wasallam tidak meninggalkan uang dirham, dinar, kambing serta unta, dan beliau tidak berwasiat."},"3464":{"ar":"أَخْبَرَنَا جَعْفَرُ بْنُ مُحَمَّدِ بْنِ الْهُذَيْلِ وَأَحْمَدُ بْنُ يُوسُفَ قَالَا حَدَّثَنَا عَاصِمُ بْنُ يُوسُفَ قَالَ حَدَّثَنَا حَسَنُ بْنُ عَيَّاشٍ عَنْ الْأَعْمَشِ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْمَا تَرَكَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ دِرْهَمًا وَلَا دِينَارًا وَلَا شَاةً وَلَا بَعِيرًا وَلَا أَوْصَى لَمْ يَذْكُرْ جَعْفَرٌ دِينَارًا وَلَا دِرْهَمًا","id":"Telah mengabarkan kepada kami [Ja'far bin Muhammad bin Al Hudzail] dan [Ahmad bin Yusuf] mereka berkata; telah menceritakan kepada kami ['Ashim bin Yusuf] berkata; telah menceritakan kepada kami [Hasan bin 'Ayyasy] dari [Al A'masy] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam tidak meninggalkan uang dirham, dinar, kambing atau unta, dan beliau tidak berwasiat.\""},"3465":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَ�� أَزْهَرُ قَالَ أَنْبَأَنَا ابْنُ عَوْنٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْ يَقُولُونَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَوْصَى إِلَى عَلِيٍّ رَضِيَ اللَّهُ عَنْهُ لَقَدْ دَعَا بِالطَّسْتِ لِيَبُولَ فِيهَا فَانْخَنَثَتْ نَفْسُهُ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَمَا أَشْعُرُ فَإِلَى مَنْ أَوْصَى","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami [Azhar] berkata; telah memberitakan kepada kami [Ibnu 'Aun] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] berkata, \"Mereka berkata, \"Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah berwasiat kepada Ali radliallahu 'anhu, beliau minta diambilkan bejana untuk buang air kecil, kemudian beliau bergetar (akan meninggal) dan aku tidak merasakan. Maka kepada siapa beliau berwasiat?\""},"3466":{"ar":"أَخْبَرَنِي أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عَارِمٌ قَالَ حَدَّثَنَا حَمَّادُ بْنُ زَيْدٍ عَنْ ابْنِ عَوْنٍ عَنْ إِبْرَاهِيمَ عَنْ الْأَسْوَدِ عَنْ عَائِشَةَ قَالَتْتُوُفِّيَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَلَيْسَ عِنْدَهُ أَحَدٌ غَيْرِي قَالَتْ وَدَعَا بِالطَّسْتِ","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] berkata; telah menceritakan kepada kami ['Arim] berkata; telah menceritakan kepada kami [Hammad bin Zaid] dari [Ibnu 'Aun] dari [Ibrahim] dari [Al Aswad] dari [Aisyah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam meninggal dan tidak ada seorangpun di sisinya selain diriku, beliau meminta dibawakan baskom.\""},"3467":{"ar":"أَخْبَرَنِي عَمْرُو بْنُ عُثْمَانَ بْنِ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ الزُّهْرِيِّ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَمَرِضْتُ مَرَضًا أَشْفَيْتُ مِنْهُ فَأَتَانِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ لِي مَالًا كَثِيرًا وَلَيْسَ يَرِثُنِي إِلَّا ابْنَتِي أَفَأَتَصَدَّقُ بِثُلُثَيْ مَالِي قَالَ لَا قُلْتُ فَالشَّطْرَ قَالَ لَا قُلْتُ فَالثُّلُثَ قَالَ الثُّلُثَ وَالثُّلُثُ كَثِيرٌ إِنَّكَ أَنْ تَتْرُكَ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ لَهُمْ مِنْ أَنْ تَتْرُكَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ","id":"Telah mengabarkan kepadaku ['Amru bin Utsman bin Sa'id] berkata; telah menceritakan kepada kami [Sufyan] dari [Az Zuhri] dari ['Amir bin Sa'd] dari [ayahnya] ia berkata, \"Aku menderita sakit kemudian Rasulullah shallallahu 'alaihi wasallam mengunjungiku. Aku berkata, \"Wahai Rasulullah, sesungguhnya aku memiliki harta yang banyak dan tidak ada yang mewarisiku kecuali anak wanitaku, bolehkah aku bersedekah dengan dua pertiga hartaku?\" Beliau bersabda: \"Tidak.\" Aku lalu bertanya lagi, \"bagaimana jika setengah?\" Beliau menjawab: \"Tidak.\" Aku bertanya lagi, \"Bagaimana jika sepertiga?\" Beliau bersabda: \"Sepertiga, dan sepertiga itu banyak. Sesungguhnya engkau meninggalkan para pewarismu dalam keadaan kaya lebih baik bagimu daripada engkau meninggalkan mereka dalam keadaan miskin, dan meminta-minta kepada manusia.\""},"3468":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ مَنْصُورٍ وَأَحْمَدُ بْنُ سُلَيْمَانَ وَاللَّفْظُ لِأَحْمَدَ قَالَا حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ سَعْدٍ قَالَجَاءَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُنِي وَأَنَا بِمَكَّةَ قُلْتُ يَا رَسُولَ اللَّهِ أُوصِي بِمَالِي كُلِّهِ قَالَ لَا قُلْتُ فَالشَّطْرَ قَالَ لَا قُلْتُ فَالثُّلُثَ قَالَ الثُّلُثَ وَالثُّلُثُ كَثِيرٌ إِنَّكَ أَنْ تَدَعَ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَدَعَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ يَتَكَفَّفُونَ فِي أَيْدِيهِمْ","id":"Telah mengabarkan kepada kami ['Amru bin Manshur] dan [Ahmad bin Sulaiman] dan lafazhnya adalah lafazh Ahmad. Mereka berkata; telah menceritakan kepada kami [Abu Nu'aim] berkata; telah menceritakan kepada kami [Sufyan] dari [Sa'd bin Ibrahim] dari ['Amir bin Sa'd] dari [Sa'd] ia berkata, \"Nabi shallallahu 'alaihi wasallam datang menjengukku saat aku di Makkah, lalu aku katakan, \"Wahai Rasulullah, bolehkah aku berwasiat dengan seluruh hartaku?\" Beliau menjawab: \"Jangan.\" Aku tanyakan lagi, \"Bagaimana jika setengah?\" Beliau menjawab: \"Jangan.\" Aku tanyakan lagi, \"Bagaimana jika sepertiga?\" Beliau menjawab: \"Sepertiga, dan sepertiga itu banyak. Sesungguhnya engkau meninggalkan pewarismu dalam keadaan kaya lebih baik daripada engkau meninggalkan mereka dalam keadaan miskin dan meminta-minta kepada manusia dengan tangan mereka.\""},"3469":{"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا عَبْدُ الرَّحْمَنِ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ عَنْ عَامِرِ بْنِ سَعْدٍ عَنْ أَبِيهِ قَالَكَانَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَعُودُهُ وَهُوَ بِمَكَّةَ وَهُوَ يَكْرَهُ أَنْ يَمُوتَ بِالْأَرْضِ الَّذِي هَاجَرَ مِنْهَا قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ رَحِمَ اللَّهُ سَعْدَ ابْنَ عَفْرَاءَ أَوْ يَرْحَمُ اللَّهُ سَعْدَ ابْنَ عَفْرَاءَ وَلَمْ يَكُنْ لَهُ إِلَّا ابْنَةٌ وَاحِدَةٌ قَالَ يَا رَسُولَ اللَّهِ أُوصِي بِمَالِي كُلِّهِ قَالَ لَا قُلْتُ النِّصْفَ قَالَ لَا قُلْتُ فَالثُّلُثَ قَالَ الثُّلُثَ وَالثُّلُثُ كَثِيرٌ إِنَّكَ أَنْ تَدَعَ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَدَعَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ مَا فِي أَيْدِيهِمْأَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا أَبُو نُعَيْمٍ قَالَ حَدَّثَنَا مِسْعَرٌ عَنْ سَعْدِ بْنِ إِبْرَاهِيمَ قَالَ حَدَّثَنِي بَعْضُ آلِ سَعْدٍ قَالَ مَرِضَ سَعْدٌ فَدَخَلَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ يَا رَسُولَ اللَّهِ أُوصِي بِمَالِي كُلِّهِ قَالَ لَا وَسَاقَ الْحَدِيثَ","id":"Telah mengabarkan kepada kami ['Amru bin Ali] berkata; telah menceritakan kepada kami ['Abdurrahman] berkata; telah menceritakan kepada kami [Sufyan] dari [Sa'd bin Ibrahim] dari ['Amir bin Sa'd] dari [ayahnya] berkata, \"Nabi shallallahu 'alaihi wasallam menjenguknya dan saat beliau berada di Makkah. Dan ia tidak ingin meninggal di tanah yang darinya ia berhijrah. Nabi shallallahu 'alaihi wasallam lalu bersabda: 'Semoga Allah merahmati Sa'd bin 'Afra', dan ia hanya memiliki satu anak wanita. Ia berkata, \"Wahai Rasulullah, bolehkah aku berwasiat dengan seluruh hartaku?\" Beliau menjawab: \"Jangan.\" Aku tanyakan lagi, \"Bagaimana jika setengah?\" Beliau menjawab: \"Jangan.\" Aku tanyakan lagi, \"Bagaimana jika sepertiga?\" Beliau menjawab: \"Sepertiga, dan sepertiga itu banyak. Sesungguhnya engkau meninggalkan pewarismu dalam keadaan kaya lebih baik daripada engkau meninggalkan mereka dalam keadaan miskin dan meminta-minta kepada manusia apa yang ada di tangan mereka.\" Telah mengabarkan kepada kami [Ahmad bin Sulaiman] berkata; telah menceritakan kepada kami [Abu Nu'aim] berkata; telah menceritakan kepada kami [Mis'ar bin Ibrahim] berkata; telah menceritakan kepadaku [sebagian keluarga Sa'd] ia berkata, \"Saat Sa'd sakit, Rasulullah shallallahu 'alaihi wasallam masuk menjenguknya, [Sa'd] lalu berkata, \"Wahai Rasulullah, bolehkah aku berwasiat dengan seluruh hartaku?\" Beliau menjawab: 'Jangan.' Lalu ia menyebutkan hadits tersebut."},"3470":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ عَبْدِ الْعَظِيمِ الْعَنْبَرِيُّ قَالَ حَدَّثَنَا عَبْدُ الْكَبِيرِ بْنُ عَبْدِ الْمَجِيدِ قَالَ حَدَّثَنَا بُكَيْرُ بْنُ مِسْمَارٍ قَالَ سَمِعْتُ عَامِرَ بْنَ سَعْدٍ عَنْ أَبِيهِأَنَّهُ اشْتَكَى بِمَكَّةَ فَجَاءَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَلَمَّا رَآهُ سَعْدٌ بَكَى وَقَالَ يَا رَسُولَ اللَّهِ أَمُوتُ بِالْأَرْضِ الَّتِي هَاجَرْتُ مِنْهَا قَالَ لَا إِنْ شَاءَ اللَّهُ وَقَالَ يَا رَسُولَ اللَّهِ أُوصِي بِمَالِي كُلِّهِ فِي سَبِيلِ اللَّهِ قَالَ لَا قَالَ يَعْنِي بِثُلُثَيْهِ قَالَ لَا قَالَ فَنِصْفَهُ قَالَ لَا قَالَ فَثُلُثَهُ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ الثُّلُثَ وَالثُّلُثُ كَثِيرٌ إِنَّكَ أَنْ تَتْرُكَ بَنِيكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَتْرُكَهُمْ عَالَةً يَتَكَفَّفُونَ النَّاسَ","id":"Telah mengabarkan kepada kami [Al Abbas bin Abdul 'Azhim Al 'Anbari] berkata; telah menceritakan kepada kami [Abdul Kabir bin Abdul Majid] berkata; telah menceritakan kepada kami [Bukair bin Mismar] berkata; aku mendengar ['Amir bin Sa'd] dari [ayahnya], bahwa ia mengalami sakit di Makkah, kemudian Rasulullah shallallahu 'alaihi wasallam datang kepadanya. Kemudian setelah Sa'd melihatnya, ia menangis dan berkata, \"Wahai Rasulullah, apakah aku akan meninggal di negeri yang darinya aku berhijrah?\" Beliau menjawab: \"Tidak, insya Allah.\" Sa'd lalu berkata, \"Wahai Rasulullah, bolehkah aku berwasiat dengan seluruh hartaku di jalan Allah?\" Beliau menjawab: \"Jangan.\" Sa'd berkata lagi, \"Bagaimana jika dua pertiganya?\" Beliau menjawab: \"Jangan.\" Sa'd berkata lagi, \"Bagaimana jika setengahnya?\" Beliau menjawab: \"Jangan.\" Sa'd berkata lagi, \"Bagaimana jika sepertiganya?\" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sepertiga, dan sepertiga itu banyak. Sesungguhnya engkau meninggalkan anak-anakmu dalam keadaan kaya lebih baik daripada engkau meninggalkan mereka dalam keadaan miskin dan meminta-minta kepada manusia.\""},"3471":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا جَرِيرٌ عَنْ عَطَاءِ بْنِ السَّائِبِ عَنْ أَبِي عَبْدِ الرَّحْمَنِ عَنْ سَعْدِ بْنِ أَبِي وَقَّاصٍ قَالَعَادَنِي رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي مَرَضِي فَقَالَ أَوْصَيْتَ قُلْتُ نَعَمْ قَالَ بِكَمْ قُلْتُ بِمَالِي كُلِّهِ فِي سَبِيلِ اللَّهِ قَالَ فَمَا تَرَكْتَ لِوَلَدِكَ قُلْتُ هُمْ أَغْنِيَاءُ قَالَ أَوْصِ بِالْعُشْرِ فَمَا زَالَ يَقُولُ وَأَقُولُ حَتَّى قَالَ أَوْصِ بِالثُّلُثِ وَالثُّلُثُ كَثِيرٌ أَوْ كَبِيرٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah memberitakan kepada kami [Jarir] dari ['Atha bin As Saib] dari [Abu 'Abdurrahman] dari [Sa'd bin Abu Waqqash] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam mengunjungiku ketika aku sedang sakit. Beliau bersabda: \"Apakah engkau telah berwasiat?\" Aku menjawab, \"Ya.\" Beliau bertanya: \"Berapa?\" Aku jawab, \"Semuanya untuk di jalan Allah.\" Beliau bersabda: \"Apakah engkau tidak meninggalkan untuk anakmu?\" Aku jawab, \"Mereka orang-orang kaya.\" Beliau lalu bersabda: \"Berwasiatlah dengan sepersepuluh.\" Beliau terus saja bersabda dan aku menimpalinya hingga beliau pun bersabda: \"Berwasiatlah dengan sepertiga, dan sepertiga itu banyak atau besar.\""},"3472":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا وَكِيعٌ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ سَعْدٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَادَهُ فِي مَرَضِهِ فَقَالَ يَا رَسُولَ اللَّهِ أُوصِي بِمَالِي كُلِّهِ قَالَ لَا قَالَ فَالشَّطْرَ قَالَ لَا قَالَ فَالثُّلُثَ قَالَ الثُّلُثَ وَالثُّلُثُ كَثِيرٌ أَوْ كَبِيرٌ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah menceritakan kepada kami [Waki'] berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [ayahnya] dari [Sa'd], bahwa Nabi shallallahu 'alaihi wasallam mengunjunginya ketika ia sedang sakit. Ia lalu berkata, \"Wahai Rasulullah, bolehkah aku berwasiat dengan seluruh hartaku?\" Beliau menjawab: \"Tidak.\" Ia berkata lagi, \"Bagaimana jika setengah?\" Beliau menjawab: \"Tidak.\" Ia berkata lagi, \"Bagaimana jika sepertiga?\" Beliau menjawab: \"Sepertiga, dan sepertiga itu banyak atau besar.\""},"3473":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْوَلِيدِ الْفَحَّامُ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ رَبِيعَةَ قَالَ حَدَّثَنَا هِشَامُ بْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَتَى سَعْدًا يَعُودُهُ فَقَالَ لَهُ سَعْدٌ يَا رَسُولَ اللَّهِ أُوصِي بِثُلُثَيْ مَالِي قَالَ لَا قَالَ فَأُوصِي بِالنِّصْفِ قَالَ لَا قَالَ فَأُوصِي بِالثُّلُثِ قَالَ نَعَمْ الثُّلُثَ وَالثُّلُثُ كَثِيرٌ أَوْ كَبِيرٌ إِنَّكَ أَنْ تَدَعَ وَرَثَتَكَ أَغْنِيَاءَ خَيْرٌ مِنْ أَنْ تَدَعَهُمْ فُقَرَاءَ يَتَكَفَّفُونَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Walid Al Fahham] berkata; telah menceritakan kepada kami [Muhammad bin Rabi'ah] berkata; telah menceritakan kepada kami [Hisyam bin 'Urwah] dari [ayahnya] dari ['Aisyah], bahwa Rasulullah shallallahu 'alaihi wasallam menjenguk Sa'd, lalu ia berkata kepada beliau, \"Wahai Rasulullah, bolehkah aku berwasiat dengan dua pertiga hartaku?\" beliau menjawab: \"Jangan.\" Ia bertanya lagi, \"Bagaimana jika setengah hartaku?\" Beliau menjawab: \"Jangan.\" Ia bertanya lagi, \"Bagaimana dengan sepertiganya?\" Beliau menjawab: \"Ya. Sepertiga, dan sepertiga itu banyak atau besar. Sesungguhnya jika engkau tinggalkan pewarismu dengan kekayaan itu lebih baik daripada engkau tinggalkan mereka fakir dan meminta-minta.\""},"3474":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا سُفْيَانُ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ ابْنِ عَبَّاسٍ قَالَلَوْ غَضَّ النَّاسُ إِلَى الرُّبُعِ لِأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ الثُّلُثَ وَالثُّلُثُ كَثِيرٌ أَوْ كَبِيرٌ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Sufyan] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Ibnu Abbas] berkata, \"Orang-orang mengurangi wasiat hingga seperempat karena Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sepertiga, dan sepertiga itu banyak atau besar.\""},"3475":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى قَالَ حَدَّثَنَا حَجَّاجُ بْنُ الْمِنْهَالِ قَالَ حَدَّثَنَا هَمَّامٌ عَنْ قَتَادَةَ عَنْ يُونُسَ بْنِ جُبَيْرٍ عَنْ مُحَمَّدِ بْنِ سَعْدٍ عَنْ أَبِيهِ سَعْدِ بْنِ مَالِكٍأَنَّ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ جَاءَهُ وَهُوَ مَرِيضٌ فَقَالَ إِنَّهُ لَيْسَ لِي وَلَدٌ إِلَّا ابْنَةٌ وَاحِدَةٌ فَأُوصِي بِمَالِي كُلِّهِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَالَ فَأُوصِي بِنِصْفِهِ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا قَالَ فَأُوصِي بِثُلُثِهِ قَالَ الثُّلُثَ وَالثُّلُثُ كَثِيرٌ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] berkata; telah menceritakan kepada kami [Hajjaj bin Al Minhal] berkata; telah menceritakan kepada kami [Hammam] dari [Qatadah] dari [Yunus bin Jubair] dari [Muhammad bin Sa'd] dari ayahnya dari [Sa'd bin Malik], bahwa Nabi shallallahu 'alaihi wasallam datang kepadanya dan ia dalam keadaan sakit, kemudian ia berkata, \"Sesungguhnya aku tidak memiliki anak kecuali seorang anak wanita, maka apakah boleh aku berwasiat dengan seluruh hartaku?\" Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak.\" Ia bertanya lagi, \"Bolehkan aku berwasiat dengan setengah?\" Nabi shallallahu 'alaihi wasallam bersabda: \"Tidak.\" Ia bertanya lagi, \"Bagaimana jika dengan sepertiga?\" Beliau bersabda: \"Sepertiga, dan sepertiga itu banyak.\""},"3476":{"ar":"أَخْبَرَنَا الْقَاسِمُ بْنُ زَكَرِيَّا بْنِ دِينَارٍ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ شَيْبَانَ عَنْ فِرَاسٍ عَنْ الشَّعْبِيِّ قَالَ حَدَّثَنِي جَابِرُ بْنُ عَبْدِ اللَّهِأَنَّ أَبَاهُ اسْتُشْهِدَ يَوْمَ أُحُدٍ وَتَرَكَ سِتَّ بَنَاتٍ وَتَرَكَ عَلَيْهِ دَيْنًا فَلَمَّا حَضَرَ جِدَادُ النَّخْلِ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ قَدْ عَلِمْتَ أَنَّ وَالِدِي اسْتُشْهِدَ يَوْمَ أُحُدٍ وَتَرَكَ دَيْنًا كَثِيرًا وَإِنِّي أُحِبُّ أَنْ يَرَاكَ الْغُرَمَاءُ قَالَ اذْهَبْ فَبَيْدِرْ كُلَّ تَمْرٍ عَلَى نَاحِيَةٍ فَفَعَلْتُ ثُمَّ دَعَوْتُهُ فَلَمَّا نَظَرُوا إِلَيْهِ كَأَنَّمَا أُغْرُوا بِي تِلْكَ السَّاعَةَ فَلَمَّا رَأَى مَا يَصْنَعُونَ أَطَافَ حَوْلَ أَعْظَمِهَا بَيْدَرًا ثَلَاثَ مَرَّاتٍ ثُمَّ جَلَسَ عَلَيْهِ ثُمَّ قَالَ ادْعُ أَصْحَابَكَ فَمَا زَالَ يَكِيلُ لَهُمْ حَتَّى أَدَّى اللَّهُ أَمَانَةَ وَالِدِي وَأَنَا رَاضٍ أَنْ يُؤَدِّيَ اللَّهُ أَمَانَةَ وَالِدِي لَمْ تَنْقُصْ تَمْرَةً وَاحِدَةً","id":"Telah mengabarkan kepada kami [Al Qasim bin Zakaria bin Dinar] berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Syaiban] dari [Firas] dari [Asy Sya'bi] ia berkata; telah menceritakan kepadaku [Jabir bin Abdullah], bahwa ayahnya syahid ketika perang Uhud dan meninggalkan enam anak perempuan dan tanggungan hutang. Ketika datang masa panen kurma, aku menemui Rasulullah shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, anda mengetahui bahwa ayahku syahid pada perang Uhud dan ia meninggalkan hutang yang banyak, dan aku ingin agar orang-orang yang memberi hutang melihatmu, beliau bersabda: \"Pergilah dan kumpulkan kurma-kurma di setiap ujungnya, \" setelah melakukannya kemudian aku memanggil beliau, ketika mereka melihat beliau seakan-akan mereka terus memintaku saat itu, ketika beliau melihat apa yang mereka perbuat beliau mengelilingkan tempat menebah di sekitar kumpulan kurma yang paling banyak, sebanyak tiga kali, lalu beliau duduk di atasnya dan bersabda: \"Panggillah para sahabatmu, \" maka beliau masih menakar untuk mereka hingga Allah menunaikan amanat ayahku dan aku ridla jika Allah menunaikan amanat ayahku, dan tidak mengurangi satu kurma pun.\""},"3477":{"ar":"أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ مُحَمَّدِ بْنِ سَلَّامٍ قَالَ حَدَّثَنَا إِسْحَقُ وَهُوَ الْأَزْرَقُ قَالَ حَدَّثَنَا زَكَرِيَّا عَنْ الشَّعْبِيِّ عَنْ جَابِرٍأَنَّ أَبَاهُ تُوُفِّيَ وَعَلَيْهِ دَيْنٌ فَأَتَيْتُ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنَّ أَبِي تُوُفِّيَ وَعَلَيْهِ دَيْنٌ وَلَمْ يَتْرُكْ إِلَّا مَا يُخْرِجُ نَخْلُهُ وَلَا يَبْلُغُ مَا يُخْرِجُ نَخْلُهُ مَا عَلَيْهِ مِنْ الدَّيْنِ دُونَ سِنِينَ فَانْطَلِقْ مَعِي يَا رَسُولَ اللَّهِ لِكَيْ لَا يُفْحِشَ عَلَيَّ الْغُرَّامُ فَأَتَى رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدُورُ بَيْدَرًا بَيْدَرًا فَسَلَّمَ حَوْلَهُ وَدَعَا لَهُ ثُمَّ جَلَسَ عَلَيْهِ وَدَعَا الْغُرَّامَ فَأَوْفَاهُمْ وَبَقِيَ مِثْلُ مَا أَخَذُوا","id":"Telah mengabarkan kepada kami ['Abdurrahman bin Muhammad bin Sallam] berkata; telah menceritakan kepada kami [Ishaq] -yaitu Al Azraq- berkata; telah menceritakan kepada kami [Zakaria] dari [Asy Sya'bi] dari [Jabir], bahwa ayahnya meninggal dan memiliki hutang. Kemudian aku datang kepada Nabi shallallahu 'alaihi wasallam dan berkata, \"Wahai Rasulullah, sesungguhnya ayahku meninggal dan memiliki hutang. Dan ia tidak meninggalkan kecuali apa yang dihasilkan oleh pohon kurma, dan apa yang dihasilkan oleh pohon kurma itu tidak mencukupi untuk membayar hutangnya, kecuali hanya enam puluh sha'. Maka pergilah bersamaku wahai Rasulullah, agar para pemilik piutang tidak bertindak keji kepadaku.\" Maka Rasulullah shallallahu 'alaihi wasallam datang dan memutar satu demi satu tempat menebah. Lalu beliau mengucapkan salam di sekitarnya dan berdoa untuknya, kemudian beliau duduk di atasnya serta memanggil para pemilik piutang dan tersisa seperti apa yang telah mereka ambil.\""},"3478":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ مُغِيرَةَ عَنْ الشَّعْبِيِّ عَنْ جَابِرٍ قَالَتُوُفِّيَ عَبْدُ اللَّهِ بْنُ عَمْرِو بْنِ حَرَامٍ قَالَ وَتَرَكَ دَيْنًا فَاسْتَشْفَعْتُ بِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ عَلَى غُرَمَائِهِ أَنْ يَضَعُوا مِنْ دَيْنِهِ شَيْئًا فَطَلَبَ إِلَيْهِمْ فَأَبَوْا فَقَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اذْهَبْ فَصَنِّفْ تَمْرَكَ أَصْنَافًا الْعَجْوَةَ عَلَى حِدَةٍ وَعِذْقَ ابْنِ زَيْدٍ عَلَى حِدَةٍ وَأَصْنَافَهُ ثُمَّ ابْعَثْ إِلَيَّ قَالَ فَفَعَلْتُ فَجَاءَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَلَسَ فِي أَعْلَاهُ أَوْ فِي أَوْسَطِهِ ثُمَّ قَالَ كِلْ لِلْقَوْمِ قَالَ فَكِلْتُ لَهُمْ حَتَّى أَوْفَيْتُهُمْ ثُمَّ بَقِيَ تَمْرِي كَأَنْ لَمْ يَنْقُصْ مِنْهُ شَيْءٌ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Jarir] dari [Mughirah] dari [Asy Sya'bi] dari [Jabir] berkata, \"Abdullah bin 'Amru bin Haran meninggal dan meninggalkan hutang, kemudian aku meminta bantuan Rasulullah shallallahu 'alaihi wasallam menghadapi para pemilik piutang agar mereka menggugurkan sebagian hutangnya. Kemudian Jabir meminta dari mereka namun mereka menolak. Kemudian Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Pergilah kemudian kelompokkan kurmamu menjadi beberapa jenis, 'Ajwa` tersendiri, 'Idzq bin Zaid tersendiri dan jenis-jenisnya. Kemudian kirimkan kepadaku utusan kepadaku.\" Jabir berkata, \"Kemudian aku melakukannya, dan Rasulullah shallallahu 'alaihi wasallam datang dan duduk di atasnya atau di tengahnya kemudian bersabda: \"Takarlah untuk orang-orang tersebut.\" Jabir berkata, \"Kemudian aku menakar untuk mereka hingga memenuhi hak mereka, kemudian tersisa kurmaku dan seakan-akan tidak berkurang sedikitpun.\""},"3479":{"ar":"أَخْبَرَنَا إِبْرَاهِيمُ بْنُ يُونُسَ بْنِ مُحَمَّدٍ حَرَمِيٌّ قَالَ حَدَّثَنَا أَبِي قَالَ حَدَّثَنَا حَمَّادٌ عَنْ عَمَّارِ بْنِ أَبِي عَمَّارٍ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَكَانَ لِيَهُودِيٍّ عَلَى أَبِي تَمْرٌ فَقُتِلَ يَوْمَ أُحُدٍ وَتَرَكَ حَدِيقَتَيْنِ وَتَمْرُ الْيَهُودِيِّ يَسْتَوْعِبُ مَا فِي الْحَدِيقَتَيْنِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ أَنْ تَأْخُذَ الْعَامَ نِصْفَهُ وَتُؤَخِّرَ نِصْفَهُ فَأَبَى الْيَهُودِيُّ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَلْ لَكَ أَنْ تَأْخُذَ الْجِدَادَ فَآذِنِّي فَآذَنْتُهُ فَجَاءَ هُوَ وَأَبُو بَكْرٍ فَجَعَلَ يُجَدُّ وَيُكَالُ مِنْ أَسْفَلِ النَّخْلِ وَرَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَدْعُو بِالْبَرَكَةِ حَتَّى وَفَيْنَاهُ جَمِيعَ حَقِّهِ مِنْ أَصْغَرِ الْحَدِيقَتَيْنِ فِيمَا يَحْسِبُ عَمَّارٌ ثُمَّ أَتَيْتُهُمْ بِرُطَبٍ وَمَاءٍ فَأَكَلُوا وَشَرِبُوا ثُمَّ قَالَ هَذَا مِنْ النَّعِيمِ الَّذِي تُسْأَلُونَ عَنْهُ","id":"Telah mengabarkan kepada kami [Ibrahim bin Yunus bin Muhammad Harami] berkata; telah menceritakan kepada kami [Bapakku] berkata; telah menceritakan kepada kami [Hammad] dari ['Ammar bin Abu 'Ammar] dari [Jabir bin Abdullah] berkata, \"Dahulu seorang Yahudi memiliki piutang atas ayahku, kemudian ayahku terbunuh pada perang Uhud dan meninggalkan dua kebun. Sedangkan (untuk membayar) kurma orang Yahudi menghabiskan apa yang ada di dalam kedua kebun tersebut. Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah engkau bisa mengambil pada tahun ini setengahnya dan menunda setengahnya.\" Lalu orang Yahudi tersebut menolak, kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Apakah engkau bisa mengambil potongan pohon kurma kemudian memberitahuku?\" Kemudian aku memberitahukan kepada beliau hingga beliau pun datang bersama Abu Bakr. Kemudian mulailah dipotong dan ditakar dari bawah pohon kurma, sedang Rasulullah shallallahu 'alaihi wasallam mendoakan agar mendapatkan berkah hingga kami dapat memenuhi seluruh haknya dari kebun yang paling kecil (sebagaimana yang diperkirakan oleh 'Ammar), kemudian aku menemui mereka dengan membawa ruthab (kurma segar) dan air, lalu mereka makan dan minum. Kemudian beliau bersabda: \"Ini adalah kenikmatan yang (akan) ditanyakan kepada kalian.\""},"3480":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ الْمُثَنَّى عَنْ حَدِيثِ عَبْدِ الْوَهَّابِ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ عَنْ وَهْبِ بْنِ كَيْسَانَ عَنْ جَابِرِ بْنِ عَبْدِ اللَّهِ قَالَتُوُفِّيَ أَبِي وَعَلَيْهِ دَيْنٌ فَعَرَضْتُ عَلَى غُرَمَائِهِ أَنْ يَأْخُذُوا الثَّمَرَةَ بِمَا عَلَيْهِ فَأَبَوْا وَلَمْ يَرَوْا فِيهِ وَفَاءً فَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَذَكَرْتُ ذَلِكَ لَهُ قَالَ إِذَا جَدَدْتَهُ فَوَضَعْتَهُ فِي الْمِرْبَدِ فَآذِنِّي فَلَمَّا جَدَدْتُهُ وَوَضَعْتُهُ فِي الْمِرْبَدِ أَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَجَاءَ وَمَعَهُ أَبُو بَكْرٍ وَعُمَرُ فَجَلَسَ عَلَيْهِ وَدَعَا بِالْبَرَكَةِ ثُمَّ قَالَ ادْعُ غُرَمَاءَكَ فَأَوْفِهِمْ قَالَ فَمَا تَرَكْتُ أَحَدًا لَهُ عَلَى أَبِي دَيْنٌ إِلَّا قَضَيْتُهُ وَفَضَلَ لِي ثَلَاثَةَ عَشَرَ وَسْقًا فَذَكَرْتُ ذَلِكَ لَهُ فَضَحِكَ وَقَالَ ائْتِ أَبَا بَكْرٍ وَعُمَرَ فَأَخْبِرْهُمَا ذَلِكَ فَأَتَيْتُ أَبَا بَكْرٍ وَعُمَرَ فَأَخْبَرْتُهُمَا فَقَالَا قَدْ عَلِمْنَا إِذْ صَنَعَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَا صَنَعَ أَنَّهُ سَيَكُونُ ذَلِكَ","id":"Telah mengabarkan kepada kami [Muhammad bin Al Mutsanna] dari [Abdul Wahhab] berkata; telah menceritakan kepada kami ['Ubaidullah] dari [Wahb bin Kaisan] dari [Jabir bin Abdullah] berkata, \"Ayahku meninggal dan beliau memiliki hutang. Kemudian aku menawarkan kepada para pemilik piutang agar mengambil buah sesuai yang ada padanya. Namun mereka tidak melihat hal itu dapat memenuhi hutang. Kemudian aku datang kepada Rasulullah shallallahu 'alaihi wasallam dan menyebutkan hal tersebut kepada beliau. Beliau bersabda: \"Apabila engkau telah memotong kurma dan meletakkannya pada tempat menebah kurma, maka beritahu aku.\" Kemudian, setelah aku memotongnya dan meletakkannya pada tempat penebahan kurma, aku datang kepada Rasulullah shallallahu 'alaihi wasallam. Beliau lantas datang bersama dengan Abu Bakr dan Umar. Lalu beliau duduk di atasnya dan mendoakan agar mendapatkan berkah. Kemudian beliau bersabda: \"Panggillah para pemilik piutangmu, dan penuhi hak mereka.\" Aku tidak meninggalkan seorangpun yang memiliki hak atas ayahku kecuali telah aku bayar haknya dan tersisa untukku tiga belas wasaq. Kemudian aku sebutkan hal tersebut kepada beliau, maka beliau tertawa dan bersabda: \"Datanglah kepada Abu Bakr dan Umar, kemudian kabarkan hal tersebut kepada mereka.\" Kemudian aku mendatangi Abu Bakr dan Umar dan mengabarkan hal tersebut kepada mereka. Lalu mereka berkata, \"Sungguh, kami telah mengetahui ketika Rasulullah shallallahu 'alaihi wasallam melakukan apa yang beliau lakukan bahwa hal tersebut akan terjadi.\""},"3481":{"ar":"أَخْبَرَنَا قُتَيْبَةُ بْنُ سَعِيدٍ قَالَ حَدَّثَنَا أَبُو عَوَانَةَ عَنْ قَتَادَةَ عَنْ شَهْرِ بْنِ حَوْشَبٍ عَنْ عَبْدِ الرَّحْمَنِ بْنِ غُنْمٍ عَنْ عَمْرِو بْنِ خَارِجَةَ قَالَخَطَبَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ اللَّهَ قَدْ أَعْطَى كُلَّ ذِي حَقٍّ حَقَّهُ وَلَا وَصِيَّةَ لِوَارِثٍ","id":"Telah mengabarkan kepada kami [Qutaibah bin Sa'id] berkata; telah menceritakan kepada kami [Abu 'Awanah] dari [Qatadah] dari [Syahr bin Hausyab] dari ['Abdurrahman bin Ghunm] dan ['Amru bin Kharijah] berkata, \"Rasulullah shallallahu 'alaihi wasallam berkhutbah kemudian bersabda: \"Sungguh, Allah telah memberikan hak kepada setiap yang berhak menerimanya, dan tidak ada wasiat bagi pewaris.\""},"3482":{"ar":"أَخْبَرَنَا إِسْمَعِيلُ بْنُ مَسْعُودٍ قَالَ حَدَّثَنَا خَالِدٌ قَالَ حَدَّثَنَا شُعْبَةُ قَالَ حَدَّثَنَا قَتَادَةُ عَنْ شَهْرِ بْنِ حَوْشَبٍ أَنَّ ابْنَ غُنْمٍ ذَكَرَ أَنَّ ابْنَ خَارِجَةَ ذَكَرَ لَهُأَنَّهُ شَهِدَ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَخْطُبُ النَّاسَ عَلَى رَاحِلَتِهِ وَإِنَّهَا لَتَقْصَعُ بِجَرَّتِهَا وَإِنَّ لُعَابَهَا لَيَسِيلُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي خُطْبَتِهِ إِنَّ اللَّهَ قَدْ قَسَّمَ لِكُلِّ إِنْسَانٍ قِسْمَهُ مِنْ الْمِيرَاثِ فَلَا تَجُوزُ لِوَارِثٍ وَصِيَّةٌ","id":"Telah mengabarkan kepada kami [Isma'il bin Mas'ud] berkata; telah menceritakan kepada kami [Khalid] berkata; telah menceritakan kepada kami [Syu'bah] berkata; telah menceritakan kepada kami [Qatadah] dari [Syahr bin Hausyab] bahwa [Ibnu Ghunm] menyebutkan bahwa [Ibnu Kharijah] menyebutkan kepadanya, bahwa ia telah menyaksikan Rasulullah shallallahu 'alaihi wasallam berkhutbah kepada manusia di atas kendaraan beliau, dan sungguh binatang tersebut menelan makanan yang keluar dari perutnya dan air liurnya mengalir. Kemudian dalam khutbahnya Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, Allah telah memberikan hak kepada setiap yang berhak menerimanya, dan tidak ada wasiat bagi pewaris.\""},"3483":{"ar":"أَخْبَرَنَا عُتْبَةُ بْنُ عَبْدِ اللَّهِ الْمَرْوَزِيُّ قَالَ أَنْبَأَنَا عَبْدُ اللَّهِ بْنُ الْمُبَارَكِ قَالَ أَنْبَأَنَا إِسْمَعِيلُ بْنُ أَبِي خَالِدٍ عَنْ قَتَادَةَ عَنْ عَمْرِو بْنِ خَارِجَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ اللَّهَ عَزَّ اسْمُهُ قَدْ أَعْطَى كُلَّ ذِي حَقٍّ حَقَّهُ وَلَا وَصِيَّةَ لِوَارِثٍ","id":"Telah mengabarkan kepada kami ['Utbah bin Abdullah Al Marwazi] berkata; telah memberitakan kepada kami [Abdullah bin Al Mubarak] berkata; telah memberitakan kepada kami [Isma'il bin Abu Khalid] dari [Qatadah] dari ['Amru bin Kharijah] ia berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Sungguh, Allah telah memberikan hak kepada setiap yang berhak menerimanya, dan tidak ada wasiat bagi pewaris.\""},"3484":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ حَدَّثَنَا جَرِيرٌ عَنْ عَبْدِ الْمَلِكِ بْنِ عُمَيْرٍ عَنْ مُوسَى بْنِ طَلْحَةَ عَنْ أَبِي هُرَيْرَةَ قَالَلَمَّا نَزَلَتْ{ وَأَنْذِرْ عَشِيرَتَ��َ الْأَقْرَبِينَ }دَعَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُرَيْشًا فَاجْتَمَعُوا فَعَمَّ وَخَصَّ فَقَالَ يَا بَنِي كَعْبِ بْنِ لُؤَيٍّ يَا بَنِي مُرَّةَ بْنِ كَعْبٍ يَا بَنِي عَبْدِ شَمْسٍ وَيَا بَنِي عَبْدِ مَنَافٍ وَيَا بَنِي هَاشِمٍ وَيَا بَنِي عَبْدِ الْمُطَّلِبِ أَنْقِذُوا أَنْفُسَكُمْ مِنْ النَّارِ وَيَا فَاطِمَةُ أَنْقِذِي نَفْسَكِ مِنْ النَّارِ إِنِّي لَا أَمْلِكُ لَكُمْ مِنْ اللَّهِ شَيْئًا غَيْرَ أَنَّ لَكُمْ رَحِمًا سَأَبُلُّهَا بِبِلَالِهَا","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah menceritakan kepada kami [Jarir] dari [Abdul Malik bin 'Umair] dari [Musa bin Thalhah] dari [Abu Hurairah] berkata, \"Tatkala turun ayat: '(dan peringatkan keluargamu yang paling dekat) ' (Qs. Asy Syu'araa': 214), Rasulullah shallallahu 'alaihi wasallam menyeru kepada orang-orang Quraisy kemudian mereka berkumpul, lalu beliau berbicara kepada orang umum dan khusus. Beliau bersabda: \"Wahai Bani Abdul Muththalib, selamatkan diri kalian dari Neraka. Wahai Fatimah, selamatkan dirimu dari Neraka, sesungguhnya aku tidak dapat menolong kalian sedikitpun dari Allah, hanya saja kalian memiliki kekerabatan yang akan aku sambung.\""},"3485":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ سُلَيْمَانَ قَالَ حَدَّثَنَا عُبَيْدُ اللَّهِ بْنُ مُوسَى قَالَ أَنْبَأَنَا إِسْرَائِيلُ عَنْ مُعَاوِيَةَ وَهُوَ ابْنُ إِسْحَقَ عَنْ مُوسَى بْنِ طَلْحَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا بَنِي عَبْدِ مَنَافٍ اشْتَرُوا أَنْفُسَكُمْ مِنْ رَبِّكُمْ إِنِّي لَا أَمْلِكُ لَكُمْ مِنْ اللَّهِ شَيْئًا يَا بَنِي عَبْدِ الْمُطَّلِبِ اشْتَرُوا أَنْفُسَكُمْ مِنْ رَبِّكُمْ إِنِّي لَا أَمْلِكُ لَكُمْ مِنْ اللَّهِ شَيْئًا وَلَكِنْ بَيْنِي وَبَيْنَكُمْ رَحِمٌ أَنَا بَالُّهَا بِبِلَالِهَا","id":"Telah mengabarkan kepada kami [Ahmad bin Sulaiman] berkata; telah menceritakan kepada kami ['Ubaidullah bin Musa] berkata; telah memberitakan kepada kami [Isra'il] dari [Mu'awiyah] -yaitu Ibnu Ishaq- dari [Musa bin Thalhah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Bani Abdu Manaf, belilah diri kalian dari Tuhan kalian, sesungguhnya aku tidak mampu menolong kalian sedikitpun dari Allah. Wahai Bani Abdul Muththalib, belilah diri kalian dari Tuhan kalian, sesungguhnya aku tidak mampu menolong kalian sedikitpun dari Allah. Akan tetapi antara diriku dan kalian terdapat hubungan kekerabatan dan aku akan menyambungnya.\""},"3486":{"ar":"أَخْبَرَنَا سُلَيْمَانُ بْنُ دَاوُدَ عَنْ ابْنِ وَهْبٍ قَالَ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ عَنْ أَبِي هُرَيْرَةَ قَالَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُنْزِلَ عَلَيْهِ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }قَالَ يَا مَعْشَرَ قُرَيْشٍ اشْتَرُوا أَنْفُسَكُمْ مِنْ اللَّهِ لَا أُغْنِي عَنْكُمْ مِنْ اللَّهِ شَيْئًا يَا بَنِي عَبْدِ الْمُطَّلِبِ لَا أُغْنِي عَنْكُمْ مِنْ اللَّهِ شَيْئًا يَا عَبَّاسُ بْنَ عَبْدِ الْمُطَّلِبِ لَا أُغْنِي عَنْكَ مِنْ اللَّهِ شَيْئًا يَا صَفِيَّةُ عَمَّةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أُغْنِي عَنْكِ مِنْ اللَّهِ شَيْئًا يَا فَاطِمَةُ بِنْتَ مُحَمَّدٍ سَلِينِي مَا شِئْتِ لَا أُغْنِي عَنْكِ مِنْ اللَّهِ شَيْئًا","id":"Telah mengabarkan kepada kami [Sulaiman bin Daud] dari [Ibnu Wahb] berkata; telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] berkata; telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] dari [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam bersabda ketika diturunkan kepadanya ayat: '(dan peringatkanlah keluargamu yang terdekat) ' (Qs. Asy Syu'araa': 214), beliau katakan: \"Wahai orang-orang Quraisy, belilah diri kalian dari Allah, aku tidak mampu menolong kalian sedikitpun dari Allah. Wahai Bani Abdul Muththalib, aku tidak mampu menolong kalian sedikitpun dari Allah. Wahai Abbas bin Abdul Muththalib, aku tidak mampu menolong kamu sedikitpun dari Allah. Wahai Shafiyah bibi Rasulullah, aku tidak mampu menolong kamu sedikitpun dari Allah. Wahai Fatimah binti Muhammad, mintalah kepadaku apa yang engkau inginkan, aku tidak mampu menolong kamu sedikitpun dari Allah.\""},"3487":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ خَالِدٍ قَالَ حَدَّثَنَا بِشْرُ بْنُ شُعَيْبٍ عَنْ أَبِيهِ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي سَعِيدُ بْنُ الْمُسَيَّبِ وَأَبُو سَلَمَةَ بْنُ عَبْدِ الرَّحْمَنِ أَنَّ أَبَا هُرَيْرَةَ قَالَقَامَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ حِينَ أُنْزِلَ عَلَيْهِ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }فَقَالَ يَا مَعْشَرَ قُرَيْشٍ اشْتَرُوا أَنْفُسَكُمْ مِنْ اللَّهِ لَا أُغْنِي عَنْكُمْ مِنْ اللَّهِ شَيْئًا يَا بَنِي عَبْدِ مَنَافٍ لَا أُغْنِي عَنْكُمْ مِنْ اللَّهِ شَيْئًا يَا عَبَّاسُ بْنَ عَبْدِ الْمُطَّلِبِ لَا أُغْنِي عَنْكَ مِنْ اللَّهِ شَيْئًا يَا صَفِيَّةُ عَمَّةَ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَا أُغْنِي عَنْكِ مِنْ اللَّهِ شَيْئًا يَا فَاطِمَةُ سَلِينِي مَا شِئْتِ لَا أُغْنِي عَنْكِ مِنْ اللَّهِ شَيْئًا","id":"Telah mengabarkan kepada kami [Muhammad bin Khalid] berkata; telah menceritakan kepada kami [Bisyr bin Syu'aib] dari [ayahnya] dari [Az Zuhri] berkata; telah mengabarkan kepadaku [Sa'id bin Al Musayyab] dan [Abu Salamah bin 'Abdurrahman] bahwa [Abu Hurairah] berkata, \"Rasulullah shallallahu 'alaihi wasallam berdiri ketika diturunkan kepadanya ayat: '(dan peringatkan keluargamu yang terdekat) ' (Qs. Asy Syu'araa': 214), kemudian bersabda: \"Wahai orang-orang Quraisy, belilah diri kalian dari Allah, aku tidak mampu menolong kalian sedikitpun dari Allah. Wahai Bani Abdul Muththalib, aku tidak mampu menolong kalian sedikitpun dari Allah. Wahai Abbas bin Abdul Muththalib, aku tidak mampu menolong kamu sedikitpun dari Allah. Wahai Shafiyah bibi Rasulullah, aku tidak mampu menolong kamu sedikitpun dari Allah. wahai Fatimah binti Muhammad mintalah kepadaku apa yang engkau inginkan, aku tidak mampu menolong kamu sedikitpun dari Allah.\""},"3488":{"ar":"أَخْبَرَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ قَالَ أَنْبَأَنَا أَبُو مُعَاوِيَةَ قَالَ حَدَّثَنَا هِشَامٌ وَهُوَ ابْنُ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَ قَالَتْلَمَّا نَزَلَتْ هَذِهِ الْآيَةُ{ وَأَنْذِرْ عَشِيرَتَكَ الْأَقْرَبِينَ }قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ يَا فَاطِمَةُ ابْنَةَ مُحَمَّدٍ يَا صَفِيَّةُ بِنْتَ عَبْدِ الْمُطَّلِبِ يَا بَنِي عَبْدِ الْمُطَّلِبِ لَا أُغْنِي عَنْكُمْ مِنْ اللَّهِ شَيْئًا سَلُونِي مِنْ مَالِي مَا شِئْتُمْ","id":"Telah mengabarkan kepada kami [Ishaq bin Ibrahim] berkata; telah memberitakan kepada kami [Abu Mu'awiyah] berkata; telah menceritakan kepada kami [Hisyam] -yaitu Ibnu 'Urwah- dari [ayahnya] dari [Aisyah] berkata, \"Tatkala turun ayat ini: '(dan peringatkan keluargamu terdekat) ' (Qs. Asy Syu'araa': 214), Rasulullah shallallahu 'alaihi wasallam bersabda: \"Wahai Fatimah binti Muhammad, wahai Shafiyah binti Abdul Muththalib, wahai Abdul Muththalib, aku tidak mampu menolong kalian sedikitpun dari Allah, mintalah dari hartaku apa yang kalian suka.\""},"3489":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ سَلَمَةَ قَالَ حَدَّثَنَا ابْنُ الْقَاسِمِ عَنْ مَالِكٍ عَنْ هِشَامِ بْنِ عُرْوَةَ عَنْ أَبِيهِ عَنْ عَائِشَةَأَنَّ رَجُلًا قَالَ لِرَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أُمِّي افْتُلِتَتْ نَفْسُهَا وَإِنَّهَا لَوْ تَكَلَّمَتْ تَصَدَّقَتْ أَفَأَتَصَدَّقُ عَنْهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ فَتَصَدَّقَ عَنْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Salamah] berkata; telah menceritakan kepada kami [Ibnu Al Qasim] dari [Malik] dari [Hisyam bin 'Urwah] dari [ayahnya] dari [Aisyah], bahwa seorang laki-laki berkata kepada Rasulullah shallallahu 'alaihi wasallam, \"Sesungguhnya ibuku telah meninggal secara tiba-tiba, sekiranya dapat bicara niscaya ia akan bersedekah. Apakah aku boleh bersedekah untuknya?\" Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Ya, bersedekahlah untuknya.\""},"3490":{"ar":"أَنْبَأَنَا الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ ابْنِ الْقَاسِمِ عَنْ مَالِكٍ عَنْ سَعِيدِ بْنِ عَمْرِو بْنِ شُرَحْبِيلَ بْنِ سَعِيدِ بْنِ سَعْدِ بْنِ عُبَادَةَ عَنْ أَبِيهِ عَنْ جَدِّهِ قَالَخَرَجَ سَعْدُ بْنُ عُبَادَةَ مَعَ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي بَعْضِ مَغَازِيهِ وَحَضَرَتْ أُمَّهُ الْوَفَاةُ بِالْمَدِينَةِ فَقِيلَ لَهَا أَوْصِي فَقَالَتْ فِيمَ أُوصِي الْمَالُ مَالُ سَعْدٍ فَتُوُفِّيَتْ قَبْلَ أَنْ يَقْدَمَ سَعْدٌ فَلَمَّا قَدِمَ سَعْدٌ ذُكِرَ ذَلِكَ لَهُ فَقَالَ يَا رَسُولَ اللَّهِ هَلْ يَنْفَعُهَا أَنْ أَتَصَدَّقَ عَنْهَا فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ نَعَمْ فَقَالَ سَعْدٌ حَائِطُ كَذَا وَكَذَا صَدَقَةٌ عَنْهَا لِحَائِطٍ سَمَّاهُ","id":"Telah memberitakan kepada kami [Al Harits bin Miskin] dia membacakannya dan aku yang mendengar, dari [Ibnu Al Qasim] dari [Malik] dari [Sa'id bin 'Amru bin Syurahbil bin Sa'id bin Sa'd bin 'Ubadah] dari [ayahnya] dari [kakeknya] berkata, \"Sa'd bin 'Ubadah keluar bersama Nabi shallallahu 'alaihi wasallam pada sebagian peperangan, dan ibunya menghadapi kematian di Madinah. Lalu dikatakan kepadanya, \"Berwasiatlah.\" Kemudian ia balik bertanya, \"Apa yang aku wasiatkan? Harta adalah hartanya Sa'd.\" Kemudian ia meninggal sebelum Sa'd datang, maka tatkala Sa'd datang hal tersebut diceritakan kepadanya, Sa'd pun berkata, \"Wahai Rasulullah, apakah bermanfaat baginya apabila aku bersedekah untuknya?\" Nabi shallallahu 'alaihi wasallam lantas bersabda: \"Ya.\" Kemudian Sa'd berkata, \"Kebun ini dan ini adalah sedekah untuknya.\""},"3491":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ حَدَّثَنَا إِسْمَعِيلُ قَالَ حَدَّثَنَا الْعَلَاءُ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَالَ إِذَا مَاتَ الْإِنْسَانُ انْقَطَعَ عَمَلُهُ إِلَّا مِنْ ثَلَاثَةٍ مِنْ صَدَقَةٍ جَارِيَةٍ وَعِلْمٍ يُنْتَفَعُ بِهِ وَوَلَدٍ صَالِحٍ يَدْعُو لَهُ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] berkata; telah menceritakan kepada kami [Isma'il] berkata; telah menceritakan kepada kami [Al 'Ala] dari [ayahnya] dari [Abu Hurairah], bahwa Rasulullah shallallahu 'alaihi wasallam bersabda: \"Apabila manusia meninggal maka amalnya terputus kecuali dari tiga perkara; sedekah jariyah, ilmu yang bermanfaat dan anak Shalih yang mendoakannya.\""},"3492":{"ar":"أَخْبَرَنَا عَلِيُّ بْنُ حُجْرٍ قَالَ أَنْبَأَنَا إِسْمَعِيلُ عَنْ الْعَلَاءِ عَنْ أَبِيهِ عَنْ أَبِي هُرَيْرَةَأَنَّ رَجُلًا قَالَ لِلنَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أَبِي مَاتَ وَتَرَكَ مَالًا وَلَمْ يُوصِ فَهَلْ يُكَفِّرُ عَنْهُ أَنْ أَتَصَدَّقَ عَنْهُ قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Ali bin Hujr] berkata; telah memberitakan kepada kami [Isma'il] dari [Al 'Ala] dari [ayahnya] dari [Abu Hurairah], bahwa seseorang berkata kepada Nabi shallallahu 'alaihi wasallam, \"Sesungguhnya ayahku wafat dengan meninggalkan harta dan belum berwasiat. Apakah aku dapat menutupinya dengan bersedekah untuknya?\" Maka beliau bersabda: \"Ya.\""},"3493":{"ar":"أَخْبَرَنَا مُوسَى بْنُ سَعِيدٍ قَالَ حَدَّثَنَا هِشَامُ بْنُ عَبْدِ الْمَلِكِ قَالَ حَدَّثَنَا حَمَّادُ بْنُ سَلَمَةَ عَنْ مُحَمَّدِ بْنِ عَمْرٍو عَنْ أَبِي سَلَمَةَ عَنْ الشَّرِيدِ بْنِ سُوَيْدٍ الثَّقَفِيِّ قَالَأَتَيْتُ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنَّ أُمِّي أَوْصَتْ أَنْ تُعْتَقَ عَنْهَا رَقَبَةٌ وَإِنَّ عِنْدِي جَارِيَةً نُوبِيَّةً أَفَيُجْزِئُ عَنِّي أَنْ أُعْتِقَهَا عَنْهَا قَالَ ائْتِنِي بِهَا فَأَتَيْتُهُ بِهَا فَقَالَ لَهَا النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ مَنْ رَبُّكِ قَالَتْ اللَّهُ قَالَ مَنْ أَنَا قَالَتْ أَنْتَ رَسُولُ اللَّهِ قَالَ فَأَعْتِقْهَا فَإِنَّهَا مُؤْمِنَةٌ","id":"Telah mengabarkan kepada kami [Musa bin Sa'id] berkata; telah menceritakan kepada kami [Hisyam bin Abdul Malik] berkata; telah menceritakan kepada kami [Hammad bin Salamah] dari [Muhammad bin 'Amru] dari [Abu Salamah] dari [Asy Syarid bin Suwaid Ats Tsaqafi] berkata, \"Aku datang kepada Rasulullah shallallahu 'alaihi wasallam kemudian berkata, \"Sesungguhnya ibuku telah berwasiat untuk membebaskan budak, dan aku memiliki seorang budak wanita berasal dari An Nub, apakah sah bagiku untuk membebaskannya?\" Beliau menjawab: \"Datangkanlah ia kepadaku.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda: \"Siapakah Tuhanmu?\" Budak wanita itu menjawab, \"Allah.\" Beliau bersabda lagi: \"Siapakah aku?\" Budak itu menjawab, \"Anda adalah Rasulullah.\" Beliau lalu bersabda: \"Bebaskanlah dia, sesungguhnya ia seorang mukminah.\""},"3494":{"ar":"أَخْبَرَنَا الْحُسَيْنُ بْنُ عِيسَى قَالَ أَنْبَأَنَا سُفْيَانُ عَنْ عَمْرٍو عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ سَعْدًا سَأَلَ النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ أُمِّي مَاتَتْ وَلَمْ تُوصِ أَفَأَتَصَدَّقُ عَنْهَا قَالَ نَعَمْ","id":"Telah mengabarkan kepada kami [Al Husain bin Isa] berkata; telah memberitakan kepada kami [Sufyan] dari ['Amru] dari ['Ikrimah] dari [Ibnu Abbas] bahwa Sa'd bertanya kepada Nabi shallallahu 'alaihi wasallam, \"Sesungguhnya ibuku telah meninggal dan belum berwasiat, bolehkah aku bersedekah untuknya?\" Beliau menjawab: \"Ya.\""},"3495":{"ar":"أَخْبَرَنَا أَحْمَدُ بْنُ الْأَزْهَرِ قَالَ حَدَّثَنَا رَوْحُ بْنُ عُبَادَةَ قَالَ حَدَّثَنَا زَكَرِيَّا بْنُ إِسْحَقَ قَالَ حَدَّثَنَا عَمْرُو بْنُ دِينَارٍ عَنْ عِكْرِمَةَ عَنْ ابْنِ عَبَّاسٍأَنَّ رَجُلًا قَالَ يَا رَسُولَ اللَّهِ إِنَّ أُمَّهُ تُوُفِّيَتْ أَفَيَنْفَعُهَا إِنْ تَصَدَّقْتُ عَنْهَا قَالَ نَعَمْ قَالَ فَإِنَّ لِي مَخْرَفًا فَأُشْهِدُكَ أَنِّي قَدْ تَصَدَّقْتُ بِهِ عَنْهَا","id":"Telah mengabarkan kepada kami [Ahmad bin Al Azhar] berkata; telah menceritakan kepada kami [Rauh bin 'Ubadah] berkata; telah menceritakan kepada kami [Zakaria bin Ishaq] berkata; telah menceritakan kepada kami ['Amru bin Dinar] dari ['Ikrimah] dari [Ibnu Abbas], bahwa seseorang berkata, \"Wahai Rasulullah, ibunya telah meninggal, apakah bermanfaat baginya apabila aku bersedekah untuknya?\" Beliau menjawab: \"Ya.\" Orang itu berkata lagi, \"Sesungguhnya aku memiliki kebun kurma, maka aku meminta persaksian anda bahwa aku telah mensedekahkannya untuknya.\""},"3496":{"ar":"أَخْبَرَنِي هَارُونُ بْنُ عَبْدِ اللَّهِ قَالَ حَدَّثَنَا عَفَّانُ قَالَ حَدَّثَنَا سُلَيْمَانُ بْنُ كَثِيرٍ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ سَعْدِ بْنِ عُبَادَةَأَنَّهُ أَتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ إِنَّ أُمِّي مَاتَتْ وَعَلَيْهَا نَذْرٌ أَفَيُجْزِئُ عَنْهَا أَنْ أُعْتِقَ عَنْهَا قَالَ أَعْتِقْ عَنْ أُمِّكَ","id":"Telah mengabarkan kepada kami [Harun bin Abdullah] berkata; telah menceritakan kepada kami ['Affan] berkata; telah menceritakan kepada kami [Sulaiman bin Katsir] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Sa'd bin Ubadah], bahwa ia datang kepada Nabi shallallahu 'alaihi wasallam kemudian berkata, \"Sesungguhnya ibuku telah meninggal dan ia memiliki hutang nadzar. Maka apakah sah jika aku membebaskan budak untuknya?\" Beliau menjawab: \"Bebaskanlah budak untuk ibumu.\""},"3497":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ أَحَمَدَ أَبُو يُوسُفَ الصَّيْدَلَانِيُّ عَنْ عِيسَى وَهُوَ ابْنُ يُونُسَ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ أَخْبَرَهُ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ سَعْدِ بْنِ عُبَادَةَأَنَّهُ اسْتَفْتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَذْرٍ كَانَ عَلَى أُمِّهِ فَتُوُفِّيَتْ قَبْلَ أَنْ تَقْضِيَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْضِهِ عَنْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Ahmad Abu Yusuf Ash Shaidalani] dari [Isa] -yaitu Ibnu Yunus- dari [Al Auza'I] dari [Az Zuhri] ia mengabarkan kepadanya dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Sa'd bin 'Ubadah], bahwa ia meminta fatwa kepada Nabi shallallahu 'alaihi wasallam mengenai nadzar yang menjadi kewajiban ibunya, dan ibunya meninggal sebelum menunaikannya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tunaikanlah untuknya.\""},"3498":{"ar":"أَخْبَرَنَا مُحَمَّدُ بْنُ صَدَقَةَ الْحِمْصِيُّ قَالَ حَدَّثَنَا مُحَمَّدُ بْنُ شُعَيْبٍ عَنْ الْأَوْزَاعِيِّ عَنْ الزُّهْرِيِّ أَخْبَرَهُ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍ عَنْ سَعْدِ بْنِ عُبَادَةَأَنَّهُ اسْتَفْتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَذْرٍ كَانَ عَلَى أُمِّهِ فَمَاتَتْ قَبْلَ أَنْ تَقْضِيَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْضِهِ عَنْهَا","id":"Telah mengabarkan kepada kami [Muhammad bin Shadaqah Al Himshi] berkata; telah menceritakan kepada kami [Muhammad bin Syu'aib] dari [Al Auza'i] dari [Az Zuhri], ia telah mengabarkan kepadanya dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas] dari [Sa'd bin 'Ubadah] bahwa ia telah meminta fatwa kepada Nabi shallallahu 'alaihi wasallam mengenai nadzar yang menjadi kewajiban atas ibunya, kemudian ia meninggal sebelum menunaikannya. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tunaikanlah untuknya.\""},"3499":{"ar":"أَخْبَرَنَا الْعَبَّاسُ بْنُ الْوَلِيدِ بْنِ مَزْيَدٍ قَالَ أَخْبَرَنِي أَبِي قَالَ حَدَّثَنَا الْأَوْزَاعِيُّ قَالَ أَخْبَرَنِي الزُّهْرِيُّ أَنَّ عُبَيْدَ اللَّهِ بْنَ عَبْدِ اللَّهِ أَخْبَرَهُ عَنْ ابْنِ عَبَّاسٍ قَالَاسْتَفْتَى سَعْدٌ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَذْرٍ كَانَ عَلَى أُمِّهِ فَتُوُفِّيَتْ قَبْلَ أَنْ تَقْضِيَهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْضِهِ عَنْهَا","id":"Telah mengabarkan kepada kami [Al Abbas bin Al Walid bin Mazyad] berkata; telah mengabarkan kepadaku [ayahku] berkata; telah menceritakan kepada kami [Al Auza'i] berkata; telah mengabarkan kepadaku [Az Zuhri] bahwa ['Ubaidullah bin Abdullah] telah mengabarkan kepadanya dari [Ibnu Abbas] ia berkata, \"Sa'd meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam mengenai nadzar yang menjadi kewajiban ibunya, dan ibunya meninggal sebelum ia menunaikannya. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Tunaikanlah untuknya.\""},"3500":{"ar":"قَالَ الْحَارِثُ بْنُ مِسْكِينٍ قِرَاءَةً عَلَيْهِ وَأَنَا أَسْمَعُ عَنْ سُفْيَانَ عَنْ الزُّهْرِيِّ عَنْ عُبَيْدِ اللَّهِ بْنِ عَبْدِ اللَّهِ عَنْ ابْنِ عَبَّاسٍأَنَّ سَعْدَ بْنَ عُبَادَةَ اسْتَفْتَى النَّبِيَّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فِي نَذْرٍ كَانَ عَلَى أُمِّهِ فَتُوُفِّيَتْ قَبْلَ أَنْ تَقْضِيَهُ فَقَالَ اقْضِهِ عَنْهَا","id":"Telah mengabarkan kepada kami [Al Harits bin Miskin] dia membacakan riwayat dan aku yang mendengar, dari [Sufyan] dari [Az Zuhri] dari ['Ubaidullah bin Abdullah] dari [Ibnu Abbas], bahwa Sa'd bin 'Ubadah meminta fatwa kepada Rasulullah shallallahu 'alaihi wasallam mengenai nadzar yang menjadi kewajiban ibunya, dan ibunya meninggal sebelum ia menunaikannya. Lalu beliau bersabda: \"Tunaikanlah untuknya.\""}};
